#[derive(Debug, Clone, PartialEq, Eq)]
pub enum CommandError {
    InvalidCommandFrame,
    InvalidUtf8Argument,
    UnknownCommand {
        command: String,
        args_preview: Option<String>,
    },
    WrongArity(&'static str),
    WrongSubcommandArity {
        command: &'static str,
        subcommand: String,
    },
    UnknownSubcommand {
        command: &'static str,
        subcommand: String,
    },
    InvalidInteger,
    InvalidSlot,
    SyntaxError,
    NoSuchKey,
    Store(StoreError),
    Custom(String),
}

fn hello_bulk(s: &str) -> RespFrame {
    RespFrame::BulkString(Some(s.as_bytes().to_vec()))
}

fn hello_simple(s: &str) -> RespFrame {
    RespFrame::SimpleString(s.to_string())
}

fn replicaof_command_name(argv: &[Vec<u8>]) -> &'static str {
    if argv
        .first()
        .is_some_and(|command| command.eq_ignore_ascii_case(b"SLAVEOF"))
    {
        "SLAVEOF"
    } else {
        "REPLICAOF"
    }
}

const HGET_COMMAND_NAME: &str = "hget";
const HGET_COMMAND_FLAGS: &str = "readonly fast";
const HGET_ARITY: usize = 3;

fn is_hget_command(name: &[u8]) -> bool {
    name.eq_ignore_ascii_case(b"HGET")
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct MigrateRequest {
    pub host: String,
    pub port_arg: Vec<u8>,
    pub destination_db: i64,
    pub timeout: Duration,
    pub copy: bool,
    pub replace: bool,
    pub auth_username: Option<Vec<u8>>,
    pub auth_password: Option<Vec<u8>>,
    pub keys: Vec<Vec<u8>>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct MigrateKeySpec {
    pub source_key: Vec<u8>,
    pub target_key: Vec<u8>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct MigrateOutcome {
    pub reply: RespFrame,
    pub deleted_keys: Vec<Vec<u8>>,
}

fn migrate_ioerr(action: &str) -> CommandError {
    CommandError::Custom(format!(
        "IOERR error or timeout {action} to target instance"
    ))
}

fn migrate_connect_err() -> CommandError {
    CommandError::Custom("IOERR error or timeout connecting to the client".to_string())
}

fn migrate_connect(host: &str, port: u16, timeout: Duration) -> Result<TcpStream, CommandError> {
    let addrs: Vec<_> = (host, port)
        .to_socket_addrs()
        .map_err(|_| migrate_connect_err())?
        .collect();
    if addrs.is_empty() {
        return Err(migrate_connect_err());
    }

    let mut last_err = None;
    for addr in addrs {
        match TcpStream::connect_timeout(&addr, timeout) {
            Ok(stream) => return Ok(stream),
            Err(err) => last_err = Some(err),
        }
    }

    let _ = last_err;
    Err(migrate_connect_err())
}

/// Return the list of key names referenced by the command.
pub fn command_keys(argv: &[Vec<u8>]) -> Vec<Vec<u8>> {
    command_key_indexes(argv)
        .into_iter()
        .filter_map(|idx| argv.get(idx).cloned())
        .collect()
}

/// Locate the index of the `<id>` argument in an `XADD` argv, skipping the
/// optional `NOMKSTREAM` and `MAXLEN|MINID [=|~] <threshold> [LIMIT <n>]`
/// prefix. Returns `None` when the argv is too short. Used to rewrite an
/// auto-generated id (`*` / `<ms>-*`) to the concrete id for deterministic
/// AOF/replication propagation. (frankenredis-f9byo)
///
/// This mirrors the option-skipping in `xadd`'s parser; it is intentionally
/// lenient (it does not re-validate threshold values) because only a
/// successfully executed XADD — whose options already parsed — is propagated.
pub fn xadd_id_arg_index(argv: &[Vec<u8>]) -> Option<usize> {
    // argv[0] = XADD, argv[1] = key, options begin at index 2.
    let mut idx = 2;
    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"NOMKSTREAM") {
            idx += 1;
        } else if eq_ascii_command(&argv[idx], b"MAXLEN") || eq_ascii_command(&argv[idx], b"MINID")
        {
            idx += 1;
            if idx < argv.len()
                && (eq_ascii_command(&argv[idx], b"=") || eq_ascii_command(&argv[idx], b"~"))
            {
                idx += 1;
            }
            idx += 1; // threshold
        } else if eq_ascii_command(&argv[idx], b"LIMIT") && idx + 1 < argv.len() {
            idx += 2; // LIMIT <n>
        } else {
            break;
        }
    }
    (idx < argv.len()).then_some(idx)
}

/// Rewrite a non-deterministic write command into the deterministic form used
/// for AOF/replication propagation, given the command's reply. This is the
/// canonical implementation shared by the Lua/script EFFECT-capture path (so a
/// script's `redis.call('XADD', k, '*')` / SPOP / INCRBYFLOAT don't propagate
/// verbatim and diverge on a replica/AOF replay). `store` is read only for
/// SPOP's DEL-vs-SREM decision (uses the current dispatch db). Returns `None`
/// to propagate the command verbatim. (frankenredis-x1225)
///
/// Mirrors the runtime direct-dispatch rewrites (1uiql / f9byo / ybaw7):
/// INCRBYFLOAT→SET, HINCRBYFLOAT→HSET, XADD `*`→concrete id, SPOP→SREM/DEL,
/// BLPOP/BRPOP→LPOP/RPOP, BZPOP*→ZPOP*, BRPOPLPUSH→RPOPLPUSH, BLMOVE→LMOVE,
/// (B)LMPOP→LPOP/RPOP key count, (B)ZMPOP→ZPOPMIN/MAX key count, GETDEL→DEL.
pub fn rewrite_effect_command_for_propagation(
    argv: &[Vec<u8>],
    reply: &fr_protocol::RespFrame,
    store: &Store,
    now_ms: u64,
) -> Option<Vec<Vec<u8>>> {
    use fr_protocol::RespFrame;
    let cmd = argv.first()?;

    // (frankenredis-9snkx) Relative-time -> absolute rewrite (mdrk8/dt3v0) runs
    // first; it is reply-independent and shares this one entry point so scripts
    // and MULTI/EXEC get it too (they previously propagated EXPIRE verbatim and
    // drifted the replica TTL).
    if let Some(rewritten) = rewrite_relative_expire_for_propagation(argv, now_ms) {
        return Some(rewritten);
    }

    let bulk = |f: &RespFrame| match f {
        RespFrame::BulkString(Some(v)) => Some(v.clone()),
        _ => None,
    };
    let items = |f: &RespFrame| match f {
        RespFrame::Array(Some(v)) | RespFrame::Set(Some(v)) => Some(v.clone()),
        _ => None,
    };

    if eq_ascii_command(cmd, b"INCRBYFLOAT") && argv.len() == 3 {
        // (frankenredis-n66hv) KEEPTTL so the rewritten SET preserves the key's
        // TTL (a plain SET would clear it on the replica / AOF replay).
        return Some(vec![
            b"SET".to_vec(),
            argv[1].clone(),
            bulk(reply)?,
            b"KEEPTTL".to_vec(),
        ]);
    }
    if eq_ascii_command(cmd, b"HINCRBYFLOAT") && argv.len() == 4 {
        return Some(vec![
            b"HSET".to_vec(),
            argv[1].clone(),
            argv[2].clone(),
            bulk(reply)?,
        ]);
    }
    if eq_ascii_command(cmd, b"XADD") {
        let id_idx = xadd_id_arg_index(argv)?;
        if !argv.get(id_idx)?.contains(&b'*') {
            return None;
        }
        let mut out = argv.to_vec();
        out[id_idx] = bulk(reply)?;
        return Some(out);
    }
    if eq_ascii_command(cmd, b"GETDEL") && argv.len() == 2 {
        return Some(vec![b"DEL".to_vec(), argv[1].clone()]);
    }
    if eq_ascii_command(cmd, b"GETSET") && argv.len() == 3 {
        // Upstream getsetCommand canonicalizes the deprecated GETSET into a plain
        // SET in the replication / AOF stream (rewriteClientCommandArgument →
        // shared.set), so replicas and AOF replay `SET key value`. No KEEPTTL:
        // GETSET clears any existing TTL exactly like a plain SET, so the bare
        // SET form already matches. The reply (the old value) is irrelevant — the
        // rewrite is fully determined by argv.
        return Some(vec![b"SET".to_vec(), argv[1].clone(), argv[2].clone()]);
    }
    if eq_ascii_command(cmd, b"BRPOPLPUSH") && argv.len() == 4 {
        return Some(vec![
            b"RPOPLPUSH".to_vec(),
            argv[1].clone(),
            argv[2].clone(),
        ]);
    }
    if eq_ascii_command(cmd, b"BLMOVE") && argv.len() == 6 {
        return Some(vec![
            b"LMOVE".to_vec(),
            argv[1].clone(),
            argv[2].clone(),
            argv[3].clone(),
            argv[4].clone(),
        ]);
    }
    if eq_ascii_command(cmd, b"BLPOP") || eq_ascii_command(cmd, b"BRPOP") {
        let key = bulk(items(reply)?.first()?)?;
        let op = if eq_ascii_command(cmd, b"BLPOP") {
            b"LPOP"
        } else {
            b"RPOP"
        };
        return Some(vec![op.to_vec(), key]);
    }
    if eq_ascii_command(cmd, b"BZPOPMIN") || eq_ascii_command(cmd, b"BZPOPMAX") {
        let key = bulk(items(reply)?.first()?)?;
        let op = if eq_ascii_command(cmd, b"BZPOPMIN") {
            b"ZPOPMIN"
        } else {
            b"ZPOPMAX"
        };
        return Some(vec![op.to_vec(), key]);
    }
    if eq_ascii_command(cmd, b"SPOP") {
        let key = argv.get(1)?;
        let members: Vec<Vec<u8>> = match reply {
            RespFrame::BulkString(Some(m)) => vec![m.clone()],
            RespFrame::Array(Some(v)) | RespFrame::Set(Some(v)) => {
                let mut out = Vec::with_capacity(v.len());
                for it in v {
                    out.push(bulk(it)?);
                }
                out
            }
            _ => return None,
        };
        if members.is_empty() {
            return None;
        }
        let encoded = fr_store::encode_db_key(store.dispatch_client_ctx.db_index, key);
        return if store.key_is_present(&encoded) {
            let mut out = Vec::with_capacity(2 + members.len());
            out.push(b"SREM".to_vec());
            out.push(key.clone());
            out.extend(members);
            Some(out)
        } else {
            Some(vec![b"DEL".to_vec(), key.clone()])
        };
    }
    // (B)LMPOP / (B)ZMPOP -> LPOP/RPOP/ZPOPMIN/ZPOPMAX <served-key> <count>.
    let (is_list, numkeys_idx) = if eq_ascii_command(cmd, b"LMPOP") {
        (true, 1usize)
    } else if eq_ascii_command(cmd, b"ZMPOP") {
        (false, 1)
    } else if eq_ascii_command(cmd, b"BLMPOP") {
        (true, 2)
    } else if eq_ascii_command(cmd, b"BZMPOP") {
        (false, 2)
    } else {
        return None;
    };
    let numkeys: usize = std::str::from_utf8(argv.get(numkeys_idx)?)
        .ok()?
        .parse()
        .ok()?;
    let dir = argv.get(numkeys_idx + 1 + numkeys)?;
    let top = items(reply)?;
    let served_key = bulk(top.first()?)?;
    let count = items(top.get(1)?)?.len();
    let op: &[u8] = if is_list {
        if eq_ascii_command(dir, b"LEFT") {
            b"LPOP"
        } else {
            b"RPOP"
        }
    } else if eq_ascii_command(dir, b"MIN") {
        b"ZPOPMIN"
    } else {
        b"ZPOPMAX"
    };
    Some(vec![
        op.to_vec(),
        served_key,
        count.to_string().into_bytes(),
    ])
}

/// Rewrite a relative-time expire command to its absolute form for AOF/
/// replication propagation, so a replica/AOF replay does not recompute the
/// deadline at its later receive time and drift the TTL upward. Mirrors upstream
/// expire.c/t_string.c `rewriteClientCommandVector(...)`:
///   EXPIRE/PEXPIRE/EXPIREAT/PEXPIREAT -> `PEXPIREAT key <ms>`
///   SETEX/PSETEX / `SET key val EX|PX|EXAT ...` -> `SET key val PXAT <ms>`
///   GETEX EX|PX|EXAT|PXAT (future) -> `PEXPIREAT`, past -> `DEL`, PERSIST -> `PERSIST`
/// Returns `None` for a non-expire command or an absolute/no-expire form (those
/// carry no relative drift and propagate verbatim). (frankenredis-mdrk8 / dt3v0)
pub fn rewrite_relative_expire_for_propagation(
    argv: &[Vec<u8>],
    now_ms: u64,
) -> Option<Vec<Vec<u8>>> {
    let cmd = argv.first()?;
    let now = i64::try_from(now_ms).unwrap_or(i64::MAX);

    if eq_ascii_command(cmd, b"EXPIRE")
        || eq_ascii_command(cmd, b"PEXPIRE")
        || eq_ascii_command(cmd, b"EXPIREAT")
        || eq_ascii_command(cmd, b"PEXPIREAT")
    {
        if argv.len() < 3 {
            return None;
        }
        let value: i64 = std::str::from_utf8(&argv[2]).ok()?.parse().ok()?;
        let abs_ms: i64 = if eq_ascii_command(cmd, b"EXPIRE") {
            now.saturating_add(value.saturating_mul(1000))
        } else if eq_ascii_command(cmd, b"PEXPIRE") {
            now.saturating_add(value)
        } else if eq_ascii_command(cmd, b"EXPIREAT") {
            value.saturating_mul(1000)
        } else {
            value
        };
        return Some(vec![
            b"PEXPIREAT".to_vec(),
            argv[1].clone(),
            abs_ms.to_string().into_bytes(),
        ]);
    }

    if eq_ascii_command(cmd, b"SETEX") || eq_ascii_command(cmd, b"PSETEX") {
        if argv.len() != 4 {
            return None;
        }
        let value: i64 = std::str::from_utf8(&argv[2]).ok()?.parse().ok()?;
        let abs_ms = if eq_ascii_command(cmd, b"SETEX") {
            now.saturating_add(value.saturating_mul(1000))
        } else {
            now.saturating_add(value)
        };
        return Some(vec![
            b"SET".to_vec(),
            argv[1].clone(),
            argv[3].clone(),
            b"PXAT".to_vec(),
            abs_ms.to_string().into_bytes(),
        ]);
    }
    if eq_ascii_command(cmd, b"SET") {
        if argv.len() < 3 {
            return None;
        }
        let abs_ms = set_relative_expire_deadline_ms(&argv[3..], now)?;
        return Some(vec![
            b"SET".to_vec(),
            argv[1].clone(),
            argv[2].clone(),
            b"PXAT".to_vec(),
            abs_ms.to_string().into_bytes(),
        ]);
    }

    if eq_ascii_command(cmd, b"GETEX") {
        if argv.len() < 3 {
            return None;
        }
        let opt = &argv[2];
        if eq_ascii_command(opt, b"PERSIST") {
            return Some(vec![b"PERSIST".to_vec(), argv[1].clone()]);
        }
        let value: i64 = std::str::from_utf8(argv.get(3)?).ok()?.parse().ok()?;
        let abs_ms: i64 = if eq_ascii_command(opt, b"EX") {
            now.saturating_add(value.saturating_mul(1000))
        } else if eq_ascii_command(opt, b"PX") {
            now.saturating_add(value)
        } else if eq_ascii_command(opt, b"EXAT") {
            value.saturating_mul(1000)
        } else if eq_ascii_command(opt, b"PXAT") {
            value
        } else {
            return None;
        };
        if abs_ms <= now {
            return Some(vec![b"DEL".to_vec(), argv[1].clone()]);
        }
        return Some(vec![
            b"PEXPIREAT".to_vec(),
            argv[1].clone(),
            abs_ms.to_string().into_bytes(),
        ]);
    }

    None
}

/// Scan SET option tokens for a relative expiry (`EX`/`PX`/`EXAT`) and return the
/// absolute deadline in ms; `None` when the only expiry is an absolute `PXAT` or
/// there is no expiry (`KEEPTTL`/plain SET). (frankenredis-dt3v0)
fn set_relative_expire_deadline_ms(opts: &[Vec<u8>], now: i64) -> Option<i64> {
    let mut i = 0;
    while i < opts.len() {
        let opt = &opts[i];
        if eq_ascii_command(opt, b"EX")
            || eq_ascii_command(opt, b"PX")
            || eq_ascii_command(opt, b"EXAT")
        {
            let value: i64 = std::str::from_utf8(opts.get(i + 1)?).ok()?.parse().ok()?;
            return Some(if eq_ascii_command(opt, b"EX") {
                now.saturating_add(value.saturating_mul(1000))
            } else if eq_ascii_command(opt, b"PX") {
                now.saturating_add(value)
            } else {
                value.saturating_mul(1000)
            });
        }
        i += 1;
    }
    None
}

/// Return the argv indexes that correspond to keys for the command.
pub fn command_key_indexes(argv: &[Vec<u8>]) -> Vec<usize> {
    let Some(raw_cmd) = argv.first() else {
        return Vec::new();
    };
    if is_hget_command(raw_cmd) {
        return if argv.len() > 1 { vec![1] } else { Vec::new() };
    }
    let cmd_name = match std::str::from_utf8(raw_cmd) {
        Ok(s) => s,
        Err(_) => return Vec::new(),
    };

    // (frankenredis-infosections) Pubsub commands have channel
    // arguments (not keyspace keys) at the same positions advertised
    // by COMMAND INFO. Returning [] here keeps the key-ACL gate from
    // misclassifying channel names as keys; channel ACLs run
    // independently via dispatch_acl_channel_permission_error_for_argv.
    if cmd_name.eq_ignore_ascii_case("PUBLISH")
        || cmd_name.eq_ignore_ascii_case("SPUBLISH")
        || cmd_name.eq_ignore_ascii_case("SUBSCRIBE")
        || cmd_name.eq_ignore_ascii_case("UNSUBSCRIBE")
        || cmd_name.eq_ignore_ascii_case("SSUBSCRIBE")
        || cmd_name.eq_ignore_ascii_case("SUNSUBSCRIBE")
        || cmd_name.eq_ignore_ascii_case("PSUBSCRIBE")
        || cmd_name.eq_ignore_ascii_case("PUNSUBSCRIBE")
    {
        return Vec::new();
    }

    // Handle special cases not fully described by first/last/step in COMMAND_TABLE.
    if cmd_name.eq_ignore_ascii_case("EVAL")
        || cmd_name.eq_ignore_ascii_case("EVALSHA")
        || cmd_name.eq_ignore_ascii_case("EVAL_RO")
        || cmd_name.eq_ignore_ascii_case("EVALSHA_RO")
        || cmd_name.eq_ignore_ascii_case("FCALL")
        || cmd_name.eq_ignore_ascii_case("FCALL_RO")
    {
        if argv.len() < 3 {
            return Vec::new();
        }
        let num_keys: usize = std::str::from_utf8(&argv[2])
            .ok()
            .and_then(|s| s.parse().ok())
            .unwrap_or(0);
        return (3..argv.len()).take(num_keys).collect();
    }

    if cmd_name.eq_ignore_ascii_case("XREAD") || cmd_name.eq_ignore_ascii_case("XREADGROUP") {
        let streams_idx = argv.iter().position(|a| a.eq_ignore_ascii_case(b"STREAMS"));
        if let Some(idx) = streams_idx {
            let remaining = &argv[idx + 1..];
            let num_keys = remaining.len() / 2;
            let mut keys = Vec::with_capacity(num_keys);
            for i in 0..num_keys {
                keys.push(idx + 1 + i);
            }
            return keys;
        }
        return Vec::new();
    }

    if cmd_name.eq_ignore_ascii_case("XSETID") {
        if argv.len() < 2 {
            return Vec::new();
        }
        return vec![1];
    }

    if cmd_name.eq_ignore_ascii_case("RESTORE") || cmd_name.eq_ignore_ascii_case("RESTORE-ASKING") {
        if argv.len() < 2 {
            return Vec::new();
        }
        return vec![1];
    }

    if cmd_name.eq_ignore_ascii_case("ZUNIONSTORE")
        || cmd_name.eq_ignore_ascii_case("ZINTERSTORE")
        || cmd_name.eq_ignore_ascii_case("ZDIFFSTORE")
    {
        if argv.len() < 3 {
            return Vec::new();
        }
        let num_keys: usize = std::str::from_utf8(&argv[2])
            .ok()
            .and_then(|s| s.parse().ok())
            .unwrap_or(0);
        let mut keys = vec![1]; // destination key
        keys.extend((3..argv.len()).take(num_keys));
        return keys;
    }

    if cmd_name.eq_ignore_ascii_case("ZUNION")
        || cmd_name.eq_ignore_ascii_case("ZINTER")
        || cmd_name.eq_ignore_ascii_case("ZDIFF")
        || cmd_name.eq_ignore_ascii_case("ZINTERCARD")
        || cmd_name.eq_ignore_ascii_case("SINTERCARD")
    {
        if argv.len() < 2 {
            return Vec::new();
        }
        let num_keys: usize = std::str::from_utf8(&argv[1])
            .ok()
            .and_then(|s| s.parse().ok())
            .unwrap_or(0);
        return (2..argv.len()).take(num_keys).collect();
    }

    if cmd_name.eq_ignore_ascii_case("SINTERSTORE")
        || cmd_name.eq_ignore_ascii_case("SUNIONSTORE")
        || cmd_name.eq_ignore_ascii_case("SDIFFSTORE")
    {
        if argv.len() < 3 {
            if argv.len() == 2 {
                return vec![1];
            }
            return Vec::new();
        }
        return (1..argv.len()).collect();
    }

    if cmd_name.eq_ignore_ascii_case("MSET") || cmd_name.eq_ignore_ascii_case("MSETNX") {
        return (1..argv.len()).step_by(2).collect();
    }

    if cmd_name.eq_ignore_ascii_case("BITOP") {
        if argv.len() < 4 {
            return Vec::new();
        }
        // BITOP operation destkey src_key [src_key ...]
        return (2..argv.len()).collect();
    }

    if cmd_name.eq_ignore_ascii_case("SINTER")
        || cmd_name.eq_ignore_ascii_case("SUNION")
        || cmd_name.eq_ignore_ascii_case("SDIFF")
    {
        return (1..argv.len()).collect();
    }

    if cmd_name.eq_ignore_ascii_case("SORT") || cmd_name.eq_ignore_ascii_case("SORT_RO") {
        if argv.len() < 2 {
            return Vec::new();
        }
        let mut keys = vec![1];
        let mut i = 2;
        while i < argv.len() {
            if let Ok(s) = std::str::from_utf8(&argv[i])
                && s.eq_ignore_ascii_case("STORE")
                && i + 1 < argv.len()
            {
                keys.push(i + 1);
                i += 2;
                continue;
            }
            i += 1;
        }
        return keys;
    }

    if cmd_name.eq_ignore_ascii_case("GEORADIUS")
        || cmd_name.eq_ignore_ascii_case("GEORADIUSBYMEMBER")
    {
        if argv.len() < 2 {
            return Vec::new();
        }
        let mut keys = vec![1];
        // STORE / STOREDIST options only appear AFTER the fixed positional
        // arguments, so the scan must skip them first — otherwise a member
        // or coordinate literally named "STORE" is mis-read as the option.
        // Upstream geo.c::georadiusGetKeys advances past the fixed args:
        // GEORADIUS has 5 (key lon lat radius unit) → options from argv[6];
        // GEORADIUSBYMEMBER has 4 (key member radius unit) → from argv[5].
        // (frankenredis-u48rd)
        let mut i = if cmd_name.eq_ignore_ascii_case("GEORADIUSBYMEMBER") {
            5
        } else {
            6
        };
        while i < argv.len() {
            if let Ok(s) = std::str::from_utf8(&argv[i])
                && (s.eq_ignore_ascii_case("STORE") || s.eq_ignore_ascii_case("STOREDIST"))
                && i + 1 < argv.len()
            {
                keys.push(i + 1);
                i += 2;
                continue;
            }
            i += 1;
        }
        return keys;
    }

    if cmd_name.eq_ignore_ascii_case("GEOSEARCH") || cmd_name.eq_ignore_ascii_case("GEOSEARCHSTORE")
    {
        if argv.len() < 3 {
            // Both take at least 'key' or 'destination source'
            if argv.len() == 2 {
                return vec![1];
            }
            return Vec::new();
        }
        if cmd_name.eq_ignore_ascii_case("GEOSEARCH") {
            return vec![1];
        } else {
            return vec![1, 2];
        }
    }

    if cmd_name.eq_ignore_ascii_case("XINFO") || cmd_name.eq_ignore_ascii_case("XGROUP") {
        if argv.len() < 3 {
            return Vec::new();
        }
        return vec![2];
    }

    if cmd_name.eq_ignore_ascii_case("XACK")
        || cmd_name.eq_ignore_ascii_case("XCLAIM")
        || cmd_name.eq_ignore_ascii_case("XAUTOCLAIM")
        || cmd_name.eq_ignore_ascii_case("XPENDING")
    {
        if argv.len() < 2 {
            return Vec::new();
        }
        return vec![1];
    }

    if cmd_name.eq_ignore_ascii_case("OBJECT") {
        if argv.len() < 3 {
            return Vec::new();
        }
        return vec![2];
    }

    if cmd_name.eq_ignore_ascii_case("MEMORY") {
        if argv.len() < 3 {
            return Vec::new();
        }
        if let Ok(sub) = std::str::from_utf8(&argv[1])
            && sub.eq_ignore_ascii_case("USAGE")
        {
            return vec![2];
        }
        return Vec::new();
    }

    if cmd_name.eq_ignore_ascii_case("LMPOP") || cmd_name.eq_ignore_ascii_case("ZMPOP") {
        if argv.len() < 2 {
            return Vec::new();
        }
        let num_keys: usize = std::str::from_utf8(&argv[1])
            .ok()
            .and_then(|s| s.parse().ok())
            .unwrap_or(0);
        return (2..argv.len()).take(num_keys).collect();
    }

    if cmd_name.eq_ignore_ascii_case("BLMPOP") || cmd_name.eq_ignore_ascii_case("BZMPOP") {
        if argv.len() < 3 {
            return Vec::new();
        }
        let num_keys: usize = std::str::from_utf8(&argv[2])
            .ok()
            .and_then(|s| s.parse().ok())
            .unwrap_or(0);
        return (3..argv.len()).take(num_keys).collect();
    }

    if cmd_name.eq_ignore_ascii_case("MIGRATE") {
        // MIGRATE host port key destination-db timeout [COPY] [REPLACE]
        //         [AUTH password] [AUTH2 username password] [KEYS k1 k2 ...]
        //
        // argv[3] is either the single key OR an empty string when the
        // multi-key form is used. Upstream's commands/migrate.json
        // declares two key specs:
        //   - { begin_search: { type: index, spec: { index: 3 } },
        //       find_keys: { type: keynum,
        //                    spec: { keynumidx: 0, firstkey: 0, keystep: 0 } } }
        //     (single positional key at argv[3])
        //   - keyword-anchored 'KEYS' spec for the multi-key tail
        // (frankenredis-migratekeyspec) fr's COMMAND_TABLE entry uses
        // first/last/step = 0/0/0 (no positional keys), so without an
        // explicit handler MIGRATE returned 'no key arguments' for both
        // forms.
        if argv.len() < 6 {
            return Vec::new();
        }
        let mut keys: Vec<usize> = Vec::new();
        // Single-key form: argv[3] is non-empty.
        if !argv[3].is_empty() {
            keys.push(3);
        }
        // Multi-key form: scan for KEYS sentinel and consume the tail.
        if let Some(keys_idx) = argv.iter().position(|a| a.eq_ignore_ascii_case(b"KEYS"))
            && keys_idx + 1 < argv.len()
        {
            for i in (keys_idx + 1)..argv.len() {
                keys.push(i);
            }
        }
        return keys;
    }

    if cmd_name.eq_ignore_ascii_case("SMOVE")
        || cmd_name.eq_ignore_ascii_case("RENAME")
        || cmd_name.eq_ignore_ascii_case("RENAMENX")
        || cmd_name.eq_ignore_ascii_case("COPY")
        || cmd_name.eq_ignore_ascii_case("LMOVE")
        || cmd_name.eq_ignore_ascii_case("BLMOVE")
        || cmd_name.eq_ignore_ascii_case("RPOPLPUSH")
        || cmd_name.eq_ignore_ascii_case("BRPOPLPUSH")
    {
        if argv.len() < 3 {
            if argv.len() == 2 {
                return vec![1];
            }
            return Vec::new();
        }
        return vec![1, 2];
    }

    for &(name, _arity, _flags, first, last, step) in COMMAND_TABLE {
        if name.eq_ignore_ascii_case(cmd_name) {
            if first == 0 {
                return Vec::new();
            }
            let first_idx = first as usize;
            let last_idx = if last < 0 {
                let len_i64 = argv.len() as i64;
                (len_i64 + last) as usize
            } else {
                last as usize
            };
            let step = step.max(1) as usize;

            let mut keys = Vec::new();
            let mut i = first_idx;
            while i < argv.len() && i <= last_idx {
                if argv.get(i).is_some() {
                    keys.push(i);
                }
                i += step;
            }
            return keys;
        }
    }

    Vec::new()
}

const KEY_FLAGS_RO_ACCESS: &[&str] = &["RO", "access"];
const KEY_FLAGS_RW_ACCESS_UPDATE: &[&str] = &["RW", "access", "update"];
const KEY_FLAGS_OW_UPDATE: &[&str] = &["OW", "update"];
const KEY_FLAGS_OW_INSERT: &[&str] = &["OW", "insert"];
const KEY_FLAGS_RM_DELETE: &[&str] = &["RM", "delete"];
const KEY_FLAGS_RW_ACCESS_DELETE: &[&str] = &["RW", "access", "delete"];
const KEY_FLAGS_RW_INSERT: &[&str] = &["RW", "insert"];
const KEY_FLAGS_RW_DELETE: &[&str] = &["RW", "delete"];
const KEY_FLAGS_RW_UPDATE: &[&str] = &["RW", "update"];
const KEY_FLAGS_RW_ACCESS_INSERT: &[&str] = &["RW", "access", "insert"];
const KEY_FLAGS_RO: &[&str] = &["RO"];

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct CommandKeyReference {
    index: usize,
    flags: &'static [&'static str],
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CommandKeyLookupError {
    InvalidCommand,
    NoKeyArguments,
    InvalidNumberOfArguments,
    InvalidArguments,
}

