/// Pack up to 8 ASCII-uppercased bytes of a command name into a `u64`.
/// Only ASCII lowercase letters are folded (matching `to_ascii_uppercase`
/// / `eq_ignore_ascii_case` semantics exactly) so non-letter bytes never
/// collide with a letter. Bytes are placed at distinct, non-overlapping
/// 8-bit shifts, so for two equal-length slices `pack(a) == pack(b)` iff
/// every uppercased byte matches — byte-identical to the per-byte fold
/// below. Caller guarantees `b.len() <= 8`.
#[inline(always)]
const fn pack_cmd_u64(b: &[u8]) -> u64 {
    let mut k = 0u64;
    let mut i = 0;
    while i < b.len() {
        let c = b[i];
        let up = if c.is_ascii_lowercase() { c - 32 } else { c };
        k |= (up as u64) << (i * 8);
        i += 1;
    }
    k
}

/// Case-insensitive command-name compare. For the common case of names up
/// to 8 bytes (every hot command — GET/SET/HSET/EXPIRE/ZADD/…), this packs
/// both sides into a single `u64` and compares with one integer op instead
/// of a per-byte fold loop. Because `pack_cmd_u64(lhs)` depends only on the
/// (loop-invariant) command bytes, the optimizer hoists it across the
/// inlined chain of `eq_ascii_command(cmd, b"LITERAL")` comparisons in
/// `classify_command` and lowers the distinct-constant comparisons into a
/// jump table — turning each length bucket's O(bucket) linear scan into an
/// effectively O(1) dispatch. Names longer than 8 bytes keep the byte loop.
#[inline(always)]
fn eq_ascii_command(lhs: &[u8], rhs: &[u8]) -> bool {
    if lhs.len() != rhs.len() {
        return false;
    }
    if rhs.len() <= 8 {
        return pack_cmd_u64(lhs) == pack_cmd_u64(rhs);
    }
    lhs.iter()
        .zip(rhs.iter())
        .all(|(left, right)| left.to_ascii_uppercase() == *right)
}

fn ping(argv: &[Vec<u8>]) -> Result<RespFrame, CommandError> {
    match argv.len() {
        1 => Ok(RespFrame::SimpleString("PONG".to_string())),
        2 => Ok(RespFrame::BulkString(Some(argv[1].clone()))),
        _ => Err(CommandError::WrongArity("PING")),
    }
}

fn echo(argv: &[Vec<u8>]) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("ECHO"));
    }
    Ok(RespFrame::BulkString(Some(argv[1].clone())))
}

fn set(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("SET"));
    }

    // Expiry mode: at most one *kind* of EX/PX/EXAT/PXAT/KEEPTTL,
    // but upstream t_string.c::parseExtendedStringArgumentsOrReply
    // allows the same expiry-kind to be repeated (last value wins) —
    // only different kinds conflict. (br-frankenredis-setdupex)
    enum ExpiryMode {
        None,
        Px(u64),
        Ex(u64),
        Pxat(u64),
        Exat(u64),
        KeepTtl,
    }
    // (frankenredis-setexorder) Upstream parseExtendedStringArgumentsOrReply
    // SCANS options WITHOUT validating the expire VALUE: only different expire
    // *kinds* conflict (the same kind may repeat, last value wins), and any
    // syntax error in the scan (conflicting kinds, NX/XX conflict, missing
    // value, unknown token) takes precedence over an invalid/overwritten expire
    // value. The chosen value is validated ONCE, after the full scan. fr
    // previously validated each EX/PX value inline, so `SET k v EX 0 PX 100`
    // (conflict) and `SET k v EX 0 EX 10` (overwrite) wrongly surfaced the value
    // error instead of upstream's syntax error / success.
    #[derive(PartialEq)]
    enum ExpiryKind {
        None,
        Px,
        Ex,
        Pxat,
        Exat,
        KeepTtl,
    }
    let mut expiry_kind = ExpiryKind::None;
    let mut expiry_raw: &[u8] = b"";
    let mut nx = false;
    let mut xx = false;
    let mut get = false;

    let mut options = argv[3..].iter();
    while let Some(option_arg) = options.next() {
        // (frankenredis-44iva) byte-match SET options; non-UTF8 -> syntax error
        let option = option_arg;
        if option.eq_ignore_ascii_case(b"PX") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::Px) {
                return Err(CommandError::SyntaxError);
            }
            let Some(ttl_arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            expiry_kind = ExpiryKind::Px;
            expiry_raw = ttl_arg;
        } else if option.eq_ignore_ascii_case(b"EX") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::Ex) {
                return Err(CommandError::SyntaxError);
            }
            let Some(seconds_arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            expiry_kind = ExpiryKind::Ex;
            expiry_raw = seconds_arg;
        } else if option.eq_ignore_ascii_case(b"PXAT") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::Pxat) {
                return Err(CommandError::SyntaxError);
            }
            let Some(ts_arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            expiry_kind = ExpiryKind::Pxat;
            expiry_raw = ts_arg;
        } else if option.eq_ignore_ascii_case(b"EXAT") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::Exat) {
                return Err(CommandError::SyntaxError);
            }
            let Some(ts_arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            expiry_kind = ExpiryKind::Exat;
            expiry_raw = ts_arg;
        } else if option.eq_ignore_ascii_case(b"KEEPTTL") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::KeepTtl) {
                return Err(CommandError::SyntaxError);
            }
            expiry_kind = ExpiryKind::KeepTtl;
        } else if option.eq_ignore_ascii_case(b"NX") {
            // (frankenredis-24276) Upstream
            // parseExtendedStringArgumentsOrReply (t_string.c lines
            // 216-225) gates NX behind `!(*flags & OBJ_SET_XX)` and
            // XX behind `!(*flags & OBJ_SET_NX)`, rejecting the
            // conflict EAGERLY. fr previously accumulated both flags
            // and only checked after the loop, which let a later
            // malformed EX/PX integer surface 'value is not an
            // integer or out of range' before the conflict was seen.
            if xx {
                return Err(CommandError::SyntaxError);
            }
            nx = true;
        } else if option.eq_ignore_ascii_case(b"XX") {
            if nx {
                return Err(CommandError::SyntaxError);
            }
            xx = true;
        } else if option.eq_ignore_ascii_case(b"GET") {
            get = true;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    // Validate the final chosen expire value AFTER the full option scan (any
    // syntax error already returned above), mirroring upstream's deferred
    // getExpireMillisecondsOrReply. This precedes the NX/XX existence gate, like
    // upstream's setGenericCommand. (frankenredis-setexorder)
    let expiry_mode = match expiry_kind {
        ExpiryKind::None => ExpiryMode::None,
        ExpiryKind::KeepTtl => ExpiryMode::KeepTtl,
        ExpiryKind::Px => {
            let ms = parse_set_expire_arg(expiry_raw)?;
            // (frankenredis-expbase) reject relative ms whose ms+basetime
            // overflows LLONG_MAX rather than silently saturating.
            validate_relative_expire_basetime(ms, now_ms, "set")?;
            ExpiryMode::Px(ms)
        }
        ExpiryKind::Ex => {
            let seconds = parse_set_expire_arg(expiry_raw)?;
            // (br-frankenredis-setexrange) seconds whose ms-conversion overflows.
            if seconds > i64::MAX as u64 / 1000 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'set' command".to_string(),
                ));
            }
            validate_relative_expire_basetime(seconds * 1000, now_ms, "set")?;
            ExpiryMode::Ex(seconds)
        }
        ExpiryKind::Pxat => ExpiryMode::Pxat(parse_set_expire_arg(expiry_raw)?),
        ExpiryKind::Exat => {
            let seconds = parse_set_expire_arg(expiry_raw)?;
            if seconds > i64::MAX as u64 / 1000 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'set' command".to_string(),
                ));
            }
            ExpiryMode::Exat(seconds)
        }
    };

    let old_value = if get {
        store.get(&argv[1], now_ms)?
    } else {
        None
    };

    let key_exists = if nx || xx {
        if get {
            old_value.is_some()
        } else {
            // (frankenredis-hjk0m) Upstream setGenericCommand performs the NX/XX
            // existence check via lookupKeyWrite, which does NOT bump
            // keyspace_hits/misses. exists_no_touch counts them (it only skips the
            // LRU/LFU touch), so `SET k v NX`/`XX` wrongly reported a keyspace
            // hit/miss vs redis's 0. Use the non-counting type peek instead.
            store.peek_value_type(&argv[1], now_ms).is_some()
        }
    } else {
        false
    };
    if nx && key_exists {
        return Ok(if get {
            RespFrame::BulkString(old_value)
        } else {
            RespFrame::BulkString(None)
        });
    }
    if xx && !key_exists {
        return Ok(RespFrame::BulkString(None));
    }

    match expiry_mode {
        ExpiryMode::None => {
            store.set(argv[1].clone(), argv[2].clone(), None, now_ms);
        }
        ExpiryMode::Px(ms) => {
            store.set(argv[1].clone(), argv[2].clone(), Some(ms), now_ms);
        }
        ExpiryMode::Ex(sec) => {
            store.set(
                argv[1].clone(),
                argv[2].clone(),
                Some(sec.saturating_mul(1000)),
                now_ms,
            );
        }
        ExpiryMode::Pxat(abs_ms) => {
            store.set_with_abs_expiry(argv[1].clone(), argv[2].clone(), Some(abs_ms), now_ms);
        }
        ExpiryMode::Exat(abs_sec) => {
            store.set_with_abs_expiry(
                argv[1].clone(),
                argv[2].clone(),
                Some(abs_sec.saturating_mul(1000)),
                now_ms,
            );
        }
        ExpiryMode::KeepTtl => {
            let existing_expiry = store.get_expires_at_ms(&argv[1], now_ms);
            store.set_with_abs_expiry(argv[1].clone(), argv[2].clone(), existing_expiry, now_ms);
        }
    }

    if get {
        Ok(RespFrame::BulkString(old_value))
    } else {
        Ok(RespFrame::SimpleString("OK".to_string()))
    }
}

fn get(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("GET"));
    }
    Ok(RespFrame::BulkString(store.get(&argv[1], now_ms)?))
}

fn delete_keys(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    command_name: &'static str,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity(command_name));
    }
    let removed = store.del(&argv[1..], now_ms);
    let removed = i64::try_from(removed).unwrap_or(i64::MAX);
    Ok(RespFrame::Integer(removed))
}

fn incr(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("INCR"));
    }
    let value = store.incr(&argv[1], now_ms)?;
    Ok(RespFrame::Integer(value))
}

#[derive(Debug, Clone, Copy, Default)]
struct ExpireOptions {
    nx: bool,
    xx: bool,
    gt: bool,
    lt: bool,
}

#[derive(Debug, Clone, Copy)]
enum ExpireCommandKind {
    RelativeSeconds,
    RelativeMilliseconds,
    AbsoluteSeconds,
    AbsoluteMilliseconds,
}

fn expire(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    expire_like(
        argv,
        store,
        now_ms,
        ExpireCommandKind::RelativeSeconds,
        "EXPIRE",
    )
}

fn pexpire(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    expire_like(
        argv,
        store,
        now_ms,
        ExpireCommandKind::RelativeMilliseconds,
        "PEXPIRE",
    )
}

fn expireat(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    expire_like(
        argv,
        store,
        now_ms,
        ExpireCommandKind::AbsoluteSeconds,
        "EXPIREAT",
    )
}

fn pexpireat(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    expire_like(
        argv,
        store,
        now_ms,
        ExpireCommandKind::AbsoluteMilliseconds,
        "PEXPIREAT",
    )
}

fn expire_like(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    kind: ExpireCommandKind,
    command_name: &'static str,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity(command_name));
    }
    // (frankenredis-6uyqo) Upstream expire.c::expireGenericCommand
    // calls parseExtendedExpireArgumentsOrReply BEFORE parsing the
    // 'when' integer, so unknown/conflicting NX/XX/GT/LT options
    // surface their dedicated error before any integer-parse error
    // on argv[2]. fr was inverting this, which made
    // `EXPIRE k NOTANINT BADOPT` reply 'value is not an integer or
    // out of range' instead of 'Unsupported option BADOPT'.
    let options = parse_expire_options(&argv[3..])?;
    let raw_time = parse_i64_arg(&argv[2])?;
    // Mirror upstream expire.c::expireGenericCommand which rejects
    // values whose ms-conversion (and basetime addition for relative
    // forms) would overflow LLONG_MAX. (br-frankenredis-expirerange)
    let invalid_expire = || {
        CommandError::Custom(format!(
            "ERR invalid expire time in '{}' command",
            command_name.to_lowercase()
        ))
    };
    let when_ms_signed: Option<i64> = match kind {
        ExpireCommandKind::RelativeSeconds | ExpireCommandKind::AbsoluteSeconds => {
            if !(i64::MIN / 1000..=i64::MAX / 1000).contains(&raw_time) {
                return Err(invalid_expire());
            }
            let ms = raw_time.saturating_mul(1000);
            if matches!(kind, ExpireCommandKind::RelativeSeconds) {
                let now_i = i64::try_from(now_ms).unwrap_or(i64::MAX);
                ms.checked_add(now_i)
            } else {
                Some(ms)
            }
        }
        ExpireCommandKind::RelativeMilliseconds => {
            let now_i = i64::try_from(now_ms).unwrap_or(i64::MAX);
            raw_time.checked_add(now_i)
        }
        ExpireCommandKind::AbsoluteMilliseconds => Some(raw_time),
    };
    if when_ms_signed.is_none() {
        return Err(invalid_expire());
    }
    let when_ms = deadline_from_expire_kind(kind, raw_time, now_ms);
    let applied = apply_expiry_with_options(store, &argv[1], when_ms, now_ms, options);
    Ok(RespFrame::Integer(if applied { 1 } else { 0 }))
}

fn pttl(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("PTTL"));
    }
    let value = match store.pttl(&argv[1], now_ms) {
        PttlValue::KeyMissing => -2,
        PttlValue::NoExpiry => -1,
        PttlValue::Remaining(ms) => ms,
    };
    Ok(RespFrame::Integer(value))
}

fn append(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("APPEND"));
    }
    // (CrimsonHawk) APPEND is a write (lookupKeyWrite + checkType + checkStringLength).
    // The WRONGTYPE check and the checkStringLength (proto-max-bulk-len) cap now live
    // INSIDE store.append, which already materializes the string — so the old separate
    // `string_len_no_stats` probe (a redundant second keyspace lookup) is gone. append is
    // a no-stat write (no keyspace_hits bump), matching the old no-counting probe; the cap
    // error byte string is identical (rendered verbatim via GenericError).
    let new_len = store.append(&argv[1], &argv[2], now_ms)?;
    let new_len = i64::try_from(new_len).unwrap_or(i64::MAX);
    Ok(RespFrame::Integer(new_len))
}

fn strlen(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("STRLEN"));
    }
    let len = store.strlen(&argv[1], now_ms)?;
    let len = i64::try_from(len).unwrap_or(i64::MAX);
    Ok(RespFrame::Integer(len))
}

fn mget(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("MGET"));
    }
    let keys: Vec<&[u8]> = argv[1..].iter().map(Vec::as_slice).collect();
    let values = store.mget(&keys, now_ms);
    let frames = values.into_iter().map(RespFrame::BulkString).collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn mset(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 || !(argv.len() - 1).is_multiple_of(2) {
        return Err(CommandError::WrongArity("MSET"));
    }
    let mut i = 1;
    while i < argv.len() {
        // Use the borrowed plain-SET fast path (no per-pair key/value clones,
        // same full overwrite cleanup as single SET) instead of the owned
        // Store::set. MSET is exactly N independent plain SETs with no TTL, so
        // this is byte-identical while avoiding 2 heap allocations per pair —
        // MSET was ~1.7x slower than redis 7.2.4 purely from that clone churn.
        store.set_plain_borrowed(&argv[i], &argv[i + 1], now_ms);
        i += 2;
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn setnx(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("SETNX"));
    }
    let result = store.setnx(&argv[1], &argv[2], now_ms);
    Ok(RespFrame::Integer(if result { 1 } else { 0 }))
}

fn getset(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("GETSET"));
    }
    let old = store.getset(argv[1].clone(), &argv[2], now_ms)?;
    Ok(RespFrame::BulkString(old))
}

fn incrby(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("INCRBY"));
    }
    let delta = parse_i64_arg(&argv[2])?;
    let value = store.incrby(&argv[1], delta, now_ms)?;
    Ok(RespFrame::Integer(value))
}

fn decrby(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("DECRBY"));
    }
    let delta = parse_i64_arg(&argv[2])?;
    // Upstream t_string.c::decrbyCommand emits the bespoke
    // 'decrement would overflow' wording when the increment is
    // LLONG_MIN (whose negation overflows). All other overflows
    // surface from incrDecrCommand as the generic
    // 'increment or decrement would overflow'. (br-frankenredis-decroverflow)
    let Some(neg_delta) = delta.checked_neg() else {
        return Err(CommandError::Custom(
            "ERR decrement would overflow".to_string(),
        ));
    };
    let value = store.incrby(&argv[1], neg_delta, now_ms)?;
    Ok(RespFrame::Integer(value))
}

fn decr(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("DECR"));
    }
    let value = store.incrby(&argv[1], -1, now_ms)?;
    Ok(RespFrame::Integer(value))
}

fn exists(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("EXISTS"));
    }
    // (frankenredis-fz457) EXISTS is a metadata query that does NOT update
    // access time. Differential probe vs vendored 7.2.4 confirmed OBJECT IDLETIME
    // remains unchanged after EXISTS.
    let mut count = 0_i64;
    for key in &argv[1..] {
        if store.exists_no_touch(key, now_ms) {
            count = count.saturating_add(1);
        }
    }
    Ok(RespFrame::Integer(count))
}

fn ttl(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("TTL"));
    }
    // (frankenredis-cnsmt) Upstream src/expire.c::ttlGenericCommand
    // converts the remaining ms→s with `(ttl + 500) / 1000` (round
    // half-up), so an EXPIRE that was just issued reads back with
    // the original whole-second value even when the wall-clock has
    // already drifted into the millisecond fraction. fr was using
    // plain integer division (floor), which made `TTL k` return
    // `N - 1` immediately after `EXPIRE k N` for any non-zero ms
    // offset.
    let value = match store.pttl(&argv[1], now_ms) {
        PttlValue::KeyMissing => -2,
        PttlValue::NoExpiry => -1,
        PttlValue::Remaining(ms) => ms.saturating_add(500) / 1000,
    };
    Ok(RespFrame::Integer(value))
}

fn expiretime(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("EXPIRETIME"));
    }
    let value = match store.expiretime_value(&argv[1], now_ms) {
        ExpireTimeValue::KeyMissing => -2,
        ExpireTimeValue::NoExpiry => -1,
        ExpireTimeValue::ExpiresAt(abs_ms) => (abs_ms.saturating_add(500) / 1000) as i64,
    };
    Ok(RespFrame::Integer(value))
}

fn pexpiretime(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("PEXPIRETIME"));
    }
    let value = match store.expiretime_value(&argv[1], now_ms) {
        ExpireTimeValue::KeyMissing => -2,
        ExpireTimeValue::NoExpiry => -1,
        ExpireTimeValue::ExpiresAt(abs_ms) => abs_ms as i64,
    };
    Ok(RespFrame::Integer(value))
}

fn persist(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("PERSIST"));
    }
    let removed = store.persist(&argv[1], now_ms);
    Ok(RespFrame::Integer(if removed { 1 } else { 0 }))
}

fn type_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("TYPE"));
    }
    let type_str = store.key_type(&argv[1], now_ms).unwrap_or("none");
    Ok(RespFrame::SimpleString(type_str.to_string()))
}

fn rename(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("RENAME"));
    }
    store
        .rename(&argv[1], &argv[2], now_ms)
        .map_err(|e| match e {
            StoreError::KeyNotFound => CommandError::NoSuchKey,
            other => CommandError::Store(other),
        })?;
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn renamenx(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("RENAMENX"));
    }
    let result = store
        .renamenx(&argv[1], &argv[2], now_ms)
        .map_err(|e| match e {
            StoreError::KeyNotFound => CommandError::NoSuchKey,
            other => CommandError::Store(other),
        })?;
    Ok(RespFrame::Integer(if result { 1 } else { 0 }))
}

fn keys(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("KEYS"));
    }
    // Scope to the dispatch context's selected db. The all-DBs
    // Store::keys_matching primitive is reserved for tooling /
    // tests; calling it here leaked multi-db key names (with raw
    // encode_db_key prefix bytes) into Lua, AOF replay, and MULTI/
    // EXEC paths. Same architectural drift as MOVE/COPY/FLUSHDB.
    // (frankenredis-shbbv)
    let db = store.dispatch_client_ctx.db_index;
    let matched = store.keys_matching_in_db(db, &argv[1], now_ms);
    let frames = matched
        .into_iter()
        .map(|k| RespFrame::BulkString(Some(k)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn dbsize(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("DBSIZE"));
    }
    // Per-DB count. Store::dbsize is the all-DBs primitive (returns
    // entries.len()); the dispatch_argv path must use dbsize_in_db
    // so Lua redis.call('DBSIZE') / AOF replay / MULTI report only
    // the selected db's count. (frankenredis-shbbv)
    let _ = now_ms;
    let db = store.dispatch_client_ctx.db_index;
    let size = store.dbsize_in_db(db);
    let size = i64::try_from(size).unwrap_or(i64::MAX);
    Ok(RespFrame::Integer(size))
}

/// Mirror upstream Redis 7.2 FLUSHDB / FLUSHALL: only ASYNC and
/// SYNC are accepted as the optional flag; any other argument or
/// arity > 2 emits a plain syntax error rather than a wrong-arity
/// reply (matches db.c::flushdbCommand → flushCommandCommon).
/// (br-frankenredis-flushflag)
fn flushdb(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    if argv.len() > 2 || (argv.len() == 2 && !is_flush_mode_arg(&argv[1])) {
        return Err(CommandError::SyntaxError);
    }
    // FLUSHDB is per-DB: clear only the currently-selected db read from the
    // dispatch context. Calling Store::flushdb() here was wrong — that
    // primitive does self.entries.clear() across all DBs (i.e. FLUSHALL
    // semantics despite the name), so Lua redis.call('FLUSHDB'),
    // AOF replay of FLUSHDB records, and MULTI/EXEC FLUSHDB silently
    // wiped unrelated databases. fr-runtime::handle_flushdb_command at
    // fr-runtime/src/lib.rs:10203 already uses flush_database; this
    // mirrors that behavior on the dispatch_argv path.
    // (frankenredis-rdz52)
    store.flush_database(store.dispatch_client_ctx.db_index);
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn flushall(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    if argv.len() > 2 || (argv.len() == 2 && !is_flush_mode_arg(&argv[1])) {
        return Err(CommandError::SyntaxError);
    }
    // FLUSHALL clears every database. Store::flushdb() is the all-DBs
    // primitive (entries.clear()); the misleading name is a pre-existing
    // wart, not a bug at this call site. (frankenredis-rdz52)
    store.flushdb();
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn is_flush_mode_arg(arg: &[u8]) -> bool {
    eq_ascii_command(arg, b"ASYNC") || eq_ascii_command(arg, b"SYNC")
}

fn hset(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 || !(argv.len() - 2).is_multiple_of(2) {
        return Err(CommandError::WrongArity("HSET"));
    }
    let mut added = 0_usize;
    let mut i = 2;
    while i + 1 < argv.len() {
        if store.hset(&argv[1], argv[i].clone(), argv[i + 1].clone(), now_ms)? {
            added += 1;
        }
        i += 2;
    }
    Ok(RespFrame::Integer(i64::try_from(added).unwrap_or(i64::MAX)))
}

