fn lpop(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 || argv.len() > 3 {
        return Err(CommandError::WrongArity("LPOP"));
    }
    if argv.len() == 3 {
        let count = parse_list_pop_count_arg(&argv[2])?;
        let values = match store.lpop_count(&argv[1], count, now_ms)? {
            None => return Ok(RespFrame::Array(None)),
            Some(values) => values,
        };
        let frames = values
            .into_iter()
            .map(|v| RespFrame::BulkString(Some(v)))
            .collect();
        return Ok(RespFrame::Array(Some(frames)));
    }
    let value = store.lpop(&argv[1], now_ms)?;
    Ok(RespFrame::BulkString(value))
}

fn rpop(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 || argv.len() > 3 {
        return Err(CommandError::WrongArity("RPOP"));
    }
    if argv.len() == 3 {
        let count = parse_list_pop_count_arg(&argv[2])?;
        let values = match store.rpop_count(&argv[1], count, now_ms)? {
            None => return Ok(RespFrame::Array(None)),
            Some(values) => values,
        };
        let frames = values
            .into_iter()
            .map(|v| RespFrame::BulkString(Some(v)))
            .collect();
        return Ok(RespFrame::Array(Some(frames)));
    }
    let value = store.rpop(&argv[1], now_ms)?;
    Ok(RespFrame::BulkString(value))
}

fn parse_list_pop_count_arg(arg: &[u8]) -> Result<usize, CommandError> {
    // Upstream t_list.c::popGenericCommand emits the same
    // "value is out of range, must be positive" error for both
    // unparseable integers and explicit-negative counts.
    // (br-frankenredis-lpopary)
    let bad = || CommandError::Custom("ERR value is out of range, must be positive".to_string());
    match parse_i64_arg(arg).map_err(|_| bad())? {
        count if count >= 0 => usize::try_from(count).map_err(|_| bad()),
        _ => Err(bad()),
    }
}

