fn lindex(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("LINDEX"));
    }
    // (frankenredis-lidxorder) Upstream t_list.c::lindexCommand:594-600
    // calls lookupKeyReadOrReply(shared.null) and checkType(OBJ_LIST)
    // BEFORE getLongFromObjectOrReply for the index. fr was performing
    // the existence check but then parsing the index BEFORE the type
    // check, so a non-numeric index on a wrong-type key surfaced
    // "value is not an integer or out of range" instead of upstream's
    // WRONGTYPE. Mirror upstream's order with a key_type probe.
    match store.key_type(&argv[1], now_ms) {
        None => return Ok(RespFrame::BulkString(None)),
        Some("list") => {}
        Some(_) => return Err(CommandError::Store(fr_store::StoreError::WrongType)),
    }
    let index = parse_i64_arg(&argv[2])?;
    let value = store.lindex(&argv[1], index, now_ms)?;
    Ok(RespFrame::BulkString(value))
}

fn lset_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("LSET"));
    }
    // (frankenredis-lsetorder) Upstream t_list.c::lsetCommand:624-630
    // calls lookupKeyWriteOrReply(shared.nokeyerr) and checkType(OBJ_LIST)
    // BEFORE getLongFromObjectOrReply for the index. fr was parsing the
    // index first, so a non-numeric index on a missing key surfaced
    // "value is not an integer or out of range" instead of upstream's
    // "ERR no such key", and on a wrong-type key surfaced the same
    // generic instead of WRONGTYPE.
    // LSET is a write (upstream lookupKeyWriteOrReply), so this nokey/WRONGTYPE
    // precheck must use the NON-counting peek — it must not bump keyspace_hits.
    // (frankenredis-934ax)
    match store.peek_value_type(&argv[1], now_ms) {
        None => return Err(CommandError::NoSuchKey),
        Some(fr_store::ValueType::List) => {}
        Some(_) => return Err(CommandError::Store(fr_store::StoreError::WrongType)),
    }
    // (frankenredis-4zv7a) Upstream t_list.c::listTypeReplaceAtIndex declares
    // its index parameter as a 32-bit `int`, so lsetCommand's parsed 64-bit
    // `long` index is silently truncated to 32 bits before the seek — e.g.
    // LSET at i64::MAX targets index -1 (the last element) and i64::MIN / 2^32
    // target index 0. Mirror that truncation for byte-exact parity; LINDEX et al
    // take a 64-bit index upstream and are unaffected.
    let index = i64::from(parse_i64_arg(&argv[2])? as i32);
    store.lset(&argv[1], index, argv[3].clone(), now_ms)?;
    Ok(RespFrame::SimpleString("OK".to_string()))
}

