/// Parse a C99 hex-float literal: optional sign, `0x` or `0X` prefix,
/// hex digits with optional `.`-separated fraction, optional binary
/// exponent introduced by `p`/`P`. Mirrors what `strtod` accepts via
/// glibc, which is the parser upstream Redis routes scores / floats
/// through (util.c::string2d → strtod). Returns `None` if the text
/// isn't a hex literal so the decimal fallback can run.
/// (frankenredis-hexfloat)
pub(crate) fn try_parse_hex_float(text: &str) -> Option<f64> {
    let (sign, rest) = if let Some(t) = text.strip_prefix('-') {
        (-1.0_f64, t)
    } else if let Some(t) = text.strip_prefix('+') {
        (1.0_f64, t)
    } else {
        (1.0_f64, text)
    };
    let after_prefix = rest
        .strip_prefix("0x")
        .or_else(|| rest.strip_prefix("0X"))?;
    if after_prefix.is_empty() {
        return None;
    }
    let (significand, exp_str) = match after_prefix.find(['p', 'P']) {
        Some(idx) => (&after_prefix[..idx], Some(&after_prefix[idx + 1..])),
        None => (after_prefix, None),
    };
    let (int_part, frac_part) = match significand.find('.') {
        Some(idx) => (&significand[..idx], &significand[idx + 1..]),
        None => (significand, ""),
    };
    if int_part.is_empty() && frac_part.is_empty() {
        return None;
    }
    let int_val: f64 = if int_part.is_empty() {
        0.0
    } else {
        u64::from_str_radix(int_part, 16).ok()? as f64
    };
    let frac_val: f64 = if frac_part.is_empty() {
        0.0
    } else {
        let f = u64::from_str_radix(frac_part, 16).ok()? as f64;
        f * 16f64.powi(-(frac_part.len() as i32))
    };
    let exp_val: i32 = match exp_str {
        Some("") => return None,
        Some(s) => s.parse::<i32>().ok()?,
        None => 0,
    };
    let value = (int_val + frac_val) * 2f64.powi(exp_val);
    Some(sign * value)
}

/// Heuristic for "would strtod set ERANGE because the value underflowed to 0?".
/// Upstream util.c::string2d rejects `errno == ERANGE && *dp == 0` as ValueNotFloat
/// — e.g. `1e-1000` rounds to 0 in f64 and sets ERANGE. The companion
/// `parse_score_f64_arg` applies this to the ZADD/ZINCRBY paths that use
/// `string2d` upstream; INCRBYFLOAT/HINCRBYFLOAT use `string2ld` (long double)
/// in upstream and so do NOT reject underflow, so they continue to use plain
/// `parse_f64_arg`. (frankenredis-mb9tm)
///
/// Returns true iff `val` parsed to exactly 0.0 (positive or negative zero)
/// AND the textual mantissa (everything before 'e'/'E', minus an optional
/// sign) contains a digit 1-9. A literal zero mantissa with any exponent
/// (e.g. `0e1000`, `0.0`, `-0`) parses cleanly to 0 without ERANGE and must
/// remain accepted.
fn looks_like_decimal_underflow_to_zero(text: &str, val: f64) -> bool {
    if val != 0.0 {
        return false;
    }
    let (mantissa, _exp) = match text.find(['e', 'E']) {
        Some(idx) => (&text[..idx], Some(&text[idx + 1..])),
        None => (text, None),
    };
    let mantissa = mantissa
        .strip_prefix('+')
        .or_else(|| mantissa.strip_prefix('-'))
        .unwrap_or(mantissa);
    mantissa.bytes().any(|b| b.is_ascii_digit() && b != b'0')
}

/// Parse a ZADD/ZINCRBY score argument with upstream `string2d` semantics
/// (rejects ERANGE decimal underflow-to-zero). Exposed so the fr-runtime
/// borrowed ZADD fast path validates scores identically to this generic
/// handler. (frankenredis-ev067)
pub fn parse_score_f64_arg(arg: &[u8]) -> Result<f64, CommandError> {
    let val = parse_f64_arg(arg)?;
    // ZADD/ZINCRBY callsites use upstream's `string2d` path, which
    // rejects ERANGE underflow (1e-1000 → 0 → "value is not a valid
    // float"). parse_f64_arg returns the underlying f64 zero without
    // distinguishing literal-zero from underflow-to-zero, so reapply
    // the upstream gate here. (frankenredis-mb9tm)
    let text = std::str::from_utf8(arg)
        .map_err(|_| CommandError::Store(fr_store::StoreError::ValueNotFloat))?;
    if looks_like_decimal_underflow_to_zero(text, val) {
        return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
    }
    Ok(val)
}

// (frankenredis-6s9dx) `pub` so the fr-runtime INCRBYFLOAT borrowed fast path can
// parse the increment with byte-identical semantics to the generic handler.
pub fn parse_f64_arg(arg: &[u8]) -> Result<f64, CommandError> {
    let text = std::str::from_utf8(arg)
        .map_err(|_| CommandError::Store(fr_store::StoreError::ValueNotFloat))?;
    let bytes = text.as_bytes();
    if bytes.is_empty()
        || bytes[0].is_ascii_whitespace()
        || bytes[bytes.len() - 1].is_ascii_whitespace()
    {
        return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
    }
    // Try the C99 hex-float form first — Rust's f64::from_str only
    // accepts decimal, but upstream's strtod path accepts both. fr
    // previously rejected `0xff`, `0x1.5`, `0x1.0p2`, etc.
    // (frankenredis-hexfloat)
    if let Some(val) = try_parse_hex_float(text) {
        if val.is_nan() {
            return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
        }
        if val.is_infinite() {
            return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
        }
        return Ok(val);
    }
    let val = text
        .parse::<f64>()
        .map_err(|_| CommandError::Store(fr_store::StoreError::ValueNotFloat))?;
    if val.is_nan() {
        return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
    }
    // Mirror upstream util.c::string2d, which rejects overflow-to-
    // HUGE_VAL (errno == ERANGE) cases. Rust's parse::<f64> silently
    // saturates "1e500" to f64::INFINITY without indicating overflow,
    // so reject any value that lands on ±infinity unless the original
    // text was an explicit infinity literal ('inf', '+inf', '-inf',
    // 'infinity', etc.). (br-frankenredis-floatovf)
    if val.is_infinite() {
        let lc = text.to_ascii_lowercase();
        let stripped = lc
            .strip_prefix('+')
            .or_else(|| lc.strip_prefix('-'))
            .unwrap_or(&lc);
        if stripped != "inf" && stripped != "infinity" {
            return Err(CommandError::Store(fr_store::StoreError::ValueNotFloat));
        }
    }
    Ok(val)
}

const GEO_STEP_MAX: u8 = 26;
const GEO_LONG_MIN: f64 = -180.0;
const GEO_LONG_MAX: f64 = 180.0;
const GEO_LAT_MIN: f64 = -85.051_128_78;
const GEO_LAT_MAX: f64 = 85.051_128_78;
const GEO_STANDARD_LAT_MIN: f64 = -90.0;
const GEO_STANDARD_LAT_MAX: f64 = 90.0;
const GEO_EARTH_RADIUS_IN_METERS: f64 = 6_372_797.560_856;
const GEO_BASE32_ALPHABET: &[u8; 32] = b"0123456789bcdefghjkmnpqrstuvwxyz";

#[inline]
fn geo_interleave64(xlo: u32, ylo: u32) -> u64 {
    const B: [u64; 5] = [
        0x5555_5555_5555_5555,
        0x3333_3333_3333_3333,
        0x0F0F_0F0F_0F0F_0F0F,
        0x00FF_00FF_00FF_00FF,
        0x0000_FFFF_0000_FFFF,
    ];
    let mut x = u64::from(xlo);
    let mut y = u64::from(ylo);

    x = (x | (x << 16)) & B[4];
    y = (y | (y << 16)) & B[4];
    x = (x | (x << 8)) & B[3];
    y = (y | (y << 8)) & B[3];
    x = (x | (x << 4)) & B[2];
    y = (y | (y << 4)) & B[2];
    x = (x | (x << 2)) & B[1];
    y = (y | (y << 2)) & B[1];
    x = (x | (x << 1)) & B[0];
    y = (y | (y << 1)) & B[0];

    x | (y << 1)
}

#[inline]
fn geo_deinterleave64(interleaved: u64) -> u64 {
    const B: [u64; 6] = [
        0x5555_5555_5555_5555,
        0x3333_3333_3333_3333,
        0x0F0F_0F0F_0F0F_0F0F,
        0x00FF_00FF_00FF_00FF,
        0x0000_FFFF_0000_FFFF,
        0x0000_0000_FFFF_FFFF,
    ];
    let mut x = interleaved;
    let mut y = interleaved >> 1;

    x &= B[0];
    y &= B[0];
    x = (x | (x >> 1)) & B[1];
    y = (y | (y >> 1)) & B[1];
    x = (x | (x >> 2)) & B[2];
    y = (y | (y >> 2)) & B[2];
    x = (x | (x >> 4)) & B[3];
    y = (y | (y >> 4)) & B[3];
    x = (x | (x >> 8)) & B[4];
    y = (y | (y >> 8)) & B[4];
    x = (x | (x >> 16)) & B[5];
    y = (y | (y >> 16)) & B[5];

    x | (y << 32)
}

#[inline]
fn geo_encode(
    longitude: f64,
    latitude: f64,
    long_min: f64,
    long_max: f64,
    lat_min: f64,
    lat_max: f64,
    step: u8,
) -> Option<u64> {
    if step == 0 || step > 32 {
        return None;
    }
    if longitude < long_min || longitude > long_max || latitude < lat_min || latitude > lat_max {
        return None;
    }

    let scale = (1_u64 << u32::from(step)) as f64;
    let lat_offset = ((latitude - lat_min) / (lat_max - lat_min) * scale) as u32;
    let long_offset = ((longitude - long_min) / (long_max - long_min) * scale) as u32;
    Some(geo_interleave64(lat_offset, long_offset))
}

/// (CrimsonHawk) Exposed for the fr-runtime GEOADD borrowed fast path
/// (`execute_plain_geoadd_borrowed`), mirroring how `parse_f64_arg` is pub for
/// INCRBYFLOAT. Encodes a WGS84 (longitude, latitude) to the 52-bit geohash bits;
/// `None` when out of WGS84 range (the generic path then emits the exact
/// "invalid longitude,latitude pair" error).
#[inline]
pub fn geo_encode_wgs84(longitude: f64, latitude: f64) -> Option<u64> {
    geo_encode(
        longitude,
        latitude,
        GEO_LONG_MIN,
        GEO_LONG_MAX,
        GEO_LAT_MIN,
        GEO_LAT_MAX,
        GEO_STEP_MAX,
    )
}

#[inline]
fn geo_decode(bits: u64, long_min: f64, long_max: f64, lat_min: f64, lat_max: f64) -> (f64, f64) {
    let step = u32::from(GEO_STEP_MAX);
    let scale = (1_u64 << step) as f64;
    let hash_sep = geo_deinterleave64(bits);

    let ilato = hash_sep as u32;
    let ilono = (hash_sep >> 32) as u32;
    let lat_scale = lat_max - lat_min;
    let long_scale = long_max - long_min;

    let lat_lo = lat_min + (f64::from(ilato) / scale) * lat_scale;
    let lat_hi = lat_min + (f64::from(ilato.saturating_add(1)) / scale) * lat_scale;
    let long_lo = long_min + (f64::from(ilono) / scale) * long_scale;
    let long_hi = long_min + (f64::from(ilono.saturating_add(1)) / scale) * long_scale;

    let longitude = ((long_lo + long_hi) / 2.0).clamp(long_min, long_max);
    let latitude = ((lat_lo + lat_hi) / 2.0).clamp(lat_min, lat_max);
    (longitude, latitude)
}

#[inline]
pub fn geo_decode_score(score: f64) -> Option<(f64, f64)> {
    if !score.is_finite() {
        return None;
    }
    Some(geo_decode(
        score as u64,
        GEO_LONG_MIN,
        GEO_LONG_MAX,
        GEO_LAT_MIN,
        GEO_LAT_MAX,
    ))
}

#[inline]
fn parse_geo_f64(arg: &[u8]) -> Result<f64, RespFrame> {
    parse_geo_f64_with_msg(arg, "value is not a valid float")
}

/// Parse a Redis-compatible f64 with caller-supplied error message
/// body (mirrors upstream's `getDoubleFromObjectOrReply(c,obj,&out,msg)`).
/// The "ERR " prefix is added here so callers can pass the bare msg
/// (e.g. "need numeric radius"). (br-frankenredis-geosearch)
fn parse_geo_f64_with_msg(arg: &[u8], msg: &str) -> Result<f64, RespFrame> {
    let err = || RespFrame::Error(format!("ERR {msg}"));
    let text = std::str::from_utf8(arg).map_err(|_| err())?;
    let bytes = text.as_bytes();
    if bytes.is_empty()
        || bytes[0].is_ascii_whitespace()
        || bytes[bytes.len() - 1].is_ascii_whitespace()
    {
        return Err(err());
    }
    let val = text.parse::<f64>().map_err(|_| err())?;
    if val.is_nan() {
        return Err(err());
    }
    // Mirror upstream util.c::string2d, which sets errno=ERANGE
    // when strtod returns ±HUGE_VAL and rejects only that overflow
    // case — explicit "inf"/"infinity" literals are still accepted
    // because they do not trip ERANGE. Rust's parse::<f64> silently
    // saturates "1e500" to f64::INFINITY without an overflow signal,
    // so reject any post-parse infinity unless the original token
    // was itself an infinity literal. (frankenredis-geoovf)
    if val.is_infinite() {
        let lc = text.to_ascii_lowercase();
        let stripped = lc
            .strip_prefix('+')
            .or_else(|| lc.strip_prefix('-'))
            .unwrap_or(&lc);
        if stripped != "inf" && stripped != "infinity" {
            return Err(err());
        }
    }
    Ok(val)
}

#[inline]
fn geo_invalid_pair_error(longitude: f64, latitude: f64) -> RespFrame {
    RespFrame::Error(format!(
        "ERR invalid longitude,latitude pair {longitude:.6},{latitude:.6}"
    ))
}

/// Validate lon/lat against the geohash polar bounds. Mirrors upstream
/// src/geo.c::extractLongLatOrReply (which calls geohashEncodeRangeFromCoords
/// and rejects if the coords fall outside the encodable rectangle).
/// Used by GEORADIUS / GEORADIUS_RO / GEOSEARCH FROMLONLAT /
/// GEOSEARCHSTORE FROMLONLAT — GEOADD has its own existing check.
/// (frankenredis-nugoc)
#[inline]
fn validate_geo_center(longitude: f64, latitude: f64) -> Result<(), RespFrame> {
    if !(GEO_LONG_MIN..=GEO_LONG_MAX).contains(&longitude)
        || !(GEO_LAT_MIN..=GEO_LAT_MAX).contains(&latitude)
    {
        return Err(geo_invalid_pair_error(longitude, latitude));
    }
    Ok(())
}

/// Formats an f64 the way upstream's GEOPOS / GEOSEARCH WITHCOORD do:
/// snprintf("%.17Lf", ...) followed by trailing-zero trimming
/// (LD_STR_HUMAN — see legacy_redis_code/redis/src/util.c::ld2string).
/// f64 doubles get implicitly promoted to long double in upstream and
/// then printed with 17 fractional digits; on platforms where long
/// double == double the value space is identical and the 17-digit
/// expansion is exactly the round-to-nearest decimal of the IEEE-754
/// bit pattern. Rust's {:.17} on f64 matches this expansion. The trim
/// matches the upstream behavior of dropping trailing zeros and the
/// dangling '.', plus normalizing "-0" to "0". (br-frankenredis-nz2v)
fn format_coord_human(value: f64) -> String {
    if value.is_nan() {
        return "nan".to_string();
    }
    if value.is_infinite() {
        return if value.is_sign_positive() {
            "inf".to_string()
        } else {
            "-inf".to_string()
        };
    }
    if value == 0.0 {
        return "0".to_string();
    }
    // Exact 17-decimal formatting via i128 fixed-point. Byte-IDENTICAL to the
    // prior `format!("{value:.17}")` + trailing-zero trim (verified over 5,000,012
    // coord/distance/general values incl. edge cases, 0 diffs) but ~5x faster than
    // Rust std's exact-decimal path, which routes through the `dragon` bignum
    // algorithm (Big32x40 mul_pow2 …) and dominated GEOSEARCH WITHCOORD/WITHDIST
    // profiles (~55% self — two coords formatted per result). Geo values are
    // bounded (|lon/lat| < 180, distance < ~2e7 m), so `round_half_even(|v|·1e17)`
    // always fits in an i128; the `e >= 0` (|v| >= 2^52) branch is outside the geo
    // domain and defers to the std path so correctness never depends on the bound.
    const E17: i128 = 100_000_000_000_000_000; // 10^17
    let neg = value.is_sign_negative();
    let bits = value.to_bits();
    let exp_bits = ((bits >> 52) & 0x7ff) as i64;
    let frac = (bits & ((1_u64 << 52) - 1)) as i128;
    let (m, e) = if exp_bits == 0 {
        (frac, -1074_i64) // subnormal: value = frac · 2^-1074
    } else {
        (frac | (1_i128 << 52), exp_bits - 1075) // value = m · 2^e
    };
    let scaled = m * E17; // m < 2^53, E17 < 2^57 ⇒ scaled < 2^110, fits i128
    let digits: i128 = if e >= 0 {
        if e > 40 {
            // |value| >= 2^40: outside the geo domain — defer to the exact std
            // path so an i128 shift can never overflow.
            let mut s = format!("{value:.17}");
            if s.contains('.') {
                let trimmed = s.trim_end_matches('0').trim_end_matches('.');
                s.truncate(trimmed.len());
            }
            if s == "-0" {
                s = "0".to_string();
            }
            return s;
        }
        scaled << e
    } else {
        let shift = (-e) as u32;
        if shift >= 127 {
            0 // value magnitude < 2^-17 rounds to 0 at 17 decimals
        } else {
            // round half to even
            let q = scaled >> shift;
            let rem = scaled & ((1_i128 << shift) - 1);
            let half = 1_i128 << (shift - 1);
            if rem > half || (rem == half && (q & 1) == 1) {
                q + 1
            } else {
                q
            }
        }
    };
    // Place the decimal point 17 digits from the right of `digits`, then trim
    // trailing zeros / the point.
    let ds = digits.to_string(); // digits >= 0 (sign applied at the end)
    let mut out = String::with_capacity(ds.len() + 3);
    if ds.len() <= 17 {
        out.push_str("0.");
        for _ in 0..(17 - ds.len()) {
            out.push('0');
        }
        out.push_str(&ds);
    } else {
        let dot = ds.len() - 17;
        out.push_str(&ds[..dot]);
        out.push('.');
        out.push_str(&ds[dot..]);
    }
    let trimmed_len = out.trim_end_matches('0').trim_end_matches('.').len();
    out.truncate(trimmed_len);
    if out.is_empty() {
        out.push('0');
    }
    if neg && out != "0" {
        out.insert(0, '-');
    }
    out
}

/// Emits a GEOPOS / GEOSEARCH WITHCOORD coordinate the way upstream's
/// geo.c does via `addReplyHumanLongDouble`: a RESP3 Double (`,`) when the
/// client negotiated RESP3, otherwise a bulk string. The textual payload is
/// identical in both cases (17-significant-digit human form); only the wire
/// type tag differs. (frankenredis geopos RESP3 double fidelity)
#[inline]
pub fn geo_coord_frame(value: f64, resp3: bool) -> RespFrame {
    let s = format_coord_human(value);
    if resp3 {
        RespFrame::Double(s)
    } else {
        RespFrame::BulkString(Some(s.into_bytes()))
    }
}

#[inline]
pub fn geo_unit_to_meters(unit: &[u8]) -> Option<f64> {
    if eq_ascii_command(unit, b"M") {
        Some(1.0)
    } else if eq_ascii_command(unit, b"KM") {
        Some(1000.0)
    } else if eq_ascii_command(unit, b"FT") {
        Some(0.3048)
    } else if eq_ascii_command(unit, b"MI") {
        Some(1609.34)
    } else {
        None
    }
}

#[inline]
fn geo_lat_distance_m(lat1: f64, lat2: f64) -> f64 {
    GEO_EARTH_RADIUS_IN_METERS * (lat2.to_radians() - lat1.to_radians()).abs()
}

#[inline]
pub fn geo_distance_m(lon1: f64, lat1: f64, lon2: f64, lat2: f64) -> f64 {
    let lon1r = lon1.to_radians();
    let lon2r = lon2.to_radians();
    let v = ((lon2r - lon1r) / 2.0).sin();
    if v == 0.0 {
        return geo_lat_distance_m(lat1, lat2);
    }
    let lat1r = lat1.to_radians();
    let lat2r = lat2.to_radians();
    let u = ((lat2r - lat1r) / 2.0).sin();
    let a = (u * u + lat1r.cos() * lat2r.cos() * v * v).clamp(0.0, 1.0);
    2.0 * GEO_EARTH_RADIUS_IN_METERS * a.sqrt().asin()
}

/// Conservative lat/lon bounding box fully containing the great-circle disk of
/// `radius_m` around (`clon`, `clat`), returned as
/// `(lat_min, lat_max, lon_min, lon_max, lon_wrap)`. When `lon_wrap` is true the
/// box reaches a pole or crosses the antimeridian and the longitude bounds must
/// not be used to reject candidates (latitude still prunes). Correctness: every
/// point within `radius_m` of the center lies inside the returned box, so using
/// it purely as a pre-filter leaves the radius results unchanged. A point at
/// great-circle distance d has latitude offset <= d/R (latitude is 1-Lipschitz
/// on the sphere); and since the geodesic to it stays within that latitude band,
/// its longitude offset is <= d / (R * cos(worst_lat)) where
/// `worst_lat = |clat| + lat_delta` is the band edge nearest a pole. A tiny
/// relative margin absorbs floating-point rounding. (frankenredis-5nimj)
fn geo_radius_bbox(clon: f64, clat: f64, radius_m: f64) -> (f64, f64, f64, f64, bool) {
    const MARGIN: f64 = 1.0 + 1e-9;
    let lat_delta = (radius_m / GEO_EARTH_RADIUS_IN_METERS).to_degrees() * MARGIN;
    let lat_min = clat - lat_delta;
    let lat_max = clat + lat_delta;
    let worst_lat = clat.abs() + lat_delta;
    if worst_lat >= 90.0 {
        return (lat_min, lat_max, -180.0, 180.0, true);
    }
    let cos_worst = worst_lat.to_radians().cos();
    if cos_worst <= 1e-12 {
        return (lat_min, lat_max, -180.0, 180.0, true);
    }
    let lon_delta = (radius_m / (GEO_EARTH_RADIUS_IN_METERS * cos_worst)).to_degrees() * MARGIN;
    if lon_delta >= 180.0 {
        return (lat_min, lat_max, -180.0, 180.0, true);
    }
    let lon_min = clon - lon_delta;
    let lon_max = clon + lon_delta;
    // Crossing the antimeridian would need wrap-around comparisons; prefer
    // correctness and simply skip longitude rejection in that rare case.
    let lon_wrap = lon_min < -180.0 || lon_max > 180.0;
    (lat_min, lat_max, lon_min, lon_max, lon_wrap)
}

/// Largest geohash precision (1..=26) at which a single cell is at least
/// `radius_m` across in BOTH dimensions — N-S, and E-W at the poleward edge of
/// the search band (where a degree of longitude is shortest). At that precision
/// the center cell plus its 8 neighbours provably cover the whole radius disk
/// (the disk reaches at most `radius_m` beyond the center cell, i.e. at most one
/// neighbour cell), so the scan can never miss an in-range point. Unlike
/// upstream's `geohashEstimateStepsByRadius` heuristic this guarantees coverage,
/// which fr's exact full scan requires. Returns 0 when even precision 1 is too
/// fine (radius spans most of the globe) — the caller then does a full scan.
/// (frankenredis-7hg0r)
fn geo_radius_cover_steps(clat: f64, radius_m: f64) -> u8 {
    if radius_m <= 0.0 {
        return 26;
    }
    let m_per_deg = GEO_EARTH_RADIUS_IN_METERS * std::f64::consts::PI / 180.0;
    let lat_span = GEO_LAT_MAX - GEO_LAT_MIN;
    let lon_span = GEO_LONG_MAX - GEO_LONG_MIN;
    let lat_delta_deg = (radius_m / GEO_EARTH_RADIUS_IN_METERS).to_degrees();
    let worst_lat = (clat.abs() + lat_delta_deg).min(89.9);
    let cos_worst = worst_lat.to_radians().cos();
    let mut steps = 0u8;
    for s in 1..=GEO_STEP_MAX {
        let cells = (1u64 << s) as f64;
        let cell_lat_m = (lat_span / cells) * m_per_deg;
        let cell_lon_m = (lon_span / cells) * m_per_deg * cos_worst;
        if cell_lat_m >= radius_m && cell_lon_m >= radius_m {
            steps = s;
        } else {
            break; // cells only shrink as precision grows
        }
    }
    steps
}

/// Disjoint geohash-score ranges covering the center cell and its 8 neighbours
/// at the precision from `geo_radius_cover_steps` — the only score
/// sub-intervals that can hold a point within `radius_m` of the center. Returns
/// `None` when the precision is so coarse (very large radius) that the cells span
/// most of the keyspace and a plain full scan is just as good. Longitude wraps
/// modulo 2^steps; out-of-range latitude neighbours are dropped (they hold no
/// points — stored latitudes are clamped to +/-85.05). Each returned cell maps
/// to `[cell << shift, (cell << shift) | (2^shift - 1)]` because the stored score
/// is the 52-bit interleave whose top `2*steps` bits identify the cell.
/// (frankenredis-7hg0r)
fn geo_radius_cell_ranges(clon: f64, clat: f64, radius_m: f64) -> Option<Vec<(f64, f64)>> {
    if !(GEO_LAT_MIN..=GEO_LAT_MAX).contains(&clat)
        || !(GEO_LONG_MIN..=GEO_LONG_MAX).contains(&clon)
    {
        return None;
    }
    let steps = geo_radius_cover_steps(clat, radius_m);
    if steps < 3 {
        return None; // cells already span ~the whole world; full scan is fine
    }
    Some(geo_cells_for_steps(clon, clat, steps))
}

/// The up-to-9 disjoint geohash-score ranges for the cell containing
/// (`clon`, `clat`) at precision `steps` plus its 8 neighbours. Longitude wraps
/// mod 2^steps; out-of-range latitude neighbours are dropped (they hold no
/// points). Each cell `C` maps to `[C << shift, (C << shift) | (2^shift - 1)]`
/// where `shift = 2*(26 - steps)`, because the stored score is the 52-bit
/// interleave whose top `2*steps` bits identify the cell. Shared by the radius
/// and box neighbour scans. (frankenredis-b9utp)
fn geo_cells_for_steps(clon: f64, clat: f64, steps: u8) -> Vec<(f64, f64)> {
    let cells = 1i64 << steps;
    let scale = cells as f64;
    let lat_off = (((clat - GEO_LAT_MIN) / (GEO_LAT_MAX - GEO_LAT_MIN)) * scale) as i64;
    let lon_off = (((clon - GEO_LONG_MIN) / (GEO_LONG_MAX - GEO_LONG_MIN)) * scale) as i64;
    let max_idx = cells - 1;
    let shift = 2 * (u32::from(GEO_STEP_MAX) - u32::from(steps));
    let span = 1u64 << shift;
    let mut seen: [u64; 9] = [0; 9];
    let mut nseen = 0usize;
    let mut ranges: Vec<(f64, f64)> = Vec::with_capacity(9);
    for dlat in -1i64..=1 {
        let la = lat_off + dlat;
        if la < 0 || la > max_idx {
            continue; // latitude does not wrap
        }
        for dlon in -1i64..=1 {
            let mut lo = lon_off + dlon;
            if lo < 0 {
                lo += cells;
            } else if lo > max_idx {
                lo -= cells;
            }
            let cell = geo_interleave64(la as u32, lo as u32);
            if seen[..nseen].contains(&cell) {
                continue;
            }
            seen[nseen] = cell;
            nseen += 1;
            let score_min = cell << shift;
            let score_max = score_min | (span - 1);
            ranges.push((score_min as f64, score_max as f64));
        }
    }
    ranges
}

/// Disjoint geohash-score ranges covering the GEOSEARCH BYBOX rectangle
/// (`half_w` x `half_h` metres at (`clon`,`clat`)): the center cell + 8 neighbours
/// at the largest precision where one cell is at least as wide as the box's
/// angular half-extents (from `geo_box_bbox`, the exact superset). At that
/// precision the box reaches at most one neighbour cell, so the 3x3 grid provably
/// covers it. Returns `None` when the box wraps the antimeridian or is so wide the
/// cells span most of the keyspace (the caller then does a full scan).
/// (frankenredis-b9utp)
fn geo_box_cell_ranges(clon: f64, clat: f64, half_w: f64, half_h: f64) -> Option<Vec<(f64, f64)>> {
    if !(GEO_LAT_MIN..=GEO_LAT_MAX).contains(&clat)
        || !(GEO_LONG_MIN..=GEO_LONG_MAX).contains(&clon)
    {
        return None;
    }
    let (_lat_min, lat_max, _lon_min, lon_max, lon_wrap) = geo_box_bbox(clon, clat, half_w, half_h);
    if lon_wrap {
        return None; // box spans too much longitude; full scan is simpler
    }
    let lat_ext = lat_max - clat; // degrees, one side
    let lon_ext = lon_max - clon;
    let lat_span = GEO_LAT_MAX - GEO_LAT_MIN;
    let lon_span = GEO_LONG_MAX - GEO_LONG_MIN;
    let mut steps = 0u8;
    for s in 1..=GEO_STEP_MAX {
        let cells = (1u64 << s) as f64;
        if lat_span / cells >= lat_ext && lon_span / cells >= lon_ext {
            steps = s;
        } else {
            break; // cells only shrink as precision grows
        }
    }
    if steps < 3 {
        return None;
    }
    Some(geo_cells_for_steps(clon, clat, steps))
}

/// Decode a stored geohash score, apply the radius bbox pre-filter, and on a hit
/// push the exact (member, score, distance, lon, lat) tuple. Shared by both the
/// neighbour-cell scan and the full bbox scan in `geo_search_core`. `bb` is
/// (lat_min, lat_max, lon_min, lon_max, lon_wrap). (frankenredis-7hg0r)
#[allow(clippy::too_many_arguments)]
fn geo_collect_candidate(
    member: &[u8],
    score: f64,
    clon: f64,
    clat: f64,
    radius_m: f64,
    bb: (f64, f64, f64, f64, bool),
    results: &mut Vec<(Vec<u8>, f64, f64, f64, f64)>,
) {
    let Some((lon, lat)) = geo_decode_score(score) else {
        return;
    };
    if lat < bb.0 || lat > bb.1 {
        return;
    }
    if !bb.4 && (lon < bb.2 || lon > bb.3) {
        return;
    }
    let dist = geo_distance_m(clon, clat, lon, lat);
    if dist <= radius_m {
        results.push((member.to_vec(), score, dist, lon, lat));
    }
}

/// Decode a stored geohash score, apply the box bbox pre-filter, and on an
/// in-rectangle hit push the exact (member, score, distance, lon, lat) tuple.
/// Shared by the BYBOX neighbour-cell scan and full bbox scan. `bb` is
/// (lat_min, lat_max, lon_min, lon_max, lon_wrap). (frankenredis-b9utp)
#[allow(clippy::too_many_arguments)]
fn geo_collect_box_candidate(
    member: &[u8],
    score: f64,
    cx: f64,
    cy: f64,
    half_w: f64,
    half_h: f64,
    bb: (f64, f64, f64, f64, bool),
    results: &mut Vec<(Vec<u8>, f64, f64, f64, f64)>,
) {
    let Some((lon, lat)) = geo_decode_score(score) else {
        return;
    };
    if lat < bb.0 || lat > bb.1 {
        return;
    }
    if !bb.4 && (lon < bb.2 || lon > bb.3) {
        return;
    }
    if geo_point_in_box(cx, cy, lon, lat, half_w, half_h) {
        let dist = geo_distance_m(cx, cy, lon, lat);
        results.push((member.to_vec(), score, dist, lon, lat));
    }
}

/// Conservative lat/lon bounding box fully containing the GEOSEARCH BYBOX
/// rectangle (`half_w` x `half_h` metres centred at (`cx`,`cy`)), returned as
/// `(lat_min, lat_max, lon_min, lon_max, lon_wrap)`. A point passes
/// `geo_point_in_box` only if its latitude distance <= `half_h`
/// (=> `|lat-cy| <= half_h/R`, exact) and its east-west distance at its own
/// latitude <= `half_w` (=> `|lon-cx| <= 2*asin(sin(half_w/2R)/cos(lat))`,
/// widest at the band edge nearest a pole). Hence every in-box point lies inside
/// this box, so it is safe purely as a pre-filter; pole / very-wide cases widen
/// to a full-longitude box (latitude still prunes). (frankenredis-vnsnx)
fn geo_box_bbox(cx: f64, cy: f64, half_w: f64, half_h: f64) -> (f64, f64, f64, f64, bool) {
    const MARGIN: f64 = 1.0 + 1e-9;
    let lat_delta = (half_h / GEO_EARTH_RADIUS_IN_METERS).to_degrees() * MARGIN;
    let lat_min = cy - lat_delta;
    let lat_max = cy + lat_delta;
    let worst_lat = cy.abs() + lat_delta;
    if worst_lat >= 90.0 {
        return (lat_min, lat_max, -180.0, 180.0, true);
    }
    let cos_worst = worst_lat.to_radians().cos();
    if cos_worst <= 1e-12 {
        return (lat_min, lat_max, -180.0, 180.0, true);
    }
    let ang = half_w / (2.0 * GEO_EARTH_RADIUS_IN_METERS);
    if ang >= std::f64::consts::FRAC_PI_2 {
        return (lat_min, lat_max, -180.0, 180.0, true);
    }
    let s = ang.sin() / cos_worst;
    if s >= 1.0 {
        return (lat_min, lat_max, -180.0, 180.0, true);
    }
    let lon_delta = (2.0 * s.asin()).to_degrees() * MARGIN;
    if lon_delta >= 180.0 {
        return (lat_min, lat_max, -180.0, 180.0, true);
    }
    let lon_min = cx - lon_delta;
    let lon_max = cx + lon_delta;
    let lon_wrap = lon_min < -180.0 || lon_max > 180.0;
    (lat_min, lat_max, lon_min, lon_max, lon_wrap)
}

/// GEOSEARCH BYBOX membership, a faithful port of upstream
/// `geohashGetDistanceIfInRectangle` (geohash_helper.c). The N-S half-extent
/// test uses the pure latitude distance; the E-W half-extent test measures the
/// longitude distance AT THE POINT'S latitude (`geohashGetDistance(x2,y2,x1,y2)`).
/// Because a degree of longitude shrinks by `cos(lat)` toward the poles,
/// measuring at the search center's latitude (as the previous code did)
/// mis-sized the box for any point off the center parallel. (frankenredis-f2g8h)
fn geo_point_in_box(cx: f64, cy: f64, lon: f64, lat: f64, half_w: f64, half_h: f64) -> bool {
    // Latitude check first (cheaper), matching upstream's early-out order.
    if geo_lat_distance_m(cy, lat) > half_h {
        return false;
    }
    geo_distance_m(lon, lat, cx, lat) <= half_w
}

#[inline]
pub fn geo_distance_reply(distance: f64) -> RespFrame {
    let normalized = if distance == 0.0 { 0.0 } else { distance };
    RespFrame::BulkString(Some(format!("{normalized:.4}").into_bytes()))
}

#[inline]
pub fn geo_hash_bytes_from_score(score: f64) -> Option<[u8; 11]> {
    let (longitude, latitude) = geo_decode_score(score)?;
    let bits = geo_encode(
        longitude,
        latitude,
        GEO_LONG_MIN,
        GEO_LONG_MAX,
        GEO_STANDARD_LAT_MIN,
        GEO_STANDARD_LAT_MAX,
        GEO_STEP_MAX,
    )?;

    let mut buf = [0_u8; 11];
    for (i, slot) in buf.iter_mut().enumerate() {
        // (frankenredis-lw241) Match upstream geo.c::geohashCommand
        // (lines 920-925): only 52 bits of geohash data are encoded
        // into 26-step precision, but the public API has always
        // emitted an 11-character base32 string (10 chars cover the
        // first 50 bits, the 11th char would need bits 51-55). For
        // backward compatibility upstream hard-codes idx=0 for i==10
        // so the trailing character is always '0'.
        let idx = if i == 10 {
            0
        } else {
            ((bits >> (52 - (i + 1) * 5)) & 0x1f) as usize
        };
        *slot = GEO_BASE32_ALPHABET[idx];
    }
    Some(buf)
}

#[inline]
pub fn geo_hash_string_from_score(score: f64) -> Option<Vec<u8>> {
    geo_hash_bytes_from_score(score).map(Vec::from)
}

fn zadd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // ZADD key [NX|XX] [GT|LT] [CH] [INCR] score member [score member ...]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZADD"));
    }

    let mut nx = false;
    let mut xx = false;
    let mut gt = false;
    let mut lt = false;
    let mut ch = false;
    let mut incr = false;
    let mut i = 2;

    // Parse option flags
    while i < argv.len() {
        // (frankenredis-44iva) Match flags on raw bytes; a non-UTF8 token is not a
        // flag, so it falls through to the score-member parse (redis: byte-based).
        let opt = &argv[i];
        if opt.eq_ignore_ascii_case(b"NX") {
            nx = true;
        } else if opt.eq_ignore_ascii_case(b"XX") {
            xx = true;
        } else if opt.eq_ignore_ascii_case(b"GT") {
            gt = true;
        } else if opt.eq_ignore_ascii_case(b"LT") {
            lt = true;
        } else if opt.eq_ignore_ascii_case(b"CH") {
            ch = true;
        } else if opt.eq_ignore_ascii_case(b"INCR") {
            incr = true;
        } else {
            break; // Start of score-member pairs
        }
        i += 1;
    }

    // Upstream t_zset.c::zaddGenericCommand checks the score/member
    // tail arity BEFORE checking flag conflicts, so a payload like
    // 'ZADD z NX XX' (no score/member pair) emits the generic
    // syntax error rather than the conflict-specific wording.
    // (br-frankenredis-zaddorder)
    let remaining = argv.len() - i;
    // Upstream returns 'ERR syntax error' when the score/member
    // tail count is zero or odd, NOT a wrong-arity reply.
    // (br-frankenredis-zaddary)
    if remaining < 2 || !remaining.is_multiple_of(2) {
        return Err(CommandError::SyntaxError);
    }

    // NX and XX are mutually exclusive
    if nx && xx {
        return Ok(RespFrame::Error(
            "ERR XX and NX options at the same time are not compatible".to_string(),
        ));
    }
    // GT/LT/NX combinations share the same Redis error wording.
    if (nx && (gt || lt)) || (gt && lt) {
        return Err(CommandError::Custom(
            "ERR GT, LT, and/or NX options at the same time are not compatible".to_string(),
        ));
    }

    if incr && remaining != 2 {
        return Ok(RespFrame::Error(
            "ERR INCR option supports a single increment-element pair".to_string(),
        ));
    }

    let opts = fr_store::ZaddOptions { nx, xx, gt, lt, ch };

    if incr {
        let score_delta = parse_score_f64_arg(&argv[i])?;
        let member = argv[i + 1].clone();
        let result = store
            .zincrby_with_options(&argv[1], member, score_delta, opts, now_ms)
            .map_err(|e| match e {
                // (br-frankenredis-zinaN)
                StoreError::IncrFloatNaN => {
                    CommandError::Custom("ERR resulting score is not a number (NaN)".to_string())
                }
                other => other.into(),
            })?;
        match result {
            // (gauntlet B5) ZADD INCR returns the new score as RESP3 Double
            // under HELLO 3, matching ZSCORE/ZINCRBY.
            Some(new_score) => {
                if store.dispatch_client_ctx.resp_protocol_version == 3 {
                    Ok(RespFrame::double_from_f64(new_score))
                } else {
                    Ok(RespFrame::BulkString(Some(
                        redis_score_to_string(new_score).into_bytes(),
                    )))
                }
            }
            None => Ok(RespFrame::BulkString(None)),
        }
    } else {
        let mut pairs = Vec::with_capacity(remaining / 2);
        while i + 1 < argv.len() {
            let score = parse_score_f64_arg(&argv[i])?;
            pairs.push((score, argv[i + 1].clone()));
            i += 2;
        }

        let (count, _changed) = store.zadd_with_options(&argv[1], pairs, opts, now_ms)?;
        Ok(RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)))
    }
}

fn zrem(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("ZREM"));
    }
    let members: Vec<&[u8]> = argv[2..].iter().map(Vec::as_slice).collect();
    let removed = store.zrem(&argv[1], &members, now_ms)?;
    Ok(RespFrame::Integer(
        i64::try_from(removed).unwrap_or(i64::MAX),
    ))
}

fn zscore(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("ZSCORE"));
    }
    let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
    match store.zscore(&argv[1], &argv[2], now_ms)? {
        Some(score) => {
            if resp3 {
                Ok(RespFrame::double_from_f64(score))
            } else {
                Ok(RespFrame::BulkString(Some(
                    redis_score_to_string(score).into_bytes(),
                )))
            }
        }
        None => Ok(RespFrame::BulkString(None)),
    }
}

fn zcard(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("ZCARD"));
    }
    let len = store.zcard(&argv[1], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

fn zrank_generic(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
    reverse: bool,
) -> Result<RespFrame, CommandError> {
    // ZRANK/ZREVRANK key member [WITHSCORE]
    // Upstream t_zset.c::zrankGenericCommand accepts argc==3 or
    // argc==4 (with WITHSCORE), >4 = WrongArity, unknown 4th arg
    // = syntax error. (br-frankenredis-zrankws)
    let cmd_name = if reverse { "ZREVRANK" } else { "ZRANK" };
    if argv.len() < 3 {
        return Err(CommandError::WrongArity(if reverse {
            "ZREVRANK"
        } else {
            "ZRANK"
        }));
    }
    if argv.len() > 4 {
        return Err(CommandError::WrongArity(if reverse {
            "ZREVRANK"
        } else {
            "ZRANK"
        }));
    }
    let withscore = if argv.len() == 4 {
        let opt = std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if !opt.eq_ignore_ascii_case("WITHSCORE") {
            return Err(CommandError::SyntaxError);
        }
        true
    } else {
        false
    };
    let _ = cmd_name;
    if withscore {
        // (CrimsonHawk) Single keyspace lookup + single zset traversal returns BOTH
        // rank and score — the old path did store.zrank THEN store.zmscore (a redundant
        // entries probe + member lookup). One record_keyspace_lookup, matching upstream.
        return match store.zrank_withscore(&argv[1], &argv[2], reverse, now_ms)? {
            Some((rank, score)) => {
                let rank_i = i64::try_from(rank).unwrap_or(i64::MAX);
                // The score element honors the negotiated protocol: a RESP3 Double
                // (`,<score>`) under HELLO 3, a bulk string under RESP2 — matching
                // upstream t_zset.c zrankGenericCommand's addReplyDouble.
                let score_frame =
                    zpop_score_frame(score, store.dispatch_client_ctx.resp_protocol_version);
                Ok(RespFrame::Array(Some(vec![
                    RespFrame::Integer(rank_i),
                    score_frame,
                ])))
            }
            None => Ok(RespFrame::Array(None)),
        };
    }
    let rank_opt = if reverse {
        store.zrevrank(&argv[1], &argv[2], now_ms)?
    } else {
        store.zrank(&argv[1], &argv[2], now_ms)?
    };
    match rank_opt {
        Some(rank) => Ok(RespFrame::Integer(i64::try_from(rank).unwrap_or(i64::MAX))),
        None => Ok(RespFrame::BulkString(None)),
    }
}

fn zrank(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    zrank_generic(argv, store, now_ms, false)
}

fn zrevrank(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    zrank_generic(argv, store, now_ms, true)
}

fn zrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // ZRANGE key min max [BYSCORE | BYLEX] [REV] [LIMIT offset count] [WITHSCORES]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZRANGE"));
    }

    let mut byscore = false;
    let mut bylex = false;
    let mut rev = false;
    let mut withscores = false;
    let mut limit_offset: Option<usize> = None;
    let mut limit_count: Option<usize> = None;
    // Raw LIMIT count, mirroring upstream's `long opt_limit = -1` default. The
    // BYSCORE/BYLEX-pairing check is `opt_limit != -1`, so ONLY an exact -1 is
    // the "no limit" sentinel — every other value (including other negatives)
    // is a real count that triggers the shape error in rank mode. (frankenredis-zrlimneg)
    let mut limit_count_raw: i64 = -1;

    let mut i = 4;
    while i < argv.len() {
        let opt = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if opt.eq_ignore_ascii_case("BYSCORE") {
            // Upstream t_zset.c::zrangeGenericCommand only matches
            // BYSCORE when rangetype is still AUTO; a second BYSCORE
            // (or BYLEX after BYSCORE) falls through to syntax error.
            // (br-frankenredis-zrangedup)
            if byscore || bylex {
                return Err(CommandError::SyntaxError);
            }
            byscore = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("BYLEX") {
            if byscore || bylex {
                return Err(CommandError::SyntaxError);
            }
            bylex = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("REV") {
            // Upstream only matches REV when direction is AUTO; a
            // duplicate REV falls through to syntax error.
            // (br-frankenredis-zrangedup)
            if rev {
                return Err(CommandError::SyntaxError);
            }
            rev = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("WITHSCORES") {
            withscores = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("LIMIT") {
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream t_zset.c::zrangeGenericCommand parses LIMIT
            // offset via getLongFromObjectOrReply (accepts any long,
            // including negatives) and only validates the BYSCORE/BYLEX
            // pairing AFTER the parse loop completes. A negative offset
            // is then carried into genericZrangebyscoreCommand which
            // short-circuits to empty via 'if (offset >= ll) goto cleanup'
            // never firing for offset<0 — but `if (limit == 0) break`
            // does fire on the clamped count, so the result is empty.
            // Use parse_limit_offset_arg (returns usize::MAX for
            // negative input) so .skip(usize::MAX) produces the same
            // empty result, and the dependency check below still wins
            // for the no-BYSCORE-no-BYLEX path. (frankenredis-zrnegoff)
            limit_offset = Some(parse_limit_offset_arg(&argv[i + 1])?);
            limit_count_raw = parse_i64_arg(&argv[i + 2])?;
            limit_count = parse_limit_count_arg(&argv[i + 2])?;
            i += 3;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    // Upstream t_zset.c::zrangeGenericCommand uses verbose syntax-error
    // wording for LIMIT-without-shape and WITHSCORES+BYLEX, matching
    // these exact strings. (br-frankenredis-zrangeshape)
    // The check is opt_limit != -1: a sentinel `LIMIT offset -1` is allowed
    // even in rank mode, but `LIMIT offset -100` (or any non-(-1) count) is
    // not — match on the RAW count, not limit_count (which clamps every
    // negative to None). (frankenredis-zrlimneg)
    if limit_count_raw != -1 && !byscore && !bylex {
        return Err(CommandError::Custom(
            "ERR syntax error, LIMIT is only supported in combination with either BYSCORE or BYLEX"
                .to_string(),
        ));
    }
    if withscores && bylex {
        return Err(CommandError::Custom(
            "ERR syntax error, WITHSCORES not supported in combination with BYLEX".to_string(),
        ));
    }

    if byscore {
        let min = parse_score_bound(&argv[2])?;
        let max = parse_score_bound(&argv[3])?;
        let (lo, hi) = if rev { (max, min) } else { (min, max) };
        if zscore_inverted_wrongtype_guard(store, &argv[1], lo, hi, now_ms)? {
            return Ok(RespFrame::Array(Some(Vec::new())));
        }
        // LIMIT pushed into the range walk — O(offset+count), not O(range).
        let pairs = store.zrangebyscore_withscores_limited(
            &argv[1],
            lo,
            hi,
            rev,
            limit_offset.unwrap_or(0),
            limit_count,
            now_ms,
        )?;
        zrange_emit_with_resp(
            pairs,
            withscores,
            store.dispatch_client_ctx.resp_protocol_version,
        )
    } else if bylex {
        let min_lex = &argv[2];
        let max_lex = &argv[3];
        // Upstream t_zset.c::zrangeGenericCommand validates the lex
        // bounds via zslParseLexRange before any range walk. (br-frankenredis-zrangeshape)
        validate_lex_bound(min_lex)?;
        validate_lex_bound(max_lex)?;
        let (lo, hi) = if rev {
            (max_lex.as_slice(), min_lex.as_slice())
        } else {
            (min_lex.as_slice(), max_lex.as_slice())
        };
        if withscores {
            // (frankenredis-ry0sr) Use zrangebylex_withscores to get scores in O(1)
            // per element rather than O(n) individual zscore lookups.
            let mut pairs = store.zrangebylex_withscores(&argv[1], lo, hi, now_ms)?;
            if rev {
                pairs.reverse();
            }
            if let Some(offset) = limit_offset {
                // In-place LIMIT. (frankenredis-5qwm6)
                if offset > 0 && offset < pairs.len() {
                    pairs.drain(0..offset);
                } else if offset >= pairs.len() {
                    pairs.clear();
                }
                if let Some(count) = limit_count {
                    pairs.truncate(count);
                }
            }
            zrange_emit_with_resp(pairs, true, store.dispatch_client_ctx.resp_protocol_version)
        } else {
            // LIMIT/REV pushed into the lex walk — O(offset+count). (frankenredis-qchm7)
            let members = store.zrangebylex_limited(
                &argv[1],
                lo,
                hi,
                rev,
                limit_offset.unwrap_or(0),
                limit_count,
                now_ms,
            )?;
            let frames = members
                .into_iter()
                .map(|m| RespFrame::BulkString(Some(m)))
                .collect();
            Ok(RespFrame::Array(Some(frames)))
        }
    } else {
        // Default: by rank (index)
        let start = parse_i64_arg(&argv[2])?;
        let stop = parse_i64_arg(&argv[3])?;
        let resp = store.dispatch_client_ctx.resp_protocol_version;
        if rev {
            let pairs = store.zrevrange_withscores(&argv[1], start, stop, now_ms)?;
            zrange_emit_with_resp(pairs, withscores, resp)
        } else if withscores {
            let pairs = store.zrange_withscores(&argv[1], start, stop, now_ms)?;
            zrange_emit_with_resp(pairs, true, resp)
        } else {
            let members = store.zrange(&argv[1], start, stop, now_ms)?;
            let frames = members
                .into_iter()
                .map(|m| RespFrame::BulkString(Some(m)))
                .collect();
            Ok(RespFrame::Array(Some(frames)))
        }
    }
}

/// (frankenredis-jnf53) Upstream t_zset.c::zrangeResultEmitCBufferToClient
/// wraps each (member, score) pair in `addReplyArrayLen(c, 2)` when
/// `c->resp > 2` and skips that wrapper under RESP2 — so the wire under
/// RESP3 is Array<[member, score]> while under RESP2 it stays flat
/// alternating. Mirror that here.
fn zrange_emit_with_resp(
    pairs: Vec<(Vec<u8>, f64)>,
    withscores: bool,
    resp_protocol_version: i64,
) -> Result<RespFrame, CommandError> {
    if !withscores {
        let frames = pairs
            .into_iter()
            .map(|(m, _)| RespFrame::BulkString(Some(m)))
            .collect();
        return Ok(RespFrame::Array(Some(frames)));
    }
    if resp_protocol_version == 3 {
        let frames = pairs
            .into_iter()
            .map(|(member, score)| {
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(member)),
                    RespFrame::double_from_f64(score),
                ]))
            })
            .collect();
        Ok(RespFrame::Array(Some(frames)))
    } else {
        let mut frames = Vec::with_capacity(pairs.len() * 2);
        for (member, score) in pairs {
            frames.push(RespFrame::BulkString(Some(member)));
            frames.push(RespFrame::BulkString(Some(
                redis_score_to_string(score).into_bytes(),
            )));
        }
        Ok(RespFrame::Array(Some(frames)))
    }
}

fn zrevrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 || argv.len() > 5 {
        return Err(CommandError::WrongArity("ZREVRANGE"));
    }
    let start = parse_i64_arg(&argv[2])?;
    let stop = parse_i64_arg(&argv[3])?;
    let withscores = argv.len() == 5
        && std::str::from_utf8(&argv[4])
            .map(|s| s.eq_ignore_ascii_case("WITHSCORES"))
            .unwrap_or(false);
    if argv.len() == 5 && !withscores {
        return Err(CommandError::SyntaxError);
    }
    let members = store.zrevrange(&argv[1], start, stop, now_ms)?;
    if withscores {
        // (frankenredis-jnf53) Route through zrange_emit_with_resp so the
        // RESP3 wire is Array<[member, score]> and RESP2 stays flat.
        let mut pairs: Vec<(Vec<u8>, f64)> = Vec::with_capacity(members.len());
        for m in members {
            let score = store.zscore(&argv[1], &m, now_ms)?.unwrap_or(0.0);
            pairs.push((m, score));
        }
        zrange_emit_with_resp(pairs, true, store.dispatch_client_ctx.resp_protocol_version)
    } else {
        let frames = members
            .into_iter()
            .map(|m| RespFrame::BulkString(Some(m)))
            .collect();
        Ok(RespFrame::Array(Some(frames)))
    }
}

/// Parse optional WITHSCORES / LIMIT offset count from argv starting at `start_idx`.
fn parse_zrangebyscore_opts(
    argv: &[Vec<u8>],
    start_idx: usize,
) -> Result<(bool, Option<usize>, Option<usize>), CommandError> {
    let mut withscores = false;
    let mut limit_offset = None;
    let mut limit_count = None;
    let mut i = start_idx;
    while i < argv.len() {
        // (frankenredis-44iva) byte-match: non-UTF8/unrecognized option -> syntax error
        let opt = &argv[i];
        if opt.eq_ignore_ascii_case(b"WITHSCORES") {
            withscores = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case(b"LIMIT") {
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            limit_offset = Some(parse_limit_offset_arg(&argv[i + 1])?);
            limit_count = parse_limit_count_arg(&argv[i + 2])?;
            i += 3;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }
    Ok((withscores, limit_offset, limit_count))
}

fn zrangebyscore(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // ZRANGEBYSCORE key min max [WITHSCORES] [LIMIT offset count]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZRANGEBYSCORE"));
    }
    // (frankenredis-e5mya) Walk the trailing option tail first so an
    // unknown / misplaced option (e.g. ZRANGEBYSCORE k WITHSCORES 1 4)
    // surfaces the upstream "syntax error" rather than the more
    // specific "min or max is not a float" wording. Vendored
    // t_zset.c::genericZrangebyscoreCommand parses options before
    // bounds for exactly this reason.
    let (withscores, limit_offset, limit_count) = parse_zrangebyscore_opts(argv, 4)?;
    let min = parse_score_bound(&argv[2])?;
    let max = parse_score_bound(&argv[3])?;
    if zscore_inverted_wrongtype_guard(store, &argv[1], min, max, now_ms)? {
        return Ok(RespFrame::Array(Some(Vec::new())));
    }
    // LIMIT pushed into the range walk — O(offset+count), not O(range).
    let pairs = store.zrangebyscore_withscores_limited(
        &argv[1],
        min,
        max,
        false,
        limit_offset.unwrap_or(0),
        limit_count,
        now_ms,
    )?;
    zrange_emit_with_resp(
        pairs,
        withscores,
        store.dispatch_client_ctx.resp_protocol_version,
    )
}

fn zcount(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("ZCOUNT"));
    }
    let min = parse_score_bound(&argv[2])?;
    let max = parse_score_bound(&argv[3])?;
    if zscore_inverted_wrongtype_guard(store, &argv[1], min, max, now_ms)? {
        return Ok(RespFrame::Integer(0));
    }
    let count = store.zcount(&argv[1], min, max, now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)))
}

fn zincrby(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("ZINCRBY"));
    }
    let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
    let delta = parse_score_f64_arg(&argv[2])?;
    let new_score = store
        .zincrby(&argv[1], argv[3].clone(), delta, now_ms)
        .map_err(|e| {
            // Upstream t_zset.c uses 'resulting score is not a number
            // (NaN)' for any zset increment that yields NaN, distinct
            // from INCRBYFLOAT's 'increment would produce NaN or
            // Infinity' wording. (br-frankenredis-zinaN)
            match e {
                StoreError::IncrFloatNaN => {
                    CommandError::Custom("ERR resulting score is not a number (NaN)".to_string())
                }
                other => other.into(),
            }
        })?;
    if resp3 {
        Ok(RespFrame::double_from_f64(new_score))
    } else {
        Ok(RespFrame::BulkString(Some(
            redis_score_to_string(new_score).into_bytes(),
        )))
    }
}

fn parse_zpop_count(arg: &[u8]) -> Result<usize, CommandError> {
    match parse_i64_arg(arg) {
        Ok(count) if count >= 0 => usize::try_from(count).map_err(|_| CommandError::InvalidInteger),
        _ => Err(CommandError::Custom(
            "ERR value is out of range, must be positive".to_string(),
        )),
    }
}

/// (frankenredis-1g3ao) Upstream zpopMinMaxCommand sets
/// use_nested_array = (c->resp > 2 && count != -1). Under RESP3 with the
/// COUNT form, each (member, score) is wrapped in a 2-Array; under RESP2
/// or the no-COUNT form, the wire stays flat. Scores use Double type under RESP3.
fn zpop_count_emit(pairs: Vec<(Vec<u8>, f64)>, resp_protocol_version: i64) -> RespFrame {
    if resp_protocol_version == 3 {
        let frames = pairs
            .into_iter()
            .map(|(member, score)| {
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(member)),
                    RespFrame::double_from_f64(score),
                ]))
            })
            .collect();
        RespFrame::Array(Some(frames))
    } else {
        let mut frames = Vec::with_capacity(pairs.len() * 2);
        for (member, score) in pairs {
            frames.push(RespFrame::BulkString(Some(member)));
            frames.push(RespFrame::BulkString(Some(
                redis_score_to_string(score).into_bytes(),
            )));
        }
        RespFrame::Array(Some(frames))
    }
}

/// (gauntlet B5) A single score element: RESP3 Double under HELLO 3, bulk string
/// under RESP2. Used by the no-count ZPOPMIN/ZPOPMAX flat `[member, score]` reply.
fn zpop_score_frame(score: f64, resp_protocol_version: i64) -> RespFrame {
    if resp_protocol_version == 3 {
        RespFrame::double_from_f64(score)
    } else {
        RespFrame::BulkString(Some(redis_score_to_string(score).into_bytes()))
    }
}

fn zpopmin(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // (frankenredis-bexnm) Upstream t_zset.c:4028 `zpopMinMaxCommand`
    // checks `c->argc > 3` and emits `shared.syntaxerr` — not the
    // generic arity error. Too-few args still gets the arity error.
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("ZPOPMIN"));
    }
    if argv.len() > 3 {
        return Err(CommandError::SyntaxError);
    }
    if argv.len() == 3 {
        // Upstream t_zset.c::genericZpopCommand uses
        //   getRangeLongFromObjectOrReply(c, c->argv[2], 0, LONG_MAX,
        //                                 &count, "value is out of range, must be positive")
        // so a non-numeric count gets the same wording as a negative
        // count. fr was calling parse_i64_arg first, surfacing the
        // generic 'value is not an integer or out of range' for
        // non-numeric input. Switch to the same parse_zpop_count helper
        // ZPOPMAX already uses to keep the wording uniform.
        // (frankenredis-zpopminword)
        let count = parse_zpop_count(&argv[2])?;
        // (frankenredis-5w1d3) Don't short-circuit count==0 here:
        // zpopmin_count's type check at fr-store/src/lib.rs:7303
        // must fire so a wrongtype-key with count==0 surfaces
        // WRONGTYPE (matching upstream t_zset.c::genericZpopCommand
        // and ZPOPMAX/LPOP/RPOP). The inner for-loop is a no-op when
        // count==0, so this is functionally equivalent for set-typed
        // keys.
        let pairs = store.zpopmin_count(&argv[1], count, now_ms)?;
        return Ok(zpop_count_emit(
            pairs,
            store.dispatch_client_ctx.resp_protocol_version,
        ));
    }
    match store.zpopmin(&argv[1], now_ms)? {
        // (gauntlet B5) flat [member, score]; score is RESP3 Double under HELLO 3.
        Some((member, score)) => Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(member)),
            zpop_score_frame(score, store.dispatch_client_ctx.resp_protocol_version),
        ]))),
        None => Ok(RespFrame::Array(Some(vec![]))),
    }
}

fn zpopmax(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // (frankenredis-bexnm) Same as ZPOPMIN — `c->argc > 3` returns
    // ERR syntax error in vendored's shared zpopMinMaxCommand handler.
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("ZPOPMAX"));
    }
    if argv.len() > 3 {
        return Err(CommandError::SyntaxError);
    }
    if argv.len() == 3 {
        let count = parse_zpop_count(&argv[2])?;
        let pairs = store.zpopmax_count(&argv[1], count, now_ms)?;
        return Ok(zpop_count_emit(
            pairs,
            store.dispatch_client_ctx.resp_protocol_version,
        ));
    }
    match store.zpopmax(&argv[1], now_ms)? {
        // (gauntlet B5) flat [member, score]; score is RESP3 Double under HELLO 3.
        Some((member, score)) => Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(member)),
            zpop_score_frame(score, store.dispatch_client_ctx.resp_protocol_version),
        ]))),
        None => Ok(RespFrame::Array(Some(vec![]))),
    }
}

fn geoadd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("GEOADD"));
    }

    let mut xx = false;
    let mut nx = false;
    let mut ch = false;
    let mut long_idx = 2;
    while long_idx < argv.len() {
        if eq_ascii_command(&argv[long_idx], b"NX") {
            nx = true;
        } else if eq_ascii_command(&argv[long_idx], b"XX") {
            xx = true;
        } else if eq_ascii_command(&argv[long_idx], b"CH") {
            ch = true;
        } else {
            break;
        }
        long_idx += 1;
    }

    if xx && nx {
        return Err(CommandError::SyntaxError);
    }

    let remaining = argv.len().saturating_sub(long_idx);
    if remaining == 0 {
        return Err(CommandError::WrongArity("GEOADD"));
    }
    if !remaining.is_multiple_of(3) {
        return Err(CommandError::SyntaxError);
    }

    let mut pairs = Vec::with_capacity(remaining / 3);
    let mut idx = long_idx;
    while idx + 2 < argv.len() {
        let longitude = match parse_geo_f64(&argv[idx]) {
            Ok(value) => value,
            Err(reply) => return Ok(reply),
        };
        let latitude = match parse_geo_f64(&argv[idx + 1]) {
            Ok(value) => value,
            Err(reply) => return Ok(reply),
        };
        if !(GEO_LONG_MIN..=GEO_LONG_MAX).contains(&longitude)
            || !(GEO_LAT_MIN..=GEO_LAT_MAX).contains(&latitude)
        {
            return Ok(geo_invalid_pair_error(longitude, latitude));
        }
        let Some(bits) = geo_encode_wgs84(longitude, latitude) else {
            return Ok(geo_invalid_pair_error(longitude, latitude));
        };
        pairs.push((bits as f64, argv[idx + 2].clone()));
        idx += 3;
    }

    let (total_changed, _only_updated) = store.zadd_with_options(
        &argv[1],
        pairs,
        fr_store::ZaddOptions {
            xx,
            nx,
            ch,
            ..Default::default()
        },
        now_ms,
    )?;

    Ok(RespFrame::Integer(total_changed as i64))
}

fn geohash(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("GEOHASH"));
    }
    let mut frames = Vec::with_capacity(argv.len().saturating_sub(2));
    for member in &argv[2..] {
        let frame = match store.zscore(&argv[1], member, now_ms)? {
            Some(score) => match geo_hash_string_from_score(score) {
                Some(hash) => RespFrame::BulkString(Some(hash)),
                None => RespFrame::BulkString(None),
            },
            None => RespFrame::BulkString(None),
        };
        frames.push(frame);
    }
    Ok(RespFrame::Array(Some(frames)))
}

fn geopos(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("GEOPOS"));
    }
    let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
    // (frankenredis keyspace-acct) Upstream geo.c::geoposCommand does ONE
    // lookupKeyReadOrReply for the key, then reads each member from that object.
    // Per-member store.zscore each bumped keyspace_hits -> N vs redis's 1. Record
    // the key lookup once, then read all members via the no-stat zmscore (mirrors
    // the geodist fix). Byte-identical reply; only the keyspace stat is corrected.
    let members: Vec<&[u8]> = argv[2..].iter().map(Vec::as_slice).collect();
    record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
    let scores = store.zmscore(&argv[1], &members, now_ms)?;
    let mut frames = Vec::with_capacity(scores.len());
    for score in scores {
        let frame = match score {
            Some(s) => match geo_decode_score(s) {
                Some((longitude, latitude)) => RespFrame::Array(Some(vec![
                    geo_coord_frame(longitude, resp3),
                    geo_coord_frame(latitude, resp3),
                ])),
                None => RespFrame::Array(None),
            },
            None => RespFrame::Array(None),
        };
        frames.push(frame);
    }
    Ok(RespFrame::Array(Some(frames)))
}

fn geodist(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Upstream commands.def declares GEODIST with arity = -4, so
    // the table-level check fires for argc<4. Trailing args after
    // the optional unit hit geo.c::geodistCommand's syntaxerr
    // branch. (br-frankenredis-geodist)
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("GEODIST"));
    }
    if argv.len() > 5 {
        return Err(CommandError::SyntaxError);
    }
    let to_meter = if argv.len() == 5 {
        match geo_unit_to_meters(&argv[4]) {
            Some(unit) => unit,
            None => {
                return Err(CommandError::Custom(
                    "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                ));
            }
        }
    } else {
        1.0
    };

    // (frankenredis keyspace-acct) Upstream geo.c::geodistCommand does ONE
    // lookupKeyReadOrReply for the key, then reads both members from that object.
    // Two separate store.zscore calls each bumped keyspace_hits -> 2 vs redis's 1.
    // Record the key lookup once, then read both scores via the no-stat zmscore.
    record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
    let scores = store.zmscore(&argv[1], &[argv[2].as_slice(), argv[3].as_slice()], now_ms)?;
    let (Some(score1), Some(score2)) = (scores[0], scores[1]) else {
        return Ok(RespFrame::BulkString(None));
    };

    let Some((lon1, lat1)) = geo_decode_score(score1) else {
        return Ok(RespFrame::BulkString(None));
    };
    let Some((lon2, lat2)) = geo_decode_score(score2) else {
        return Ok(RespFrame::BulkString(None));
    };

    let distance = geo_distance_m(lon1, lat1, lon2, lat2) / to_meter;
    Ok(geo_distance_reply(distance))
}

/// Direction parameter for GEORADIUS / GEOSEARCH result ordering.
///
/// Mirrors upstream geo.c's SORT_NONE / SORT_ASC / SORT_DESC enum.
/// `Unspecified` (= SORT_NONE) means the user did not pass ASC or
/// DESC — results are returned in the underlying zset iteration
/// order (geohash-score order). Upstream geo.c:714-718 promotes
/// `Unspecified` to `Asc` when `COUNT` is specified without `ANY`,
/// because returning the closest-N requires sorting by distance.
#[derive(Copy, Clone, PartialEq, Eq, Debug)]
pub(crate) enum GeoSort {
    Unspecified,
    Asc,
    Desc,
}

/// Shared core for GEORADIUS, GEORADIUSBYMEMBER, GEOSEARCH, GEOSEARCHSTORE.
/// Returns filtered (member, score, distance, lon, lat) tuples in the requested order.
#[allow(clippy::too_many_arguments, clippy::type_complexity)]
fn geo_search_core(
    store: &mut Store,
    key: &[u8],
    center_lon: f64,
    center_lat: f64,
    radius_m: f64,
    count: Option<usize>,
    sort: GeoSort,
    any: bool,
    now_ms: u64,
) -> Result<Vec<(Vec<u8>, f64, f64, f64, f64)>, CommandError> {
    // Spatial pre-filter: a lat/lon bounding box that provably contains the
    // whole great-circle disk of `radius_m`. Points outside it cannot be in
    // range, so we skip the trig-heavy haversine for them; and by scanning the
    // zset by reference (zset_for_each_asc) we clone only the members we keep
    // instead of every member. The box is a conservative superset, so the
    // surviving result set and its ascending-score order are identical to
    // scanning and distance-testing every member. (frankenredis-5nimj)
    let bb = geo_radius_bbox(center_lon, center_lat, radius_m);
    let mut results: Vec<(Vec<u8>, f64, f64, f64, f64)> = Vec::new();
    // When the radius is small enough that the center geohash cell + its 8
    // neighbours cover it, walk only those cells' score ranges (O(log n + k))
    // instead of every member; otherwise fall back to the full bbox+borrow scan.
    // Both apply the identical exact bbox+haversine candidate filter, so results
    // are unchanged. (frankenredis-7hg0r)
    match geo_radius_cell_ranges(center_lon, center_lat, radius_m) {
        Some(ranges) => {
            store.zset_for_each_in_score_ranges(key, &ranges, now_ms, |member, score| {
                geo_collect_candidate(
                    member,
                    score,
                    center_lon,
                    center_lat,
                    radius_m,
                    bb,
                    &mut results,
                );
            })?;
            // Per-cell scan order is not global; restore ascending (score, member)
            // order so SORT_NONE output and the stable ASC/DESC tie-breaks match
            // the full scan byte-for-byte.
            results.sort_by(|a, b| {
                a.1.partial_cmp(&b.1)
                    .unwrap_or(std::cmp::Ordering::Equal)
                    .then_with(|| a.0.cmp(&b.0))
            });
        }
        None => {
            store.zset_for_each_asc(key, now_ms, |member, score| {
                geo_collect_candidate(
                    member,
                    score,
                    center_lon,
                    center_lat,
                    radius_m,
                    bb,
                    &mut results,
                );
            })?;
        }
    }
    // (frankenredis-1axne) Match upstream geo.c:714-718: if the
    // user supplied COUNT without explicit ordering and without ANY,
    // promote SORT_NONE → SORT_ASC. Otherwise SORT_NONE leaves the
    // zset iteration order intact (geohash-score order), matching
    // vendored where the result of `membersOfAllNeighbors` is iterated
    // and not sorted. fr previously defaulted asc=true unconditionally,
    // which always sorted by distance and broke parity with vendored
    // for the no-ASC/DESC case.
    let effective = if matches!(sort, GeoSort::Unspecified) && count.is_some() && !any {
        GeoSort::Asc
    } else {
        sort
    };
    match effective {
        GeoSort::Asc => {
            results.sort_by(|a, b| a.2.partial_cmp(&b.2).unwrap_or(std::cmp::Ordering::Equal));
        }
        GeoSort::Desc => {
            results.sort_by(|a, b| b.2.partial_cmp(&a.2).unwrap_or(std::cmp::Ordering::Equal));
        }
        GeoSort::Unspecified => {
            // Leave in zset iteration order (already produced above
            // by zrange_withscores(0, -1) which emits members in
            // ascending score order).
        }
    }
    if let Some(limit) = count {
        results.truncate(limit);
    }
    Ok(results)
}

/// Formats GEOSEARCH-family results as RESP frames.
fn geo_search_reply(
    results: &[(Vec<u8>, f64, f64, f64, f64)],
    withcoord: bool,
    withdist: bool,
    withhash: bool,
    to_meter: f64,
    resp3: bool,
) -> RespFrame {
    let frames: Vec<RespFrame> = results
        .iter()
        .map(|(member, score, dist, lon, lat)| {
            if !withcoord && !withdist && !withhash {
                return RespFrame::BulkString(Some(member.clone()));
            }
            let mut parts = vec![RespFrame::BulkString(Some(member.clone()))];
            if withdist {
                let d = dist / to_meter;
                let normalized = if d == 0.0 { 0.0 } else { d };
                parts.push(RespFrame::BulkString(Some(
                    format!("{normalized:.4}").into_bytes(),
                )));
            }
            if withhash {
                parts.push(RespFrame::Integer(*score as i64));
            }
            if withcoord {
                parts.push(RespFrame::Array(Some(vec![
                    geo_coord_frame(*lon, resp3),
                    geo_coord_frame(*lat, resp3),
                ])));
            }
            RespFrame::Array(Some(parts))
        })
        .collect();
    RespFrame::Array(Some(frames))
}

/// Variant of the geo search command, used by `parse_geo_search_flags`
/// to gate which STORE/STOREDIST forms are valid.
///
/// Mirrors upstream geo.c::geoSearchGeneric flags:
/// - `GeoRadius`        → GEORADIUS / GEORADIUSBYMEMBER: accept
///   `STORE key` and `STOREDIST key` (each followed by a destination
///   key argument).
/// - `GeoSearch`        → GEOSEARCH: reject STORE and STOREDIST
///   entirely (upstream geo.c:596-607 gates `store` on
///   `!(flags & GEOSEARCH)`; standalone `storedist` is only allowed
///   when both GEOSEARCH and GEOSEARCHSTORE flags are set).
/// - `GeoSearchStore`   → GEOSEARCHSTORE: accept the bare `STOREDIST`
///   token (no key argument); STORE is still rejected.
#[derive(Copy, Clone, PartialEq, Eq, Debug)]
#[allow(clippy::enum_variant_names)]
enum GeoFlagContext {
    GeoRadius,
    GeoSearch,
    GeoSearchStore,
}

/// Parse optional flags WITHCOORD, WITHDIST, WITHHASH, COUNT N [ANY], ASC, DESC from argv starting
/// at `start`. STORE/STOREDIST consumption depends on `context` — see [`GeoFlagContext`].
///
/// Returns `(withcoord, withdist, withhash, count, any, sort, to_meter)` where `sort` is
/// `GeoSort::Unspecified` when neither ASC nor DESC was supplied (mirroring upstream's
/// SORT_NONE default — see geo.c:569,585-587).
#[allow(clippy::type_complexity)]
fn parse_geo_search_flags(
    argv: &[Vec<u8>],
    start: usize,
    default_unit: f64,
    context: GeoFlagContext,
) -> Result<(bool, bool, bool, Option<usize>, bool, GeoSort, f64), CommandError> {
    let mut withcoord = false;
    let mut withdist = false;
    let mut withhash = false;
    let mut count: Option<usize> = None;
    let mut any = false;
    let mut sort = GeoSort::Unspecified;
    let mut to_meter = default_unit;
    let mut i = start;
    while i < argv.len() {
        if eq_ascii_command(&argv[i], b"WITHCOORD") {
            withcoord = true;
        } else if eq_ascii_command(&argv[i], b"WITHDIST") {
            withdist = true;
        } else if eq_ascii_command(&argv[i], b"WITHHASH") {
            withhash = true;
        } else if eq_ascii_command(&argv[i], b"COUNT") {
            i += 1;
            if i >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let n = parse_i64_arg(&argv[i])?;
            // Upstream geo.c::geoSearchGeneric uses the literal
            // wording 'COUNT must be > 0'. (br-frankenredis-geocount)
            if n <= 0 {
                return Err(CommandError::Custom("ERR COUNT must be > 0".to_string()));
            }
            count = Some(usize::try_from(n).map_err(|_| CommandError::InvalidInteger)?);
        } else if eq_ascii_command(&argv[i], b"ANY") {
            any = true;
        } else if eq_ascii_command(&argv[i], b"ASC") {
            sort = GeoSort::Asc;
        } else if eq_ascii_command(&argv[i], b"DESC") {
            sort = GeoSort::Desc;
        } else if eq_ascii_command(&argv[i], b"STORE") {
            // (frankenredis-ffr2k) Upstream geo.c:596-602 gates STORE
            // on `!(flags & GEOSEARCH)` — only GEORADIUS variants
            // accept STORE. GEOSEARCH/GEOSEARCHSTORE fall through to
            // the syntax-error else.
            if context != GeoFlagContext::GeoRadius {
                return Err(CommandError::SyntaxError);
            }
            // GEORADIUS context: skip STORE's destination-key argument
            // (consumed by georadius/georadiusbymember callers).
            i += 1;
        } else if eq_ascii_command(&argv[i], b"STOREDIST") {
            match context {
                GeoFlagContext::GeoRadius => {
                    // GEORADIUS context: STOREDIST takes a key arg;
                    // peek ahead and skip it if it doesn't look like
                    // another flag or unit token.
                    if i + 1 < argv.len()
                        && !is_geo_flag(&argv[i + 1])
                        && geo_unit_to_meters(&argv[i + 1]).is_none()
                    {
                        i += 1; // skip the key
                    }
                }
                GeoFlagContext::GeoSearchStore => {
                    // (frankenredis-ffr2k) Upstream geo.c:612-616
                    // accepts the bare STOREDIST token (no key arg)
                    // when both GEOSEARCH and GEOSEARCHSTORE flags
                    // are set. GEOSEARCHSTORE uses its own dedicated
                    // pre-scan for the storedist boolean.
                }
                GeoFlagContext::GeoSearch => {
                    // (frankenredis-ffr2k) Upstream rejects STOREDIST
                    // for plain GEOSEARCH (no matching else-if branch
                    // → falls through to addReplyErrorObject with
                    // shared.syntaxerr).
                    return Err(CommandError::SyntaxError);
                }
            }
        } else if let Some(m) = geo_unit_to_meters(&argv[i]) {
            to_meter = m;
        } else {
            // Mirror upstream geo.c::geoSearchGeneric which falls
            // through to addReplyErrorObject(c, shared.syntaxerr) for
            // any unrecognised token in the trailing-flags loop.
            // (br-frankenredis-geounknown)
            return Err(CommandError::SyntaxError);
        }
        i += 1;
    }
    // Upstream geo.c::geoSearchGeneric rejects ANY without an
    // accompanying COUNT argument with the dedicated wording.
    // fr previously set any=true unconditionally and silently
    // ignored the missing-COUNT case. (frankenredis-geoanyc)
    if any && count.is_none() {
        return Err(CommandError::Custom(
            "ERR the ANY argument requires COUNT argument".to_string(),
        ));
    }
    Ok((withcoord, withdist, withhash, count, any, sort, to_meter))
}

/// Check whether a byte slice is a recognized geo search flag keyword.
fn is_geo_flag(arg: &[u8]) -> bool {
    eq_ascii_command(arg, b"WITHCOORD")
        || eq_ascii_command(arg, b"WITHDIST")
        || eq_ascii_command(arg, b"WITHHASH")
        || eq_ascii_command(arg, b"COUNT")
        || eq_ascii_command(arg, b"ANY")
        || eq_ascii_command(arg, b"ASC")
        || eq_ascii_command(arg, b"DESC")
        || eq_ascii_command(arg, b"STORE")
        || eq_ascii_command(arg, b"STOREDIST")
}

/// Extract STORE/STOREDIST destination key from GEORADIUS/GEORADIUSBYMEMBER argv.
/// Returns (store_key, is_storedist).
/// Mirror upstream geo.c::georadiusGeneric's STORE/STOREDIST gate:
/// each option must be followed by a destination key (`(i+1) <
/// remaining`), and `RADIUS_NOSTORE` (set for the _RO variants)
/// rejects the option entirely. Bare STORE/STOREDIST falls through
/// to the loop's else and surfaces shared.syntaxerr. fr previously
/// silently dropped the missing-key case and silently accepted
/// STORE/STOREDIST in _RO mode. (frankenredis-geostorearg)
fn validate_geo_store_args(
    argv: &[Vec<u8>],
    start: usize,
    nostore: bool,
) -> Result<(), CommandError> {
    let mut i = start;
    while i < argv.len() {
        let is_store = eq_ascii_command(&argv[i], b"STORE");
        let is_storedist = eq_ascii_command(&argv[i], b"STOREDIST");
        if is_store || is_storedist {
            if nostore {
                return Err(CommandError::SyntaxError);
            }
            if i + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Skip the dest key so a `STORE foo STORE` pattern
            // doesn't double-trigger; the second STORE keyword is
            // a new option occurrence.
            i += 2;
            continue;
        }
        i += 1;
    }
    Ok(())
}

/// Returns true when the command name is GEORADIUS_RO or
/// GEORADIUSBYMEMBER_RO. Both share the same dispatch handler as
/// their non-RO counterparts but upstream's RADIUS_NOSTORE flag
/// rejects STORE/STOREDIST in those variants. (frankenredis-geostorearg)
fn is_geo_ro_variant(cmd: &[u8]) -> bool {
    eq_ascii_command(cmd, b"GEORADIUS_RO") || eq_ascii_command(cmd, b"GEORADIUSBYMEMBER_RO")
}

fn extract_geo_store(argv: &[Vec<u8>], start: usize) -> (Option<Vec<u8>>, bool) {
    let mut store_key: Option<Vec<u8>> = None;
    let mut storedist = false;
    let mut i = start;
    while i < argv.len() {
        if eq_ascii_command(&argv[i], b"STOREDIST") && i + 1 < argv.len() {
            store_key = Some(argv[i + 1].clone());
            storedist = true;
            i += 2;
        } else if eq_ascii_command(&argv[i], b"STORE") && i + 1 < argv.len() {
            store_key = Some(argv[i + 1].clone());
            storedist = false;
            i += 2;
        } else {
            i += 1;
        }
    }
    (store_key, storedist)
}

/// Store geo search results into a destination sorted set. With `storedist`, scores are
/// distances in `unit_mult`; otherwise scores are geohash values.
fn geo_store_results(
    store: &mut Store,
    dest: &Vec<u8>,
    results: &[(Vec<u8>, f64, f64, f64, f64)],
    unit_mult: f64,
    storedist: bool,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    let count_result = results.len() as i64;
    if results.is_empty() {
        store.del(std::slice::from_ref(dest), now_ms);
    } else {
        let pairs: Vec<(f64, Vec<u8>)> = results
            .iter()
            .map(|(member, score, dist, _, _)| {
                if storedist {
                    (*dist / unit_mult, member.clone())
                } else {
                    (*score, member.clone())
                }
            })
            .collect();
        store.del(std::slice::from_ref(dest), now_ms);
        store.zadd(dest, &pairs, now_ms)?;
    }
    Ok(RespFrame::Integer(count_result))
}

fn georadius(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // GEORADIUS key longitude latitude radius m|km|ft|mi [WITHCOORD] [WITHDIST] [WITHHASH] [COUNT count [ANY]] [ASC|DESC] [STORE key] [STOREDIST key]
    if argv.len() < 6 {
        // GEORADIUS_RO shares this handler; the arity error must name the
        // command the client actually invoked, not the base GEORADIUS, matching
        // upstream where each registered fullname owns its error.
        // (frankenredis-aliasarity)
        let name = if argv
            .first()
            .is_some_and(|c| c.eq_ignore_ascii_case(b"GEORADIUS_RO"))
        {
            "GEORADIUS_RO"
        } else {
            "GEORADIUS"
        };
        return Err(CommandError::WrongArity(name));
    }
    // (frankenredis-geowrongtype) Upstream geo.c::georadiusGeneric runs
    // lookupKeyRead + checkType(OBJ_ZSET) BEFORE extracting the coords/radius/
    // unit or parsing the option tail, so a wrong-type key surfaces WRONGTYPE
    // ahead of any 'need numeric radius' / 'unsupported unit' / 'radius cannot
    // be negative' option error. A missing key still falls through to option
    // parsing (upstream proceeds with a NULL zobj and replies empty at the end);
    // the no-stat peek preserves WRONGTYPE-before-parse ordering.
    match store.peek_value_type(&argv[1], now_ms) {
        None | Some(fr_store::ValueType::ZSet) => {}
        Some(_) => return Err(CommandError::Store(fr_store::StoreError::WrongType)),
    }
    // geo_search_core scans the zset by reference (no-stat), so record the
    // keyspace lookup here at the point upstream's lookupKeyRead runs (after
    // the type check, before coord/radius/unit option parsing). Records a miss
    // for a missing key, a hit otherwise — matching georadiusbymember, whose
    // member zscore already records, and GEOSEARCH.
    record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
    let center_lon = match parse_geo_f64(&argv[2]) {
        Ok(v) => v,
        Err(e) => return Ok(e),
    };
    let center_lat = match parse_geo_f64(&argv[3]) {
        Ok(v) => v,
        Err(e) => return Ok(e),
    };
    // (frankenredis-nugoc) Upstream geo.c::georadiusGeneric routes
    // both positional coordinates through extractLongLatOrReply, which
    // rejects |lon|>180 or |lat|>85.05112878 with the dedicated
    // "ERR invalid longitude,latitude pair %.6f,%.6f" error.
    if let Err(e) = validate_geo_center(center_lon, center_lat) {
        return Ok(e);
    }
    // (frankenredis-geostorearg) Upstream geo.c::georadiusGeneric
    // routes the radius parse through extractDistanceOrReply, whose
    // error message is "need numeric radius" — not the generic
    // "value is not a valid float" wording fr inherited from
    // parse_geo_f64. Match upstream exactly so radius-arg failure
    // is distinguishable from longitude/latitude-arg failure.
    let radius = match parse_geo_f64_with_msg(&argv[4], "need numeric radius") {
        Ok(v) => v,
        Err(e) => return Ok(e),
    };
    if radius < 0.0 {
        return Ok(RespFrame::Error(
            "ERR radius cannot be negative".to_string(),
        ));
    }
    let unit_mult = match geo_unit_to_meters(&argv[5]) {
        Some(m) => m,
        None => {
            return Err(CommandError::Custom(
                "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
            ));
        }
    };
    let radius_m = radius * unit_mult;
    // (frankenredis-geostorearg) Upstream geo.c::georadiusGeneric
    // gates the STORE/STOREDIST option branches on `(i+1) < remaining`
    // and `!(flags & RADIUS_NOSTORE)`. A trailing STORE/STOREDIST
    // with no following key, OR any STORE/STOREDIST in the _RO
    // variant, falls through to the loop's else and surfaces
    // shared.syntaxerr. fr was silently dropping a missing dest
    // key and silently accepting STORE/STOREDIST in _RO mode.
    validate_geo_store_args(argv, 6, /* nostore = */ is_geo_ro_variant(&argv[0]))?;
    let (withcoord, withdist, withhash, count, any, sort, _) =
        parse_geo_search_flags(argv, 6, unit_mult, GeoFlagContext::GeoRadius)?;
    let (store_key, storedist) = extract_geo_store(argv, 6);
    // (frankenredis-kdmf3) Upstream geo.c::georadiusGeneric guards
    // against STORE/STOREDIST combined with any WITH* metadata flag:
    // the reply payload shape changes between [member, withcoord,
    // withdist, withhash] arrays and the integer count returned by
    // STORE, so the two modes are mutually exclusive.
    if store_key.is_some() && (withcoord || withdist || withhash) {
        return Ok(RespFrame::Error(
            "ERR STORE option in GEORADIUS is not compatible with WITHDIST, WITHHASH and WITHCOORD options".to_string(),
        ));
    }
    let results = geo_search_core(
        store, &argv[1], center_lon, center_lat, radius_m, count, sort, any, now_ms,
    )?;
    if let Some(dest) = store_key {
        geo_store_results(store, &dest, &results, unit_mult, storedist, now_ms)
    } else {
        Ok(geo_search_reply(
            &results,
            withcoord,
            withdist,
            withhash,
            unit_mult,
            store.dispatch_client_ctx.resp_protocol_version == 3,
        ))
    }
}

fn georadiusbymember(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // GEORADIUSBYMEMBER key member radius m|km|ft|mi [WITHCOORD] [WITHDIST] [WITHHASH] [COUNT count [ANY]] [ASC|DESC] [STORE key] [STOREDIST key]
    if argv.len() < 5 {
        // GEORADIUSBYMEMBER_RO shares this handler; report the invoked name.
        // (frankenredis-aliasarity)
        let name = if argv
            .first()
            .is_some_and(|c| c.eq_ignore_ascii_case(b"GEORADIUSBYMEMBER_RO"))
        {
            "GEORADIUSBYMEMBER_RO"
        } else {
            "GEORADIUSBYMEMBER"
        };
        return Err(CommandError::WrongArity(name));
    }
    // Upstream geo.c::georadiusbymemberCommand only emits 'could
    // not decode requested zset member' when the source key exists
    // but the member is missing. A missing source key returns an
    // empty array. (br-frankenredis-geofromnonexistent)
    let score = store.zscore(&argv[1], &argv[2], now_ms)?;
    let Some(score) = score else {
        // zscore already touched the key if it exists; this is just for error selection.
        if !store.exists_no_touch(&argv[1], now_ms) {
            return Ok(RespFrame::Array(Some(Vec::new())));
        }
        return Ok(RespFrame::Error(
            "ERR could not decode requested zset member".to_string(),
        ));
    };
    let Some((center_lon, center_lat)) = geo_decode_score(score) else {
        return Ok(RespFrame::Array(Some(Vec::new())));
    };
    // (frankenredis-geostorearg) Upstream geo.c::georadiusGeneric
    // routes the radius parse through extractDistanceOrReply with
    // the literal message "need numeric radius".
    let radius = match parse_geo_f64_with_msg(&argv[3], "need numeric radius") {
        Ok(v) => v,
        Err(e) => return Ok(e),
    };
    if radius < 0.0 {
        return Ok(RespFrame::Error(
            "ERR radius cannot be negative".to_string(),
        ));
    }
    let unit_mult = match geo_unit_to_meters(&argv[4]) {
        Some(m) => m,
        None => {
            return Err(CommandError::Custom(
                "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
            ));
        }
    };
    let radius_m = radius * unit_mult;
    // (frankenredis-geostorearg) See georadius() above for rationale.
    validate_geo_store_args(argv, 5, /* nostore = */ is_geo_ro_variant(&argv[0]))?;
    let (withcoord, withdist, withhash, count, any, sort, _) =
        parse_geo_search_flags(argv, 5, unit_mult, GeoFlagContext::GeoRadius)?;
    let (store_key, storedist) = extract_geo_store(argv, 5);
    // (frankenredis-kdmf3) See georadius() above for rationale.
    if store_key.is_some() && (withcoord || withdist || withhash) {
        return Ok(RespFrame::Error(
            "ERR STORE option in GEORADIUS is not compatible with WITHDIST, WITHHASH and WITHCOORD options".to_string(),
        ));
    }
    let results = geo_search_core(
        store, &argv[1], center_lon, center_lat, radius_m, count, sort, any, now_ms,
    )?;
    if let Some(dest) = store_key {
        geo_store_results(store, &dest, &results, unit_mult, storedist, now_ms)
    } else {
        Ok(geo_search_reply(
            &results,
            withcoord,
            withdist,
            withhash,
            unit_mult,
            store.dispatch_client_ctx.resp_protocol_version == 3,
        ))
    }
}

fn geosearch(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // GEOSEARCH key FROMMEMBER member | FROMLONLAT lon lat BYRADIUS radius m|km|ft|mi | BYBOX width height m|km|ft|mi
    //   [ASC|DESC] [COUNT count [ANY]] [WITHCOORD] [WITHDIST] [WITHHASH]
    // Upstream commands.def declares GEOSEARCH with arity -7
    // (minimum: GEOSEARCH key FROM... BY... + radius/box args).
    // (br-frankenredis-geosearcharity)
    if argv.len() < 7 {
        return Err(CommandError::WrongArity("GEOSEARCH"));
    }
    // (frankenredis-geowrongtype) Upstream geo.c::geoSearchCommand type-checks
    // the key (checkType OBJ_ZSET) before parsing FROM.../BY... and the option
    // tail, so a wrong-type key surfaces WRONGTYPE ahead of any shape/unit/count
    // option error; a missing key still falls through (replies empty later).
    match store.peek_value_type(&argv[1], now_ms) {
        None | Some(fr_store::ValueType::ZSet) => {}
        Some(_) => return Err(CommandError::Store(fr_store::StoreError::WrongType)),
    }
    let mut i = 2;
    let mut center_lon: Option<f64> = None;
    let mut center_lat: Option<f64> = None;
    let mut has_frommember = false;
    let mut has_fromlonlat = false;
    let mut radius_m: Option<f64> = None;
    let mut box_width_m: Option<f64> = None;
    let mut box_height_m: Option<f64> = None;
    let mut has_byradius = false;
    let mut has_bybox = false;
    let mut unit_mult = 1.0_f64;

    // Parse FROMMEMBER/FROMLONLAT and BYRADIUS/BYBOX.
    //
    // Error-reply wording MUST match upstream geo.c::geosearchCommand
    // (br-frankenredis-kro2 / frankenredis-dnguy). Upstream guards:
    //   - FROMMEMBER with `!fromloc`  — rejects FROMLONLAT+FROMMEMBER
    //   - FROMLONLAT with `!frommember` — rejects FROMMEMBER+FROMLONLAT
    //   - BYRADIUS with `!bybox`      — rejects BYBOX+BYRADIUS
    //   - BYBOX    with `!byradius`   — rejects BYRADIUS+BYBOX
    // None of those guards reject the SAME clause twice; the parser
    // just overwrites center_lon/lat/radius/box. fr previously used
    // single has_center/has_shape booleans, which also rejected
    // duplicate-of-same with "ERR syntax error". Split into separate
    // flags so duplicate-of-same is silently accepted (later wins)
    // and only mixed pairs are rejected.
    while i < argv.len() {
        if eq_ascii_command(&argv[i], b"FROMMEMBER") {
            if has_fromlonlat {
                return Err(CommandError::SyntaxError);
            }
            has_frommember = true;
            i += 1;
            if i >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let score = store.zscore(&argv[1], &argv[i], now_ms)?;
            if let Some(score) = score
                && let Some((lon, lat)) = geo_decode_score(score)
            {
                center_lon = Some(lon);
                center_lat = Some(lat);
            }
            // Upstream geo.c::geoSearchGeneric only emits 'could not
            // decode requested zset member' when the source key
            // exists but the member does not. A missing source key
            // proceeds with frommember set, then returns an empty
            // result. (br-frankenredis-geofromnonexistent)
            // zscore already touched the key if it exists; this is just for error selection.
            if center_lon.is_none() && store.exists_no_touch(&argv[1], now_ms) {
                return Ok(RespFrame::Error(
                    "ERR could not decode requested zset member".to_string(),
                ));
            }
        } else if eq_ascii_command(&argv[i], b"FROMLONLAT") {
            if has_frommember {
                return Err(CommandError::SyntaxError);
            }
            has_fromlonlat = true;
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let lon = match parse_geo_f64(&argv[i + 1]) {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            let lat = match parse_geo_f64(&argv[i + 2]) {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            // (frankenredis-nugoc) Reject out-of-range coords with
            // upstream's extractLongLatOrReply wording.
            if let Err(e) = validate_geo_center(lon, lat) {
                return Ok(e);
            }
            center_lon = Some(lon);
            center_lat = Some(lat);
            i += 2;
        } else if eq_ascii_command(&argv[i], b"BYRADIUS") {
            if has_bybox {
                return Err(CommandError::SyntaxError);
            }
            has_byradius = true;
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream geo.c::extractDistanceOrReply: non-numeric →
            // 'need numeric radius', explicit-negative → 'radius
            // cannot be negative'. (br-frankenredis-geosearch)
            let r = match parse_geo_f64_with_msg(&argv[i + 1], "need numeric radius") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            if r < 0.0 {
                return Ok(RespFrame::Error(
                    "ERR radius cannot be negative".to_string(),
                ));
            }
            let um = match geo_unit_to_meters(&argv[i + 2]) {
                Some(m) => m,
                None => {
                    return Err(CommandError::Custom(
                        "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                    ));
                }
            };
            unit_mult = um;
            radius_m = Some(r * um);
            i += 2;
        } else if eq_ascii_command(&argv[i], b"BYBOX") {
            if has_byradius {
                return Err(CommandError::SyntaxError);
            }
            has_bybox = true;
            if i + 3 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream geo.c::extractBoxOrReply: non-numeric →
            // 'need numeric width' / 'need numeric height',
            // negative → 'height or width cannot be negative'.
            // (br-frankenredis-geosearch)
            let w = match parse_geo_f64_with_msg(&argv[i + 1], "need numeric width") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            let h = match parse_geo_f64_with_msg(&argv[i + 2], "need numeric height") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            if w < 0.0 || h < 0.0 {
                return Ok(RespFrame::Error(
                    "ERR height or width cannot be negative".to_string(),
                ));
            }
            let um = match geo_unit_to_meters(&argv[i + 3]) {
                Some(m) => m,
                None => {
                    return Err(CommandError::Custom(
                        "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                    ));
                }
            };
            unit_mult = um;
            box_width_m = Some(w * um);
            box_height_m = Some(h * um);
            i += 3;
        } else {
            break;
        }
        i += 1;
    }

    // (frankenredis-w6v9p) Parse the trailing flags BEFORE the
    // has_center/has_shape arity check so an unknown shape keyword
    // (e.g. `BYSHAPE`, mistyped `BY_RADIUS`) surfaces as the upstream
    // syntax-error reply instead of being misreported as wrong arity.
    // The shape parse loop above breaks out on anything it doesn't
    // recognise, leaving `i` pointing at the first unrecognised token;
    // parse_geo_search_flags's else-branch then routes that to
    // SyntaxError, matching upstream addReplyErrorObject(c,
    // shared.syntaxerr) on the unknown-token branch.
    let (withcoord, withdist, withhash, count, any, sort, _) =
        parse_geo_search_flags(argv, i, unit_mult, GeoFlagContext::GeoSearch)?;
    if !(has_frommember || has_fromlonlat) || !(has_byradius || has_bybox) {
        return Err(CommandError::WrongArity("GEOSEARCH"));
    }
    let (Some(cx), Some(cy)) = (center_lon, center_lat) else {
        // Missing source key with FROMMEMBER — return empty set.
        return Ok(RespFrame::Array(Some(Vec::new())));
    };

    if let Some(rm) = radius_m {
        let results = geo_search_core(store, &argv[1], cx, cy, rm, count, sort, any, now_ms)?;
        Ok(geo_search_reply(
            &results,
            withcoord,
            withdist,
            withhash,
            unit_mult,
            store.dispatch_client_ctx.resp_protocol_version == 3,
        ))
    } else if let (Some(w), Some(h)) = (box_width_m, box_height_m) {
        // BYBOX: filter by bounding box. Pre-filter with a lat/lon box that
        // provably contains the search rectangle and scan the zset by reference
        // (zset_for_each_asc), so the trig-heavy geo_point_in_box / distance run
        // only for candidates near the box and only survivors are cloned. The
        // box is a conservative superset, so the surviving result set and its
        // ascending-score order are identical to scanning every member.
        // (frankenredis-vnsnx)
        let half_w = w / 2.0;
        let half_h = h / 2.0;
        let bb = geo_box_bbox(cx, cy, half_w, half_h);
        let mut results: Vec<(Vec<u8>, f64, f64, f64, f64)> = Vec::new();
        // O(log n + k) geohash neighbour-cell scan when the box fits the center
        // cell + its 8 neighbours; otherwise the full bbox+borrow scan. Both
        // apply the identical exact bbox + geo_point_in_box filter, so results
        // are unchanged. (frankenredis-b9utp)
        match geo_box_cell_ranges(cx, cy, half_w, half_h) {
            Some(ranges) => {
                store.zset_for_each_in_score_ranges(
                    &argv[1],
                    &ranges,
                    now_ms,
                    |member, score| {
                        geo_collect_box_candidate(
                            member,
                            score,
                            cx,
                            cy,
                            half_w,
                            half_h,
                            bb,
                            &mut results,
                        );
                    },
                )?;
                // Restore ascending (score, member) order to match the full scan.
                results.sort_by(|a, b| {
                    a.1.partial_cmp(&b.1)
                        .unwrap_or(std::cmp::Ordering::Equal)
                        .then_with(|| a.0.cmp(&b.0))
                });
            }
            None => {
                store.zset_for_each_asc(&argv[1], now_ms, |member, score| {
                    geo_collect_box_candidate(
                        member,
                        score,
                        cx,
                        cy,
                        half_w,
                        half_h,
                        bb,
                        &mut results,
                    );
                })?;
            }
        }
        // (frankenredis-1axne) Apply the same SORT_NONE handling as
        // geo_search_core: leave zset-iteration order intact unless
        // ASC/DESC was explicit, OR COUNT-without-ANY promotes to ASC
        // per upstream geo.c:714-718.
        let effective = if matches!(sort, GeoSort::Unspecified) && count.is_some() && !any {
            GeoSort::Asc
        } else {
            sort
        };
        match effective {
            GeoSort::Asc => {
                results.sort_by(|a, b| a.2.partial_cmp(&b.2).unwrap_or(std::cmp::Ordering::Equal));
            }
            GeoSort::Desc => {
                results.sort_by(|a, b| b.2.partial_cmp(&a.2).unwrap_or(std::cmp::Ordering::Equal));
            }
            GeoSort::Unspecified => {}
        }
        if let Some(limit) = count {
            results.truncate(limit);
        }
        Ok(geo_search_reply(
            &results,
            withcoord,
            withdist,
            withhash,
            unit_mult,
            store.dispatch_client_ctx.resp_protocol_version == 3,
        ))
    } else {
        Ok(RespFrame::Error(
            "ERR exactly one of BYRADIUS or BYBOX must be provided".to_string(),
        ))
    }
}

fn geosearchstore(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // GEOSEARCHSTORE destination source FROMMEMBER member | FROMLONLAT lon lat BYRADIUS radius m|km|ft|mi | BYBOX width height m|km|ft|mi
    //   [ASC|DESC] [COUNT count [ANY]] [STOREDIST]
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("GEOSEARCHSTORE"));
    }
    let dest = argv[1].clone();
    let source = argv[2].clone();
    // (frankenredis-geowrongtype) Upstream geo.c::georadiusGeneric (the
    // GEOSEARCHSTORE path) type-checks the SOURCE key (argv[2]) before parsing
    // FROM.../BY... and the option tail, so a wrong-type source surfaces
    // WRONGTYPE ahead of any shape/unit/count option error.
    match store.peek_value_type(&source, now_ms) {
        None | Some(fr_store::ValueType::ZSet) => {}
        Some(_) => return Err(CommandError::Store(fr_store::StoreError::WrongType)),
    }
    let mut storedist = false;

    // Check for STOREDIST flag
    for arg in &argv[3..] {
        if eq_ascii_command(arg, b"STOREDIST") {
            storedist = true;
        }
    }

    // Build a synthetic GEOSEARCH argv: [GEOSEARCH, source, ...rest]
    let mut synth = vec![b"GEOSEARCH".to_vec(), source];
    synth.extend_from_slice(&argv[3..]);

    // Parse the geosearch args to get center and radius/box
    let mut i = 2;
    let mut center_lon: Option<f64> = None;
    let mut center_lat: Option<f64> = None;
    // (frankenredis-dnguy) Split flags per FROM/BY kind so duplicate
    // FROMMEMBER (or FROMLONLAT/BYRADIUS/BYBOX) silently overwrites
    // and only mixed pairs error. Mirrors upstream geo.c::geoSearchGeneric
    // which is the single function backing both GEOSEARCH and
    // GEOSEARCHSTORE.
    let mut has_frommember = false;
    let mut has_fromlonlat = false;
    let mut radius_m: Option<f64> = None;
    let mut box_width_m: Option<f64> = None;
    let mut box_height_m: Option<f64> = None;
    let mut has_byradius = false;
    let mut has_bybox = false;
    let mut unit_mult = 1.0_f64;

    while i < synth.len() {
        if eq_ascii_command(&synth[i], b"FROMMEMBER") {
            if has_fromlonlat {
                return Ok(RespFrame::Error(
                    "ERR exactly one of FROMMEMBER or FROMLONLAT must be provided".to_string(),
                ));
            }
            has_frommember = true;
            i += 1;
            if i >= synth.len() {
                return Err(CommandError::SyntaxError);
            }
            let score = store.zscore(&synth[1], &synth[i], now_ms)?;
            if let Some(score) = score
                && let Some((lon, lat)) = geo_decode_score(score)
            {
                center_lon = Some(lon);
                center_lat = Some(lat);
            }
            // (br-frankenredis-geofromnonexistent) — missing source
            // key proceeds with frommember set; only error when the
            // key exists but the member is missing.
            // zscore already touched the key if it exists; this is just for error selection.
            if center_lon.is_none() && store.exists_no_touch(&synth[1], now_ms) {
                return Ok(RespFrame::Error(
                    "ERR could not decode requested zset member".to_string(),
                ));
            }
        } else if eq_ascii_command(&synth[i], b"FROMLONLAT") {
            if has_frommember {
                return Ok(RespFrame::Error(
                    "ERR exactly one of FROMMEMBER or FROMLONLAT must be provided".to_string(),
                ));
            }
            has_fromlonlat = true;
            if i + 2 >= synth.len() {
                return Err(CommandError::SyntaxError);
            }
            let lon = match parse_geo_f64(&synth[i + 1]) {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            let lat = match parse_geo_f64(&synth[i + 2]) {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            // (frankenredis-nugoc) Reject out-of-range coords with
            // upstream's extractLongLatOrReply wording.
            if let Err(e) = validate_geo_center(lon, lat) {
                return Ok(e);
            }
            center_lon = Some(lon);
            center_lat = Some(lat);
            i += 2;
        } else if eq_ascii_command(&synth[i], b"BYRADIUS") {
            if has_bybox {
                return Ok(RespFrame::Error(
                    "ERR exactly one of BYRADIUS or BYBOX must be provided".to_string(),
                ));
            }
            has_byradius = true;
            if i + 2 >= synth.len() {
                return Err(CommandError::SyntaxError);
            }
            // (br-frankenredis-geosearch)
            let r = match parse_geo_f64_with_msg(&synth[i + 1], "need numeric radius") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            if r < 0.0 {
                return Ok(RespFrame::Error(
                    "ERR radius cannot be negative".to_string(),
                ));
            }
            let um = match geo_unit_to_meters(&synth[i + 2]) {
                Some(m) => m,
                None => {
                    return Err(CommandError::Custom(
                        "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                    ));
                }
            };
            unit_mult = um;
            radius_m = Some(r * um);
            i += 2;
        } else if eq_ascii_command(&synth[i], b"BYBOX") {
            if has_byradius {
                return Ok(RespFrame::Error(
                    "ERR exactly one of BYRADIUS or BYBOX must be provided".to_string(),
                ));
            }
            has_bybox = true;
            if i + 3 >= synth.len() {
                return Err(CommandError::SyntaxError);
            }
            // (br-frankenredis-geosearch)
            let w = match parse_geo_f64_with_msg(&synth[i + 1], "need numeric width") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            let h = match parse_geo_f64_with_msg(&synth[i + 2], "need numeric height") {
                Ok(v) => v,
                Err(e) => return Ok(e),
            };
            if w < 0.0 || h < 0.0 {
                return Ok(RespFrame::Error(
                    "ERR height or width cannot be negative".to_string(),
                ));
            }
            let um = match geo_unit_to_meters(&synth[i + 3]) {
                Some(m) => m,
                None => {
                    return Err(CommandError::Custom(
                        "ERR unsupported unit provided. please use M, KM, FT, MI".to_string(),
                    ));
                }
            };
            unit_mult = um;
            box_width_m = Some(w * um);
            box_height_m = Some(h * um);
            i += 3;
        } else {
            break;
        }
        i += 1;
    }

    // (br-frankenredis-geofromnonexistent) — parse trailing flags
    // before the missing-center check so syntax errors surface even
    // when the source key is absent.
    let (withcoord, withdist, withhash, count, any, sort, _) =
        parse_geo_search_flags(&synth, i, unit_mult, GeoFlagContext::GeoSearchStore)?;

    // (frankenredis-w2whf) Upstream src/geo.c::georadiusGeneric on
    // the GEOSEARCHSTORE path rejects any WITH* metadata flag with
    // the dedicated wording (distinct from GEORADIUS STORE's
    // "STORE option in GEORADIUS is not compatible..." form). The
    // store-output of GEOSEARCHSTORE is always a {member→score} set,
    // so the WITH* output-shaping flags have no defined meaning here.
    if withcoord || withdist || withhash {
        return Ok(RespFrame::Error(
            "ERR GEOSEARCHSTORE is not compatible with WITHDIST, WITHHASH and WITHCOORD options"
                .to_string(),
        ));
    }

    let (Some(cx), Some(cy)) = (center_lon, center_lat) else {
        if !(has_frommember || has_fromlonlat) {
            return Ok(RespFrame::Error(
                "ERR exactly one of FROMMEMBER or FROMLONLAT must be provided".to_string(),
            ));
        }
        // FROMMEMBER with missing source key: store nothing,
        // return 0.
        store.del(std::slice::from_ref(&synth[0]), now_ms);
        return Ok(RespFrame::Integer(0));
    };

    let results = if let Some(rm) = radius_m {
        geo_search_core(store, &synth[1], cx, cy, rm, count, sort, any, now_ms)?
    } else if let (Some(w), Some(h)) = (box_width_m, box_height_m) {
        let members = store.zrange_withscores(&synth[1], 0, -1, now_ms)?;
        let half_w = w / 2.0;
        let half_h = h / 2.0;
        let mut res: Vec<(Vec<u8>, f64, f64, f64, f64)> = Vec::new();
        for (member, score) in members {
            let Some((lon, lat)) = geo_decode_score(score) else {
                continue;
            };
            let dist = geo_distance_m(cx, cy, lon, lat);
            let lat_dist = geo_distance_m(cx, cy, cx, lat);
            let lon_dist = geo_distance_m(cx, cy, lon, cy);
            if lat_dist <= half_h && lon_dist <= half_w {
                res.push((member, score, dist, lon, lat));
            }
        }
        // (frankenredis-1axne) Apply same SORT_NONE handling as
        // geo_search_core / GEOSEARCH BYBOX (upstream geo.c:714-718).
        let effective = if matches!(sort, GeoSort::Unspecified) && count.is_some() && !any {
            GeoSort::Asc
        } else {
            sort
        };
        match effective {
            GeoSort::Asc => {
                res.sort_by(|a, b| a.2.partial_cmp(&b.2).unwrap_or(std::cmp::Ordering::Equal));
            }
            GeoSort::Desc => {
                res.sort_by(|a, b| b.2.partial_cmp(&a.2).unwrap_or(std::cmp::Ordering::Equal));
            }
            GeoSort::Unspecified => {}
        }
        if let Some(limit) = count {
            res.truncate(limit);
        }
        res
    } else {
        return Ok(RespFrame::Error(
            "ERR exactly one of BYRADIUS or BYBOX must be provided".to_string(),
        ));
    };

    geo_store_results(store, &dest, &results, unit_mult, storedist, now_ms)
}

/// Parse a stream ID matching upstream Redis 7.2 strict semantics.
///
/// Accepted strict forms:
/// - `ms-seq` -> `(ms, seq)`
/// - `ms` -> `(ms, 0)`, matching upstream's common `missing_seq=0`
///
/// Dedicated range-parsing helpers handle non-strict `+` and `-` special IDs.
/// (br-frankenredis-s0v0)
fn parse_stream_id(arg: &[u8]) -> Result<StreamId, RespFrame> {
    let invalid = || {
        RespFrame::Error("ERR Invalid stream ID specified as stream command argument".to_string())
    };
    let text = std::str::from_utf8(arg).map_err(|_| invalid())?;
    let (ms_text, seq) = match text.split_once('-') {
        Some((ms, seq)) => (ms, seq.parse::<u64>().map_err(|_| invalid())?),
        None => (text, 0),
    };
    let ms = ms_text.parse::<u64>().map_err(|_| invalid())?;
    Ok((ms, seq))
}

/// Parse a partial auto-ID like "1000-*" → Some(1000).
/// Returns None if the format doesn't match "ms-*".
fn parse_partial_auto_id(arg: &[u8]) -> Option<u64> {
    let text = std::str::from_utf8(arg).ok()?;
    let (ms_str, seq_str) = text.split_once('-')?;
    if seq_str != "*" {
        return None;
    }
    ms_str.parse::<u64>().ok()
}

/// Append the decimal ASCII of `n` to `out` without the general `fmt` machinery.
/// (CrimsonHawk) `format!` is ~21% of XRANGE full-scan self-time (the per-entry
/// `<ms>-<seq>` id); this manual path is byte-identical and avoids the formatter
/// plus its intermediate `String` allocation.
#[inline]
fn push_u64_ascii(out: &mut Vec<u8>, mut n: u64) {
    if n == 0 {
        out.push(b'0');
        return;
    }
    // u64::MAX is 20 digits.
    let mut buf = [0u8; 20];
    let mut i = buf.len();
    while n > 0 {
        i -= 1;
        buf[i] = b'0' + (n % 10) as u8;
        n /= 10;
    }
    out.extend_from_slice(&buf[i..]);
}

#[inline]
pub fn format_stream_id(id: StreamId) -> Vec<u8> {
    // 20 (ms) + 1 ('-') + 20 (seq) worst case.
    let mut out = Vec::with_capacity(41);
    push_u64_ascii(&mut out, id.0);
    out.push(b'-');
    push_u64_ascii(&mut out, id.1);
    out
}

#[inline]
// (CrimsonHawk) pub for the fr-runtime XADD borrowed fast path
// (`execute_plain_xadd_borrowed`) — reused verbatim so the auto-id `*` resolution
// is byte-identical to the generic handler. `None` = ID space exhausted (the
// fast path then defers to the generic path for the exact error).
pub fn next_auto_stream_id(last_id: Option<StreamId>, now_ms: u64) -> Option<StreamId> {
    let id = match last_id {
        Some((last_ms, last_seq)) => {
            if now_ms > last_ms {
                (now_ms, 0)
            } else {
                // Try to increment sequence; if exhausted, try next ms
                match last_seq.checked_add(1) {
                    Some(next_seq) => (last_ms, next_seq),
                    None => {
                        // Sequence exhausted at this ms, try next ms
                        let next_ms = last_ms.checked_add(1)?;
                        (next_ms, 0)
                    }
                }
            }
        }
        None => (now_ms, 0),
    };
    if id == (0, 0) { Some((0, 1)) } else { Some(id) }
}

// Upstream t_stream.c::streamIncrID — successor in lexicographic (ms, seq)
// order. Returns None when 'id' is already the maximum representable id.
#[inline]
fn stream_incr_id(id: StreamId) -> Option<StreamId> {
    let (ms, seq) = id;
    if seq == u64::MAX {
        if ms == u64::MAX {
            None
        } else {
            Some((ms + 1, 0))
        }
    } else {
        Some((ms, seq + 1))
    }
}

// Upstream t_stream.c::streamDecrID — predecessor of 'id'. Returns None
// when 'id' is the minimum (0-0).
#[inline]
fn stream_decr_id(id: StreamId) -> Option<StreamId> {
    let (ms, seq) = id;
    if seq == 0 {
        if ms == 0 {
            None
        } else {
            Some((ms - 1, u64::MAX))
        }
    } else {
        Some((ms, seq - 1))
    }
}

// Parse a strict numeric id form ('ms' or 'ms-seq') with partial-id
// completion: when seq is omitted, 0 is used for start bounds, u64::MAX
// for end bounds (mirrors upstream's missing_seq plumbing).
fn parse_partial_stream_id(arg: &[u8], is_start: bool) -> Result<StreamId, RespFrame> {
    let invalid_id = || {
        RespFrame::Error("ERR Invalid stream ID specified as stream command argument".to_string())
    };
    if let Some((ms_str, seq_str)) = std::str::from_utf8(arg)
        .ok()
        .and_then(|text| text.split_once('-'))
    {
        let ms = ms_str.parse::<u64>().map_err(|_| invalid_id())?;
        let seq = seq_str.parse::<u64>().map_err(|_| invalid_id())?;
        return Ok((ms, seq));
    }
    let ms = parse_u64_arg(arg).map_err(|_| invalid_id())?;
    Ok((ms, if is_start { 0 } else { u64::MAX }))
}

// XRANGE/XREVRANGE/XPENDING/XAUTOCLAIM bound parser. Matches upstream's
// streamParseIntervalIDOrReply: accepts the `-`/`+` sentinels and the
// `(N` exclusive prefix (Redis 6.2+). XREAD/XTRIM/XADD MINID/XGROUP do
// NOT accept `(N` and must reject it upstream of this call.
pub fn parse_stream_range_bound(arg: &[u8], is_start: bool) -> Result<StreamId, RespFrame> {
    let invalid_id = || {
        RespFrame::Error("ERR Invalid stream ID specified as stream command argument".to_string())
    };

    if let Some(rest) = arg.strip_prefix(b"(") {
        if rest.is_empty() || rest == b"-" || rest == b"+" {
            return Err(invalid_id());
        }
        let inner = parse_partial_stream_id(rest, is_start)?;
        return if is_start {
            stream_incr_id(inner).ok_or_else(|| {
                RespFrame::Error("ERR invalid start ID for the interval".to_string())
            })
        } else {
            stream_decr_id(inner)
                .ok_or_else(|| RespFrame::Error("ERR invalid end ID for the interval".to_string()))
        };
    }

    if arg == b"-" {
        return Ok((0, 0));
    }
    if arg == b"+" {
        return Ok((u64::MAX, u64::MAX));
    }

    parse_partial_stream_id(arg, is_start)
}

fn parse_xread_id(arg: &[u8]) -> Result<StreamId, RespFrame> {
    if arg == b"-" || arg == b"+" || arg == b"$" || arg.starts_with(b"(") {
        return Err(RespFrame::Error(
            "ERR Invalid stream ID specified as stream command argument".to_string(),
        ));
    }
    parse_stream_range_bound(arg, true)
}

fn xadd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("XADD"));
    }

    // Parse optional flags before the ID: NOMKSTREAM, MAXLEN/MINID, LIMIT.
    // Upstream t_stream.c::streamParseAddOrTrimArgsOrReply mandates:
    //   * MAXLEN and MINID are mutually exclusive
    //   * LIMIT requires a trimming strategy AND the approximate (~) form
    //   * LIMIT must be >= 0
    // (br-frankenredis-r71v)
    let mut idx = 2;
    let mut nomkstream = false;
    let mut trim_maxlen: Option<usize> = None;
    let mut trim_minid: Option<StreamId> = None;
    let mut trim_approx = false;
    let mut limit_given = false;
    let mut trim_limit: Option<i64> = None;

    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"NOMKSTREAM") {
            nomkstream = true;
            idx += 1;
        } else if eq_ascii_command(&argv[idx], b"MAXLEN") {
            if trim_maxlen.is_some() || trim_minid.is_some() {
                return Ok(RespFrame::Error(
                    "ERR syntax error, MAXLEN and MINID options at the same time are not compatible"
                        .to_string(),
                ));
            }
            idx += 1;
            if idx >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            if eq_ascii_command(&argv[idx], b"=") || eq_ascii_command(&argv[idx], b"~") {
                trim_approx = eq_ascii_command(&argv[idx], b"~");
                idx += 1;
                if idx >= argv.len() {
                    return Err(CommandError::SyntaxError);
                }
            }
            let n = parse_i64_arg(&argv[idx])?;
            if n < 0 {
                return Ok(RespFrame::Error(
                    "ERR The MAXLEN argument must be >= 0.".to_string(),
                ));
            }
            trim_maxlen = Some(usize::try_from(n).map_err(|_| CommandError::InvalidInteger)?);
            idx += 1;
        } else if eq_ascii_command(&argv[idx], b"MINID") {
            if trim_maxlen.is_some() || trim_minid.is_some() {
                return Ok(RespFrame::Error(
                    "ERR syntax error, MAXLEN and MINID options at the same time are not compatible"
                        .to_string(),
                ));
            }
            idx += 1;
            if idx >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            if eq_ascii_command(&argv[idx], b"=") || eq_ascii_command(&argv[idx], b"~") {
                trim_approx = eq_ascii_command(&argv[idx], b"~");
                idx += 1;
                if idx >= argv.len() {
                    return Err(CommandError::SyntaxError);
                }
            }
            let min_id = match parse_stream_id(&argv[idx]) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            };
            trim_minid = Some(min_id);
            idx += 1;
        } else if eq_ascii_command(&argv[idx], b"LIMIT") && idx + 1 < argv.len() {
            // Upstream t_stream.c::streamParseAddOrTrimArgsOrReply
            // only consumes LIMIT when a value follows; otherwise the
            // token falls through and becomes the candidate stream ID,
            // which fails ID parsing. (br-frankenredis-xaddlimit)
            idx += 1;
            let n = parse_i64_arg(&argv[idx])?;
            if n < 0 {
                return Ok(RespFrame::Error(
                    "ERR The LIMIT argument must be >= 0.".to_string(),
                ));
            }
            trim_limit = Some(n);
            limit_given = true;
            idx += 1;
        } else {
            break;
        }
    }

    // (frankenredis-kgxl7) Upstream t_stream.c::streamParseAddOrTrimArgsOrReply
    // gates the "without specifying a trimming strategy" check on
    // `args->limit && args->trim_strategy == NONE` — the limit value is
    // a long long treated as truthy/falsy in C, so `LIMIT 0` (value 0)
    // skips this check and falls through to the "without ~" branch.
    // fr previously gated on the `limit_given` boolean, which fired
    // regardless of value; mirror vendored's quirk by checking value > 0
    // so that `XADD ms LIMIT 0 * a 1` returns the "without the special ~
    // option" wording.
    if trim_limit.is_some_and(|n| n > 0) && trim_maxlen.is_none() && trim_minid.is_none() {
        return Ok(RespFrame::Error(
            "ERR syntax error, LIMIT cannot be used without specifying a trimming strategy"
                .to_string(),
        ));
    }
    if limit_given && !trim_approx {
        return Ok(RespFrame::Error(
            "ERR syntax error, LIMIT cannot be used without the special ~ option".to_string(),
        ));
    }
    let trim_limit_usize: Option<usize> = trim_limit.and_then(|n| {
        if n == 0 {
            None
        } else {
            Some(usize::try_from(n).unwrap_or(usize::MAX))
        }
    });

    // argv[idx] should now be the ID, followed by field-value pairs
    if idx >= argv.len() {
        return Err(CommandError::WrongArity("XADD"));
    }
    let id_idx = idx;
    idx += 1;

    // Upstream t_stream.c::xaddCommand validates the explicit
    // stream-id BEFORE checking field-value pair arity, so a token
    // like 'LIMIT' that fell through option parsing emits
    // 'Invalid stream ID specified...' rather than wrong-arity.
    // (br-frankenredis-xaddidvalid)
    if !eq_ascii_command(&argv[id_idx], b"*") && parse_partial_auto_id(&argv[id_idx]).is_none() {
        match parse_stream_id(&argv[id_idx]) {
            Ok((0, 0)) => {
                // Upstream xaddCommand also requires the ID to be
                // strictly greater than 0-0. (br-frankenredis-xaddorder)
                return Ok(RespFrame::Error(
                    "ERR The ID specified in XADD must be greater than 0-0".to_string(),
                ));
            }
            Ok(_) => {}
            Err(reply) => return Ok(reply),
        }
    }

    // Must have at least one field-value pair after the ID
    if idx >= argv.len() || !(argv.len() - idx).is_multiple_of(2) {
        return Err(CommandError::WrongArity("XADD"));
    }

    let mut fields = Vec::with_capacity((argv.len() - idx) / 2);
    while idx + 1 < argv.len() {
        fields.push((argv[idx].clone(), argv[idx + 1].clone()));
        idx += 2;
    }

    // XADD is a write (upstream streamTypeLookupWriteOrCreate -> lookupKeyWrite),
    // so resolving the auto-id / existence must NOT bump keyspace_hits/misses.
    // (frankenredis-ljtdo)
    let (stream_exists, last_id) = if nomkstream {
        store.xlast_id_with_existence_no_stat(&argv[1], now_ms)?
    } else {
        (true, store.xlast_id_no_stat(&argv[1], now_ms)?)
    };
    // NOMKSTREAM: if key doesn't exist, return nil (but proceed if key exists, even empty)
    if nomkstream && !stream_exists {
        return Ok(RespFrame::BulkString(None));
    }
    let id = if eq_ascii_command(&argv[id_idx], b"*") {
        match next_auto_stream_id(last_id, now_ms) {
            Some(id) => id,
            None => {
                return Ok(RespFrame::Error(
                    "ERR The stream has exhausted the last possible ID, unable to add more items"
                        .to_string(),
                ));
            }
        }
    } else if let Some(partial_ms) = parse_partial_auto_id(&argv[id_idx]) {
        // "ms-*" format: explicit timestamp, auto-generate sequence
        let seq = match last_id {
            Some((last_ms, last_seq)) if partial_ms == last_ms => match last_seq.checked_add(1) {
                Some(next_seq) => next_seq,
                None => {
                    return Ok(RespFrame::Error(
                            "ERR The stream has exhausted the last possible ID, unable to add more items"
                                .to_string(),
                        ));
                }
            },
            Some((last_ms, _)) if partial_ms < last_ms => {
                return Ok(RespFrame::Error(
                    "ERR The ID specified in XADD is equal or smaller than the target stream top item"
                        .to_string(),
                ));
            }
            _ => 0,
        };
        let id = (partial_ms, seq);
        if id == (0, 0) {
            (0, 1) // minimum allowed ID
        } else {
            id
        }
    } else {
        let id = match parse_stream_id(&argv[id_idx]) {
            Ok(id) => id,
            Err(reply) => return Ok(reply),
        };
        if id == (0, 0) {
            return Ok(RespFrame::Error(
                "ERR The ID specified in XADD must be greater than 0-0".to_string(),
            ));
        }
        if let Some(last_id) = last_id
            && id <= last_id
        {
            return Ok(RespFrame::Error(
                "ERR The ID specified in XADD is equal or smaller than the target stream top item"
                    .to_string(),
            ));
        }
        id
    };

    store.xadd(&argv[1], id, &fields, now_ms)?;
    // (frankenredis-xaddtrimdirty) Upstream t_stream.c::xaddCommand bumps
    // server.dirty exactly once (for the add). Its inline MAXLEN/MINID trim
    // fires a separate "xtrim" keyspace event but does NOT add to server.dirty —
    // only standalone XTRIM does. fr's store.xtrim bumps dirty per removed entry,
    // so capture the post-add value and restore it after the inline trim to
    // avoid overcounting rdb_changes_since_last_save (the trim's removals still
    // happen; only the dirty contribution is dropped). The secondary "xtrim"
    // keyspace notification on inline trim is tracked separately.
    let dirty_after_add = store.dirty;
    // (frankenredis-f7xy7) Total entries removed by the inline trim, used to
    // decide whether to fire the secondary "xtrim" keyspace event.
    let mut trimmed_entries: usize = 0;

    // Apply inline trimming after the add. Approximate trimming
    // (~) without LIMIT is best-effort: upstream lazily skips trimming
    // when the trailing radix-tree node isn't full, and we model that
    // as a no-op. Approximate trimming WITH `LIMIT n` (Redis 6.2+
    // dialect) executes through the store cap path; LIMIT 0 means no
    // cap, matching upstream streamAddTrimArgs::limit. Exact trimming
    // (= or absent qualifier) always executes and rejects LIMIT
    // upstream of this block. (br-frankenredis-r71v + LIMIT clause
    // follow-up)
    // (frankenredis-c6j11) Inline MAXLEN trim mirrors upstream xaddCommand's
    // streamTrim: exact trim honors the target verbatim; approximate (~) trim
    // removes whole nodes via stream_approx_trim_target (an un-LIMITed `~` gets
    // the upstream default cap of 100 * stream-node-max-entries). Crucially this
    // runs for `~` even WITHOUT an explicit LIMIT — upstream is not a no-op, so
    // `XADD ... MAXLEN ~ N` trims on every add (and `~ 0` clears the stream).
    if let Some(max_len) = trim_maxlen {
        let effective_max_len = if trim_approx {
            // xlen returns Result<usize, StoreError>; on error, fall through to a
            // no-op (effective_max_len = current_len means "trim to current").
            let current_len = store.xlen(&argv[1], now_ms).unwrap_or(max_len);
            let approx_limit = if limit_given {
                trim_limit_usize
            } else {
                Some(STREAM_APPROX_TRIM_DEFAULT_LIMIT)
            };
            stream_approx_trim_target(current_len, max_len, approx_limit)
        } else {
            max_len
        };
        let pass_limit = if trim_approx { None } else { trim_limit_usize };
        let removed = store
            .xtrim(&argv[1], effective_max_len, pass_limit, now_ms)
            .unwrap_or(0);
        trimmed_entries = trimmed_entries.saturating_add(removed);
    }
    // (frankenredis-8t4vl.1) Inline MINID trim mirrors XTRIM MINID and upstream
    // xaddCommand's streamTrim: exact (= or absent) removes every entry below the
    // threshold; approximate (~) removes WHOLE head nodes via
    // store.xtrim_minid_approx and runs on every add even WITHOUT an explicit
    // LIMIT (an un-LIMITed `~` gets the upstream default cap of
    // 100 * stream-node-max-entries). The previous approx-without-LIMIT no-op /
    // exact-with-LIMIT path diverged from Redis node-boundary semantics.
    if let Some(min_id) = trim_minid {
        let removed = if trim_approx {
            let approx_limit = if limit_given {
                trim_limit_usize
            } else {
                Some(STREAM_APPROX_TRIM_DEFAULT_LIMIT)
            };
            store
                .xtrim_minid_approx(&argv[1], min_id, approx_limit, now_ms)
                .unwrap_or(0)
        } else {
            store
                .xtrim_minid(&argv[1], min_id, trim_limit_usize, now_ms)
                .unwrap_or(0)
        };
        trimmed_entries = trimmed_entries.saturating_add(removed);
    }
    // (frankenredis-xaddtrimdirty) Drop any dirty units the inline trim added;
    // the XADD itself already accounted for exactly one.
    store.dirty = dirty_after_add;
    // (frankenredis-f7xy7) Signal the runtime to emit the secondary "xtrim"
    // keyspace event (after "xadd") iff the inline trim actually removed
    // entries — matching upstream xaddCommand. Overwritten by every XADD.
    store.last_xadd_trimmed = trimmed_entries > 0;

    Ok(RespFrame::BulkString(Some(format_stream_id(id))))
}

fn xlen(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("XLEN"));
    }
    let len = store.xlen(&argv[1], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

fn xdel(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("XDEL"));
    }

    // XDEL is a write (upstream lookupKeyWriteOrReply) — no keyspace hit/miss.
    // (frankenredis-ljtdo)
    let (stream_exists, _) = store.xlast_id_with_existence_no_stat(&argv[1], now_ms)?;
    if !stream_exists {
        return Ok(RespFrame::Integer(0));
    }

    let mut ids = Vec::with_capacity(argv.len() - 2);
    for arg in &argv[2..] {
        let id = match parse_stream_id(arg) {
            Ok(id) => id,
            Err(reply) => return Ok(reply),
        };
        ids.push(id);
    }

    let removed = store.xdel(&argv[1], &ids, now_ms)?;
    Ok(RespFrame::Integer(
        i64::try_from(removed).unwrap_or(i64::MAX),
    ))
}

fn xtrim(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Upstream t_stream.c::xtrimCommand → streamParseAddOrTrimArgsOrReply:
    //   XTRIM key (MAXLEN | MINID) [= | ~] threshold [LIMIT count]
    //
    // Upstream walks argv token-by-token, tracking a trim_strategy
    // flag and a limit_given flag, and bails on the first guard that
    // trips. That structure (rather than fr's previous positional
    // parser) is what surfaces the type-specific parse error on a
    // missing threshold (MAXLEN → integer, MINID → stream ID) and
    // the bespoke "MAXLEN and MINID at the same time" wording when
    // either strategy token reappears. (frankenredis-wglo0)
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("XTRIM"));
    }

    #[derive(Copy, Clone, PartialEq)]
    enum Strat {
        None,
        MaxLen,
        MinId,
    }

    let mut strategy = Strat::None;
    let mut approx = false;
    let mut maxlen_value: Option<usize> = None;
    let mut minid_value: Option<StreamId> = None;
    let mut limit: Option<usize> = None;
    let mut limit_given = false;
    let mut limit_value: i64 = 0;
    let incompat = || {
        RespFrame::Error(
            "ERR syntax error, MAXLEN and MINID options at the same time are not compatible"
                .to_string(),
        )
    };

    let mut i = 2usize;
    while i < argv.len() {
        let tok = &argv[i];
        let is_maxlen = eq_ascii_command(tok, b"MAXLEN");
        let is_minid = eq_ascii_command(tok, b"MINID");
        if is_maxlen || is_minid {
            if strategy != Strat::None {
                return Ok(incompat());
            }
            // moreargs check matches upstream: with no argument at
            // all after the strategy token, fall through to the
            // generic "syntax error" catch-all.
            if i + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let mut j = i + 1;
            if eq_ascii_command(&argv[j], b"~") {
                approx = true;
                j += 1;
            } else if eq_ascii_command(&argv[j], b"=") {
                approx = false;
                j += 1;
            }
            // Upstream parses the threshold inline (eagerly) via
            // getLongLongFromObjectOrReply for MAXLEN or
            // streamParseStrictIDOrReply for MINID. That ordering
            // matters for cases like `MAXLEN ~ MAXLEN 5` — the
            // second `MAXLEN` is consumed as the *threshold* of the
            // first and surfaces "value is not an integer" before
            // the duplicate-strategy guard ever sees the second
            // token.
            if j >= argv.len() {
                if is_maxlen {
                    return Ok(RespFrame::Error(
                        "ERR value is not an integer or out of range".to_string(),
                    ));
                } else {
                    return Ok(RespFrame::Error(
                        "ERR Invalid stream ID specified as stream command argument".to_string(),
                    ));
                }
            }
            if is_maxlen {
                let n = parse_i64_arg(&argv[j])?;
                if n < 0 {
                    return Ok(RespFrame::Error(
                        "ERR The MAXLEN argument must be >= 0.".to_string(),
                    ));
                }
                maxlen_value = Some(usize::try_from(n).unwrap_or(usize::MAX));
                strategy = Strat::MaxLen;
            } else {
                let id = match parse_stream_id(&argv[j]) {
                    Ok(id) => id,
                    Err(reply) => return Ok(reply),
                };
                minid_value = Some(id);
                strategy = Strat::MinId;
            }
            i = j + 1;
            continue;
        }
        if eq_ascii_command(tok, b"LIMIT") {
            // (frankenredis-5zr5y) Upstream
            // t_stream.c::streamParseAddOrTrimArgsOrReply parses LIMIT
            // eagerly (value + bounds check only) and defers the
            // "without specifying a trimming strategy" / "XTRIM must be
            // called with a trimming strategy" / "without the special ~
            // option" diagnostics until after the full arg loop.
            // The first of those checks is gated on `args->limit`
            // (long long, C-truthy), so `LIMIT 0` skips it and falls
            // through to the XTRIM-specific "must be called with a
            // trimming strategy" wording. fr previously errored eagerly
            // here on strategy==None and missed both behaviors.
            if i + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let n = parse_i64_arg(&argv[i + 1])?;
            if n < 0 {
                return Ok(RespFrame::Error(
                    "ERR The LIMIT argument must be >= 0.".to_string(),
                ));
            }
            limit_given = true;
            limit_value = n;
            if n != 0 {
                limit = Some(usize::try_from(n).unwrap_or(usize::MAX));
            }
            i += 2;
            continue;
        }
        // Catch-all: any other token (including a stray "FOO" or a
        // trailing token after a complete MAXLEN/MINID + LIMIT
        // clause) maps to "syntax error" per upstream.
        return Err(CommandError::SyntaxError);
    }

    // (frankenredis-5zr5y) Deferred post-parse diagnostics, in vendored
    // order (t_stream.c:998-1019). The first check is value-gated to
    // mirror C's truthy/falsy semantics for `args->limit`.
    if limit_given && limit_value > 0 && strategy == Strat::None {
        return Ok(RespFrame::Error(
            "ERR syntax error, LIMIT cannot be used without specifying a trimming strategy"
                .to_string(),
        ));
    }
    if strategy == Strat::None {
        return Ok(RespFrame::Error(
            "ERR syntax error, XTRIM must be called with a trimming strategy".to_string(),
        ));
    }
    if limit_given && !approx {
        return Ok(RespFrame::Error(
            "ERR syntax error, LIMIT cannot be used without the special ~ option".to_string(),
        ));
    }
    let is_maxlen = strategy == Strat::MaxLen;

    // (frankenredis-hpz8a) Approximate (~) trim is node-boundary aware
    // in upstream: streamTrim only deletes whole radix-tree listpack
    // nodes (default `stream-node-max-entries` = 100). For exact (=
    // or no qualifier), the requested target is honored verbatim.
    //
    // fr's storage doesn't expose rax node boundaries, so MAXLEN approximate
    // (~) trimming is modeled by stream_approx_trim_target — upstream removes
    // whole nodes from the head while the remaining length stays >= the target
    // and (within a LIMIT) the evicted count fits, so the tail node is dropped
    // only at MAXLEN ~ 0 and a sub-node LIMIT evicts nothing. An un-LIMITed `~`
    // gets the upstream default cap of 100 * stream-node-max-entries; an
    // explicit LIMIT 0 (limit == None below) means no cap. (frankenredis-c6j11)
    //
    // MINID approximate (~) trimming is node-boundary aware too, via
    // store.xtrim_minid_approx — whole head nodes are evicted while the node's
    // last id < threshold (and within LIMIT), mirroring streamTrim. An un-LIMITed
    // `~` gets the upstream default cap; an explicit LIMIT 0 means no cap.
    // (frankenredis-8t4vl)

    if is_maxlen {
        let max_len = maxlen_value.expect("maxlen_value set when strategy = MaxLen");
        let effective_max_len = if approx {
            let current_len = store.xlen(&argv[1], now_ms)?;
            let approx_limit = if limit_given {
                limit
            } else {
                Some(STREAM_APPROX_TRIM_DEFAULT_LIMIT)
            };
            stream_approx_trim_target(current_len, max_len, approx_limit)
        } else {
            max_len
        };
        // After computing the effective target, the underlying
        // store does an exact trim. Pass `None` for limit because we
        // already incorporated the cap into effective_max_len.
        let pass_limit = if approx { None } else { limit };
        let removed = store.xtrim(&argv[1], effective_max_len, pass_limit, now_ms)?;
        Ok(RespFrame::Integer(
            i64::try_from(removed).unwrap_or(i64::MAX),
        ))
    } else {
        let min_id = minid_value.expect("minid_value set when strategy = MinId");
        let removed = if approx {
            let approx_limit = if limit_given {
                limit
            } else {
                Some(STREAM_APPROX_TRIM_DEFAULT_LIMIT)
            };
            store.xtrim_minid_approx(&argv[1], min_id, approx_limit, now_ms)?
        } else {
            store.xtrim_minid(&argv[1], min_id, limit, now_ms)?
        };
        Ok(RespFrame::Integer(
            i64::try_from(removed).unwrap_or(i64::MAX),
        ))
    }
}

/// Number of entries per rax/listpack node — upstream's default
/// `stream-node-max-entries`. (frankenredis-c6j11)
const STREAM_NODE_MAX_ENTRIES: usize = 100;
/// Default LIMIT applied to an approximate (`~`) trim with no explicit LIMIT,
/// mirroring upstream's `args->limit = 100 * server.stream_node_max_entries`.
const STREAM_APPROX_TRIM_DEFAULT_LIMIT: usize = 100 * STREAM_NODE_MAX_ENTRIES;

/// Mirror upstream `t_stream.c::streamTrim`'s approximate (`~`) eviction: it
/// removes WHOLE rax nodes (each holding up to `STREAM_NODE_MAX_ENTRIES`
/// entries; the head nodes are full and the tail node may be partial) from the
/// head of the stream while evicting the node keeps the remaining length
/// `>= max_len` AND, when a LIMIT is in effect, the running evicted count would
/// not exceed it. `limit == None` means no cap (an explicit `LIMIT 0`). Returns
/// the post-trim target length (`current_len - removed`).
///
/// Consequences matched against vendored 7.2.4: the tail (partial) node is
/// evicted only when `max_len == 0` (so `MAXLEN ~ 0` clears the stream), and a
/// LIMIT smaller than the head node size evicts nothing (whole-node granularity)
/// rather than a partial count. The earlier "round the exact count down to a
/// node multiple, then `.min(limit)`" model diverged on both. (frankenredis-c6j11)
fn stream_approx_trim_target(current_len: usize, max_len: usize, limit: Option<usize>) -> usize {
    let mut removed = 0usize;
    loop {
        let remaining = current_len - removed;
        let node = STREAM_NODE_MAX_ENTRIES.min(remaining);
        if node == 0 {
            break;
        }
        if limit.is_some_and(|lim| removed + node > lim) {
            break;
        }
        if remaining - node < max_len {
            break;
        }
        removed += node;
    }
    current_len - removed
}

fn stream_record_to_frame(id: StreamId, fields: Vec<(Vec<u8>, Vec<u8>)>) -> RespFrame {
    let mut field_frames = Vec::with_capacity(fields.len().saturating_mul(2));
    for (field, value) in fields {
        field_frames.push(RespFrame::BulkString(Some(field)));
        field_frames.push(RespFrame::BulkString(Some(value)));
    }
    RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(format_stream_id(id))),
        RespFrame::Array(Some(field_frames)),
    ]))
}

/// Build the per-group info frame. Upstream Redis 7.2
/// t_stream.c::xinfoCommand emits this as a Map in RESP3 and an
/// alternating-array in RESP2. (br-frankenredis-f6z6)
fn stream_group_info_to_frame(
    name: Vec<u8>,
    consumers: usize,
    pending: usize,
    last_delivered_id: StreamId,
    entries_read: Option<u64>,
    lag: RespFrame,
    resp_protocol_version: i64,
) -> RespFrame {
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"name".to_vec())),
            RespFrame::BulkString(Some(name)),
        ),
        (
            RespFrame::BulkString(Some(b"consumers".to_vec())),
            RespFrame::Integer(i64::try_from(consumers).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"pending".to_vec())),
            RespFrame::Integer(i64::try_from(pending).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
            RespFrame::BulkString(Some(format_stream_id(last_delivered_id))),
        ),
        (
            RespFrame::BulkString(Some(b"entries-read".to_vec())),
            stream_entries_read_frame(entries_read),
        ),
        (RespFrame::BulkString(Some(b"lag".to_vec())), lag),
    ];
    if resp_protocol_version == 3 {
        RespFrame::Map(Some(pairs))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        RespFrame::Array(Some(flat))
    }
}

/// (br-frankenredis-f6z6, extended by frankenredis-p4dpj)
fn stream_consumer_info_to_frame(
    info: (Vec<u8>, usize, u64, i64),
    resp_protocol_version: i64,
) -> RespFrame {
    let (name, pending_count, idle_ms, inactive_or_neg_one) = info;
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"name".to_vec())),
            RespFrame::BulkString(Some(name)),
        ),
        (
            RespFrame::BulkString(Some(b"pending".to_vec())),
            RespFrame::Integer(i64::try_from(pending_count).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"idle".to_vec())),
            RespFrame::Integer(i64::try_from(idle_ms).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"inactive".to_vec())),
            RespFrame::Integer(inactive_or_neg_one),
        ),
    ];
    if resp_protocol_version == 3 {
        RespFrame::Map(Some(pairs))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        RespFrame::Array(Some(flat))
    }
}

/// Consumer rows nested under `XINFO STREAM ... FULL`.
///
/// Upstream t_stream.c::xinfoReplyWithStreamInfo emits these as maps with
/// seen/active timestamps and per-consumer PEL details.
/// (frankenredis-hgqc, frankenredis-xjmm)
fn stream_full_consumer_info_to_frame(
    info: (Vec<u8>, usize, u64, i64),
    pending: Vec<RespFrame>,
    now_ms: u64,
    resp_protocol_version: i64,
) -> RespFrame {
    let (name, pending_count, idle_ms, inactive_or_neg_one) = info;
    let seen_time = now_ms.saturating_sub(idle_ms);
    // (frankenredis-p4dpj) active-time mirrors inactive: when -1
    // (never active) emit -1, otherwise reconstruct the absolute
    // timestamp from now_ms - inactive_ms.
    let active_time: i64 = if inactive_or_neg_one < 0 {
        -1
    } else {
        i64::try_from(now_ms.saturating_sub(inactive_or_neg_one as u64)).unwrap_or(i64::MAX)
    };
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"name".to_vec())),
            RespFrame::BulkString(Some(name)),
        ),
        (
            RespFrame::BulkString(Some(b"seen-time".to_vec())),
            RespFrame::Integer(i64::try_from(seen_time).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"active-time".to_vec())),
            RespFrame::Integer(active_time),
        ),
        (
            RespFrame::BulkString(Some(b"pel-count".to_vec())),
            RespFrame::Integer(i64::try_from(pending_count).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"pending".to_vec())),
            RespFrame::Array(Some(pending)),
        ),
    ];

    if resp_protocol_version == 3 {
        RespFrame::Map(Some(pairs))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        RespFrame::Array(Some(flat))
    }
}

struct StreamFullGroupFrameInfo {
    name: Vec<u8>,
    pending_count: usize,
    last_delivered_id: StreamId,
    entries_read: Option<u64>,
    lag: RespFrame,
}

#[derive(Clone, Copy)]
struct StreamLagInfo {
    entries_added: u64,
    len: usize,
    first_id: Option<StreamId>,
    last_id: Option<StreamId>,
    max_deleted_id: StreamId,
    last_generated_id: Option<StreamId>,
}

fn stream_full_group_info_to_frame(
    info: StreamFullGroupFrameInfo,
    pending_frames: Vec<RespFrame>,
    consumer_frames: Vec<RespFrame>,
    resp_protocol_version: i64,
) -> RespFrame {
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"name".to_vec())),
            RespFrame::BulkString(Some(info.name)),
        ),
        (
            RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
            RespFrame::BulkString(Some(format_stream_id(info.last_delivered_id))),
        ),
        (
            RespFrame::BulkString(Some(b"entries-read".to_vec())),
            stream_entries_read_frame(info.entries_read),
        ),
        (RespFrame::BulkString(Some(b"lag".to_vec())), info.lag),
        (
            RespFrame::BulkString(Some(b"pel-count".to_vec())),
            RespFrame::Integer(i64::try_from(info.pending_count).unwrap_or(i64::MAX)),
        ),
        (
            RespFrame::BulkString(Some(b"pending".to_vec())),
            RespFrame::Array(Some(pending_frames)),
        ),
        (
            RespFrame::BulkString(Some(b"consumers".to_vec())),
            RespFrame::Array(Some(consumer_frames)),
        ),
    ];

    if resp_protocol_version == 3 {
        RespFrame::Map(Some(pairs))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        RespFrame::Array(Some(flat))
    }
}

fn stream_full_count_limit(full_count: usize) -> usize {
    if full_count == 0 {
        usize::MAX
    } else {
        full_count
    }
}

fn stream_radix_tree_metrics(live_len: usize, entries_added: u64) -> (i64, i64) {
    if live_len == 0 {
        return (0, 1);
    }

    // Redis streams pack many sequential entries into one radix-tree
    // leaf/listpack until stream-node-max-entries is reached. fr stores
    // stream entries directly in a BTreeMap, so approximate the default
    // 100-entry listpack split instead of treating every live entry as a
    // radix key. Deleted entries still occupied a listpack before XDEL,
    // so entries-added is the better proxy for small tombstone cases.
    const STREAM_NODE_MAX_ENTRIES: u64 = 100;
    let retained_entries = entries_added.max(u64::try_from(live_len).unwrap_or(u64::MAX));
    let radix_keys = retained_entries.div_ceil(STREAM_NODE_MAX_ENTRIES).max(1);
    let radix_nodes = radix_keys.saturating_add(1);
    (
        i64::try_from(radix_keys).unwrap_or(i64::MAX),
        i64::try_from(radix_nodes).unwrap_or(i64::MAX),
    )
}

fn stream_entries_read_frame(entries_read: Option<u64>) -> RespFrame {
    entries_read.map_or(RespFrame::BulkString(None), |read| {
        RespFrame::Integer(i64::try_from(read).unwrap_or(i64::MAX))
    })
}

fn stream_lag_range_has_tombstones(
    stream_len: usize,
    first_id: Option<StreamId>,
    max_deleted_id: StreamId,
    start_id: StreamId,
) -> bool {
    if stream_len == 0 || max_deleted_id == (0, 0) {
        return false;
    }
    let Some(first_id) = first_id else {
        return false;
    };
    if first_id > max_deleted_id {
        return false;
    }
    start_id <= max_deleted_id
}

/// Faithful port of upstream t_stream.c `streamReplyWithCGLag`. Returns the
/// group's lag (entries yet to be delivered) as an Integer, or a null bulk
/// string when the value can't be determined (SCG_INVALID — e.g. the group's
/// position falls inside a tombstoned range).
fn stream_full_group_lag_frame(
    stream: StreamLagInfo,
    last_delivered_id: StreamId,
    entries_read: Option<u64>,
) -> RespFrame {
    let lag: Option<i64> = if stream.entries_added == 0 {
        // The lag of a newly-initialized stream is 0.
        Some(0)
    } else if let Some(read) = entries_read
        && !stream_lag_range_has_tombstones(
            stream.len,
            stream.first_id,
            stream.max_deleted_id,
            last_delivered_id,
        )
    {
        // No fragmentation ahead → the group's logical reads counter is valid.
        Some(
            i64::try_from(stream.entries_added)
                .unwrap_or(i64::MAX)
                .saturating_sub(i64::try_from(read).unwrap_or(i64::MAX)),
        )
    } else {
        // Estimate the group's logical read counter from its last-delivered-id.
        stream_estimate_distance_from_first_ever(&stream, last_delivered_id).map(|read| {
            i64::try_from(stream.entries_added)
                .unwrap_or(i64::MAX)
                .saturating_sub(i64::try_from(read).unwrap_or(i64::MAX))
        })
    };
    match lag {
        Some(value) => RespFrame::Integer(value),
        None => RespFrame::BulkString(None),
    }
}

/// Port of upstream `streamEstimateDistanceFromFirstEverEntry(s, id)`, where
/// `id` is the group's last-delivered-id. Crucially this uses the
/// last-GENERATED-id watermark as the stream's last ID (upstream `s->last_id`,
/// which survives an emptied or XSETID-lowered stream and may sit AHEAD of the
/// last live entry), not the last live entry — so a group caught up to the
/// watermark reports the exact `entries_added` counter (lag 0) even when the
/// last physical entry is older. `None` is the SCG_INVALID sentinel.
fn stream_estimate_distance_from_first_ever(stream: &StreamLagInfo, id: StreamId) -> Option<u64> {
    if stream.entries_added == 0 {
        return Some(0);
    }
    // `s->last_id` is the watermark; fall back to the last live entry only when
    // no watermark was supplied (synthetic callers / never-XSETID'd streams).
    let last_id = stream
        .last_generated_id
        .or(stream.last_id)
        .unwrap_or((0, 0));
    let len = u64::try_from(stream.len).unwrap_or(u64::MAX);
    // In an empty stream, an ID at or before the last ID maps to entries_added.
    if stream.len == 0 && id <= last_id {
        return Some(stream.entries_added);
    }
    match id.cmp(&last_id) {
        std::cmp::Ordering::Equal => return Some(stream.entries_added),
        std::cmp::Ordering::Greater => return None, // a future ID is unknown
        std::cmp::Ordering::Less => {}
    }
    let first_id = stream.first_id.unwrap_or((0, 0));
    // No fragmentation ahead iff there are no tombstones, or the last tombstone
    // is strictly below the current first entry.
    if stream.max_deleted_id == (0, 0) || stream.max_deleted_id < first_id {
        match id.cmp(&first_id) {
            std::cmp::Ordering::Less => return Some(stream.entries_added.saturating_sub(len)),
            std::cmp::Ordering::Equal => {
                return Some(stream.entries_added.saturating_sub(len).saturating_add(1));
            }
            std::cmp::Ordering::Greater => {}
        }
    }
    None
}

fn stream_pending_delivery_time(now_ms: u64, idle_ms: u64) -> i64 {
    i64::try_from(now_ms.saturating_sub(idle_ms)).unwrap_or(i64::MAX)
}

fn stream_full_group_pending_to_frame(
    (id, consumer, idle_ms, deliveries): StreamPendingRecord,
    now_ms: u64,
) -> RespFrame {
    RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(format_stream_id(id))),
        RespFrame::BulkString(Some(consumer)),
        RespFrame::Integer(stream_pending_delivery_time(now_ms, idle_ms)),
        RespFrame::Integer(i64::try_from(deliveries).unwrap_or(i64::MAX)),
    ]))
}

fn stream_full_consumer_pending_to_frame(record: StreamPendingRecord, now_ms: u64) -> RespFrame {
    let (id, _consumer, idle_ms, deliveries) = record;
    RespFrame::Array(Some(vec![
        RespFrame::BulkString(Some(format_stream_id(id))),
        RespFrame::Integer(stream_pending_delivery_time(now_ms, idle_ms)),
        RespFrame::Integer(i64::try_from(deliveries).unwrap_or(i64::MAX)),
    ]))
}

fn xread(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("XREAD"));
    }

    let mut idx = 1usize;
    let mut count: Option<usize> = None;
    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"COUNT") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::WrongArity("XREAD"));
            }
            // Upstream t_stream.c::xreadCommand parses COUNT via
            // getLongFromObjectOrReply, then `if (count < 0) count = 0;`.
            // The inner read loop has `if (count > 0 && ... > count)
            // rsubcount = count;`, so count == 0 means "no upper bound",
            // not "limit to 0". fr was rejecting negative COUNT with
            // 'value is not an integer or out of range' and treating
            // COUNT 0 as `Some(0)` (an explicit zero-cap) — both diverge
            // from upstream. Map any non-positive COUNT to None
            // (unbounded). (frankenredis-xreadcount)
            let parsed = parse_i64_arg(&argv[idx + 1])?;
            count = if parsed > 0 {
                Some(usize::try_from(parsed).unwrap_or(usize::MAX))
            } else {
                None
            };
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"BLOCK") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::WrongArity("XREAD"));
            }
            if store.script_nesting_level >= 1 {
                return Err(CommandError::Custom(
                    "XREAD command is not allowed with BLOCK option from scripts".to_string(),
                ));
            }
            // Validate the timeout but ignore it (non-blocking only)
            let _deadline_ms = parse_blocking_deadline_milliseconds(&argv[idx + 1], now_ms)?;
            idx += 2;
            continue;
        }
        break;
    }

    if idx >= argv.len() || !eq_ascii_command(&argv[idx], b"STREAMS") {
        return Err(CommandError::SyntaxError);
    }
    // (frankenredis-pnkd6) Upstream t_stream.c::xreadCommand only
    // accepts the STREAMS keyword via `!strcasecmp(o,"STREAMS") &&
    // moreargs` — when STREAMS is the last arg the keyword does not
    // match and the parse loop's terminal `else` branch emits
    // shared.syntaxerr. The 'Unbalanced ... list of streams' wording
    // is reserved for odd-count tails (e.g. STREAMS k id1 id2 id3);
    // an empty tail must surface as the generic syntax error.
    if idx + 1 >= argv.len() {
        return Err(CommandError::SyntaxError);
    }
    idx += 1;

    let tail = argv.len().saturating_sub(idx);
    // Upstream t_stream.c::xreadCommand emits the dedicated
    // 'Unbalanced ... list of streams' error when the trailing
    // STREAMS arg count is odd. (br-frankenredis-xreadbal)
    if !tail.is_multiple_of(2) {
        return Err(CommandError::Custom(
            "ERR Unbalanced 'xread' list of streams: for each stream key an ID or '$' must be specified.".to_string(),
        ));
    }
    let stream_count = tail / 2;
    let keys = &argv[idx..idx + stream_count];
    let ids = &argv[idx + stream_count..];

    // (frankenredis-lnglj) Upstream t_stream.c::xreadCommand looks up each stream
    // key TWICE via lookupKeyRead — once in the id-resolution loop, once in the
    // serve loop — so every key records two keyspace hits, and any WRONGTYPE /
    // bad-id error surfaces in the resolution pass BEFORE any key is served. Keep
    // the two-phase shape: `store.xlast_id` is the first lookup (and resolves the
    // `$` cursor); `store.xread` below is the second.
    let mut cursors = Vec::with_capacity(stream_count);
    for (key, id_arg) in keys.iter().zip(ids.iter()) {
        let resolved_last = store.xlast_id(key, now_ms)?;
        let cursor = if id_arg.as_slice() == b"$" {
            resolved_last.unwrap_or((u64::MAX, u64::MAX))
        } else {
            match parse_xread_id(id_arg) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            }
        };
        cursors.push(cursor);
    }

    let mut out = Vec::new();
    for (key, cursor) in keys.iter().zip(cursors.iter()) {
        let records = store.xread(key, *cursor, count, now_ms)?;
        if records.is_empty() {
            continue;
        }

        let mut entry_frames = Vec::with_capacity(records.len());
        for (id, fields) in records {
            entry_frames.push(stream_record_to_frame(id, fields));
        }

        out.push((
            RespFrame::BulkString(Some(key.clone())),
            RespFrame::Array(Some(entry_frames)),
        ));
    }

    if out.is_empty() {
        Ok(RespFrame::Array(None))
    } else {
        let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
        if resp3 {
            Ok(RespFrame::Map(Some(out)))
        } else {
            let array = out
                .into_iter()
                .map(|(k, v)| RespFrame::Array(Some(vec![k, v])))
                .collect();
            Ok(RespFrame::Array(Some(array)))
        }
    }
}

fn xreadgroup(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 7 {
        return Err(CommandError::WrongArity("XREADGROUP"));
    }
    if !eq_ascii_command(&argv[1], b"GROUP") {
        return Err(CommandError::SyntaxError);
    }

    let group = &argv[2];
    let consumer = &argv[3];

    let mut idx = 4usize;
    let mut count: Option<usize> = None;
    let mut noack = false;
    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"COUNT") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::WrongArity("XREADGROUP"));
            }
            // Same parse-order discipline as XREAD: upstream clamps
            // negative COUNT to 0 and treats 0 as "no upper bound".
            // Map any non-positive COUNT to None (unbounded).
            // (frankenredis-xreadcount)
            let parsed = parse_i64_arg(&argv[idx + 1])?;
            count = if parsed > 0 {
                Some(usize::try_from(parsed).unwrap_or(usize::MAX))
            } else {
                None
            };
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"BLOCK") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::WrongArity("XREADGROUP"));
            }
            if store.script_nesting_level >= 1 {
                return Err(CommandError::Custom(
                    "XREADGROUP command is not allowed with BLOCK option from scripts".to_string(),
                ));
            }
            // Validate the timeout but ignore it (non-blocking only)
            let _deadline_ms = parse_blocking_deadline_milliseconds(&argv[idx + 1], now_ms)?;
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"NOACK") {
            noack = true;
            idx += 1;
            continue;
        }
        break;
    }

    if idx >= argv.len() || !eq_ascii_command(&argv[idx], b"STREAMS") {
        return Err(CommandError::SyntaxError);
    }
    // (frankenredis-pnkd6) Same `STREAMS && moreargs` short-circuit as
    // upstream — empty tail must surface as generic syntax error, not
    // the Unbalanced wording.
    if idx + 1 >= argv.len() {
        return Err(CommandError::SyntaxError);
    }
    idx += 1;

    let tail = argv.len().saturating_sub(idx);
    // (br-frankenredis-xreadbal)
    if !tail.is_multiple_of(2) {
        return Err(CommandError::Custom(
            // Upstream t_stream.c::xreadCommand uses '>' for the XREADGROUP
            // sentinel (vs '$' for plain XREAD); pin the matching wording.
            // (br-frankenredis-xreadbal)
            "ERR Unbalanced 'xreadgroup' list of streams: for each stream key an ID or '>' must be specified.".to_string(),
        ));
    }
    let stream_count = tail / 2;
    let keys = &argv[idx..idx + stream_count];
    let ids = &argv[idx + stream_count..];

    let mut out = Vec::new();
    for (key, id_arg) in keys.iter().zip(ids.iter()) {
        // (frankenredis-xrgrphist) A history read (explicit id, not '>') always
        // includes the stream in the reply — with an empty entry list when the
        // consumer has no matching pending entries — matching upstream
        // t_stream.c::xreadCommand. Only the '>' (new-entries) cursor omits an
        // empty stream (and yields nil when every requested stream is empty).
        let is_new_entries = id_arg.as_slice() == b">";
        let cursor = if is_new_entries {
            StreamGroupReadCursor::NewEntries
        } else {
            match parse_xread_id(id_arg) {
                Ok(id) => StreamGroupReadCursor::Id(id),
                Err(id_reply) => {
                    // (frankenredis-xrgord) Upstream t_stream.c::xreadCommand
                    // looks up the key (recording the keyspace hit/miss) and
                    // checks its type, then the consumer group, BEFORE parsing
                    // the stream ID. So a wrong-type key surfaces WRONGTYPE and a
                    // missing key/group surfaces NOGROUP even when the ID is also
                    // malformed; only a valid stream + existing group lets the
                    // invalid-ID error stand. The valid-ID path is unchanged
                    // (store.xreadgroup performs the single keyspace lookup), so
                    // this branch must itself count the lookup — key_type routes
                    // through the stat-recording value_type, exactly like the
                    // XCLAIM early-validation path above. (frankenredis-xrgord)
                    return match store.key_type(key, now_ms) {
                        None => Ok(xreadgroup_nogroup_error(key, group)),
                        Some("stream") => {
                            let group_exists = store
                                .stream_consumer_groups(key)
                                .is_some_and(|groups| groups.contains_key(group.as_slice()));
                            if group_exists {
                                Ok(id_reply)
                            } else {
                                Ok(xreadgroup_nogroup_error(key, group))
                            }
                        }
                        Some(_) => Err(CommandError::Store(StoreError::WrongType)),
                    };
                }
            }
        };

        // (frankenredis-xrgkscount) Upstream t_stream.c::xreadCommand looks each
        // stream key up TWICE via lookupKeyRead — once in the parse/resolution
        // loop and once in the serve loop. store.xreadgroup below performs only
        // the serve-loop lookup (records one hit). For a key that will actually
        // serve (an existing stream WITH the requested group) record the
        // resolution-loop lookup too, so the valid path counts 2 hits like
        // upstream. Keys that error out (missing/wrong-type/no-group/bad-id) are
        // looked up exactly once below (or in the bad-id branch above), matching
        // upstream's single resolution-loop lookup for those — same shape as the
        // XREAD fix (lnglj, 58996991e). Stat-only; reply/data unchanged.
        if matches!(
            store.peek_value_type(key, now_ms),
            Some(fr_store::ValueType::Stream)
        ) && store
            .stream_consumer_groups(key)
            .is_some_and(|groups| groups.contains_key(group.as_slice()))
        {
            store.exists_no_touch(key, now_ms);
        }
        let read_options = StreamGroupReadOptions {
            cursor,
            noack,
            count,
        };
        let Some(records) = store.xreadgroup(key, group, consumer, read_options, now_ms)? else {
            return Ok(xreadgroup_nogroup_error(key, group));
        };
        if records.is_empty() && is_new_entries {
            continue;
        }

        let mut entry_frames = Vec::with_capacity(records.len());
        for (id, fields) in records {
            // (frankenredis-s0614) A history read may return PEL entries whose
            // stream entry was XDEL'd (tombstones); the store marks them with an
            // empty field list (a live entry always has >=1 field), and upstream
            // renders them as `[id, nil]` rather than `[id, []]`.
            if fields.is_empty() {
                entry_frames.push(RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(format_stream_id(id))),
                    RespFrame::Array(None),
                ])));
            } else {
                entry_frames.push(stream_record_to_frame(id, fields));
            }
        }

        out.push((
            RespFrame::BulkString(Some(key.clone())),
            RespFrame::Array(Some(entry_frames)),
        ));
    }

    if out.is_empty() {
        Ok(RespFrame::Array(None))
    } else {
        let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
        if resp3 {
            Ok(RespFrame::Map(Some(out)))
        } else {
            let array = out
                .into_iter()
                .map(|(k, v)| RespFrame::Array(Some(vec![k, v])))
                .collect();
            Ok(RespFrame::Array(Some(array)))
        }
    }
}

fn xclaim(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 6 {
        return Err(CommandError::WrongArity("XCLAIM"));
    }

    // Upstream t_stream.c::xclaimCommand looks up the stream key + the
    // consumer group BEFORE parsing min-idle-time or any trailing
    // options, so a missing-key/group call replies NOGROUP regardless
    // of how mangled the rest of the argv is. The other XCLAIM-family
    // commands (XPENDING, XAUTOCLAIM) parse args first per upstream;
    // only XCLAIM short-circuits early. (frankenredis-3qrt)
    // No-stat type peek: XCLAIM does ONE lookupKeyRead upstream and the store
    // xclaim call below records that single keyspace hit. A stat-counting
    // key_type precheck here would double-count keyspace_hits.
    match store.value_type_no_stat(&argv[1], now_ms) {
        None => return Ok(xclaim_nogroup_error(&argv[1], &argv[2])),
        Some(fr_store::ValueType::Stream) => {
            let group_exists = store
                .stream_consumer_groups(&argv[1])
                .is_some_and(|groups| groups.contains_key(argv[2].as_slice()));
            if !group_exists {
                return Ok(xclaim_nogroup_error(&argv[1], &argv[2]));
            }
        }
        Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
    }

    // Upstream t_stream.c::xclaimCommand parses min-idle-time via
    // getLongLongFromObjectOrReply with the 'Invalid min-idle-time
    // argument for XCLAIM' error string, then clamps negative values
    // silently to 0. (br-frankenredis-xclaim)
    let min_idle_raw = parse_i64_arg(&argv[4]).map_err(|_| {
        CommandError::Custom("ERR Invalid min-idle-time argument for XCLAIM".to_string())
    })?;
    let min_idle_time_ms = if min_idle_raw < 0 {
        0
    } else {
        u64::try_from(min_idle_raw).unwrap_or(u64::MAX)
    };

    // Upstream's ID-collection loop breaks on the first arg that
    // doesn't parse as a stream ID, then continues to option parsing
    // (the NULL client passed to streamParseStrictIDOrReply suppresses
    // the parse-time error reply). So an unrecognised trailing token
    // surfaces as 'Unrecognized XCLAIM option <X>', not as 'Invalid
    // stream ID …'. (br-frankenredis-xclaim)
    let mut ids = Vec::new();
    let mut idx = 5usize;
    while idx < argv.len() {
        match parse_stream_id(&argv[idx]) {
            Ok(id) => {
                ids.push(id);
                idx += 1;
            }
            Err(_) => break,
        }
    }
    // Upstream tolerates an empty IDs vector — the for-loop break
    // simply hands the first unparseable token to the option parser
    // for the 'Unrecognized XCLAIM option …' fallthrough.

    let mut idle_ms: Option<u64> = None;
    let mut time_ms: Option<u64> = None;
    let mut retry_count: Option<u64> = None;
    let mut force = false;
    let mut justid = false;
    let mut last_id: Option<StreamId> = None;

    // Upstream's option parser emits 'Unrecognized XCLAIM option <opt>'
    // for any unknown token AND for known options without a value
    // (the `&& moreargs` guards mean IDLE/TIME/RETRYCOUNT/LASTID
    // without an arg fall through to the catch-all). The numeric
    // option arguments use the per-option 'Invalid X option argument
    // for XCLAIM' wording. (br-frankenredis-xclaim)
    let unrecognized = |opt: &[u8]| {
        CommandError::Custom(format!(
            "ERR Unrecognized XCLAIM option '{}'",
            String::from_utf8_lossy(opt)
        ))
    };
    let invalid_opt_arg = |label: &str| {
        CommandError::Custom(format!("ERR Invalid {label} option argument for XCLAIM"))
    };
    // (frankenredis-xclaimneg) Upstream t_stream.c::xclaimCommand:
    //   IDLE  → `deliverytime = now - idle`, then if `deliverytime < 0
    //           || deliverytime > now` clamp to now. So a negative IDLE
    //           silently maps to "delivery time = now" (i.e. idle=0).
    //   TIME  → `deliverytime = parsed`; if `< 0 || > now` clamp to now.
    //           Negative TIME also silently maps to "delivery time = now".
    //   RETRYCOUNT → upstream stores the parsed long long verbatim with
    //           no validation; negatives are silently accepted.
    // fr was rejecting all three with the per-option "Invalid X option
    // argument for XCLAIM" wording. Clamp the parsed value to >= 0 to
    // mirror upstream's accept-and-clamp behavior.
    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"IDLE") {
            if idx + 1 >= argv.len() {
                return Err(unrecognized(&argv[idx]));
            }
            let parsed = parse_i64_arg(&argv[idx + 1]).map_err(|_| invalid_opt_arg("IDLE"))?;
            idle_ms = Some(u64::try_from(parsed.max(0)).unwrap_or(u64::MAX));
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"TIME") {
            if idx + 1 >= argv.len() {
                return Err(unrecognized(&argv[idx]));
            }
            let parsed = parse_i64_arg(&argv[idx + 1]).map_err(|_| invalid_opt_arg("TIME"))?;
            time_ms = Some(u64::try_from(parsed.max(0)).unwrap_or(u64::MAX));
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"RETRYCOUNT") {
            if idx + 1 >= argv.len() {
                return Err(unrecognized(&argv[idx]));
            }
            let parsed =
                parse_i64_arg(&argv[idx + 1]).map_err(|_| invalid_opt_arg("RETRYCOUNT"))?;
            retry_count = Some(u64::try_from(parsed.max(0)).unwrap_or(u64::MAX));
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"FORCE") {
            force = true;
            idx += 1;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"JUSTID") {
            justid = true;
            idx += 1;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"LASTID") {
            if idx + 1 >= argv.len() {
                return Err(unrecognized(&argv[idx]));
            }
            let parsed = match parse_stream_id(&argv[idx + 1]) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            };
            last_id = Some(parsed);
            idx += 2;
            continue;
        }
        return Err(unrecognized(&argv[idx]));
    }

    if idle_ms.is_some() && time_ms.is_some() {
        return Err(CommandError::SyntaxError);
    }

    let Some(reply) = store.xclaim(
        &argv[1],
        &argv[2],
        &argv[3],
        &ids,
        StreamClaimOptions {
            min_idle_time_ms,
            idle_ms,
            time_ms,
            retry_count,
            force,
            justid,
            last_id,
        },
        now_ms,
    )?
    else {
        return Ok(xclaim_nogroup_error(&argv[1], &argv[2]));
    };

    match reply {
        StreamClaimReply::Entries(entries) => Ok(RespFrame::Array(Some(
            entries
                .into_iter()
                .map(|(id, fields)| stream_record_to_frame(id, fields))
                .collect(),
        ))),
        StreamClaimReply::Ids(ids) => Ok(RespFrame::Array(Some(
            ids.into_iter()
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .collect(),
        ))),
    }
}

fn xautoclaim(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 6 {
        return Err(CommandError::WrongArity("XAUTOCLAIM"));
    }

    // Upstream t_stream.c::xautoclaimCommand parses min-idle-time
    // via getLongLongFromObjectOrReply with the dedicated wording
    // 'Invalid min-idle-time argument for XAUTOCLAIM'. Negative
    // values are rejected. (br-frankenredis-xautoclaim)
    let min_idle_raw = parse_i64_arg(&argv[4]).map_err(|_| {
        CommandError::Custom("ERR Invalid min-idle-time argument for XAUTOCLAIM".to_string())
    })?;
    // Upstream silently clamps negative min-idle-time to 0.
    let min_idle_time_ms = if min_idle_raw < 0 {
        0
    } else {
        u64::try_from(min_idle_raw).unwrap_or(u64::MAX)
    };

    // Upstream xautoclaimCommand parses the start ID via
    // streamParseIntervalIDOrReply, which accepts `-`/`+`/`(N`. fr was
    // routing this through parse_stream_id which only allows the strict
    // 'ms-seq' form. (frankenredis-j3j26)
    let start = match parse_stream_range_bound(&argv[5], true) {
        Ok(id) => id,
        Err(reply) => return Ok(reply),
    };

    let mut count = 100usize;
    let mut justid = false;
    let mut idx = 6usize;
    while idx < argv.len() {
        if eq_ascii_command(&argv[idx], b"COUNT") {
            if idx + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream uses getRangeLongFromObjectOrReply that
            // returns 'COUNT must be > 0' for any non-positive or
            // unparseable value. (br-frankenredis-xautoclaim)
            // It also bounds COUNT to [1, LONG_MAX / max(sizeof(streamID)=16,
            // attempts_factor=10)] = [1, i64::MAX / 16]; a too-LARGE count is
            // rejected with the same wording, and this range-check runs BEFORE
            // the key type-check (t_stream.c:3361-3377 precedes the checkType
            // at :3380), so a wrong-type key still surfaces 'COUNT must be > 0'
            // for an out-of-range count. (frankenredis-zlpqd)
            const XAUTOCLAIM_MAX_COUNT: i64 = i64::MAX / 16;
            let bad_count = || CommandError::Custom("ERR COUNT must be > 0".to_string());
            let parsed = parse_i64_arg(&argv[idx + 1]).map_err(|_| bad_count())?;
            if !(1..=XAUTOCLAIM_MAX_COUNT).contains(&parsed) {
                return Err(bad_count());
            }
            count = usize::try_from(parsed).unwrap_or(usize::MAX);
            idx += 2;
            continue;
        }
        if eq_ascii_command(&argv[idx], b"JUSTID") {
            justid = true;
            idx += 1;
            continue;
        }
        return Err(CommandError::SyntaxError);
    }

    let Some(reply) = store.xautoclaim(
        &argv[1],
        &argv[2],
        &argv[3],
        start,
        StreamAutoClaimOptions {
            min_idle_time_ms,
            count,
            justid,
        },
        now_ms,
    )?
    else {
        return Ok(xautoclaim_nogroup_error(&argv[1], &argv[2]));
    };

    match reply {
        StreamAutoClaimReply::Entries {
            next_start,
            entries,
            deleted_ids,
        } => {
            let mut entry_frames = Vec::with_capacity(entries.len());
            for (id, fields) in entries {
                entry_frames.push(stream_record_to_frame(id, fields));
            }
            let deleted_frames = deleted_ids
                .into_iter()
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .collect();
            Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(format_stream_id(next_start))),
                RespFrame::Array(Some(entry_frames)),
                RespFrame::Array(Some(deleted_frames)),
            ])))
        }
        StreamAutoClaimReply::Ids {
            next_start,
            ids,
            deleted_ids,
        } => {
            let id_frames = ids
                .into_iter()
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .collect();
            let deleted_frames = deleted_ids
                .into_iter()
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .collect();
            Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(format_stream_id(next_start))),
                RespFrame::Array(Some(id_frames)),
                RespFrame::Array(Some(deleted_frames)),
            ])))
        }
    }
}

fn xpending(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Upstream commands.def declares XPENDING with arity = -3, so the
    // table-level WrongArity check fires for argc < 3. (br-frankenredis-xpending)
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("XPENDING"));
    }
    if argv.len() == 3 {
        let Some((total, min_id, max_id, per_consumer)) =
            store.xpending_summary(&argv[1], &argv[2], now_ms)?
        else {
            return Ok(xpending_nogroup_error(&argv[1], &argv[2]));
        };

        let mut consumer_frames = Vec::with_capacity(per_consumer.len());
        for (consumer, pending_count) in per_consumer {
            // Upstream t_stream.c (xpendingCommand summary form) emits each
            // per-consumer pending count as a BULK STRING, not an integer.
            // Vendored 7.2.4 returns "1", not :1. (gauntlet B1)
            consumer_frames.push(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(consumer)),
                RespFrame::BulkString(Some(pending_count.to_string().into_bytes())),
            ])));
        }

        // Upstream t_stream.c::xpendingCommand summary form: when there are
        // no pending entries it emits the consumers field as a NULL array
        // (addReplyNullArray → *-1 / _), not an empty array. fr was emitting
        // *0. min/max are already null in that case. (frankenredis-b2okv)
        let consumers_frame = if total == 0 {
            RespFrame::Array(None)
        } else {
            RespFrame::Array(Some(consumer_frames))
        };
        return Ok(RespFrame::Array(Some(vec![
            RespFrame::Integer(i64::try_from(total).unwrap_or(i64::MAX)),
            min_id
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .unwrap_or(RespFrame::BulkString(None)),
            max_id
                .map(|id| RespFrame::BulkString(Some(format_stream_id(id))))
                .unwrap_or(RespFrame::BulkString(None)),
            consumers_frame,
        ])));
    }

    // Extended form: XPENDING key group [[IDLE min-idle-time] start end count [consumer]]
    // Upstream allows argc ∈ {3, 6, 7, 8, 9} and emits SyntaxError
    // for anything else. Trailing args past the canonical positions
    // are silently ignored. (br-frankenredis-xpending)
    if !matches!(argv.len(), 3 | 6 | 7 | 8 | 9) {
        return Err(CommandError::SyntaxError);
    }
    let mut min_idle_ms: u64 = 0;
    let (start_idx, consumer_idx) = if argv.len() >= 4 && eq_ascii_command(&argv[3], b"IDLE") {
        // IDLE form: argv[3]=IDLE, argv[4]=min-idle-time, argv[5]=start, argv[6]=end, argv[7]=count, [argv[8]=consumer]
        if argv.len() < 8 {
            return Err(CommandError::SyntaxError);
        }
        min_idle_ms = parse_i64_arg(&argv[4]).map(|v| v.max(0) as u64)?;
        (5, if argv.len() >= 9 { Some(8) } else { None })
    } else {
        (3, if argv.len() >= 7 { Some(6) } else { None })
    };

    // (frankenredis-xpendcount) Upstream t_stream.c::xpendingCommand:
    // 2895-2929 parses the count argument FIRST and clamps `count < 0`
    // to 0, then parses start/end. This affects the surfaced error for
    // mixed-bad inputs:
    //   XPENDING s g abc - + 5  →  upstream rejects count='+' first
    //                              ("value is not an integer..."),
    //                              fr was rejecting start='abc'
    //                              ("Invalid stream ID...").
    //   XPENDING s g - + -1     →  upstream clamps count=0 and replies
    //                              with an empty array; fr was erroring.
    let count_raw = parse_i64_arg(&argv[start_idx + 2])?;
    let count = if count_raw < 0 {
        0
    } else {
        usize::try_from(count_raw).unwrap_or(usize::MAX)
    };

    let start = match parse_stream_range_bound(&argv[start_idx], true) {
        Ok(id) => id,
        Err(reply) => return Ok(reply),
    };
    let end = match parse_stream_range_bound(&argv[start_idx + 1], false) {
        Ok(id) => id,
        Err(reply) => return Ok(reply),
    };
    let consumer = consumer_idx.map(|idx| argv[idx].as_slice());

    let Some(entries) = store.xpending_entries(
        &argv[1],
        &argv[2],
        (start, end),
        count,
        consumer,
        now_ms,
        min_idle_ms,
    )?
    else {
        return Ok(xpending_nogroup_error(&argv[1], &argv[2]));
    };

    let mut out = Vec::with_capacity(entries.len());
    for (id, owner, idle_ms, deliveries) in entries {
        out.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(format_stream_id(id))),
            RespFrame::BulkString(Some(owner)),
            RespFrame::Integer(i64::try_from(idle_ms).unwrap_or(i64::MAX)),
            RespFrame::Integer(i64::try_from(deliveries).unwrap_or(i64::MAX)),
        ])));
    }
    Ok(RespFrame::Array(Some(out)))
}

fn xgroup(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("XGROUP"));
    }
    let sub = match std::str::from_utf8(&argv[1]) {
        Ok(s) => s,
        Err(_) => return Err(CommandError::InvalidUtf8Argument),
    };

    if sub.eq_ignore_ascii_case("CREATE") {
        // XGROUP CREATE key groupname id|$ [MKSTREAM] [ENTRIESREAD entries-read]
        // Upstream xgroupCommand parses MKSTREAM and ENTRIESREAD as
        // independent option tokens (in any order) and dispatches
        // addReplySubcommandSyntaxError for any unrecognised tail.
        // (br-frankenredis-xgroupcreate)
        let create_subcommand_syntax = || {
            CommandError::Custom(format!(
                "ERR unknown subcommand or wrong number of arguments for '{sub}'. Try XGROUP HELP."
            ))
        };
        // XGROUP CREATE has arity -5 in upstream commands.def, so
        // argc<5 emits the table-level 'wrong number of arguments
        // for xgroup|create command' wording. Bad option tokens
        // with argc>=5 still reach the subcommand-syntax-error
        // catch-all below. (br-frankenredis-xgrouparity)
        if argv.len() < 5 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        let mut mkstream = false;
        let mut entries_read = None;
        let mut i = 5;
        while i < argv.len() {
            if eq_ascii_command(&argv[i], b"MKSTREAM") {
                mkstream = true;
                i += 1;
            } else if eq_ascii_command(&argv[i], b"ENTRIESREAD") {
                if i + 1 >= argv.len() {
                    return Err(create_subcommand_syntax());
                }
                let parsed = parse_i64_arg(&argv[i + 1])?;
                if parsed < 0 && parsed != -1 {
                    return Err(CommandError::Custom(
                        "ERR value for ENTRIESREAD must be positive or -1".to_string(),
                    ));
                }
                entries_read = u64::try_from(parsed).ok();
                i += 2;
            } else {
                return Err(create_subcommand_syntax());
            }
        }

        // (frankenredis-a6nkn, sibling of b7jra) Upstream xgroupCommand resolves
        // the key BEFORE parsing the id, so an existing wrong-type key reports
        // WRONGTYPE and a missing key (without MKSTREAM) reports "requires the
        // key to exist" — rather than "Invalid stream ID". Use the no-stat
        // precheck and ignore the group result: id parsing still precedes the
        // BUSYGROUP check (verified vs vendored: `XGROUP CREATE s <existing> bad`
        // returns "Invalid stream ID", not BUSYGROUP), and MKSTREAM only waives
        // the missing-key error, never the wrong-type one.
        match store.stream_group_precheck(&argv[2], &argv[3], now_ms) {
            Err(StoreError::WrongType) => {
                return Err(CommandError::Store(StoreError::WrongType));
            }
            Err(StoreError::KeyNotFound) if !mkstream => {
                return Ok(xgroup_key_required_error());
            }
            _ => {}
        }

        // XGROUP CREATE is a write (upstream lookupKeyWrite) — resolving a `$`
        // start id must NOT bump keyspace_hits/misses. (frankenredis-ljtdo)
        let start_id = if eq_ascii_command(&argv[4], b"$") {
            store.xlast_id_no_stat(&argv[2], now_ms)?.unwrap_or((0, 0))
        } else {
            // Upstream xgroupCommand CREATE uses streamParseStrictIDOrReply
            // (rejects `-`/`+`/`(N`); only `$` and a strict id are valid.
            if eq_ascii_command(&argv[4], b"-")
                || eq_ascii_command(&argv[4], b"+")
                || argv[4].starts_with(b"(")
            {
                return Ok(RespFrame::Error(
                    "ERR Invalid stream ID specified as stream command argument".to_string(),
                ));
            }
            match parse_stream_range_bound(&argv[4], true) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            }
        };

        return match store.xgroup_create_with_entries_read(
            &argv[2],
            &argv[3],
            start_id,
            entries_read,
            mkstream,
            now_ms,
        ) {
            Ok(true) => Ok(RespFrame::SimpleString("OK".to_string())),
            Ok(false) => Ok(RespFrame::Error(
                "BUSYGROUP Consumer Group name already exists".to_string(),
            )),
            // Upstream xgroupCommand emits the verbose "requires the
            // key to exist" message for every XGROUP subcommand on a
            // missing stream key (see legacy_redis_code/redis/src/
            // t_stream.c::xgroupCommand). (br-frankenredis-qcmh)
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("DESTROY") {
        if argv.len() != 4 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        // Upstream xgroupCommand DESTROY rejects missing keys with
        // the verbose "requires the key to exist" error rather than
        // silently returning 0. Store::xlen returns Ok(0) on a missing
        // key (same as the user-facing XLEN contract), so it can't be
        // used to distinguish absent-vs-empty here — Store::key_type
        // is the right probe. (frankenredis-n4qd, supersedes qcmh)
        // No-stat type peek — XGROUP is a write (lookupKeyWrite, no keyspace
        // stats); a stat-counting key_type precheck would over-count.
        match store.value_type_no_stat(&argv[2], now_ms) {
            None => return Ok(xgroup_key_required_error()),
            Some(fr_store::ValueType::Stream) => {}
            Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
        }
        return match store.xgroup_destroy(&argv[2], &argv[3], now_ms) {
            Ok(removed) => Ok(RespFrame::Integer(if removed { 1 } else { 0 })),
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("SETID") {
        // XGROUP SETID key groupname id|$ [ENTRIESREAD entries-read]
        // XGROUP SETID has arity -5 in upstream commands.def, so
        // argc<5 emits the table-level 'wrong number of arguments
        // for xgroup|setid command' wording. Other shape errors
        // (argc=6 or unknown trailing token at argc=7) still reach
        // the addReplySubcommandSyntaxError catch-all in
        // xgroupCommand. (br-frankenredis-xgrouparity)
        let setid_subcommand_syntax = || {
            CommandError::Custom(format!(
                "ERR unknown subcommand or wrong number of arguments for '{sub}'. Try XGROUP HELP."
            ))
        };
        if argv.len() < 5 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        if argv.len() != 5 && argv.len() != 7 {
            return Err(setid_subcommand_syntax());
        }
        // (frankenredis-xgsetid) Upstream xgroupCommand parses the optional
        // ENTRIESREAD argument in a loop at the TOP (t_stream.c:2589-2605),
        // BEFORE the key lookup/type-check, the key/group existence checks, and
        // the id parse. So a malformed ENTRIESREAD value (or a bad trailing
        // token) surfaces its own error ahead of WRONGTYPE / "requires key to
        // exist" / NOGROUP / "Invalid stream ID".
        if argv.len() == 7 && !eq_ascii_command(&argv[5], b"ENTRIESREAD") {
            return Err(setid_subcommand_syntax());
        }
        let entries_read = if argv.len() == 7 {
            let parsed = parse_i64_arg(&argv[6])?;
            if parsed < 0 && parsed != -1 {
                return Err(CommandError::Custom(
                    "ERR value for ENTRIESREAD must be positive or -1".to_string(),
                ));
            }
            u64::try_from(parsed).ok()
        } else {
            None
        };
        // (frankenredis-b7jra) Resolve the key + consumer group before the id
        // parse, so a missing key or group reports its own error rather than
        // "Invalid stream ID". No-stat precheck (matches `lookupKeyWrite`: no
        // keyspace-hit accounting) so the ordering is fixed without perturbing
        // INFO keyspace stats.
        match store.stream_group_precheck(&argv[2], &argv[3], now_ms) {
            Ok(true) => {}
            Ok(false) => return Ok(xgroup_nogroup_error(&argv[2], &argv[3])),
            Err(StoreError::KeyNotFound) => return Ok(xgroup_key_required_error()),
            Err(err) => return Err(CommandError::Store(err)),
        }
        // (frankenredis-xgsetid) Upstream SETID uses streamParseIDOrReply — the
        // NON-strict parser (t_stream.c:2694) — so `-` (0-0) and `+` (the
        // maximum id) are valid, as is `$` (the stream's last id). Only the
        // `(N` interval syntax is rejected.
        // XGROUP SETID is a write (upstream lookupKeyWrite) — resolving a `$`
        // id must NOT bump keyspace_hits/misses. (frankenredis-ljtdo)
        let last_delivered_id = if eq_ascii_command(&argv[4], b"$") {
            store.xlast_id_no_stat(&argv[2], now_ms)?.unwrap_or((0, 0))
        } else if argv[4].starts_with(b"(") {
            return Ok(RespFrame::Error(
                "ERR Invalid stream ID specified as stream command argument".to_string(),
            ));
        } else {
            match parse_stream_range_bound(&argv[4], true) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            }
        };
        return match store.xgroup_setid_with_entries_read(
            &argv[2],
            &argv[3],
            last_delivered_id,
            entries_read,
            now_ms,
        ) {
            Ok(true) => Ok(RespFrame::SimpleString("OK".to_string())),
            // The precheck already guaranteed key+group exist, so these arms are
            // defensive (e.g. a concurrent expiry between precheck and apply).
            Ok(false) => Ok(xgroup_nogroup_error(&argv[2], &argv[3])),
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("CREATECONSUMER") {
        if argv.len() != 5 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        // Same dead-code shape as DELCONSUMER (n4g5, supersedes qcmh):
        // Store::xlen returns Ok(0) for both missing keys AND empty
        // streams (e.g. created via XGROUP CREATE ... MKSTREAM), so the
        // xlen probe wrongly emitted "key required" against an empty
        // stream that vendored accepts. Use Store::key_type instead.
        // (frankenredis-3vfpi)
        // No-stat type peek — XGROUP is a write (lookupKeyWrite, no keyspace
        // stats); a stat-counting key_type precheck would over-count.
        match store.value_type_no_stat(&argv[2], now_ms) {
            None => return Ok(xgroup_key_required_error()),
            Some(fr_store::ValueType::Stream) => {}
            Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
        }
        return match store.xgroup_createconsumer(&argv[2], &argv[3], &argv[4], now_ms) {
            Ok(Some(created)) => Ok(RespFrame::Integer(if created { 1 } else { 0 })),
            Ok(None) => Ok(xgroup_nogroup_error(&argv[2], &argv[3])),
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("DELCONSUMER") {
        if argv.len() != 5 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: sub.to_string(),
            });
        }
        // Same dead-code shape as XGROUP DESTROY: Store::xlen returns
        // Ok(0) for a missing key (matching the user-facing XLEN
        // contract), so the KeyNotFound arm never fired and dispatch
        // fell through to xgroup_delconsumer → NOGROUP error wording
        // instead of upstream's key-required ERR. Replace the probe
        // with Store::key_type. (frankenredis-n4g5, supersedes qcmh)
        // No-stat type peek — XGROUP is a write (lookupKeyWrite, no keyspace
        // stats); a stat-counting key_type precheck would over-count.
        match store.value_type_no_stat(&argv[2], now_ms) {
            None => return Ok(xgroup_key_required_error()),
            Some(fr_store::ValueType::Stream) => {}
            Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
        }
        return match store.xgroup_delconsumer(&argv[2], &argv[3], &argv[4], now_ms) {
            Ok(Some(deleted_pending)) => Ok(RespFrame::Integer(
                i64::try_from(deleted_pending).unwrap_or(i64::MAX),
            )),
            Ok(None) => Ok(xgroup_nogroup_error(&argv[2], &argv[3])),
            Err(StoreError::KeyNotFound) => Ok(xgroup_key_required_error()),
            Err(err) => Err(CommandError::Store(err)),
        };
    }

    if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XGROUP",
                subcommand: "HELP".to_string(),
            });
        }
        // (frankenredis-s574p) Mirror upstream t_stream.c::xgroupCommand
        // HELP body line-for-line (vendored Redis 7.2.4). Frames are
        // SimpleString (was BulkString — same divergence as 0o9vo /
        // vtege / kuthf). Placeholders use upstream syntax (`<id|$>`,
        // `<consumer>`) and the CREATE entry surfaces the MKSTREAM /
        // ENTRIESREAD option detail; SETID surfaces the
        // [ENTRIESREAD entries_read] option.
        return Ok(RespFrame::Array(Some(vec![
            hello_simple("XGROUP <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("CREATE <key> <groupname> <id|$> [option]"),
            hello_simple("    Create a new consumer group. Options are:"),
            hello_simple("    * MKSTREAM"),
            hello_simple("      Create the empty stream if it does not exist."),
            hello_simple("    * ENTRIESREAD entries_read"),
            hello_simple("      Set the group's entries_read counter (internal use)."),
            hello_simple("CREATECONSUMER <key> <groupname> <consumer>"),
            hello_simple("    Create a new consumer in the specified group."),
            hello_simple("DELCONSUMER <key> <groupname> <consumer>"),
            hello_simple("    Remove the specified consumer."),
            hello_simple("DESTROY <key> <groupname>"),
            hello_simple("    Remove the specified group."),
            hello_simple("SETID <key> <groupname> <id|$> [ENTRIESREAD entries_read]"),
            hello_simple("    Set the current group ID and entries_read counter."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])));
    }

    Err(CommandError::UnknownSubcommand {
        command: "XGROUP",
        subcommand: sub.to_string(),
    })
}

/// Upstream Redis 7.2 XREADGROUP / XCLAIM / XAUTOCLAIM / XPENDING /
/// XACK emit "NOGROUP No such key '<k>' or consumer group '<g>'"
/// from their shared streamCG-lookup error path (see
/// legacy_redis_code/redis/src/t_stream.c lines 2275, 2945, 3136,
/// 3388, 3880). The text is identical regardless of whether it
/// was the key or the group that was actually missing.
/// (br-frankenredis-ud94)
/// The keys reaching command handlers are the DB-namespaced PHYSICAL keys
/// (`\0frdb\0<db><logical>` for db != 0), so any error that echoes the key name
/// must first strip that prefix — upstream reports the LOGICAL key the client
/// sent. Without this, e.g. `SELECT 3; XREADGROUP GROUP g c STREAMS s >` leaked
/// `No such key '\x00frdb\x00...\x03s'` instead of `'s'`.
fn logical_key_lossy(key: &[u8]) -> std::borrow::Cow<'_, str> {
    let logical = decode_db_key(key).map_or(key, |(_, lk)| lk);
    String::from_utf8_lossy(logical)
}

fn xstream_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    let key = logical_key_lossy(key);
    let group = String::from_utf8_lossy(group);
    RespFrame::Error(format!(
        "NOGROUP No such key '{key}' or consumer group '{group}'"
    ))
}

fn xreadgroup_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    // XREADGROUP appends " in XREADGROUP with GROUP option" to the
    // shared NOGROUP wording (legacy_redis_code/redis/src/t_stream.c
    // around line 4495 where the streamLookupCG failure is reported
    // for XREADGROUP specifically). (br-frankenredis-ud94)
    let key = logical_key_lossy(key);
    let group = String::from_utf8_lossy(group);
    RespFrame::Error(format!(
        "NOGROUP No such key '{key}' or consumer group '{group}' in XREADGROUP with GROUP option"
    ))
}

fn xgroup_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    // XGROUP SETID / DELCONSUMER / CREATECONSUMER report
    // "No such consumer group" because the key existence check has
    // already passed by the time the lookup is hit. (Upstream
    // t_stream.c:2632, 3880 in nested branches.)
    let key = logical_key_lossy(key);
    let group = String::from_utf8_lossy(group);
    RespFrame::Error(format!(
        "NOGROUP No such consumer group '{group}' for key name '{key}'"
    ))
}

fn xgroup_key_required_error() -> RespFrame {
    RespFrame::Error(
        "ERR The XGROUP subcommand requires the key to exist. Note that for CREATE you may want to use the MKSTREAM option to create an empty stream automatically.".to_string(),
    )
}

fn xclaim_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    xstream_nogroup_error(key, group)
}

fn xautoclaim_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    xstream_nogroup_error(key, group)
}

fn xpending_nogroup_error(key: &[u8], group: &[u8]) -> RespFrame {
    xstream_nogroup_error(key, group)
}

fn xinfo_nogroup_consumers_error(key: &[u8], group: &[u8]) -> RespFrame {
    let key = logical_key_lossy(key);
    let group = String::from_utf8_lossy(group);
    RespFrame::Error(format!(
        "NOGROUP No such consumer group '{group}' for key name '{key}'"
    ))
}

fn xinfo(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("XINFO"));
    }
    let sub = match std::str::from_utf8(&argv[1]) {
        Ok(s) => s,
        Err(_) => return Err(CommandError::InvalidUtf8Argument),
    };
    if sub.eq_ignore_ascii_case("CONSUMERS") {
        if argv.len() != 4 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XINFO",
                subcommand: sub.to_string(),
            });
        }
        let consumers = match store.xinfo_consumers(&argv[2], &argv[3], now_ms) {
            Ok(Some(consumers)) => consumers,
            Ok(None) => return Ok(xinfo_nogroup_consumers_error(&argv[2], &argv[3])),
            Err(StoreError::KeyNotFound) => return Err(CommandError::NoSuchKey),
            Err(err) => return Err(CommandError::Store(err)),
        };
        let resp = store.dispatch_client_ctx.resp_protocol_version;
        let out = consumers
            .into_iter()
            .map(|info| stream_consumer_info_to_frame(info, resp))
            .collect();
        return Ok(RespFrame::Array(Some(out)));
    }
    if sub.eq_ignore_ascii_case("GROUPS") {
        if argv.len() != 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "XINFO",
                subcommand: sub.to_string(),
            });
        }
        let Some(groups) = store.xinfo_groups(&argv[2], now_ms)? else {
            return Err(CommandError::NoSuchKey);
        };
        // xinfo_groups above already recorded the single command keyspace lookup;
        // read the stream bounds no-stat so XINFO GROUPS doesn't double-count.
        let Some((len, first, last)) = store.xinfo_stream_no_stat(&argv[2], now_ms)? else {
            return Err(CommandError::NoSuchKey);
        };
        let entries_added = store.stream_entries_added(&argv[2], len);
        let max_deleted_id = store.stream_max_deleted_id(&argv[2]).unwrap_or((0, 0));
        // (frankenredis-ren6y) The last-generated-id watermark (survives an
        // emptied stream) — needed so lag is nil when a group is ahead of it.
        let stream_last_generated_id = store.stream_watermark(&argv[2]).unwrap_or(None);
        let lag_info = StreamLagInfo {
            entries_added,
            len,
            first_id: first.as_ref().map(|(id, _)| *id),
            last_id: last.as_ref().map(|(id, _)| *id),
            max_deleted_id,
            last_generated_id: stream_last_generated_id,
        };
        let resp = store.dispatch_client_ctx.resp_protocol_version;
        let mut out = Vec::with_capacity(groups.len());
        for (name, consumers, pending, last_delivered_id, entries_read) in groups {
            out.push(stream_group_info_to_frame(
                name,
                consumers,
                pending,
                last_delivered_id,
                entries_read,
                stream_full_group_lag_frame(lag_info, last_delivered_id, entries_read),
                resp,
            ));
        }
        return Ok(RespFrame::Array(Some(out)));
    }
    if !sub.eq_ignore_ascii_case("STREAM") {
        if sub.eq_ignore_ascii_case("HELP") {
            if argv.len() != 2 {
                return Err(CommandError::WrongSubcommandArity {
                    command: "XINFO",
                    subcommand: "HELP".to_string(),
                });
            }
            // (frankenredis-tnscz) Mirror upstream t_stream.c::xinfo
            // Command HELP body line-for-line (vendored Redis 7.2.4).
            // Frames are SimpleString (was BulkString — same as the
            // 0o9vo / vtege / kuthf / s574p HELP cluster). The
            // STREAM line preserves upstream's missing-closing-bracket
            // typo ('[FULL [COUNT <count>]' — one ']' instead of two)
            // for byte-for-byte wire parity.
            return Ok(RespFrame::Array(Some(vec![
                hello_simple("XINFO <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
                hello_simple("CONSUMERS <key> <groupname>"),
                hello_simple("    Show consumers of <groupname>."),
                hello_simple("GROUPS <key>"),
                hello_simple("    Show the stream consumer groups."),
                hello_simple("STREAM <key> [FULL [COUNT <count>]"),
                hello_simple("    Show information about the stream."),
                hello_simple("HELP"),
                hello_simple("    Print this help."),
            ])));
        }
        return Err(CommandError::UnknownSubcommand {
            command: "XINFO",
            subcommand: sub.to_string(),
        });
    }

    // XINFO STREAM key [FULL [COUNT count]]
    if argv.len() < 3 {
        return Err(CommandError::WrongSubcommandArity {
            command: "XINFO",
            subcommand: sub.to_string(),
        });
    }
    // Upstream t_stream.c::xinfoCommand looks up the key BEFORE
    // dispatching to the STREAM/FULL branch, so any missing key
    // (or wrong-type key) replies with 'no such key' /
    // 'WRONGTYPE…' regardless of any unrecognised trailing args.
    // (br-frankenredis-xinfokey)
    let Some((len, first, last)) = store.xinfo_stream(&argv[2], now_ms)? else {
        return Err(CommandError::NoSuchKey);
    };
    // Upstream xinfoReplyWithStreamInfo uses addReplySubcommandSyntaxError
    // for any unrecognised tail, which renders as 'unknown subcommand
    // or wrong number of arguments for <SUB>. Try XINFO HELP.'.
    // (br-frankenredis-xinfokey)
    let xinfo_subcommand_syntax_error = || {
        CommandError::Custom(format!(
            "ERR unknown subcommand or wrong number of arguments for '{sub}'. Try XINFO HELP."
        ))
    };
    let full_mode = argv.len() >= 4 && eq_ascii_command(&argv[3], b"FULL");
    if !full_mode && argv.len() != 3 {
        return Err(xinfo_subcommand_syntax_error());
    }
    if full_mode && argv.len() != 4 && argv.len() != 6 {
        return Err(xinfo_subcommand_syntax_error());
    }
    let full_count: usize = if full_mode && argv.len() == 6 {
        if !eq_ascii_command(&argv[4], b"COUNT") {
            return Err(xinfo_subcommand_syntax_error());
        }
        // Upstream parses COUNT via getLongLongFromObjectOrReply
        // (which uses 'value is not an integer or out of range')
        // and silently treats negative counts as the default 10.
        let n = parse_i64_arg(&argv[5])?;
        if n < 0 {
            10
        } else {
            usize::try_from(n).map_err(|_| CommandError::InvalidInteger)?
        }
    } else {
        10 // Redis default COUNT for FULL is 10
    };

    let stream_watermark = store.stream_watermark(&argv[2])?;
    let last_generated_id = stream_watermark
        .map(format_stream_id)
        .unwrap_or_else(|| b"0-0".to_vec());
    let recorded_first_entry_id = first
        .as_ref()
        .map(|(id, _)| format_stream_id(*id))
        .unwrap_or_else(|| b"0-0".to_vec());
    let len_i64 = i64::try_from(len).unwrap_or(i64::MAX);
    let entries_added = store.stream_entries_added(&argv[2], len);
    let entries_added_i64 = i64::try_from(entries_added).unwrap_or(i64::MAX);
    let (radix_tree_keys, radix_tree_nodes) = stream_radix_tree_metrics(len, entries_added);
    let max_deleted_id = store.stream_max_deleted_id(&argv[2]).unwrap_or((0, 0));
    let max_deleted_entry_id = format_stream_id(max_deleted_id);
    let lag_info = StreamLagInfo {
        entries_added,
        len,
        first_id: first.as_ref().map(|(id, _)| *id),
        last_id: last.as_ref().map(|(id, _)| *id),
        max_deleted_id,
        last_generated_id: stream_watermark,
    };

    if full_mode {
        // FULL mode: include entries and detailed group info
        let count_limit = stream_full_count_limit(full_count);
        let entries_frames: Vec<RespFrame> = store
            .xrange(&argv[2], (0, 0), (u64::MAX, u64::MAX), None, now_ms)?
            .into_iter()
            .take(count_limit)
            .map(|(id, fields)| stream_record_to_frame(id, fields))
            .collect();

        let groups = store.xinfo_groups(&argv[2], now_ms)?.unwrap_or_default();
        let mut group_frames = Vec::with_capacity(groups.len());
        for (name, _consumers_count, pending_count, last_delivered_id, entries_read) in &groups {
            let group_pending = store
                .xpending_entries(
                    &argv[2],
                    name,
                    ((0, 0), (u64::MAX, u64::MAX)),
                    count_limit,
                    None,
                    now_ms,
                    0,
                )?
                .unwrap_or_default()
                .into_iter()
                .map(|record| stream_full_group_pending_to_frame(record, now_ms))
                .collect();
            let consumers_info = store
                .xinfo_consumers(&argv[2], name, now_ms)
                .ok()
                .flatten()
                .unwrap_or_default();
            let resp_v = store.dispatch_client_ctx.resp_protocol_version;
            let mut consumer_frames = Vec::with_capacity(consumers_info.len());
            for info in consumers_info {
                let consumer = info.0.clone();
                let pending = store
                    .xpending_entries(
                        &argv[2],
                        name,
                        ((0, 0), (u64::MAX, u64::MAX)),
                        count_limit,
                        Some(&consumer),
                        now_ms,
                        0,
                    )?
                    .unwrap_or_default()
                    .into_iter()
                    .map(|record| stream_full_consumer_pending_to_frame(record, now_ms))
                    .collect();
                consumer_frames.push(stream_full_consumer_info_to_frame(
                    info, pending, now_ms, resp_v,
                ));
            }
            group_frames.push(stream_full_group_info_to_frame(
                StreamFullGroupFrameInfo {
                    name: name.clone(),
                    pending_count: *pending_count,
                    last_delivered_id: *last_delivered_id,
                    entries_read: *entries_read,
                    lag: stream_full_group_lag_frame(lag_info, *last_delivered_id, *entries_read),
                },
                group_pending,
                consumer_frames,
                resp_v,
            ));
        }

        // Upstream t_stream.c::xinfoFullCommand uses addReplyMapLen for
        // the FULL form (same as the non-FULL one). Emit RespFrame::Map
        // for RESP3 callers, alternating-array for RESP2.
        // (br-frankenredis-f6z6)
        let pairs: Vec<(RespFrame, RespFrame)> = vec![
            (
                RespFrame::BulkString(Some(b"length".to_vec())),
                RespFrame::Integer(len_i64),
            ),
            (
                RespFrame::BulkString(Some(b"radix-tree-keys".to_vec())),
                RespFrame::Integer(radix_tree_keys),
            ),
            (
                RespFrame::BulkString(Some(b"radix-tree-nodes".to_vec())),
                RespFrame::Integer(radix_tree_nodes),
            ),
            (
                RespFrame::BulkString(Some(b"last-generated-id".to_vec())),
                RespFrame::BulkString(Some(last_generated_id)),
            ),
            (
                RespFrame::BulkString(Some(b"max-deleted-entry-id".to_vec())),
                RespFrame::BulkString(Some(max_deleted_entry_id)),
            ),
            (
                RespFrame::BulkString(Some(b"entries-added".to_vec())),
                RespFrame::Integer(entries_added_i64),
            ),
            (
                RespFrame::BulkString(Some(b"recorded-first-entry-id".to_vec())),
                RespFrame::BulkString(Some(recorded_first_entry_id)),
            ),
            (
                RespFrame::BulkString(Some(b"entries".to_vec())),
                RespFrame::Array(Some(entries_frames)),
            ),
            (
                RespFrame::BulkString(Some(b"groups".to_vec())),
                RespFrame::Array(Some(group_frames)),
            ),
        ];
        if store.dispatch_client_ctx.resp_protocol_version == 3 {
            return Ok(RespFrame::Map(Some(pairs)));
        }
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        return Ok(RespFrame::Array(Some(flat)));
    }

    // Use the no-stat group count: xinfo_stream above already recorded the
    // single keyspace lookup upstream's xinfoCommand performs; calling the
    // stat-counting store.xinfo_groups here would double-count keyspace_hits.
    let group_count = i64::try_from(store.stream_group_count(&argv[2])).unwrap_or(i64::MAX);

    let first_entry = first
        .map(|(id, fields)| stream_record_to_frame(id, fields))
        .unwrap_or(RespFrame::BulkString(None));
    let last_entry = last
        .map(|(id, fields)| stream_record_to_frame(id, fields))
        .unwrap_or(RespFrame::BulkString(None));

    // Upstream t_stream.c::xinfoCommand uses addReplyMapLen for
    // the non-FULL form. Emit RespFrame::Map for RESP3 callers,
    // alternating-array for RESP2. (br-frankenredis-f6z6)
    let pairs: Vec<(RespFrame, RespFrame)> = vec![
        (
            RespFrame::BulkString(Some(b"length".to_vec())),
            RespFrame::Integer(len_i64),
        ),
        (
            RespFrame::BulkString(Some(b"radix-tree-keys".to_vec())),
            RespFrame::Integer(radix_tree_keys),
        ),
        (
            RespFrame::BulkString(Some(b"radix-tree-nodes".to_vec())),
            RespFrame::Integer(radix_tree_nodes),
        ),
        (
            RespFrame::BulkString(Some(b"last-generated-id".to_vec())),
            RespFrame::BulkString(Some(last_generated_id)),
        ),
        (
            RespFrame::BulkString(Some(b"max-deleted-entry-id".to_vec())),
            RespFrame::BulkString(Some(max_deleted_entry_id)),
        ),
        (
            RespFrame::BulkString(Some(b"entries-added".to_vec())),
            RespFrame::Integer(entries_added_i64),
        ),
        (
            RespFrame::BulkString(Some(b"recorded-first-entry-id".to_vec())),
            RespFrame::BulkString(Some(recorded_first_entry_id)),
        ),
        (
            RespFrame::BulkString(Some(b"groups".to_vec())),
            RespFrame::Integer(group_count),
        ),
        (
            RespFrame::BulkString(Some(b"first-entry".to_vec())),
            first_entry,
        ),
        (
            RespFrame::BulkString(Some(b"last-entry".to_vec())),
            last_entry,
        ),
    ];
    if store.dispatch_client_ctx.resp_protocol_version == 3 {
        Ok(RespFrame::Map(Some(pairs)))
    } else {
        let mut flat = Vec::with_capacity(pairs.len() * 2);
        for (k, v) in pairs {
            flat.push(k);
            flat.push(v);
        }
        Ok(RespFrame::Array(Some(flat)))
    }
}

fn xrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("XRANGE"));
    }
    // Upstream t_stream.c::xrangeGenericCommand parses the start/end interval IDs
    // (streamParseIntervalIDOrReply) BEFORE validating the optional COUNT trailer,
    // so a malformed start/end ID surfaces "Invalid stream ID..." even when the
    // trailing args are also wrong (e.g. `XRANGE k <bad-id> + extra`). The trailer
    // syntax-error ("not COUNT" / wrong count of trailing args) is only reached
    // once both IDs parse. (br-frankenredis-xrangearity; ID-before-arity order)
    let start = match parse_stream_range_bound(&argv[2], true) {
        Ok(v) => v,
        Err(reply) => return Ok(reply),
    };
    let end = match parse_stream_range_bound(&argv[3], false) {
        Ok(v) => v,
        Err(reply) => return Ok(reply),
    };

    let count = if argv.len() != 4 {
        if argv.len() != 6 || !eq_ascii_command(&argv[4], b"COUNT") {
            return Err(CommandError::SyntaxError);
        }
        let parsed = parse_i64_arg(&argv[5])?;
        // Upstream parses COUNT via getLongFromObjectOrReply, clamps
        // negative values to 0, then emits a null array when count is 0.
        // (br-frankenredis-xrangenegcount) But the key is resolved FIRST —
        // lookupKeyReadOrReply(emptyarray)+checkType (t_stream.c:2133) run
        // before the count==0 null reply — so a wrong-type key is WRONGTYPE
        // and a missing key is an empty array even when COUNT<=0, not the
        // null array. (frankenredis-xrangecounttype)
        if parsed <= 0 {
            return match store.peek_value_type(&argv[1], now_ms) {
                Some(fr_store::ValueType::Stream) => Ok(RespFrame::Array(None)),
                None => Ok(RespFrame::Array(Some(Vec::new()))),
                Some(_) => Err(CommandError::Store(fr_store::StoreError::WrongType)),
            };
        }
        Some(usize::try_from(parsed).unwrap_or(usize::MAX))
    } else {
        None
    };

    let records = store.xrange(&argv[1], start, end, count, now_ms)?;
    let mut out = Vec::with_capacity(records.len());
    for (id, fields) in records {
        let mut field_frames = Vec::with_capacity(fields.len().saturating_mul(2));
        for (field, value) in fields {
            field_frames.push(RespFrame::BulkString(Some(field)));
            field_frames.push(RespFrame::BulkString(Some(value)));
        }
        out.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(format_stream_id(id))),
            RespFrame::Array(Some(field_frames)),
        ])));
    }
    Ok(RespFrame::Array(Some(out)))
}

fn xrevrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("XREVRANGE"));
    }
    // (br-frankenredis-xrangearity; ID-before-arity order) Upstream parses the
    // end/start interval IDs before validating the COUNT trailer, so a malformed
    // ID beats the trailing-arg syntax error even when both are wrong.
    let end = match parse_stream_range_bound(&argv[2], false) {
        Ok(v) => v,
        Err(reply) => return Ok(reply),
    };
    let start = match parse_stream_range_bound(&argv[3], true) {
        Ok(v) => v,
        Err(reply) => return Ok(reply),
    };

    let count = if argv.len() != 4 {
        if argv.len() != 6 || !eq_ascii_command(&argv[4], b"COUNT") {
            return Err(CommandError::SyntaxError);
        }
        let parsed = parse_i64_arg(&argv[5])?;
        // (br-frankenredis-xrangenegcount / -xrangecounttype) — see xrange:
        // resolve the key (wrong-type → WRONGTYPE, missing → empty array)
        // before emitting the count<=0 null array.
        if parsed <= 0 {
            return match store.peek_value_type(&argv[1], now_ms) {
                Some(fr_store::ValueType::Stream) => Ok(RespFrame::Array(None)),
                None => Ok(RespFrame::Array(Some(Vec::new()))),
                Some(_) => Err(CommandError::Store(fr_store::StoreError::WrongType)),
            };
        }
        Some(usize::try_from(parsed).unwrap_or(usize::MAX))
    } else {
        None
    };

    let records = store.xrevrange(&argv[1], end, start, count, now_ms)?;
    let mut out = Vec::with_capacity(records.len());
    for (id, fields) in records {
        let mut field_frames = Vec::with_capacity(fields.len().saturating_mul(2));
        for (field, value) in fields {
            field_frames.push(RespFrame::BulkString(Some(field)));
            field_frames.push(RespFrame::BulkString(Some(value)));
        }
        out.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(format_stream_id(id))),
            RespFrame::Array(Some(field_frames)),
        ])));
    }
    Ok(RespFrame::Array(Some(out)))
}

// ── XACK ────────────────────────────────────────────────────────────

fn xack_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("XACK"));
    }
    let key = &argv[1];
    let group = &argv[2];
    // Upstream t_stream.c::xackCommand looks up the key + group
    // BEFORE validating IDs and short-circuits to 0 when either is
    // missing. The IDs are only parsed once both exist, so an
    // invalid ID against a missing key/group reports 0 rather than
    // 'Invalid stream ID specified...'. (br-frankenredis-xackorder)
    // (frankenredis-j9lgb) Use the O(log) existence check, NOT
    // xpending_summary — XACK never needs the per-consumer histogram, and the
    // O(P) scan made XACK ~20x slower than redis on a large pending list.
    match store.stream_group_exists(key, group, now_ms) {
        Ok(false) => return Ok(RespFrame::Integer(0)),
        Ok(true) => {}
        Err(e) => return Err(CommandError::Store(e)),
    }
    let mut ids = Vec::with_capacity(argv.len() - 3);
    for arg in &argv[3..] {
        let id = match parse_stream_id(arg) {
            Ok(id) => id,
            Err(reply) => return Ok(reply),
        };
        ids.push(id);
    }
    let acked = store.xack(key, group, &ids, now_ms)?;
    Ok(RespFrame::Integer(acked as i64))
}

// ── XSETID ──────────────────────────────────────────────────────────

fn xsetid_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // XSETID key last-id [ENTRIESADDED entries-added] [MAXDELETEDID max-deleted-id]
    //
    // Upstream t_stream.c::xsetidCommand parses both options strictly,
    // requires ENTRIESADDED >= 0, validates MAXDELETEDID as a stream
    // ID, and rejects when last-id < max_deleted_entry_id. The
    // missing-key case routes to `shared.nokeyerr` ("ERR no such key"),
    // not the prior FrankenRedis-specific "not present in the target
    // stream" wording. (br-frankenredis-r71v)
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("XSETID"));
    }
    let key = &argv[1];
    let last_id = match parse_stream_id(&argv[2]) {
        Ok(id) => id,
        Err(reply) => return Ok(reply),
    };

    let mut entries_added: Option<u64> = None;
    let mut max_deleted_id: Option<StreamId> = None;
    let mut i = 3;
    while i < argv.len() {
        let kw = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let moreargs = argv.len().saturating_sub(i + 1);
        if kw.eq_ignore_ascii_case("ENTRIESADDED") && moreargs > 0 {
            let value = parse_i64_arg(&argv[i + 1])?;
            if value < 0 {
                return Ok(RespFrame::Error(
                    "ERR entries_added must be positive".to_string(),
                ));
            }
            entries_added = Some(u64::try_from(value).unwrap_or(u64::MAX));
            i += 2;
        } else if kw.eq_ignore_ascii_case("MAXDELETEDID") && moreargs > 0 {
            let parsed = match parse_stream_id(&argv[i + 1]) {
                Ok(id) => id,
                Err(reply) => return Ok(reply),
            };
            if last_id < parsed {
                return Ok(RespFrame::Error(
                    "ERR The ID specified in XSETID is smaller than the provided max_deleted_entry_id"
                        .to_string(),
                ));
            }
            max_deleted_id = Some(parsed);
            i += 2;
        } else {
            return Ok(RespFrame::Error("ERR syntax error".to_string()));
        }
    }
    if let Some(current_max_deleted_id) = store.stream_max_deleted_id(key)
        && last_id < current_max_deleted_id
    {
        return Ok(RespFrame::Error(
            "ERR The ID specified in XSETID is smaller than current max_deleted_entry_id"
                .to_string(),
        ));
    }
    // Upstream t_stream.c::xsetidCommand only runs the "smaller than the target
    // stream top item" check when the stream has entries (s->length > 0), and
    // compares against the max ACTUAL entry id (streamLastValidID) — NOT the
    // persisted last-generated-id. So an emptied stream (e.g. after XTRIM MAXLEN
    // 0) accepts XSETID to a smaller id. Using xlast_id here wrongly folded in
    // the surviving watermark and rejected those. (frankenredis-xsetidempty,
    // supersedes br-frankenredis-xsetid-top)
    if let Ok(Some(top)) = store.stream_last_entry_id(key)
        && last_id < top
    {
        return Ok(RespFrame::Error(
            "ERR The ID specified in XSETID is smaller than the target stream top item".to_string(),
        ));
    }
    if let Some(entries_added) = entries_added {
        let live_len = store.xlen(key, now_ms)?;
        if entries_added < u64::try_from(live_len).unwrap_or(u64::MAX) {
            return Ok(RespFrame::Error(
                "ERR The entries_added specified in XSETID is smaller than the target stream length"
                    .to_string(),
            ));
        }
    }
    match store.xsetid_with_metadata(key, last_id, entries_added, max_deleted_id, now_ms) {
        Ok(true) => Ok(RespFrame::SimpleString("OK".to_string())),
        Ok(false) => Ok(RespFrame::Error("ERR no such key".to_string())),
        Err(e) => Err(e.into()),
    }
}

// ── LOLWUT ──────────────────────────────────────────────────────────

fn lolwut_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // LOLWUT [VERSION version]
    // Upstream Redis 7.2 lolwut.c::lolwutCommand only enters the VERSION
    // branch when `argc >= 3 && strcasecmp(argv[1], "version") == 0`,
    // shifts argv past `VERSION <ver>`, and then dispatches to
    // lolwut5/lolwut6/lolwutUnstable based on the parsed version.
    //   - argc==2 ("LOLWUT VERSION" with no value, or "LOLWUT BOGUS",
    //     or "LOLWUT 5"): the VERSION branch is NOT taken (argc check
    //     fails or first token isn't "version"), and the chosen render
    //     fn for vendored 7.2 is lolwutUnstable, which IGNORES every
    //     remaining arg and just emits "Redis ver. <REDIS_VERSION>\n".
    //   - argc>=3 && argv[1]=="version" && argv[2] non-numeric: upstream's
    //     getLongFromObjectOrReply emits the generic
    //     "value is not an integer or out of range" envelope.
    //
    // fr currently ports only the unstable render path. The pre-fix
    // code (br-frankenredis-m5nf) eagerly validated trailing args as
    // i64 and rejected `LOLWUT VERSION` (no value) with WrongArity,
    // so vendored-permissive inputs like `LOLWUT BOGUS`, `LOLWUT VERSION`,
    // `LOLWUT VERSION 5 some-token` surfaced errors that vendored 7.2.4
    // never raises. (frankenredis-lolwutpermit)
    if argv.len() >= 3 {
        let ver_kw =
            std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if ver_kw.eq_ignore_ascii_case("VERSION") {
            // Only the version selector arg is parsed by upstream's
            // top-level lolwutCommand. lolwut5/lolwut6 do parse their
            // own trailing cols/squares-per-row/squares-per-col args,
            // but fr's port routes everything to lolwutUnstable, which
            // ignores them — so don't reject them here.
            parse_i64_arg(&argv[2])?;
        }
    }
    let body = format!("Redis ver. {}\n", fr_store::REDIS_COMPAT_VERSION);
    // RESP3 clients expect verbatim string for LOLWUT output
    if store.dispatch_client_ctx.resp_protocol_version == 3 {
        Ok(RespFrame::Verbatim(body))
    } else {
        Ok(RespFrame::BulkString(Some(body.into_bytes())))
    }
}

// ── WAITAOF ─────────────────────────────────────────────────────────

fn waitaof_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // WAITAOF numlocal numreplicas timeout
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("WAITAOF"));
    }
    // Upstream commands.def declares WAITAOF with CMD_NOSCRIPT, so
    // server.c::processCommand emits the noscript reply BEFORE the
    // handler ever runs. Mirror that order here so a scripted call
    // with bad args surfaces the noscript error rather than the
    // parse error. (frankenredis-d021m)
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    let required_local = match parse_i64_arg(&argv[1]) {
        Ok(value @ 0..=1) => value,
        Ok(_) => {
            return Err(CommandError::Custom(
                "ERR value is out of range, value must between 0 and 1".to_string(),
            ));
        }
        Err(_) => return Err(CommandError::InvalidInteger),
    };
    let _required_replicas = match parse_i64_arg(&argv[2]) {
        Ok(value) if value >= 0 => value,
        _ => {
            return Err(CommandError::Custom(
                "ERR value is out of range, must be positive".to_string(),
            ));
        }
    };
    let timeout_ms = parse_i64_arg(&argv[3]).map_err(|_| {
        CommandError::Custom("ERR timeout is not an integer or out of range".to_string())
    })?;
    if timeout_ms < 0 {
        return Err(CommandError::Custom("ERR timeout is negative".to_string()));
    }
    // (frankenredis-0axo9) Upstream replication.c::waitaofCommand
    // gates this error on `numlocal && !server.aof_enabled` — fr was
    // unconditionally rejecting numlocal=1 regardless of the actual
    // AOF state, so a user who turned AOF on still got the
    // 'appendonly is disabled' error.
    if required_local > 0 && !store.aof_enabled {
        return Ok(RespFrame::Error(
            "ERR WAITAOF cannot be used when numlocal is set but appendonly is disabled."
                .to_string(),
        ));
    }
    Err(CommandError::Custom(
        "ERR WAITAOF requires runtime replication context".to_string(),
    ))
}

fn cluster_disabled_error() -> CommandError {
    CommandError::Custom("ERR This instance has cluster support disabled".to_string())
}

fn cluster_wrong_subcommand_arity(subcommand: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR wrong number of arguments for 'cluster|{}' command",
        subcommand.to_ascii_lowercase()
    ))
}

fn cluster_unknown_subcommand_error(subcommand: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR unknown subcommand '{subcommand}'. Try CLUSTER HELP."
    ))
}

fn cluster_subcommand_syntax_error(subcommand: &str) -> CommandError {
    CommandError::Custom(format!(
        "ERR unknown subcommand or wrong number of arguments for '{subcommand}'. Try CLUSTER HELP."
    ))
}

fn cluster_invalid_setslot_action_error() -> CommandError {
    CommandError::Custom(
        "ERR Invalid CLUSTER SETSLOT action or number of arguments. Try CLUSTER HELP".to_string(),
    )
}

fn cluster_reset_with_keys_error() -> CommandError {
    CommandError::Custom(
        "ERR CLUSTER RESET can't be called with master nodes containing keys".to_string(),
    )
}

fn parse_cluster_slot_arg(arg: &[u8]) -> Result<u16, CommandError> {
    let slot = parse_i64_arg(arg)
        .map_err(|_| CommandError::Custom("ERR Invalid or out of range slot".to_string()))?;
    if !(0..=16383).contains(&slot) {
        return Err(CommandError::Custom(
            "ERR Invalid or out of range slot".to_string(),
        ));
    }
    Ok(slot as u16)
}

fn cluster_slot_specified_multiple_times_error(slot: u16) -> CommandError {
    CommandError::Custom(format!("ERR Slot {slot} specified multiple times"))
}

fn cluster_slot_busy_error(slot: u16) -> CommandError {
    CommandError::Custom(format!("ERR Slot {slot} is already busy"))
}

fn cluster_slot_unassigned_error(slot: u16) -> CommandError {
    CommandError::Custom(format!("ERR Slot {slot} is already unassigned"))
}

fn cluster_invalid_node_address(host: &str, port: &str) -> CommandError {
    CommandError::Custom(format!("ERR Invalid node address specified: {host}:{port}"))
}

fn cluster_invalid_base_port(port: &str) -> CommandError {
    CommandError::Custom(format!("ERR Invalid base port specified: {port}"))
}

fn cluster_invalid_bus_port(port: &str) -> CommandError {
    CommandError::Custom(format!("ERR Invalid bus port specified: {port}"))
}

fn cluster_parse_port_arg(arg: &[u8]) -> Option<i64> {
    let s = std::str::from_utf8(arg).ok()?;
    s.parse::<i64>().ok()
}

fn cluster_collect_explicit_slots_for_update(
    argv: &[Vec<u8>],
    assigned_slots: &BTreeSet<u16>,
    deleting: bool,
) -> Result<BTreeSet<u16>, CommandError> {
    let mut parsed = Vec::with_capacity(argv.len());
    for slot_arg in argv {
        let slot = parse_cluster_slot_arg(slot_arg)?;
        parsed.push(slot);
    }

    let mut slots = BTreeSet::new();
    for slot in parsed {
        if deleting && !assigned_slots.contains(&slot) {
            return Err(cluster_slot_unassigned_error(slot));
        }
        if !deleting && assigned_slots.contains(&slot) {
            return Err(cluster_slot_busy_error(slot));
        }
        if !slots.insert(slot) {
            return Err(cluster_slot_specified_multiple_times_error(slot));
        }
    }
    Ok(slots)
}

fn cluster_collect_slot_ranges_for_update(
    argv: &[Vec<u8>],
    assigned_slots: &BTreeSet<u16>,
    deleting: bool,
) -> Result<BTreeSet<u16>, CommandError> {
    let mut slots = BTreeSet::new();
    let mut i = 0;
    while i + 1 < argv.len() {
        let start = parse_cluster_slot_arg(&argv[i])?;
        let end = parse_cluster_slot_arg(&argv[i + 1])?;
        if start > end {
            return Err(CommandError::Custom(format!(
                "ERR start slot number {start} is greater than end slot number {end}"
            )));
        }
        for slot in start..=end {
            if deleting && !assigned_slots.contains(&slot) {
                return Err(cluster_slot_unassigned_error(slot));
            }
            if !deleting && assigned_slots.contains(&slot) {
                return Err(cluster_slot_busy_error(slot));
            }
            if !slots.insert(slot) {
                return Err(cluster_slot_specified_multiple_times_error(slot));
            }
        }
        i += 2;
    }
    Ok(slots)
}

fn cluster_slot_range_frames(slots: &BTreeSet<u16>) -> Vec<RespFrame> {
    let mut frames = Vec::new();
    let mut iter = slots.iter().copied();
    let Some(mut start) = iter.next() else {
        return frames;
    };
    let mut end = start;
    for slot in iter {
        if end.checked_add(1) == Some(slot) {
            end = slot;
        } else {
            frames.push(RespFrame::Integer(i64::from(start)));
            frames.push(RespFrame::Integer(i64::from(end)));
            start = slot;
            end = slot;
        }
    }
    frames.push(RespFrame::Integer(i64::from(start)));
    frames.push(RespFrame::Integer(i64::from(end)));
    frames
}

fn cluster_shards_reply(store: &Store) -> RespFrame {
    // Mirror upstream cluster.c — addShardReplyForClusterShards uses
    // addReplyMapLen(c, 2) for the per-shard wrapper and addNodeToNodeReply
    // uses addReplyMapLen(c, length) for the per-node frame. Under RESP3
    // both must be Maps; RESP2 keeps the existing flat Array shape.
    // (frankenredis-ec2rf)
    let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
    let node = if resp3 {
        RespFrame::Map(Some(vec![
            (
                hello_bulk("id"),
                RespFrame::BulkString(Some(store.server_run_id.as_bytes().to_vec())),
            ),
            (
                hello_bulk("port"),
                RespFrame::Integer(i64::from(store.server_port)),
            ),
            (hello_bulk("ip"), hello_bulk("")),
            (hello_bulk("endpoint"), hello_bulk("")),
            (hello_bulk("role"), hello_bulk("master")),
            (hello_bulk("replication-offset"), RespFrame::Integer(0)),
            (hello_bulk("health"), hello_bulk("online")),
        ]))
    } else {
        RespFrame::Array(Some(vec![
            hello_bulk("id"),
            RespFrame::BulkString(Some(store.server_run_id.as_bytes().to_vec())),
            hello_bulk("port"),
            RespFrame::Integer(i64::from(store.server_port)),
            hello_bulk("ip"),
            hello_bulk(""),
            hello_bulk("endpoint"),
            hello_bulk(""),
            hello_bulk("role"),
            hello_bulk("master"),
            hello_bulk("replication-offset"),
            RespFrame::Integer(0),
            hello_bulk("health"),
            hello_bulk("online"),
        ]))
    };
    let slots_frame = RespFrame::Array(Some(cluster_slot_range_frames(
        &store.cluster_assigned_slots,
    )));
    let nodes_frame = RespFrame::Array(Some(vec![node]));
    let shard = if resp3 {
        RespFrame::Map(Some(vec![
            (hello_bulk("slots"), slots_frame),
            (hello_bulk("nodes"), nodes_frame),
        ]))
    } else {
        RespFrame::Array(Some(vec![
            hello_bulk("slots"),
            slots_frame,
            hello_bulk("nodes"),
            nodes_frame,
        ]))
    };
    RespFrame::Array(Some(vec![shard]))
}

// ── CLUSTER ─────────────────────────────────────────────────────────

fn cluster_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("CLUSTER"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        // Mirror upstream cluster.c::clusterCommand:5890-5949 line-for-line
        // (frankenredis-u5he7).
        return Ok(RespFrame::Array(Some(vec![
            hello_simple("CLUSTER <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("ADDSLOTS <slot> [<slot> ...]"),
            hello_simple("    Assign slots to current node."),
            hello_simple("ADDSLOTSRANGE <start slot> <end slot> [<start slot> <end slot> ...]"),
            hello_simple(
                "    Assign slots which are between <start-slot> and <end-slot> to current node.",
            ),
            hello_simple("BUMPEPOCH"),
            hello_simple("    Advance the cluster config epoch."),
            hello_simple("COUNT-FAILURE-REPORTS <node-id>"),
            hello_simple("    Return number of failure reports for <node-id>."),
            hello_simple("COUNTKEYSINSLOT <slot>"),
            hello_simple("    Return the number of keys in <slot>."),
            hello_simple("DELSLOTS <slot> [<slot> ...]"),
            hello_simple("    Delete slots information from current node."),
            hello_simple("DELSLOTSRANGE <start slot> <end slot> [<start slot> <end slot> ...]"),
            hello_simple(
                "    Delete slots information which are between <start-slot> and <end-slot> from current node.",
            ),
            hello_simple("FAILOVER [FORCE|TAKEOVER]"),
            hello_simple("    Promote current replica node to being a master."),
            hello_simple("FORGET <node-id>"),
            hello_simple("    Remove a node from the cluster."),
            hello_simple("GETKEYSINSLOT <slot> <count>"),
            hello_simple("    Return key names stored by current node in a slot."),
            hello_simple("FLUSHSLOTS"),
            hello_simple("    Delete current node own slots information."),
            hello_simple("INFO"),
            hello_simple("    Return information about the cluster."),
            hello_simple("KEYSLOT <key>"),
            hello_simple("    Return the hash slot for <key>."),
            hello_simple("MEET <ip> <port> [<bus-port>]"),
            hello_simple("    Connect nodes into a working cluster."),
            hello_simple("MYID"),
            hello_simple("    Return the node id."),
            hello_simple("MYSHARDID"),
            hello_simple("    Return the node's shard id."),
            hello_simple("NODES"),
            hello_simple("    Return cluster configuration seen by node. Output format:"),
            hello_simple(
                "    <id> <ip:port@bus-port[,hostname]> <flags> <master> <pings> <pongs> <epoch> <link> <slot> ...",
            ),
            hello_simple("REPLICATE <node-id>"),
            hello_simple("    Configure current node as replica to <node-id>."),
            hello_simple("RESET [HARD|SOFT]"),
            hello_simple("    Reset current node (default: soft)."),
            hello_simple("SET-CONFIG-EPOCH <epoch>"),
            hello_simple("    Set config epoch of current node."),
            hello_simple(
                "SETSLOT <slot> (IMPORTING <node-id>|MIGRATING <node-id>|STABLE|NODE <node-id>)",
            ),
            hello_simple("    Set slot state."),
            hello_simple("REPLICAS <node-id>"),
            hello_simple("    Return <node-id> replicas."),
            hello_simple("SAVECONFIG"),
            hello_simple("    Force saving cluster configuration on disk."),
            hello_simple("SLOTS"),
            hello_simple(
                "    Return information about slots range mappings. Each range is made of:",
            ),
            hello_simple("    start, end, master and replicas IP addresses, ports and ids"),
            hello_simple("SHARDS"),
            hello_simple(
                "    Return information about slot range mappings and the nodes associated with them.",
            ),
            hello_simple("LINKS"),
            hello_simple(
                "    Return information about all network links between this node and its peers.",
            ),
            hello_simple(
                "    Output format is an array where each array element is a map containing attributes of a link",
            ),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])));
    }
    if sub.eq_ignore_ascii_case("INFO") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        // Mirror upstream cluster.c::genClusterInfoString:5806-5881.
        // fr models a single self node with no peers and no failure
        // tracking; epoch fields are still stateful because CLUSTER
        // BUMPEPOCH / SET-CONFIG-EPOCH expose them. cluster_state is "ok"
        // only when the 16384 slots are fully covered (matches
        // upstream's cluster.c verifyClusterConfigWithData semantics
        // where partial coverage flips the state to "fail").
        // (frankenredis-39rkv)
        let slots_assigned = store.cluster_assigned_slots.len();
        let cluster_state = if slots_assigned >= 16384 {
            "ok"
        } else {
            "fail"
        };
        let cluster_size = if slots_assigned > 0 { 1 } else { 0 };
        let cluster_current_epoch = store.cluster_current_epoch;
        let cluster_my_epoch = store.cluster_my_config_epoch;
        let info = format!(
            "cluster_state:{cluster_state}\r\n\
             cluster_slots_assigned:{slots_assigned}\r\n\
             cluster_slots_ok:{slots_assigned}\r\n\
             cluster_slots_pfail:0\r\n\
             cluster_slots_fail:0\r\n\
             cluster_known_nodes:1\r\n\
             cluster_size:{cluster_size}\r\n\
             cluster_current_epoch:{cluster_current_epoch}\r\n\
             cluster_my_epoch:{cluster_my_epoch}\r\n\
             cluster_stats_messages_sent:0\r\n\
             cluster_stats_messages_received:0\r\n\
             total_cluster_links_buffer_limit_exceeded:0\r\n",
        );
        return Ok(RespFrame::BulkString(Some(info.into_bytes())));
    }
    if sub.eq_ignore_ascii_case("NODES") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        // Mirror upstream cluster.c::clusterGenNodeDescription:5251-5328
        // for the single self node:
        //   <id> <ip:port@cport> myself,master - 0 0 <epoch> connected <slot ranges>
        // The cluster bus port follows upstream's default offset
        // convention (port + 10000). (frankenredis-bdokn)
        let cport = u32::from(store.server_port).saturating_add(10000);
        let mut line = format!(
            "{id} 127.0.0.1:{port}@{cport} myself,master - 0 0 {epoch} connected",
            id = store.server_run_id,
            port = store.server_port,
            epoch = store.cluster_my_config_epoch,
        );
        // Emit assigned slot ranges (single slot prints as a single
        // integer; contiguous runs print as start-end, matching
        // upstream's representation).
        let mut iter = store.cluster_assigned_slots.iter().copied();
        if let Some(mut start) = iter.next() {
            let mut end = start;
            for slot in iter {
                if end.checked_add(1) == Some(slot) {
                    end = slot;
                } else {
                    if start == end {
                        line.push_str(&format!(" {start}"));
                    } else {
                        line.push_str(&format!(" {start}-{end}"));
                    }
                    start = slot;
                    end = slot;
                }
            }
            if start == end {
                line.push_str(&format!(" {start}"));
            } else {
                line.push_str(&format!(" {start}-{end}"));
            }
        }
        line.push('\n');
        return Ok(RespFrame::BulkString(Some(line.into_bytes())));
    }
    if sub.eq_ignore_ascii_case("SLOTS") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        // Upstream cluster.c::clusterReplyShards-style entries: each
        // assigned slot range becomes [start, end, [primary_ip,
        // primary_port, primary_id]]. fr models a single self node
        // with no peer replicas. (frankenredis-u5he7)
        let slot_pairs = cluster_slot_range_frames(&store.cluster_assigned_slots);
        let mut entries = Vec::new();
        let mut i = 0;
        while i + 1 < slot_pairs.len() {
            let start = slot_pairs[i].clone();
            let end = slot_pairs[i + 1].clone();
            let primary = RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"".to_vec())),
                RespFrame::Integer(i64::from(store.server_port)),
                RespFrame::BulkString(Some(store.server_run_id.as_bytes().to_vec())),
            ]));
            entries.push(RespFrame::Array(Some(vec![start, end, primary])));
            i += 2;
        }
        return Ok(RespFrame::Array(Some(entries)));
    }
    if sub.eq_ignore_ascii_case("LINKS") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(RespFrame::Array(Some(vec![])));
    }
    if sub.eq_ignore_ascii_case("MYID") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(RespFrame::BulkString(Some(
            store.server_run_id.as_bytes().to_vec(),
        )));
    }
    if sub.eq_ignore_ascii_case("SHARDS") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(cluster_shards_reply(store));
    }
    if sub.eq_ignore_ascii_case("MYSHARDID") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        return Ok(RespFrame::BulkString(Some(
            store.cluster_shard_id.as_bytes().to_vec(),
        )));
    }
    if sub.eq_ignore_ascii_case("KEYSLOT") {
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = fr_store::crc16_slot(&argv[2]);
        return Ok(RespFrame::Integer(i64::from(slot)));
    }
    if sub.eq_ignore_ascii_case("GETKEYSINSLOT") {
        if argv.len() != 4 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = parse_i64_arg(&argv[2])?;
        if !(0..=16383).contains(&slot) {
            return Err(CommandError::Custom("ERR Invalid slot".to_string()));
        }
        let count = parse_i64_arg(&argv[3])?;
        if count < 0 {
            return Err(CommandError::InvalidInteger);
        }
        let keys = store.keys_in_slot(slot as u16, count as usize, now_ms);
        let frames: Vec<RespFrame> = keys
            .into_iter()
            .map(|k| RespFrame::BulkString(Some(k)))
            .collect();
        return Ok(RespFrame::Array(Some(frames)));
    }
    if sub.eq_ignore_ascii_case("COUNTKEYSINSLOT") {
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = parse_i64_arg(&argv[2])?;
        if !(0..=16383).contains(&slot) {
            return Err(CommandError::Custom("ERR Invalid slot".to_string()));
        }
        let count = store.count_keys_in_slot(slot as u16, now_ms);
        return Ok(RespFrame::Integer(count as i64));
    }
    if sub.eq_ignore_ascii_case("RESET") {
        if argv.len() > 3 {
            if store.script_nesting_level >= 1 {
                return Err(cluster_subcommand_syntax_error(sub));
            }
            if !store.cluster_enabled {
                return Err(cluster_disabled_error());
            }
            return Err(cluster_subcommand_syntax_error(sub));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let hard_reset = if let Some(mode) = argv.get(2) {
            let mode = std::str::from_utf8(mode).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !mode.eq_ignore_ascii_case("SOFT") && !mode.eq_ignore_ascii_case("HARD") {
                return Err(CommandError::SyntaxError);
            }
            mode.eq_ignore_ascii_case("HARD")
        } else {
            false
        };
        let db_index = store.dispatch_client_ctx.db_index;
        if store.dbsize_in_db(db_index) != 0 {
            return Err(cluster_reset_with_keys_error());
        }
        store.cluster_assigned_slots.clear();
        if hard_reset {
            store.cluster_current_epoch = 0;
            store.cluster_my_config_epoch = 0;
        }
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    // ── CLUSTER admin subcommands (first-pass per br-frankenredis-jsr7) ──
    //
    // Upstream cluster.c::clusterCommand wires each of these with distinct
    // validation + reply semantics. We implement arity + syntax validation
    // against the upstream shape; for commands that need a real node map
    // (which fr-repl does not yet expose), we accept-OK for no-op admin
    // flows and surface upstream-matching specific errors ("Unknown node X",
    // "DB must be empty ...", etc.) rather than the blanket "cluster
    // support disabled" string. Commands still punted to that blanket
    // error because they need a slot map / config epoch / node registry:
    //   SET-CONFIG-EPOCH, SLOTSTATE.
    if sub.eq_ignore_ascii_case("MEET") {
        // CLUSTER MEET <host> <port> [cluster-bus-port]
        // Upstream commands.def declares arity -4 (min 4, no max),
        // so trailing args still hit the cluster-disabled error
        // before any per-subcommand arity rejection. Once cluster
        // mode is enabled the handler still rejects argc > 5.
        // (br-frankenredis-clustermeetarity)
        if argv.len() < 4 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if argv.len() > 5 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        let host = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let port = std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        let Some(parsed_port) = cluster_parse_port_arg(&argv[3]) else {
            return Err(cluster_invalid_base_port(port));
        };
        if !(1..=65535).contains(&parsed_port) || host.parse::<std::net::IpAddr>().is_err() {
            return Err(cluster_invalid_node_address(host, port));
        }
        if let Some(bus_port) = argv.get(4) {
            let bus_port_str =
                std::str::from_utf8(bus_port).map_err(|_| CommandError::InvalidUtf8Argument)?;
            let Some(parsed_bus_port) = cluster_parse_port_arg(bus_port) else {
                return Err(cluster_invalid_bus_port(bus_port_str));
            };
            if !(1..=65535).contains(&parsed_bus_port) {
                return Err(cluster_invalid_node_address(host, port));
            }
        }
        // Accept but do not yet actually start a cluster handshake — a real
        // node registry is a separate work item.
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("FORGET") || sub.eq_ignore_ascii_case("REPLICATE") {
        // CLUSTER FORGET <node-id> / CLUSTER REPLICATE <node-id>
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let node_id =
            std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if sub.eq_ignore_ascii_case("FORGET") && node_id == store.server_run_id {
            return Err(CommandError::Custom(
                "ERR I tried hard but I can't forget myself...".to_string(),
            ));
        }
        if sub.eq_ignore_ascii_case("REPLICATE") && node_id == store.server_run_id {
            return Err(CommandError::Custom(
                "ERR Can't replicate myself".to_string(),
            ));
        }
        return Err(CommandError::Custom(format!("ERR Unknown node {node_id}")));
    }
    if sub.eq_ignore_ascii_case("REPLICAS") || sub.eq_ignore_ascii_case("SLAVES") {
        // CLUSTER REPLICAS <node-id> — upstream returns the replica array or
        // "The specified node is not known or can't be a replica" error.
        // SLAVES is upstream's deprecated alias for REPLICAS — see
        // legacy_redis_code/redis/src/commands/cluster-slaves.json.
        // (br-frankenredis-gcmq)
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let node_id =
            std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if node_id == store.server_run_id {
            return Ok(RespFrame::Array(Some(vec![])));
        }
        return Err(CommandError::Custom(
            "ERR The specified node is not known or can't be a replica".to_string(),
        ));
    }
    if sub.eq_ignore_ascii_case("FAILOVER") {
        // CLUSTER FAILOVER [FORCE|TAKEOVER] — upstream
        // cluster.c::clusterCommand gates this branch on
        // `argc == 2 || argc == 3`, so a 4-arg form like
        // "CLUSTER FAILOVER FORCE TAKEOVER" skips the branch and
        // falls through to the generic unknown-subcommand error.
        // FORCE and TAKEOVER are mutually exclusive — only one
        // may appear. The cluster-enabled gate fires BEFORE any
        // subcommand-level validation, so standalone instances
        // still get 'cluster support disabled' regardless of
        // arg shape. (br-frankenredis-clusterord, frankenredis-7mqn0)
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if argv.len() > 3 {
            return Err(cluster_subcommand_syntax_error(sub));
        }
        if argv.len() == 3 {
            let flag_str =
                std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !flag_str.eq_ignore_ascii_case("FORCE") && !flag_str.eq_ignore_ascii_case("TAKEOVER")
            {
                return Err(CommandError::SyntaxError);
            }
        }
        // Upstream: "You should send CLUSTER FAILOVER to a replica" when
        // issued on a master. We treat ourselves as master here (no replica
        // role tracking at the Store layer yet).
        return Err(CommandError::Custom(
            "ERR You should send CLUSTER FAILOVER to a replica".to_string(),
        ));
    }
    if sub.eq_ignore_ascii_case("ADDSLOTS") || sub.eq_ignore_ascii_case("DELSLOTS") {
        // CLUSTER ADDSLOTS <slot> [slot] ... / CLUSTER DELSLOTS ...
        if argv.len() < 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if sub.eq_ignore_ascii_case("ADDSLOTS") {
            let slots = cluster_collect_explicit_slots_for_update(
                &argv[2..],
                &store.cluster_assigned_slots,
                false,
            )?;
            for slot in slots {
                store.cluster_assigned_slots.insert(slot);
            }
        } else {
            let slots = cluster_collect_explicit_slots_for_update(
                &argv[2..],
                &store.cluster_assigned_slots,
                true,
            )?;
            for slot in slots {
                store.cluster_assigned_slots.remove(&slot);
            }
        }
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("ADDSLOTSRANGE") || sub.eq_ignore_ascii_case("DELSLOTSRANGE") {
        // CLUSTER ADDSLOTSRANGE <start> <end> [<start> <end> ...]
        // Upstream commands.def declares arity = -4 (≥4 args incl
        // CLUSTER + sub). The multiple-of-2 pair check happens
        // inside the cluster handler AFTER the cluster-enabled gate
        // — so in standalone mode 'cluster support disabled' fires
        // before the pair check. (br-frankenredis-clusterord)
        if argv.len() < 4 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        if !argv.len().is_multiple_of(2) {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if sub.eq_ignore_ascii_case("ADDSLOTSRANGE") {
            let slots = cluster_collect_slot_ranges_for_update(
                &argv[2..],
                &store.cluster_assigned_slots,
                false,
            )?;
            for slot in slots {
                store.cluster_assigned_slots.insert(slot);
            }
        } else {
            let slots = cluster_collect_slot_ranges_for_update(
                &argv[2..],
                &store.cluster_assigned_slots,
                true,
            )?;
            for slot in slots {
                store.cluster_assigned_slots.remove(&slot);
            }
        }
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("FLUSHSLOTS") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let db_index = store.dispatch_client_ctx.db_index;
        if store.dbsize_in_db(db_index) != 0 {
            return Err(CommandError::Custom(
                "ERR DB must be empty to perform CLUSTER FLUSHSLOTS.".to_string(),
            ));
        }
        store.cluster_assigned_slots.clear();
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("SAVECONFIG") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        // Upstream writes cluster.conf; we don't persist cluster state yet,
        // so this is a no-op. Returning OK matches the happy-path reply.
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    if sub.eq_ignore_ascii_case("BUMPEPOCH") {
        if argv.len() != 2 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let max_epoch = store
            .cluster_current_epoch
            .max(store.cluster_my_config_epoch);
        let bumped =
            store.cluster_my_config_epoch == 0 || store.cluster_my_config_epoch != max_epoch;
        if bumped {
            store.cluster_current_epoch = store.cluster_current_epoch.saturating_add(1);
            store.cluster_my_config_epoch = store.cluster_current_epoch;
        }
        let verb = if bumped { "BUMPED" } else { "STILL" };
        return Ok(RespFrame::SimpleString(format!(
            "{verb} {}",
            store.cluster_my_config_epoch
        )));
    }
    if sub.eq_ignore_ascii_case("SET-CONFIG-EPOCH") {
        // Upstream cluster.c::clusterCommand:6420+ validates the
        // epoch arg and replies with one of:
        //   - "Invalid config epoch specified: <epoch>" (negative)
        //   - "The user can assign a config epoch only when the
        //      node does not know any other node." (peer dict > 1)
        //   - "Node config epoch is already non-zero" (configEpoch != 0)
        //   - OK on success
        // commands.def declares arity = 3 so missing/extra args
        // trigger the table-level WrongArity check before
        // clusterCommand runs. (br-frankenredis-clusterord, frankenredis-pfamt)
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let epoch = parse_i64_arg(&argv[2])?;
        if epoch < 0 {
            return Err(CommandError::Custom(format!(
                "ERR Invalid config epoch specified: {epoch}"
            )));
        }
        if store.cluster_my_config_epoch != 0 {
            return Err(CommandError::Custom(
                "ERR Node config epoch is already non-zero".to_string(),
            ));
        }
        let epoch = epoch.unsigned_abs();
        store.cluster_my_config_epoch = epoch;
        store.cluster_current_epoch = store.cluster_current_epoch.max(epoch);
        return Ok(RespFrame::SimpleString("OK".to_string()));
    }
    // (frankenredis-cslotstate) CLUSTER SLOTSTATE is not a recognized
    // subcommand in upstream Redis 7.2.4 — neither commands.def nor
    // cluster.c::clusterCommand mentions it — so vendored returns
    // "ERR unknown subcommand 'SLOTSTATE'. Try CLUSTER HELP." even
    // when cluster mode is enabled. fr previously short-circuited
    // SLOTSTATE to cluster_disabled_error(), masking the typo. The
    // arm is removed so the catch-all unknown-subcommand fallthrough
    // (frankenredis-cunk) handles it the same way as any other
    // typo'd token.
    if sub.eq_ignore_ascii_case("SETSLOT") {
        // CLUSTER SETSLOT <slot> STABLE
        // CLUSTER SETSLOT <slot> NODE <node-id>
        // CLUSTER SETSLOT <slot> MIGRATING <node-id>
        // CLUSTER SETSLOT <slot> IMPORTING <node-id>
        // Mirror upstream cluster.c::clusterCommand:6073-6132 arg
        // validation. fr does not yet model peer nodes / migration
        // state, so any node-id other than self is unknown and the
        // STABLE / NODE paths accept-and-OK. (br-frankenredis-nzaw,
        // frankenredis-t1s3f)
        //
        // (frankenredis-0pnd6) Upstream's top-level guard is `c->argc
        // >= 4` (loose); the exact arity per action (STABLE=4, others=5)
        // is enforced AFTER the cluster_enabled check. With argv.len()
        // == 6 (e.g. CLUSTER SETSLOT 0 NODE someid extra) upstream
        // surfaces 'cluster support disabled', not 'wrong number of
        // arguments', when cluster mode is off. Move the cluster_enabled
        // gate ahead of the per-action exact-arity check.
        if argv.len() < 4 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let slot = parse_i64_arg(&argv[2])?;
        if !(0..=16383).contains(&slot) {
            return Err(CommandError::Custom("ERR Invalid slot".to_string()));
        }
        let action =
            std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if action.eq_ignore_ascii_case("STABLE") {
            if argv.len() != 4 {
                return Err(cluster_invalid_setslot_action_error());
            }
            // STABLE clears any migration state — no-op in fr's stub.
            return Ok(RespFrame::SimpleString("OK".to_string()));
        }
        if action.eq_ignore_ascii_case("MIGRATING")
            || action.eq_ignore_ascii_case("IMPORTING")
            || action.eq_ignore_ascii_case("NODE")
        {
            if argv.len() != 5 {
                return Err(cluster_invalid_setslot_action_error());
            }
            let slot = slot as u16;
            let node_id =
                std::str::from_utf8(&argv[4]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if action.eq_ignore_ascii_case("MIGRATING")
                && !store.cluster_assigned_slots.contains(&slot)
            {
                return Err(CommandError::Custom(format!(
                    "ERR I'm not the owner of hash slot {slot}"
                )));
            }
            if action.eq_ignore_ascii_case("IMPORTING")
                && store.cluster_assigned_slots.contains(&slot)
            {
                return Err(CommandError::Custom(format!(
                    "ERR I'm already the owner of hash slot {slot}"
                )));
            }
            // fr models a single self node; any other id is unknown.
            // Upstream's NODE branch emits "Unknown node <id>", while
            // MIGRATING / IMPORTING emit "I don't know about node <id>".
            if node_id != store.server_run_id {
                let msg = if action.eq_ignore_ascii_case("NODE") {
                    format!("ERR Unknown node {node_id}")
                } else {
                    format!("ERR I don't know about node {node_id}")
                };
                return Err(CommandError::Custom(msg));
            }
            if action.eq_ignore_ascii_case("NODE") {
                store.cluster_assigned_slots.insert(slot);
            }
            // Self MIGRATING/IMPORTING is accepted; fr has no migration state yet.
            return Ok(RespFrame::SimpleString("OK".to_string()));
        }
        return Err(cluster_invalid_setslot_action_error());
    }
    if sub.eq_ignore_ascii_case("COUNT-FAILURE-REPORTS") {
        // Upstream cluster.c::clusterCommand: when cluster mode is on,
        // looks up the node-id and replies with the failure-report
        // count or `-Unknown node <id>`. With cluster mode off the
        // standard "This instance has cluster support disabled" applies.
        // (br-frankenredis-r84v)
        if argv.len() != 3 {
            return Err(cluster_wrong_subcommand_arity(sub));
        }
        if !store.cluster_enabled {
            return Err(cluster_disabled_error());
        }
        let node_id =
            std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if node_id == store.server_run_id {
            return Ok(RespFrame::Integer(0));
        }
        return Err(CommandError::Custom(format!("ERR Unknown node {node_id}")));
    }
    // Upstream commands.def declares each known cluster subcommand
    // (cluster|myid, cluster|nodes, ...) with clusterCommand as the
    // handler, so the dispatcher returns
    // "ERR unknown subcommand '<X>'. Try CLUSTER HELP." for any token
    // that isn't one of those entries — BEFORE clusterCommand (and
    // therefore the cluster_enabled gate inside it) ever runs.
    // Differential probe vs vendored Redis 7.2.4 with cluster-enabled
    // set to no confirmed: `CLUSTER MYID` -> "cluster support
    // disabled" (handler runs), but `CLUSTER NOPE` -> "unknown
    // subcommand 'NOPE'..." (handler is never called). The earlier
    // frankenredis-53ati change misread the upstream source's
    // top-of-function gate and gated the unknown-subcommand
    // fallthrough on cluster_enabled too, leaking "disabled" for
    // typo'd subs. (frankenredis-cunk)
    Err(cluster_unknown_subcommand_error(sub))
}

// ── REPLCONF ────────────────────────────────────────────────────────

fn replconf_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len().is_multiple_of(2) {
        return Err(CommandError::SyntaxError);
    }
    let mut idx = 1;
    while idx < argv.len() {
        let option =
            std::str::from_utf8(&argv[idx]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if option.eq_ignore_ascii_case("ACK") || option.eq_ignore_ascii_case("FACK") {
            let offset = parse_i64_arg(&argv[idx + 1])?;
            if offset < 0 {
                return Err(CommandError::InvalidInteger);
            }
            if store.script_nesting_level >= 1 {
                return Err(script_noscript_command_error());
            }
            return Ok(RespFrame::SimpleString("OK".to_string()));
        }
        if option.eq_ignore_ascii_case("GETACK") {
            if store.script_nesting_level >= 1 {
                return Err(script_noscript_command_error());
            }
            return Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"REPLCONF".to_vec())),
                RespFrame::BulkString(Some(b"ACK".to_vec())),
                RespFrame::BulkString(Some(b"0".to_vec())),
            ])));
        }
        if option.eq_ignore_ascii_case("listening-port") {
            let parsed = parse_i64_arg(&argv[idx + 1])?;
            u16::try_from(parsed).map_err(|_| CommandError::InvalidInteger)?;
        } else if option.eq_ignore_ascii_case("ip-address") || option.eq_ignore_ascii_case("capa") {
            // Accept configuration pairs silently.
        } else {
            return Err(CommandError::Custom(format!(
                "ERR Unrecognized REPLCONF option: {option}"
            )));
        }
        idx += 2;
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

// ── PSYNC ───────────────────────────────────────────────────────────

fn psync_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // PSYNC replid offset
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("PSYNC"));
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    // In standalone mode, FULLRESYNC with the server's own run_id so
    // subsequent PSYNC retries that echo this replid can be matched. The
    // offset stays at 0 here (a full replication backlog is not yet
    // tracked at this layer — see frankenredis-fcjh for the real
    // handshake pipeline). (br-frankenredis-fcjh, partial)
    let replid = store.server_run_id.clone();
    let offset = 0;
    Ok(RespFrame::SimpleString(format!(
        "FULLRESYNC {replid} {offset}"
    )))
}

// ── REPLICAOF / SLAVEOF ─────────────────────────────────────────────

fn replicaof_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // REPLICAOF host port / REPLICAOF NO ONE
    if argv.len() < 3 {
        return Err(CommandError::WrongArity(replicaof_command_name(argv)));
    }
    // Upstream commands.def declares REPLICAOF/SLAVEOF with
    // CMD_NOSCRIPT. server.c::processCommand emits the noscript
    // reply BEFORE the handler runs, so a scripted call must
    // surface that error rather than the 'Invalid master port'
    // parse error we previously emitted for non-numeric ports.
    // (frankenredis-d021m)
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    let host = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    let port = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if host.eq_ignore_ascii_case("NO") && port.eq_ignore_ascii_case("ONE") {
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else {
        let parsed = parse_i64_arg(&argv[2])
            .map_err(|_| CommandError::Custom("ERR Invalid master port".to_string()))?;
        u16::try_from(parsed)
            .map_err(|_| CommandError::Custom("ERR Invalid master port".to_string()))?;
        // Accept but don't actually replicate - standalone mode
        Ok(RespFrame::SimpleString("OK".to_string()))
    }
}

// ── READONLY / READWRITE ────────────────────────────────────────────

fn readonly_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("READONLY"));
    }
    // Upstream cluster.c::readonlyCommand: returns OK when cluster_enabled,
    // errors with "This instance has cluster support disabled" otherwise.
    // The actual per-client CLIENT_READONLY bit-flag is a cluster-routing
    // concern we don't yet honor; returning OK unblocks clients that use
    // READONLY as a preamble to replica-routed reads. (br-frankenredis-jsr7)
    if !store.cluster_enabled {
        return Err(CommandError::Custom(
            "ERR This instance has cluster support disabled".to_string(),
        ));
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn readwrite_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("READWRITE"));
    }
    // Upstream cluster.c::readwriteCommand: mirror of readonly — OK when
    // cluster_enabled, disabled-error otherwise.
    if !store.cluster_enabled {
        return Err(CommandError::Custom(
            "ERR This instance has cluster support disabled".to_string(),
        ));
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

// ── ZRANGESTORE ────────────────────────────────────────────────────

fn zrangestore_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // ZRANGESTORE dst src min max [BYSCORE | BYLEX] [REV] [LIMIT offset count]
    if argv.len() < 5 {
        return Err(CommandError::WrongArity("ZRANGESTORE"));
    }
    let dst = &argv[1];
    let src = &argv[2];

    let mut byscore = false;
    let mut bylex = false;
    let mut rev = false;
    let mut limit_offset: Option<usize> = None;
    let mut limit_count: Option<usize> = None;
    // See ZRANGE: upstream's shape check is `opt_limit != -1`, so only an exact
    // -1 is the no-limit sentinel. (frankenredis-zrlimneg)
    let mut limit_count_raw: i64 = -1;

    let mut i = 5;
    while i < argv.len() {
        let opt = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if opt.eq_ignore_ascii_case("BYSCORE") {
            // (frankenredis-r2f7m) ZRANGE rejects duplicate BYSCORE /
            // BYLEX / REV because upstream t_zset.c::zrangeGenericCommand
            // only matches each marker while the corresponding state is
            // still AUTO. ZRANGESTORE shares that parser; mirror the
            // guards here so a second `BYSCORE`/`BYLEX`/`REV` falls
            // through to "syntax error" instead of silently winning.
            if byscore || bylex {
                return Err(CommandError::SyntaxError);
            }
            byscore = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("BYLEX") {
            if byscore || bylex {
                return Err(CommandError::SyntaxError);
            }
            bylex = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("REV") {
            if rev {
                return Err(CommandError::SyntaxError);
            }
            rev = true;
            i += 1;
        } else if opt.eq_ignore_ascii_case("LIMIT") {
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Same parse-order discipline as the ZRANGE generic above:
            // upstream t_zset.c::zrangeGenericCommand (called by
            // ZRANGESTORE via the shared ZRangeArgs path) parses the
            // LIMIT offset as a long and defers BYSCORE/BYLEX-pairing
            // validation to a post-loop check. (frankenredis-zrnegoff)
            limit_offset = Some(parse_limit_offset_arg(&argv[i + 1])?);
            limit_count_raw = parse_i64_arg(&argv[i + 2])?;
            limit_count = parse_limit_count_arg(&argv[i + 2])?;
            i += 3;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    if byscore && bylex {
        return Err(CommandError::SyntaxError);
    }

    // (frankenredis-qsd9p) Upstream's zrangeGenericCommand checks
    // `opt_limit != -1` after the parse loop — the sentinel for
    // "LIMIT was specified with a real count" is limit_count being
    // set, not limit_offset. fr's ZRANGE check uses the same rule
    // (line ~4261). The previous `limit_offset.is_some()` guard
    // rejected `LIMIT 0 -1` (no-op) even in plain-rank mode, while
    // ZRANGE accepts it. The raw count (not the negative-clamped limit_count)
    // drives the `opt_limit != -1` test so a non-(-1) negative count errors in
    // rank mode, matching ZRANGE and vendored. (frankenredis-zrlimneg)
    if limit_count_raw != -1 && !byscore && !bylex {
        return Ok(RespFrame::Error(
            "ERR syntax error, LIMIT is only supported in combination with either BYSCORE or BYLEX"
                .to_string(),
        ));
    }

    // The source range reads below are no-stat; upstream zrangestoreCommand
    // (zrangeGenericCommand) does a lookupKeyRead on src, so record one keyspace
    // hit/miss here (after option validation, before the range walk / wrongtype).
    record_source_key_lookups(store, &[src.as_slice()], now_ms);
    let pairs: Vec<(Vec<u8>, f64)> = if byscore {
        let min = parse_score_bound(&argv[3])?;
        let max = parse_score_bound(&argv[4])?;
        let (lo, hi) = if rev { (max, min) } else { (min, max) };
        if zscore_inverted_wrongtype_guard(store, src, lo, hi, now_ms)? {
            // Inverted range on a zset/missing src → empty result: delete dst
            // and return 0 (wrong-type src already returned WRONGTYPE above).
            store.del(std::slice::from_ref(dst), now_ms);
            return Ok(RespFrame::Integer(0));
        }
        // LIMIT/REV pushed into the range walk — O(offset+count), not O(range)
        // (mirrors the ZRANGE BYSCORE path; frankenredis-qchm7).
        store.zrangebyscore_withscores_limited(
            src,
            lo,
            hi,
            rev,
            limit_offset.unwrap_or(0),
            limit_count,
            now_ms,
        )?
    } else if bylex {
        let min_lex = &argv[3];
        let max_lex = &argv[4];
        validate_lex_bound(min_lex)?;
        validate_lex_bound(max_lex)?;
        let (lo, hi) = if rev {
            (max_lex.as_slice(), min_lex.as_slice())
        } else {
            (min_lex.as_slice(), max_lex.as_slice())
        };
        store.zrangebylex_withscores_limited(
            src,
            lo,
            hi,
            rev,
            limit_offset.unwrap_or(0),
            limit_count,
            now_ms,
        )?
    } else {
        // Default: by rank (index)
        let start = parse_i64_arg(&argv[3])?;
        let stop = parse_i64_arg(&argv[4])?;
        if rev {
            store.zrevrange_withscores(src, start, stop, now_ms)?
        } else {
            store.zrange_withscores(src, start, stop, now_ms)?
        }
    };

    // LIMIT is now pushed down into both BYSCORE (zrangebyscore_withscores_limited)
    // and BYLEX (zrangebylex_withscores_limited) range walks, so no post-collect
    // slice remains. Rank mode never carries a real-count LIMIT (rejected above),
    // matching upstream zrangeGenericCommand. (frankenredis-qchm7, qsd9p, 5qwm6)
    let count = pairs.len() as i64;
    if pairs.is_empty() {
        // Delete dst if it exists
        store.del(std::slice::from_ref(dst), now_ms);
    } else {
        // (frankenredis-t8rma) BYSCORE / BYLEX destinations are always created
        // skiplist-encoded upstream (zsetTypeCreate(-1, 0)); rank mode sizes by
        // the exact count and derives its encoding naturally.
        store.zstore_from_pairs(dst.clone(), pairs, byscore || bylex, now_ms);
    }
    Ok(RespFrame::Integer(count))
}

// ── FUNCTION ────────────────────────────────────────────────────────

fn function_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    _now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("FUNCTION"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("LOAD") {
        // FUNCTION LOAD [REPLACE] function-code
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "LOAD".to_string(),
            });
        }
        let mut replace = false;
        let code_idx;
        if argv.len() >= 4 {
            let flag =
                std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if flag.eq_ignore_ascii_case("REPLACE") {
                replace = true;
                code_idx = 3;
            } else {
                // Upstream functions.c::functionsCommand rejects any
                // non-REPLACE token in the option slot with the
                // dedicated 'ERR Unknown option given: <token>' wording
                // before parsing the body. fr previously fell through
                // and treated argv[2] as the code body, losing the
                // upstream wording. (frankenredis-fnopt)
                return Err(CommandError::Custom(format!(
                    "ERR Unknown option given: {flag}"
                )));
            }
        } else {
            code_idx = 2;
        }
        if code_idx >= argv.len() {
            return Err(CommandError::WrongArity("FUNCTION"));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        // (frankenredis-5qhz7 / mbyoe / sg7b4) Upstream functions.c validates the
        // library metadata header, then COMPILES the whole body, then registers
        // — so a Lua syntax error ANYWHERE surfaces "Error compiling function:
        // user_function:<line>: <msg>" before any store mutation, but AFTER
        // metadata-header validation. fr-store text-scans for register_function
        // and never compiles, so it (a) reported "No functions registered" for a
        // syntax-error body with no scannable register_function, and (b) accepted
        // a library whose register_function was scannable but whose body had a
        // syntax error elsewhere. Pre-compile here: on failure let a metadata
        // error win (precedence), else surface the compile error WITHOUT
        // mutating the store — which preserves REPLACE atomicity (the existing
        // library is left untouched, exactly as upstream does on a failed
        // recompile). lua_execution_source blanks the shebang to a same-width
        // space run, so compile_error_line reports the true file line.
        if lua_eval::compile_check(&argv[code_idx]).is_err() {
            store
                .function_validate_metadata(&argv[code_idx])
                .map_err(CommandError::Store)?;
            return Err(CommandError::Custom(format!(
                "ERR Error compiling function: user_function:{}",
                lua_eval::compile_error_line(&argv[code_idx])
            )));
        }
        match store.function_load(&argv[code_idx], replace) {
            Ok(name) => Ok(RespFrame::BulkString(Some(name.into_bytes()))),
            Err(e) => Err(CommandError::Store(e)),
        }
    } else if sub.eq_ignore_ascii_case("LIST") {
        // FUNCTION LIST [LIBRARYNAME pattern] [WITHCODE]
        // Upstream FUNCTION LIST carries CMD_NOSCRIPT — fire the
        // noscript guard before the option-parsing loop so a
        // scripted bad-arg call surfaces the noscript reply
        // rather than 'Unknown argument <token>' or 'library name
        // argument was not given'. (frankenredis-yrm7e)
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let mut pattern = None;
        let mut with_code = false;
        let mut i = 2;
        while i < argv.len() {
            let arg =
                std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if arg.eq_ignore_ascii_case("LIBRARYNAME") {
                i += 1;
                if i >= argv.len() {
                    // Upstream functions.c::functionListCommand emits
                    // 'library name argument was not given' when the
                    // LIBRARYNAME option is missing its argument.
                    // (br-frankenredis-funclist)
                    return Err(CommandError::Custom(
                        "ERR library name argument was not given".to_string(),
                    ));
                }
                let pat =
                    std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
                pattern = Some(pat.to_string());
            } else if arg.eq_ignore_ascii_case("WITHCODE") {
                with_code = true;
            } else {
                // Upstream functions.c::functionListCommand emits
                // 'ERR Unknown argument <token>' for any token
                // outside LIBRARYNAME / WITHCODE. (br-frankenredis-funclist)
                return Err(CommandError::Custom(format!("ERR Unknown argument {arg}")));
            }
            i += 1;
        }
        // (frankenredis-1dfox) Upstream functions.c::functionListCommand
        // emits per-library + per-function as Maps under RESP3
        // (addReplyMapLen(c, with_code ? 4 : 3) for the library and
        // addReplyMapLen(c, 3) for each function). RESP2 stays the
        // existing flat alternating-k/v Array. Same shape pattern
        // as i40x2/e4njz/udl3y/asvh1/5d04d/ndz0j/5h86s/cz712/ec2rf/
        // q11am.
        let resp = store.dispatch_client_ctx.resp_protocol_version;
        let libs = store.function_list(pattern.as_deref());
        let mut result = Vec::new();
        for lib in libs {
            let mut entries = vec![
                RespFrame::BulkString(Some(b"library_name".to_vec())),
                RespFrame::BulkString(Some(lib.name.as_bytes().to_vec())),
                RespFrame::BulkString(Some(b"engine".to_vec())),
                // PINNED 2026-04-22 — do NOT lowercase this.
                //
                // Verified against the vendored Redis 7.2.4 source
                // (legacy_redis_code/redis/src/function_lua.c:48 defines
                // `#define LUA_ENGINE_NAME "LUA"` and line 505 registers the
                // Lua engine as `functionsRegisterEngine(LUA_ENGINE_NAME, ...)`).
                // functions.c:551-552 then emits the engine field via
                // `addReplyBulkCBuffer(c, li->ei->name, ...)`, which is the
                // registered `"LUA"` string — i.e. upstream Redis 7.2.4 emits
                // the engine name in its stored case (`"LUA"`, uppercase).
                // The matching pin in the FUNCTION STATS engines map below
                // hardcodes `b"LUA"` for the same reason.
                //
                // Prior agents have flipped this line to
                // `lib.engine.to_ascii_lowercase().into_bytes()` at least
                // four times. The empirical record on the vendored Redis
                // 7.2.4 tree is unambiguous — `to_ascii_lowercase` introduces
                // a parity divergence. The root cause of the repeated flip
                // was that the `function_list_basic` fixture in
                // crates/fr-conformance/fixtures/core_scripting.json briefly
                // expected `"lua"`; that fixture has been corrected to
                // `"LUA"` so the fixture and the code now agree.
                // If a future Redis release changes this, update both the
                // live-oracle fixture and this comment in the same commit.
                RespFrame::BulkString(Some(lib.engine.as_bytes().to_vec())),
                RespFrame::BulkString(Some(b"functions".to_vec())),
            ];
            let funcs: Vec<RespFrame> = lib
                .functions
                .iter()
                .map(|f| {
                    let name_frame = RespFrame::BulkString(Some(f.name.as_bytes().to_vec()));
                    let desc_frame = match &f.description {
                        Some(d) => RespFrame::BulkString(Some(d.as_bytes().to_vec())),
                        None => RespFrame::BulkString(None),
                    };
                    // Upstream functions.c emits each function flag via
                    // addReplyStatus (a simple string `+`), and wraps the
                    // list in addReplySetLen — so it is a Set (~) in RESP3
                    // and a flat Array of simple strings in RESP2. fr was
                    // emitting bulk strings inside an Array. (frankenredis-fnflags)
                    let flag_elems: Vec<RespFrame> = f
                        .flags
                        .iter()
                        .map(|fl| RespFrame::SimpleString(fl.to_string()))
                        .collect();
                    let flags_frame = if resp == 3 {
                        RespFrame::Set(Some(flag_elems))
                    } else {
                        RespFrame::Array(Some(flag_elems))
                    };
                    if resp == 3 {
                        RespFrame::Map(Some(vec![
                            (RespFrame::BulkString(Some(b"name".to_vec())), name_frame),
                            (
                                RespFrame::BulkString(Some(b"description".to_vec())),
                                desc_frame,
                            ),
                            (RespFrame::BulkString(Some(b"flags".to_vec())), flags_frame),
                        ]))
                    } else {
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(b"name".to_vec())),
                            name_frame,
                            RespFrame::BulkString(Some(b"description".to_vec())),
                            desc_frame,
                            RespFrame::BulkString(Some(b"flags".to_vec())),
                            flags_frame,
                        ]))
                    }
                })
                .collect();
            entries.push(RespFrame::Array(Some(funcs)));
            if with_code {
                entries.push(RespFrame::BulkString(Some(b"library_code".to_vec())));
                entries.push(RespFrame::BulkString(Some(lib.code.clone())));
            }
            if resp == 3 {
                assert!(
                    entries.len().is_multiple_of(2),
                    "FUNCTION LIST library entries must be balanced k/v pairs"
                );
                let mut pairs = Vec::with_capacity(entries.len() / 2);
                let mut iter = entries.into_iter();
                while let (Some(k), Some(v)) = (iter.next(), iter.next()) {
                    pairs.push((k, v));
                }
                result.push(RespFrame::Map(Some(pairs)));
            } else {
                result.push(RespFrame::Array(Some(entries)));
            }
        }
        Ok(RespFrame::Array(Some(result)))
    } else if sub.eq_ignore_ascii_case("STATS") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "STATS".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let (lib_count, func_count) = store.function_stats();
        // Mirror upstream functions.c::functionStatsCommand which uses
        // doubly-nested addReplyMapLen — RESP3 wire shape is a Map of
        // 2 pairs at the outer level (running_script, engines), with
        // 'engines' being a Map of (engine_name, per-engine Map). The
        // per-engine inner Map carries (libraries_count, N) and
        // (functions_count, M). RESP2 stays the existing flat Array of
        // alternating k/v entries with the engine details nested as
        // sub-Arrays. (frankenredis-asvh1)
        if store.dispatch_client_ctx.resp_protocol_version == 3 {
            let lua_inner = RespFrame::Map(Some(vec![
                (
                    RespFrame::BulkString(Some(b"libraries_count".to_vec())),
                    RespFrame::Integer(lib_count as i64),
                ),
                (
                    RespFrame::BulkString(Some(b"functions_count".to_vec())),
                    RespFrame::Integer(func_count as i64),
                ),
            ]));
            let engines = RespFrame::Map(Some(vec![(
                RespFrame::BulkString(Some(b"LUA".to_vec())),
                lua_inner,
            )]));
            Ok(RespFrame::Map(Some(vec![
                (
                    RespFrame::BulkString(Some(b"running_script".to_vec())),
                    RespFrame::BulkString(None),
                ),
                (RespFrame::BulkString(Some(b"engines".to_vec())), engines),
            ])))
        } else {
            Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"running_script".to_vec())),
                // PINNED 2026-04-22 — running_script is RESP2 nil (BulkString(None))
                // when no script is executing, NOT Integer(0). Verified against
                // stock `redis:7.4` (version 7.4.8): `FUNCTION STATS` returns
                // `(nil)` in the running_script slot on an idle server. A prior
                // session briefly changed this to `RespFrame::Integer(0)`; that
                // was incorrect and has since been reverted. Leave it as nil.
                RespFrame::BulkString(None),
                RespFrame::BulkString(Some(b"engines".to_vec())),
                RespFrame::Array(Some(vec![
                    // PINNED 2026-04-22 — engine name is emitted in its stored case
                    // (uppercase "LUA") in both FUNCTION STATS and FUNCTION LIST;
                    // see the matching pin at the `lib.engine.as_bytes()` line in
                    // the FUNCTION LIST handler above.
                    RespFrame::BulkString(Some(b"LUA".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"libraries_count".to_vec())),
                        RespFrame::Integer(lib_count as i64),
                        RespFrame::BulkString(Some(b"functions_count".to_vec())),
                        RespFrame::Integer(func_count as i64),
                    ])),
                ])),
            ])))
        }
    } else if sub.eq_ignore_ascii_case("DUMP") {
        // Upstream commands.def declares FUNCTION DUMP with arity = 2,
        // so any extra arg trips the table-level WrongArity check
        // before functions.c::functionDumpCommand runs. (br-frankenredis-funcdump)
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "DUMP".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let data = store.function_dump();
        Ok(RespFrame::BulkString(Some(data)))
    } else if sub.eq_ignore_ascii_case("RESTORE") {
        // FUNCTION RESTORE serialized-value [FLUSH|APPEND|REPLACE]
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "RESTORE".to_string(),
            });
        }
        // Upstream FUNCTION RESTORE carries CMD_NOSCRIPT — fire the
        // noscript guard before the extra-arg / policy parse checks.
        // (frankenredis-yrm7e)
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        if argv.len() > 4 {
            // (frankenredis-subcase) Preserve the input-case sub token
            // per upstream addReplySubcommandSyntaxError.
            return Err(CommandError::Custom(format!(
                "ERR unknown subcommand or wrong number of arguments for '{sub}'. Try FUNCTION HELP."
            )));
        }
        let policy = if argv.len() >= 4 {
            std::str::from_utf8(&argv[3]).map_err(|_| CommandError::InvalidUtf8Argument)?
        } else {
            ""
        };
        match store.function_restore(&argv[2], policy) {
            Ok(()) => Ok(RespFrame::SimpleString("OK".to_string())),
            Err(e) => Err(CommandError::Store(e)),
        }
    } else if sub.eq_ignore_ascii_case("FLUSH") {
        // (br-frankenredis-ngn0) — upstream functions.c::functionsCommand
        // emits the FLUSH-specific subcommand error, not a generic
        // wrong-arity reply.
        // Upstream FUNCTION FLUSH carries CMD_NOSCRIPT (commands.def
        // line 5140) — the flag is checked at dispatch level before
        // any handler-level extra-arg or mode validation.
        // (frankenredis-yrm7e)
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        if argv.len() > 3 {
            // (frankenredis-subcase)
            return Err(CommandError::Custom(format!(
                "ERR unknown subcommand or wrong number of arguments for '{sub}'. Try FUNCTION HELP."
            )));
        }
        if argv.len() == 3 {
            let mode =
                std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if !mode.eq_ignore_ascii_case("ASYNC") && !mode.eq_ignore_ascii_case("SYNC") {
                return Ok(RespFrame::Error(
                    "ERR FUNCTION FLUSH only supports SYNC|ASYNC option".to_string(),
                ));
            }
        }
        store.function_flush();
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("KILL") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "KILL".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Ok(RespFrame::Error(
            "NOTBUSY No scripts in execution right now.".to_string(),
        ))
    } else if sub.eq_ignore_ascii_case("DELETE") {
        if argv.len() != 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "DELETE".to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        let name = std::str::from_utf8(&argv[2]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        match store.function_delete(name) {
            Ok(()) => Ok(RespFrame::SimpleString("OK".to_string())),
            Err(e) => Err(CommandError::Store(e)),
        }
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "FUNCTION",
                subcommand: "HELP".to_string(),
            });
        }
        Ok(RespFrame::Array(Some(vec![
            hello_simple("FUNCTION <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("LOAD [REPLACE] <FUNCTION CODE>"),
            hello_simple("    Create a new library with the given library name and code."),
            hello_simple("DELETE <LIBRARY NAME>"),
            hello_simple("    Delete the given library."),
            hello_simple("LIST [LIBRARYNAME PATTERN] [WITHCODE]"),
            hello_simple("    Return general information on all the libraries:"),
            hello_simple("    * Library name"),
            hello_simple("    * The engine used to run the Library"),
            hello_simple("    * Library description"),
            hello_simple("    * Functions list"),
            hello_simple("    * Library code (if WITHCODE is given)"),
            hello_simple(
                "    It also possible to get only function that matches a pattern using LIBRARYNAME argument.",
            ),
            hello_simple("STATS"),
            hello_simple("    Return information about the current function running:"),
            hello_simple("    * Function name"),
            hello_simple("    * Command used to run the function"),
            hello_simple("    * Duration in MS that the function is running"),
            hello_simple("    If no function is running, return nil"),
            hello_simple("    In addition, returns a list of available engines."),
            hello_simple("KILL"),
            hello_simple("    Kill the current running function."),
            hello_simple("FLUSH [ASYNC|SYNC]"),
            hello_simple("    Delete all the libraries."),
            hello_simple(
                "    When called without the optional mode argument, the behavior is determined by the",
            ),
            hello_simple("    lazyfree-lazy-user-flush configuration directive. Valid modes are:"),
            hello_simple("    * ASYNC: Asynchronously flush the libraries."),
            hello_simple("    * SYNC: Synchronously flush the libraries."),
            hello_simple("DUMP"),
            hello_simple(
                "    Return a serialized payload representing the current libraries, can be restored using FUNCTION RESTORE command",
            ),
            hello_simple("RESTORE <PAYLOAD> [FLUSH|APPEND|REPLACE]"),
            hello_simple(
                "    Restore the libraries represented by the given payload, it is possible to give a restore policy to",
            ),
            hello_simple("    control how to handle existing libraries (default APPEND):"),
            hello_simple("    * FLUSH: delete all existing libraries."),
            hello_simple(
                "    * APPEND: appends the restored libraries to the existing libraries. On collision, abort.",
            ),
            hello_simple(
                "    * REPLACE: appends the restored libraries to the existing libraries, On collision, replace the old",
            ),
            hello_simple(
                "      libraries with the new libraries (notice that even on this option there is a chance of failure",
            ),
            hello_simple("      in case of functions name collision with another library)."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])))
    } else {
        Err(CommandError::UnknownSubcommand {
            command: "FUNCTION",
            subcommand: sub.to_string(),
        })
    }
}

/// Remap parse_eval_args' generic InvalidInteger error into FCALL's
/// upstream-specific 'Bad number of keys provided' wording.
/// (frankenredis-ascgr)
fn fcall_map_eval_arg_error(err: CommandError) -> CommandError {
    if matches!(err, CommandError::InvalidInteger) {
        CommandError::Custom("ERR Bad number of keys provided".to_string())
    } else {
        err
    }
}

fn fcall_cmd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // FCALL function numkeys [key ...] [arg ...]
    let cmd_name = std::str::from_utf8(&argv[0]).unwrap_or("FCALL");
    let is_ro = cmd_name.eq_ignore_ascii_case("FCALL_RO");

    if argv.len() < 3 {
        return Err(CommandError::WrongArity(if is_ro {
            "fcall_ro"
        } else {
            "fcall"
        }));
    }
    // Upstream FCALL/FCALL_RO carry CMD_NOSCRIPT — mirror script.c
    // ordering so scripted calls surface the noscript reply BEFORE
    // any handler-level parsing. The previous code remapped the
    // numkeys parse error via fcall_map_eval_arg_error, masking
    // the canonical noscript wording. (frankenredis-7j2cw)
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    let func_name = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;

    // Validate function name contains only safe identifier characters to prevent
    // Lua code injection when constructing the wrapper script.
    if func_name.is_empty()
        || !func_name
            .bytes()
            .all(|b| b.is_ascii_alphanumeric() || b == b'_')
    {
        return Ok(RespFrame::Error("ERR Function not found".to_string()));
    }

    // Look up the function by name
    let (script, has_no_writes) = match store.function_get(func_name) {
        Some((lib, func)) => {
            let no_writes = func
                .flags
                .iter()
                .any(|f| f.eq_ignore_ascii_case("no-writes"));
            (lib.code.clone(), no_writes)
        }
        None => {
            return Ok(RespFrame::Error("ERR Function not found".to_string()));
        }
    };

    if is_ro && !has_no_writes {
        return Ok(RespFrame::Error(
            "ERR Can not execute a script with write flag using *_ro command.".to_string(),
        ));
    }

    // (frankenredis-ascgr) Upstream functions.c::fcallCommandGeneric
    // line 638-641 uses `getLongLongFromObject` (no _OrReply suffix)
    // and emits a bespoke 'Bad number of keys provided' for
    // non-integer numkeys, distinct from EVAL's generic 'value is
    // not an integer' wording. parse_eval_args returns InvalidInteger
    // for that case; remap it to FCALL's specific wording.
    let (_numkeys, keys, args) = parse_eval_args(argv).map_err(fcall_map_eval_arg_error)?;

    // Transform the library code for execution:
    // 1. Strip the #!lua name=... header line (not valid Lua) but
    //    preserve its line position with a blank line so reported line
    //    numbers still align with the library source.
    // 2. Convert redis.register_function('name', func) calls into
    //    named function definitions so they can be called directly.
    // (frankenredis-tos1j) Track the source line of the matching
    // register_function call so FCALL errors can report
    // user_function:<line> with the same line vendored would (the line
    // of the function definition inside the library code).
    let code_str = String::from_utf8_lossy(&script);
    let mut lua_lines = Vec::new();
    let mut target_func_line: Option<usize> = None;
    for (idx, line) in code_str.lines().enumerate() {
        let line_no = idx + 1;
        let trimmed = line.trim();
        if trimmed.starts_with("#!") {
            lua_lines.push(String::new());
            continue;
        }
        if trimmed.contains("register_function") {
            if let Some(transformed) = transform_register_function(trimmed) {
                if let Some(name) = transformed
                    .strip_prefix("local function ")
                    .and_then(|s| s.find('(').map(|i| &s[..i]))
                    && name == func_name
                    && target_func_line.is_none()
                {
                    target_func_line = Some(line_no);
                }
                lua_lines.push(transformed);
            } else {
                lua_lines.push(String::new());
            }
            continue;
        }
        lua_lines.push(line.to_string());
    }
    lua_lines.push(format!("return {func_name}(KEYS, ARGV)"));
    let wrapper_script = lua_lines.join("\n");

    let keys_vec: Vec<Vec<u8>> = keys.to_vec();
    let args_vec: Vec<Vec<u8>> = args.to_vec();
    let previous_read_only = store.script_read_only;
    store.script_read_only = is_ro || has_no_writes;
    store.script_nesting_level += 1;
    let result = match lua_eval::eval_script(
        wrapper_script.as_bytes(),
        &keys_vec,
        &args_vec,
        store,
        now_ms,
    ) {
        Ok(frame) => Ok(frame),
        Err(e) => Ok(RespFrame::Error(format_fcall_runtime_error(
            &e,
            func_name,
            target_func_line.unwrap_or(2),
        ))),
    };
    store.script_nesting_level -= 1;
    store.script_read_only = previous_read_only;
    result
}

/// Reformat an eval_script error to match vendored Redis 7.0+ FCALL
/// error wording: `ERR <body> script: <func>, on @user_function:<N>.`
/// where <body> retains any `user_function:<N>:` source-location
/// prefix (rewritten from fr's hardcoded `user_script:<N>:`) and
/// errors from redis.call propagate without the source-location
/// prefix. (frankenredis-tos1j) Vendored f_lua_error_call composes
/// this in functions.c via luaPushErrorBuff; mirror it at the FCALL
/// boundary since fr's interpreter labels every line `user_script:1:`
/// regardless of where the error actually originated.
fn format_fcall_runtime_error(err: &str, func_name: &str, func_line: usize) -> String {
    let body = err.strip_prefix("ERR ").unwrap_or(err);
    let body = if let Some(rest) = body.strip_prefix("user_script:") {
        if let Some(colon) = rest.find(':') {
            format!("user_function:{}{}", func_line, &rest[colon..])
        } else {
            format!("user_function:{rest}")
        }
    } else {
        body.to_string()
    };
    format!("ERR {body} script: {func_name}, on @user_function:{func_line}.")
}

/// Transform `redis.register_function('name', function(k,a) body end)` into
/// `function name(k,a) body end` so it can be called by name in our Lua evaluator.
fn transform_register_function(line: &str) -> Option<String> {
    // Match: redis.register_function('name', function(...))    (positional)
    //   or:  redis.register_function("name", function(...))    (positional)
    //   or:  redis.register_function{function_name='name', callback=function(...) ...}  (table)
    let after = line
        .find("register_function")
        .map(|i| &line[i + "register_function".len()..])?;
    let after = after.trim_start();
    if let Some(rest) = after.strip_prefix('{') {
        return transform_register_function_table_form(rest);
    }
    let after = after.strip_prefix('(')?;
    let after = after.trim_start();
    // Extract function name from 'name' or "name"
    let (name, rest) = if let Some(stripped) = after.strip_prefix('\'') {
        let end = stripped.find('\'')?;
        (&stripped[..end], &stripped[end + 1..])
    } else {
        let stripped = after.strip_prefix('"')?;
        let end = stripped.find('"')?;
        (&stripped[..end], &stripped[end + 1..])
    };
    // Skip comma and whitespace to find 'function'
    let rest = rest.trim_start().strip_prefix(',')?;
    let rest = rest.trim_start();
    // Rest should be: function(params) body end)
    // Strip trailing ')' from the register_function call
    let rest = rest.strip_prefix("function")?;
    let rest = rest.trim_end();
    let rest = rest.strip_suffix(')')?;
    // (frankenredis-j02x9) Use `local function` to keep the function out
    // of the locked globals table — fr's strict-globals enforcement now
    // blocks bare `function name() ...` writes during script execution.
    Some(format!("local function {name}{rest}"))
}

/// Transform a table-form `register_function{...}` call into a
/// named-function definition for the wrapper script.
/// Handles `{function_name='name', callback=function(params) body end, ...}`
/// in any field order. (frankenredis-fntblxform)
fn transform_register_function_table_form(body: &str) -> Option<String> {
    // Locate the closing `}` of the table at brace_depth==0,
    // skipping nested strings and braces.
    let bytes = body.as_bytes();
    let mut i = 0;
    let mut depth: i32 = 1;
    let mut name: Option<String> = None;
    let mut params: Option<&str> = None;
    let mut fn_body: Option<&str> = None;
    while i < bytes.len() && depth > 0 {
        let b = bytes[i];
        if b == b'\'' || b == b'"' {
            let q = b;
            i += 1;
            while i < bytes.len() && bytes[i] != q {
                if bytes[i] == b'\\' && i + 1 < bytes.len() {
                    i += 1;
                }
                i += 1;
            }
            if i < bytes.len() {
                i += 1;
            }
            continue;
        }
        if b == b'{' {
            depth += 1;
            i += 1;
            continue;
        }
        if b == b'}' {
            depth -= 1;
            i += 1;
            continue;
        }
        let left_ok =
            i == 0 || !matches!(bytes[i - 1], b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_');
        if depth == 1 && left_ok && matches!(b, b'A'..=b'Z' | b'a'..=b'z' | b'_') {
            let start = i;
            while i < bytes.len()
                && matches!(bytes[i], b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_')
            {
                i += 1;
            }
            let ident = &body[start..i];
            let mut j = i;
            while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                j += 1;
            }
            if j < bytes.len() && bytes[j] == b'=' {
                let after_eq = body[j + 1..].trim_start();
                if ident == "function_name" {
                    let qbytes = after_eq.as_bytes();
                    if let Some(&q) = qbytes.first()
                        && (q == b'\'' || q == b'"')
                        && let Some(end) = after_eq[1..].find(q as char)
                    {
                        name = Some(after_eq[1..1 + end].to_string());
                    }
                } else if ident == "callback"
                    && let Some(rest) = after_eq.strip_prefix("function")
                {
                    // rest = (params) body end[, ...]
                    let rest = rest.trim_start();
                    if rest.starts_with('(') {
                        // Find matching ')'
                        let pbytes = rest.as_bytes();
                        let mut k = 1;
                        let mut pdepth: i32 = 1;
                        while k < pbytes.len() && pdepth > 0 {
                            match pbytes[k] {
                                b'(' => pdepth += 1,
                                b')' => pdepth -= 1,
                                _ => {}
                            }
                            k += 1;
                        }
                        params = Some(&rest[..k]);
                        // body extends from k to the matching `end` token
                        // closing the function. Coarse keyword-block depth
                        // counter (matches the helper in fr-store).
                        let after_params = &rest[k..];
                        let abytes = after_params.as_bytes();
                        let mut m = 0;
                        let mut bdepth: i32 = 1;
                        while m < abytes.len() && bdepth > 0 {
                            let bb = abytes[m];
                            if bb == b'\'' || bb == b'"' {
                                let q = bb;
                                m += 1;
                                while m < abytes.len() && abytes[m] != q {
                                    if abytes[m] == b'\\' && m + 1 < abytes.len() {
                                        m += 1;
                                    }
                                    m += 1;
                                }
                                if m < abytes.len() {
                                    m += 1;
                                }
                                continue;
                            }
                            let lok = m == 0
                                || !matches!(
                                    abytes[m - 1],
                                    b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_'
                                );
                            if lok && matches!(bb, b'A'..=b'Z' | b'a'..=b'z' | b'_') {
                                let s = m;
                                while m < abytes.len()
                                    && matches!(
                                        abytes[m],
                                        b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'_'
                                    )
                                {
                                    m += 1;
                                }
                                let id = &after_params[s..m];
                                match id {
                                    "function" | "if" | "while" | "for" | "do" => bdepth += 1,
                                    "end" => bdepth -= 1,
                                    _ => {}
                                }
                                continue;
                            }
                            m += 1;
                        }
                        fn_body = Some(&after_params[..m]);
                        i = j
                            + 1
                            + (after_eq.as_ptr() as usize - body[j + 1..].as_ptr() as usize)
                            + (rest.as_ptr() as usize - after_eq.as_ptr() as usize)
                            + k
                            + m;
                        continue;
                    }
                }
            }
            continue;
        }
        i += 1;
    }
    let name = name?;
    let params = params?;
    let body = fn_body?;
    // (frankenredis-j02x9) Use `local function` to keep the function out
    // of the locked globals table.
    Some(format!("local function {name}{params}{body}"))
}

// ── SSUBSCRIBE / SUNSUBSCRIBE / SPUBLISH (shard Pub/Sub) ───────────

fn ssubscribe_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    // SSUBSCRIBE shardchannel [shardchannel ...]
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SSUBSCRIBE"));
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    if argv.len() == 2 {
        let count = store.ssubscribe(argv[1].clone()) as i64;
        return Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"ssubscribe".to_vec())),
            RespFrame::BulkString(Some(argv[1].clone())),
            RespFrame::Integer(count),
        ])));
    }
    let mut replies = Vec::with_capacity(argv.len() - 1);
    for channel in &argv[1..] {
        let count = store.ssubscribe(channel.clone()) as i64;
        replies.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"ssubscribe".to_vec())),
            RespFrame::BulkString(Some(channel.clone())),
            RespFrame::Integer(count),
        ])));
    }
    Ok(RespFrame::Sequence(replies))
}

fn sunsubscribe_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    // SUNSUBSCRIBE [shardchannel ...]
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    if argv.len() < 2 {
        // Unsubscribe from all shard channels (sorted for deterministic order)
        let mut channels: Vec<Vec<u8>> = store.subscribed_shard_channels.iter().cloned().collect();
        channels.sort();
        if channels.is_empty() {
            return Ok(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
                RespFrame::BulkString(None),
                RespFrame::Integer(0),
            ])));
        }
        let mut replies = Vec::with_capacity(channels.len());
        for channel in channels {
            let count = store.sunsubscribe(&channel) as i64;
            replies.push(RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
                RespFrame::BulkString(Some(channel)),
                RespFrame::Integer(count),
            ])));
        }
        return Ok(RespFrame::Sequence(replies));
    }
    if argv.len() == 2 {
        let count = store.sunsubscribe(&argv[1]) as i64;
        return Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
            RespFrame::BulkString(Some(argv[1].clone())),
            RespFrame::Integer(count),
        ])));
    }
    let mut replies = Vec::with_capacity(argv.len() - 1);
    for channel in &argv[1..] {
        let count = store.sunsubscribe(channel) as i64;
        replies.push(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"sunsubscribe".to_vec())),
            RespFrame::BulkString(Some(channel.clone())),
            RespFrame::Integer(count),
        ])));
    }
    Ok(RespFrame::Sequence(replies))
}

fn spublish_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    // SPUBLISH shardchannel message
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("SPUBLISH"));
    }
    if store.dispatch_client_ctx.is_pubsub {
        return Err(CommandError::Custom(
            "ERR Can't execute 'spublish': only (P|S)SUBSCRIBE / (P|S)UNSUBSCRIBE / PING / QUIT / RESET are allowed in this context".to_string(),
        ));
    }
    let receivers = store.spublish(&argv[1], &argv[2]);
    Ok(RespFrame::Integer(receivers as i64))
}

pub fn parse_score_bound(arg: &[u8]) -> Result<ScoreBound, CommandError> {
    // Upstream Redis 7.2 t_zset.c::zslParseRange uses
    // strtod((char*)ptr+(open?1:0), &eptr) and `eptr[0] != '\0'` as
    // the trailing-junk gate. That has three observable consequences
    // worth mirroring exactly (frankenredis-zbound):
    //
    //   1. The `(` prefix must be the FIRST character — strtod is
    //      called on `ptr+1` only when `ptr[0] == '('`. Leading
    //      whitespace BEFORE `(` (e.g. ` (5`) routes to the non-open
    //      branch and strtod fails on the `(` character.
    //   2. After `(` (or with no prefix), strtod accepts an empty
    //      string by returning 0.0 with eptr at `'\0'`, so `(`
    //      alone is parsed as an exclusive 0.
    //   3. strtod skips LEADING whitespace but the `eptr[0] != '\0'`
    //      check rejects any trailing whitespace or junk.
    //
    // fr previously called `.trim()` on the whole input, which
    // accepted both leading whitespace before `(` and trailing
    // whitespace anywhere, and called `parse::<f64>` on `""` for
    // bare `(` which rejected the value upstream silently coerces
    // to 0. The wording stays "ERR min or max is not a float"
    // (upstream uczv).
    let bad = || CommandError::Custom("ERR min or max is not a float".to_string());
    let text = std::str::from_utf8(arg).map_err(|_| bad())?;
    let (rest, exclusive) = match text.strip_prefix('(') {
        Some(rest) => (rest, true),
        None => (text, false),
    };
    // Mirror strtod's empty-string -> 0.0 branch.
    let val = if rest.is_empty() {
        0.0
    } else {
        // strtod skips leading whitespace then attempts to parse;
        // the eptr[0] != '\0' check rejects any trailing chars.
        // Rust's parse::<f64> doesn't skip whitespace, so do that
        // explicitly. parse::<f64> rejects trailing whitespace too,
        // which matches upstream.
        let after_ws = rest.trim_start();
        if after_ws.is_empty() {
            return Err(bad());
        }
        // strtod accepts C99 hex-float notation (`0x10`, `0X1A`,
        // `0x1.8p3`), but Rust's `f64::from_str` only parses decimal —
        // so a hex bound that upstream's zslParseRange accepts was
        // rejected here as "min or max is not a float" (and, for a
        // wrong-type key, masked the WRONGTYPE error redis returns
        // after a successful range parse). Mirror the score path
        // (`parse_f64_arg`) by trying the hex-float form first.
        // try_parse_hex_float rejects trailing junk (from_str_radix
        // fails), matching strtod's `eptr[0] != '\0'` check. nan/inf
        // are handled by the shared `is_nan` gate below (zslParseRange
        // rejects only nan, accepting overflow-to-inf like strtod).
        // (frankenredis-hexfloat range bounds)
        if let Some(hex) = try_parse_hex_float(after_ws) {
            hex
        } else {
            after_ws.parse::<f64>().map_err(|_| bad())?
        }
    };
    if val.is_nan() {
        return Err(bad());
    }
    if exclusive {
        Ok(ScoreBound::Exclusive(val))
    } else {
        Ok(ScoreBound::Inclusive(val))
    }
}

/// The numeric value of a score bound, ignoring inclusivity — mirrors
/// fr-store's `score_bound_value`, used only to detect an inverted range.
fn score_bound_f64(bound: ScoreBound) -> f64 {
    match bound {
        ScoreBound::Inclusive(v) | ScoreBound::Exclusive(v) => v,
    }
}

/// Upstream t_zset.c::genericZrangebyscoreCommand type-checks the key
/// (WRONGTYPE) BEFORE it discovers an inverted score range and returns empty.
/// fr's store range methods short-circuit `min > max` to an empty result
/// *before* the type check, so a BYSCORE query with `min > max` against a
/// wrong-type key returned an empty reply instead of WRONGTYPE
/// (frankenredis ZRANGEBYSCORE inverted-range type-order parity).
///
/// `lo`/`hi` are the bounds in the order passed to the store method (already
/// swapped for REV). Returns:
/// - `Ok(false)` — range is not inverted; the normal path type-checks itself.
/// - `Ok(true)`  — inverted range on a zset or missing key; the caller should
///   emit its empty result WITHOUT calling the store (so exactly the single
///   keyspace lookup redis performs is recorded).
/// - `Err(WrongType)` — inverted range on a wrong-type key.
pub fn zscore_inverted_wrongtype_guard(
    store: &mut Store,
    key: &[u8],
    lo: ScoreBound,
    hi: ScoreBound,
    now_ms: u64,
) -> Result<bool, CommandError> {
    if score_bound_f64(lo) <= score_bound_f64(hi) {
        return Ok(false);
    }
    match store.key_type(key, now_ms) {
        None | Some("zset") => Ok(true),
        Some(_) => Err(CommandError::Store(fr_store::StoreError::WrongType)),
    }
}

fn setex(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // SETEX key seconds value
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("SETEX"));
    }
    let seconds = parse_expire_time_arg(&argv[2], "setex")?;
    // (br-frankenredis-setexrange) — reject when seconds*1000
    // would overflow LLONG_MAX, matching upstream
    // t_string.c::getExpireMillisecondsOrReply.
    if seconds > i64::MAX as u64 / 1000 {
        return Err(CommandError::Custom(
            "ERR invalid expire time in 'setex' command".to_string(),
        ));
    }
    let px = seconds.saturating_mul(1000);
    // (frankenredis-expbase) basetime overflow check.
    validate_relative_expire_basetime(px, now_ms, "setex")?;
    store.set(argv[1].clone(), argv[3].clone(), Some(px), now_ms);
    Ok(RespFrame::SimpleString("OK".to_string()))
}

