fn getrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("GETRANGE"));
    }
    let start = parse_i64_arg(&argv[2])?;
    let end = parse_i64_arg(&argv[3])?;
    // (frankenredis-getrangewt) No pre-lookup empty short-circuit: upstream
    // t_string.c::getrangeCommand does lookupKeyReadOrReply + checkType(STRING)
    // BEFORE deciding the range is empty, so a wrong-type key reports WRONGTYPE
    // even for an inverted range like `GETRANGE listk -1 -2`. Store::getrange
    // performs the type check then the identical resolve-clamp-`start>end`
    // emptiness logic, so the previous handler-level short-circuit was both
    // redundant and skipped the type check (returned "" instead of WRONGTYPE).
    let result = store.getrange(&argv[1], start, end, now_ms)?;
    Ok(RespFrame::BulkString(Some(result)))
}

/// SUBSTR is a deprecated alias for GETRANGE but upstream preserves
/// the command name in wrong-arity error replies. Forwarding through
/// `getrange` would leak "GETRANGE" into the error wording.
/// (br-frankenredis-68ql)
fn substr(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("SUBSTR"));
    }
    let start = parse_i64_arg(&argv[2])?;
    let end = parse_i64_arg(&argv[3])?;
    // (frankenredis-getrangewt) Type check precedes emptiness — see getrange.
    let result = store.getrange(&argv[1], start, end, now_ms)?;
    Ok(RespFrame::BulkString(Some(result)))
}

fn setrange(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("SETRANGE"));
    }
    let offset = parse_i64_arg(&argv[2])?;
    if offset < 0 {
        return Err(CommandError::Custom(
            "ERR offset is out of range".to_string(),
        ));
    }
    // (frankenredis-setrangeorder) Mirror upstream
    // t_string.c::setrangeCommand ordering:
    //   1. parse offset
    //   2. negative offset rejected
    //   3. lookupKeyWrite + checkType(OBJ_STRING) -> WRONGTYPE
    //   4. empty value short-circuit
    //   5. checkStringLength
    // fr previously fired the size check (step 5) before the type
    // check (step 3) for non-empty values, so a probe like
    // `LPUSH listk a; SETRANGE listk 600000000 v` returned the
    // size-limit error instead of WRONGTYPE.
    // SETRANGE is a write (lookupKeyWrite), so this precheck must use the
    // NON-counting peek — it must not bump keyspace_hits. (frankenredis-934ax)
    if let Some(t) = store.peek_value_type(&argv[1], now_ms)
        && t != fr_store::ValueType::String
    {
        return Err(CommandError::Store(StoreError::WrongType));
    }
    let offset_u64 = u64::try_from(offset).map_err(|_| CommandError::InvalidInteger)?;
    let added_len = argv[3].len();
    // (frankenredis-23ngn) Upstream t_string.c::setrangeCommand
    // short-circuits an EMPTY value BEFORE checkStringLength: a
    // missing key returns 0, an existing string returns its current
    // length, an existing non-string is WRONGTYPE. The size check
    // never runs in this path, so `SETRANGE k 600000000 ""` must
    // not surface 'string exceeds maximum allowed size'.
    if added_len == 0 {
        let cur = store.strlen(&argv[1], now_ms)?;
        return Ok(RespFrame::Integer(i64::try_from(cur).unwrap_or(i64::MAX)));
    }
    if offset_u64.saturating_add(added_len as u64) > store.proto_max_bulk_len as u64 {
        // Upstream reply: "string exceeds maximum allowed size
        // (proto-max-bulk-len)" (br-frankenredis-68ql).
        return Err(CommandError::Custom(
            "ERR string exceeds maximum allowed size (proto-max-bulk-len)".to_string(),
        ));
    }
    let offset_usize = usize::try_from(offset_u64).map_err(|_| CommandError::InvalidInteger)?;
    let new_len = store.setrange(&argv[1], offset_usize, &argv[3], now_ms)?;
    Ok(RespFrame::Integer(
        i64::try_from(new_len).unwrap_or(i64::MAX),
    ))
}

fn incrbyfloat(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("INCRBYFLOAT"));
    }
    // (frankenredis-incrbyfloatorder) Mirror upstream
    // t_string.c::incrbyfloatCommand ordering:
    //   1. lookupKeyWrite + checkType(OBJ_STRING)  -> WRONGTYPE
    //   2. getLongDoubleFromObjectOrReply(current value)
    //   3. getLongDoubleFromObjectOrReply(incr/argv[2])
    //   4. add + NaN/Inf check
    // fr previously parsed the delta first, leaking
    // "value is not a valid float" on a wrong-type key when the
    // delta was unparseable (probe: INCRBYFLOAT <list-key> abc).
    // INCRBYFLOAT is a write (lookupKeyWrite), so this precheck must use the
    // NON-counting peek — it must not bump keyspace_hits. (frankenredis-934ax)
    if let Some(t) = store.peek_value_type(&argv[1], now_ms)
        && t != fr_store::ValueType::String
    {
        return Err(CommandError::Store(StoreError::WrongType));
    }
    // Accept the full x87 80-bit long double decimal range (e.g. "1e500"), which
    // overflows f64 to inf and so is rejected by parse_f64_arg even though
    // redis's strtold/INCRBYFLOAT accepts it. The f64 value is only used by the
    // legacy f64 fallback; the faithful f80 path uses the original text, so a
    // finite placeholder is fine here. (frankenredis f80 decimal range)
    let delta = match parse_f64_arg(&argv[2]) {
        Ok(v) => v,
        Err(_) if fr_store::long_double_text_is_valid(&argv[2]) => 0.0,
        Err(e) => return Err(e),
    };
    let new_val = store.incrbyfloat_text(&argv[1], &argv[2], delta, now_ms)?;
    Ok(RespFrame::BulkString(Some(new_val)))
}

/// (frankenredis-6f2f5) Record one keyspace hit/miss per SOURCE key, matching
/// upstream's lookupKeyRead-per-key accounting. The Store sinter/sunion/sdiff/
/// zunionstore/zinterstore/zmscore read methods touch their input keys (LFU/LRU)
/// but never bump the keyspace_hits/misses counters, so these handlers under-
/// counted (recorded 0 where redis records numkeys). `exists_no_touch` records
/// the hit/miss without an LFU touch (the store method's own touch stays single)
/// and without firing keyspace events. Call BEFORE the store computation so a
/// later WRONGTYPE/empty result still records the lookups, as upstream does.
/// Destination keys of the *STORE variants are writes and are NOT counted here.
pub fn record_source_key_lookups(store: &mut Store, keys: &[&[u8]], now_ms: u64) {
    for &key in keys {
        let _ = store.exists_no_touch(key, now_ms);
    }
}

fn sinter(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SINTER"));
    }
    let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
    let keys: Vec<&[u8]> = argv[1..].iter().map(Vec::as_slice).collect();
    record_source_key_lookups(store, &keys, now_ms);
    let members = store.sinter(&keys, now_ms)?;
    let frames = members
        .into_iter()
        .map(|m| RespFrame::BulkString(Some(m)))
        .collect();
    if resp3 {
        Ok(RespFrame::Set(Some(frames)))
    } else {
        Ok(RespFrame::Array(Some(frames)))
    }
}

