fn spop(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SPOP"));
    }
    // Upstream commands.def declares SPOP with arity = -2 and
    // t_set.c::spopCommand:974-977 emits `addReplyErrorObject(
    // c, shared.syntaxerr)` when argc > 3. fr previously rejected
    // those calls with the table-level
    // 'wrong number of arguments for spop command' wording.
    // (frankenredis-spopary)
    if argv.len() > 3 {
        return Err(CommandError::SyntaxError);
    }
    if argv.len() == 3 {
        // Upstream t_set.c::spopCommand uses the
        // 'value is out of range, must be positive' error for
        // both unparseable and negative counts.
        // (br-frankenredis-spopary)
        let bad =
            || CommandError::Custom("ERR value is out of range, must be positive".to_string());
        let parsed = parse_i64_arg(&argv[2]).map_err(|_| bad())?;
        if parsed < 0 {
            return Err(bad());
        }
        let count = usize::try_from(parsed).map_err(|_| bad())?;
        // (frankenredis-cf9z1) Upstream t_set.c::spopWithCountCommand
        // validates the key type via checkType() BEFORE the count==0
        // short-circuit. fr's spop_count loops `for _ in 0..count`
        // which skips the type check when count==0 and returns an
        // empty array, masking WRONGTYPE. Fire the type check here
        // so a wrongtype key with count==0 reports the same error.
        // SPOP is a write (lookupKeyWrite), so use the NON-counting
        // peek — this precheck must not bump keyspace_hits. (frankenredis-934ax)
        match store.peek_value_type(&argv[1], now_ms) {
            Some(fr_store::ValueType::Set) | None => {}
            Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
        }
        // (frankenredis-934ax) Upstream spopWithCountCommand routes the
        // whole-set-removal branch (count >= cardinality) through a SUNION-style
        // READ that bumps exactly one keyspace_hit, whereas the partial branch
        // uses lookupKeyWrite (no count). Mirror that single hit here; the
        // peek/scard reads above are non-counting so this is the only count.
        if count > 0
            && let Some(card) = store.set_cardinality_no_stats(&argv[1], now_ms)
            && count >= card
        {
            let _ = store.exists_no_touch(&argv[1], now_ms);
        }
        let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
        let members = store.spop_count(&argv[1], count, now_ms)?;
        let arr = members
            .into_iter()
            .map(|m| RespFrame::BulkString(Some(m)))
            .collect();
        if resp3 {
            return Ok(RespFrame::Set(Some(arr)));
        } else {
            return Ok(RespFrame::Array(Some(arr)));
        }
    }
    match store.spop(&argv[1], now_ms)? {
        Some(m) => Ok(RespFrame::BulkString(Some(m))),
        None => Ok(RespFrame::BulkString(None)),
    }
}

fn srandmember(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // Upstream commands.def declares SRANDMEMBER with arity = -2,
    // so any extra trailing args land in srandmemberCommand's
    // syntaxerr branch rather than the table-level arity check.
    // (br-frankenredis-randextra)
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("SRANDMEMBER"));
    }
    if argv.len() > 3 {
        return Err(CommandError::SyntaxError);
    }
    if argv.len() == 2 {
        // No count: return single element or nil
        match store.srandmember(&argv[1], now_ms)? {
            Some(m) => Ok(RespFrame::BulkString(Some(m))),
            None => Ok(RespFrame::BulkString(None)),
        }
    } else {
        // With count: return array. (frankenredis-wsqf2) Range-check
        // matches upstream getRangeLongFromObjectOrReply call so that
        // i64::MIN cannot trigger a 9.2-quintillion-iteration DoS.
        let count = parse_i64_arg_long_range(&argv[2])?;
        let members = store.srandmember_count(&argv[1], count, now_ms)?;
        let arr: Vec<RespFrame> = members
            .into_iter()
            .map(|m| RespFrame::BulkString(Some(m)))
            .collect();
        Ok(RespFrame::Array(Some(arr)))
    }
}

