fn zrandmember(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // ZRANDMEMBER key [count [WITHSCORES]]
    // Upstream commands.def declares ZRANDMEMBER with arity = -2,
    // so any extra trailing args after WITHSCORES land in
    // zrandmemberCommand's syntaxerr branch, not the table-level
    // arity check. (br-frankenredis-randextra)
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("ZRANDMEMBER"));
    }
    if argv.len() > 4 {
        return Err(CommandError::SyntaxError);
    }
    if argv.len() == 2 {
        // No count: return single element or nil. store.zrandmember is no-stat,
        // so record the keyspace lookup here (upstream lookupKeyReadOrReply).
        record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
        return match store.zrandmember(&argv[1], now_ms)? {
            Some(m) => Ok(RespFrame::BulkString(Some(m))),
            None => Ok(RespFrame::BulkString(None)),
        };
    }
    // (frankenredis-wsqf2) Reject i64::MIN to prevent the
    // ~9.2-quintillion-iteration DoS in zrandmember_count's
    // negative-count path.
    let count = parse_i64_arg_long_range(&argv[2])?;
    let withscores = argv.len() == 4
        && std::str::from_utf8(&argv[3]).is_ok_and(|s| s.eq_ignore_ascii_case("WITHSCORES"));
    // (frankenredis-sntxr) WITHSCORES emits 2 elements per row, so
    // upstream tightens the count range to [-LONG_MAX/2, LONG_MAX/2].
    if withscores {
        require_count_fits_half_long_range(count)?;
    }
    if argv.len() == 4 && !withscores {
        return Err(CommandError::SyntaxError);
    }
    // store.zrandmember_count is no-stat; record the single keyspace lookup
    // (placed after all syntax/count validation, matching upstream order).
    record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
    let pairs = store.zrandmember_count(&argv[1], count, now_ms)?;
    // (frankenredis-jnf53) Mirror ZRANGE WITHSCORES wire shape: under
    // RESP3 wrap each (member, score) in a 2-element Array; under RESP2
    // emit flat alternating.
    zrange_emit_with_resp(
        pairs,
        withscores,
        store.dispatch_client_ctx.resp_protocol_version,
    )
}

fn zmscore(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("ZMSCORE"));
    }
    let resp3 = store.dispatch_client_ctx.resp_protocol_version == 3;
    let members: Vec<&[u8]> = argv[2..].iter().map(|a| a.as_slice()).collect();
    record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
    let scores = store.zmscore(&argv[1], &members, now_ms)?;
    let frames = scores
        .into_iter()
        .map(|s| match s {
            Some(score) => {
                if resp3 {
                    RespFrame::double_from_f64(score)
                } else {
                    RespFrame::BulkString(Some(redis_score_to_string(score).into_bytes()))
                }
            }
            None => RespFrame::BulkString(None),
        })
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn setbit(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("SETBIT"));
    }
    let offset = parse_i64_arg(&argv[2]).map_err(|_| {
        CommandError::Custom("ERR bit offset is not an integer or out of range".to_string())
    })?;
    if !(0..4_294_967_296).contains(&offset) {
        return Err(CommandError::Custom(
            "ERR bit offset is not an integer or out of range".to_string(),
        ));
    }
    let bit_val = parse_i64_arg(&argv[3]).map_err(|_| {
        CommandError::Custom("ERR bit is not an integer or out of range".to_string())
    })?;
    if bit_val != 0 && bit_val != 1 {
        return Err(CommandError::Custom(
            "ERR bit is not an integer or out of range".to_string(),
        ));
    }
    let old = store.setbit(&argv[1], offset as usize, bit_val == 1, now_ms)?;
    Ok(RespFrame::Integer(if old { 1 } else { 0 }))
}

fn getbit(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("GETBIT"));
    }
    let offset = parse_bit_offset_or_reply(&argv[2])?;
    let bit = store.getbit(&argv[1], offset as usize, now_ms)?;
    Ok(RespFrame::Integer(if bit { 1 } else { 0 }))
}

/// Mirror upstream bitops.c::getBitOffsetFromArgument: a bit offset
/// must parse as a non-negative i64 AND `offset >> 3` must stay
/// below proto_max_bulk_len (default 512MB → bits < 4 GiB).
/// (br-frankenredis-bitoff)
fn parse_bit_offset_or_reply(arg: &[u8]) -> Result<i64, CommandError> {
    let err =
        || CommandError::Custom("ERR bit offset is not an integer or out of range".to_string());
    let offset = parse_i64_arg(arg).map_err(|_| err())?;
    // Upstream's default proto_max_bulk_len is 512 * 1024 * 1024 bytes.
    // The check is `(loffset >> 3) >= server.proto_max_bulk_len`, i.e.
    // bit-offsets >= 512 MiB << 3 = 2^32 are rejected.
    const MAX_BIT_OFFSET_EXCLUSIVE: i64 = 512 * 1024 * 1024 * 8;
    if !(0..MAX_BIT_OFFSET_EXCLUSIVE).contains(&offset) {
        return Err(err());
    }
    Ok(offset)
}

fn bitcount(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Upstream bitcountCommand (bitops.c lines 805-854) short-circuits
    // to Integer(0) when the key doesn't exist — BEFORE argv-shape
    // validation — so a nonexistent key with too many args returns 0
    // instead of a syntax error. (br-frankenredis-ugkf)
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("BITCOUNT"));
    }
    // (frankenredis-oss8i) Match upstream's precedence: lookup +
    // WRONGTYPE check happen BEFORE any argv parsing. Otherwise
    // `BITCOUNT listkey BAD BAD BADUNIT` returns SyntaxError instead
    // of WRONGTYPE.
    match store.key_type(&argv[1], now_ms) {
        None => return Ok(RespFrame::Integer(0)),
        Some("string") => {}
        Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
    }
    let (start, end, unit) = match argv.len() {
        2 => (None, None, BitRangeUnit::Byte),
        4 => (
            Some(parse_i64_arg(&argv[2])?),
            Some(parse_i64_arg(&argv[3])?),
            BitRangeUnit::Byte,
        ),
        5 => {
            // (frankenredis-oss8i) Upstream parses start/end BEFORE
            // checking the BIT|BYTE modifier (bitops.c lines 815-830),
            // so a malformed integer takes precedence over a bad unit.
            let start = parse_i64_arg(&argv[2])?;
            let end = parse_i64_arg(&argv[3])?;
            // (frankenredis-bitcountnegunit) Upstream's fully-negative
            // reversed-range early-return `if (start<0 && end<0 && start>end)
            // { addReply(czero); return; }` runs BEFORE the BYTE|BIT unit
            // check, so e.g. `BITCOUNT k -1 -2 BAD` is 0, not a syntax error.
            // fr validated the unit first, surfacing the syntax error instead.
            if start < 0 && end < 0 && start > end {
                return Ok(RespFrame::Integer(0));
            }
            let unit = if argv[4].eq_ignore_ascii_case(b"bit") {
                BitRangeUnit::Bit
            } else if argv[4].eq_ignore_ascii_case(b"byte") {
                BitRangeUnit::Byte
            } else {
                return Err(CommandError::SyntaxError);
            };
            (Some(start), Some(end), unit)
        }
        _ => return Err(CommandError::SyntaxError),
    };
    let count = store.bitcount(&argv[1], start, end, unit, now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)))
}

fn bitpos(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Upstream t_string.c::bitposCommand:
    //   BITPOS key bit [start [end [BYTE | BIT]]]
    // The trailing BYTE|BIT modifier (Redis 7.0+) is only legal when
    // BOTH start AND end are supplied; the parser dispatches strictly
    // on argc:
    //   argc == 3 → no range
    //   argc == 4 → start only
    //   argc == 5 → start + end (BYTE semantics)
    //   argc == 6 → start + end + BIT|BYTE modifier
    //   anything else → syntax error
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("BITPOS"));
    }
    let bit_val = parse_i64_arg(&argv[2])?;
    if bit_val != 0 && bit_val != 1 {
        return Err(CommandError::Custom(
            "ERR The bit argument must be 1 or 0.".to_string(),
        ));
    }
    // Upstream t_string.c::bitposCommand looks up the key BEFORE
    // parsing trailing args — a missing key short-circuits to
    // (bit ? -1 : 0). So 'BITPOS nokey 1 0 -1 NOSUCH' returns -1
    // even though NOSUCH would be a syntax error if the key
    // existed. (br-frankenredis-bitposkey)
    match store.key_type(&argv[1], now_ms) {
        None => return Ok(RespFrame::Integer(if bit_val == 1 { -1 } else { 0 })),
        Some("string") => {}
        Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
    }
    if argv.len() > 6 {
        return Err(CommandError::SyntaxError);
    }
    // (frankenredis-abpzk) Mirror upstream bitops.c lines 905-927:
    // start parses first, then for argc==6 the BIT|BYTE modifier
    // is validated, THEN end parses. Inverting end and unit caused
    // `BITPOS key 1 0 NOTANINT BADUNIT` to surface a parse error
    // instead of upstream's syntax error on the bad modifier.
    let start = if argv.len() >= 4 {
        Some(parse_i64_arg(&argv[3])?)
    } else {
        None
    };
    let unit = if argv.len() == 6 {
        if argv[5].eq_ignore_ascii_case(b"bit") {
            BitRangeUnit::Bit
        } else if argv[5].eq_ignore_ascii_case(b"byte") {
            BitRangeUnit::Byte
        } else {
            return Err(CommandError::SyntaxError);
        }
    } else {
        BitRangeUnit::Byte
    };
    let end = if argv.len() >= 5 {
        Some(parse_i64_arg(&argv[4])?)
    } else {
        None
    };
    let pos = store.bitpos(&argv[1], bit_val == 1, start, end, unit, now_ms)?;
    Ok(RespFrame::Integer(pos))
}

fn lpos(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // LPOS key element [RANK rank] [COUNT count] [MAXLEN maxlen]
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("LPOS"));
    }
    let mut rank: i64 = 1;
    let mut count: Option<u64> = None;
    let mut maxlen: usize = 0;
    let mut i = 3;
    while i < argv.len() {
        let opt = &argv[i]; // (frankenredis-44iva) byte-match: non-UTF8 -> syntax error
        if opt.eq_ignore_ascii_case(b"RANK") {
            i += 1;
            if i >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // (frankenredis-xiome) Upstream lposCommand uses
            // getRangeLongFromObjectOrReply(c, argv, -LONG_MAX, LONG_MAX,
            // &rank, NULL) which rejects only i64::MIN. fr was accepting
            // it and silently returning an empty array (skip overflow
            // never matches anything).
            rank = parse_i64_arg_long_range(&argv[i])?;
            if rank == 0 {
                return Err(CommandError::Custom(
                    "ERR RANK can't be zero: use 1 to start from the first match, 2 from the second ... or use negative to start from the end of the list"
                        .to_string(),
                ));
            }
        } else if opt.eq_ignore_ascii_case(b"COUNT") {
            i += 1;
            if i >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream t_list.c::lposCommand uses
            // getPositiveLongFromObjectOrReply with the
            // "COUNT can't be negative" error for both unparseable
            // integers and explicit-negative values.
            // (br-frankenredis-lposcount)
            let bad = || CommandError::Custom("ERR COUNT can't be negative".to_string());
            let c = parse_i64_arg(&argv[i]).map_err(|_| bad())?;
            if c < 0 {
                return Err(bad());
            }
            count = Some(c as u64);
        } else if opt.eq_ignore_ascii_case(b"MAXLEN") {
            i += 1;
            if i >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream t_list.c::lposCommand uses the
            // 'MAXLEN can't be negative' error for both unparseable
            // integers and explicit-negative values.
            // (br-frankenredis-lposmaxlen)
            let bad = || CommandError::Custom("ERR MAXLEN can't be negative".to_string());
            let m = parse_i64_arg(&argv[i]).map_err(|_| bad())?;
            if m < 0 {
                return Err(bad());
            }
            maxlen = usize::try_from(m).map_err(|_| bad())?;
        } else {
            return Err(CommandError::SyntaxError);
        }
        i += 1;
    }

    let positions = store.lpos_full(&argv[1], &argv[2], rank, count, maxlen, now_ms)?;

    if count.is_some() {
        // COUNT mode: always return array
        let arr: Vec<RespFrame> = positions
            .into_iter()
            .map(|p| RespFrame::Integer(i64::try_from(p).unwrap_or(i64::MAX)))
            .collect();
        Ok(RespFrame::Array(Some(arr)))
    } else {
        // No COUNT: return single integer or nil
        match positions.first() {
            Some(&pos) => Ok(RespFrame::Integer(i64::try_from(pos).unwrap_or(i64::MAX))),
            None => Ok(RespFrame::BulkString(None)),
        }
    }
}

fn linsert(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // LINSERT key BEFORE|AFTER pivot element
    if argv.len() != 5 {
        return Err(CommandError::WrongArity("LINSERT"));
    }
    // (frankenredis-re7sp) byte-match BEFORE/AFTER; non-UTF8 -> syntax error (else)
    let direction = &argv[2];
    if direction.eq_ignore_ascii_case(b"BEFORE") {
        let len = store.linsert_before(&argv[1], &argv[3], argv[4].clone(), now_ms)?;
        Ok(RespFrame::Integer(len))
    } else if direction.eq_ignore_ascii_case(b"AFTER") {
        let len = store.linsert_after(&argv[1], &argv[3], argv[4].clone(), now_ms)?;
        Ok(RespFrame::Integer(len))
    } else {
        Err(CommandError::SyntaxError)
    }
}

fn lrem(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("LREM"));
    }
    let count = parse_i64_arg(&argv[2])?;
    let removed = store.lrem(&argv[1], count, &argv[3], now_ms)?;
    Ok(RespFrame::Integer(
        i64::try_from(removed).unwrap_or(i64::MAX),
    ))
}

fn rpoplpush(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("RPOPLPUSH"));
    }
    match store.rpoplpush(&argv[1], &argv[2], now_ms)? {
        Some(v) => Ok(RespFrame::BulkString(Some(v))),
        None => Ok(RespFrame::BulkString(None)),
    }
}

fn hincrbyfloat(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("HINCRBYFLOAT"));
    }
    // Accept the full f80 decimal range (e.g. "1e500"); see incrbyfloat.
    // A finite placeholder keeps the NaN/Infinity gate below from misfiring on
    // an f80-range value that merely overflows f64. (frankenredis f80 decimal range)
    let delta = match parse_f64_arg(&argv[3]) {
        Ok(v) => v,
        Err(_) if fr_store::long_double_text_is_valid(&argv[3]) => 0.0,
        Err(e) => return Err(e),
    };
    // Upstream t_hash.c::hincrbyfloatCommand validates the increment
    // for NaN/Infinity BEFORE looking up the key, so a probe like
    // 'HINCRBYFLOAT wrong-type-key f inf' reports 'value is NaN or
    // Infinity' rather than WRONGTYPE. (br-frankenredis-hincrnaninf)
    if delta.is_nan() || delta.is_infinite() {
        return Err(CommandError::Custom(
            "ERR value is NaN or Infinity".to_string(),
        ));
    }
    let new_val = store
        .hincrbyfloat_text(&argv[1], &argv[2], &argv[3], delta, now_ms)
        .map_err(|err| match err {
            StoreError::IncrFloatNaN => {
                CommandError::Custom("ERR value is NaN or Infinity".to_string())
            }
            // Upstream t_hash.c::hincrbyfloatCommand uses
            // 'hash value is not a float' (not the generic 'value
            // is not a valid float') when the existing field can't
            // be parsed as a float. (br-frankenredis-hincrfloat)
            StoreError::ValueNotFloat => {
                CommandError::Custom("ERR hash value is not a float".to_string())
            }
            other => CommandError::Store(other),
        })?;
    Ok(RespFrame::BulkString(Some(new_val)))
}

fn hrandfield(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // HRANDFIELD key [count [WITHVALUES]]
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("HRANDFIELD"));
    }
    if argv.len() > 4 {
        return Err(CommandError::SyntaxError);
    }
    if argv.len() == 2 {
        // No count: return single field or nil. store.hrandfield is no-stat,
        // so record the keyspace lookup here (upstream lookupKeyReadOrReply).
        record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
        return match store.hrandfield(&argv[1], now_ms)? {
            Some(field) => Ok(RespFrame::BulkString(Some(field))),
            None => Ok(RespFrame::BulkString(None)),
        };
    }
    // (frankenredis-wsqf2) Reject i64::MIN to prevent the
    // ~9.2-quintillion-iteration DoS in hrandfield_count's negative-count path.
    let count = parse_i64_arg_long_range(&argv[2])?;
    let withvalues = argv.len() == 4
        && std::str::from_utf8(&argv[3]).is_ok_and(|s| s.eq_ignore_ascii_case("WITHVALUES"));
    // (frankenredis-sntxr) WITHVALUES emits 2 elements per row, so
    // upstream tightens the count range to [-LONG_MAX/2, LONG_MAX/2].
    if withvalues {
        require_count_fits_half_long_range(count)?;
    }
    if argv.len() == 4 && !withvalues {
        return Err(CommandError::SyntaxError);
    }
    // store.hrandfield_count is no-stat; record the single keyspace lookup
    // (placed after all syntax/count validation, matching upstream order).
    record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
    let pairs = store.hrandfield_count(&argv[1], count, now_ms)?;
    if withvalues {
        // Upstream t_hash.c::hrandfieldWithCountCommand uses
        // addReplyArrayLen(2) per pair when in RESP3 mode (array of
        // [field, value] sub-arrays) but emits flat alternating k/v
        // when in RESP2. Match both shapes. (br-frankenredis-f6z6)
        if store.dispatch_client_ctx.resp_protocol_version == 3 {
            let frames = pairs
                .into_iter()
                .map(|(field, value)| {
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(field)),
                        RespFrame::BulkString(Some(value)),
                    ]))
                })
                .collect();
            Ok(RespFrame::Array(Some(frames)))
        } else {
            let mut frames = Vec::with_capacity(pairs.len() * 2);
            for (field, value) in pairs {
                frames.push(RespFrame::BulkString(Some(field)));
                frames.push(RespFrame::BulkString(Some(value)));
            }
            Ok(RespFrame::Array(Some(frames)))
        }
    } else {
        let frames = pairs
            .into_iter()
            .map(|(f, _)| RespFrame::BulkString(Some(f)))
            .collect();
        Ok(RespFrame::Array(Some(frames)))
    }
}

fn zrevrangebyscore(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // ZREVRANGEBYSCORE key max min [WITHSCORES] [LIMIT offset count]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZREVRANGEBYSCORE"));
    }
    // (frankenredis-e5mya) Options before bounds; see zrangebyscore().
    let (withscores, limit_offset, limit_count) = parse_zrangebyscore_opts(argv, 4)?;
    let max = parse_score_bound(&argv[2])?;
    let min = parse_score_bound(&argv[3])?;
    if zscore_inverted_wrongtype_guard(store, &argv[1], min, max, now_ms)? {
        return Ok(RespFrame::Array(Some(Vec::new())));
    }
    // REV + LIMIT pushed into the range walk — O(offset+count), not O(range).
    let pairs = store.zrangebyscore_withscores_limited(
        &argv[1],
        min,
        max,
        true,
        limit_offset.unwrap_or(0),
        limit_count,
        now_ms,
    )?;
    zrange_emit_with_resp(
        pairs,
        withscores,
        store.dispatch_client_ctx.resp_protocol_version,
    )
}

fn zrangebylex(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // ZRANGEBYLEX key min max [LIMIT offset count]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZRANGEBYLEX"));
    }
    // (frankenredis-zlexws / frankenredis-e5mya) Upstream
    // t_zset.c::genericZrangebyscoreCommand guards
    // `if (withscores && zlex)` and emits the WITHSCORES-not-supported
    // wording. fr was reusing parse_zrangebyscore_opts (which silently
    // accepts WITHSCORES) and discarding the flag, so a stray
    // WITHSCORES on ZRANGEBYLEX returned the elements without scores
    // instead of erroring. The newer ZRANGE BYLEX path already
    // rejects this case correctly; the regression was scoped to the
    // legacy ZRANGEBYLEX / ZREVRANGEBYLEX commands. Options must also
    // parse *before* validate_lex_bound so a misplaced LIMIT/option
    // at the bound position surfaces "syntax error" rather than the
    // bound-format wording (e5mya).
    let (withscores, limit_offset, limit_count) = parse_zrangebyscore_opts(argv, 4)?;
    validate_lex_bound(&argv[2])?;
    validate_lex_bound(&argv[3])?;
    if withscores {
        return Err(CommandError::Custom(
            "ERR syntax error, WITHSCORES not supported in combination with BYLEX".to_string(),
        ));
    }
    // (frankenredis keyspace-acct) Legacy ZRANGEBYLEX must record the keyspace
    // hit/miss like upstream's lookupKeyReadOrReply (zrangebylex_limited is
    // no-stat; the unified ZRANGE BYLEX path records separately).
    record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
    // LIMIT pushed into the lex walk — O(offset+count). (frankenredis-qchm7)
    let members = store.zrangebylex_limited(
        &argv[1],
        &argv[2],
        &argv[3],
        false,
        limit_offset.unwrap_or(0),
        limit_count,
        now_ms,
    )?;
    let frames = members
        .into_iter()
        .map(|m| RespFrame::BulkString(Some(m)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn zrevrangebylex(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    // ZREVRANGEBYLEX key max min [LIMIT offset count]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZREVRANGEBYLEX"));
    }
    // (frankenredis-zlexws / frankenredis-e5mya) See zrangebylex().
    let (withscores, limit_offset, limit_count) = parse_zrangebyscore_opts(argv, 4)?;
    validate_lex_bound(&argv[2])?;
    validate_lex_bound(&argv[3])?;
    if withscores {
        return Err(CommandError::Custom(
            "ERR syntax error, WITHSCORES not supported in combination with BYLEX".to_string(),
        ));
    }
    // (frankenredis keyspace-acct) Record the keyspace hit/miss like upstream.
    record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
    // REV + LIMIT pushed into the lex walk: zrevrangebylex(key, max, min) is
    // zrangebylex_limited(key, min, max, rev=true). (frankenredis-qchm7)
    let members = store.zrangebylex_limited(
        &argv[1],
        &argv[3],
        &argv[2],
        true,
        limit_offset.unwrap_or(0),
        limit_count,
        now_ms,
    )?;
    let frames = members
        .into_iter()
        .map(|m| RespFrame::BulkString(Some(m)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn zlexcount(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() != 4 {
        return Err(CommandError::WrongArity("ZLEXCOUNT"));
    }
    validate_lex_bound(&argv[2])?;
    validate_lex_bound(&argv[3])?;
    // (frankenredis keyspace-acct) Record the keyspace hit/miss like upstream's
    // lookupKeyReadOrReply; store.zlexcount is no-stat (same lex-range class as
    // the ZRANGEBYLEX fix).
    record_source_key_lookups(store, &[argv[1].as_slice()], now_ms);
    let count = store.zlexcount(&argv[1], &argv[2], &argv[3], now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)))
}

/// Mirror upstream Redis 7.2 t_zset.c::zslParseLexRangeItem: lex
/// bounds must start with '[' (inclusive), '(' (exclusive), or be
/// exactly '-' (min) or '+' (max). Plain strings are rejected with
/// "ERR min or max not valid string range item". (br-frankenredis-moer)
/// `pub` so the ZLEXCOUNT borrowed fast path validates bounds identically (cc).
pub fn validate_lex_bound(arg: &[u8]) -> Result<(), CommandError> {
    let valid = arg == b"-" || arg == b"+" || arg.first().is_some_and(|c| *c == b'[' || *c == b'(');
    if valid {
        Ok(())
    } else {
        Err(CommandError::Custom(
            "ERR min or max not valid string range item".to_string(),
        ))
    }
}

// ── HyperLogLog command handlers ──────────────────────────────────────

fn pfadd(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("PFADD"));
    }
    let elements: Vec<Vec<u8>> = argv[2..].to_vec();
    let modified = store.pfadd(&argv[1], &elements, now_ms)?;
    Ok(RespFrame::Integer(i64::from(modified)))
}

fn pfcount(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("PFCOUNT"));
    }
    let keys: Vec<&[u8]> = argv[1..].iter().map(|k| k.as_slice()).collect();
    // (frankenredis keyspace-acct) Upstream hyperloglog.c::pfcountCommand does
    // lookupKeyRead per source key, bumping keyspace_hits/misses; store.pfcount
    // is no-stat, so record the per-key lookups here to match.
    record_source_key_lookups(store, &keys, now_ms);
    let count = store.pfcount(&keys, now_ms)?;
    Ok(RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)))
}

fn pfmerge(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("PFMERGE"));
    }
    // Upstream pfmergeCommand does a lookupKeyRead over EVERY key arg — the
    // destination AND each source (it reads them all to merge, then writes the
    // dest) — so each records a keyspace hit/miss. store.pfmerge is no-stat;
    // record one lookup per key arg (dest first, then sources) before merging.
    let all_keys: Vec<&[u8]> = argv[1..].iter().map(|k| k.as_slice()).collect();
    record_source_key_lookups(store, &all_keys, now_ms);
    let sources: Vec<&[u8]> = argv[2..].iter().map(|k| k.as_slice()).collect();
    store.pfmerge(&argv[1], &sources, now_ms)?;
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn pfdebug_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() != 3 {
        return Err(CommandError::WrongArity("PFDEBUG"));
    }

    let missing = || CommandError::Custom("ERR The specified key does not exist".to_string());

    if argv[1].eq_ignore_ascii_case(b"GETREG") {
        let Some(registers) = store.hll_debug_getreg(&argv[2], now_ms)? else {
            return Err(missing());
        };
        return Ok(RespFrame::Array(Some(
            registers
                .into_iter()
                .map(|value| RespFrame::Integer(i64::from(value)))
                .collect(),
        )));
    }

    if argv[1].eq_ignore_ascii_case(b"DECODE") {
        let Some(decoded) = store.hll_debug_decode(&argv[2], now_ms)? else {
            return Err(missing());
        };
        return Ok(RespFrame::BulkString(Some(decoded.into_bytes())));
    }

    if argv[1].eq_ignore_ascii_case(b"ENCODING") {
        let Some(encoding) = store.hll_debug_encoding(&argv[2], now_ms)? else {
            return Err(missing());
        };
        return Ok(RespFrame::SimpleString(encoding.to_string()));
    }

    if argv[1].eq_ignore_ascii_case(b"TODENSE") {
        let Some(converted) = store.hll_debug_todense(&argv[2], now_ms)? else {
            return Err(missing());
        };
        return Ok(RespFrame::Integer(i64::from(converted)));
    }

    match store.hll_debug_validate(&argv[2], now_ms)? {
        Some(()) => Err(CommandError::Custom(format!(
            "ERR Unknown PFDEBUG subcommand '{}'",
            bytes_to_lossy_string(&argv[1])
        ))),
        None => Err(missing()),
    }
}

fn pfselftest_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("PFSELFTEST"));
    }
    store.hll_selftest()?;
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn monitor_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    if argv.len() != 1 {
        return Err(CommandError::WrongArity("MONITOR"));
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    // MONITOR returns OK immediately. The runtime/server handles the actual
    // streaming of commands to monitor clients. The client is flagged as a
    // monitor in the server event loop after this response is sent.
    Ok(RespFrame::SimpleString("OK".to_string()))
}

pub fn parse_migrate_request(argv: &[Vec<u8>]) -> Result<MigrateRequest, CommandError> {
    if argv.len() < 6 {
        return Err(CommandError::WrongArity("MIGRATE"));
    }

    let host = std::str::from_utf8(&argv[1])
        .map_err(|_| CommandError::InvalidUtf8Argument)?
        .to_string();
    let key_arg = &argv[3];
    // Upstream cluster.c::migrateCommand parses dbid/timeout via
    // atoi (silent on parse failure, default 0) and runs the option
    // loop AFTER. Pre-scan for unknown trailing tokens so that
    // 'MIGRATE h p k bad-db bad-timeout extra' reports the option
    // syntax error before falling foul of a stricter integer parser.
    // (br-frankenredis-migratesyntax)
    {
        let mut j = 6;
        while j < argv.len() {
            let opt =
                std::str::from_utf8(&argv[j]).map_err(|_| CommandError::InvalidUtf8Argument)?;
            if opt.eq_ignore_ascii_case("COPY") || opt.eq_ignore_ascii_case("REPLACE") {
                j += 1;
            } else if opt.eq_ignore_ascii_case("AUTH") {
                if j + 1 >= argv.len() {
                    return Err(CommandError::SyntaxError);
                }
                j += 2;
            } else if opt.eq_ignore_ascii_case("AUTH2") {
                if j + 2 >= argv.len() {
                    return Err(CommandError::SyntaxError);
                }
                j += 3;
            } else if opt.eq_ignore_ascii_case("KEYS") {
                // KEYS consumes the remaining tokens.
                break;
            } else {
                return Err(CommandError::SyntaxError);
            }
        }
    }
    let destination_db = parse_i64_arg(&argv[4])?;
    let timeout_ms = parse_i64_arg(&argv[5])?;
    let timeout = Duration::from_millis(if timeout_ms <= 0 {
        1000
    } else {
        timeout_ms as u64
    });

    let mut copy = false;
    let mut replace = false;
    let mut auth_password: Option<Vec<u8>> = None;
    let mut auth_username: Option<Vec<u8>> = None;
    let mut keys_mode = false;
    let mut extra_keys = Vec::new();

    let mut i = 6;
    while i < argv.len() {
        let arg = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if arg.eq_ignore_ascii_case("COPY") {
            copy = true;
            i += 1;
        } else if arg.eq_ignore_ascii_case("REPLACE") {
            replace = true;
            i += 1;
        } else if arg.eq_ignore_ascii_case("AUTH") {
            if i + 1 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            auth_password = Some(argv[i + 1].clone()); // ubs:ignore (user-supplied)
            i += 2;
        } else if arg.eq_ignore_ascii_case("AUTH2") {
            if i + 2 >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            auth_username = Some(argv[i + 1].clone());
            auth_password = Some(argv[i + 2].clone()); // ubs:ignore (user-supplied)
            i += 3;
        } else if arg.eq_ignore_ascii_case("KEYS") {
            keys_mode = true;
            i += 1;
            while i < argv.len() {
                extra_keys.push(argv[i].clone());
                i += 1;
            }
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    if keys_mode && !key_arg.is_empty() {
        return Err(CommandError::Custom(
            "ERR When using MIGRATE KEYS option, the key argument must be set to the empty string"
                .to_string(),
        ));
    }

    let mut keys = Vec::new();
    if keys_mode {
        keys = extra_keys;
    } else if !key_arg.is_empty() {
        keys.push(key_arg.clone());
    }

    Ok(MigrateRequest {
        host,
        port_arg: argv[2].clone(),
        destination_db,
        timeout,
        copy,
        replace,
        auth_username,
        auth_password,
        keys,
    })
}

fn migrate_build_command(parts: &[&[u8]]) -> RespFrame {
    RespFrame::Array(Some(
        parts
            .iter()
            .map(|part| RespFrame::BulkString(Some((*part).to_vec())))
            .collect(),
    ))
}

fn migrate_write_frame(stream: &mut TcpStream, frame: RespFrame) -> Result<(), CommandError> {
    stream
        .write_all(&frame.to_bytes())
        .map_err(|_| migrate_ioerr("writing"))
}

fn migrate_read_frame(
    stream: &mut TcpStream,
    read_buf: &mut Vec<u8>,
) -> Result<RespFrame, CommandError> {
    let parser_config = fr_protocol::ParserConfig::default();
    loop {
        match fr_protocol::parse_frame_with_config(read_buf, &parser_config) {
            Ok(parsed) => {
                read_buf.drain(..parsed.consumed);
                return Ok(parsed.frame);
            }
            Err(fr_protocol::RespParseError::Incomplete) => {}
            Err(_) => return Err(migrate_ioerr("reading")),
        }

        let mut chunk = [0u8; 8192];
        match stream.read(&mut chunk) {
            Ok(0) => return Err(migrate_ioerr("reading")),
            Ok(n) => read_buf.extend_from_slice(&chunk[..n]),
            Err(ref err) if matches!(err.kind(), ErrorKind::WouldBlock | ErrorKind::TimedOut) => {
                return Err(migrate_ioerr("reading"));
            }
            Err(ref err) if err.kind() == ErrorKind::Interrupted => continue,
            Err(_) => return Err(migrate_ioerr("reading")),
        }
    }
}

fn migrate_port_from_redis_atoi(port_arg: &[u8]) -> Result<u16, CommandError> {
    let mut idx = 0;
    while port_arg
        .get(idx)
        .is_some_and(|byte| byte.is_ascii_whitespace())
    {
        idx += 1;
    }

    let negative = match port_arg.get(idx) {
        Some(b'-') => {
            idx += 1;
            true
        }
        Some(b'+') => {
            idx += 1;
            false
        }
        _ => false,
    };

    let mut saw_digit = false;
    let mut value = 0u64;
    while let Some(byte @ b'0'..=b'9') = port_arg.get(idx).copied() {
        saw_digit = true;
        value = value
            .saturating_mul(10)
            .saturating_add(u64::from(byte - b'0'));
        if value > u64::from(u16::MAX) {
            return Err(migrate_connect_err());
        }
        idx += 1;
    }

    if !saw_digit {
        return Ok(0);
    }
    if negative {
        return Err(migrate_connect_err());
    }

    u16::try_from(value).map_err(|_| migrate_connect_err())
}

pub fn execute_migrate(
    request: &MigrateRequest,
    keys: &[MigrateKeySpec],
    store: &mut Store,
    now_ms: u64,
) -> Result<MigrateOutcome, CommandError> {
    let mut payloads = Vec::new();
    for key in keys {
        let Some(payload) = store.dump_key(&key.source_key, now_ms) else {
            continue;
        };
        let ttl_ms = match store.pttl(&key.source_key, now_ms) {
            PttlValue::Remaining(ms) => ms.max(1) as u64,
            _ => 0,
        };
        payloads.push((key, ttl_ms, payload));
    }

    if payloads.is_empty() {
        return Ok(MigrateOutcome {
            reply: RespFrame::SimpleString("NOKEY".to_string()),
            deleted_keys: Vec::new(),
        });
    }

    // Redis only validates the target port once there is at least one key to transfer.
    let port = migrate_port_from_redis_atoi(&request.port_arg)?;
    let mut stream = migrate_connect(&request.host, port, request.timeout)?;
    let _ = stream.set_nodelay(true);
    let _ = stream.set_read_timeout(Some(request.timeout));
    let _ = stream.set_write_timeout(Some(request.timeout));

    if let Some(password) = request.auth_password.as_deref() {
        if let Some(username) = request.auth_username.as_deref() {
            migrate_write_frame(
                &mut stream,
                migrate_build_command(&[b"AUTH", username, password]),
            )?;
        } else {
            migrate_write_frame(&mut stream, migrate_build_command(&[b"AUTH", password]))?;
        }
    }

    let destination_db = request.destination_db.to_string();
    migrate_write_frame(
        &mut stream,
        migrate_build_command(&[b"SELECT", destination_db.as_bytes()]),
    )?;

    for (key, ttl_ms, payload) in &payloads {
        let ttl_string = ttl_ms.to_string();
        if request.replace {
            migrate_write_frame(
                &mut stream,
                migrate_build_command(&[
                    b"RESTORE",
                    key.target_key.as_slice(),
                    ttl_string.as_bytes(),
                    payload.as_slice(),
                    b"REPLACE",
                ]),
            )?;
        } else {
            migrate_write_frame(
                &mut stream,
                migrate_build_command(&[
                    b"RESTORE",
                    key.target_key.as_slice(),
                    ttl_string.as_bytes(),
                    payload.as_slice(),
                ]),
            )?;
        }
    }

    let mut read_buf = Vec::new();
    let auth_reply = if request.auth_password.is_some() {
        Some(migrate_read_frame(&mut stream, &mut read_buf)?)
    } else {
        None
    };
    let select_reply = migrate_read_frame(&mut stream, &mut read_buf)?;

    let mut first_target_error = auth_reply.as_ref().and_then(|frame| match frame {
        RespFrame::Error(err) => Some(err.clone()),
        _ => None,
    });
    if first_target_error.is_none() {
        first_target_error = match &select_reply {
            RespFrame::Error(err) => Some(err.clone()),
            _ => None,
        };
    }

    let mut deleted_source_keys = Vec::new();
    let mut deleted_target_keys = Vec::new();
    for (key, _, _) in &payloads {
        let reply = migrate_read_frame(&mut stream, &mut read_buf)?;
        if let RespFrame::Error(err) = &reply {
            if first_target_error.is_none() {
                first_target_error = Some(err.clone());
            }
        } else if first_target_error.is_none() && !request.copy {
            deleted_source_keys.push(key.source_key.clone());
            deleted_target_keys.push(key.target_key.clone());
        }
    }

    if !request.copy && !deleted_source_keys.is_empty() {
        let _ = store.del(&deleted_source_keys, now_ms);
    }

    let reply = if let Some(err) = first_target_error {
        RespFrame::Error(format!("Target instance replied with error: {err}"))
    } else {
        RespFrame::SimpleString("OK".to_string())
    };

    let _ = stream.shutdown(std::net::Shutdown::Both);

    Ok(MigrateOutcome {
        reply,
        deleted_keys: deleted_target_keys,
    })
}

fn migrate_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    let request = parse_migrate_request(argv)?;
    let key_specs: Vec<MigrateKeySpec> = request
        .keys
        .iter()
        .map(|key| MigrateKeySpec {
            source_key: key.clone(),
            target_key: key.clone(),
        })
        .collect();
    Ok(execute_migrate(&request, &key_specs, store, now_ms)?.reply)
}

fn failover_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // Upstream commands.def declares FAILOVER with CMD_NOSCRIPT, so
    // server.c::processCommand emits the noscript reply BEFORE the
    // handler ever runs. Mirror that order so a scripted call with
    // unknown options surfaces the noscript error rather than the
    // syntax error. (frankenredis-d021m)
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    // Parse FAILOVER arguments using Redis's option grammar:
    // [TO host port] [FORCE] [TIMEOUT ms], with each option accepted at most once.
    let mut abort = false;
    let mut _to_host: Option<&[u8]> = None;
    let mut _to_port: Option<i64> = None;
    let mut _force = false;
    let mut _timeout_ms: Option<u64> = None;

    let mut i = 1;
    while i < argv.len() {
        let arg = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if arg.eq_ignore_ascii_case("ABORT")
            && i + 1 == argv.len()
            && !abort
            && _to_host.is_none()
            && !_force
            && _timeout_ms.is_none()
        {
            abort = true;
            i += 1;
        } else if arg.eq_ignore_ascii_case("TIMEOUT") && i + 1 < argv.len() && _timeout_ms.is_none()
        {
            let ms = parse_i64_arg(&argv[i + 1])?;
            if ms <= 0 {
                return Err(CommandError::Custom(
                    "ERR FAILOVER timeout must be greater than 0".to_string(),
                ));
            }
            _timeout_ms = Some(ms as u64);
            i += 2;
        } else if arg.eq_ignore_ascii_case("TO") && i + 2 < argv.len() && _to_host.is_none() {
            _to_host = Some(&argv[i + 1]);
            // (frankenredis-ovp5b) Upstream failoverCommand parses
            // the port as a plain long long via
            // getLongFromObjectOrReply with no 0..65535 range check.
            // 99999, -1, 0 all parse fine; only an actual i64 overflow
            // (or non-numeric input) trips the integer error. The
            // port value is never consulted again unless the failover
            // path proceeds, so wider acceptance is harmless.
            let port = parse_i64_arg(&argv[i + 2])?;
            _to_port = Some(port);
            i += 3;
        } else if arg.eq_ignore_ascii_case("FORCE") && !_force {
            _force = true;
            i += 1;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    if abort {
        return Err(CommandError::Custom(
            "ERR No failover in progress.".to_string(),
        ));
    }

    // In standalone mode without replicas, FAILOVER cannot proceed
    Err(CommandError::Custom(
        "ERR FAILOVER requires connected replicas.".to_string(),
    ))
}

fn module_wrong_arity(subcommand: &[u8]) -> CommandError {
    CommandError::Custom(format!(
        "ERR wrong number of arguments for 'module|{}' command",
        bytes_to_lossy_string(subcommand).to_ascii_lowercase()
    ))
}

fn module_disabled_error() -> CommandError {
    CommandError::Custom(
        "ERR MODULE command not allowed. If the enable-module-command option is set to \"local\", you can run it from a local connection, otherwise you need to set this option in the configuration file, and then restart the server.".to_string(),
    )
}

fn module_cmd(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("MODULE"));
    }

    if argv[1].eq_ignore_ascii_case(b"HELP") {
        if argv.len() != 2 {
            return Err(module_wrong_arity(&argv[1]));
        }
        return Ok(RespFrame::Array(Some(vec![
            hello_simple("MODULE <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("LIST"),
            hello_simple("    Return a list of loaded modules."),
            hello_simple("LOAD <path> [<arg> ...]"),
            hello_simple(
                "    Load a module library from <path>, passing to it any optional arguments.",
            ),
            hello_simple("LOADEX <path> [[CONFIG NAME VALUE] [CONFIG NAME VALUE]] [ARGS ...]"),
            hello_simple(
                "    Load a module library from <path>, while passing it module configurations and optional arguments.",
            ),
            hello_simple("UNLOAD <name>"),
            hello_simple("    Unload a module."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])));
    }

    if argv[1].eq_ignore_ascii_case(b"LIST") {
        if argv.len() != 2 {
            return Err(module_wrong_arity(&argv[1]));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        return Ok(RespFrame::Array(Some(Vec::new())));
    }

    if argv[1].eq_ignore_ascii_case(b"UNLOAD") {
        if argv.len() != 3 {
            return Err(module_wrong_arity(&argv[1]));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        return Err(module_disabled_error());
    }

    if argv[1].eq_ignore_ascii_case(b"LOAD") || argv[1].eq_ignore_ascii_case(b"LOADEX") {
        if argv.len() < 3 {
            return Err(module_wrong_arity(&argv[1]));
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        return Err(module_disabled_error());
    }

    Err(CommandError::Custom(format!(
        "ERR unknown subcommand '{}'. Try MODULE HELP.",
        bytes_to_lossy_string(&argv[1])
    )))
}

fn sentinel_cmd(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    let args = argv.iter().skip(1).map(Vec::as_slice).collect::<Vec<_>>();
    let reply = fr_sentinel::commands::dispatch_sentinel_command(&mut store.sentinel_state, &args);
    // SENTINEL MASTER(S)/SLAVES/SENTINELS build per-instance info as RESP3
    // maps. Upstream's addReplyMapLen emits a flat 2N array on a RESP2
    // connection, so downconvert the map(s) when the client isn't RESP3 —
    // otherwise a RESP2 client receives an unparseable `%` frame.
    // (frankenredis-sentmap)
    if store.dispatch_client_ctx.resp_protocol_version == 3 {
        Ok(reply)
    } else {
        Ok(lua_eval::downconvert_lua_reply_to_resp2(reply))
    }
}

fn bytes_to_lossy_string(bytes: &[u8]) -> String {
    String::from_utf8_lossy(bytes).into_owned()
}

/// (frankenredis-wsqf2) Mirror upstream
/// getRangeLongFromObjectOrReply(c, argv, -LONG_MAX, LONG_MAX, ...).
/// On 64-bit Linux LONG_MAX == i64::MAX, so the only i64 value
/// rejected is i64::MIN. Used by *RANDMEMBER / *RANGEBYSCORE-style
/// handlers where i64::MIN with .unsigned_abs() would create a
/// ~9.2 quintillion-iteration loop and hang the server.
fn parse_i64_arg_long_range(arg: &[u8]) -> Result<i64, CommandError> {
    let value = parse_i64_arg(arg)?;
    if value == i64::MIN {
        return Err(CommandError::Custom(format!(
            "ERR value is out of range, value must between {} and {}",
            -i64::MAX,
            i64::MAX
        )));
    }
    Ok(value)
}

/// (frankenredis-sntxr) Tighter bound used by HRANDFIELD WITHVALUES
/// and ZRANDMEMBER WITHSCORES — restricts count to [-LONG_MAX/2,
/// LONG_MAX/2] so that count*2 (one member + one value/score per row)
/// can't overflow the reply length field. Matches upstream
/// t_zset.c::zrandmemberCommand line 4376 and t_hash.c::hrandfield
/// Command line 1146 ("value is out of range" with no range hint in
/// the message).
fn require_count_fits_half_long_range(count: i64) -> Result<(), CommandError> {
    let half = i64::MAX / 2;
    if count < -half || count > half {
        return Err(CommandError::Custom(
            "ERR value is out of range".to_string(),
        ));
    }
    Ok(())
}

/// Strict redis `string2ll` integer parse (rejects leading `+`, leading zeros,
/// embedded space). Public so the borrowed LRANGE fast path parses index args
/// IDENTICALLY to the generic dispatch — guaranteeing the fast path accepts
/// exactly the same inputs (and falls back, never diverging, on any the generic
/// path would reject). (frankenredis: LRANGE borrow-encode)
pub fn parse_i64_arg(arg: &[u8]) -> Result<i64, CommandError> {
    let slen = arg.len();
    if slen == 0 || slen > 20 {
        return Err(CommandError::InvalidInteger);
    }
    if slen == 1 && arg[0] == b'0' {
        return Ok(0);
    }

    let mut p = 0;
    let negative = arg[0] == b'-';
    if negative {
        p += 1;
        if p == slen {
            return Err(CommandError::InvalidInteger);
        }
    }

    if arg[p] >= b'1' && arg[p] <= b'9' {
        let mut v: u64 = (arg[p] - b'0') as u64;
        p += 1;
        while p < slen {
            let b = arg[p];
            if b.is_ascii_digit() {
                if v > (u64::MAX / 10) {
                    return Err(CommandError::InvalidInteger);
                }
                v *= 10;
                let digit = (b - b'0') as u64;
                if v > (u64::MAX - digit) {
                    return Err(CommandError::InvalidInteger);
                }
                v += digit;
                p += 1;
            } else {
                return Err(CommandError::InvalidInteger);
            }
        }

        if negative {
            let limit = (i64::MIN as u64).wrapping_neg();
            if v > limit {
                return Err(CommandError::InvalidInteger);
            }
            return Ok(v.wrapping_neg() as i64);
        } else {
            if v > i64::MAX as u64 {
                return Err(CommandError::InvalidInteger);
            }
            return Ok(v as i64);
        }
    }

    Err(CommandError::InvalidInteger)
}

/// Parse an expire time argument for SET/GETEX commands.
/// Redis rejects 0 and negative values with a specific error message.
fn parse_expire_time_arg(arg: &[u8], command: &str) -> Result<u64, CommandError> {
    let val = parse_i64_arg(arg)?;
    if val <= 0 {
        return Err(CommandError::Custom(format!(
            "ERR invalid expire time in '{command}' command"
        )));
    }
    Ok(val as u64)
}

fn parse_set_expire_arg(arg: &[u8]) -> Result<u64, CommandError> {
    parse_expire_time_arg(arg, "set")
}

/// Mirror upstream t_string.c::getExpireMillisecondsOrReply's
/// relative-to-absolute basetime overflow check: when a relative
/// EX/PX value (already converted to milliseconds) plus the
/// current `now_ms` would exceed LLONG_MAX, upstream replies
/// "ERR invalid expire time in '<command>' command" rather than
/// silently saturating. (frankenredis-expbase)
fn validate_relative_expire_basetime(
    relative_ms: u64,
    now_ms: u64,
    command: &str,
) -> Result<(), CommandError> {
    let max_ms = i64::MAX as u64;
    if relative_ms > max_ms.saturating_sub(now_ms) {
        return Err(CommandError::Custom(format!(
            "ERR invalid expire time in '{command}' command"
        )));
    }
    Ok(())
}

fn parse_u64_arg(arg: &[u8]) -> Result<u64, CommandError> {
    let val = parse_i64_arg(arg)?;
    if val < 0 {
        return Err(CommandError::InvalidInteger);
    }
    Ok(val as u64)
}

/// Parse a LIMIT count that can be negative (Redis uses -1 to mean "unlimited").
/// Returns None for negative values, Some(n) for non-negative.
fn parse_limit_count_arg(arg: &[u8]) -> Result<Option<usize>, CommandError> {
    let val = parse_i64_arg(arg)?;
    if val < 0 {
        return Ok(None);
    }
    usize::try_from(val)
        .map(Some)
        .map_err(|_| CommandError::InvalidInteger)
}

fn parse_limit_offset_arg(arg: &[u8]) -> Result<usize, CommandError> {
    let val = parse_i64_arg(arg)?;
    if val < 0 {
        return Ok(usize::MAX);
    }
    usize::try_from(val).map_err(|_| CommandError::InvalidInteger)
}

fn parse_expire_options(extra_args: &[Vec<u8>]) -> Result<ExpireOptions, CommandError> {
    let mut options = ExpireOptions::default();
    for arg in extra_args {
        let option = std::str::from_utf8(arg).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if option.eq_ignore_ascii_case("NX") {
            options.nx = true;
        } else if option.eq_ignore_ascii_case("XX") {
            options.xx = true;
        } else if option.eq_ignore_ascii_case("GT") {
            options.gt = true;
        } else if option.eq_ignore_ascii_case("LT") {
            options.lt = true;
        } else {
            return Err(CommandError::Custom(format!(
                "ERR Unsupported option {option}"
            )));
        }
    }

    if options.nx && (options.xx || options.gt || options.lt) {
        return Err(CommandError::Custom(
            "ERR NX and XX, GT or LT options at the same time are not compatible".to_string(),
        ));
    }
    if options.gt && options.lt {
        return Err(CommandError::Custom(
            "ERR GT and LT options at the same time are not compatible".to_string(),
        ));
    }

    Ok(options)
}

fn deadline_from_expire_kind(kind: ExpireCommandKind, raw_time: i64, now_ms: u64) -> i128 {
    match kind {
        ExpireCommandKind::RelativeSeconds => {
            i128::from(now_ms).saturating_add(i128::from(raw_time).saturating_mul(1000))
        }
        ExpireCommandKind::RelativeMilliseconds => {
            i128::from(now_ms).saturating_add(i128::from(raw_time))
        }
        ExpireCommandKind::AbsoluteSeconds => i128::from(raw_time).saturating_mul(1000),
        ExpireCommandKind::AbsoluteMilliseconds => i128::from(raw_time),
    }
}

fn apply_expiry_with_options(
    store: &mut Store,
    key: &[u8],
    when_ms: i128,
    now_ms: u64,
    options: ExpireOptions,
) -> bool {
    // EXPIRE/PEXPIRE/EXPIREAT/PEXPIREAT are writes (lookupKeyWrite); reading the
    // current TTL for the NX/XX/GT/LT comparison must NOT bump keyspace_hits, so
    // use the non-counting PTTL. (frankenredis-934ax)
    let current_remaining_ms = match store.pttl_no_stats(key, now_ms) {
        PttlValue::KeyMissing => return false,
        PttlValue::NoExpiry => None,
        PttlValue::Remaining(ms) => Some(ms),
    };

    if options.nx && current_remaining_ms.is_some() {
        return false;
    }
    if options.xx && current_remaining_ms.is_none() {
        return false;
    }
    if options.gt {
        let Some(remaining_ms) = current_remaining_ms else {
            return false;
        };
        let current_when_ms = i128::from(now_ms).saturating_add(i128::from(remaining_ms));
        if when_ms <= current_when_ms {
            return false;
        }
    }
    if options.lt
        && let Some(remaining_ms) = current_remaining_ms
    {
        let current_when_ms = i128::from(now_ms).saturating_add(i128::from(remaining_ms));
        if when_ms >= current_when_ms {
            return false;
        }
    }

    store.expire_at_milliseconds(key, clamp_i128_to_i64(when_ms), now_ms)
}

fn clamp_i128_to_i64(value: i128) -> i64 {
    if value < i128::from(i64::MIN) {
        i64::MIN
    } else if value > i128::from(i64::MAX) {
        i64::MAX
    } else {
        value as i64
    }
}

pub fn build_unknown_args_preview(argv: &[Vec<u8>]) -> Option<String> {
    if argv.len() < 2 {
        return None;
    }

    let mut out = String::new();
    for arg in &argv[1..] {
        if out.len() >= 128 {
            break;
        }
        let remaining = 128_usize.saturating_sub(out.len());
        if remaining < 3 {
            break;
        }

        // Upstream formats each arg with printf %.*s, which stops at the first
        // NUL (C-string semantics) even within the length bound — so truncate
        // each arg at its first NUL, mirroring the command-name handling.
        // (frankenredis-unkcmdname)
        let nul_truncated = match arg.iter().position(|&b| b == 0) {
            Some(nul) => &arg[..nul],
            None => arg.as_slice(),
        };
        let text = String::from_utf8_lossy(nul_truncated);
        let sanitized = text.replace(['\r', '\n'], " ");
        let capped = trim_and_cap_string(&sanitized, remaining.saturating_sub(3));
        out.push('\'');
        out.push_str(&capped);
        out.push_str("' ");
    }

    if out.is_empty() { None } else { Some(out) }
}

pub fn trim_and_cap_string(input: &str, cap: usize) -> String {
    let mut out = String::new();
    for ch in input.chars() {
        if out.len() + ch.len_utf8() > cap {
            break;
        }
        if ch == '\r' || ch == '\n' {
            out.push(' ');
        } else {
            out.push(ch);
        }
    }
    out
}

fn getex(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("GETEX"));
    }
    let key = &argv[1];

    // (frankenredis-getexdup) Mirror upstream
    // t_string.c::parseExtendedStringArgumentsOrReply (the COMMAND_GET
    // branch shared with SET): each expiry-kind is gated on
    // !(*flags & OBJ_<other>) but NOT on its own flag, so the same
    // option can appear twice (last value wins). Only mixed kinds
    // conflict. fr previously hardcoded a strict argc check that
    // rejected `GETEX k EX 5 EX 10`, `GETEX k PERSIST PERSIST`, etc.,
    // diverging from vendored Redis 7.2.4.
    //
    // (frankenredis-qw3kt) The keyword/value parse here mirrors
    // parseExtendedStringArgumentsOrReply, which only checks the option
    // keyword + arg presence and stashes the raw value as a robj*. The
    // integer + sign + bound checks (getExpireMillisecondsOrReply) and
    // the WRONGTYPE / nil-on-missing reply come AFTER the lookup in
    // getexCommand at t_string.c:381. Validate values lazily so a
    // missing key short-circuits to nil and a wrong-type key surfaces
    // WRONGTYPE before any "invalid expire time" error.
    enum ExpiryKind {
        None,
        Persist,
        Ex,
        Px,
        Exat,
        Pxat,
    }
    let mut expiry_kind = ExpiryKind::None;
    let mut raw_value: Option<&[u8]> = None;
    let mut options = argv[2..].iter();
    while let Some(option_arg) = options.next() {
        let option = std::str::from_utf8(option_arg).map_err(|_| CommandError::SyntaxError)?;
        if option.eq_ignore_ascii_case("EX") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::Ex) {
                return Err(CommandError::SyntaxError);
            }
            let Some(arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            raw_value = Some(arg);
            expiry_kind = ExpiryKind::Ex;
        } else if option.eq_ignore_ascii_case("PX") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::Px) {
                return Err(CommandError::SyntaxError);
            }
            let Some(arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            raw_value = Some(arg);
            expiry_kind = ExpiryKind::Px;
        } else if option.eq_ignore_ascii_case("EXAT") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::Exat) {
                return Err(CommandError::SyntaxError);
            }
            let Some(arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            raw_value = Some(arg);
            expiry_kind = ExpiryKind::Exat;
        } else if option.eq_ignore_ascii_case("PXAT") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::Pxat) {
                return Err(CommandError::SyntaxError);
            }
            let Some(arg) = options.next() else {
                return Err(CommandError::SyntaxError);
            };
            raw_value = Some(arg);
            expiry_kind = ExpiryKind::Pxat;
        } else if option.eq_ignore_ascii_case("PERSIST") {
            if !matches!(expiry_kind, ExpiryKind::None | ExpiryKind::Persist) {
                return Err(CommandError::SyntaxError);
            }
            expiry_kind = ExpiryKind::Persist;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    // Upstream lookupKeyReadOrReply / checkType run before
    // getExpireMillisecondsOrReply: a missing key short-circuits to
    // BulkString(None) and a non-string value surfaces WRONGTYPE,
    // regardless of whether the requested expiry value would have been
    // rejected as invalid.
    match store.key_type(key, now_ms) {
        None => return Ok(RespFrame::BulkString(None)),
        Some("string") => {}
        Some(_) => return Err(CommandError::Store(StoreError::WrongType)),
    }

    let new_expires: Option<Option<u64>> = match expiry_kind {
        ExpiryKind::None => None,
        ExpiryKind::Persist => Some(None),
        ExpiryKind::Ex => {
            let arg = raw_value.expect("EX value collected above");
            let secs = parse_expire_time_arg(arg, "getex")?;
            if secs > i64::MAX as u64 / 1000 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'getex' command".to_string(),
                ));
            }
            validate_relative_expire_basetime(secs * 1000, now_ms, "getex")?;
            Some(Some(now_ms.saturating_add(secs.saturating_mul(1000))))
        }
        ExpiryKind::Px => {
            let arg = raw_value.expect("PX value collected above");
            let ms = parse_expire_time_arg(arg, "getex")?;
            validate_relative_expire_basetime(ms, now_ms, "getex")?;
            Some(Some(now_ms.saturating_add(ms)))
        }
        ExpiryKind::Exat => {
            let arg = raw_value.expect("EXAT value collected above");
            let ts = parse_expire_time_arg(arg, "getex")?;
            if ts > i64::MAX as u64 / 1000 {
                return Err(CommandError::Custom(
                    "ERR invalid expire time in 'getex' command".to_string(),
                ));
            }
            Some(Some(ts.saturating_mul(1000)))
        }
        ExpiryKind::Pxat => {
            let arg = raw_value.expect("PXAT value collected above");
            Some(Some(parse_expire_time_arg(arg, "getex")?))
        }
    };

    match store.getex(key, new_expires, now_ms)? {
        Some(v) => Ok(RespFrame::BulkString(Some(v))),
        None => Ok(RespFrame::BulkString(None)),
    }
}

fn smismember(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("SMISMEMBER"));
    }
    let key = &argv[1];
    let members: Vec<&[u8]> = argv[2..].iter().map(|v| v.as_slice()).collect();
    let results = store
        .smismember(key, &members, now_ms)
        .map_err(CommandError::Store)?;
    let frames: Vec<RespFrame> = results
        .into_iter()
        .map(|b| RespFrame::Integer(i64::from(b)))
        .collect();
    Ok(RespFrame::Array(Some(frames)))
}

fn sintercard(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // SINTERCARD numkeys key [key ...] [LIMIT limit]
    //
    // Error-reply wording MUST match upstream byte-for-byte
    // (br-frankenredis-ozj0). See legacy_redis_code/redis/src/t_set.c
    // `sinterGenericCommand` + `genericSintercardCommand` for the
    // source strings quoted below.
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("SINTERCARD"));
    }
    // Upstream t_set.c:1451-1453 routes both parse failure and
    // out-of-range numkeys through getRangeLongFromObjectOrReply with
    // the 'numkeys should be greater than 0' msg argument, so 'abc',
    // '0', '-1', and the empty string all share one wording.
    // (frankenredis-sw76v)
    let bad_numkeys = || CommandError::Custom("ERR numkeys should be greater than 0".to_string());
    let numkeys_val = match parse_i64_arg(&argv[1]) {
        Ok(v) if v >= 1 => v,
        _ => return Err(bad_numkeys()),
    };
    let numkeys = usize::try_from(numkeys_val).map_err(|_| bad_numkeys())?;
    let keys_end = 2_usize.saturating_add(numkeys);
    if keys_end > argv.len() {
        return Ok(RespFrame::Error(
            "ERR Number of keys can't be greater than number of args".to_string(),
        ));
    }
    let keys: Vec<&[u8]> = argv[2..keys_end].iter().map(Vec::as_slice).collect();
    let mut limit: u64 = 0;
    let mut idx = keys_end;
    while idx < argv.len() {
        if argv[idx].eq_ignore_ascii_case(b"LIMIT") {
            idx += 1;
            if idx >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream routes both parse failure AND negative values
            // through the same "LIMIT can't be negative" reply via
            // getRangeLongFromObjectOrReply's error-string argument.
            let val = match parse_i64_arg(&argv[idx]) {
                Ok(v) => v,
                Err(_) => {
                    return Ok(RespFrame::Error("ERR LIMIT can't be negative".to_string()));
                }
            };
            if val < 0 {
                return Err(CommandError::Custom(
                    "ERR LIMIT can't be negative".to_string(),
                ));
            }
            limit = val as u64;
            idx += 1;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }
    record_source_key_lookups(store, &keys, now_ms);
    let count = store.sintercard(&keys, limit, now_ms)?;
    #[allow(clippy::cast_possible_wrap)]
    Ok(RespFrame::Integer(count as i64))
}

fn lcs(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // LCS key1 key2 [LEN] [IDX] [MINMATCHLEN min] [WITHMATCHLEN]
    //
    // Error-reply wording MUST match upstream t_string.c::lcsCommand
    // (br-frankenredis-68ql).
    if argv.len() < 3 {
        return Err(CommandError::WrongArity("LCS"));
    }
    // Convert a raw WRONGTYPE from the store into upstream's
    // LCS-specific wording. Other StoreError kinds pass through.
    let map_type_err = |err: StoreError| -> CommandError {
        if matches!(err, StoreError::WrongType) {
            CommandError::Custom("ERR The specified keys must contain string values".to_string())
        } else {
            CommandError::Store(err)
        }
    };
    let a = store
        .get(&argv[1], now_ms)
        .map_err(map_type_err)?
        .unwrap_or_default();
    let b = store
        .get(&argv[2], now_ms)
        .map_err(map_type_err)?
        .unwrap_or_default();

    let mut len_only = false;
    let mut idx_mode = false;
    let mut min_match_len: usize = 0;
    let mut with_match_len = false;
    let mut i = 3;
    while i < argv.len() {
        if argv[i].eq_ignore_ascii_case(b"LEN") {
            len_only = true;
            i += 1;
        } else if argv[i].eq_ignore_ascii_case(b"IDX") {
            idx_mode = true;
            i += 1;
        } else if argv[i].eq_ignore_ascii_case(b"MINMATCHLEN") {
            i += 1;
            if i >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let val = parse_i64_arg(&argv[i])?;
            // Upstream clamps negative MINMATCHLEN to 0 rather than
            // rejecting — see t_string.c where `min_match_len` is
            // read with getLongLongFromObjectOrReply and then
            // negative values silently floor to 0.
            min_match_len = if val < 0 {
                0
            } else {
                usize::try_from(val).map_err(|_| CommandError::InvalidInteger)?
            };
            i += 1;
        } else if argv[i].eq_ignore_ascii_case(b"WITHMATCHLEN") {
            with_match_len = true;
            i += 1;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }

    // Upstream rejects the LEN+IDX combination with a specific
    // message instead of silently preferring LEN.
    if len_only && idx_mode {
        return Ok(RespFrame::Error(
            "ERR If you want both the length and indexes, please just use IDX.".to_string(),
        ));
    }

    if len_only {
        return Ok(RespFrame::Integer(compute_lcs_len(&a, &b) as i64));
    }

    if idx_mode {
        let matches = compute_lcs_matches(&a, &b, min_match_len)?;
        let mut match_frames = Vec::new();
        for m in &matches {
            let a_range = RespFrame::Array(Some(vec![
                RespFrame::Integer(m.a_start as i64),
                RespFrame::Integer(m.a_end as i64),
            ]));
            let b_range = RespFrame::Array(Some(vec![
                RespFrame::Integer(m.b_start as i64),
                RespFrame::Integer(m.b_end as i64),
            ]));
            if with_match_len {
                match_frames.push(RespFrame::Array(Some(vec![
                    a_range,
                    b_range,
                    RespFrame::Integer(m.len as i64),
                ])));
            } else {
                match_frames.push(RespFrame::Array(Some(vec![a_range, b_range])));
            }
        }
        // Upstream t_string.c:863 wraps the IDX reply in
        // addReplyMapLen(c, 2) — RESP3 wire shape is a 2-entry Map
        // ('matches' → Array, 'len' → Integer); RESP2 stays the
        // flat 4-element Array. Same shape pattern as i40x2 / e4njz /
        // udl3y / asvh1 / 5d04d / ndz0j / 5h86s.
        // (frankenredis-cz712)
        if store.dispatch_client_ctx.resp_protocol_version == 3 {
            return Ok(RespFrame::Map(Some(vec![
                (
                    RespFrame::BulkString(Some(b"matches".to_vec())),
                    RespFrame::Array(Some(match_frames)),
                ),
                (
                    RespFrame::BulkString(Some(b"len".to_vec())),
                    RespFrame::Integer(compute_lcs_len(&a, &b) as i64),
                ),
            ])));
        }
        return Ok(RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"matches".to_vec())),
            RespFrame::Array(Some(match_frames)),
            RespFrame::BulkString(Some(b"len".to_vec())),
            RespFrame::Integer(compute_lcs_len(&a, &b) as i64),
        ])));
    }

    let lcs_result = compute_lcs(&a, &b)?;
    Ok(RespFrame::BulkString(Some(lcs_result)))
}

struct LcsMatch {
    a_start: usize,
    a_end: usize,
    b_start: usize,
    b_end: usize,
    len: usize,
}

const LCS_MAX_DP_SIZE: usize = 16 * 1024 * 1024; // 16M entries = 64MB

fn compute_lcs_len(a: &[u8], b: &[u8]) -> usize {
    // `a` is the shorter string (the inner / pattern dimension).
    let (a, b) = if a.len() < b.len() { (a, b) } else { (b, a) };
    let m = a.len();
    let n = b.len();
    if m == 0 || n == 0 {
        return 0;
    }
    if m <= 64 {
        // Bit-parallel LCS-length (Crochemore-Iliopoulos-Pinzon-Rytter, 2001):
        // encode the pattern `a` (m<=64 bits) as per-byte position masks, then
        // fold each text byte through one word recurrence instead of the O(m)
        // inner DP row. The LCS length is `m` minus the popcount of the final
        // match vector. This is the exact LCS length (not an approximation) and
        // is byte-identical to the scalar DP — see
        // compute_lcs_len_scalar and the equivalence test. (frankenredis-t8veh)
        let mut pm = [0u64; 256];
        for (i, &c) in a.iter().enumerate() {
            pm[c as usize] |= 1u64 << i;
        }
        let mask: u64 = if m == 64 { !0u64 } else { (1u64 << m) - 1 };
        let mut v: u64 = mask;
        for &c in b {
            let u = v & pm[c as usize];
            v = (v.wrapping_add(u) | v.wrapping_sub(u)) & mask;
        }
        return m - v.count_ones() as usize;
    }
    compute_lcs_len_scalar(a, b)
}

/// Scalar two-row LCS-length DP. Reference fallback for patterns longer than a
/// machine word (m > 64), and the equivalence oracle for the bit-parallel path.
/// `a` must be the shorter string. (frankenredis-t8veh)
fn compute_lcs_len_scalar(a: &[u8], b: &[u8]) -> usize {
    let m = a.len();
    let n = b.len();
    if m == 0 || n == 0 {
        return 0;
    }
    let mut prev = vec![0u32; m + 1];
    let mut curr = vec![0u32; m + 1];
    for j in 1..=n {
        for i in 1..=m {
            if a[i - 1] == b[j - 1] {
                curr[i] = prev[i - 1] + 1;
            } else {
                curr[i] = curr[i - 1].max(prev[i]);
            }
        }
        std::mem::swap(&mut prev, &mut curr);
    }
    prev[m] as usize
}

/// Low-`k`-bits mask (`k <= 64`); `lcs_low_mask(64) == u64::MAX`. (frankenredis-mug2e)
fn lcs_low_mask(k: usize) -> u64 {
    if k >= 64 { u64::MAX } else { (1u64 << k) - 1 }
}

/// LCS dynamic-programming oracle shared by `compute_lcs` and
/// `compute_lcs_matches`. `Full` is the classic O(n*m) u32 matrix, used when
/// both inputs exceed a machine word and as the equivalence oracle in tests.
/// The two bit-parallel variants store one Allison-Dix LCS vector per
/// outer-axis position (the same Crochemore-Iliopoulos-Pinzon-Rytter
/// `v = (v+u)|(v-u)` recurrence as `compute_lcs_len`), from which any
/// `dp[i][j]` is recovered by a single prefix-popcount: O(n+m) build + O(1)
/// cell lookup, replacing the O(n*m) fill/alloc. Because `get` returns the
/// *exact* scalar `dp` value, the shared backtrack is byte-identical to the
/// matrix version. (frankenredis-mug2e)
enum LcsDp {
    /// Full scalar matrix; `dp[i * cols + j]`.
    Full { dp: Vec<u32>, cols: usize },
    /// Pattern = `a` along rows (`a.len() <= 64`); `v[j]` is the LCS vector after
    /// column `j`, so `dp[i][j] = i - popcount(v[j] & low_mask(i))`.
    ColBits { v: Vec<u64> },
    /// Pattern = `b` along columns (`b.len() <= 64`); `v[i]` is the LCS vector
    /// after row `i`, so `dp[i][j] = j - popcount(v[i] & low_mask(j))`.
    RowBits { v: Vec<u64> },
}

impl LcsDp {
    /// LCS length of the prefixes `a[..i]` x `b[..j]`. Identical to the scalar
    /// `dp[i][j]` for every `(i, j)`; never underflows because
    /// `popcount(v & low_mask(k)) <= k`. (frankenredis-mug2e)
    #[inline]
    fn get(&self, i: usize, j: usize) -> u32 {
        match self {
            LcsDp::Full { dp, cols } => dp[i * cols + j],
            LcsDp::ColBits { v } => i as u32 - (v[j] & lcs_low_mask(i)).count_ones(),
            LcsDp::RowBits { v } => j as u32 - (v[i] & lcs_low_mask(j)).count_ones(),
        }
    }
}

/// Build the LCS DP oracle for `a` (rows) x `b` (columns), preferring the
/// bit-parallel representation whenever either string fits a machine word.
/// Callers must already have handled the empty-input case. (frankenredis-mug2e)
fn build_lcs_dp(a: &[u8], b: &[u8]) -> LcsDp {
    let m = a.len();
    let n = b.len();
    if m <= 64 {
        // Pattern = a over rows: fold each column (b byte) through the word
        // recurrence, recording the LCS vector after every column.
        let mut pm = [0u64; 256];
        for (idx, &c) in a.iter().enumerate() {
            pm[c as usize] |= 1u64 << idx;
        }
        let full = lcs_low_mask(m);
        let mut v = Vec::with_capacity(n + 1);
        let mut cur = full;
        v.push(cur);
        for &c in b {
            let u = cur & pm[c as usize];
            cur = (cur.wrapping_add(u) | cur.wrapping_sub(u)) & full;
            v.push(cur);
        }
        LcsDp::ColBits { v }
    } else if n <= 64 {
        // Pattern = b over columns: fold each row (a byte) through the word
        // recurrence, recording the LCS vector after every row.
        let mut pm = [0u64; 256];
        for (idx, &c) in b.iter().enumerate() {
            pm[c as usize] |= 1u64 << idx;
        }
        let full = lcs_low_mask(n);
        let mut v = Vec::with_capacity(m + 1);
        let mut cur = full;
        v.push(cur);
        for &c in a {
            let u = cur & pm[c as usize];
            cur = (cur.wrapping_add(u) | cur.wrapping_sub(u)) & full;
            v.push(cur);
        }
        LcsDp::RowBits { v }
    } else {
        // Both strings exceed a machine word: classic flat-matrix DP.
        let cols = n + 1;
        let mut dp = vec![0u32; (m + 1) * cols];
        for i in 1..=m {
            for j in 1..=n {
                if a[i - 1] == b[j - 1] {
                    dp[i * cols + j] = dp[(i - 1) * cols + (j - 1)] + 1;
                } else {
                    dp[i * cols + j] = dp[(i - 1) * cols + j].max(dp[i * cols + (j - 1)]);
                }
            }
        }
        LcsDp::Full { dp, cols }
    }
}

fn compute_lcs(a: &[u8], b: &[u8]) -> Result<Vec<u8>, CommandError> {
    let m = a.len();
    let n = b.len();
    if m == 0 || n == 0 {
        return Ok(Vec::new());
    }
    if m.saturating_mul(n) > LCS_MAX_DP_SIZE {
        // (frankenredis-ruc5t) Match upstream t_string.c line 812
        // wording. fr's prior 'too long without LEN flag' message
        // was invented and didn't match any upstream addReplyError.
        return Err(CommandError::Custom(
            "ERR Insufficient memory, transient memory for LCS exceeds proto-max-bulk-len"
                .to_string(),
        ));
    }
    let dp = build_lcs_dp(a, b);
    // Backtrack (identical tie-break to the scalar matrix version).
    let mut result = Vec::with_capacity(dp.get(m, n) as usize);
    let (mut i, mut j) = (m, n);
    while i > 0 && j > 0 {
        if a[i - 1] == b[j - 1] {
            result.push(a[i - 1]);
            i -= 1;
            j -= 1;
        } else if dp.get(i - 1, j) > dp.get(i, j - 1) {
            i -= 1;
        } else {
            j -= 1;
        }
    }
    result.reverse();
    Ok(result)
}

fn compute_lcs_matches(
    a: &[u8],
    b: &[u8],
    min_match_len: usize,
) -> Result<Vec<LcsMatch>, CommandError> {
    let m = a.len();
    let n = b.len();
    if m == 0 || n == 0 {
        return Ok(Vec::new());
    }
    if m.saturating_mul(n) > LCS_MAX_DP_SIZE {
        // (frankenredis-ruc5t) Match upstream t_string.c line 812
        // wording. fr's prior 'too long without LEN flag' message
        // was invented and didn't match any upstream addReplyError.
        return Err(CommandError::Custom(
            "ERR Insufficient memory, transient memory for LCS exceeds proto-max-bulk-len"
                .to_string(),
        ));
    }
    let dp = build_lcs_dp(a, b);
    // Backtrack to find matching segments (identical tie-break to scalar).
    let mut segments = Vec::new();
    let (mut i, mut j) = (m, n);
    while i > 0 && j > 0 {
        if a[i - 1] == b[j - 1] {
            let end_a = i - 1;
            let end_b = j - 1;
            while i > 0 && j > 0 && a[i - 1] == b[j - 1] {
                i -= 1;
                j -= 1;
            }
            let start_a = i;
            let start_b = j;
            let len = end_a - start_a + 1;
            if len >= min_match_len {
                segments.push(LcsMatch {
                    a_start: start_a,
                    a_end: end_a,
                    b_start: start_b,
                    b_end: end_b,
                    len,
                });
            }
        } else if dp.get(i - 1, j) > dp.get(i, j - 1) {
            i -= 1;
        } else {
            j -= 1;
        }
    }
    Ok(segments)
}

fn lmpop(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // LMPOP numkeys key [key ...] LEFT|RIGHT [COUNT count]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("LMPOP"));
    }
    // (br-frankenredis-blmpcount) — upstream emits the same wording
    // for both unparseable and non-positive numkeys/count values.
    let bad_numkeys = || RespFrame::Error("ERR numkeys should be greater than 0".to_string());
    let numkeys_val = match parse_i64_arg(&argv[1]) {
        Ok(v) => v,
        Err(_) => return Ok(bad_numkeys()),
    };
    if numkeys_val <= 0 {
        return Ok(bad_numkeys());
    }
    let numkeys = usize::try_from(numkeys_val).map_err(|_| CommandError::InvalidInteger)?;
    let keys_end = 2_usize.saturating_add(numkeys);
    if keys_end >= argv.len() {
        return Err(CommandError::SyntaxError);
    }
    let direction = &argv[keys_end];
    let left = if direction.eq_ignore_ascii_case(b"LEFT") {
        true
    } else if direction.eq_ignore_ascii_case(b"RIGHT") {
        false
    } else {
        return Err(CommandError::SyntaxError);
    };
    let bad_count = || RespFrame::Error("ERR count should be greater than 0".to_string());
    let mut count: usize = 1;
    let mut idx = keys_end + 1;
    if idx < argv.len() {
        if argv[idx].eq_ignore_ascii_case(b"COUNT") {
            idx += 1;
            if idx >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let val = match parse_i64_arg(&argv[idx]) {
                Ok(v) => v,
                Err(_) => return Ok(bad_count()),
            };
            if val <= 0 {
                return Ok(bad_count());
            }
            count = usize::try_from(val).map_err(|_| CommandError::InvalidInteger)?;
            idx += 1;
            if idx < argv.len() {
                return Err(CommandError::SyntaxError);
            }
        } else {
            return Err(CommandError::SyntaxError);
        }
    }
    for key in &argv[2..keys_end] {
        // (CrimsonHawk) LMPOP is a write (upstream lookupKeyWrite). Pop directly with
        // the count variant: ONE keyspace lookup pops up to `count` from the chosen key,
        // replacing the old `llen_no_stat` probe + per-element single-pop loop (count+1
        // lookups). Lists are never stored empty, so a missing/empty key returns None —
        // exactly the old `n > 0` test — and we scan the next key; WrongType -> error.
        // lpop_count/rpop_count back the shipped LPOP/RPOP COUNT (byte-exact order), and
        // neither lpop nor lpop_count emits keyspace events (the runtime does), so dirty,
        // key-removal, and notifications are unchanged.
        let popped = if left {
            store.lpop_count(key, count, now_ms)
        } else {
            store.rpop_count(key, count, now_ms)
        };
        match popped {
            Ok(Some(items)) if !items.is_empty() => {
                let arr = items
                    .into_iter()
                    .map(|v| RespFrame::BulkString(Some(v)))
                    .collect();
                return Ok(RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(key.clone())),
                    RespFrame::Array(Some(arr)),
                ])));
            }
            Ok(_) => continue,
            Err(StoreError::WrongType) => {
                return Err(CommandError::Store(StoreError::WrongType));
            }
            Err(e) => return Err(CommandError::Store(e)),
        }
    }
    Ok(RespFrame::Array(None))
}

fn zmpop(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // ZMPOP numkeys key [key ...] MIN|MAX [COUNT count]
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZMPOP"));
    }
    // (br-frankenredis-blmpcount)
    let bad_numkeys = || RespFrame::Error("ERR numkeys should be greater than 0".to_string());
    let numkeys_val = match parse_i64_arg(&argv[1]) {
        Ok(v) => v,
        Err(_) => return Ok(bad_numkeys()),
    };
    if numkeys_val <= 0 {
        return Ok(bad_numkeys());
    }
    let numkeys = usize::try_from(numkeys_val).map_err(|_| CommandError::InvalidInteger)?;
    let keys_end = 2_usize.saturating_add(numkeys);
    if keys_end >= argv.len() {
        return Err(CommandError::SyntaxError);
    }
    let direction = &argv[keys_end];
    let use_min = if direction.eq_ignore_ascii_case(b"MIN") {
        true
    } else if direction.eq_ignore_ascii_case(b"MAX") {
        false
    } else {
        return Err(CommandError::SyntaxError);
    };
    let bad_count = || RespFrame::Error("ERR count should be greater than 0".to_string());
    let mut count: usize = 1;
    let mut idx = keys_end + 1;
    if idx < argv.len() {
        if argv[idx].eq_ignore_ascii_case(b"COUNT") {
            idx += 1;
            if idx >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            let val = match parse_i64_arg(&argv[idx]) {
                Ok(v) => v,
                Err(_) => return Ok(bad_count()),
            };
            if val <= 0 {
                return Ok(bad_count());
            }
            count = usize::try_from(val).map_err(|_| CommandError::InvalidInteger)?;
            idx += 1;
            if idx < argv.len() {
                return Err(CommandError::SyntaxError);
            }
        } else {
            return Err(CommandError::SyntaxError);
        }
    }
    let resp_proto = store.dispatch_client_ctx.resp_protocol_version;
    for key in &argv[2..keys_end] {
        // (CrimsonHawk) ZMPOP is a write (upstream lookupKeyWrite). Pop directly with
        // the count variant: ONE keyspace lookup pops up to `count` from the chosen key,
        // replacing the old `zcard_no_stat` probe + per-element single-pop loop (count+1
        // lookups). Sorted sets are never stored empty, so an empty result == the old
        // `n > 0` test; scan the next key on empty, error on WrongType. zpopmin_count/
        // zpopmax_count back the shipped ZPOPMIN/ZPOPMAX COUNT (byte-exact order), and
        // emit no keyspace events themselves (the runtime does), so dirty/removal/notify
        // are unchanged.
        let result = if use_min {
            store.zpopmin_count(key, count, now_ms)
        } else {
            store.zpopmax_count(key, count, now_ms)
        };
        match result {
            Ok(pairs) if !pairs.is_empty() => {
                let popped = pairs
                    .into_iter()
                    .map(|(member, score)| {
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(member)),
                            zpop_score_frame(score, resp_proto),
                        ]))
                    })
                    .collect();
                return Ok(RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(key.clone())),
                    RespFrame::Array(Some(popped)),
                ])));
            }
            Ok(_) => continue,
            Err(StoreError::WrongType) => {
                return Err(CommandError::Store(StoreError::WrongType));
            }
            Err(e) => return Err(CommandError::Store(e)),
        }
    }
    Ok(RespFrame::Array(None))
}

fn bitop(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("BITOP"));
    }
    let op = &argv[1];
    let dest = &argv[2];
    let keys: Vec<&[u8]> = argv[3..].iter().map(|v| v.as_slice()).collect();

    // Validate operation
    let is_valid_op = eq_ascii_command(op, b"AND")
        || eq_ascii_command(op, b"OR")
        || eq_ascii_command(op, b"XOR")
        || eq_ascii_command(op, b"NOT");
    if !is_valid_op {
        return Err(CommandError::SyntaxError);
    }

    if eq_ascii_command(op, b"NOT") && keys.len() != 1 {
        return Ok(RespFrame::Error(
            "ERR BITOP NOT must be called with a single source key.".to_string(),
        ));
    }

    // store.bitop reads the source keys no-stat; upstream bitopCommand does a
    // lookupKeyRead per source key, so record one keyspace hit/miss per source
    // (after op/arity validation, matching upstream order).
    record_source_key_lookups(store, &keys, now_ms);
    let len = store
        .bitop(op, dest, &keys, now_ms)
        .map_err(CommandError::Store)?;
    Ok(RespFrame::Integer(i64::try_from(len).unwrap_or(i64::MAX)))
}

fn parse_zstore_args(
    argv: &[Vec<u8>],
    start: usize,
    numkeys: usize,
) -> Result<(Vec<f64>, Vec<u8>), CommandError> {
    let (weights, aggregate, _) = parse_zset_algebra_options(argv, start, numkeys, false)?;
    Ok((weights, aggregate))
}

fn parse_zset_algebra_options(
    argv: &[Vec<u8>],
    start: usize,
    numkeys: usize,
    allow_withscores: bool,
) -> Result<(Vec<f64>, Vec<u8>, bool), CommandError> {
    let mut weights: Vec<f64> = vec![1.0; numkeys];
    let mut aggregate: Vec<u8> = b"SUM".to_vec();
    let mut withscores = false;
    let mut i = start;
    while i < argv.len() {
        let kw = std::str::from_utf8(&argv[i]).map_err(|_| CommandError::InvalidUtf8Argument)?;
        if kw.eq_ignore_ascii_case("WEIGHTS") {
            i += 1;
            if i + numkeys > argv.len() {
                return Err(CommandError::SyntaxError);
            }
            // Upstream t_zset.c::zunionInterDiffGenericCommand emits
            // "ERR weight value is not a float" for both
            // unparseable and NaN weights. (br-frankenredis-uczv)
            let bad_weight = || CommandError::Custom("ERR weight value is not a float".to_string());
            for slot in weights.iter_mut().take(numkeys) {
                let w = std::str::from_utf8(&argv[i])
                    .map_err(|_| bad_weight())?
                    .trim()
                    .parse::<f64>()
                    .map_err(|_| bad_weight())?;
                if w.is_nan() {
                    return Err(bad_weight());
                }
                *slot = w;
                i += 1;
            }
        } else if kw.eq_ignore_ascii_case("AGGREGATE") {
            i += 1;
            if i >= argv.len() {
                return Err(CommandError::SyntaxError);
            }
            if argv[i].eq_ignore_ascii_case(b"SUM") {
                aggregate = b"SUM".to_vec();
            } else if argv[i].eq_ignore_ascii_case(b"MIN") {
                aggregate = b"MIN".to_vec();
            } else if argv[i].eq_ignore_ascii_case(b"MAX") {
                aggregate = b"MAX".to_vec();
            } else {
                return Err(CommandError::SyntaxError);
            }
            i += 1;
        } else if allow_withscores && kw.eq_ignore_ascii_case("WITHSCORES") {
            withscores = true;
            i += 1;
        } else {
            return Err(CommandError::SyntaxError);
        }
    }
    Ok((weights, aggregate, withscores))
}

fn zunionstore(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZUNIONSTORE"));
    }
    let dest = &argv[1];
    let numkeys_val = parse_i64_arg(&argv[2])?;
    // (frankenredis-zstoreneg) Upstream t_zset.c::zunionInterDiffGenericCommand
    // gates on `setnum < 1` after a successful getLongFromObjectOrReply, so
    // a negative count surfaces the dedicated 'at least 1 input key is
    // needed' wording — not the generic out-of-range envelope. fr was
    // splitting the check and emitting CommandError::InvalidInteger for
    // negative numkeys, diverging from vendored 7.2.4 for ZUNIONSTORE -1.
    if numkeys_val < 1 {
        return Ok(RespFrame::Error(
            "ERR at least 1 input key is needed for 'zunionstore' command".to_string(),
        ));
    }
    let numkeys = usize::try_from(numkeys_val).map_err(|_| CommandError::InvalidInteger)?;
    if argv.len() < 3_usize.saturating_add(numkeys) {
        return Err(CommandError::SyntaxError);
    }
    let keys: Vec<&[u8]> = argv[3..3 + numkeys].iter().map(|v| v.as_slice()).collect();
    // (frankenredis-zsetop-wrongtype) Upstream zunionInterDiffGenericCommand
    // reads + type-checks every source key (ZSET/SET ok, else WRONGTYPE) at
    // t_zset.c:2603-2621 BEFORE parsing the WEIGHTS/AGGREGATE options at :2623,
    // so a wrong-type source key surfaces WRONGTYPE ahead of any option syntax
    // error. (The numkeys-overflow syntax check still precedes the type-check.)
    for &key in &keys {
        // (frankenredis-6f2f5) Store::zunionstore never records keyspace
        // hits/misses for its source keys, so the lookupKeyRead per key is
        // recorded here — before the type check, matching upstream's
        // lookup-then-checkType order so a wrong-type key still counts as a hit.
        let _ = store.exists_no_touch(key, now_ms);
        store.ensure_zset_or_set_source(key, now_ms)?;
    }
    let (weights, aggregate) = parse_zstore_args(argv, 3 + numkeys, numkeys)?;
    let count = store
        .zunionstore(dest, &keys, &weights, &aggregate, now_ms)
        .map_err(CommandError::Store)?;
    Ok(RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)))
}

fn zinterstore(
    argv: &[Vec<u8>],
    store: &mut Store,
    now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 4 {
        return Err(CommandError::WrongArity("ZINTERSTORE"));
    }
    let dest = &argv[1];
    let numkeys_val = parse_i64_arg(&argv[2])?;
    // (frankenredis-zstoreneg) See zunionstore() above for rationale.
    if numkeys_val < 1 {
        return Ok(RespFrame::Error(
            "ERR at least 1 input key is needed for 'zinterstore' command".to_string(),
        ));
    }
    let numkeys = usize::try_from(numkeys_val).map_err(|_| CommandError::InvalidInteger)?;
    if argv.len() < 3_usize.saturating_add(numkeys) {
        return Err(CommandError::SyntaxError);
    }
    let keys: Vec<&[u8]> = argv[3..3 + numkeys].iter().map(|v| v.as_slice()).collect();
    // (frankenredis-zsetop-wrongtype) Source-key type-check precedes the
    // WEIGHTS/AGGREGATE option parse — see zunionstore().
    for &key in &keys {
        // (frankenredis-6f2f5) Record the per-key lookupKeyRead before the type
        // check (Store::zinterstore doesn't), matching upstream's order.
        let _ = store.exists_no_touch(key, now_ms);
        store.ensure_zset_or_set_source(key, now_ms)?;
    }
    let (weights, aggregate) = parse_zstore_args(argv, 3 + numkeys, numkeys)?;
    let count = store
        .zinterstore(dest, &keys, &weights, &aggregate, now_ms)
        .map_err(CommandError::Store)?;
    Ok(RespFrame::Integer(i64::try_from(count).unwrap_or(i64::MAX)))
}

// ── Server / connection commands ──────────────────────────────────────

fn quit(argv: &[Vec<u8>], store: &Store) -> Result<RespFrame, CommandError> {
    // (frankenredis-quitarity) Upstream commands.def declares QUIT with
    // arity = -1 (argc >= 1 is accepted) and networking.c::quitCommand
    // ignores any trailing arguments — `QUIT garbage extra` returns OK
    // in vendored Redis 7.2.4. fr previously hardcoded an exact-arity
    // check and rejected extra args.
    if argv.is_empty() {
        return Err(CommandError::WrongArity("QUIT"));
    }
    if store.script_nesting_level >= 1 {
        return Err(script_noscript_command_error());
    }
    Ok(RespFrame::SimpleString("OK".to_string()))
}

fn select(argv: &[Vec<u8>], store: &mut Store) -> Result<RespFrame, CommandError> {
    if argv.len() != 2 {
        return Err(CommandError::WrongArity("SELECT"));
    }
    let db = parse_i64_arg(&argv[1])?;
    // (frankenredis-wal9t) Upstream uses getIntFromObjectOrReply
    // (i32-narrowed) for the DB index; values outside i32 surface
    // the generic i32-range message, not the per-command
    // "DB index is out of range" wording.
    if i32::try_from(db).is_err() {
        return Ok(RespFrame::Error(
            "ERR value is out of range, value must between -2147483648 and 2147483647".to_string(),
        ));
    }
    let Ok(db_index) = usize::try_from(db) else {
        return Ok(RespFrame::Error("ERR DB index is out of range".to_string()));
    };
    // Upstream db.c::selectCommand:762-765 rejects SELECT N (N != 0)
    // when cluster_enabled is true — cluster mode only uses DB 0.
    // (frankenredis-8qgk7)
    if store.cluster_enabled && db_index != 0 {
        return Ok(RespFrame::Error(
            "ERR SELECT is not allowed in cluster mode".to_string(),
        ));
    }
    if db_index < store.database_count {
        store.dispatch_client_ctx.db_index = db_index;
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else {
        Ok(RespFrame::Error("ERR DB index is out of range".to_string()))
    }
}

fn format_bytes_human(bytes: usize) -> String {
    const KB: f64 = 1024.0;
    const MB: f64 = 1024.0 * 1024.0;
    const GB: f64 = 1024.0 * 1024.0 * 1024.0;
    let b = bytes as f64;
    if b >= GB {
        format!("{:.2}G", b / GB)
    } else if b >= MB {
        format!("{:.2}M", b / MB)
    } else if b >= KB {
        format!("{:.2}K", b / KB)
    } else {
        format!("{bytes}B")
    }
}

fn info(argv: &[Vec<u8>], store: &mut Store, now_ms: u64) -> Result<RespFrame, CommandError> {
    // Trigger lazy expiry for the dbsize side effect (cleans expired keys).
    let _ = store.dbsize(now_ms);
    let sections: Vec<&str> = argv[1..]
        .iter()
        .map(|arg| std::str::from_utf8(arg).map_err(|_| CommandError::InvalidUtf8Argument))
        .collect::<Result<_, _>>()?;
    let is_all = sections.is_empty()
        || sections.iter().any(|section| {
            section.eq_ignore_ascii_case("all")
                || section.eq_ignore_ascii_case("everything")
                || section.eq_ignore_ascii_case("default")
        });
    let section_requested = |name: &str| {
        is_all
            || sections
                .iter()
                .any(|section| section.eq_ignore_ascii_case(name))
    };

    let mut info = String::new();

    // Server section. Field order + names mirror upstream
    // Redis 7.2 server.c::genRedisInfoString. Adds atomicvar_api,
    // process_supervised, server_time_usec, io_threads_active,
    // listener0 fields previously missing. (br-frankenredis-infoserver)
    if section_requested("server") {
        info.push_str("# Server\r\n");
        let _ = write!(info, "redis_version:{}\r\n", fr_store::REDIS_COMPAT_VERSION);
        info.push_str("redis_git_sha1:00000000\r\n");
        info.push_str("redis_git_dirty:0\r\n");
        info.push_str("redis_build_id:0\r\n");
        // Upstream server.c::genRedisInfoString:5469-5471 selects
        // redis_mode from server flags: "cluster" when cluster_enabled,
        // "sentinel" when sentinel_mode, else "standalone". fr does
        // not track sentinel_mode so only the cluster/standalone
        // branch matters. (frankenredis-xa8u4)
        info.push_str(if store.cluster_enabled {
            "redis_mode:cluster\r\n"
        } else {
            "redis_mode:standalone\r\n"
        });
        // (frankenredis-efkwg, frankenredis-6xj9o) Upstream
        // server.c::genRedisInfoString concatenates uname struct
        // sysname + release + machine (equivalent to `uname -srm`,
        // e.g. "Linux 6.17.0-14-generic x86_64"). Read sysname and
        // release from /proc on Linux and fall back to a static
        // mapping where /proc isn't available; pair with std::env's
        // ARCH for the machine field. Defensive fallbacks keep the
        // string non-empty if any read fails.
        let os_name = format_info_os_string();
        let _ = write!(info, "os:{os_name}\r\n");
        let _ = write!(info, "arch_bits:{}\r\n", std::mem::size_of::<usize>() * 8);
        info.push_str("monotonic_clock:POSIX clock_gettime\r\n");
        // (frankenredis-ksl7m) Map fr's mio-based eventloop to the
        // syscall names upstream uses for each platform:
        //   Linux            → epoll
        //   macOS / *BSD     → kqueue
        //   Solaris          → evport
        //   Windows          → IOCP (mio uses I/O Completion Ports)
        //   Other POSIX      → select (fallback)
        let multiplexing = match std::env::consts::OS {
            "linux" | "android" => "epoll",
            "macos" | "ios" | "freebsd" | "openbsd" | "netbsd" | "dragonfly" => "kqueue",
            "solaris" | "illumos" => "evport",
            "windows" => "IOCP",
            _ => "select",
        };
        let _ = write!(info, "multiplexing_api:{multiplexing}\r\n");
        info.push_str("atomicvar_api:c11-builtin\r\n");
        info.push_str("gcc_version:0.0.0\r\n");
        let _ = write!(info, "process_id:{}\r\n", store.server_pid);
        info.push_str("process_supervised:no\r\n");
        let _ = write!(info, "run_id:{}\r\n", store.server_run_id);
        let _ = write!(info, "tcp_port:{}\r\n", store.server_port);
        let _ = write!(info, "server_time_usec:{}\r\n", now_ms.saturating_mul(1000));
        // Upstream INFO server's uptime_in_seconds reports
        // (now - server_start), not the absolute now. fr's old
        // expression `now_ms / 1000` accidentally returned the
        // Unix timestamp. (br-frankenredis-uptime)
        let uptime_s = now_ms.saturating_sub(store.server_start_ms) / 1000;
        let _ = write!(info, "uptime_in_seconds:{uptime_s}\r\n");
        let _ = write!(info, "uptime_in_days:{}\r\n", uptime_s / 86400);
        let _ = write!(info, "hz:{}\r\n", store.server_hz);
        let _ = write!(info, "configured_hz:{}\r\n", store.server_hz);
        // (frankenredis-debugobjlru) Upstream evict.c::getLRUClock:
        //   return (mstime() / LRU_CLOCK_RESOLUTION) & LRU_CLOCK_MAX
        // where LRU_CLOCK_RESOLUTION = 1000ms and LRU_CLOCK_MAX =
        // (1<<24)-1 = 0xFFFFFF. fr previously divided by 10_000
        // (10-second resolution), so INFO's lru_clock value was 10×
        // smaller than vendored's and didn't match the per-object
        // `lru:` field emitted by DEBUG OBJECT.
        let lru_clock = (now_ms / 1_000) & 0xFF_FFFF;
        let _ = write!(info, "lru_clock:{lru_clock}\r\n");
        let exe = std::env::current_exe()
            .map(|p| p.to_string_lossy().into_owned())
            .unwrap_or_else(|_| "/usr/local/bin/frankenredis".to_string());
        let _ = write!(info, "executable:{exe}\r\n");
        info.push_str("config_file:\r\n");
        info.push_str("io_threads_active:0\r\n");
        let _ = write!(
            info,
            "listener0:name=tcp,bind=*,bind=-::*,port={}\r\n",
            store.server_port
        );
        info.push_str("\r\n");
    }

    // Clients section. Field names + ordering mirror upstream
    // Redis 7.2 server.c::genRedisInfoString. Removed the
    // never-emitted-by-upstream `total_clients_connected_including_replicas`
    // field and renamed `total_blocking_clients[_on_nokey]` to
    // `total_blocking_keys[_on_nokey]`. (br-frankenredis-infoclients)
    if section_requested("clients") {
        let connected = store.stat_connected_clients.max(1); // at least 1 (the current client)
        info.push_str("# Clients\r\n");
        let _ = write!(info, "connected_clients:{connected}\r\n");
        info.push_str("cluster_connections:0\r\n");
        let _ = write!(info, "maxclients:{}\r\n", store.server_maxclients);
        // (frankenredis-jrqgd) Real recent-max read/write buffer
        // accumulators, fed by Runtime::record_client_session after
        // every handle_readable turn. Resets on CONFIG RESETSTAT.
        let _ = write!(
            info,
            "client_recent_max_input_buffer:{}\r\n",
            store.stat_clients_recent_max_input_buffer
        );
        let _ = write!(
            info,
            "client_recent_max_output_buffer:{}\r\n",
            store.stat_clients_recent_max_output_buffer
        );
        let _ = write!(info, "blocked_clients:{}\r\n", store.stat_blocked_clients);
        let _ = write!(info, "tracking_clients:{}\r\n", store.stat_tracking_clients);
        info.push_str("clients_in_timeout_table:0\r\n");
        let _ = write!(
            info,
            "total_blocking_keys:{}\r\n",
            store.stat_blocked_clients
        );
        info.push_str("total_blocking_keys_on_nokey:0\r\n");
        info.push_str("\r\n");
    }

    // Memory section
    if section_requested("memory") {
        let used_memory = store.estimate_memory_usage_bytes();
        let used_memory_human = format_bytes_human(used_memory);
        // (CrimsonHawk) Report the RSS sampled by `record_ops_sec_sample` (the
        // ~100ms event-loop tick = redis's serverCron hz=10 equivalent), instead
        // of reading the 8KB /proc/self/status on EVERY INFO. Matches upstream,
        // which reports the cron-sampled RSS. Fall back to a fresh read only
        // before the first sample (cold start), preserving peak tracking there.
        let used_memory_rss = if store.stat_used_memory_rss != 0 {
            store.stat_used_memory_rss
        } else {
            let rss = read_rss_bytes().unwrap_or(used_memory);
            store.observe_memory_sample(rss);
            rss
        };
        let used_memory_rss_human = format_bytes_human(used_memory_rss);
        let policy_str = store.maxmemory_policy.as_config_str();
        let frag_ratio = if used_memory > 0 {
            used_memory_rss as f64 / used_memory as f64
        } else {
            1.0
        };

        let peak = store.stat_used_memory_peak;
        let peak_human = format_bytes_human(peak);
        let peak_perc = if peak > 0 {
            (used_memory_rss as f64 / peak as f64) * 100.0
        } else {
            100.0
        };

        // (frankenredis-d9mxz) Compute used_memory_overhead from the
        // same component summation MEMORY STATS uses (wkglo). This is
        // upstream object.c::getMemoryOverheadData's mh->overhead_total
        // = startup + repl_backlog + clients_slaves + clients_normal +
        // cluster_links + aof_buffer + lua_caches + functions_caches
        // + per-db hashtable overheads. fr's startup/repl_backlog/
        // cluster_links/aof_buffer are all 0 currently — separate gaps.
        const DICT_ENTRY_BYTES_FOR_OVERHEAD: usize = 64;
        let mut used_memory_overhead: usize = store
            .stat_clients_replica_mem_bytes
            .saturating_add(store.stat_clients_normal_mem_bytes)
            .saturating_add(store.scripts_memory_bytes())
            .saturating_add(store.functions_memory_bytes());
        for db in 0..store.database_count {
            let keys = store.dbsize_in_db(db);
            if keys == 0 {
                continue;
            }
            let expires = store.expires_in_db(db);
            used_memory_overhead = used_memory_overhead
                .saturating_add(keys.saturating_mul(DICT_ENTRY_BYTES_FOR_OVERHEAD))
                .saturating_add(expires.saturating_mul(DICT_ENTRY_BYTES_FOR_OVERHEAD));
        }
        info.push_str("# Memory\r\n");
        let _ = write!(info, "used_memory:{used_memory}\r\n");
        let _ = write!(info, "used_memory_human:{used_memory_human}\r\n");
        let _ = write!(info, "used_memory_rss:{used_memory_rss}\r\n");
        let _ = write!(info, "used_memory_rss_human:{used_memory_rss_human}\r\n");
        let _ = write!(info, "used_memory_peak:{peak}\r\n");
        let _ = write!(info, "used_memory_peak_human:{peak_human}\r\n");
        let _ = write!(info, "used_memory_peak_perc:{peak_perc:.2}%\r\n");
        let _ = write!(info, "used_memory_overhead:{used_memory_overhead}\r\n");
        info.push_str("used_memory_startup:0\r\n");
        // (frankenredis-d9mxz) fr's `used_memory` = estimate_memory_usage_bytes
        // is the *dataset-only* accounting (hand-counted bytes for keys
        // + value structures). Upstream's used_memory is total heap
        // allocation including overhead, so upstream computes
        // dataset = used_memory - overhead. fr's used_memory IS
        // dataset, so used_memory_dataset == used_memory and the perc
        // is 100% by definition. This intentional divergence keeps
        // fr's other accounting (MEMORY USAGE etc.) coherent — exact
        // total-heap accounting would require a jemalloc/mimalloc
        // sampler that #![forbid(unsafe_code)] blocks.
        let _ = write!(info, "used_memory_dataset:{used_memory}\r\n");
        info.push_str("used_memory_dataset_perc:100.00%\r\n");
        // (frankenredis-fqwyf) maxmemory/maxmemory_human/maxmemory_policy
        // are emitted later in the section per upstream
        // server.c::genRedisInfoString — right after
        // used_memory_scripts_human, just before allocator_frag_ratio.
        // Allocator-derived stats (placeholders since fr uses the
        // Rust system allocator). Upstream Redis 7.2 always emits
        // these, even with libc malloc — values are 0 / 1.0 then.
        // (br-frankenredis-infomemory)
        let _ = write!(info, "allocator_allocated:{used_memory}\r\n");
        let _ = write!(info, "allocator_active:{used_memory}\r\n");
        let _ = write!(info, "allocator_resident:{used_memory_rss}\r\n");
        // (frankenredis-totalsysmem) Upstream populates this from
        // sysconf(_SC_PHYS_PAGES) * sysconf(_SC_PAGE_SIZE). fr reads
        // /proc/meminfo MemTotal under #[forbid(unsafe_code)]. Falls
        // back to 0 / "0B" on non-Linux or parse failure.
        let total_system_memory = read_total_system_memory_bytes().unwrap_or(0);
        let _ = write!(info, "total_system_memory:{total_system_memory}\r\n");
        let _ = write!(
            info,
            "total_system_memory_human:{}\r\n",
            format_bytes_human(total_system_memory)
        );
        // (frankenredis-ymyrt) Mirror upstream eval.c::evalScriptsMemory.
        // Sum per-script sha (40 hex chars) + body bytes; dict overhead
        // is implementation-specific and skipped. used_memory_lua and
        // used_memory_scripts_eval share the same counter upstream
        // (lctx.lua_scripts_mem) — fr has only one Lua context, so
        // both lines emit the same value.
        let scripts_bytes = store.scripts_memory_bytes();
        let _ = write!(info, "used_memory_lua:{scripts_bytes}\r\n");
        info.push_str("used_memory_vm_eval:0\r\n");
        let _ = write!(
            info,
            "used_memory_lua_human:{}\r\n",
            format_bytes_human(scripts_bytes)
        );
        let _ = write!(info, "used_memory_scripts_eval:{scripts_bytes}\r\n");
        // (frankenredis-8tk8h) Mirror upstream server.c INFO memory:
        // number_of_cached_scripts = dictSize(server.lua_scripts);
        // number_of_libraries     = engineLibrariesNum();
        // number_of_functions     = sum of per-library function counts.
        let scripts_cached = store.script_count();
        let (lib_count, func_count) = store.function_stats();
        let _ = write!(info, "number_of_cached_scripts:{scripts_cached}\r\n");
        let _ = write!(info, "number_of_functions:{func_count}\r\n");
        let _ = write!(info, "number_of_libraries:{lib_count}\r\n");
        // (frankenredis-2usb3) Mirror upstream functions.c::functions
        // MemoryOverhead. Sum per-library raw code length + name +
        // description + per-function name/description/flag bytes.
        // used_memory_vm_functions == used_memory_functions in fr (one
        // engine, no separate VM heap accounting).
        let functions_bytes = store.functions_memory_bytes();
        let _ = write!(info, "used_memory_vm_functions:{functions_bytes}\r\n");
        info.push_str("used_memory_vm_total:0\r\n");
        info.push_str("used_memory_vm_total_human:0B\r\n");
        let _ = write!(info, "used_memory_functions:{functions_bytes}\r\n");
        // (frankenredis-ymyrt) used_memory_scripts mirrors upstream's
        // mh->lua_caches = evalScriptsMemory(). Same source as
        // used_memory_lua above.
        let _ = write!(info, "used_memory_scripts:{scripts_bytes}\r\n");
        let _ = write!(
            info,
            "used_memory_scripts_human:{}\r\n",
            format_bytes_human(scripts_bytes)
        );
        // (frankenredis-fqwyf) Upstream emits the maxmemory triple
        // here, between used_memory_scripts_human and the
        // allocator_frag_ratio block.
        let maxmemory = store.maxmemory_bytes_live;
        let _ = write!(info, "maxmemory:{maxmemory}\r\n");
        let _ = write!(
            info,
            "maxmemory_human:{}\r\n",
            format_bytes_human(maxmemory)
        );
        let _ = write!(info, "maxmemory_policy:{policy_str}\r\n");
        // (frankenredis-ngoap) Vendored Redis 7.2.4 INFO memory does
        // not include maxmemory_desired{,_human} or
        // maxmemory_reservation{,_human} — these were fr-specific
        // extensions that broke field-name parity. Removed so the INFO
        // memory section field set matches vendored exactly.
        info.push_str("allocator_frag_ratio:1.00\r\n");
        info.push_str("allocator_frag_bytes:0\r\n");
        info.push_str("allocator_rss_ratio:1.00\r\n");
        info.push_str("allocator_rss_bytes:0\r\n");
        info.push_str("rss_overhead_ratio:1.00\r\n");
        info.push_str("rss_overhead_bytes:0\r\n");
        let _ = write!(info, "mem_fragmentation_ratio:{frag_ratio:.2}\r\n");
        info.push_str("mem_fragmentation_bytes:0\r\n");
        info.push_str("mem_not_counted_for_evict:0\r\n");
        let _ = write!(
            info,
            "mem_replication_backlog:{}\r\n",
            store.mem_replication_backlog
        );
        // mem_total_replication_buffers = backlog + per-replica output buffers.
        // Currently only tracks backlog; replica output buffers aren't measured.
        let _ = write!(
            info,
            "mem_total_replication_buffers:{}\r\n",
            store.mem_replication_backlog
        );
        // (frankenredis-d9mxz) Mirror the same per-client buffer
        // summation MEMORY STATS uses (zfu61). Vendored emits 0 for
        // mem_clients_slaves when no replicas are attached.
        let _ = write!(
            info,
            "mem_clients_slaves:{}\r\n",
            store.stat_clients_replica_mem_bytes
        );
        let _ = write!(
            info,
            "mem_clients_normal:{}\r\n",
            store.stat_clients_normal_mem_bytes
        );
        info.push_str("mem_cluster_links:0\r\n");
        info.push_str("mem_aof_buffer:0\r\n");
        info.push_str("mem_allocator:rust-alloc\r\n");
        info.push_str("active_defrag_running:0\r\n");
        info.push_str("lazyfree_pending_objects:0\r\n");
        info.push_str("lazyfreed_objects:0\r\n");
        info.push_str("\r\n");
    }

    // Persistence section
    if section_requested("persistence") {
        info.push_str("# Persistence\r\n");
        info.push_str("loading:0\r\n");
        info.push_str("async_loading:0\r\n");
        info.push_str("current_cow_peak:0\r\n");
        info.push_str("current_cow_size:0\r\n");
        info.push_str("current_cow_size_age:0\r\n");
        info.push_str("current_fork_perc:0.00\r\n");
        info.push_str("current_save_keys_processed:0\r\n");
        info.push_str("current_save_keys_total:0\r\n");
        let _ = write!(info, "rdb_changes_since_last_save:{}\r\n", store.dirty);
        let _ = write!(
            info,
            "rdb_bgsave_in_progress:{}\r\n",
            u8::from(store.rdb_bgsave_in_progress)
        );
        let _ = write!(info, "rdb_last_save_time:{}\r\n", store.last_save_time_sec);
        let _ = write!(
            info,
            "rdb_last_bgsave_status:{}\r\n",
            if store.stat_rdb_last_bgsave_ok {
                "ok"
            } else {
                "err"
            }
        );
        let _ = write!(
            info,
            "rdb_last_bgsave_time_sec:{}\r\n",
            store
                .stat_rdb_last_bgsave_time_sec
                .map_or(-1, |ts| ts as i64)
        );
        let rdb_current_bgsave_time_sec: i64 = store
            .rdb_bgsave_start_time_sec
            .map(|start| (now_ms / 1000).saturating_sub(start) as i64)
            .unwrap_or(-1);
        let _ = write!(
            info,
            "rdb_current_bgsave_time_sec:{}\r\n",
            rdb_current_bgsave_time_sec
        );
        let _ = write!(info, "rdb_saves:{}\r\n", store.stat_rdb_saves);
        info.push_str("rdb_last_cow_size:0\r\n");
        let _ = write!(
            info,
            "rdb_last_load_keys_expired:{}\r\n",
            store.stat_rdb_last_load_keys_expired
        );
        let _ = write!(
            info,
            "rdb_last_load_keys_loaded:{}\r\n",
            store.stat_rdb_last_load_keys_loaded
        );
        let _ = write!(info, "aof_enabled:{}\r\n", usize::from(store.aof_enabled));
        let _ = write!(
            info,
            "aof_rewrite_in_progress:{}\r\n",
            u8::from(store.aof_rewrite_in_progress)
        );
        let _ = write!(
            info,
            "aof_rewrite_scheduled:{}\r\n",
            u8::from(store.aof_rewrite_scheduled)
        );
        let _ = write!(
            info,
            "aof_last_rewrite_time_sec:{}\r\n",
            store
                .stat_aof_last_rewrite_time_sec
                .map_or(-1, |ts| ts as i64)
        );
        let aof_current_rewrite_time_sec: i64 = store
            .aof_rewrite_start_time_sec
            .map(|start| (now_ms / 1000).saturating_sub(start) as i64)
            .unwrap_or(-1);
        let _ = write!(
            info,
            "aof_current_rewrite_time_sec:{}\r\n",
            aof_current_rewrite_time_sec
        );
        let _ = write!(
            info,
            "aof_last_bgrewrite_status:{}\r\n",
            if store.stat_aof_last_bgrewrite_ok {
                "ok"
            } else {
                "err"
            }
        );
        let _ = write!(
            info,
            "aof_last_write_status:{}\r\n",
            if store.stat_aof_last_write_ok {
                "ok"
            } else {
                "err"
            }
        );
        info.push_str("aof_last_cow_size:0\r\n");
        // (frankenredis-f1f8f) Live counter incremented on each
        // record_aof_rewrite() call, mirroring upstream's
        // server.aof_rewrites_count.
        let _ = write!(info, "aof_rewrites:{}\r\n", store.stat_aof_rewrites);
        info.push_str("aof_rewrites_consecutive_failures:0\r\n");
        info.push_str("module_fork_in_progress:0\r\n");
        info.push_str("module_fork_last_cow_size:0\r\n");
        info.push_str("\r\n");
    }

    // Stats section
    if section_requested("stats") {
        info.push_str("# Stats\r\n");
        let _ = write!(
            info,
            "total_connections_received:{}\r\n",
            store.stat_total_connections_received.max(1)
        );
        let _ = write!(
            info,
            "total_commands_processed:{}\r\n",
            store.stat_total_commands_processed
        );
        let _ = write!(
            info,
            "instantaneous_ops_per_sec:{}\r\n",
            store.instantaneous_ops_per_sec()
        );
        let _ = write!(
            info,
            "total_net_input_bytes:{}\r\n",
            store.stat_total_net_input_bytes
        );
        let _ = write!(
            info,
            "total_net_output_bytes:{}\r\n",
            store.stat_total_net_output_bytes
        );
        info.push_str("total_net_repl_input_bytes:0\r\n");
        info.push_str("total_net_repl_output_bytes:0\r\n");
        let _ = write!(
            info,
            "instantaneous_input_kbps:{:.2}\r\n",
            store.instantaneous_input_kbps()
        );
        let _ = write!(
            info,
            "instantaneous_output_kbps:{:.2}\r\n",
            store.instantaneous_output_kbps()
        );
        info.push_str("instantaneous_input_repl_kbps:0.00\r\n");
        info.push_str("instantaneous_output_repl_kbps:0.00\r\n");
        let _ = write!(
            info,
            "rejected_connections:{}\r\n",
            store.stat_rejected_connections
        );
        let _ = write!(info, "sync_full:{}\r\n", store.stat_sync_full);
        let _ = write!(info, "sync_partial_ok:{}\r\n", store.stat_sync_partial_ok);
        let _ = write!(info, "sync_partial_err:{}\r\n", store.stat_sync_partial_err);
        let _ = write!(info, "expired_keys:{}\r\n", store.stat_expired_keys);
        let _ = write!(
            info,
            "expired_stale_perc:{:.2}\r\n",
            store.stat_expired_stale_perc as f64
        );
        info.push_str("expired_time_cap_reached_count:0\r\n");
        let _ = write!(
            info,
            "expire_cycle_cpu_milliseconds:{}\r\n",
            store.stat_expire_cycle_cpu_milliseconds
        );
        let _ = write!(info, "evicted_keys:{}\r\n", store.stat_evicted_keys);
        info.push_str("evicted_clients:0\r\n");
        // (frankenredis-gpseq) Upstream server.c::genRedisInfoString
        // emits the eviction-time pair contiguously with the eviction
        // counters block (right after evicted_clients), not at the end
        // of the Stats section. fr previously appended both fields
        // after acl_access_denied_channel, which broke field-order
        // parity for any tool that consumes INFO Stats positionally.
        info.push_str("total_eviction_exceeded_time:0\r\n");
        info.push_str("current_eviction_exceeded_time:0\r\n");
        // (frankenredis-ngoap) total_keys_expired / total_keys_evicted
        // were fr-specific duplicates of expired_keys / evicted_keys
        // (which are already emitted above). Vendored Redis 7.2.4 has
        // no such fields; removed for INFO stats field-set parity.
        let _ = write!(info, "keyspace_hits:{}\r\n", store.stat_keyspace_hits);
        let _ = write!(info, "keyspace_misses:{}\r\n", store.stat_keyspace_misses);
        let _ = write!(
            info,
            "pubsub_channels:{}\r\n",
            store.subscribed_channels.len()
        );
        let _ = write!(
            info,
            "pubsub_patterns:{}\r\n",
            store.subscribed_patterns.len()
        );
        // (frankenredis-ngoap) Upstream Redis 7.2.4 emits ONLY
        // 'pubsubshard_channels' — the underscore-after-pubsub spelling
        // 'pubsub_shardchannels' is fr-specific and was emitted as a
        // duplicate. Removed; the canonical line stays.
        let _ = write!(
            info,
            "pubsubshard_channels:{}\r\n",
            store.subscribed_shard_channels.len()
        );
        info.push_str("latest_fork_usec:0\r\n");
        info.push_str("total_forks:0\r\n");
        info.push_str("migrate_cached_sockets:0\r\n");
        info.push_str("slave_expires_tracked_keys:0\r\n");
        info.push_str("active_defrag_hits:0\r\n");
        info.push_str("active_defrag_misses:0\r\n");
        info.push_str("active_defrag_key_hits:0\r\n");
        info.push_str("active_defrag_key_misses:0\r\n");
        info.push_str("total_active_defrag_time:0\r\n");
        info.push_str("current_active_defrag_time:0\r\n");
        let _ = write!(
            info,
            "tracking_total_keys:{}\r\n",
            store.stat_tracking_total_keys
        );
        let _ = write!(
            info,
            "tracking_total_items:{}\r\n",
            store.stat_tracking_total_items
        );
        let _ = write!(
            info,
            "tracking_total_prefixes:{}\r\n",
            store.stat_tracking_total_prefixes
        );
        let _ = write!(
            info,
            "unexpected_error_replies:{}\r\n",
            store.stat_unexpected_error_replies
        );
        let _ = write!(
            info,
            "total_error_replies:{}\r\n",
            store.stat_total_error_replies
        );
        info.push_str("dump_payload_sanitizations:0\r\n");
        let _ = write!(
            info,
            "total_reads_processed:{}\r\n",
            store.stat_total_reads_processed
        );
        let _ = write!(
            info,
            "total_writes_processed:{}\r\n",
            store.stat_total_writes_processed
        );
        info.push_str("io_threaded_reads_processed:0\r\n");
        info.push_str("io_threaded_writes_processed:0\r\n");
        info.push_str("reply_buffer_shrinks:0\r\n");
        info.push_str("reply_buffer_expands:0\r\n");
        let _ = write!(info, "eventloop_cycles:{}\r\n", store.stat_eventloop_cycles);
        let _ = write!(
            info,
            "eventloop_duration_sum:{}\r\n",
            store.stat_eventloop_duration_sum_usec
        );
        let _ = write!(
            info,
            "eventloop_duration_cmd_sum:{}\r\n",
            store.eventloop_duration_cmd_sum_usec()
        );
        let _ = write!(
            info,
            "instantaneous_eventloop_cycles_per_sec:{}\r\n",
            store.instantaneous_eventloop_cycles_per_sec()
        );
        let _ = write!(
            info,
            "instantaneous_eventloop_duration_usec:{}\r\n",
            store.instantaneous_eventloop_duration_usec()
        );
        let _ = write!(
            info,
            "acl_access_denied_auth:{}\r\n",
            store.stat_acl_access_denied_auth
        );
        let _ = write!(
            info,
            "acl_access_denied_cmd:{}\r\n",
            store.stat_acl_access_denied_cmd
        );
        let _ = write!(
            info,
            "acl_access_denied_key:{}\r\n",
            store.stat_acl_access_denied_key
        );
        let _ = write!(
            info,
            "acl_access_denied_channel:{}\r\n",
            store.stat_acl_access_denied_channel
        );
        info.push_str("\r\n");
    }

    // Replication section
    if section_requested("replication") {
        info.push_str("# Replication\r\n");
        info.push_str("role:master\r\n");
        info.push_str("connected_slaves:0\r\n");
        info.push_str("master_failover_state:no-failover\r\n");
        let _ = write!(info, "master_replid:{}\r\n", store.server_run_id);
        info.push_str("master_replid2:0000000000000000000000000000000000000000\r\n");
        info.push_str("master_repl_offset:0\r\n");
        info.push_str("second_repl_offset:-1\r\n");
        info.push_str("repl_backlog_active:0\r\n");
        let _ = write!(
            info,
            "repl_backlog_size:{}\r\n",
            store.server_repl_backlog_size
        );
        info.push_str("repl_backlog_first_byte_offset:0\r\n");
        info.push_str("repl_backlog_histlen:0\r\n");
        info.push_str("\r\n");
    }

    // CPU section
    if section_requested("cpu") {
        let (used_cpu_user, used_cpu_sys) = read_cpu_times();
        info.push_str("# CPU\r\n");
        let _ = write!(info, "used_cpu_sys:{used_cpu_sys:.6}\r\n");
        let _ = write!(info, "used_cpu_user:{used_cpu_user:.6}\r\n");
        info.push_str("used_cpu_sys_children:0.000000\r\n");
        info.push_str("used_cpu_user_children:0.000000\r\n");
        let _ = write!(info, "used_cpu_sys_main_thread:{used_cpu_sys:.6}\r\n");
        let _ = write!(info, "used_cpu_user_main_thread:{used_cpu_user:.6}\r\n");
        info.push_str("\r\n");
    }

    // Modules section
    if section_requested("modules") {
        info.push_str("# Modules\r\n");
        info.push_str("\r\n");
    }

    // Errorstats section
    if section_requested("errorstats") {
        // Upstream server.c::genRedisInfoString:6178-6191 emits one
        // 'errorstat_<CODE>:count=<N>' line per error code that has a
        // non-zero counter, sorted by code (lex). The counters are
        // populated by server.c::incrementErrorCount keyed on the
        // leading whitespace-delimited token of each error reply.
        // (frankenredis-errorstatslines)
        info.push_str("# Errorstats\r\n");
        let mut codes: Vec<(&String, &u64)> = store
            .errorstats_per_type
            .iter()
            .filter(|(_, count)| **count > 0)
            .collect();
        codes.sort_by(|a, b| a.0.cmp(b.0));
        for (code, count) in codes {
            let _ = write!(info, "errorstat_{code}:count={count}\r\n");
        }
        info.push_str("\r\n");
    }

    // Cluster section
    if section_requested("cluster") {
        info.push_str("# Cluster\r\n");
        // Upstream server.c::genRedisInfoString reports cluster_enabled
        // from server.cluster_enabled; fr previously hardcoded 0 so a
        // cluster-mode instance still showed cluster_enabled:0.
        // (frankenredis-5w0rd)
        info.push_str(if store.cluster_enabled {
            "cluster_enabled:1\r\n"
        } else {
            "cluster_enabled:0\r\n"
        });
        info.push_str("\r\n");
    }

    // Keyspace section — report per-database stats like Redis
    if section_requested("keyspace") {
        info.push_str("# Keyspace\r\n");
        for db in 0..store.database_count {
            let keys = store.dbsize_in_db(db);
            if keys > 0 {
                let expires = store.expires_in_db(db);
                let avg_ttl = store.avg_ttl_in_db(db, now_ms);
                let _ = write!(
                    info,
                    "db{db}:keys={keys},expires={expires},avg_ttl={avg_ttl}\r\n"
                );
            }
        }
        info.push_str("\r\n");
    }

    // RESP3 clients expect verbatim string for INFO output
    if store.dispatch_client_ctx.resp_protocol_version == 3 {
        Ok(RespFrame::Verbatim(info))
    } else {
        Ok(RespFrame::BulkString(Some(info.into_bytes())))
    }
}

