fn is_key_argument_position(
    position: i64,
    argc_without_command: i64,
    first_key: i64,
    last_key: i64,
    step: i64,
) -> bool {
    if first_key <= 0 || step <= 0 {
        return false;
    }
    let actual_last = if last_key < 0 {
        argc_without_command + last_key
    } else {
        last_key
    };
    position >= first_key && position <= actual_last && (position - first_key) % step == 0
}

fn command_group_for_docs(name: &str, flags: &str) -> &'static str {
    // (frankenredis-bpf4q) For subcommands like "cluster|addslots", the
    // upstream `group` is inherited from the parent. Recurse on the
    // parent so per-subcommand DOCS entries land in the right group.
    if let Some((parent, _)) = name.split_once('|') {
        return command_group_for_docs(parent, flags);
    }
    let flag_list: Vec<&str> = flags.split_whitespace().collect();
    // (frankenredis-cmddocgrp) Differential probe vs vendored 7.2.4
    // exposed several mis-classifications driven by name.starts_with('s'):
    //   SET / SETEX / SETNX / SETRANGE / STRLEN / SUBSTR were "set" in fr,
    //     "string" upstream;
    //   SETBIT was "set" in fr, "bitmap" upstream (the
    //     `name.starts_with("bit")` arm came AFTER the s-prefix arm so
    //     never fired for setbit);
    //   SELECT was "generic" in fr, "connection" upstream;
    //   SWAPDB was "generic" in fr, "server" upstream;
    //   SENTINEL is intentionally not enumerated upstream (returns no
    //     COMMAND DOCS entry), so dropping it from the server list is
    //     wire-compatible.
    // Enumerate the affected commands explicitly BEFORE the prefix
    // heuristics so each lands in the correct upstream group.
    // (frankenredis-commandflagsaudit) Group classification was
    // previously driven by the COMMAND_TABLE flags column ("scripting",
    // "pubsub"). Those tags were not real CMD_* flags upstream — they
    // were ACL category names that fr stuffed into the flags slot —
    // so cleaning the flags column to match `redis-cli COMMAND INFO`
    // had to come with an explicit name-based group rule here.
    if matches!(
        name,
        "eval"
            | "evalsha"
            | "eval_ro"
            | "evalsha_ro"
            | "fcall"
            | "fcall_ro"
            | "script"
            | "function"
    ) {
        "scripting"
    } else if flag_list.contains(&"pubsub")
        || matches!(
            name,
            "subscribe"
                | "unsubscribe"
                | "psubscribe"
                | "punsubscribe"
                | "ssubscribe"
                | "sunsubscribe"
                | "publish"
                | "spublish"
                | "pubsub"
        )
    {
        "pubsub"
    } else if matches!(name, "multi" | "exec" | "discard" | "watch" | "unwatch") {
        "transactions"
    } else if matches!(
        name,
        "auth" | "hello" | "quit" | "reset" | "client" | "echo" | "ping" | "select"
    ) {
        "connection"
    } else if matches!(name, "cluster" | "asking" | "readonly" | "readwrite") {
        "cluster"
    } else if matches!(
        name,
        "config"
            | "acl"
            | "save"
            | "bgsave"
            | "bgrewriteaof"
            | "shutdown"
            | "lastsave"
            | "monitor"
            | "slowlog"
            | "debug"
            | "latency"
            | "role"
            | "info"
            | "command"
            | "module"
            | "failover"
            | "replconf"
            | "psync"
            | "sync"
            | "replicaof"
            | "slaveof"
            | "swapdb"
            // (frankenredis-7wcuq) Upstream commands/*.json places these
            // in the `server` group rather than where fr's previous
            // prefix/catch-all heuristics routed them:
            //   memory, dbsize, flushdb, flushall — were "generic" pre-fix
            //   time, restore-asking, lolwut — were prefix/catch-all
            | "memory"
            | "dbsize"
            | "flushdb"
            | "flushall"
            | "time"
            | "restore-asking"
            | "lolwut"
    ) {
        "server"
    } else if matches!(
        name,
        "expire"
            | "pexpire"
            | "expireat"
            | "pexpireat"
            | "persist"
            | "ttl"
            | "pttl"
            | "expiretime"
            | "pexpiretime"
            | "keys"
            | "randomkey"
            | "scan"
            | "type"
            | "rename"
            | "renamenx"
            | "move"
            | "copy"
            | "dump"
            | "restore"
            | "unlink"
            | "touch"
            | "sort"
            | "sort_ro"
            | "object"
            // (frankenredis-5ozae) DEL and EXISTS are upstream-classified
            // "generic", not the catch-all→string fallback.
            | "del"
            | "exists"
            // (frankenredis-7wcuq) WAIT/WAITAOF and MIGRATE are upstream
            // "generic", not "server" or the catch-all "string".
            | "wait"
            | "waitaof"
            | "migrate"
    ) {
        "generic"
    } else if matches!(
        name,
        "set" | "setex" | "setnx" | "setrange" | "strlen" | "substr"
            // (frankenredis-7wcuq) LCS starts with 'l' so the prefix
            // arm below would route it to "list" — upstream classifies
            // it as "string" (longest common subsequence on two strings).
            | "lcs"
    ) {
        // s-prefix string commands — must come before the s-prefix→set
        // heuristic below.
        "string"
    } else if matches!(name, "setbit" | "getbit") || name.starts_with("bit") {
        // Likewise setbit must beat the s-prefix arm, and getbit needs
        // an explicit match because it doesn't start with "bit".
        "bitmap"
    } else if name.starts_with('h') {
        "hash"
    } else if name.starts_with('l')
        || matches!(
            name,
            "blpop" | "brpop" | "blmove" | "blmpop" | "brpoplpush"
                // (frankenredis-7wcuq) The r-prefix list commands have
                // no explicit prefix arm so were falling to "string".
                | "rpush"
                | "rpushx"
                | "rpop"
                | "rpoplpush"
        )
    {
        "list"
    } else if name.starts_with('s') {
        "set"
    } else if name.starts_with('z') || matches!(name, "bzpopmin" | "bzpopmax" | "bzmpop") {
        "sorted-set"
    } else if name.starts_with('x') {
        "stream"
    } else if name.starts_with("geo") {
        "geo"
    } else if name.starts_with("pf") {
        "hyperloglog"
    } else {
        "string"
    }
}

fn command_group_summary_prefix(group: &str) -> &'static str {
    match group {
        "connection" => "Connection-management",
        "transactions" => "Transaction-control",
        "sorted-set" => "Sorted-set",
        _ => {
            if group.is_empty() {
                "General"
            } else {
                match group {
                    "string" => "String",
                    "generic" => "Generic",
                    "server" => "Server",
                    "hash" => "Hash",
                    "list" => "List",
                    "set" => "Set",
                    "stream" => "Stream",
                    "geo" => "Geo",
                    "bitmap" => "Bitmap",
                    "hyperloglog" => "HyperLogLog",
                    "pubsub" => "Pub/sub",
                    "scripting" => "Scripting",
                    "cluster" => "Cluster",
                    _ => "General",
                }
            }
        }
    }
}

fn command_getkeysandflags_flags(flags: &str) -> &'static [&'static str] {
    let flag_list: Vec<&str> = flags.split_whitespace().collect();
    if flag_list.contains(&"readonly") {
        &["RO", "access"]
    } else if flag_list.contains(&"write") {
        &["RW", "access", "update"]
    } else {
        &["access"]
    }
}

fn config_cmd(
    argv: &[Vec<u8>],
    store: &mut Store,
    _now_ms: u64,
) -> Result<RespFrame, CommandError> {
    if argv.len() < 2 {
        return Err(CommandError::WrongArity("CONFIG"));
    }
    let sub = std::str::from_utf8(&argv[1]).map_err(|_| CommandError::InvalidUtf8Argument)?;
    if sub.eq_ignore_ascii_case("GET") {
        if argv.len() < 3 {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: sub.to_string(),
            });
        }
        // Upstream commands.def declares config|get with CMD_NOSCRIPT
        // (line 6530). fr previously ran CONFIG GET from script
        // contexts and returned the config values. (frankenredis-cfgsc)
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        // (frankenredis-2ribk) Upstream config.c::configGetCommand
        // iterates the parameters dict once and emits any param that
        // matches any of the supplied glob patterns, deduping by name.
        // fr was emitting in user-arg order (e.g. CONFIG GET maxmemory
        // timeout returned in that order), but vendored is consistent
        // regardless of arg order because it walks its own dict. Match
        // the order-independence by emitting each parameter at most
        // once in the canonical (registry) order.
        let mut patterns: Vec<String> = Vec::with_capacity(argv.len() - 2);
        for arg in &argv[2..] {
            let raw_pattern =
                std::str::from_utf8(arg).map_err(|_| CommandError::InvalidUtf8Argument)?;
            patterns.push(raw_pattern.to_ascii_lowercase());
        }
        let mut entries = Vec::new();
        let mut seen: std::collections::HashSet<String> = std::collections::HashSet::new();
        config_collect_store_entries_multi(&patterns, store, &mut entries, &mut seen);
        Ok(RespFrame::Array(Some(entries)))
    } else if sub.eq_ignore_ascii_case("SET") {
        if argv.len() < 4 {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: sub.to_string(),
            });
        }
        // Upstream config.c::configSetCommand line 819-821 routes
        // odd-arity (`c->argc & 1`) through addReplyErrorObject with
        // shared.syntaxerr — i.e. 'ERR syntax error', distinct from
        // the table-level wrong-arity reply emitted for argv.len()
        // < 4. Differential probe vs vendored 7.2.4 confirmed the
        // wording: `CONFIG SET maxmemory 0 extra` (5 args) surfaces
        // 'ERR syntax error', not 'wrong number of arguments for
        // config|set command'. (frankenredis-cfgsetodd)
        if !argv.len().is_multiple_of(2) {
            return Err(CommandError::SyntaxError);
        }
        // Upstream commands.def declares config|set with CMD_NOSCRIPT
        // (line 6534). (frankenredis-cfgsc)
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        config_apply_store_sets(&argv[2..], store)?;
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("RESETSTAT") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: sub.to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        store.reset_info_stats();
        Ok(RespFrame::SimpleString("OK".to_string()))
    } else if sub.eq_ignore_ascii_case("REWRITE") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: sub.to_string(),
            });
        }
        if store.script_nesting_level >= 1 {
            return Err(script_noscript_command_error());
        }
        Err(CommandError::Custom(
            "ERR The server is running without a config file".to_string(),
        ))
    } else if sub.eq_ignore_ascii_case("HELP") {
        if argv.len() != 2 {
            return Err(CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: "HELP".to_string(),
            });
        }
        // (frankenredis-kuthf) Mirror upstream config.c::configHelpCommand
        // (vendored Redis 7.2.4) line-for-line. Frames are SimpleString
        // (was BulkString) and the body uses upstream's single-pattern
        // / single-directive wording (the multi-arg forms are runtime
        // capabilities, not part of the 7.2.4 HELP text).
        Ok(RespFrame::Array(Some(vec![
            hello_simple("CONFIG <subcommand> [<arg> [value] [opt] ...]. Subcommands are:"),
            hello_simple("GET <pattern>"),
            hello_simple(
                "    Return parameters matching the glob-like <pattern> and their values.",
            ),
            hello_simple("SET <directive> <value>"),
            hello_simple("    Set the configuration <directive> to <value>."),
            hello_simple("RESETSTAT"),
            hello_simple("    Reset statistics reported by the INFO command."),
            hello_simple("REWRITE"),
            hello_simple("    Rewrite the configuration file."),
            hello_simple("HELP"),
            hello_simple("    Print this help."),
        ])))
    } else {
        Err(CommandError::UnknownSubcommand {
            command: "CONFIG",
            subcommand: sub.to_string(),
        })
    }
}

