    #[test]
    fn acl_enforces_command_and_key_restrictions_on_direct_dispatch_7ymk5() {
        // (frankenredis-7ymk5) Direct (non-Lua) commands must honour the
        // authenticated user's ACL command/key permissions. The previous
        // gate scoped the check to script_nesting_level >= 1, so an alice-
        // like user with limited perms could run arbitrary commands.
        use fr_store::{AclKeyPattern, DispatchAclPermissions, DispatchClientContext};
        let mut store = Store::new();

        // Build a permissions snapshot for an alice-like user: only GET
        // on keys matching k*.
        let mut allowed = std::collections::HashSet::new();
        allowed.insert("get".to_string());
        store.dispatch_client_ctx = DispatchClientContext {
            authenticated_user: b"alice".to_vec(),
            acl_permissions: Some(DispatchAclPermissions {
                all_commands: false,
                allowed_commands: allowed,
                denied_commands: Default::default(),
                allowed_categories: Default::default(),
                denied_categories: Default::default(),
                key_patterns: vec![AclKeyPattern {
                    pattern: b"k*".to_vec(),
                    read: true,
                    write: true,
                }],
                all_keys: false,
                channel_patterns: vec![],
                all_channels: false,
                selectors: vec![],
            }),
            ..Default::default()
        };

        // SET (not in allowed_commands) — denied with NOPERM command.
        let err = dispatch_argv(
            &[b"SET".to_vec(), b"k1".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect_err("SET denied");
        match err {
            CommandError::Custom(msg) => assert!(
                msg.contains("NOPERM User alice has no permissions to run the 'set' command"),
                "{msg}"
            ),
            other => panic!("expected NOPERM command, got {other:?}"),
        }

        // GET on an allowed-key-pattern key — succeeds (returns nil).
        let r =
            dispatch_argv(&[b"GET".to_vec(), b"k1".to_vec()], &mut store, 0).expect("GET allowed");
        assert!(matches!(r, RespFrame::BulkString(None)));

        // GET on a key outside the allowed pattern — NOPERM key.
        let err = dispatch_argv(&[b"GET".to_vec(), b"notallowed".to_vec()], &mut store, 0)
            .expect_err("GET denied key");
        match err {
            CommandError::Custom(msg) => {
                assert!(
                    msg.contains("NOPERM No permissions to access a key"),
                    "{msg}"
                )
            }
            other => panic!("expected NOPERM key, got {other:?}"),
        }

        // Switch to the default user (all_commands=true, all_keys=true);
        // every command must pass.
        store.dispatch_client_ctx = DispatchClientContext {
            authenticated_user: b"default".to_vec(),
            acl_permissions: Some(DispatchAclPermissions {
                all_commands: true,
                all_keys: true,
                all_channels: true,
                ..Default::default()
            }),
            ..Default::default()
        };
        let r = dispatch_argv(
            &[b"SET".to_vec(), b"defaultkey".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("default SET ok");
        assert!(matches!(r, RespFrame::SimpleString(ref s) if s == "OK"));
        let r = dispatch_argv(&[b"PING".to_vec()], &mut store, 0).expect("default PING ok");
        assert_eq!(r, RespFrame::SimpleString("PONG".to_string()));
    }

    #[test]
    fn acl_dispatch_enforces_read_write_key_selector_split() {
        // (frankenredis-y40p3) The dispatch-side ACL gate — the path that
        // covers Lua-invoked `redis.call` — must honour `%R~` / `%W~` key
        // selectors: a read-only selector never satisfies a write command
        // and vice versa, even when the command itself is allowed.
        use fr_store::{AclKeyPattern, DispatchAclPermissions, DispatchClientContext};
        let mut store = Store::new();

        let allowed: std::collections::HashSet<String> =
            ["get", "set"].into_iter().map(String::from).collect();
        store.dispatch_client_ctx = DispatchClientContext {
            authenticated_user: b"sel".to_vec(),
            acl_permissions: Some(DispatchAclPermissions {
                all_commands: false,
                allowed_commands: allowed,
                denied_commands: Default::default(),
                allowed_categories: Default::default(),
                denied_categories: Default::default(),
                key_patterns: vec![
                    AclKeyPattern {
                        pattern: b"r*".to_vec(),
                        read: true,
                        write: false,
                    },
                    AclKeyPattern {
                        pattern: b"w*".to_vec(),
                        read: false,
                        write: true,
                    },
                ],
                all_keys: false,
                channel_patterns: vec![],
                all_channels: false,
                selectors: vec![],
            }),
            ..Default::default()
        };

        let expect_key_denied = |store: &mut Store, argv: &[&[u8]]| {
            let owned: Vec<Vec<u8>> = argv.iter().map(|a| a.to_vec()).collect();
            match dispatch_argv(&owned, store, 0).expect_err("key access must be denied") {
                CommandError::Custom(msg) => assert!(
                    msg.contains("NOPERM No permissions to access a key"),
                    "expected NOPERM key error, got {msg}"
                ),
                other => panic!("expected NOPERM key error, got {other:?}"),
            }
        };

        // GET on a read-only selector succeeds; SET on it is denied even
        // though `+set` is granted at the command level.
        let r = dispatch_argv(&[b"GET".to_vec(), b"r1".to_vec()], &mut store, 0)
            .expect("GET on %R selector allowed");
        assert!(matches!(r, RespFrame::BulkString(None)));
        expect_key_denied(&mut store, &[b"SET", b"r1", b"v"]);

        // SET on a write-only selector succeeds; GET on it is denied.
        let r = dispatch_argv(
            &[b"SET".to_vec(), b"w1".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("SET on %W selector allowed");
        assert!(matches!(r, RespFrame::SimpleString(ref s) if s == "OK"));
        expect_key_denied(&mut store, &[b"GET", b"w1"]);
    }

    #[test]
    fn command_info_emits_subcommands_for_all_container_parents_94zpo() {
        // (frankenredis-94zpo) Pre-fix: COMMAND INFO for container
        // commands like CLUSTER/CLIENT/CONFIG/etc. emitted an empty
        // subcommands array (slot 10), missing the per-subcommand
        // metadata that vendored emits. Verify that every container
        // parent now fans out at least one row from SUBCOMMAND_TABLE
        // (debug excluded — vendored intentionally suppresses its
        // admin-flagged subcommand fan-out).
        let mut store = Store::new();
        let containers: &[(&[u8], &[u8])] = &[
            (b"ACL", b"acl|cat"),
            (b"CLIENT", b"client|kill"),
            (b"CLUSTER", b"cluster|count-failure-reports"),
            (b"CONFIG", b"config|get"),
            (b"FUNCTION", b"function|flush"),
            (b"LATENCY", b"latency|history"),
            (b"MEMORY", b"memory|usage"),
            (b"MODULE", b"module|list"),
            (b"OBJECT", b"object|encoding"),
            (b"PUBSUB", b"pubsub|channels"),
            (b"SCRIPT", b"script|flush"),
            (b"SLOWLOG", b"slowlog|reset"),
            (b"XGROUP", b"xgroup|create"),
            (b"XINFO", b"xinfo|stream"),
            (b"COMMAND", b"command|count"),
        ];
        for (parent, expected_sub) in containers {
            let out = dispatch_argv(
                &[b"COMMAND".to_vec(), b"INFO".to_vec(), parent.to_vec()],
                &mut store,
                0,
            )
            .expect("dispatch");
            let RespFrame::Array(Some(rows)) = out else {
                panic!("COMMAND INFO {:?}: expected array", parent);
            };
            assert_eq!(rows.len(), 1, "COMMAND INFO {parent:?}: one entry per name");
            let RespFrame::Array(Some(ref entry)) = rows[0] else {
                panic!("COMMAND INFO {parent:?}: entry not array");
            };
            // Slot 9 (zero-indexed) is the subcommands array.
            let RespFrame::Array(Some(ref subs)) = entry[9] else {
                panic!("COMMAND INFO {parent:?}: subcommand slot not array");
            };
            assert!(
                !subs.is_empty(),
                "COMMAND INFO {parent:?}: subcommand slot must not be empty"
            );
            let sub_names: Vec<&[u8]> = subs
                .iter()
                .filter_map(|s| match s {
                    RespFrame::Array(Some(e)) => match e.first() {
                        Some(RespFrame::BulkString(Some(n))) => Some(n.as_slice()),
                        _ => None,
                    },
                    _ => None,
                })
                .collect();
            assert!(
                sub_names.iter().any(|n| n == expected_sub),
                "COMMAND INFO {parent:?}: expected subcommand {expected_sub:?} in {sub_names:?}",
            );
        }

        // DEBUG must continue to emit an empty subcommands slot
        // (matches upstream — admin-flagged subcommands suppressed).
        let out = dispatch_argv(
            &[b"COMMAND".to_vec(), b"INFO".to_vec(), b"DEBUG".to_vec()],
            &mut store,
            0,
        )
        .expect("dispatch debug");
        let RespFrame::Array(Some(rows)) = out else {
            panic!("COMMAND INFO DEBUG: expected array");
        };
        let RespFrame::Array(Some(ref entry)) = rows[0] else {
            panic!("COMMAND INFO DEBUG: entry not array");
        };
        let RespFrame::Array(Some(ref subs)) = entry[9] else {
            panic!("COMMAND INFO DEBUG: subcommand slot not array");
        };
        assert!(
            subs.is_empty(),
            "COMMAND INFO DEBUG: subcommand slot must be empty (vendored parity)"
        );
    }

