    #[test]
    fn randomkey_via_dispatch_only_returns_selected_db_keys() {
        // (frankenredis-bwkfm) Lua redis.call('RANDOMKEY') and AOF
        // replay route RANDOMKEY through dispatch_argv. Per-DB scope
        // must come from dispatch_client_ctx.db_index — the earlier
        // implementation called Store::randomkey() (the all-DBs
        // primitive) and Lua scripts saw key names from any other db.
        // 100 trials catches the bug deterministically; previously
        // every trial returned a foreign-db name.
        let mut store = Store::new();
        store.set(
            fr_store::encode_db_key(1, b"k1_alpha"),
            b"v1".to_vec(),
            None,
            0,
        );
        store.set(
            fr_store::encode_db_key(1, b"k1_beta"),
            b"v1b".to_vec(),
            None,
            0,
        );
        store.set(
            fr_store::encode_db_key(2, b"k2_alpha"),
            b"v2".to_vec(),
            None,
            0,
        );

        // db 0 is empty: every RANDOMKEY call must return Nil.
        for _ in 0..100 {
            let out = dispatch_argv(&[b"RANDOMKEY".to_vec()], &mut store, 0).expect("randomkey");
            assert_eq!(
                out,
                RespFrame::BulkString(None),
                "db 0 is empty; RANDOMKEY must return nil"
            );
        }

        // db 1 has 2 keys: every RANDOMKEY call must return one of
        // them as a logical name (no encode_db_key prefix bytes,
        // no k2_alpha leaking through).
        store.dispatch_client_ctx.db_index = 1;
        let allowed: std::collections::HashSet<Vec<u8>> =
            [b"k1_alpha".to_vec(), b"k1_beta".to_vec()]
                .into_iter()
                .collect();
        for _ in 0..100 {
            let out = dispatch_argv(&[b"RANDOMKEY".to_vec()], &mut store, 0).expect("randomkey");
            let RespFrame::BulkString(Some(name)) = out else {
                panic!("expected bulk string for db 1, got {out:?}"); // ubs:ignore — AI triage
            };
            assert!(
                allowed.contains(&name),
                "db 1 RANDOMKEY returned unexpected name {name:?} — must be one of k1_alpha / k1_beta"
            );
        }
    }

    #[test]
    fn dbsize_via_dispatch_only_counts_selected_db() {
        // (frankenredis-shbbv) Lua redis.call('DBSIZE'), AOF replay,
        // and MULTI/EXEC route DBSIZE through dispatch_argv. Per-DB
        // scope must come from dispatch_client_ctx.db_index — the
        // earlier implementation called Store::dbsize() (the all-DBs
        // primitive) and Lua scripts saw the global keyspace count.
        let mut store = Store::new();
        store.set(fr_store::encode_db_key(0, b"k0"), b"v0".to_vec(), None, 0);
        store.set(fr_store::encode_db_key(0, b"k0b"), b"v0b".to_vec(), None, 0);
        store.set(fr_store::encode_db_key(1, b"k1"), b"v1".to_vec(), None, 0);
        store.set(fr_store::encode_db_key(2, b"k2"), b"v2".to_vec(), None, 0);

        // Default db_index = 0 → 2 entries.
        let out = dispatch_argv(&[b"DBSIZE".to_vec()], &mut store, 0).expect("dbsize db 0");
        assert_eq!(out, RespFrame::Integer(2));

        // db 1 → 1 entry; db 2 → 1 entry; db 5 → 0.
        store.dispatch_client_ctx.db_index = 1;
        let out = dispatch_argv(&[b"DBSIZE".to_vec()], &mut store, 0).expect("dbsize db 1");
        assert_eq!(out, RespFrame::Integer(1));

        store.dispatch_client_ctx.db_index = 2;
        let out = dispatch_argv(&[b"DBSIZE".to_vec()], &mut store, 0).expect("dbsize db 2");
        assert_eq!(out, RespFrame::Integer(1));

        store.dispatch_client_ctx.db_index = 5;
        let out = dispatch_argv(&[b"DBSIZE".to_vec()], &mut store, 0).expect("dbsize db 5");
        assert_eq!(out, RespFrame::Integer(0));
    }

    #[test]
    fn keys_via_dispatch_only_returns_selected_db_keys() {
        // (frankenredis-shbbv) Companion to the DBSIZE pin. KEYS must
        // return only the logical names from the selected db, with
        // the encode_db_key prefix bytes stripped — Lua / AOF /
        // MULTI must not see foreign-db key existence.
        let mut store = Store::new();
        store.set(fr_store::encode_db_key(0, b"k0"), b"v0".to_vec(), None, 0);
        store.set(
            fr_store::encode_db_key(1, b"k1_alpha"),
            b"v1".to_vec(),
            None,
            0,
        );
        store.set(
            fr_store::encode_db_key(1, b"k1_beta"),
            b"v1b".to_vec(),
            None,
            0,
        );

        store.dispatch_client_ctx.db_index = 1;
        let out =
            dispatch_argv(&[b"KEYS".to_vec(), b"*".to_vec()], &mut store, 0).expect("keys db 1");
        let RespFrame::Array(Some(frames)) = out else {
            panic!("expected keys array"); // ubs:ignore — AI triage
        };
        let mut keys: Vec<Vec<u8>> = frames
            .into_iter()
            .map(|f| match f {
                RespFrame::BulkString(Some(b)) => b,
                other => panic!("expected bulk string, got {other:?}"), // ubs:ignore — AI triage
            })
            .collect();
        keys.sort();
        // db 1 has two keys, both surfaced as logical names — no db
        // 0's "k0" leaking through, no encode_db_key prefix bytes.
        assert_eq!(keys, vec![b"k1_alpha".to_vec(), b"k1_beta".to_vec()]);

        store.dispatch_client_ctx.db_index = 0;
        let out =
            dispatch_argv(&[b"KEYS".to_vec(), b"*".to_vec()], &mut store, 0).expect("keys db 0");
        let RespFrame::Array(Some(frames)) = out else {
            panic!("expected keys array"); // ubs:ignore — AI triage
        };
        let keys: Vec<Vec<u8>> = frames
            .into_iter()
            .map(|f| match f {
                RespFrame::BulkString(Some(b)) => b,
                other => panic!("expected bulk string, got {other:?}"), // ubs:ignore — AI triage
            })
            .collect();
        assert_eq!(keys, vec![b"k0".to_vec()]);
    }

    #[test]
    fn expired_keys_become_invisible_to_get_keys_dbsize_and_ttl() {
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"live".to_vec(), b"1".to_vec()],
            &mut store,
            0,
        )
        .expect("set live");
        dispatch_argv(
            &[
                b"SET".to_vec(),
                b"soon".to_vec(),
                b"2".to_vec(),
                b"PX".to_vec(),
                b"100".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("set soon");

        let keys_before =
            dispatch_argv(&[b"KEYS".to_vec(), b"*".to_vec()], &mut store, 0).expect("keys before");
        assert_eq!(
            keys_before,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"live".to_vec())),
                RespFrame::BulkString(Some(b"soon".to_vec())),
            ]))
        );

        let get_expired =
            dispatch_argv(&[b"GET".to_vec(), b"soon".to_vec()], &mut store, 150).expect("get");
        assert_eq!(get_expired, RespFrame::BulkString(None));

        let ttl_expired =
            dispatch_argv(&[b"TTL".to_vec(), b"soon".to_vec()], &mut store, 150).expect("ttl");
        assert_eq!(ttl_expired, RespFrame::Integer(-2));

        let keys_after =
            dispatch_argv(&[b"KEYS".to_vec(), b"*".to_vec()], &mut store, 150).expect("keys after");
        assert_eq!(
            keys_after,
            RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"live".to_vec()))]))
        );

        let dbsize_after =
            dispatch_argv(&[b"DBSIZE".to_vec()], &mut store, 150).expect("dbsize after");
        assert_eq!(dbsize_after, RespFrame::Integer(1));
    }

