    #[test]
    fn lset_lookup_and_type_check_run_before_index_parse() {
        // (frankenredis-lsetorder) Upstream t_list.c::lsetCommand:624-630
        // routes through lookupKeyWriteOrReply(shared.nokeyerr) and
        // checkType(OBJ_LIST) BEFORE getLongFromObjectOrReply for the
        // index. fr was parsing the index first, so a non-numeric
        // index on a missing key surfaced "value is not an integer
        // or out of range" instead of upstream's "ERR no such key",
        // and on a wrong-type key surfaced the same generic instead
        // of WRONGTYPE.
        let mut store = Store::new();

        // Missing key + invalid index → "ERR no such key" (lookup wins).
        let err = dispatch_argv(
            &[
                b"LSET".to_vec(),
                b"missing".to_vec(),
                b"abc".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("missing key");
        assert!(matches!(err, CommandError::NoSuchKey), "got {err:?}");

        // String key + invalid index → WRONGTYPE (type check wins).
        dispatch_argv(
            &[b"SET".to_vec(), b"s".to_vec(), b"hello".to_vec()],
            &mut store,
            0,
        )
        .expect("set");
        let err = dispatch_argv(
            &[
                b"LSET".to_vec(),
                b"s".to_vec(),
                b"abc".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("string key");
        assert!(
            matches!(err, CommandError::Store(fr_store::StoreError::WrongType)),
            "got {err:?}"
        );

        // List key + invalid index → InvalidInteger (index parse fires).
        dispatch_argv(
            &[
                b"RPUSH".to_vec(),
                b"l".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("rpush");
        let err = dispatch_argv(
            &[
                b"LSET".to_vec(),
                b"l".to_vec(),
                b"abc".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("list key bad index");
        assert!(matches!(err, CommandError::InvalidInteger), "got {err:?}");

        // List key + overflow index → InvalidInteger (parse_i64 rejects).
        let err = dispatch_argv(
            &[
                b"LSET".to_vec(),
                b"l".to_vec(),
                b"99999999999999999999".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("list key overflow index");
        assert!(matches!(err, CommandError::InvalidInteger), "got {err:?}");

        // Regression: list key + valid index still sets and returns OK.
        let out = dispatch_argv(
            &[
                b"LSET".to_vec(),
                b"l".to_vec(),
                b"0".to_vec(),
                b"newval".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("happy path");
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
    }

    #[test]
    fn lset_truncates_index_to_i32_like_upstream() {
        // (frankenredis-4zv7a) Upstream listTypeReplaceAtIndex takes a 32-bit
        // `int` index, so LSET silently truncates its parsed 64-bit index to 32
        // bits: i64::MAX -> -1 (last element), i64::MIN / 2^32 -> 0 (first), and
        // a value whose low 32 bits land out of [-len, len) is still rejected.
        let argv = |parts: &[&str]| -> Vec<Vec<u8>> {
            parts.iter().map(|p| p.as_bytes().to_vec()).collect()
        };
        let reset = |store: &mut Store| {
            dispatch_argv(&argv(&["DEL", "l"]), store, 0).unwrap();
            dispatch_argv(&argv(&["RPUSH", "l", "a", "b", "c", "d"]), store, 0).unwrap();
        };
        let lrange = |store: &mut Store| -> Vec<Vec<u8>> {
            match dispatch_argv(&argv(&["LRANGE", "l", "0", "-1"]), store, 0).unwrap() {
                RespFrame::Array(Some(items)) => items
                    .into_iter()
                    .map(|f| match f {
                        RespFrame::BulkString(Some(b)) => b,
                        other => panic!("got {other:?}"),
                    })
                    .collect(),
                other => panic!("got {other:?}"),
            }
        };
        let mut store = Store::new();

        // i64::MAX truncates to -1 -> the LAST element.
        reset(&mut store);
        assert_eq!(
            dispatch_argv(
                &argv(&["LSET", "l", "9223372036854775807", "X"]),
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            lrange(&mut store),
            vec![b"a".to_vec(), b"b".to_vec(), b"c".to_vec(), b"X".to_vec()]
        );

        // i64::MIN truncates to 0 -> the FIRST element.
        reset(&mut store);
        dispatch_argv(
            &argv(&["LSET", "l", "-9223372036854775808", "Y"]),
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            lrange(&mut store),
            vec![b"Y".to_vec(), b"b".to_vec(), b"c".to_vec(), b"d".to_vec()]
        );

        // 2^32 truncates to 0 -> the FIRST element.
        reset(&mut store);
        dispatch_argv(&argv(&["LSET", "l", "4294967296", "Z"]), &mut store, 0).unwrap();
        assert_eq!(
            lrange(&mut store),
            vec![b"Z".to_vec(), b"b".to_vec(), b"c".to_vec(), b"d".to_vec()]
        );

        // (2^63-5) truncates to -5 -> out of range on a 4-element list.
        reset(&mut store);
        let err = dispatch_argv(
            &argv(&["LSET", "l", "9223372036854775803", "W"]),
            &mut store,
            0,
        )
        .expect_err("low-32-bits out of range");
        assert!(
            matches!(
                err,
                CommandError::Store(fr_store::StoreError::IndexOutOfRange)
            ),
            "got {err:?}"
        );

        // A plain out-of-range index (4) still errors.
        reset(&mut store);
        let err = dispatch_argv(&argv(&["LSET", "l", "4", "V"]), &mut store, 0).expect_err("oob");
        assert!(
            matches!(
                err,
                CommandError::Store(fr_store::StoreError::IndexOutOfRange)
            ),
            "got {err:?}"
        );
    }

