    #[test]
    fn zrangebyscore_score_bound_matches_strtod_semantics() {
        // (frankenredis-zbound) Pin upstream
        // t_zset.c::zslParseRange's strtod-based parser:
        //   1. Bare `(` -> exclusive 0 (strtod("") returns 0.0,
        //      eptr[0] == '\0' passes the trailing-junk check).
        //   2. `( 5` (whitespace after `(`) -> exclusive 5
        //      (strtod skips leading whitespace).
        //   3. ` (5` (whitespace BEFORE `(`) -> error (the open
        //      gate only triggers when ptr[0] == '(').
        //   4. `(5 ` (trailing whitespace) -> error (eptr[0]
        //      points at the trailing space).
        //   5. `(NaN` -> error (isnan check).
        // fr previously called .trim() on the whole input, which
        // accepted both leading-before-paren and trailing whitespace
        // and rejected the bare `(` case.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"zs".to_vec(),
                b"0".to_vec(),
                b"zero".to_vec(),
                b"1".to_vec(),
                b"one".to_vec(),
                b"2".to_vec(),
                b"two".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zadd seed");

        // (1) Bare `(` is parsed as exclusive 0; range `(`..`(2`
        //     selects scores in (0, 2] but max is also `(2` so it's
        //     just one == "one".
        let one = dispatch_argv(
            &[
                b"ZRANGEBYSCORE".to_vec(),
                b"zs".to_vec(),
                b"(".to_vec(),
                b"(2".to_vec(),
            ],
            &mut store,
            1,
        )
        .expect("bare ( must parse as exclusive 0");
        assert_eq!(
            one,
            RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"one".to_vec()))]))
        );

        // (2) `( 5` -> exclusive 5 (whitespace after paren is fine).
        let after_open_ws = dispatch_argv(
            &[
                b"ZRANGEBYSCORE".to_vec(),
                b"zs".to_vec(),
                b"( 0".to_vec(),
                b"+inf".to_vec(),
            ],
            &mut store,
            2,
        )
        .expect("( 0 must parse as exclusive 0");
        let RespFrame::Array(Some(items)) = after_open_ws else {
            panic!("expected array");
        };
        assert_eq!(items.len(), 2);

        // (3-5) These all reject with the upstream wording.
        let bad = CommandError::Custom("ERR min or max is not a float".to_string());
        for arg in [
            b" (0".as_slice(), // leading whitespace before `(`
            b"(0 ",            // trailing whitespace after number
            b"0 ",             // trailing whitespace, no paren
            b"(NaN",           // NaN rejected
            b"NaN",            // NaN rejected (no paren)
        ] {
            let err = dispatch_argv(
                &[
                    b"ZRANGEBYSCORE".to_vec(),
                    b"zs".to_vec(),
                    arg.to_vec(),
                    b"+inf".to_vec(),
                ],
                &mut store,
                3,
            )
            .expect_err("invalid score bound");
            assert_eq!(err, bad, "input={:?}", String::from_utf8_lossy(arg));
        }
    }

    #[test]
    fn zrangebyscore_score_bound_accepts_c99_hex_float() {
        // (frankenredis-hexfloat range bounds) Upstream zslParseRange uses
        // strtod, which accepts C99 hex-float notation; fr's parser used
        // Rust f64::from_str (decimal-only) and rejected `0x10`, `0X1A`,
        // `0x1.8p3`, and the exclusive `(0x10`. Mirror the score path.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"zh".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
                b"16".to_vec(),
                b"p".to_vec(),
                b"100".to_vec(),
                b"z".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zadd seed");

        // 0x10 == 16.0 inclusive → {p(16), z(100)}.
        let hex_incl = dispatch_argv(
            &[
                b"ZRANGEBYSCORE".to_vec(),
                b"zh".to_vec(),
                b"0x10".to_vec(),
                b"+inf".to_vec(),
            ],
            &mut store,
            1,
        )
        .expect("0x10 hex bound must parse");
        assert_eq!(
            hex_incl,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"p".to_vec())),
                RespFrame::BulkString(Some(b"z".to_vec())),
            ]))
        );

        // Exclusive `(0x10` == exclusive 16 → only z(100).
        let hex_excl = dispatch_argv(
            &[
                b"ZRANGEBYSCORE".to_vec(),
                b"zh".to_vec(),
                b"(0x10".to_vec(),
                b"+inf".to_vec(),
            ],
            &mut store,
            2,
        )
        .expect("(0x10 exclusive hex bound must parse");
        assert_eq!(
            hex_excl,
            RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"z".to_vec()))]))
        );

        // 0x1.8p3 == 12.0 inclusive → {p(16), z(100)}.
        let hex_p = dispatch_argv(
            &[
                b"ZCOUNT".to_vec(),
                b"zh".to_vec(),
                b"0x1.8p3".to_vec(),
                b"+inf".to_vec(),
            ],
            &mut store,
            3,
        )
        .expect("0x1.8p3 hex bound must parse");
        assert_eq!(hex_p, RespFrame::Integer(2));

        // Trailing junk after a hex prefix is still rejected (strtod's
        // eptr[0] != '\0' check), as is a bare bad-hex.
        let bad = CommandError::Custom("ERR min or max is not a float".to_string());
        for arg in [b"0x10z".as_slice(), b"0xg"] {
            let err = dispatch_argv(
                &[
                    b"ZRANGEBYSCORE".to_vec(),
                    b"zh".to_vec(),
                    arg.to_vec(),
                    b"+inf".to_vec(),
                ],
                &mut store,
                4,
            )
            .expect_err("invalid hex bound");
            assert_eq!(err, bad, "input={:?}", String::from_utf8_lossy(arg));
        }
    }

    /// (ZRANGEBYSCORE inverted-range type-order parity) An inverted score range
    /// (`min > max`) against a WRONG-TYPE key must still surface WRONGTYPE —
    /// upstream type-checks the key before discovering the empty range. fr's
    /// store fast-path returned an empty reply instead; the command-level guard
    /// restores upstream order for ZRANGEBYSCORE / ZREVRANGEBYSCORE / ZRANGE
    /// BYSCORE / ZCOUNT / ZRANGESTORE BYSCORE.
    #[test]
    fn zscore_inverted_range_on_wrongtype_is_wrongtype() {
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"strk".to_vec(), b"hello".to_vec()],
            &mut store,
            0,
        )
        .unwrap();

        // Inverted ranges (min > max) on the wrong-type key → WRONGTYPE.
        let inverted: &[&[&[u8]]] = &[
            &[b"ZRANGEBYSCORE", b"strk", b"10", b"1"],
            &[b"ZRANGEBYSCORE", b"strk", b"10", b"1", b"WITHSCORES"],
            &[b"ZRANGEBYSCORE", b"strk", b"10", b"1", b"LIMIT", b"0", b"5"],
            &[b"ZREVRANGEBYSCORE", b"strk", b"1", b"10"],
            &[b"ZRANGE", b"strk", b"10", b"1", b"BYSCORE"],
            &[b"ZRANGE", b"strk", b"(5", b"(2", b"BYSCORE"],
            &[b"ZCOUNT", b"strk", b"10", b"1"],
            &[b"ZRANGESTORE", b"dst", b"strk", b"10", b"1", b"BYSCORE"],
        ];
        for cmd in inverted {
            let argv: Vec<Vec<u8>> = cmd.iter().map(|a| a.to_vec()).collect();
            let label = cmd
                .iter()
                .map(|a| String::from_utf8_lossy(a))
                .collect::<Vec<_>>();
            match dispatch_argv(&argv, &mut store, 0) {
                Err(CommandError::Store(StoreError::WrongType)) => {}
                other => panic!("cmd={label:?} expected WrongType, got {other:?}"),
            }
        }

        // Inverted range on a MISSING key → empty / 0 (not an error).
        assert_eq!(
            dispatch_argv(
                &[
                    b"ZRANGEBYSCORE".to_vec(),
                    b"nope".to_vec(),
                    b"10".to_vec(),
                    b"1".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::Array(Some(Vec::new()))
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"ZCOUNT".to_vec(),
                    b"nope".to_vec(),
                    b"10".to_vec(),
                    b"1".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::Integer(0)
        );

        // Inverted range on a real zset → empty / 0 (type check passes).
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            dispatch_argv(
                &[
                    b"ZRANGEBYSCORE".to_vec(),
                    b"z".to_vec(),
                    b"10".to_vec(),
                    b"1".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::Array(Some(Vec::new()))
        );
    }

