    #[test]
    fn geoadd_geodist_geohash_and_geopos() {
        let mut store = Store::new();
        let out = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"13.361389".to_vec(),
                b"38.115556".to_vec(),
                b"Palermo".to_vec(),
                b"15.087269".to_vec(),
                b"37.502669".to_vec(),
                b"Catania".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geoadd");
        assert_eq!(out, RespFrame::Integer(2));

        let dist = dispatch_argv(
            &[
                b"GEODIST".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"Catania".to_vec(),
                b"km".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geodist");
        assert_eq!(dist, RespFrame::BulkString(Some(b"166.2742".to_vec())));

        let hashes = dispatch_argv(
            &[
                b"GEOHASH".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"Catania".to_vec(),
                b"Missing".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geohash");
        // (frankenredis-lw241) Vendored 7.2.4 forces idx=0 for the
        // 11th character (geo.c:920-925 — only 52 bits encoded into a
        // 26-step hash, last 5-bit slot would need bits 51-55 which
        // don't exist, so upstream emits '0' for backward compat).
        // fr previously emitted a non-zero 11th char by left-shifting
        // bits 0-1, producing `sqc8b49rnys` (last char `s`) for
        // Palermo while vendored returned `sqc8b49rny0`. Catania's
        // hash bits happened to evaluate to idx=0 anyway, masking the
        // bug for that particular member.
        assert_eq!(
            hashes,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"sqc8b49rny0".to_vec())),
                RespFrame::BulkString(Some(b"sqdtr74hyu0".to_vec())),
                RespFrame::BulkString(None),
            ]))
        );

        let pos = dispatch_argv(
            &[
                b"GEOPOS".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"Catania".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geopos");
        let RespFrame::Array(Some(items)) = pos else {
            panic!("geopos should return array"); // ubs:ignore — AI triage
        };
        assert_eq!(items.len(), 2);
        for item in items {
            let RespFrame::Array(Some(coords)) = item else {
                panic!("geopos entry should be coord array"); // ubs:ignore — AI triage
            };
            assert_eq!(coords.len(), 2);
            let RespFrame::BulkString(Some(longitude_raw)) = &coords[0] else {
                panic!("geopos longitude should be bulk"); // ubs:ignore — AI triage
            };
            let RespFrame::BulkString(Some(latitude_raw)) = &coords[1] else {
                panic!("geopos latitude should be bulk"); // ubs:ignore — AI triage
            };
            let longitude = std::str::from_utf8(longitude_raw)
                .expect("longitude utf8")
                .parse::<f64>()
                .expect("longitude float");
            let latitude = std::str::from_utf8(latitude_raw)
                .expect("latitude utf8")
                .parse::<f64>()
                .expect("latitude float");
            assert!((-180.0..=180.0).contains(&longitude));
            assert!((-85.051_128_78..=85.051_128_78).contains(&latitude));
        }
    }

    #[test]
    fn geoadd_options_and_errors() {
        let mut store = Store::new();

        let out = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"CH".to_vec(),
                b"13.361389".to_vec(),
                b"38.115556".to_vec(),
                b"Palermo".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geoadd ch initial");
        assert_eq!(out, RespFrame::Integer(1));

        let unchanged = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"CH".to_vec(),
                b"13.361389".to_vec(),
                b"38.115556".to_vec(),
                b"Palermo".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geoadd same coords");
        assert_eq!(unchanged, RespFrame::Integer(0));

        let changed = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"CH".to_vec(),
                b"13.362".to_vec(),
                b"38.115".to_vec(),
                b"Palermo".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geoadd changed coords");
        assert_eq!(changed, RespFrame::Integer(1));

        let nx_skip = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"NX".to_vec(),
                b"13.1".to_vec(),
                b"38.1".to_vec(),
                b"Palermo".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geoadd nx skip");
        assert_eq!(nx_skip, RespFrame::Integer(0));

        let xx_skip = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"XX".to_vec(),
                b"15.087269".to_vec(),
                b"37.502669".to_vec(),
                b"Catania".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geoadd xx skip on missing");
        assert_eq!(xx_skip, RespFrame::Integer(0));

        let invalid = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"181".to_vec(),
                b"0".to_vec(),
                b"bad".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geoadd invalid pair");
        assert_eq!(
            invalid,
            RespFrame::Error("ERR invalid longitude,latitude pair 181.000000,0.000000".to_string())
        );

        let syntax = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"NX".to_vec(),
                b"XX".to_vec(),
                b"13.0".to_vec(),
                b"38.0".to_vec(),
                b"x".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("geoadd nx+xx should be syntax error");
        assert!(matches!(syntax, CommandError::SyntaxError));
    }

    #[test]
    fn geodist_units_and_missing_members() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"13.361389".to_vec(),
                b"38.115556".to_vec(),
                b"Palermo".to_vec(),
                b"15.087269".to_vec(),
                b"37.502669".to_vec(),
                b"Catania".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_or_else(|e| e.to_resp());

        let meters = dispatch_argv(
            &[
                b"GEODIST".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"Catania".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_or_else(|e| e.to_resp());
        let RespFrame::BulkString(Some(distance_raw)) = meters else {
            panic!("geodist should return bulk distance"); // ubs:ignore — AI triage
        };
        let meters_value = std::str::from_utf8(&distance_raw)
            .expect("geodist distance utf8")
            .parse::<f64>()
            .expect("geodist distance parse");
        assert!(meters_value > 166_000.0);

        let invalid_unit = dispatch_argv(
            &[
                b"GEODIST".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"Catania".to_vec(),
                b"yards".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_or_else(|e| e.to_resp());
        assert_eq!(
            invalid_unit,
            RespFrame::Error("ERR unsupported unit provided. please use M, KM, FT, MI".to_string())
        );

        let missing = dispatch_argv(
            &[
                b"GEODIST".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"Missing".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_or_else(|e| e.to_resp());
        assert_eq!(missing, RespFrame::BulkString(None));
    }

    #[test]
    fn geo_unit_errors_use_uppercase_unit_names_across_family() {
        // (frankenredis-lcs68) Upstream geo.c::extractUnitOrReply emits
        // 'M, KM, FT, MI' (uppercase). 7 fr-command sites — GEORADIUS,
        // GEORADIUSBYMEMBER, GEORADIUS_RO, GEORADIUSBYMEMBER_RO,
        // GEOSEARCH, GEOSEARCHSTORE — were emitting lowercase. Pin the
        // canonical uppercase wording across the family.
        let expected = "ERR unsupported unit provided. please use M, KM, FT, MI";
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"13.361389".to_vec(),
                b"38.115556".to_vec(),
                b"Palermo".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_or_else(|e| e.to_resp());

        let cases = [
            // GEOSEARCH FROMMEMBER ... BYRADIUS ... <bad-unit>
            vec![
                b"GEOSEARCH".to_vec(),
                b"geo".to_vec(),
                b"FROMMEMBER".to_vec(),
                b"Palermo".to_vec(),
                b"BYRADIUS".to_vec(),
                b"100".to_vec(),
                b"yards".to_vec(),
                b"ASC".to_vec(),
            ],
            // GEORADIUSBYMEMBER ... <bad-unit>
            vec![
                b"GEORADIUSBYMEMBER".to_vec(),
                b"geo".to_vec(),
                b"Palermo".to_vec(),
                b"100".to_vec(),
                b"yards".to_vec(),
            ],
            // GEORADIUS lon lat radius <bad-unit>
            vec![
                b"GEORADIUS".to_vec(),
                b"geo".to_vec(),
                b"13".to_vec(),
                b"38".to_vec(),
                b"100".to_vec(),
                b"yards".to_vec(),
            ],
        ];
        for argv in cases {
            let out = dispatch_argv(&argv, &mut store, 0).unwrap_or_else(|e| e.to_resp());
            assert_eq!(out, RespFrame::Error(expected.to_string()), "argv={argv:?}");
        }
    }

    #[test]
    fn xadd_xlen_and_type_roundtrip() {
        let mut store = Store::new();

        let first = dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"stream".to_vec(),
                b"*".to_vec(),
                b"field1".to_vec(),
                b"value1".to_vec(),
            ],
            &mut store,
            1_000,
        )
        .expect("xadd first");
        assert_eq!(first, RespFrame::BulkString(Some(b"1000-0".to_vec())));

        let second = dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"stream".to_vec(),
                b"*".to_vec(),
                b"field2".to_vec(),
                b"value2".to_vec(),
            ],
            &mut store,
            1_000,
        )
        .expect("xadd second same ms");
        assert_eq!(second, RespFrame::BulkString(Some(b"1000-1".to_vec())));

        let third = dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"stream".to_vec(),
                b"*".to_vec(),
                b"field3".to_vec(),
                b"value3".to_vec(),
            ],
            &mut store,
            1_500,
        )
        .expect("xadd third newer ms");
        assert_eq!(third, RespFrame::BulkString(Some(b"1500-0".to_vec())));

        let len = dispatch_argv(&[b"XLEN".to_vec(), b"stream".to_vec()], &mut store, 1_500)
            .expect("xlen");
        assert_eq!(len, RespFrame::Integer(3));

        let type_out = dispatch_argv(&[b"TYPE".to_vec(), b"stream".to_vec()], &mut store, 1_500)
            .expect("type stream");
        assert_eq!(type_out, RespFrame::SimpleString("stream".to_string()));
    }

