    #[test]
    fn xrange_returns_entries_and_supports_count() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"stream".to_vec(),
                b"1000-0".to_vec(),
                b"field1".to_vec(),
                b"value1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 1");
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"stream".to_vec(),
                b"1000-1".to_vec(),
                b"field2".to_vec(),
                b"value2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 2");
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"stream".to_vec(),
                b"1001-0".to_vec(),
                b"field3".to_vec(),
                b"value3".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 3");

        let all = dispatch_argv(
            &[
                b"XRANGE".to_vec(),
                b"stream".to_vec(),
                b"-".to_vec(),
                b"+".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xrange all");
        assert_eq!(
            all,
            RespFrame::Array(Some(vec![
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-0".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"field1".to_vec())),
                        RespFrame::BulkString(Some(b"value1".to_vec())),
                    ])),
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-1".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"field2".to_vec())),
                        RespFrame::BulkString(Some(b"value2".to_vec())),
                    ])),
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1001-0".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"field3".to_vec())),
                        RespFrame::BulkString(Some(b"value3".to_vec())),
                    ])),
                ])),
            ]))
        );

        let limited = dispatch_argv(
            &[
                b"XRANGE".to_vec(),
                b"stream".to_vec(),
                b"1000".to_vec(),
                b"+".to_vec(),
                b"COUNT".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xrange count 1");
        assert_eq!(
            limited,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"1000-0".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"field1".to_vec())),
                    RespFrame::BulkString(Some(b"value1".to_vec())),
                ])),
            ]))]))
        );
    }

    #[test]
    fn cluster_addslotsrange_set_config_epoch_check_ordering_matches_upstream() {
        // Pin upstream cluster.c::clusterCommand check ordering
        // (frankenredis-ujdy):
        //   1. CLUSTER ADDSLOTSRANGE 1 2 3 (argc=5): commands.def
        //      arity = -4 passes; multiple-of-2 pair check happens
        //      AFTER cluster_enabled gate, so standalone mode replies
        //      "cluster support disabled" — not WrongSubcommandArity.
        //   2. CLUSTER SET-CONFIG-EPOCH (argc=2): commands.def arity
        //      = 3 fails table-level, so reply is the wrong-arity
        //      wording (preempts the cluster_enabled gate).
        let mut store = Store::new();

        let standalone_addslots = dispatch_argv(
            &[
                b"CLUSTER".to_vec(),
                b"ADDSLOTSRANGE".to_vec(),
                b"1".to_vec(),
                b"2".to_vec(),
                b"3".to_vec(),
            ],
            &mut store,
            0,
        );
        let got = match standalone_addslots {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR This instance has cluster support disabled".to_string()
        );

        let missing_epoch = dispatch_argv(
            &[b"CLUSTER".to_vec(), b"SET-CONFIG-EPOCH".to_vec()],
            &mut store,
            0,
        );
        let got = match missing_epoch {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR wrong number of arguments for 'cluster|set-config-epoch' command".to_string()
        );

        // Sanity: ADDSLOTSRANGE with too-few args also surfaces
        // wrong-arity (still preempts the cluster_enabled gate).
        let too_few = dispatch_argv(
            &[
                b"CLUSTER".to_vec(),
                b"ADDSLOTSRANGE".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        );
        let got = match too_few {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR wrong number of arguments for 'cluster|addslotsrange' command".to_string()
        );
    }

    #[test]
    fn xrange_xrevrange_extra_trailing_args_match_upstream_syntax_error() {
        // Pin upstream t_stream.c::xrangeGenericCommand wording for
        // trailing-junk and malformed-COUNT contexts (frankenredis-x6p9):
        // 5-arg form (one extra after start/end) and 6-arg form with a
        // non-COUNT keyword both surface "syntax error", not the
        // table-level wrong-arity reply.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1-0".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd");

        for cmd in [b"XRANGE".as_slice(), b"XREVRANGE".as_slice()] {
            // 5 args: one trailing junk after start/end.
            let err = dispatch_argv(
                &[
                    cmd.to_vec(),
                    b"s".to_vec(),
                    b"-".to_vec(),
                    b"+".to_vec(),
                    b"EXTRA".to_vec(),
                ],
                &mut store,
                0,
            )
            .expect_err("error");
            assert_eq!(err, CommandError::SyntaxError, "{cmd:?} 5-arg");

            // 6 args, non-COUNT keyword.
            let err = dispatch_argv(
                &[
                    cmd.to_vec(),
                    b"s".to_vec(),
                    b"-".to_vec(),
                    b"+".to_vec(),
                    b"NOPE".to_vec(),
                    b"3".to_vec(),
                ],
                &mut store,
                0,
            )
            .expect_err("error");
            assert_eq!(err, CommandError::SyntaxError, "{cmd:?} non-COUNT");
        }
    }

