    /// (frankenredis-hpz8a) XTRIM MAXLEN ~ N [LIMIT M] must follow
    /// upstream's node-boundary approximate semantics: trim count is
    /// rounded down to the nearest multiple of stream-node-max-entries
    /// (default 100). When LIMIT is given, the result is also capped
    /// to that limit. fr previously did exact trimming with LIMIT as
    /// a max-evictions cap, which over-trimmed small streams.
    #[test]
    fn xtrim_maxlen_approximate_respects_node_boundary_hpz8a() {
        let mut store = Store::new();

        let add_n = |store: &mut Store, n: usize| {
            // Reset stream by deleting and re-adding.
            dispatch_argv(&[b"DEL".to_vec(), b"s".to_vec()], store, 0).expect("del");
            for i in 1..=n {
                dispatch_argv(
                    &[
                        b"XADD".to_vec(),
                        b"s".to_vec(),
                        format!("{i}-0").into_bytes(),
                        b"f".to_vec(),
                        b"v".to_vec(),
                    ],
                    store,
                    0,
                )
                .expect("xadd");
            }
        };
        let xtrim = |store: &mut Store, args: &[&[u8]]| -> i64 {
            let mut argv = vec![b"XTRIM".to_vec(), b"s".to_vec()];
            for a in args {
                argv.push(a.to_vec());
            }
            match dispatch_argv(&argv, store, 0).expect("xtrim") {
                RespFrame::Integer(n) => n,
                other => panic!("expected integer, got {other:?}"),
            }
        };

        // 10 entries, target 5, ~: stream fits in one node — refuse.
        add_n(&mut store, 10);
        assert_eq!(xtrim(&mut store, &[b"MAXLEN", b"~", b"5"]), 0);
        // 10 entries, target 5, ~ + LIMIT 100: still refuse (one node).
        add_n(&mut store, 10);
        assert_eq!(
            xtrim(&mut store, &[b"MAXLEN", b"~", b"5", b"LIMIT", b"100"]),
            0
        );
        // 128 entries, target 5, ~: trim one full node (100).
        add_n(&mut store, 128);
        assert_eq!(xtrim(&mut store, &[b"MAXLEN", b"~", b"5"]), 100);
        // 200 entries, target 5, ~: trim one full node (100), leaving 100.
        add_n(&mut store, 200);
        assert_eq!(xtrim(&mut store, &[b"MAXLEN", b"~", b"5"]), 100);
        // 300 entries, target 5, ~ + LIMIT 100: LIMIT caps to 100.
        add_n(&mut store, 300);
        assert_eq!(
            xtrim(&mut store, &[b"MAXLEN", b"~", b"5", b"LIMIT", b"100"]),
            100
        );
        // 500 entries, target 5, ~: trim 4 full nodes (400).
        add_n(&mut store, 500);
        assert_eq!(xtrim(&mut store, &[b"MAXLEN", b"~", b"5"]), 400);
        // Exact (=) still honors the requested target verbatim.
        add_n(&mut store, 10);
        assert_eq!(xtrim(&mut store, &[b"MAXLEN", b"=", b"5"]), 5);
        // No qualifier behaves like '='.
        add_n(&mut store, 10);
        assert_eq!(xtrim(&mut store, &[b"MAXLEN", b"5"]), 5);

        // (frankenredis-c6j11) MAXLEN ~ 0 clears the whole stream (the partial
        // tail node IS evicted at target 0), matching vendored 7.2.4 — the old
        // round-down model left `len % 100` entries.
        for n in [5usize, 50, 99, 100, 101, 150, 250] {
            add_n(&mut store, n);
            assert_eq!(
                xtrim(&mut store, &[b"MAXLEN", b"~", b"0"]),
                n as i64,
                "len={n}"
            );
            assert_eq!(
                dispatch_argv(&[b"XLEN".to_vec(), b"s".to_vec()], &mut store, 0).unwrap(),
                RespFrame::Integer(0),
                "len={n} not cleared"
            );
        }
        // A sub-node LIMIT evicts NOTHING (whole-node granularity), not a partial.
        add_n(&mut store, 150);
        assert_eq!(
            xtrim(&mut store, &[b"MAXLEN", b"~", b"0", b"LIMIT", b"1"]),
            0
        );
        add_n(&mut store, 250);
        assert_eq!(
            xtrim(&mut store, &[b"MAXLEN", b"~", b"5", b"LIMIT", b"150"]),
            100
        );

        // (frankenredis-c6j11) XADD inline `~` trim is NOT a no-op: XADD MAXLEN ~ 0
        // clears the stream (the new entry is added, then everything is evicted),
        // and XADD MAXLEN ~ N trims whole nodes even without an explicit LIMIT.
        add_n(&mut store, 5);
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"MAXLEN".to_vec(),
                b"~".to_vec(),
                b"0".to_vec(),
                b"*".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            dispatch_argv(&[b"XLEN".to_vec(), b"s".to_vec()], &mut store, 0).unwrap(),
            RespFrame::Integer(0),
            "XADD ~0 must clear"
        );
        add_n(&mut store, 150);
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"MAXLEN".to_vec(),
                b"~".to_vec(),
                b"5".to_vec(),
                b"*".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        // 150 + 1 new = 151; one full head node (100) evicted -> 51 remain.
        assert_eq!(
            dispatch_argv(&[b"XLEN".to_vec(), b"s".to_vec()], &mut store, 0).unwrap(),
            RespFrame::Integer(51),
            "XADD ~5 must trim a whole node without LIMIT"
        );
    }

    /// (frankenredis-8t4vl) XTRIM MINID ~ N [LIMIT M] follows upstream's
    /// approximate whole-node model: it drops only full head nodes whose last id
    /// is still below the MINID threshold, and a sub-node LIMIT drops nothing.
    #[test]
    fn xtrim_minid_approximate_respects_node_boundary_8t4vl() {
        let mut store = Store::new();

        let add_n = |store: &mut Store, n: usize| {
            dispatch_argv(&[b"DEL".to_vec(), b"s".to_vec()], store, 0).expect("del");
            for i in 1..=n {
                dispatch_argv(
                    &[
                        b"XADD".to_vec(),
                        b"s".to_vec(),
                        format!("{i}-0").into_bytes(),
                        b"f".to_vec(),
                        b"v".to_vec(),
                    ],
                    store,
                    0,
                )
                .expect("xadd");
            }
        };
        let xtrim = |store: &mut Store, args: &[&[u8]]| -> i64 {
            let mut argv = vec![b"XTRIM".to_vec(), b"s".to_vec()];
            for a in args {
                argv.push(a.to_vec());
            }
            match dispatch_argv(&argv, store, 0).expect("xtrim") {
                RespFrame::Integer(n) => n,
                other => panic!("expected integer, got {other:?}"),
            }
        };

        add_n(&mut store, 250);
        assert_eq!(xtrim(&mut store, &[b"MINID", b"~", b"100-0"]), 0);
        assert_eq!(xtrim(&mut store, &[b"MINID", b"~", b"150-0"]), 100);
        assert_eq!(
            dispatch_argv(&[b"XLEN".to_vec(), b"s".to_vec()], &mut store, 0).unwrap(),
            RespFrame::Integer(150)
        );
        let remaining = dispatch_argv(
            &[
                b"XRANGE".to_vec(),
                b"s".to_vec(),
                b"-".to_vec(),
                b"+".to_vec(),
                b"COUNT".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xrange");
        assert!(matches!(
            remaining,
            RespFrame::Array(Some(ref rows))
                if matches!(
                    rows.first(),
                    Some(RespFrame::Array(Some(first)))
                        if first.first()
                            == Some(&RespFrame::BulkString(Some(b"101-0".to_vec())))
                )
        ));

        add_n(&mut store, 250);
        assert_eq!(
            xtrim(&mut store, &[b"MINID", b"~", b"10000-0", b"LIMIT", b"50"]),
            0
        );
        assert_eq!(
            xtrim(&mut store, &[b"MINID", b"~", b"10000-0", b"LIMIT", b"150"]),
            100
        );
        add_n(&mut store, 250);
        assert_eq!(
            xtrim(&mut store, &[b"MINID", b"~", b"10000-0", b"LIMIT", b"0"]),
            250
        );
    }

