    /// (frankenredis-5zr5y) Vendored XTRIM defers the LIMIT/strategy
    /// diagnostics to a post-parse pass: `args->limit && no_strategy`
    /// emits "LIMIT cannot be used without specifying a trimming
    /// strategy"; `!xadd && no_strategy` emits the XTRIM-specific
    /// "must be called with a trimming strategy"; `limit_given &&
    /// !approx` emits "without the special ~ option". The first check
    /// is C-truthy on the LIMIT value, so `LIMIT 0` skips it and falls
    /// through to the XTRIM-specific wording. fr previously errored
    /// eagerly at the LIMIT token whenever strategy was unset and
    /// always reported the "without strategy" wording.
    #[test]
    fn xtrim_limit_zero_without_strategy_returns_xtrim_specific_wording_5zr5y() {
        let mut store = Store::new();
        // LIMIT 0 without strategy: vendored falls through to the
        // XTRIM-specific "must be called with a trimming strategy"
        // wording because args->limit (0) is falsy.
        let reply = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"s".to_vec(),
                b"LIMIT".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xtrim limit 0");
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR syntax error, XTRIM must be called with a trimming strategy".to_string()
            )
        );
        // LIMIT 5 without strategy: vendored fires the value-gated
        // "without specifying a trimming strategy" wording.
        let reply = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"s".to_vec(),
                b"LIMIT".to_vec(),
                b"5".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xtrim limit 5");
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR syntax error, LIMIT cannot be used without specifying a trimming strategy"
                    .to_string()
            )
        );
        // MAXLEN 5 LIMIT 0 (no ~): falls to the third diagnostic.
        let reply = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"s".to_vec(),
                b"MAXLEN".to_vec(),
                b"5".to_vec(),
                b"LIMIT".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xtrim maxlen 5 limit 0");
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR syntax error, LIMIT cannot be used without the special ~ option".to_string()
            )
        );
    }

    /// (frankenredis-kgxl7) Vendored Redis 7.2.4 t_stream.c:998 gates the
    /// "without specifying a trimming strategy" message on
    /// `args->limit && trim_strategy == NONE`. The C `args->limit` is a
    /// long long treated as truthy/falsy, so `LIMIT 0` (value 0) skips
    /// the first check and falls through to line 1015's `limit_given &&
    /// !approx_trim`, which emits "without the special ~ option".
    /// fr previously emitted the "without specifying a trimming strategy"
    /// wording in this case, diverging from vendored.
    #[test]
    fn xadd_limit_zero_without_strategy_matches_vendored_wording_kgxl7() {
        let mut store = Store::new();
        // LIMIT 0 with no MAXLEN/MINID — vendored quirk routes to the
        // "without the special ~ option" wording even though there is
        // no trim strategy at all.
        let reply = dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"LIMIT".to_vec(),
                b"0".to_vec(),
                b"*".to_vec(),
                b"k".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd limit 0 no strategy");
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR syntax error, LIMIT cannot be used without the special ~ option".to_string()
            )
        );
        // LIMIT >0 with no strategy keeps the original wording.
        let reply = dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"LIMIT".to_vec(),
                b"5".to_vec(),
                b"*".to_vec(),
                b"k".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd limit 5 no strategy");
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR syntax error, LIMIT cannot be used without specifying a trimming strategy"
                    .to_string()
            )
        );
        // MAXLEN 5 (exact) + LIMIT 0 — strategy exists but no ~, still emits
        // "without the special ~ option".
        let reply = dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"MAXLEN".to_vec(),
                b"5".to_vec(),
                b"LIMIT".to_vec(),
                b"0".to_vec(),
                b"*".to_vec(),
                b"k".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd maxlen 5 limit 0");
        assert_eq!(
            reply,
            RespFrame::Error(
                "ERR syntax error, LIMIT cannot be used without the special ~ option".to_string()
            )
        );
    }

    /// (frankenredis-hpz8a) Under upstream's node-boundary semantics,
    /// `MAXLEN ~ N LIMIT 0` on a single-node stream (≤ 100 entries)
    /// is a no-op — even with LIMIT 0 meaning "unlimited cap", the
    /// approximate trim refuses to split a node. This test previously
    /// pinned fr's over-trimming behavior.
    #[test]
    fn stream_trim_limit_zero_respects_node_boundary_hpz8a() {
        let mut store = Store::new();
        for id in [b"1-0", b"2-0", b"3-0", b"4-0", b"5-0"] {
            dispatch_argv(
                &[
                    b"XADD".to_vec(),
                    b"s".to_vec(),
                    id.to_vec(),
                    b"f".to_vec(),
                    b"v".to_vec(),
                ],
                &mut store,
                0,
            )
            .expect("seed xadd");
        }

        // Single-node stream (5 entries) + ~ + LIMIT 0 → upstream refuses to trim.
        let removed = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"s".to_vec(),
                b"MAXLEN".to_vec(),
                b"~".to_vec(),
                b"2".to_vec(),
                b"LIMIT".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xtrim limit zero");
        assert_eq!(removed, RespFrame::Integer(0));

        let len = dispatch_argv(&[b"XLEN".to_vec(), b"s".to_vec()], &mut store, 0)
            .expect("xlen after xtrim");
        assert_eq!(len, RespFrame::Integer(5));

        // Same single-node refusal applies to XADD's inline trim.
        let mut inline_store = Store::new();
        for id in [b"1-0", b"2-0", b"3-0", b"4-0"] {
            dispatch_argv(
                &[
                    b"XADD".to_vec(),
                    b"inline".to_vec(),
                    id.to_vec(),
                    b"f".to_vec(),
                    b"v".to_vec(),
                ],
                &mut inline_store,
                0,
            )
            .expect("seed inline xadd");
        }

        let added = dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"inline".to_vec(),
                b"MAXLEN".to_vec(),
                b"~".to_vec(),
                b"2".to_vec(),
                b"LIMIT".to_vec(),
                b"0".to_vec(),
                b"5-0".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut inline_store,
            0,
        )
        .expect("xadd limit zero");
        assert_eq!(added, RespFrame::BulkString(Some(b"5-0".to_vec())));

        // Stream went from 4 → 5 entries via the XADD itself; the
        // inline trim refused (single node still).
        let len = dispatch_argv(
            &[b"XLEN".to_vec(), b"inline".to_vec()],
            &mut inline_store,
            0,
        )
        .expect("xlen after inline trim");
        assert_eq!(len, RespFrame::Integer(5));
    }

    #[test]
    fn xtrim_validation_missing_and_wrongtype() {
        let mut store = Store::new();
        let missing = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"missing".to_vec(),
                b"MAXLEN".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xtrim missing key");
        assert_eq!(missing, RespFrame::Integer(0));

        // MINID is now supported — should return Integer(0) on missing key
        let minid_missing = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"missing".to_vec(),
                b"MINID".to_vec(),
                b"1-0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xtrim minid missing key");
        assert_eq!(minid_missing, RespFrame::Integer(0));

        // ~ (approximate) is now accepted as a modifier
        let approx = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"missing".to_vec(),
                b"MAXLEN".to_vec(),
                b"~".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xtrim approx missing key");
        assert_eq!(approx, RespFrame::Integer(0));

        let neg_maxlen = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"stream".to_vec(),
                b"MAXLEN".to_vec(),
                b"-1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xtrim negative maxlen");
        // Upstream emits the bespoke 'The MAXLEN argument must be >= 0.'
        // wording. (br-frankenredis-xtrimmaxlenneg)
        assert_eq!(
            neg_maxlen,
            RespFrame::Error("ERR The MAXLEN argument must be >= 0.".to_string())
        );

        let arity = dispatch_argv(
            &[b"XTRIM".to_vec(), b"stream".to_vec(), b"MAXLEN".to_vec()],
            &mut store,
            0,
        )
        .expect_err("xtrim arity");
        assert!(matches!(arity, CommandError::WrongArity("XTRIM")));

        // (frankenredis-wglo0) Token-iteration error wordings.
        // Upstream streamParseAddOrTrimArgsOrReply walks argv,
        // tracks a trim_strategy flag, and bails with type-specific
        // wording for missing-threshold and bespoke wording for
        // duplicate / mixed strategies.
        for &(extra, want_err) in &[
            // MAXLEN with no threshold (after consuming ~ or =) —
            // upstream's getLongLongFromObjectOrReply on argv[i+1]
            // reads past the vector and surfaces the int wording.
            (
                &[b"MAXLEN".as_ref(), b"~".as_ref()][..],
                "ERR value is not an integer or out of range",
            ),
            (
                &[b"MAXLEN".as_ref(), b"=".as_ref()][..],
                "ERR value is not an integer or out of range",
            ),
            // MINID parses the threshold as a stream ID, so the
            // missing-threshold case surfaces the stream-ID wording.
            (
                &[b"MINID".as_ref(), b"~".as_ref()][..],
                "ERR Invalid stream ID specified as stream command argument",
            ),
            (
                &[b"MINID".as_ref(), b"=".as_ref()][..],
                "ERR Invalid stream ID specified as stream command argument",
            ),
            // Two strategy tokens in any combination — upstream's
            // `if (trim_strategy != TRIM_STRATEGY_NONE)` guard fires
            // on the second one and emits the bespoke wording.
            (
                &[
                    b"MAXLEN".as_ref(),
                    b"5".as_ref(),
                    b"MINID".as_ref(),
                    b"0".as_ref(),
                ][..],
                "ERR syntax error, MAXLEN and MINID options at the same time are not compatible",
            ),
            (
                &[
                    b"MINID".as_ref(),
                    b"0".as_ref(),
                    b"MAXLEN".as_ref(),
                    b"5".as_ref(),
                ][..],
                "ERR syntax error, MAXLEN and MINID options at the same time are not compatible",
            ),
            (
                &[
                    b"MAXLEN".as_ref(),
                    b"5".as_ref(),
                    b"MAXLEN".as_ref(),
                    b"3".as_ref(),
                ][..],
                "ERR syntax error, MAXLEN and MINID options at the same time are not compatible",
            ),
            (
                &[
                    b"MAXLEN".as_ref(),
                    b"~".as_ref(),
                    b"5".as_ref(),
                    b"MINID".as_ref(),
                    b"0".as_ref(),
                ][..],
                "ERR syntax error, MAXLEN and MINID options at the same time are not compatible",
            ),
            (
                &[
                    b"MAXLEN".as_ref(),
                    b"~".as_ref(),
                    b"5".as_ref(),
                    b"LIMIT".as_ref(),
                    b"5".as_ref(),
                    b"MINID".as_ref(),
                    b"0".as_ref(),
                ][..],
                "ERR syntax error, MAXLEN and MINID options at the same time are not compatible",
            ),
        ] {
            let mut argv = vec![b"XTRIM".to_vec(), b"stream".to_vec()];
            for tok in extra {
                argv.push(tok.to_vec());
            }
            let reply = dispatch_argv(&argv, &mut store, 0).expect("xtrim parse path");
            assert_eq!(
                reply,
                RespFrame::Error(want_err.to_string()),
                "case {:?}",
                extra
                    .iter()
                    .map(|t| String::from_utf8_lossy(t).to_string())
                    .collect::<Vec<_>>()
            );
        }

        // (frankenredis-d5y9h) XTRIM key LIMIT N — LIMIT alone without
        // MAXLEN/MINID. Upstream streamParseAddOrTrimArgsOrReply
        // (t_stream.c lines 998-1000) emits the specific error wording.
        // fr previously fell through to a generic 'syntax error'.
        let limit_no_strategy = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"stream".to_vec(),
                b"LIMIT".to_vec(),
                b"5".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xtrim LIMIT without strategy must surface as Error frame");
        assert_eq!(
            limit_no_strategy,
            RespFrame::Error(
                "ERR syntax error, LIMIT cannot be used without specifying a trimming strategy"
                    .to_string()
            )
        );

        store.set(b"k".to_vec(), b"v".to_vec(), None, 0);
        let wrongtype = dispatch_argv(
            &[
                b"XTRIM".to_vec(),
                b"k".to_vec(),
                b"MAXLEN".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xtrim wrongtype");
        assert!(matches!(
            wrongtype,
            CommandError::Store(fr_store::StoreError::WrongType)
        ));
    }

    #[test]
