    #[test]
    fn xread_validation_and_wrongtype() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1000-0".to_vec(),
                b"field".to_vec(),
                b"value".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd");

        let invalid_id = dispatch_argv(
            &[
                b"XREAD".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"bad-id".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xread invalid id");
        assert_eq!(
            invalid_id,
            RespFrame::Error(
                "ERR Invalid stream ID specified as stream command argument".to_string()
            )
        );

        // Integer BLOCK values are accepted here; blocking wakeups are exercised
        // in fr-server integration coverage.
        let block_result = dispatch_argv(
            &[
                b"XREAD".to_vec(),
                b"BLOCK".to_vec(),
                b"0".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        );
        assert!(block_result.is_ok());

        let fractional_block = dispatch_argv(
            &[
                b"XREAD".to_vec(),
                b"BLOCK".to_vec(),
                b"1.5".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        );
        assert_eq!(
            fractional_block,
            Err(CommandError::Custom(
                "ERR timeout is not an integer or out of range".to_string()
            ))
        );

        let bad_keyword = dispatch_argv(
            &[
                b"XREAD".to_vec(),
                b"COUNT".to_vec(),
                b"1".to_vec(),
                b"NOTSTREAMS".to_vec(),
                b"s".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xread missing STREAMS keyword");
        assert!(matches!(bad_keyword, CommandError::SyntaxError));

        let arity = dispatch_argv(
            &[
                b"XREAD".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"s2".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xread mismatched keys/ids");
        // Upstream emits the dedicated 'Unbalanced ...' error for
        // XREAD STREAMS with an odd number of trailing tokens.
        // (br-frankenredis-xreadbal)
        assert_eq!(
            arity,
            CommandError::Custom(
                "ERR Unbalanced 'xread' list of streams: for each stream key an ID or '$' must be specified.".to_string()
            )
        );

        store.set(b"k".to_vec(), b"v".to_vec(), None, 0);
        let wrongtype = dispatch_argv(
            &[
                b"XREAD".to_vec(),
                b"STREAMS".to_vec(),
                b"k".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xread wrongtype");
        assert!(matches!(
            wrongtype,
            CommandError::Store(fr_store::StoreError::WrongType)
        ));
    }

    #[test]
    fn xread_xreadgroup_streams_with_empty_tail_returns_syntax_error_pnkd6() {
        // (frankenredis-pnkd6) Upstream t_stream.c::xreadCommand only
        // matches the STREAMS keyword when at least one arg follows it
        // (`!strcasecmp(o,"STREAMS") && moreargs`). When STREAMS is the
        // last argument the keyword does not match and the parse loop
        // emits shared.syntaxerr. The 'Unbalanced ...' wording is
        // reserved for odd-count tails (e.g. STREAMS k id1 id2 id3).
        let mut store = Store::new();
        let cases: &[&[&[u8]]] = &[
            &[b"XREAD", b"COUNT", b"5", b"STREAMS"],
            &[b"XREAD", b"BLOCK", b"10", b"STREAMS"],
            &[b"XREAD", b"BLOCK", b"10", b"COUNT", b"5", b"STREAMS"],
        ];
        for argv in cases {
            let owned: Vec<Vec<u8>> = argv.iter().map(|a| a.to_vec()).collect();
            let err = dispatch_argv(&owned, &mut store, 0).expect_err("expected syntax error");
            assert!(
                matches!(err, CommandError::SyntaxError),
                "expected SyntaxError for {:?}, got {:?}",
                argv,
                err
            );
        }

        let xreadgroup_cases: &[&[&[u8]]] = &[
            &[
                b"XREADGROUP",
                b"GROUP",
                b"g",
                b"c",
                b"COUNT",
                b"5",
                b"STREAMS",
            ],
            &[
                b"XREADGROUP",
                b"GROUP",
                b"g",
                b"c",
                b"COUNT",
                b"5",
                b"NOACK",
                b"STREAMS",
            ],
            &[
                b"XREADGROUP",
                b"GROUP",
                b"g",
                b"c",
                b"BLOCK",
                b"10",
                b"STREAMS",
            ],
        ];
        for argv in xreadgroup_cases {
            let owned: Vec<Vec<u8>> = argv.iter().map(|a| a.to_vec()).collect();
            let err = dispatch_argv(&owned, &mut store, 0).expect_err("expected syntax error");
            assert!(
                matches!(err, CommandError::SyntaxError),
                "expected SyntaxError for {:?}, got {:?}",
                argv,
                err
            );
        }

        // Odd-count tails still produce the 'Unbalanced' error, not syntax.
        let unbalanced_xread = dispatch_argv(
            &[
                b"XREAD".to_vec(),
                b"STREAMS".to_vec(),
                b"s1".to_vec(),
                b"s2".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("expected unbalanced");
        assert_eq!(
            unbalanced_xread,
            CommandError::Custom(
                "ERR Unbalanced 'xread' list of streams: for each stream key an ID or '$' must be specified.".to_string()
            )
        );

        let unbalanced_xreadgroup = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"STREAMS".to_vec(),
                b"s1".to_vec(),
                b"s2".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("expected unbalanced");
        assert_eq!(
            unbalanced_xreadgroup,
            CommandError::Custom(
                "ERR Unbalanced 'xreadgroup' list of streams: for each stream key an ID or '>' must be specified.".to_string()
            )
        );
    }

    #[test]
    fn xreadgroup_reads_new_entries_and_advances_group_cursor() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"2000-0".to_vec(),
                b"field1".to_vec(),
                b"value1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 1");
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"2000-1".to_vec(),
                b"field2".to_vec(),
                b"value2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 2");
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");

        let first = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xreadgroup first");
        assert_eq!(
            first,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"s".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"2000-0".to_vec())),
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(b"field1".to_vec())),
                            RespFrame::BulkString(Some(b"value1".to_vec())),
                        ])),
                    ])),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"2000-1".to_vec())),
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(b"field2".to_vec())),
                            RespFrame::BulkString(Some(b"value2".to_vec())),
                        ])),
                    ])),
                ])),
            ]))]))
        );

        let second = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xreadgroup no new entries");
        assert_eq!(second, RespFrame::Array(None));

        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"2000-2".to_vec(),
                b"field3".to_vec(),
                b"value3".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 3");

        let third = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"COUNT".to_vec(),
                b"1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xreadgroup count");
        assert_eq!(
            third,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"s".to_vec())),
                RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"2000-2".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"field3".to_vec())),
                        RespFrame::BulkString(Some(b"value3".to_vec())),
                    ])),
                ]))])),
            ]))]))
        );

        let groups = dispatch_argv(
            &[b"XINFO".to_vec(), b"GROUPS".to_vec(), b"s".to_vec()],
            &mut store,
            0,
        )
        .expect("xinfo groups");
        // (frankenredis-o3m0f) When the stream has no XDEL'd entries
        // and entries-added is reliably tracked, vendored Redis 7.2.4
        // t_stream.c::xinfoCommand emits entries-read and lag as
        // integers (group->entries_read = 3, lag = 0 since the group
        // has consumed all 3 entries). Pinning to nil was a stale
        // assertion that masked actual fr correctness.
        assert_eq!(
            groups,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"name".to_vec())),
                RespFrame::BulkString(Some(b"g1".to_vec())),
                RespFrame::BulkString(Some(b"consumers".to_vec())),
                RespFrame::Integer(1),
                RespFrame::BulkString(Some(b"pending".to_vec())),
                RespFrame::Integer(3),
                RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
                RespFrame::BulkString(Some(b"2000-2".to_vec())),
                RespFrame::BulkString(Some(b"entries-read".to_vec())),
                RespFrame::Integer(3),
                RespFrame::BulkString(Some(b"lag".to_vec())),
                RespFrame::Integer(0),
            ]))]))
        );
    }

