    #[test]
    fn xreadgroup_type_and_group_checks_precede_id_validation_xrgord() {
        // (frankenredis-xrgord) Upstream checks key type (WRONGTYPE) and consumer
        // group existence (NOGROUP) BEFORE parsing the stream ID, so a malformed
        // ID must NOT mask those errors. fr previously parsed the ID first and
        // returned the generic invalid-ID error.
        let mut store = Store::new();
        // s2: a real stream with NO matching group; str1: a string (wrong type);
        // nostream: absent.
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s2".to_vec(),
                b"1-1".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd s2");
        store.set(b"str1".to_vec(), b"hello".to_vec(), None, 0);

        let nogroup = |key: &str| {
            format!(
                "NOGROUP No such key '{key}' or consumer group 'gX' in XREADGROUP with GROUP option"
            )
        };
        let rg = |key: &str, id: &str, store: &mut Store| {
            dispatch_argv(
                &[
                    b"XREADGROUP".to_vec(),
                    b"GROUP".to_vec(),
                    b"gX".to_vec(),
                    b"c1".to_vec(),
                    b"STREAMS".to_vec(),
                    key.as_bytes().to_vec(),
                    id.as_bytes().to_vec(),
                ],
                store,
                0,
            )
        };

        // Wrong type + malformed id -> WRONGTYPE (not invalid-id).
        assert!(matches!(
            rg("str1", "1-1-1", &mut store),
            Err(CommandError::Store(fr_store::StoreError::WrongType))
        ));
        // Existing stream, missing group, malformed id -> NOGROUP.
        assert_eq!(
            rg("s2", "abc", &mut store).expect("nogroup reply"),
            RespFrame::Error(nogroup("s2"))
        );
        // Absent key, malformed id -> NOGROUP.
        assert_eq!(
            rg("nostream", "1-1-1", &mut store).expect("nogroup reply"),
            RespFrame::Error(nogroup("nostream"))
        );
        // Sanity: wrong type with the '>' sentinel still WRONGTYPE (unchanged path).
        assert!(matches!(
            rg("str1", ">", &mut store),
            Err(CommandError::Store(fr_store::StoreError::WrongType))
        ));
    }

    #[test]
    fn blocking_deadline_milliseconds_requires_integer_and_rejects_overflow() {
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"0", 123),
            Ok(u64::MAX)
        );
        assert_eq!(parse_blocking_deadline_milliseconds(b"5", 123), Ok(128));
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"1.5", 123),
            Err(CommandError::Custom(
                "ERR timeout is not an integer or out of range".to_string()
            ))
        );
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"+1", 123),
            Err(CommandError::Custom(
                "ERR timeout is not an integer or out of range".to_string()
            ))
        );
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"001", 123),
            Err(CommandError::Custom(
                "ERR timeout is not an integer or out of range".to_string()
            ))
        );
        assert_eq!(
            parse_blocking_deadline_milliseconds(b"1", u64::MAX),
            Err(CommandError::Custom(
                "ERR timeout is out of range".to_string()
            ))
        );
    }

    #[test]
    fn count_parsers_reject_noncanonical_tokens() {
        assert_eq!(
            crate::parse_u64_arg(b"+1"),
            Err(CommandError::InvalidInteger)
        );
        assert_eq!(
            crate::parse_u64_arg(b"001"),
            Err(CommandError::InvalidInteger)
        );
        assert_eq!(crate::parse_u64_arg(b"0"), Ok(0));
        assert_eq!(crate::parse_u64_arg(b"5"), Ok(5));

        assert_eq!(
            crate::parse_limit_count_arg(b"+1"),
            Err(CommandError::InvalidInteger)
        );
        assert_eq!(
            crate::parse_limit_count_arg(b"001"),
            Err(CommandError::InvalidInteger)
        );
        assert_eq!(crate::parse_limit_count_arg(b"-1"), Ok(None));
        assert_eq!(crate::parse_limit_count_arg(b"0"), Ok(Some(0)));
    }

    #[test]
    fn float_parsers_reject_whitespace() {
        assert!(matches!(
            crate::parse_f64_arg(b" 1"),
            Err(CommandError::Store(fr_store::StoreError::ValueNotFloat))
        ));
        assert!(matches!(
            crate::parse_f64_arg(b"1 "),
            Err(CommandError::Store(fr_store::StoreError::ValueNotFloat))
        ));
        assert!(matches!(
            crate::parse_f64_arg(b"\t1"),
            Err(CommandError::Store(fr_store::StoreError::ValueNotFloat))
        ));
        assert!(matches!(
            crate::parse_f64_arg(b"1\t"),
            Err(CommandError::Store(fr_store::StoreError::ValueNotFloat))
        ));
        assert_eq!(crate::parse_f64_arg(b"1"), Ok(1.0));
        assert_eq!(crate::parse_f64_arg(b"-1.5"), Ok(-1.5));

        assert!(matches!(
            crate::parse_geo_f64(b" 1"),
            Err(RespFrame::Error(msg)) if msg == "ERR value is not a valid float"
        ));
        assert!(matches!(
            crate::parse_geo_f64(b"1 "),
            Err(RespFrame::Error(msg)) if msg == "ERR value is not a valid float"
        ));
        assert_eq!(crate::parse_geo_f64(b"1"), Ok(1.0));
        assert_eq!(crate::parse_geo_f64(b"-1.5"), Ok(-1.5));
    }

