    #[test]
    fn quit_and_reset_rejected_from_scripts_after_arity_validation() {
        // (frankenredis-quitarity) Upstream commands.def declares QUIT
        // with arity=-1, so `QUIT extra` is accepted (returns OK from a
        // non-script context, NOSCRIPT from inside a script). RESET is
        // still arity=1 and rejects extras.
        let mut store = Store::new();
        store.script_nesting_level = 1;

        // QUIT extra under script: extras are valid per upstream arity,
        // but the noscript guard still fires for QUIT itself.
        let quit_extra_noscript =
            dispatch_argv(&[b"QUIT".to_vec(), b"extra".to_vec()], &mut store, 0)
                .expect_err("quit noscript with extras");
        assert_eq!(
            quit_extra_noscript,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );

        let reset_arity = dispatch_argv(&[b"RESET".to_vec(), b"extra".to_vec()], &mut store, 0)
            .expect_err("reset arity");
        assert_eq!(reset_arity, CommandError::WrongArity("RESET"));

        for argv in [vec![b"QUIT".to_vec()], vec![b"RESET".to_vec()]] {
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("connection noscript");
            assert_eq!(err, CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()));
        }

        // Outside scripts, `QUIT garbage extra` returns OK to mirror
        // upstream networking.c::quitCommand.
        let mut clean = Store::new();
        let r = dispatch_argv(
            &[b"QUIT".to_vec(), b"garbage".to_vec(), b"extra".to_vec()],
            &mut clean,
            0,
        )
        .expect("QUIT extras outside script must succeed");
        assert_eq!(r, RespFrame::SimpleString("OK".to_string()));
    }

    #[test]
    fn xreadgroup_history_returns_deleted_pel_entries_as_nil_s0614() {
        // (frankenredis-s0614) A history read (explicit id) returns every PEL
        // entry for the consumer, including ones whose stream entry was XDEL'd —
        // upstream emits those tombstones as `[id, nil]`, not omitted.
        let mut store = Store::new();
        for id in [b"1-0".as_slice(), b"2-0", b"3-0"] {
            dispatch_argv(
                &[
                    b"XADD".to_vec(),
                    b"st".to_vec(),
                    id.to_vec(),
                    b"f".to_vec(),
                    b"v".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap();
        }
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"st".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        // deliver all 3 to c1 (now pending)
        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"st".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        // delete the middle entry; it stays in the PEL as a tombstone
        dispatch_argv(
            &[b"XDEL".to_vec(), b"st".to_vec(), b"2-0".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        let hist = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"st".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let nil_fields = || RespFrame::Array(None);
        let live = |id: &[u8]| {
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(id.to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"f".to_vec())),
                    RespFrame::BulkString(Some(b"v".to_vec())),
                ])),
            ]))
        };
        assert_eq!(
            hist,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"st".to_vec())),
                RespFrame::Array(Some(vec![
                    live(b"1-0"),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"2-0".to_vec())),
                        nil_fields(),
                    ])),
                    live(b"3-0"),
                ])),
            ]))]))
        );
    }

    #[test]
    fn xreadgroup_pending_replay_and_noack_behavior() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1000-0".to_vec(),
                b"field".to_vec(),
                b"v0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 0");
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1000-1".to_vec(),
                b"field".to_vec(),
                b"v1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 1");
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1000-2".to_vec(),
                b"field".to_vec(),
                b"v2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 2");
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");

        let first_pending = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"COUNT".to_vec(),
                b"1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("first pending read");
        assert_eq!(
            first_pending,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"s".to_vec())),
                RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-0".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"field".to_vec())),
                        RespFrame::BulkString(Some(b"v0".to_vec())),
                    ])),
                ]))])),
            ]))]))
        );

        let replay_for_owner = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("owner replay");
        assert_eq!(
            replay_for_owner,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"s".to_vec())),
                RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-0".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"field".to_vec())),
                        RespFrame::BulkString(Some(b"v0".to_vec())),
                    ])),
                ]))])),
            ]))]))
        );

        let replay_for_other_consumer = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c2".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("other consumer replay");
        // (frankenredis-xrgrphist) A history read (explicit id, not '>') always
        // includes the stream with an empty entry list when the consumer has no
        // matching pending entries — it does NOT collapse to a nil array.
        assert_eq!(
            replay_for_other_consumer,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"s".to_vec())),
                RespFrame::Array(Some(Vec::new())),
            ]))]))
        );

        let noack_read = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"NOACK".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("noack read");
        assert_eq!(
            noack_read,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"s".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"1000-1".to_vec())),
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(b"field".to_vec())),
                            RespFrame::BulkString(Some(b"v1".to_vec())),
                        ])),
                    ])),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"1000-2".to_vec())),
                        RespFrame::Array(Some(vec![
                            RespFrame::BulkString(Some(b"field".to_vec())),
                            RespFrame::BulkString(Some(b"v2".to_vec())),
                        ])),
                    ])),
                ])),
            ]))]))
        );

        let replay_after_noack = dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("replay after noack");
        assert_eq!(
            replay_after_noack,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"s".to_vec())),
                RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-0".to_vec())),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"field".to_vec())),
                        RespFrame::BulkString(Some(b"v0".to_vec())),
                    ])),
                ]))])),
            ]))]))
        );

        let groups = dispatch_argv(
            &[b"XINFO".to_vec(), b"GROUPS".to_vec(), b"s".to_vec()],
            &mut store,
            0,
        )
        .expect("xinfo groups");
        // (frankenredis-o3m0f) See companion test: vendored 7.2.4
        // emits entries-read/lag as integers when the stream has not
        // had XDEL operations that would invalidate the running count.
        assert_eq!(
            groups,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"name".to_vec())),
                RespFrame::BulkString(Some(b"g1".to_vec())),
                RespFrame::BulkString(Some(b"consumers".to_vec())),
                RespFrame::Integer(2),
                RespFrame::BulkString(Some(b"pending".to_vec())),
                RespFrame::Integer(1),
                RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
                RespFrame::BulkString(Some(b"1000-2".to_vec())),
                RespFrame::BulkString(Some(b"entries-read".to_vec())),
                RespFrame::Integer(3),
                RespFrame::BulkString(Some(b"lag".to_vec())),
                RespFrame::Integer(0),
            ]))]))
        );
    }

    #[test]
    fn xpending_reports_summary_and_detailed_pending_entries() {
        let mut store = Store::new();
        for (id, value) in [("1000-0", "v0"), ("1000-1", "v1"), ("1000-2", "v2")] {
            dispatch_argv(
                &[
                    b"XADD".to_vec(),
                    b"s".to_vec(),
                    id.as_bytes().to_vec(),
                    b"field".to_vec(),
                    value.as_bytes().to_vec(),
                ],
                &mut store,
                0,
            )
            .expect("xadd");
        }
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");

        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"COUNT".to_vec(),
                b"2".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            10,
        )
        .expect("xreadgroup first");
        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            20,
        )
        .expect("xreadgroup replay");
        dispatch_argv(
            &[
                b"XREADGROUP".to_vec(),
                b"GROUP".to_vec(),
                b"g1".to_vec(),
                b"c2".to_vec(),
                b"COUNT".to_vec(),
                b"1".to_vec(),
                b"STREAMS".to_vec(),
                b"s".to_vec(),
                b">".to_vec(),
            ],
            &mut store,
            30,
        )
        .expect("xreadgroup second consumer");

        let summary = dispatch_argv(
            &[b"XPENDING".to_vec(), b"s".to_vec(), b"g1".to_vec()],
            &mut store,
            40,
        )
        .expect("xpending summary");
        assert_eq!(
            summary,
            RespFrame::Array(Some(vec![
                RespFrame::Integer(3),
                RespFrame::BulkString(Some(b"1000-0".to_vec())),
                RespFrame::BulkString(Some(b"1000-2".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"c1".to_vec())),
                        // Summary per-consumer count is a bulk string in vendored
                        // 7.2.4 (t_stream.c), not an integer. (gauntlet B1)
                        RespFrame::BulkString(Some(b"2".to_vec())),
                    ])),
                    RespFrame::Array(Some(vec![
                        RespFrame::BulkString(Some(b"c2".to_vec())),
                        RespFrame::BulkString(Some(b"1".to_vec())),
                    ])),
                ])),
            ]))
        );

        let detail = dispatch_argv(
            &[
                b"XPENDING".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"-".to_vec(),
                b"+".to_vec(),
                b"10".to_vec(),
            ],
            &mut store,
            40,
        )
        .expect("xpending detail");
        assert_eq!(
            detail,
            RespFrame::Array(Some(vec![
                // The c1 '0' history replay at t=20 re-served the live PEL
                // entries 1000-0/1000-1, so — matching upstream
                // streamReplyWithRangeFromConsumerPEL — their delivery counts
                // bumped to 2 and delivery times refreshed to 20 (idle now
                // 40-20=20). 1000-2 was delivered once to c2 at t=30 (idle 10).
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-0".to_vec())),
                    RespFrame::BulkString(Some(b"c1".to_vec())),
                    RespFrame::Integer(20), // idle since the t=20 replay refresh
                    RespFrame::Integer(2),  // delivered once + one history re-read
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-1".to_vec())),
                    RespFrame::BulkString(Some(b"c1".to_vec())),
                    RespFrame::Integer(20),
                    RespFrame::Integer(2),
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-2".to_vec())),
                    RespFrame::BulkString(Some(b"c2".to_vec())),
                    RespFrame::Integer(10),
                    RespFrame::Integer(1),
                ])),
            ]))
        );

        let filtered = dispatch_argv(
            &[
                b"XPENDING".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"-".to_vec(),
                b"+".to_vec(),
                b"10".to_vec(),
                b"c1".to_vec(),
            ],
            &mut store,
            40,
        )
        .expect("xpending filtered");
        assert_eq!(
            filtered,
            RespFrame::Array(Some(vec![
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-0".to_vec())),
                    RespFrame::BulkString(Some(b"c1".to_vec())),
                    RespFrame::Integer(20),
                    RespFrame::Integer(2),
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"1000-1".to_vec())),
                    RespFrame::BulkString(Some(b"c1".to_vec())),
                    RespFrame::Integer(20),
                    RespFrame::Integer(2),
                ])),
            ]))
        );
    }

    #[test]
    fn xpending_validation_and_nogroup_behavior() {
        let mut store = Store::new();
        let arity = dispatch_argv(&[b"XPENDING".to_vec(), b"s".to_vec()], &mut store, 0)
            .expect_err("xpending arity");
        assert!(matches!(arity, CommandError::WrongArity("XPENDING")));

        // (frankenredis-xpendcount) Upstream t_stream.c::xpendingCommand
        // line 2915 clamps `count < 0` to 0 (after parsing as long long)
        // and proceeds rather than erroring. The empty range plus a
        // missing key/group then triggers the NOGROUP path; with a
        // valid group it would return an empty array. fr previously
        // surfaced InvalidInteger for negative count.
        let negative_count = dispatch_argv(
            &[
                b"XPENDING".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"-".to_vec(),
                b"+".to_vec(),
                b"-1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xpending negative count must clamp, not error");
        assert_eq!(
            negative_count,
            RespFrame::Error("NOGROUP No such key 's' or consumer group 'g1'".to_string())
        );

        let missing = dispatch_argv(
            &[b"XPENDING".to_vec(), b"s".to_vec(), b"g1".to_vec()],
            &mut store,
            0,
        )
        .expect("xpending missing group");
        // (br-frankenredis-ud94)
        assert_eq!(
            missing,
            RespFrame::Error("NOGROUP No such key 's' or consumer group 'g1'".to_string())
        );
    }

    #[test]
    fn xpending_parses_count_before_start_end_per_upstream() {
        // (frankenredis-xpendcount) Upstream t_stream.c::xpendingCommand
        // 2895-2929 parses the count argument FIRST, then start/end.
        // For a call like `XPENDING s g abc - + 5`: argv layout (no
        // IDLE) maps to start=abc, end=-, count=+. Upstream errors on
        // count='+' first ("value is not an integer or out of range");
        // fr was erroring on start='abc' first ("Invalid stream ID
        // specified as stream command argument").
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1-1".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd");
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"$".to_vec(),
                b"MKSTREAM".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");

        // count='+' must surface the integer-parse error BEFORE the
        // start='abc' stream-ID parse.
        let err = dispatch_argv(
            &[
                b"XPENDING".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"abc".to_vec(),
                b"-".to_vec(),
                b"+".to_vec(),
                b"5".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("count parses before start");
        assert!(matches!(err, CommandError::InvalidInteger), "got {err:?}",);
    }

