    #[test]
    fn xclaim_and_xautoclaim_validation_and_nogroup_errors() {
        let mut store = Store::new();
        let xclaim_arity = dispatch_argv(
            &[
                b"XCLAIM".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xclaim arity");
        assert!(matches!(xclaim_arity, CommandError::WrongArity("XCLAIM")));

        let xautoclaim_arity =
            dispatch_argv(&[b"XAUTOCLAIM".to_vec(), b"s".to_vec()], &mut store, 0)
                .expect_err("xautoclaim arity");
        assert!(matches!(
            xautoclaim_arity,
            CommandError::WrongArity("XAUTOCLAIM")
        ));

        let invalid_count = dispatch_argv(
            &[
                b"XAUTOCLAIM".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"0".to_vec(),
                b"0-0".to_vec(),
                b"COUNT".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xautoclaim invalid count");
        // Upstream uses 'COUNT must be > 0' for any non-positive
        // or unparseable COUNT value. (br-frankenredis-xautoclaim)
        assert_eq!(
            invalid_count,
            CommandError::Custom("ERR COUNT must be > 0".to_string())
        );

        let xclaim_missing = dispatch_argv(
            &[
                b"XCLAIM".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"0".to_vec(),
                b"1-0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xclaim nogroup");
        // (br-frankenredis-ud94)
        assert_eq!(
            xclaim_missing,
            RespFrame::Error("NOGROUP No such key 's' or consumer group 'g1'".to_string())
        );

        let xautoclaim_missing = dispatch_argv(
            &[
                b"XAUTOCLAIM".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
                b"0".to_vec(),
                b"0-0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xautoclaim nogroup");
        // (br-frankenredis-ud94)
        assert_eq!(
            xautoclaim_missing,
            RespFrame::Error("NOGROUP No such key 's' or consumer group 'g1'".to_string())
        );
    }

    #[test]
    fn xautoclaim_count_upper_bound_precedes_type_check() {
        // (frankenredis-zlpqd) Upstream bounds COUNT to [1, i64::MAX/16] via
        // getRangeLongFromObjectOrReply, and that range-check runs BEFORE the
        // key type-check — so a too-LARGE count surfaces 'COUNT must be > 0'
        // even on a wrong-type key, while exactly i64::MAX/16 passes the range
        // and reaches the type-check (WRONGTYPE).
        let argv = |parts: &[&str]| -> Vec<Vec<u8>> {
            parts.iter().map(|p| p.as_bytes().to_vec()).collect()
        };
        let bad_count = CommandError::Custom("ERR COUNT must be > 0".to_string());
        let max = (i64::MAX / 16).to_string();
        let over = (i64::MAX / 16 + 1).to_string();
        let mut store = Store::new();
        store.set(b"wt".to_vec(), b"v".to_vec(), None, 0);

        // Too-large count on a wrong-type key -> COUNT error (range before type).
        for cnt in [over.as_str(), "9223372036854775807", "0", "-1"] {
            assert_eq!(
                dispatch_argv(
                    &argv(&["XAUTOCLAIM", "wt", "g", "c", "0", "0", "COUNT", cnt]),
                    &mut store,
                    0
                )
                .expect_err("count error"),
                bad_count,
                "COUNT {cnt} on a wrong-type key must be the COUNT range error"
            );
        }
        // Exactly i64::MAX/16 is in range -> reaches the type-check -> WRONGTYPE.
        assert!(matches!(
            dispatch_argv(
                &argv(&["XAUTOCLAIM", "wt", "g", "c", "0", "0", "COUNT", &max]),
                &mut store,
                0
            ),
            Err(CommandError::Store(fr_store::StoreError::WrongType))
        ));
    }

    #[test]
    fn xclaim_missing_group_short_circuits_before_arg_parsing() {
        // (frankenredis-3qrt) Upstream xclaimCommand looks up the key +
        // consumer group BEFORE parsing min-idle-time and trailing
        // options, so a missing-group call must surface NOGROUP — not
        // 'Invalid min-idle-time argument' or 'Unrecognized XCLAIM option'.
        let mut store = Store::new();
        // Stream key exists but no group 'g'.
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"xs".to_vec(),
                b"*".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        for argv in [
            // Garbage min-idle-time would normally surface
            // 'Invalid min-idle-time argument for XCLAIM'.
            vec![
                b"XCLAIM".to_vec(),
                b"xs".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"BAD".to_vec(),
                b"0-0".to_vec(),
            ],
            // Bad IDLE option arg would normally surface
            // 'Invalid IDLE option argument for XCLAIM'.
            vec![
                b"XCLAIM".to_vec(),
                b"xs".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"0".to_vec(),
                b"0-0".to_vec(),
                b"IDLE".to_vec(),
                b"BAD".to_vec(),
            ],
            // Unknown trailing option would normally surface
            // "Unrecognized XCLAIM option 'NOSUCH'".
            vec![
                b"XCLAIM".to_vec(),
                b"xs".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"0".to_vec(),
                b"0-0".to_vec(),
                b"NOSUCH".to_vec(),
            ],
        ] {
            let reply = dispatch_argv(&argv, &mut store, 0).expect("xclaim returns frame");
            assert_eq!(
                reply,
                RespFrame::Error("NOGROUP No such key 'xs' or consumer group 'g'".to_string()),
                "xclaim with missing group must NOGROUP, got {reply:?} for {argv:?}"
            );
        }

        // Missing key (not just group) also short-circuits.
        let reply = dispatch_argv(
            &[
                b"XCLAIM".to_vec(),
                b"nokey".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"BAD".to_vec(),
                b"0-0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            reply,
            RespFrame::Error("NOGROUP No such key 'nokey' or consumer group 'g'".to_string())
        );

        // Wrong-type key surfaces WRONGTYPE per upstream checkType, not
        // NOGROUP.
        dispatch_argv(
            &[b"SET".to_vec(), b"strkey".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        let err = dispatch_argv(
            &[
                b"XCLAIM".to_vec(),
                b"strkey".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"0".to_vec(),
                b"0-0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("wrongtype");
        assert!(matches!(err, CommandError::Store(StoreError::WrongType)));
    }

    #[test]
    fn nogroup_errors_report_logical_key_not_db_namespaced() {
        use crate::{
            xgroup_nogroup_error, xinfo_nogroup_consumers_error, xreadgroup_nogroup_error,
            xstream_nogroup_error,
        };
        // Command handlers receive DB-namespaced physical keys; the NOGROUP
        // error wording must echo the LOGICAL key the client sent, never the
        // internal `\0frdb\0<db><key>` encoding. (Found by random_command_differ:
        // SELECT 3; XREADGROUP ... STREAMS s > leaked the prefix.)
        let phys = fr_store::encode_db_key(3, b"mystream");
        assert_ne!(phys.as_slice(), b"mystream", "db>0 key must be prefixed");
        for err in [
            xreadgroup_nogroup_error(&phys, b"g"),
            xstream_nogroup_error(&phys, b"g"),
            xgroup_nogroup_error(&phys, b"g"),
            xinfo_nogroup_consumers_error(&phys, b"g"),
        ] {
            let RespFrame::Error(msg) = err else {
                panic!("expected NOGROUP error frame, got {err:?}");
            };
            assert!(
                msg.contains("'mystream'"),
                "must report logical key: {msg:?}"
            );
            assert!(!msg.contains("frdb"), "must not leak db prefix: {msg:?}");
        }
        // db 0 keys are unprefixed and pass through unchanged.
        let RespFrame::Error(msg) = xreadgroup_nogroup_error(b"plainkey", b"g") else {
            panic!("expected error");
        };
        assert!(msg.contains("'plainkey'"), "db0 key unchanged: {msg:?}");
    }

    #[test]
    fn xinfo_stream_lookup_ordering_and_arg_validation_match_upstream() {
        // Pin three XINFO STREAM divergences vs vendored 7.2.4
        // (frankenredis-y8m7):
        //   1. Missing key + bogus tail -> NoSuchKey (lookup runs
        //      before arg validation; t_stream.c::xinfoCommand).
        //   2. Existing key + malformed FULL tail -> upstream's
        //      addReplySubcommandSyntaxError envelope, NOT the
        //      table-level wrong-arity wording.
        //   3. FULL COUNT -1 -> default 10, no error (upstream
        //      silently clamps negatives to default).
        let mut store = Store::new();

        let missing = dispatch_argv(
            &[
                b"XINFO".to_vec(),
                b"STREAM".to_vec(),
                b"nokey".to_vec(),
                b"FULL".to_vec(),
                b"extra".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xinfo missing");
        assert_eq!(missing, CommandError::NoSuchKey);

        // Seed a stream so existing-key paths exercise the validator.
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1-0".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        let bad_tail = dispatch_argv(
            &[
                b"XINFO".to_vec(),
                b"STREAM".to_vec(),
                b"s".to_vec(),
                b"FULL".to_vec(),
                b"NOPE".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xinfo bad tail");
        assert_eq!(
            bad_tail,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments for 'STREAM'. Try XINFO HELP."
                    .to_string()
            )
        );

        // FULL COUNT -1 must succeed (silently default 10).
        let neg_count = dispatch_argv(
            &[
                b"XINFO".to_vec(),
                b"STREAM".to_vec(),
                b"s".to_vec(),
                b"FULL".to_vec(),
                b"COUNT".to_vec(),
                b"-1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xinfo neg count");
        assert!(matches!(neg_count, RespFrame::Array(Some(_))));
    }

