    #[test]
    fn xinfo_consumers_reports_group_membership() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1000-0".to_vec(),
                b"field".to_vec(),
                b"value".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd");
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");

        let empty = dispatch_argv(
            &[
                b"XINFO".to_vec(),
                b"CONSUMERS".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xinfo consumers empty");
        assert_eq!(empty, RespFrame::Array(Some(Vec::new())));

        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATECONSUMER".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("createconsumer c2");
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATECONSUMER".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"c1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("createconsumer c1");

        let consumers = dispatch_argv(
            &[
                b"XINFO".to_vec(),
                b"CONSUMERS".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xinfo consumers");
        assert_eq!(
            consumers,
            RespFrame::Array(Some(vec![
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"name".to_vec())),
                    RespFrame::BulkString(Some(b"c1".to_vec())),
                    RespFrame::BulkString(Some(b"pending".to_vec())),
                    RespFrame::Integer(0),
                    RespFrame::BulkString(Some(b"idle".to_vec())),
                    RespFrame::Integer(0),
                    RespFrame::BulkString(Some(b"inactive".to_vec())),
                    // (frankenredis-p4dpj) freshly-created consumer
                    // via XGROUP CREATECONSUMER has active_time = None
                    // -> inactive = -1 (matches vendored 7.2.4).
                    RespFrame::Integer(-1),
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"name".to_vec())),
                    RespFrame::BulkString(Some(b"c2".to_vec())),
                    RespFrame::BulkString(Some(b"pending".to_vec())),
                    RespFrame::Integer(0),
                    RespFrame::BulkString(Some(b"idle".to_vec())),
                    RespFrame::Integer(0),
                    RespFrame::BulkString(Some(b"inactive".to_vec())),
                    RespFrame::Integer(-1),
                ])),
            ]))
        );
    }

