    #[test]
    fn xgroup_setid_updates_group_cursor_and_supports_dollar() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1000-0".to_vec(),
                b"f1".to_vec(),
                b"v1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 1");
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1001-0".to_vec(),
                b"f2".to_vec(),
                b"v2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xadd 2");
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup create");

        let setid = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"SETID".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"1000-0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup setid");
        assert_eq!(setid, RespFrame::SimpleString("OK".to_string()));

        let groups_after_setid = dispatch_argv(
            &[b"XINFO".to_vec(), b"GROUPS".to_vec(), b"s".to_vec()],
            &mut store,
            0,
        )
        .expect("xinfo groups after setid");
        assert_eq!(
            groups_after_setid,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"name".to_vec())),
                RespFrame::BulkString(Some(b"g1".to_vec())),
                RespFrame::BulkString(Some(b"consumers".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"pending".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
                RespFrame::BulkString(Some(b"1000-0".to_vec())),
                RespFrame::BulkString(Some(b"entries-read".to_vec())),
                RespFrame::BulkString(None),
                // (frankenredis-9wr6) lag = 1 entry behind tail.
                RespFrame::BulkString(Some(b"lag".to_vec())),
                RespFrame::Integer(1),
            ]))]))
        );

        let setid_dollar = dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"SETID".to_vec(),
                b"s".to_vec(),
                b"g1".to_vec(),
                b"$".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xgroup setid dollar");
        assert_eq!(setid_dollar, RespFrame::SimpleString("OK".to_string()));

        let groups_after_dollar = dispatch_argv(
            &[b"XINFO".to_vec(), b"GROUPS".to_vec(), b"s".to_vec()],
            &mut store,
            0,
        )
        .expect("xinfo groups after dollar");
        assert_eq!(
            groups_after_dollar,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"name".to_vec())),
                RespFrame::BulkString(Some(b"g1".to_vec())),
                RespFrame::BulkString(Some(b"consumers".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"pending".to_vec())),
                RespFrame::Integer(0),
                RespFrame::BulkString(Some(b"last-delivered-id".to_vec())),
                RespFrame::BulkString(Some(b"1001-0".to_vec())),
                RespFrame::BulkString(Some(b"entries-read".to_vec())),
                RespFrame::BulkString(None),
                // (frankenredis-9wr6) SETID $ moved cursor to tail
                // (1001-0) → caught up → lag = 0.
                RespFrame::BulkString(Some(b"lag".to_vec())),
                RespFrame::Integer(0),
            ]))]))
        );
    }

    #[test]
    fn xautoclaim_error_wordings_match_upstream() {
        // Pin upstream xautoclaimCommand wordings (frankenredis-rqr7):
        //   - min-idle-time non-numeric -> "Invalid min-idle-time argument for XAUTOCLAIM"
        //   - min-idle-time negative    -> silently clamped to 0
        //   - COUNT non-numeric or <=0  -> "COUNT must be > 0"
        //   - COUNT without value       -> SyntaxError
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"XADD".to_vec(),
                b"s".to_vec(),
                b"1-0".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        // min-idle-time non-numeric.
        let bad_min = dispatch_argv(
            &[
                b"XAUTOCLAIM".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"abc".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xautoclaim bad min-idle");
        assert_eq!(
            bad_min,
            CommandError::Custom("ERR Invalid min-idle-time argument for XAUTOCLAIM".to_string())
        );

        // min-idle-time negative -> success (clamped to 0).
        let neg_min = dispatch_argv(
            &[
                b"XAUTOCLAIM".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"-100".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("xautoclaim neg min-idle");
        assert!(matches!(neg_min, RespFrame::Array(Some(_))));

        // COUNT non-numeric.
        let bad_count = dispatch_argv(
            &[
                b"XAUTOCLAIM".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"0".to_vec(),
                b"0".to_vec(),
                b"COUNT".to_vec(),
                b"abc".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xautoclaim bad COUNT");
        assert_eq!(
            bad_count,
            CommandError::Custom("ERR COUNT must be > 0".to_string())
        );

        // COUNT zero / negative.
        for c in [b"0".as_slice(), b"-1".as_slice()] {
            let err = dispatch_argv(
                &[
                    b"XAUTOCLAIM".to_vec(),
                    b"s".to_vec(),
                    b"g".to_vec(),
                    b"c".to_vec(),
                    b"0".to_vec(),
                    b"0".to_vec(),
                    b"COUNT".to_vec(),
                    c.to_vec(),
                ],
                &mut store,
                0,
            )
            .expect_err("xautoclaim non-positive COUNT");
            assert_eq!(
                err,
                CommandError::Custom("ERR COUNT must be > 0".to_string()),
                "{c:?}"
            );
        }

        // COUNT without value -> SyntaxError.
        let count_no_value = dispatch_argv(
            &[
                b"XAUTOCLAIM".to_vec(),
                b"s".to_vec(),
                b"g".to_vec(),
                b"c".to_vec(),
                b"0".to_vec(),
                b"0".to_vec(),
                b"COUNT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("xautoclaim COUNT no value");
        assert_eq!(count_no_value, CommandError::SyntaxError);
    }

    #[test]
    fn hincrbyfloat_non_numeric_field_uses_hash_specific_wording() {
        // Pin upstream t_hash.c::hincrbyfloatCommand wording: when
        // the existing field's value can't be parsed as a float,
        // surface "hash value is not a float" (paralleling HINCRBY's
        // "hash value is not an integer"), not the generic
        // "value is not a valid float". (frankenredis-tdh9)
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"HSET".to_vec(),
                b"h".to_vec(),
                b"f".to_vec(),
                b"abc".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        let bad_field = dispatch_argv(
            &[
                b"HINCRBYFLOAT".to_vec(),
                b"h".to_vec(),
                b"f".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("hincrbyfloat bad field");
        assert_eq!(
            bad_field,
            CommandError::Custom("ERR hash value is not a float".to_string())
        );

        // Sanity: HINCRBY (integer variant) keeps "hash value is not
        // an integer" wording.
        let bad_int = dispatch_argv(
            &[
                b"HINCRBY".to_vec(),
                b"h".to_vec(),
                b"f".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        );
        let got = match bad_int {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(got, "ERR hash value is not an integer".to_string());
    }

    #[test]
    fn zinter_borrowed_core_matches_materialized_reference_crimsonhawk() {
        // (CrimsonHawk) ZINTER now iterates the first source by reference and
        // clones only survivors via `zinter_members_argv_order_no_stats`. Prove
        // the visible reply is byte-identical to an independent reference that
        // materializes the first source, then filters/aggregates in argv order,
        // across SortedSet/Set mixes, WEIGHTS, AGGREGATE SUM/MIN/MAX, WITHSCORES,
        // a disjoint pair, a single key, and a missing key.
        fn seed() -> Store {
            let mut store = Store::new();
            // zset za: a=1, b=2, c=3, d=4
            for (m, s) in [("a", "1"), ("b", "2"), ("c", "3"), ("d", "4")] {
                dispatch_argv(
                    &[b"ZADD".to_vec(), b"za".to_vec(), s.into(), m.into()],
                    &mut store,
                    0,
                )
                .unwrap();
            }
            // zset zb: b=10, c=20, e=30
            for (m, s) in [("b", "10"), ("c", "20"), ("e", "30")] {
                dispatch_argv(
                    &[b"ZADD".to_vec(), b"zb".to_vec(), s.into(), m.into()],
                    &mut store,
                    0,
                )
                .unwrap();
            }
            // plain set sc: {c, d, f}  (membership score 1.0)
            dispatch_argv(
                &[
                    b"SADD".to_vec(),
                    b"sc".to_vec(),
                    b"c".to_vec(),
                    b"d".to_vec(),
                    b"f".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap();
            // disjoint zset zx: x=1, y=2
            for (m, s) in [("x", "1"), ("y", "2")] {
                dispatch_argv(
                    &[b"ZADD".to_vec(), b"zx".to_vec(), s.into(), m.into()],
                    &mut store,
                    0,
                )
                .unwrap();
            }
            store
        }

        // Independent reference DATA mirroring the OLD ZINTER loop exactly.
        // Returns sorted (member, score) pairs; the reply byte-format/emit code is
        // unchanged by this refactor, so comparing data is the right invariant.
        fn reference(
            store: &mut Store,
            keys: &[&[u8]],
            weights: &[f64],
            aggregate: &[u8],
        ) -> Vec<(Vec<u8>, f64)> {
            let first = store.zget_members_with_scores_no_stats(keys[0]).unwrap();
            let w0 = weights.first().copied().unwrap_or(1.0);
            let mut result: Vec<(Vec<u8>, f64)> = Vec::new();
            for (member, score) in first {
                let ws = score * w0;
                let mut combined = if ws.is_nan() { 0.0 } else { ws };
                let mut in_all = true;
                for (i, &key) in keys[1..].iter().enumerate() {
                    match store
                        .zget_score_or_set_member_no_stats(key, &member)
                        .unwrap()
                    {
                        Some(s) => {
                            let w = weights.get(i + 1).copied().unwrap_or(1.0);
                            let b = s * w;
                            combined = if aggregate.eq_ignore_ascii_case(b"MIN") {
                                combined.min(b)
                            } else if aggregate.eq_ignore_ascii_case(b"MAX") {
                                combined.max(b)
                            } else {
                                let r = combined + b;
                                if r.is_nan() { 0.0 } else { r }
                            };
                        }
                        None => {
                            in_all = false;
                            break;
                        }
                    }
                }
                if in_all {
                    result.push((member, combined));
                }
            }
            result.sort_by(|a, b| {
                a.1.partial_cmp(&b.1)
                    .unwrap_or(std::cmp::Ordering::Equal)
                    .then_with(|| a.0.cmp(&b.0))
            });
            result
        }

        // Parse a ZINTER ... WITHSCORES reply into (member, score) pairs.
        fn pairs_from_reply(reply: &RespFrame) -> Vec<(Vec<u8>, f64)> {
            let RespFrame::Array(Some(items)) = reply else {
                panic!("expected array reply, got {reply:?}");
            };
            let mut out = Vec::new();
            let mut it = items.iter();
            while let Some(m) = it.next() {
                let RespFrame::BulkString(Some(member)) = m else {
                    panic!("expected bulk member, got {m:?}");
                };
                let s = it.next().expect("withscores: score follows member");
                let RespFrame::BulkString(Some(score)) = s else {
                    panic!("expected bulk score, got {s:?}");
                };
                let score: f64 = std::str::from_utf8(score).unwrap().parse().unwrap();
                out.push((member.clone(), score));
            }
            out
        }

        let scenarios: &[(&[&[u8]], Vec<f64>, &[u8])] = &[
            (&[b"za", b"zb"], vec![1.0, 1.0], b"SUM"),
            (&[b"za", b"zb"], vec![2.0, 3.0], b"SUM"),
            (&[b"za", b"zb"], vec![1.0, 1.0], b"MIN"),
            (&[b"za", b"zb"], vec![1.0, 1.0], b"MAX"),
            (&[b"za", b"sc"], vec![1.0, 1.0], b"SUM"),
            (&[b"sc", b"za"], vec![1.0, 1.0], b"SUM"),
            (&[b"za", b"zb", b"sc"], vec![1.0, 1.0, 1.0], b"SUM"),
            (&[b"za", b"zx"], vec![1.0, 1.0], b"SUM"),
            (&[b"za"], vec![1.0], b"SUM"),
            (&[b"za", b"missing"], vec![1.0, 1.0], b"SUM"),
        ];

        for (keys, weights, aggregate) in scenarios {
            let mut argv: Vec<Vec<u8>> = vec![b"ZINTER".to_vec(), keys.len().to_string().into()];
            for k in *keys {
                argv.push(k.to_vec());
            }
            argv.push(b"WEIGHTS".to_vec());
            for w in weights {
                argv.push(format!("{w}").into_bytes());
            }
            argv.push(b"AGGREGATE".to_vec());
            argv.push(aggregate.to_vec());
            argv.push(b"WITHSCORES".to_vec());

            let mut store = seed();
            let got = dispatch_argv(&argv, &mut store, 0).expect("zinter dispatch");
            let got_pairs = pairs_from_reply(&got);
            let mut ref_store = seed();
            let want = reference(&mut ref_store, keys, weights, aggregate);
            assert_eq!(
                got_pairs,
                want,
                "ZINTER diverged for keys={keys:?} weights={weights:?} aggregate={}",
                String::from_utf8_lossy(aggregate),
            );
        }
    }

    #[test]
    fn zinter_zunion_zdiff_family_numkeys_zero_uses_per_command_wording() {
        // Pin upstream t_zset.c per-command "at least 1 input key is
        // needed for '<cmd>' command" wording for numkeys=0 across
        // the six aggregate commands (frankenredis-2x9t). Generic
        // InvalidInteger (ZINTER/ZUNION/ZDIFF/ZDIFFSTORE) and shared
        // wording (ZUNIONSTORE/ZINTERSTORE) are the regression.
        let mut store = Store::new();

        // Each argv satisfies the upstream commands.def arity (-3 for
        // ZINTER/ZUNION/ZDIFF, -4 for the *STORE variants) so the
        // numkeys=0 path is reached rather than the generic wrong-arity.
        let cases: &[(&[&[u8]], &str)] = &[
            (
                &[b"ZINTER", b"0", b"k"],
                "ERR at least 1 input key is needed for 'zinter' command",
            ),
            (
                &[b"ZUNION", b"0", b"k"],
                "ERR at least 1 input key is needed for 'zunion' command",
            ),
            (
                &[b"ZDIFF", b"0", b"k"],
                "ERR at least 1 input key is needed for 'zdiff' command",
            ),
            (
                &[b"ZDIFFSTORE", b"dst", b"0", b"k"],
                "ERR at least 1 input key is needed for 'zdiffstore' command",
            ),
            (
                &[b"ZUNIONSTORE", b"dst", b"0", b"k"],
                "ERR at least 1 input key is needed for 'zunionstore' command",
            ),
            (
                &[b"ZINTERSTORE", b"dst", b"0", b"k"],
                "ERR at least 1 input key is needed for 'zinterstore' command",
            ),
        ];

        for (argv_in, expected) in cases {
            let argv: Vec<Vec<u8>> = argv_in.iter().map(|s| s.to_vec()).collect();
            let result = dispatch_argv(&argv, &mut store, 0);
            let got = match result {
                Ok(RespFrame::Error(s)) => s,
                Err(e) => match e.to_resp() {
                    RespFrame::Error(s) => s,
                    other => panic!("expected error frame, got {other:?}"),
                },
                other => panic!("expected error frame for {argv_in:?}, got {other:?}"),
            };
            assert_eq!(&got, *expected, "argv: {argv_in:?}");
        }
    }

    #[test]
    fn zsetop_source_type_check_precedes_option_parse() {
        // (frankenredis-8g0ad) Upstream zunionInterDiffGenericCommand reads +
        // type-checks every source key (ZSET/SET ok, else WRONGTYPE) BEFORE
        // parsing WEIGHTS/AGGREGATE/WITHSCORES, so a wrong-type source key with
        // a malformed trailing option surfaces WRONGTYPE — not a syntax error.
        // The numkeys-overflow syntax check still precedes the type-check, and a
        // SET source counts as valid (proceeds to the option syntax check).
        let argv = |parts: &[&str]| -> Vec<Vec<u8>> {
            parts.iter().map(|p| p.as_bytes().to_vec()).collect()
        };
        let is_wrongtype = |r: Result<RespFrame, CommandError>| -> bool {
            matches!(r, Err(CommandError::Store(fr_store::StoreError::WrongType)))
        };
        let mut store = Store::new();
        store.set(b"str".to_vec(), b"v".to_vec(), None, 0);
        dispatch_argv(&argv(&["SADD", "set", "a"]), &mut store, 0).unwrap();
        dispatch_argv(&argv(&["ZADD", "zs", "1", "a"]), &mut store, 0).unwrap();

        // wrong-type source + malformed option -> WRONGTYPE (all six commands)
        for c in [
            &["ZUNIONSTORE", "d", "1", "str", "WEIGHTS"][..],
            &["ZINTERSTORE", "d", "1", "str", "str", "str"][..],
            &["ZDIFFSTORE", "d", "2", "set", "str", "WEIGHTS"][..],
            &["ZUNION", "1", "str", "AGGREGATE", "BAD"][..],
            &["ZINTER", "2", "str", "zs", "WEIGHTS", "1"][..],
            &["ZDIFF", "2", "str", "none", "WITHSCORES", "EXTRA"][..],
        ] {
            assert!(
                is_wrongtype(dispatch_argv(&argv(c), &mut store, 0)),
                "{c:?} must be WRONGTYPE"
            );
        }

        // numkeys overflow still beats the type-check (syntax error).
        assert!(matches!(
            dispatch_argv(&argv(&["ZUNIONSTORE", "d", "9", "str"]), &mut store, 0),
            Err(CommandError::SyntaxError)
        ));

        // A SET source is valid -> reaches the option syntax check (bad AGGREGATE).
        assert!(matches!(
            dispatch_argv(
                &argv(&["ZUNIONSTORE", "d", "1", "set", "AGGREGATE", "BAD"]),
                &mut store,
                0
            ),
            Err(CommandError::SyntaxError)
        ));
    }

    #[test]
    fn zinterstore_zunionstore_negative_numkeys_uses_input_key_wording() {
        // (frankenredis-zstoreneg) Upstream t_zset.c::zunionInterDiff
        // GenericCommand gates on `setnum < 1` after a successful
        // getLongFromObjectOrReply, so a NEGATIVE count surfaces the
        // same dedicated 'at least 1 input key is needed for <cmd>
        // command' wording as numkeys=0. fr was splitting the check
        // into a (numkeys < 0) → InvalidInteger arm plus a separate
        // (numkeys == 0) → input-key arm, diverging from vendored
        // 7.2.4 only on the negative branch. ZDIFFSTORE / ZINTER /
        // ZUNION / ZDIFF / ZINTERCARD already used `<= 0` correctly;
        // the regression was scoped to ZUNIONSTORE and ZINTERSTORE.
        let mut store = Store::new();
        let cases: &[(&[&[u8]], &str)] = &[
            (
                &[b"ZUNIONSTORE", b"dst", b"-1", b"k"],
                "ERR at least 1 input key is needed for 'zunionstore' command",
            ),
            (
                &[b"ZUNIONSTORE", b"dst", b"-100", b"a", b"b"],
                "ERR at least 1 input key is needed for 'zunionstore' command",
            ),
            (
                &[b"ZINTERSTORE", b"dst", b"-1", b"k"],
                "ERR at least 1 input key is needed for 'zinterstore' command",
            ),
            (
                &[b"ZINTERSTORE", b"dst", b"-100", b"a", b"b"],
                "ERR at least 1 input key is needed for 'zinterstore' command",
            ),
        ];
        for (argv_in, expected) in cases {
            let argv: Vec<Vec<u8>> = argv_in.iter().map(|s| s.to_vec()).collect();
            let result = dispatch_argv(&argv, &mut store, 0);
            let got = match result {
                Ok(RespFrame::Error(s)) => s,
                Err(e) => match e.to_resp() {
                    RespFrame::Error(s) => s,
                    other => panic!("expected error frame, got {other:?}"),
                },
                other => panic!("expected error frame for {argv_in:?}, got {other:?}"),
            };
            assert_eq!(&got, *expected, "argv: {argv_in:?}");
        }
    }

    #[test]
    fn info_server_uptime_in_seconds_is_relative_to_startup_not_unix_epoch() {
        // Pin upstream server.c::genRedisInfoString uptime semantics
        // (frankenredis-ifj5): uptime_in_seconds = (now - server_start)
        // / 1000, NOT the absolute Unix timestamp. Source-level fix at
        // lib.rs:12338 plus Store::server_start_ms (fr-store/src/lib.rs:
        // 1326). Differential probe vs vendored 7.2.4 confirmed fr was
        // previously emitting ~1.7e9 (Unix ms / 1000).
        let mut store = Store::new();
        // Pin server_start_ms to a known value so the assertion
        // tolerates any wall-clock drift in the suite.
        store.server_start_ms = 1_000_000;
        let now_ms = 1_000_000 + 30_000; // 30 seconds later
        let out = dispatch_argv(&[b"INFO".to_vec(), b"server".to_vec()], &mut store, now_ms)
            .expect("INFO server");
        let body = match out {
            RespFrame::BulkString(Some(b)) => String::from_utf8(b).expect("info utf8"),
            other => panic!("expected BulkString from INFO, got {other:?}"),
        };
        assert!(
            body.contains("uptime_in_seconds:30\r\n"),
            "expected uptime_in_seconds:30 in INFO server: {body}"
        );
        assert!(
            body.contains("uptime_in_days:0\r\n"),
            "expected uptime_in_days:0 in INFO server: {body}"
        );
        // Regression guard: uptime must not approach the absolute
        // wall-clock value. (Pre-fix value was ~1.7e9.)
        for line in body.lines() {
            if let Some(val) = line.strip_prefix("uptime_in_seconds:") {
                let v: u64 = val.trim().parse().expect("uptime numeric");
                assert!(
                    v < 1_000_000_000,
                    "uptime_in_seconds={v} looks like a Unix timestamp, not seconds-since-startup"
                );
            }
        }
    }

    #[test]
    fn scan_family_rejects_novalues_for_7_2_4_baseline_and_function_list_libraryname_wording() {
        // Pin upstream parity for two scoped wording divergences
        // (frankenredis-bvw2 + frankenredis-c5746):
        //
        // (a) NOVALUES is a Redis 7.4 HSCAN-only option; the project's
        //     parity baseline is 7.2.4, so SCAN/SSCAN/ZSCAN/HSCAN must
        //     all reject it as 'ERR syntax error'. Source-level guard
        //     at parse_scan_args_with_novalues + per-call sites
        //     passing accept_novalues=false. Differential probe vs
        //     vendored 7.2.4 confirmed (with populated keys, since
        //     missing-key short-circuits to empty-scan before parse).
        // (b) FUNCTION LIST LIBRARYNAME with no argument must reply
        //     'ERR library name argument was not given' (not the
        //     generic syntax error).
        let mut store = Store::new();

        // Seed populated keys so SSCAN/ZSCAN reach parse_scan_args
        // (missing keys legitimately return empty-scan).
        dispatch_argv(
            &[
                b"SADD".to_vec(),
                b"s".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("sadd seed");
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zadd seed");
        dispatch_argv(
            &[
                b"HSET".to_vec(),
                b"h".to_vec(),
                b"f".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("hset seed");

        // (frankenredis-c5746) NOVALUES is a Redis 7.4 HSCAN option;
        // the project's parity baseline is 7.2.4, so HSCAN must also
        // reject it (alongside SCAN/SSCAN/ZSCAN which never accepted
        // it). Differential probe vs vendored 7.2.4 16380 confirmed:
        //   HSCAN h 0 NOVALUES -> ERR syntax error.
        // Earlier versions of fr accepted HSCAN+NOVALUES as a forward-
        // compat to 7.4, but that broke parity for the 7.2.4 baseline
        // — same class as v0swv (DEBUG OBJECT hexpired_fields) and
        // is now disabled across the entire SCAN family.
        let novalues_reject_cases: &[&[&[u8]]] = &[
            &[b"SCAN", b"0", b"NOVALUES"],
            &[b"SSCAN", b"s", b"0", b"NOVALUES"],
            &[b"ZSCAN", b"z", b"0", b"NOVALUES"],
            &[b"HSCAN", b"h", b"0", b"NOVALUES"],
        ];
        for argv_in in novalues_reject_cases {
            let argv: Vec<Vec<u8>> = argv_in.iter().map(|b| b.to_vec()).collect();
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("scan novalues");
            assert_eq!(
                err,
                CommandError::SyntaxError,
                "argv={argv_in:?} should reject NOVALUES with syntax error"
            );
        }

        // FUNCTION LIST LIBRARYNAME with no argument: dedicated wording.
        let func_err = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LIST".to_vec(),
                b"LIBRARYNAME".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("function list libraryname missing arg");
        assert_eq!(
            func_err,
            CommandError::Custom("ERR library name argument was not given".to_string())
        );
    }

    #[test]
    fn parse_f64_arg_rejects_overflow_to_infinity_like_redis() {
        // Pin upstream util.c::string2d ERANGE rejection for
        // overflow-to-infinity (frankenredis-uxwm). Rust's parse::<f64>
        // silently saturates "1e500" to f64::INFINITY; we must reject
        // such inputs while still accepting explicit infinity literals.
        // Differential probe vs vendored redis 7.2.4 (ZADD z <v> a)
        // confirmed:
        //   1e500, -1e500             -> "ERR value is not a valid float"
        //   1e308, inf, +inf, -inf,
        //   infinity, Infinity, 1.5   -> accepted
        let mut store = Store::new();

        // Overflow-to-infinity must surface ValueNotFloat at the ZADD
        // arity boundary.
        for bad in [b"1e500".as_slice(), b"-1e500", b"1e1000", b"+1e500"] {
            let err = dispatch_argv(
                &[b"ZADD".to_vec(), b"z".to_vec(), bad.to_vec(), b"m".to_vec()],
                &mut store,
                0,
            )
            .expect_err("zadd overflow");
            assert_eq!(
                err,
                CommandError::Store(fr_store::StoreError::ValueNotFloat),
                "bad={:?}",
                String::from_utf8_lossy(bad)
            );
        }

        // Explicit infinity literals are still accepted (case
        // variants and optional sign).
        for good in [
            b"inf".as_slice(),
            b"+inf",
            b"-inf",
            b"INF",
            b"infinity",
            b"Infinity",
            b"-Infinity",
            b"1e308",
            b"1.5",
            b"0",
        ] {
            let mut s = Store::new();
            let out = dispatch_argv(
                &[
                    b"ZADD".to_vec(),
                    b"z".to_vec(),
                    good.to_vec(),
                    b"m".to_vec(),
                ],
                &mut s,
                0,
            )
            .expect("zadd ok");
            assert_eq!(
                out,
                RespFrame::Integer(1),
                "good={:?}",
                String::from_utf8_lossy(good)
            );
        }
    }

    #[test]
    fn zadd_zincrby_reject_decimal_underflow_to_zero_mb9tm() {
        // (frankenredis-mb9tm) Upstream util.c::string2d (used by
        // ZADD/ZINCRBY's getDoubleFromObjectOrReply) rejects ERANGE
        // underflow when the result is exactly 0 (e.g. `1e-1000`).
        // Rust's f64::FromStr silently rounds to 0 with no errno
        // signal, so parse_score_f64_arg reapplies the gate using a
        // mantissa-digit heuristic.
        let mut store = Store::new();

        // ZADD with underflowing scores must error like upstream.
        for bad in [
            b"1e-1000".as_slice(),
            b"-1e-1000",
            b"+1e-1000",
            b"1.0e-400",
            b"0.5e-400",
            b"5e-500",
        ] {
            let err = dispatch_argv(
                &[b"ZADD".to_vec(), b"z".to_vec(), bad.to_vec(), b"m".to_vec()],
                &mut store,
                0,
            )
            .expect_err("expected underflow rejection");
            assert_eq!(
                err,
                CommandError::Store(fr_store::StoreError::ValueNotFloat),
                "bad={:?}",
                String::from_utf8_lossy(bad)
            );
        }

        // ZINCRBY mirror.
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"m".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        for bad in [b"1e-1000".as_slice(), b"-1e-1000"] {
            let err = dispatch_argv(
                &[
                    b"ZINCRBY".to_vec(),
                    b"z".to_vec(),
                    bad.to_vec(),
                    b"m".to_vec(),
                ],
                &mut store,
                0,
            )
            .expect_err("zincrby underflow");
            assert_eq!(
                err,
                CommandError::Store(fr_store::StoreError::ValueNotFloat),
                "bad={:?}",
                String::from_utf8_lossy(bad)
            );
        }

        // ZADD INCR mirror.
        let err = dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"INCR".to_vec(),
                b"1e-1000".to_vec(),
                b"m".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("zadd incr underflow");
        assert_eq!(
            err,
            CommandError::Store(fr_store::StoreError::ValueNotFloat),
        );

        // Literal-zero forms still accepted — these parse to exactly
        // 0 with no ERANGE upstream.
        for good in [
            b"0".as_slice(),
            b"0.0",
            b"-0",
            b"-0.0",
            b"+0",
            b"0e1000",
            b"0e-1000",
            b"0.0e0",
        ] {
            let mut s = Store::new();
            let out = dispatch_argv(
                &[
                    b"ZADD".to_vec(),
                    b"z".to_vec(),
                    good.to_vec(),
                    b"m".to_vec(),
                ],
                &mut s,
                0,
            )
            .expect("zadd literal zero ok");
            assert_eq!(
                out,
                RespFrame::Integer(1),
                "good={:?}",
                String::from_utf8_lossy(good)
            );
        }

        // Denormal-but-nonzero values stay accepted in fr (Rust's
        // parser yields the denormal as a non-zero f64; upstream's
        // strtod returns the same denormal so *dp != 0 and the
        // ERANGE gate doesn't fire).
        let mut s = Store::new();
        let out = dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1e-310".to_vec(),
                b"m".to_vec(),
            ],
            &mut s,
            0,
        )
        .expect("denormal accepted");
        assert_eq!(out, RespFrame::Integer(1));

        // INCRBYFLOAT/HINCRBYFLOAT continue to accept underflowing
        // deltas — upstream uses long double which can represent
        // 1e-1000 without underflow, so the ERANGE gate doesn't fire
        // there. fr loses precision but matches the accept/reject
        // decision (both yield no observable change for tiny deltas).
        let mut s = Store::new();
        s.set(b"k".to_vec(), b"10".to_vec(), None, 0);
        let out = dispatch_argv(
            &[b"INCRBYFLOAT".to_vec(), b"k".to_vec(), b"1e-1000".to_vec()],
            &mut s,
            0,
        )
        .expect("incrbyfloat underflow still accepted");
        if let RespFrame::BulkString(Some(bytes)) = out {
            let s = String::from_utf8_lossy(&bytes);
            assert!(s == "10" || s == "10.0", "got {s}");
        } else {
            panic!("expected bulk string, got {:?}", out);
        }
    }

    #[test]
    fn zincrby_zadd_incr_nan_error_wording_matches_upstream() {
        // Pin upstream t_zset.c NaN-result wording for ZINCRBY and
        // ZADD INCR (frankenredis-r76j): "resulting score is not a
        // number (NaN)" — distinct from INCRBYFLOAT's "increment
        // would produce NaN or Infinity" wording (which is preserved
        // for the float-string command at dispatch boundary).
        let mut store = Store::new();
        // Seed +inf score; -inf increment yields NaN.
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"inf".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        let zincrby_nan = dispatch_argv(
            &[
                b"ZINCRBY".to_vec(),
                b"z".to_vec(),
                b"-inf".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("zincrby nan");
        assert_eq!(
            zincrby_nan,
            CommandError::Custom("ERR resulting score is not a number (NaN)".to_string())
        );

        let zadd_incr_nan = dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"INCR".to_vec(),
                b"-inf".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("zadd incr nan");
        assert_eq!(
            zadd_incr_nan,
            CommandError::Custom("ERR resulting score is not a number (NaN)".to_string())
        );

        // Sanity: INCRBYFLOAT keeps the original wording.
        dispatch_argv(
            &[b"SET".to_vec(), b"f".to_vec(), b"inf".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        let incrbyfloat = dispatch_argv(
            &[b"INCRBYFLOAT".to_vec(), b"f".to_vec(), b"-inf".to_vec()],
            &mut store,
            0,
        );
        let got = match incrbyfloat {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR increment would produce NaN or Infinity".to_string()
        );
    }

