    #[test]
    fn setrange_empty_value_short_circuits_before_size_check() {
        // (frankenredis-23ngn) Upstream t_string.c::setrangeCommand
        // returns the current strlen (or 0 for missing keys) without
        // running checkStringLength when value is empty. fr was
        // emitting 'string exceeds maximum allowed size' for offsets
        // > 512 MiB even when value was zero-length.
        let mut store = Store::new();

        // Missing key, empty value, huge offset → Integer(0).
        let out = dispatch_argv(
            &[
                b"SETRANGE".to_vec(),
                b"nokey".to_vec(),
                b"600000000".to_vec(),
                b"".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("missing key + empty value must short-circuit to 0");
        assert_eq!(out, RespFrame::Integer(0));
        // Must NOT have created the key.
        let exists =
            dispatch_argv(&[b"EXISTS".to_vec(), b"nokey".to_vec()], &mut store, 0).expect("exists");
        assert_eq!(exists, RespFrame::Integer(0));

        // Existing string, empty value, huge offset → Integer(strlen).
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"hello".to_vec()],
            &mut store,
            0,
        )
        .expect("seed");
        let out = dispatch_argv(
            &[
                b"SETRANGE".to_vec(),
                b"k".to_vec(),
                b"600000000".to_vec(),
                b"".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("existing key + empty value must return strlen");
        assert_eq!(out, RespFrame::Integer(5));
        // Value must be unchanged.
        let val = dispatch_argv(&[b"GET".to_vec(), b"k".to_vec()], &mut store, 0).expect("get");
        assert_eq!(val, RespFrame::BulkString(Some(b"hello".to_vec())));

        // Existing non-string + empty value → WRONGTYPE.
        dispatch_argv(
            &[b"RPUSH".to_vec(), b"lst".to_vec(), b"a".to_vec()],
            &mut store,
            0,
        )
        .expect("rpush");
        let err = dispatch_argv(
            &[
                b"SETRANGE".to_vec(),
                b"lst".to_vec(),
                b"600000000".to_vec(),
                b"".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("non-string + empty value must WRONGTYPE");
        assert_eq!(err, CommandError::Store(StoreError::WrongType));
    }

    /// (frankenredis-setrangeorder) Upstream t_string.c::setrangeCommand
    /// runs the type check before the size check, so SETRANGE on a
    /// list/hash/set key with a huge offset surfaces WRONGTYPE rather
    /// than the size-limit error. Pinned vs vendored Redis 7.2.4:
    ///   LPUSH listk a; SETRANGE listk 600000000 v -> WRONGTYPE
    #[test]
    fn setrange_wrongtype_check_precedes_size_check() {
        let mut store = Store::new();
        dispatch_argv(
            &[b"LPUSH".to_vec(), b"listk".to_vec(), b"a".to_vec()],
            &mut store,
            0,
        )
        .unwrap_or_else(|e| e.to_resp());
        let err = dispatch_argv(
            &[
                b"SETRANGE".to_vec(),
                b"listk".to_vec(),
                b"600000000".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("SETRANGE on list w/ huge offset must surface WRONGTYPE before size check");
        assert_eq!(err, CommandError::Store(StoreError::WrongType));

        // Missing key with same huge offset must still hit the size
        // limit (preserves existing 23ngn invariant).
        let r = dispatch_argv(
            &[
                b"SETRANGE".to_vec(),
                b"nonex".to_vec(),
                b"600000000".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_or_else(|e| e.to_resp());
        assert_eq!(
            r,
            RespFrame::Error(
                "ERR string exceeds maximum allowed size (proto-max-bulk-len)".to_string()
            )
        );
    }

