    // (frankenredis-expbase) Upstream
    // t_string.c::getExpireMillisecondsOrReply rejects EX/PX (and
    // SETEX/PSETEX) values whose ms-resolved expression added to
    // basetime would overflow LLONG_MAX. Pre-fix, fr only checked
    // the seconds*1000 ladder for SET/SETEX/GETEX EX and skipped
    // overflow validation entirely for PX/PSETEX/GETEX PX, so a
    // relative ms near i64::MAX silently saturated instead of
    // raising the canonical error wording.
    #[test]
    fn relative_expire_rejects_basetime_overflow_across_set_paths() {
        // basetime = 10s into the epoch (in ms). Anything
        // strictly greater than i64::MAX - 10_000 must be
        // rejected with the per-command "ERR invalid expire time"
        // wording.
        let now_ms: u64 = 10_000;
        let just_over: u64 = (i64::MAX as u64) - now_ms + 1;
        let just_under: u64 = (i64::MAX as u64) - now_ms;

        // SET ... PX <ms>
        {
            let mut store = Store::new();
            let err = dispatch_argv(
                &[
                    b"SET".to_vec(),
                    b"k".to_vec(),
                    b"v".to_vec(),
                    b"PX".to_vec(),
                    just_over.to_string().into_bytes(),
                ],
                &mut store,
                now_ms,
            )
            .expect_err("SET PX must reject basetime overflow");
            assert_eq!(
                err.to_resp(),
                RespFrame::Error("ERR invalid expire time in 'set' command".into())
            );
            // The boundary value MUST still be accepted.
            dispatch_argv(
                &[
                    b"SET".to_vec(),
                    b"k".to_vec(),
                    b"v".to_vec(),
                    b"PX".to_vec(),
                    just_under.to_string().into_bytes(),
                ],
                &mut store,
                now_ms,
            )
            .expect("SET PX boundary value must succeed");
        }

        // GETEX k PX <ms>
        {
            let mut store = Store::new();
            dispatch_argv(
                &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
                &mut store,
                now_ms,
            )
            .expect("SET k v");
            let err = dispatch_argv(
                &[
                    b"GETEX".to_vec(),
                    b"k".to_vec(),
                    b"PX".to_vec(),
                    just_over.to_string().into_bytes(),
                ],
                &mut store,
                now_ms,
            )
            .expect_err("GETEX PX must reject basetime overflow");
            assert_eq!(
                err.to_resp(),
                RespFrame::Error("ERR invalid expire time in 'getex' command".into())
            );
        }

        // PSETEX k <ms> v
        {
            let mut store = Store::new();
            let err = dispatch_argv(
                &[
                    b"PSETEX".to_vec(),
                    b"k".to_vec(),
                    just_over.to_string().into_bytes(),
                    b"v".to_vec(),
                ],
                &mut store,
                now_ms,
            )
            .expect_err("PSETEX must reject basetime overflow");
            assert_eq!(
                err.to_resp(),
                RespFrame::Error("ERR invalid expire time in 'psetex' command".into())
            );
        }

        // SET/SETEX/GETEX EX <seconds> overflow happens further
        // out (basetime / 1000). Ensure the same wording fires
        // for relative EX once seconds*1000 + basetime tips over.
        // Pick now_ms_big such that 1 second over the seconds-cap
        // window triggers the basetime check rather than the
        // seconds-ladder check.
        let now_ms_big: u64 = 5_000;
        let secs_over: u64 = ((i64::MAX as u64) - now_ms_big) / 1000 + 1;
        // Sanity: this is still ≤ i64::MAX/1000, so it bypasses
        // the older seconds-ladder check and exercises the new
        // basetime check instead.
        assert!(secs_over <= (i64::MAX as u64) / 1000);

        let mut store = Store::new();
        let err = dispatch_argv(
            &[
                b"SET".to_vec(),
                b"k".to_vec(),
                b"v".to_vec(),
                b"EX".to_vec(),
                secs_over.to_string().into_bytes(),
            ],
            &mut store,
            now_ms_big,
        )
        .expect_err("SET EX must reject basetime overflow");
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR invalid expire time in 'set' command".into())
        );

        let mut store = Store::new();
        let err = dispatch_argv(
            &[
                b"SETEX".to_vec(),
                b"k".to_vec(),
                secs_over.to_string().into_bytes(),
                b"v".to_vec(),
            ],
            &mut store,
            now_ms_big,
        )
        .expect_err("SETEX must reject basetime overflow");
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR invalid expire time in 'setex' command".into())
        );

        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            now_ms_big,
        )
        .expect("SET k v");
        let err = dispatch_argv(
            &[
                b"GETEX".to_vec(),
                b"k".to_vec(),
                b"EX".to_vec(),
                secs_over.to_string().into_bytes(),
            ],
            &mut store,
            now_ms_big,
        )
        .expect_err("GETEX EX must reject basetime overflow");
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR invalid expire time in 'getex' command".into())
        );
    }

    /// (frankenredis-getexdup) Upstream
    /// t_string.c::parseExtendedStringArgumentsOrReply allows the same
    /// expiry-kind to repeat (last value wins); only mixed kinds
    /// conflict. Verified vs vendored Redis 7.2.4:
    ///   GETEX k PERSIST PERSIST -> v
    ///   GETEX k EX 5 EX 10      -> v + TTL=10
    ///   GETEX k PXAT 1 PXAT 2   -> v
    ///   GETEX k EX 5 EXAT 100   -> ERR syntax error
    #[test]
    fn getex_accepts_duplicate_same_kind_options_and_rejects_mixed() {
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("SET k v");

        // Duplicate PERSIST is accepted (idempotent).
        let r = dispatch_argv(
            &[
                b"GETEX".to_vec(),
                b"k".to_vec(),
                b"PERSIST".to_vec(),
                b"PERSIST".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("GETEX PERSIST PERSIST");
        assert_eq!(r, RespFrame::BulkString(Some(b"v".to_vec())));

        // Duplicate EX accepted, second value wins.
        let r = dispatch_argv(
            &[
                b"GETEX".to_vec(),
                b"k".to_vec(),
                b"EX".to_vec(),
                b"5".to_vec(),
                b"EX".to_vec(),
                b"10".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("GETEX EX 5 EX 10");
        assert_eq!(r, RespFrame::BulkString(Some(b"v".to_vec())));
        let abs_ms = store.get_expires_at_ms(b"k", 0);
        assert_eq!(
            abs_ms,
            Some(10_000),
            "expected absolute expiry of now_ms(0) + 10s = 10000ms after EX 5 EX 10 override, got {abs_ms:?}"
        );

        // Duplicate PXAT accepted (last wins; no error).
        let r = dispatch_argv(
            &[
                b"GETEX".to_vec(),
                b"k".to_vec(),
                b"PXAT".to_vec(),
                b"1".to_vec(),
                b"PXAT".to_vec(),
                b"2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("GETEX PXAT 1 PXAT 2");
        assert_eq!(r, RespFrame::BulkString(Some(b"v".to_vec())));

        // Mixed kinds still rejected.
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("SET k v");
        let err = dispatch_argv(
            &[
                b"GETEX".to_vec(),
                b"k".to_vec(),
                b"EX".to_vec(),
                b"5".to_vec(),
                b"EXAT".to_vec(),
                b"100".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("GETEX EX 5 EXAT 100 must reject mixed kinds");
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR syntax error".to_string())
        );
        let err = dispatch_argv(
            &[
                b"GETEX".to_vec(),
                b"k".to_vec(),
                b"PERSIST".to_vec(),
                b"EX".to_vec(),
                b"5".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("GETEX PERSIST EX 5 must reject mixed kinds");
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR syntax error".to_string())
        );
    }

    /// (frankenredis-qw3kt) Upstream getexCommand
    /// (t_string.c::361) calls parseExtendedStringArgumentsOrReply
    /// (which only validates option keywords + arg presence), then
    /// lookupKeyReadOrReply, then checkType, and only then
    /// getExpireMillisecondsOrReply. fr previously parsed the integer
    /// value during option parsing, so a missing key with a "bad"
    /// expiry (EX 0, EX -1, integer overflow) surfaced
    /// "ERR invalid expire time" instead of nil, and a wrong-type key
    /// surfaced the same error instead of WRONGTYPE.
    #[test]
    fn getex_defers_value_validation_until_after_lookup_per_upstream() {
        let mut store = Store::new();

        // Missing key short-circuits to nil regardless of how invalid
        // the expiry value would be.
        for tail in [
            &[b"EX".to_vec(), b"0".to_vec()][..],
            &[b"EX".to_vec(), b"-1".to_vec()],
            &[b"EX".to_vec(), b"9999999999999999999".to_vec()],
            &[b"EXAT".to_vec(), b"0".to_vec()],
            &[b"PX".to_vec(), b"0".to_vec()],
            &[b"PXAT".to_vec(), b"0".to_vec()],
        ] {
            let mut argv: Vec<Vec<u8>> = vec![b"GETEX".to_vec(), b"missing".to_vec()];
            argv.extend(tail.iter().cloned());
            let r = dispatch_argv(&argv, &mut store, 1_000)
                .unwrap_or_else(|_| panic!("GETEX missing {tail:?} must return nil"));
            assert_eq!(
                r,
                RespFrame::BulkString(None),
                "GETEX missing {tail:?} expected nil before any expiry validation"
            );
        }

        // Syntax errors on keywords still surface before lookup, just
        // like upstream's parseExtendedStringArgumentsOrReply.
        let err = dispatch_argv(
            &[b"GETEX".to_vec(), b"missing".to_vec(), b"FOOBAR".to_vec()],
            &mut store,
            1_000,
        )
        .expect_err("GETEX missing FOOBAR must surface syntax error");
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR syntax error".to_string())
        );

        // Wrong-type key surfaces WRONGTYPE before any expiry validation.
        dispatch_argv(
            &[b"LPUSH".to_vec(), b"lst".to_vec(), b"x".to_vec()],
            &mut store,
            1_000,
        )
        .expect("LPUSH lst x");
        let err = dispatch_argv(
            &[
                b"GETEX".to_vec(),
                b"lst".to_vec(),
                b"EX".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            1_000,
        )
        .expect_err("GETEX list EX 0 must surface WRONGTYPE");
        assert_eq!(
            err.to_resp(),
            RespFrame::Error(
                "WRONGTYPE Operation against a key holding the wrong kind of value".to_string()
            )
        );

        // Existing string with EX 0 still rejected with the upstream
        // wording (validation runs after lookup but still rejects).
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            1_000,
        )
        .expect("SET k v");
        let err = dispatch_argv(
            &[
                b"GETEX".to_vec(),
                b"k".to_vec(),
                b"EX".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            1_000,
        )
        .expect_err("GETEX existing-string EX 0 must reject after lookup");
        assert_eq!(
            err.to_resp(),
            RespFrame::Error("ERR invalid expire time in 'getex' command".to_string())
        );
    }

