    #[test]
    fn bitfield_offsets_above_4gib_rejected_with_invalid_offset_wording() {
        // Pin upstream bitops.c::getBitOffsetFromArgument cap for
        // BITFIELD GET/SET/INCRBY: bit-offsets must satisfy
        // (offset >> 3) < proto_max_bulk_len (default 512 MiB),
        // so bits < 2^32. Above the cap, upstream emits "ERR bit
        // offset is not an integer or out of range". The #N hash
        // form computes N*bits first then applies the same cap.
        // (frankenredis-2b51) Mirrors qd8i for GETBIT/SETBIT.
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v".to_vec(), None, 0);

        let assert_offset_err = |argv_in: &[&[u8]]| {
            let argv: Vec<Vec<u8>> = argv_in.iter().map(|s| s.to_vec()).collect();
            let result = dispatch_argv(&argv, &mut Store::new(), 0);
            let got = match result {
                Ok(RespFrame::Error(s)) => s,
                Err(e) => match e.to_resp() {
                    RespFrame::Error(s) => s,
                    other => panic!("expected error frame, got {other:?}"),
                },
                other => panic!("expected error for {argv_in:?}, got {other:?}"),
            };
            assert_eq!(
                got,
                "ERR bit offset is not an integer or out of range".to_string(),
                "argv: {argv_in:?}"
            );
        };

        // GET above-cap absolute.
        assert_offset_err(&[b"BITFIELD", b"k", b"GET", b"u8", b"4294967296"]);
        // GET huge absolute.
        assert_offset_err(&[b"BITFIELD", b"k", b"GET", b"u8", b"99999999999"]);
        // SET above-cap absolute.
        assert_offset_err(&[b"BITFIELD", b"k", b"SET", b"u8", b"4294967296", b"1"]);
        // INCRBY above-cap absolute.
        assert_offset_err(&[b"BITFIELD", b"k", b"INCRBY", b"u8", b"4294967296", b"1"]);
        // #N hash form: u8 #536870912 = 8*536870912 = 4 GiB exactly,
        // which is the exclusive cap → reject.
        assert_offset_err(&[b"BITFIELD", b"k", b"GET", b"u8", b"#536870912"]);
        let _ = store;
    }

    #[test]
    fn getbit_setbit_reject_offsets_above_4gib() {
        // Pin upstream bitops.c::getBitOffsetFromArgument bound:
        // bit offsets must satisfy (offset >> 3) < proto_max_bulk_len
        // (default 512 MiB), i.e. bits must be < 2^32 (4 GiB).
        // Both GETBIT and SETBIT reject above-bound and negative
        // offsets with the same wording. (frankenredis-qd8i)
        let mut store = Store::new();

        for cmd in [b"GETBIT".as_slice(), b"SETBIT".as_slice()] {
            // Above 4 GiB bits.
            let mut argv: Vec<Vec<u8>> = vec![cmd.to_vec(), b"k".to_vec(), b"4294967296".to_vec()];
            if cmd == b"SETBIT" {
                argv.push(b"1".to_vec());
            }
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("offset too high");
            assert_eq!(
                err,
                CommandError::Custom(
                    "ERR bit offset is not an integer or out of range".to_string()
                ),
                "{cmd:?}"
            );

            // Far above (99 billion).
            let mut argv: Vec<Vec<u8>> = vec![cmd.to_vec(), b"k".to_vec(), b"99999999999".to_vec()];
            if cmd == b"SETBIT" {
                argv.push(b"1".to_vec());
            }
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("offset huge");
            assert_eq!(
                err,
                CommandError::Custom(
                    "ERR bit offset is not an integer or out of range".to_string()
                ),
                "{cmd:?}"
            );

            // Negative.
            let mut argv: Vec<Vec<u8>> = vec![cmd.to_vec(), b"k".to_vec(), b"-1".to_vec()];
            if cmd == b"SETBIT" {
                argv.push(b"1".to_vec());
            }
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("negative");
            assert_eq!(
                err,
                CommandError::Custom(
                    "ERR bit offset is not an integer or out of range".to_string()
                ),
                "{cmd:?}"
            );
        }

        // Sanity: just below the bound parses successfully.
        let just_below = dispatch_argv(
            &[
                b"GETBIT".to_vec(),
                b"nokey".to_vec(),
                b"4294967295".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("just-below-bound");
        assert_eq!(just_below, RespFrame::Integer(0));
    }

    #[test]
    fn bitpos_missing_key_short_circuits_before_arg_parse() {
        // Pin upstream t_string.c::bitposCommand ordering: missing
        // key returns (bit ? -1 : 0) regardless of any trailing
        // argument validity, since lookupKey runs first.
        // (frankenredis-4urm)
        let mut store = Store::new();

        // bit=1, missing key → -1 even with bogus trailing junk
        let bit1 = dispatch_argv(
            &[
                b"BITPOS".to_vec(),
                b"nokey".to_vec(),
                b"1".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
                b"NOSUCH".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("bitpos missing");
        assert_eq!(bit1, RespFrame::Integer(-1));

        // bit=0, missing key → 0 even with bogus 7-arg form
        let bit0 = dispatch_argv(
            &[
                b"BITPOS".to_vec(),
                b"nokey".to_vec(),
                b"0".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
                b"BYTE".to_vec(),
                b"BIT".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("bitpos missing bit0");
        assert_eq!(bit0, RespFrame::Integer(0));

        // Sanity: bit-arg validation still runs first (must be 0 or 1)
        // so bit=2 errors even before the key-lookup short-circuit.
        let bad_bit = dispatch_argv(
            &[b"BITPOS".to_vec(), b"nokey".to_vec(), b"2".to_vec()],
            &mut store,
            0,
        )
        .expect_err("bitpos bad bit");
        assert_eq!(
            bad_bit,
            CommandError::Custom("ERR The bit argument must be 1 or 0.".to_string())
        );
    }

