    #[test]
    fn debug_digest_returns_hex_string() {
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"key1".to_vec(), b"value1".to_vec()],
            &mut store,
            0,
        )
        .expect("set");
        dispatch_argv(
            &[b"SET".to_vec(), b"key2".to_vec(), b"value2".to_vec()],
            &mut store,
            0,
        )
        .expect("set");

        let digest = dispatch_argv(&[b"DEBUG".to_vec(), b"DIGEST".to_vec()], &mut store, 0)
            .expect("debug digest");
        // Upstream emits `addReplyStatus` — a RESP simple string.
        let RespFrame::SimpleString(digest_str) = digest else {
            panic!("expected simple string");
        };
        // (frankenredis-dbgdiglen) Upstream debug.c::computeDatasetDigest
        // emits a 20-byte SHA1 XOR digest hex-encoded to 40 chars. fr
        // mirrors the frame width via Sha256 truncated to 20 bytes.
        assert_eq!(digest_str.len(), 40, "digest should be 40 hex chars");
        assert!(
            digest_str.chars().all(|c| c.is_ascii_hexdigit()),
            "digest should be hex"
        );
    }

    #[test]
    fn debug_digest_is_deterministic() {
        let mut store1 = Store::new();
        let mut store2 = Store::new();

        // Same data, same order
        for store in [&mut store1, &mut store2] {
            dispatch_argv(&[b"SET".to_vec(), b"a".to_vec(), b"1".to_vec()], store, 0).expect("set");
            dispatch_argv(&[b"SET".to_vec(), b"b".to_vec(), b"2".to_vec()], store, 0).expect("set");
        }

        let d1 = dispatch_argv(&[b"DEBUG".to_vec(), b"DIGEST".to_vec()], &mut store1, 0)
            .expect("digest1");
        let d2 = dispatch_argv(&[b"DEBUG".to_vec(), b"DIGEST".to_vec()], &mut store2, 0)
            .expect("digest2");
        assert_eq!(d1, d2, "same data should produce same digest");
    }

    #[test]
    fn debug_digest_value_specific_keys() {
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"foo".to_vec(), b"bar".to_vec()],
            &mut store,
            0,
        )
        .expect("set");
        dispatch_argv(
            &[b"SET".to_vec(), b"baz".to_vec(), b"qux".to_vec()],
            &mut store,
            0,
        )
        .expect("set");

        // (frankenredis-dbgdigval) DEBUG DIGEST-VALUE returns an
        // Array of per-key digests (one entry per requested key),
        // matching upstream debug.c. Each entry is a SimpleString of
        // hex digits (upstream `addReplyStatus` per key).
        let digest = dispatch_argv(
            &[b"DEBUG".to_vec(), b"DIGEST-VALUE".to_vec(), b"foo".to_vec()],
            &mut store,
            0,
        )
        .expect("debug digest-value");
        let RespFrame::Array(Some(entries)) = digest else {
            panic!("expected array of digests"); // ubs:ignore — AI triage
        };
        assert_eq!(entries.len(), 1);
        let RespFrame::SimpleString(digest_str) = &entries[0] else {
            panic!("expected simple string per-key digest"); // ubs:ignore — AI triage
        };
        assert_eq!(digest_str.len(), 40);

        // DIGEST-VALUE with multiple keys returns one entry per key.
        let multi = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"DIGEST-VALUE".to_vec(),
                b"foo".to_vec(),
                b"baz".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("debug digest-value multi");
        let RespFrame::Array(Some(multi_entries)) = multi else {
            panic!("expected array of digests"); // ubs:ignore — AI triage
        };
        assert_eq!(multi_entries.len(), 2);
        for entry in &multi_entries {
            assert!(matches!(entry, RespFrame::SimpleString(s) if s.len() == 40));
        }

        // Digest of nonexistent key should still emit a SimpleString
        // entry so the array shape stays predictable.
        let digest_nokey = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"DIGEST-VALUE".to_vec(),
                b"nonexistent".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("debug digest-value nonexistent");
        let RespFrame::Array(Some(missing)) = digest_nokey else {
            panic!("expected array"); // ubs:ignore — AI triage
        };
        assert_eq!(missing.len(), 1);
        assert!(matches!(&missing[0], RespFrame::SimpleString(_)));

        // (frankenredis-dbgdigvempty) DEBUG DIGEST-VALUE with no keys
        // is gated by `c->argc >= 2` upstream and emits
        // `addReplyArrayLen(c, c->argc - 2)` (i.e. an empty array)
        // — NOT the subcommand-syntax envelope. fr previously
        // rejected argc==2 with the envelope wording.
        let empty = dispatch_argv(
            &[b"DEBUG".to_vec(), b"DIGEST-VALUE".to_vec()],
            &mut store,
            0,
        )
        .expect("debug digest-value with no keys must succeed");
        assert_eq!(empty, RespFrame::Array(Some(Vec::new())));
    }

    #[test]
    fn debug_digest_string_values_match_vendored_redis_724() {
        // (frankenredis-729zz) Pin Redis 7.2.4 debug.c digest
        // algorithm for simple string objects: key mixing for DEBUG
        // DIGEST, object-only digest for DIGEST-VALUE, SHA1
        // xor/mixDigest flow, and object type aux header.
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"k1".to_vec(), b"v1".to_vec()],
            &mut store,
            0,
        )
        .expect("set k1");

        let one_key_digest = dispatch_argv(&[b"DEBUG".to_vec(), b"DIGEST".to_vec()], &mut store, 0)
            .expect("debug digest");
        assert_eq!(
            one_key_digest,
            RespFrame::SimpleString("f501b7e652f1e4874b8a6890245c152b5b89fe96".to_string())
        );

        let k1_value = dispatch_argv(
            &[b"DEBUG".to_vec(), b"DIGEST-VALUE".to_vec(), b"k1".to_vec()],
            &mut store,
            0,
        )
        .expect("debug digest-value k1");
        assert_eq!(
            k1_value,
            RespFrame::Array(Some(vec![RespFrame::SimpleString(
                "1b39f6ecf00cfce8fa56c4c62c40126162d878fe".to_string()
            )]))
        );

        dispatch_argv(
            &[b"SET".to_vec(), b"k2".to_vec(), b"v2".to_vec()],
            &mut store,
            0,
        )
        .expect("set k2");
        let two_key_digest = dispatch_argv(&[b"DEBUG".to_vec(), b"DIGEST".to_vec()], &mut store, 0)
            .expect("debug digest after k2");
        assert_eq!(
            two_key_digest,
            RespFrame::SimpleString("91720c7142b6dfec5df4d6409a6f52e2da2a829f".to_string())
        );
        let k2_value = dispatch_argv(
            &[b"DEBUG".to_vec(), b"DIGEST-VALUE".to_vec(), b"k2".to_vec()],
            &mut store,
            0,
        )
        .expect("debug digest-value k2");
        assert_eq!(
            k2_value,
            RespFrame::Array(Some(vec![RespFrame::SimpleString(
                "becefaf9bf124b8996f547b6b4876ef6a6b60c37".to_string()
            )]))
        );
    }

    #[test]
    fn debug_populate_rejects_non_positive_count_and_size_with_upstream_wording() {
        // (frankenredis-dbgpop) Upstream debug.c::debugCommand:707-723
        // parses both <count> and <size> via
        // getPositiveLongFromObjectOrReply with NULL msg, so the
        // canonical "value is out of range, must be positive" reply
        // covers BOTH unparseable input and non-positive values. fr's
        // POPULATE branch was using parse_i64_arg, so negative counts
        // silently iterated 0 times (returning OK) and bad-parse
        // cases surfaced "value is not an integer or out of range".
        let mut store = Store::new();
        let want = "ERR value is out of range, must be positive";

        // <count> must be parseable AND non-negative.
        for bad_count in [b"-1".as_slice(), b"-100", b"abc"] {
            let err = dispatch_argv(
                &[b"DEBUG".to_vec(), b"POPULATE".to_vec(), bad_count.to_vec()],
                &mut store,
                0,
            )
            .expect_err("DEBUG POPULATE bad count must error");
            assert_eq!(
                err,
                CommandError::Custom(want.to_string()),
                "count={:?}",
                String::from_utf8_lossy(bad_count)
            );
        }

        // Same wording when the bad value lands in the <size> slot
        // (fourth argument).
        for bad_size in [b"-1".as_slice(), b"abc"] {
            let err = dispatch_argv(
                &[
                    b"DEBUG".to_vec(),
                    b"POPULATE".to_vec(),
                    b"5".to_vec(),
                    b"pre:".to_vec(),
                    bad_size.to_vec(),
                ],
                &mut store,
                1,
            )
            .expect_err("DEBUG POPULATE bad size must error");
            assert_eq!(
                err,
                CommandError::Custom(want.to_string()),
                "size={:?}",
                String::from_utf8_lossy(bad_size)
            );
        }

        // Sanity: count = 0 still succeeds (no iteration).
        dispatch_argv(
            &[b"DEBUG".to_vec(), b"POPULATE".to_vec(), b"0".to_vec()],
            &mut store,
            2,
        )
        .expect("DEBUG POPULATE 0 must succeed");
    }

