    #[test]
    fn lcs_oversize_emits_upstream_proto_max_bulk_len_wording() {
        // (frankenredis-ruc5t) Upstream t_string.c:812 emits
        // 'Insufficient memory, transient memory for LCS exceeds
        // proto-max-bulk-len' when the DP table size exceeds the
        // proto_max_bulk_len cap. fr was inventing a 'too long without
        // LEN flag' message that doesn't appear in upstream sources.
        // Reproduce by passing two strings whose len-product exceeds
        // LCS_MAX_DP_SIZE (16M entries) — the early bail-out fires
        // BEFORE any DP allocation, so 4097-byte strings are enough.
        let mut store = Store::new();
        let big_a = vec![b'a'; 4097];
        let big_b = vec![b'b'; 4097];
        dispatch_argv(&[b"SET".to_vec(), b"k1".to_vec(), big_a], &mut store, 0).expect("set k1");
        dispatch_argv(&[b"SET".to_vec(), b"k2".to_vec(), big_b], &mut store, 0).expect("set k2");

        // Plain LCS path → compute_lcs.
        let err = dispatch_argv(
            &[b"LCS".to_vec(), b"k1".to_vec(), b"k2".to_vec()],
            &mut store,
            0,
        )
        .expect_err("oversize plain LCS should error");
        assert_eq!(
            err,
            CommandError::Custom(
                "ERR Insufficient memory, transient memory for LCS exceeds proto-max-bulk-len"
                    .to_string()
            )
        );

        // IDX path → compute_lcs_matches.
        let err = dispatch_argv(
            &[
                b"LCS".to_vec(),
                b"k1".to_vec(),
                b"k2".to_vec(),
                b"IDX".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("oversize IDX LCS should error");
        assert_eq!(
            err,
            CommandError::Custom(
                "ERR Insufficient memory, transient memory for LCS exceeds proto-max-bulk-len"
                    .to_string()
            )
        );
    }

    #[test]
    fn lcs_idx_under_resp3_returns_2_entry_map() {
        // (frankenredis-cz712) Upstream t_string.c:863 wraps the LCS
        // IDX reply in addReplyMapLen(c, 2), so the RESP3 wire shape
        // is a 2-entry Map ('matches' → Array of match-ranges,
        // 'len' → Integer). Pin both shapes (RESP2 + RESP3).
        let mut store = Store::new();
        store.set(b"k1".to_vec(), b"abcdef".to_vec(), None, 0);
        store.set(b"k2".to_vec(), b"acef".to_vec(), None, 0);
        store.dispatch_client_ctx.resp_protocol_version = 3;
        let out = dispatch_argv(
            &[
                b"LCS".to_vec(),
                b"k1".to_vec(),
                b"k2".to_vec(),
                b"IDX".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("lcs idx resp3");
        let RespFrame::Map(Some(pairs)) = out else {
            panic!("RESP3 LCS IDX must be Map, got {out:?}"); // ubs:ignore — AI triage
        };
        assert_eq!(pairs.len(), 2);
        assert_eq!(pairs[0].0, RespFrame::BulkString(Some(b"matches".to_vec())));
        assert!(matches!(pairs[0].1, RespFrame::Array(Some(_))));
        assert_eq!(pairs[1].0, RespFrame::BulkString(Some(b"len".to_vec())));
        assert!(matches!(pairs[1].1, RespFrame::Integer(_)));
    }

