    #[test]
    fn lastsave_returns_timestamp() {
        // (frankenredis-wqdrw) Store::new() seeds last_save_time_sec to the
        // current Unix time at boot (frankenredis-30hub mirrors upstream
        // server.lastsave = time(NULL)), so initial LASTSAVE returns the
        // boot time, not 0.
        let mut store = Store::new();
        let boot_time = store.last_save_time_sec as i64;
        let initial = dispatch_argv(&[b"LASTSAVE".to_vec()], &mut store, 1_700_000_000_000)
            .expect("initial lastsave");
        assert_eq!(initial, RespFrame::Integer(boot_time));

        dispatch_argv(&[b"SAVE".to_vec()], &mut store, 1_700_000_005_000).expect("save");
        let after_save = dispatch_argv(&[b"LASTSAVE".to_vec()], &mut store, 1_700_000_099_000)
            .expect("lastsave after save");
        assert_eq!(after_save, RespFrame::Integer(1_700_000_005));

        dispatch_argv(&[b"BGSAVE".to_vec()], &mut store, 1_700_000_007_000).expect("bgsave");
        let after_bgsave = dispatch_argv(&[b"LASTSAVE".to_vec()], &mut store, 1_700_000_199_000)
            .expect("lastsave after bgsave");
        assert_eq!(after_bgsave, RespFrame::Integer(1_700_000_007));
    }

    #[test]
    fn info_persistence_reports_tracked_last_save_time() {
        let mut store = Store::new();
        dispatch_argv(&[b"SAVE".to_vec()], &mut store, 1_700_000_005_000).expect("save");
        dispatch_argv(&[b"BGSAVE".to_vec()], &mut store, 1_700_000_007_000).expect("bgsave");
        store.record_aof_bgrewrite_status(false);
        store.record_aof_write_status(false);
        store.stat_rdb_last_load_keys_expired = 2;
        store.stat_rdb_last_load_keys_loaded = 5;

        let out = dispatch_argv(&[b"INFO".to_vec(), b"persistence".to_vec()], &mut store, 0)
            .expect("info persistence");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8 info");
        assert!(info.contains("rdb_last_save_time:1700000007\r\n"), "{info}");
        assert!(info.contains("rdb_last_bgsave_status:ok\r\n"), "{info}");
        assert!(
            info.contains("rdb_last_bgsave_time_sec:1700000007\r\n"),
            "{info}"
        );
        assert!(info.contains("rdb_saves:2\r\n"), "{info}");
        assert!(info.contains("rdb_last_load_keys_expired:2\r\n"), "{info}");
        assert!(info.contains("rdb_last_load_keys_loaded:5\r\n"), "{info}");
        assert!(info.contains("aof_last_bgrewrite_status:err\r\n"), "{info}");
        assert!(info.contains("aof_last_write_status:err\r\n"), "{info}");
        assert!(info.contains("aof_last_rewrite_time_sec:-1\r\n"), "{info}");
    }

