    #[test]
    fn zintercard_wrongtype_precedes_limit_and_syntax_validation() {
        // (frankenredis-zintercardwt) Upstream zinterCardCommand type-checks
        // every key (WRONGTYPE for non-zset/non-set) BEFORE parsing the optional
        // LIMIT clause — so a wrong-type key beats a negative/bad LIMIT or a
        // trailing syntax error. A SET is a valid zset-like operand. fr
        // previously validated LIMIT first.
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"str".to_vec(), b"x".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[b"RPUSH".to_vec(), b"lst".to_vec(), b"a".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[b"SADD".to_vec(), b"s".to_vec(), b"a".to_vec()],
            &mut store,
            0,
        )
        .unwrap();

        let argv = |parts: &[&str]| -> Vec<Vec<u8>> {
            parts.iter().map(|p| p.as_bytes().to_vec()).collect()
        };
        // wrong-type key beats LIMIT / trailing-syntax errors
        for parts in [
            vec!["ZINTERCARD", "1", "str", "LIMIT", "-1"],
            vec!["ZINTERCARD", "1", "str", "BADTRAIL"],
            vec!["ZINTERCARD", "2", "str", "z", "LIMIT", "abc"],
            vec!["ZINTERCARD", "1", "lst", "LIMIT", "-1"],
        ] {
            assert_eq!(
                dispatch_argv(&argv(&parts), &mut store, 0).expect_err("wrongtype"),
                CommandError::Store(fr_store::StoreError::WrongType),
                "{parts:?}"
            );
        }
        // valid types (zset / set / missing) still validate LIMIT
        assert_eq!(
            dispatch_argv(
                &argv(&["ZINTERCARD", "1", "z", "LIMIT", "-1"]),
                &mut store,
                0
            )
            .expect_err("limit"),
            CommandError::Custom("ERR LIMIT can't be negative".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &argv(&["ZINTERCARD", "1", "s", "LIMIT", "-1"]),
                &mut store,
                0
            )
            .expect_err("limit on set operand"),
            CommandError::Custom("ERR LIMIT can't be negative".to_string())
        );
        // a SET key is a valid operand (counts members)
        assert_eq!(
            dispatch_argv(&argv(&["ZINTERCARD", "1", "s"]), &mut store, 0).unwrap(),
            RespFrame::Integer(1)
        );
    }

    #[test]
    fn zrange_shape_combination_wordings_match_upstream() {
        // Pin three ZRANGE shape-combination wordings caught by
        // differential probe vs vendored 7.2.4 t_zset.c::
        // zrangeGenericCommand (frankenredis-06pl):
        //   - LIMIT without BYSCORE/BYLEX -> verbose syntax-error envelope
        //   - WITHSCORES + BYLEX           -> conflict envelope
        //   - BYLEX with non-[/(/-/+ bound -> "min or max not valid string range item"
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        let limit_no_shape = dispatch_argv(
            &[
                b"ZRANGE".to_vec(),
                b"z".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
                b"LIMIT".to_vec(),
                b"0".to_vec(),
                b"5".to_vec(),
            ],
            &mut store,
            0,
        );
        let got = match limit_no_shape {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR syntax error, LIMIT is only supported in combination with either BYSCORE or BYLEX"
                .to_string()
        );

        let withscores_bylex = dispatch_argv(
            &[
                b"ZRANGE".to_vec(),
                b"z".to_vec(),
                b"-".to_vec(),
                b"+".to_vec(),
                b"WITHSCORES".to_vec(),
                b"BYLEX".to_vec(),
            ],
            &mut store,
            0,
        );
        let got = match withscores_bylex {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR syntax error, WITHSCORES not supported in combination with BYLEX".to_string()
        );

        let bylex_bad_bound = dispatch_argv(
            &[
                b"ZRANGE".to_vec(),
                b"z".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
                b"BYLEX".to_vec(),
            ],
            &mut store,
            0,
        );
        let got = match bylex_bad_bound {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR min or max not valid string range item".to_string()
        );
    }

    #[test]
    fn zrange_limit_count_sentinel_is_only_minus_one() {
        // Pins frankenredis-zrlimneg/xcaw5. Upstream zrangeGenericCommand's
        // shape check is `opt_limit != -1`, so ONLY an exact -1 count is the
        // no-limit sentinel — any other count (incl. other negatives) without
        // BYSCORE/BYLEX triggers the verbose LIMIT shape error, and that error
        // precedes the key type-check and the rank min/max parse.
        let argv = |parts: &[&str]| -> Vec<Vec<u8>> {
            parts.iter().map(|p| p.as_bytes().to_vec()).collect()
        };
        let err_of = |r: Result<RespFrame, CommandError>| -> String {
            match r {
                Ok(RespFrame::Error(s)) => s,
                Err(e) => match e.to_resp() {
                    RespFrame::Error(s) => s,
                    other => panic!("expected error frame, got {other:?}"),
                },
                other => panic!("expected error, got {other:?}"),
            }
        };
        let shape = "ERR syntax error, LIMIT is only supported in combination \
                     with either BYSCORE or BYLEX";

        let mut store = Store::new();
        dispatch_argv(
            &argv(&["ZADD", "z", "1", "a", "2", "b", "3", "c"]),
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(&argv(&["SET", "s", "v"]), &mut store, 0).unwrap();

        // -1 sentinel in rank mode: NOT an error (normal rank result).
        let ok = dispatch_argv(
            &argv(&["ZRANGE", "z", "0", "-1", "LIMIT", "0", "-1"]),
            &mut store,
            0,
        );
        assert!(
            matches!(ok, Ok(RespFrame::Array(Some(_)))),
            "LIMIT count -1 is the no-limit sentinel and must be accepted in rank mode, got {ok:?}"
        );

        // A non-(-1) negative count in rank mode -> LIMIT shape error.
        assert_eq!(
            err_of(dispatch_argv(
                &argv(&["ZRANGE", "z", "0", "-1", "LIMIT", "0", "-100"]),
                &mut store,
                0
            )),
            shape
        );
        // Positive count too.
        assert_eq!(
            err_of(dispatch_argv(
                &argv(&["ZRANGE", "z", "0", "-1", "LIMIT", "0", "5"]),
                &mut store,
                0
            )),
            shape
        );
        // The LIMIT shape error precedes the key type-check (wrong-type key).
        assert_eq!(
            err_of(dispatch_argv(
                &argv(&["ZRANGE", "s", "0", "-1", "LIMIT", "0", "-100"]),
                &mut store,
                0
            )),
            shape
        );
        // ZRANGESTORE shares the rule.
        assert_eq!(
            err_of(dispatch_argv(
                &argv(&["ZRANGESTORE", "d", "z", "0", "-1", "LIMIT", "0", "-100"]),
                &mut store,
                0
            )),
            shape
        );
        assert_eq!(
            err_of(dispatch_argv(
                &argv(&["ZRANGESTORE", "d", "s", "0", "-1", "LIMIT", "0", "-100"]),
                &mut store,
                0
            )),
            shape
        );
    }

    #[test]
    fn zrange_zrangestore_limit_negative_offset_defers_to_dependency_check_or_empties() {
        // Pins frankenredis-zrnegoff. Upstream t_zset.c::zrangeGenericCommand
        // parses LIMIT offset as a long via getLongFromObjectOrReply, so a
        // negative offset is accepted; the BYSCORE/BYLEX-pairing check runs
        // AFTER the parse loop. Pre-fix fr called parse_u64_arg on the
        // offset and rejected with 'value is not an integer or out of
        // range' before reaching the dependency check, masking upstream's
        // verbose 'LIMIT is only supported in combination with BYSCORE/BYLEX'
        // wording for the no-shape path and erroring instead of returning
        // empty for the BYSCORE-with-negative-offset path.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
                b"2".to_vec(),
                b"b".to_vec(),
                b"3".to_vec(),
                b"c".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        // ZRANGE z 0 -1 LIMIT -1 0  (no BYSCORE/BYLEX) → upstream's LIMIT-
        // requires-shape error wording, not the integer-parse error.
        let zrange_no_shape = dispatch_argv(
            &[
                b"ZRANGE".to_vec(),
                b"z".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
                b"LIMIT".to_vec(),
                b"-1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        );
        let got = match zrange_no_shape {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR syntax error, LIMIT is only supported in combination with either BYSCORE or BYLEX"
                .to_string()
        );

        // ZRANGE z 0 +inf BYSCORE LIMIT -1 0  → upstream's negative-offset
        // path produces an empty array (offset >= ll never fires for
        // negative offset, but the limit==0 break still does). fr's
        // .skip(usize::MAX) yields the same empty result.
        let zrange_byscore_neg = dispatch_argv(
            &[
                b"ZRANGE".to_vec(),
                b"z".to_vec(),
                b"0".to_vec(),
                b"+inf".to_vec(),
                b"BYSCORE".to_vec(),
                b"LIMIT".to_vec(),
                b"-1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zrange byscore limit -1 0");
        assert_eq!(zrange_byscore_neg, RespFrame::Array(Some(Vec::new())));

        // ZRANGESTORE dst z 0 -1 LIMIT -1 0  → same dependency-check error.
        let zrs_no_shape = dispatch_argv(
            &[
                b"ZRANGESTORE".to_vec(),
                b"dst".to_vec(),
                b"z".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
                b"LIMIT".to_vec(),
                b"-1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        );
        let got = match zrs_no_shape {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR syntax error, LIMIT is only supported in combination with either BYSCORE or BYLEX"
                .to_string()
        );

        // ZRANGESTORE dst z 0 +inf BYSCORE LIMIT -1 0  → empty result, dst
        // is deleted (count = 0).
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"dst".to_vec(),
                b"99".to_vec(),
                b"z".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let zrs_byscore_neg = dispatch_argv(
            &[
                b"ZRANGESTORE".to_vec(),
                b"dst".to_vec(),
                b"z".to_vec(),
                b"0".to_vec(),
                b"+inf".to_vec(),
                b"BYSCORE".to_vec(),
                b"LIMIT".to_vec(),
                b"-1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zrangestore byscore limit -1 0");
        assert_eq!(zrs_byscore_neg, RespFrame::Integer(0));
        // dst should now be deleted (empty pairs branch in zrangestore_cmd).
        let exists_dst = dispatch_argv(&[b"EXISTS".to_vec(), b"dst".to_vec()], &mut store, 0)
            .expect("exists dst");
        assert_eq!(exists_dst, RespFrame::Integer(0));

        // Regression: positive LIMIT 0 5 without BYSCORE/BYLEX still
        // surfaces the same dependency-check error (no behavior change).
        let zrange_pos_no_shape = dispatch_argv(
            &[
                b"ZRANGE".to_vec(),
                b"z".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
                b"LIMIT".to_vec(),
                b"0".to_vec(),
                b"5".to_vec(),
            ],
            &mut store,
            0,
        );
        let got = match zrange_pos_no_shape {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            got,
            "ERR syntax error, LIMIT is only supported in combination with either BYSCORE or BYLEX"
                .to_string()
        );
    }

    #[test]
    fn zset_score_and_limit_error_wordings_match_upstream() {
        // Pins three small upstream wording divergences caught by
        // differential probe vs vendored 7.2.4 (frankenredis-uczv):
        //   - ZRANGEBYSCORE bad bound -> "ERR min or max is not a float"
        //     (t_zset.c::zslParseRange)
        //   - ZUNIONSTORE WEIGHTS bad -> "ERR weight value is not a float"
        //     (t_zset.c::zunionInterAggregateGenericCommand WEIGHTS branch)
        //   - ZINTERCARD LIMIT negative / bad -> "ERR LIMIT can't be negative"
        //     (t_zset.c::zinterCardCommand)
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        let assert_custom = |argv: &[&[u8]], wanted: &str| {
            let argv: Vec<Vec<u8>> = argv.iter().map(|s| s.to_vec()).collect();
            // Either Err(Custom) or Ok(RespFrame::Error) is acceptable;
            // both serialize identically on the wire.
            let result = dispatch_argv(&argv, &mut Store::new(), 0);
            let dispatched_via_err = matches!(&result, Err(CommandError::Custom(s)) if s == wanted);
            let dispatched_via_ok = matches!(&result, Ok(RespFrame::Error(s)) if s == wanted);
            assert!(
                dispatched_via_err || dispatched_via_ok,
                "{wanted:?} not produced — got {result:?}"
            );
        };

        // Seed dest store via dispatch_argv to guarantee parser path.
        let zadd = dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        );
        let _ = zadd;

        assert_custom(
            &[b"ZRANGEBYSCORE", b"z", b"BAD-BOUND", b"5"],
            "ERR min or max is not a float",
        );
        assert_custom(
            &[b"ZUNIONSTORE", b"dst", b"1", b"z", b"WEIGHTS", b"BAD"],
            "ERR weight value is not a float",
        );
        assert_custom(
            &[b"ZINTERCARD", b"1", b"z", b"LIMIT", b"-1"],
            "ERR LIMIT can't be negative",
        );
        assert_custom(
            &[b"ZINTERCARD", b"1", b"z", b"LIMIT", b"BAD"],
            "ERR LIMIT can't be negative",
        );
    }

