    #[test]
    fn debug_subcommand_envelope_preserves_input_case() {
        // (frankenredis-dbgcase) Upstream debug.c routes per-subcommand
        // wrong-arity through addReplySubcommandSyntaxError, which echoes
        // argv[1] verbatim — preserving the input case. fr previously
        // hard-coded each subcommand's name in uppercase across ~20
        // arity-error sites. Differential probe vs vendored 7.2.4
        // confirmed lowercase / mixed-case inputs surface the lowercase /
        // mixed-case token in the wording.
        let mut store = Store::new();
        let cases: &[(&[u8], &str)] = &[
            (b"sleep", "sleep"),
            (b"Sleep", "Sleep"),
            (b"set-active-expire", "set-active-expire"),
            (b"SeT-AcTive-EXPIRE", "SeT-AcTive-EXPIRE"),
            (b"object", "object"),
            (b"populate", "populate"),
            (b"digest extra", "digest"),
            (b"error", "error"),
            (b"log", "log"),
            (b"leak", "leak"),
            (b"pause-cron", "pause-cron"),
            (b"set-disable-deny-scripts", "set-disable-deny-scripts"),
            (b"aof-flush-sleep", "aof-flush-sleep"),
            (
                b"set-skip-checksum-validation",
                "set-skip-checksum-validation",
            ),
            (b"sdslen", "sdslen"),
            (b"structsize extra", "structsize"),
            (b"listpack", "listpack"),
            (b"quicklist", "quicklist"),
            (
                b"config-rewrite-force-all extra",
                "config-rewrite-force-all",
            ),
            (b"drop-cluster-packet-filter", "drop-cluster-packet-filter"),
            (b"client-eviction extra", "client-eviction"),
            (b"htstats", "htstats"),
            (b"htstats-key", "htstats-key"),
            (b"replicate", "replicate"),
            (b"replybuffer", "replybuffer"),
            (b"stringmatch-len extra", "stringmatch-len"),
            (b"stringmatch-test extra", "stringmatch-test"),
            (b"change-repl-id extra", "change-repl-id"),
            // (frankenredis-dbgdigvempty) DEBUG DIGEST-VALUE accepts
            // any argc >= 2 (extra args are treated as keys), so it
            // can no longer trigger the envelope error and is no
            // longer pinned in this case-preservation sweep.
        ];
        for (token, expected_in_msg) in cases {
            let argv = if token.contains(&b' ') {
                let parts: Vec<Vec<u8>> = token.split(|b| *b == b' ').map(|s| s.to_vec()).collect();
                let mut v = vec![b"DEBUG".to_vec()];
                v.extend(parts);
                v
            } else {
                vec![b"DEBUG".to_vec(), token.to_vec()]
            };
            let result = dispatch_argv(&argv, &mut store, 0);
            let frame = match result {
                Ok(frame) => frame,
                Err(CommandError::Custom(msg)) => RespFrame::Error(msg),
                Err(other) => panic!("unexpected error for {token:?}: {other:?}"),
            };
            let expected = format!(
                "ERR unknown subcommand or wrong number of arguments for '{expected_in_msg}'. Try DEBUG HELP."
            );
            assert_eq!(
                frame,
                RespFrame::Error(expected),
                "case-preservation mismatch for input {:?}",
                std::str::from_utf8(token).unwrap_or("<bin>")
            );
        }
    }

    #[test]
    fn subcommand_arity_envelopes_preserve_input_case() {
        // (frankenredis-subcase) Beyond DEBUG, several other dispatched
        // commands route per-subcommand wrong-arity through
        // addReplySubcommandSyntaxError. Upstream preserves the input
        // case of argv[1] in the wording. fr previously hard-coded the
        // sub token in uppercase across CLIENT PAUSE / SLOWLOG GET /
        // PUBSUB CHANNELS / PUBSUB SHARDCHANNELS / FUNCTION RESTORE /
        // FUNCTION FLUSH. Probe vs vendored 7.2.4 confirmed the
        // lowercase / mixed-case echo.
        let mut store = Store::new();
        let cases: &[(&[&[u8]], &str, &str)] = &[
            // Use too-many-args to exercise the SubcommandSyntaxError
            // envelope. The too-few-args path now uses the table-level
            // wording per (frankenredis-clipausearity).
            (
                &[b"CLIENT", b"pause", b"100", b"WRITE", b"extra"],
                "pause",
                "CLIENT",
            ),
            (
                &[b"CLIENT", b"Pause", b"100", b"WRITE", b"extra"],
                "Pause",
                "CLIENT",
            ),
            (&[b"SLOWLOG", b"get", b"1", b"extra"], "get", "SLOWLOG"),
            (&[b"SLOWLOG", b"Get", b"1", b"extra"], "Get", "SLOWLOG"),
            (
                &[b"PUBSUB", b"channels", b"a", b"extra"],
                "channels",
                "PUBSUB",
            ),
            (
                &[b"PUBSUB", b"Channels", b"a", b"extra"],
                "Channels",
                "PUBSUB",
            ),
            (
                &[b"PUBSUB", b"shardchannels", b"a", b"extra"],
                "shardchannels",
                "PUBSUB",
            ),
            (
                &[b"FUNCTION", b"flush", b"SYNC", b"extra"],
                "flush",
                "FUNCTION",
            ),
            (
                &[b"FUNCTION", b"Flush", b"SYNC", b"extra"],
                "Flush",
                "FUNCTION",
            ),
            (
                &[b"FUNCTION", b"restore", b"body", b"REPLACE", b"extra"],
                "restore",
                "FUNCTION",
            ),
        ];
        for (argv_parts, expected_token, parent_cmd) in cases {
            let argv: Vec<Vec<u8>> = argv_parts.iter().map(|p| p.to_vec()).collect();
            let result = dispatch_argv(&argv, &mut store, 0);
            let frame = match result {
                Ok(frame) => frame,
                Err(CommandError::Custom(msg)) => RespFrame::Error(msg),
                Err(other) => panic!("unexpected error for {argv_parts:?}: {other:?}"),
            };
            let expected = format!(
                "ERR unknown subcommand or wrong number of arguments for '{expected_token}'. Try {parent_cmd} HELP."
            );
            assert_eq!(
                frame,
                RespFrame::Error(expected),
                "case-preservation mismatch for argv {argv_parts:?}"
            );
        }
    }

    #[test]
    fn debug_subcommands_use_subcommand_syntax_envelope_for_arity_errors() {
        // (frankenredis-dbgenv) Upstream debug.c::debugCommand routes
        // wrong-arity through addReplySubcommandSyntaxError for the
        // per-subcommand handlers — distinct from the table-level
        // 'wrong number of arguments for debug command' wording. fr
        // previously surfaced the table-level reply for several DEBUG
        // subcommands. Differential probe vs vendored 7.2.4 confirmed
        // the envelope wording per subcommand.
        let mut store = Store::new();
        for (argv, sub) in [
            (
                vec![b"DEBUG".to_vec(), b"DIGEST".to_vec(), b"extra".to_vec()],
                "DIGEST",
            ),
            // (frankenredis-dbgdigvempty) DEBUG DIGEST-VALUE accepts
            // argc == 2 (empty key list -> empty array), so the
            // envelope-error pin lives on the argc-with-bogus-tail
            // form below rather than no-args.
            (vec![b"DEBUG".to_vec(), b"POPULATE".to_vec()], "POPULATE"),
            (
                vec![
                    b"DEBUG".to_vec(),
                    b"CHANGE-REPL-ID".to_vec(),
                    b"extra".to_vec(),
                ],
                "CHANGE-REPL-ID",
            ),
            (
                vec![
                    b"DEBUG".to_vec(),
                    b"STRINGMATCH-TEST".to_vec(),
                    b"extra".to_vec(),
                ],
                "STRINGMATCH-TEST",
            ),
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            let expected = format!(
                "ERR unknown subcommand or wrong number of arguments \
                 for '{sub}'. Try DEBUG HELP."
            );
            assert_eq!(err, CommandError::Custom(expected), "subcommand: {sub}");
        }
    }

