    /// (frankenredis-debugobjlru) Upstream INFO server emits
    ///   lru_clock:(mstime/1000) & 0xFFFFFF
    /// fr previously divided by 10_000 (10-second resolution),
    /// emitting a value 10× smaller than vendored.
    #[test]
    fn info_server_lru_clock_uses_one_second_resolution_per_upstream_evict() {
        let mut store = Store::new();
        let now_ms: u64 = 1_700_000_001_234;
        let out = dispatch_argv(&[b"INFO".to_vec(), b"server".to_vec()], &mut store, now_ms)
            .expect("info server");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected BulkString, got {out:?}");
        };
        let body = std::str::from_utf8(&bytes).unwrap();
        let want = (now_ms / 1_000) & 0xFF_FFFF;
        let needle = format!("lru_clock:{want}\r\n");
        assert!(
            body.contains(&needle),
            "expected `{needle}` (mstime/1000 & 0xFFFFFF) in INFO server, body:\n{body}"
        );
    }

    #[test]
    fn debug_htstats_and_htstats_key_match_upstream_wire_shapes() {
        // Upstream debug.c::debugCommand:
        //   HTSTATS <dbid> [full]    at 889-916 → BulkString or "Out of range database"
        //   HTSTATS-KEY <key> [full] at 917-949 → BulkString | no such key |
        //                                          "not represented using an hash table"
        // (frankenredis-72pfi)
        let mut store = Store::new();

        // HTSTATS with valid dbid → BulkString containing both sections.
        let stats = dispatch_argv(
            &[b"DEBUG".to_vec(), b"HTSTATS".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .expect("htstats db 0");
        let RespFrame::BulkString(Some(bytes)) = stats else {
            panic!("expected BulkString, got {stats:?}");
        };
        let body = std::str::from_utf8(&bytes).unwrap();
        assert!(body.contains("[Dictionary HT]"), "{body}");
        assert!(body.contains("[Expires HT]"), "{body}");

        // HTSTATS with `full` flag accepted-and-ignored.
        let stats_full = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"HTSTATS".to_vec(),
                b"0".to_vec(),
                b"full".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("htstats full");
        assert!(matches!(stats_full, RespFrame::BulkString(Some(_))));

        // HTSTATS with out-of-range dbid → upstream error.
        let oor = dispatch_argv(
            &[b"DEBUG".to_vec(), b"HTSTATS".to_vec(), b"99999".to_vec()],
            &mut store,
            0,
        )
        .expect("htstats out-of-range returns Error frame");
        assert_eq!(
            oor,
            RespFrame::Error("ERR Out of range database".to_string())
        );

        // Wrong-arity → canonical unknown-subcommand error.
        let bad_arity = dispatch_argv(&[b"DEBUG".to_vec(), b"HTSTATS".to_vec()], &mut store, 0)
            .expect_err("htstats needs dbid");
        assert_eq!(
            bad_arity,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'HTSTATS'. Try DEBUG HELP."
                    .to_string()
            )
        );

        // HTSTATS-KEY: missing key → "no such key".
        let miss = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"HTSTATS-KEY".to_vec(),
                b"absent".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("htstats-key missing");
        assert_eq!(miss, RespFrame::Error("ERR no such key".to_string()));

        // HTSTATS-KEY against a string key → not-represented error.
        dispatch_argv(
            &[b"SET".to_vec(), b"strkey".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("seed string");
        let str_reject = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"HTSTATS-KEY".to_vec(),
                b"strkey".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("htstats-key string");
        assert_eq!(
            str_reject,
            RespFrame::Error(
                "ERR The value stored at the specified key is not represented using an hash table"
                    .to_string()
            )
        );

        // HTSTATS-KEY against a sortedset → BulkString with synthetic stats.
        // ZADD with enough elements to force skiplist encoding (default
        // zset-max-listpack-entries is 128).
        for i in 0..200 {
            dispatch_argv(
                &[
                    b"ZADD".to_vec(),
                    b"sortset".to_vec(),
                    format!("{i}").into_bytes(),
                    format!("m{i}").into_bytes(),
                ],
                &mut store,
                0,
            )
            .expect("seed zset");
        }
        let zset_ok = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"HTSTATS-KEY".to_vec(),
                b"sortset".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("htstats-key zset");
        assert!(matches!(zset_ok, RespFrame::BulkString(Some(_))));
    }

    #[test]
    fn debug_config_rewrite_force_all_drop_cluster_packet_filter_client_eviction_match_upstream() {
        // Upstream debug.c::debugCommand:
        //   CONFIG-REWRITE-FORCE-ALL       at 962-967  → +OK / error
        //   DROP-CLUSTER-PACKET-FILTER <n> at 597-602  → +OK after long parse
        //   CLIENT-EVICTION                at 968-988  → ERR or Verbatim bucket
        //                                                stats. fr has no client
        //                                                mem buckets → ERR.
        // (frankenredis-eejfm)
        let mut store = Store::new();

        // (frankenredis-i7oxt) CONFIG-REWRITE-FORCE-ALL → ERR matching
        // upstream's strerror(EFAULT) reply when there's no config file
        // loaded (which is always true for fr's purely-in-memory config).
        let crfa = dispatch_argv(
            &[b"DEBUG".to_vec(), b"CONFIG-REWRITE-FORCE-ALL".to_vec()],
            &mut store,
            0,
        )
        .expect("debug crfa");
        assert_eq!(
            crfa,
            RespFrame::Error("ERR CONFIG-REWRITE-FORCE-ALL failed: Bad address".to_string()),
        );

        // CONFIG-REWRITE-FORCE-ALL with extra arg → unknown-subcommand error
        let crfa_bad = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"CONFIG-REWRITE-FORCE-ALL".to_vec(),
                b"x".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("crfa takes no args");
        assert_eq!(
            crfa_bad,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'CONFIG-REWRITE-FORCE-ALL'. Try DEBUG HELP."
                    .to_string()
            )
        );

        // DROP-CLUSTER-PACKET-FILTER with parseable integer → +OK
        for v in [b"-1".as_slice(), b"0", b"7", b"42"] {
            let out = dispatch_argv(
                &[
                    b"DEBUG".to_vec(),
                    b"DROP-CLUSTER-PACKET-FILTER".to_vec(),
                    v.to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_or_else(|_| panic!("dcpf {} ok", std::str::from_utf8(v).unwrap()));
            assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        }

        // DROP-CLUSTER-PACKET-FILTER with bad integer → InvalidInteger error.
        let dcpf_bad = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"DROP-CLUSTER-PACKET-FILTER".to_vec(),
                b"notanint".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("dcpf needs int");
        assert!(matches!(dcpf_bad, CommandError::InvalidInteger));

        // DROP-CLUSTER-PACKET-FILTER with no arg → unknown-subcommand error.
        let dcpf_arity = dispatch_argv(
            &[b"DEBUG".to_vec(), b"DROP-CLUSTER-PACKET-FILTER".to_vec()],
            &mut store,
            0,
        )
        .expect_err("dcpf needs packet-type");
        assert_eq!(
            dcpf_arity,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'DROP-CLUSTER-PACKET-FILTER'. Try DEBUG HELP."
                    .to_string()
            )
        );

        // CLIENT-EVICTION → ERR maxmemory-clients is disabled.
        let ce = dispatch_argv(
            &[b"DEBUG".to_vec(), b"CLIENT-EVICTION".to_vec()],
            &mut store,
            0,
        )
        .expect("client-eviction returns Error frame");
        assert_eq!(
            ce,
            RespFrame::Error("ERR maxmemory-clients is disabled.".to_string())
        );

        // CLIENT-EVICTION with extra arg → unknown-subcommand error.
        let ce_bad = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"CLIENT-EVICTION".to_vec(),
                b"x".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("client-eviction takes no args");
        assert_eq!(
            ce_bad,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'CLIENT-EVICTION'. Try DEBUG HELP."
                    .to_string()
            )
        );
    }

    #[test]
    fn debug_structsize_listpack_quicklist_match_upstream_wire_shapes() {
        // Upstream debug.c::debugCommand:
        //   STRUCTSIZE  at 878-888 → $BulkString with "bits:N robj:N ..."
        //   LISTPACK    at 680-691 → ERR no such key | ERR Not a listpack...
        //                            | +Listpack structure printed on stdout
        //   QUICKLIST   at 692-706 → ERR no such key | ERR Not a quicklist...
        //                            | +Quicklist structure printed on stdout
        // (frankenredis-wcedk)
        let mut store = Store::new();

        // STRUCTSIZE: returns a BulkString with key:value tokens.
        let structsize = dispatch_argv(&[b"DEBUG".to_vec(), b"STRUCTSIZE".to_vec()], &mut store, 0)
            .expect("debug structsize");
        let RespFrame::BulkString(Some(bytes)) = structsize else {
            panic!("expected BulkString from DEBUG STRUCTSIZE, got {structsize:?}");
        };
        let body = std::str::from_utf8(&bytes).unwrap();
        assert!(
            body.starts_with("bits:"),
            "structsize must start with bits: token, got {body}"
        );
        assert!(body.contains("robj:"));
        assert!(body.contains("dictentry:"));
        assert!(body.contains("sdshdr5:"));
        assert!(body.contains("sdshdr64:"));

        // STRUCTSIZE wrong-arity → unknown-subcommand error.
        let bad_ss = dispatch_argv(
            &[b"DEBUG".to_vec(), b"STRUCTSIZE".to_vec(), b"x".to_vec()],
            &mut store,
            0,
        )
        .expect_err("structsize takes no args");
        assert_eq!(
            bad_ss,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'STRUCTSIZE'. Try DEBUG HELP."
                    .to_string()
            )
        );

        // LISTPACK / QUICKLIST: missing key → "no such key".
        let lp_missing = dispatch_argv(
            &[b"DEBUG".to_vec(), b"LISTPACK".to_vec(), b"absent".to_vec()],
            &mut store,
            0,
        )
        .expect("listpack missing");
        assert_eq!(lp_missing, RespFrame::Error("ERR no such key".to_string()));

        let ql_missing = dispatch_argv(
            &[b"DEBUG".to_vec(), b"QUICKLIST".to_vec(), b"absent".to_vec()],
            &mut store,
            0,
        )
        .expect("quicklist missing");
        assert_eq!(ql_missing, RespFrame::Error("ERR no such key".to_string()));

        // Seed a small list. Default fr encoding for a 1-element small list
        // is "listpack" (legacy_list mode under the size budget).
        dispatch_argv(
            &[b"RPUSH".to_vec(), b"smalllist".to_vec(), b"a".to_vec()],
            &mut store,
            0,
        )
        .expect("seed list");
        let lp_ok = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"LISTPACK".to_vec(),
                b"smalllist".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("listpack ok");
        assert_eq!(
            lp_ok,
            RespFrame::SimpleString("Listpack structure printed on stdout".to_string())
        );

        // The same key is listpack-encoded, so QUICKLIST must reject it.
        let ql_wrong = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"QUICKLIST".to_vec(),
                b"smalllist".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("quicklist wrong-encoding");
        assert_eq!(
            ql_wrong,
            RespFrame::Error("ERR Not a quicklist encoded object.".to_string())
        );

        // Conversely, LISTPACK on a string must reject.
        dispatch_argv(
            &[b"SET".to_vec(), b"strkey".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("seed string");
        let lp_wrong = dispatch_argv(
            &[b"DEBUG".to_vec(), b"LISTPACK".to_vec(), b"strkey".to_vec()],
            &mut store,
            0,
        )
        .expect("listpack wrong-encoding");
        assert_eq!(
            lp_wrong,
            RespFrame::Error("ERR Not a listpack encoded object.".to_string())
        );

        // Wrong-arity for LISTPACK / QUICKLIST.
        let bad_lp = dispatch_argv(&[b"DEBUG".to_vec(), b"LISTPACK".to_vec()], &mut store, 0)
            .expect_err("listpack needs key");
        assert_eq!(
            bad_lp,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'LISTPACK'. Try DEBUG HELP."
                    .to_string()
            )
        );
        let bad_ql = dispatch_argv(&[b"DEBUG".to_vec(), b"QUICKLIST".to_vec()], &mut store, 0)
            .expect_err("quicklist needs key");
        assert_eq!(
            bad_ql,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'QUICKLIST'. Try DEBUG HELP."
                    .to_string()
            )
        );
    }

    #[test]
    fn debug_sdslen_returns_upstream_three_branch_shape() {
        // Upstream debug.c::debugCommand:655-679 has three replies:
        //   ERR no such key                       if missing
        //   ERR Not an sds encoded string.        if int-encoded or non-string
        //   +SimpleString with 6 sds-state fields otherwise
        // (frankenredis-byt3l)
        let mut store = Store::new();

        // Missing key
        let missing = dispatch_argv(
            &[b"DEBUG".to_vec(), b"SDSLEN".to_vec(), b"absent".to_vec()],
            &mut store,
            0,
        )
        .expect("debug sdslen missing");
        assert_eq!(missing, RespFrame::Error("ERR no such key".to_string()));

        // Int-encoded canonical i64 string
        dispatch_argv(
            &[b"SET".to_vec(), b"int_key".to_vec(), b"42".to_vec()],
            &mut store,
            0,
        )
        .expect("seed int");
        let int_reply = dispatch_argv(
            &[b"DEBUG".to_vec(), b"SDSLEN".to_vec(), b"int_key".to_vec()],
            &mut store,
            0,
        )
        .expect("debug sdslen int");
        assert_eq!(
            int_reply,
            RespFrame::Error("ERR Not an sds encoded string.".to_string())
        );

        // Non-string (list)
        dispatch_argv(
            &[b"RPUSH".to_vec(), b"list_key".to_vec(), b"x".to_vec()],
            &mut store,
            0,
        )
        .expect("seed list");
        let list_reply = dispatch_argv(
            &[b"DEBUG".to_vec(), b"SDSLEN".to_vec(), b"list_key".to_vec()],
            &mut store,
            0,
        )
        .expect("debug sdslen list");
        assert_eq!(
            list_reply,
            RespFrame::Error("ERR Not an sds encoded string.".to_string())
        );

        // Sds-encoded string (embstr / raw): formatted SimpleString.
        dispatch_argv(
            &[
                b"SET".to_vec(),
                b"sds_key".to_vec(),
                b"hello world".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("seed sds");
        let sds_reply = dispatch_argv(
            &[b"DEBUG".to_vec(), b"SDSLEN".to_vec(), b"sds_key".to_vec()],
            &mut store,
            0,
        )
        .expect("debug sdslen sds");
        let RespFrame::SimpleString(info) = sds_reply else {
            panic!("expected SimpleString from DEBUG SDSLEN, got {sds_reply:?}");
        };
        // Key 'sds_key' is 7 bytes; value 'hello world' is 11.
        assert!(
            info.contains("key_sds_len:7"),
            "missing or wrong key_sds_len in {info}"
        );
        assert!(
            info.contains("val_sds_len:11"),
            "missing or wrong val_sds_len in {info}"
        );
        assert!(info.contains("key_sds_avail:0"));
        assert!(info.contains("val_sds_avail:0"));

        // Wrong arity → canonical "unknown subcommand or wrong number" error.
        let bad = dispatch_argv(&[b"DEBUG".to_vec(), b"SDSLEN".to_vec()], &mut store, 0)
            .expect_err("missing key arg");
        assert_eq!(
            bad,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'SDSLEN'. Try DEBUG HELP."
                    .to_string()
            )
        );
    }

    #[test]
    fn debug_sdslen_reports_jemalloc_rounded_zmalloc_dp2wu() {
        // (frankenredis-dp2wu) Vendored DEBUG SDSLEN reports
        // jemalloc-rounded zmalloc sizes and `avail = alloc - len` for
        // raw strings (capped at the SDS type's alloc-field width).
        // Sample lengths confirmed against vendored 7.2.4 on :16380.
        let mut store = Store::new();
        for (val_len, expect_val_zmalloc, expect_val_avail, encoding_should_be) in [
            (1usize, 8usize, 0usize, "embstr"),
            (4, 8, 0, "embstr"),
            (5, 16, 0, "embstr"),
            (44, 48, 0, "embstr"),
            (45, 56, 7, "raw"),    // 56 - 3 - 45 - 1
            (47, 56, 5, "raw"),    // 56 - 3 - 47 - 1
            (100, 112, 8, "raw"),  // 112 - 3 - 100 - 1
            (200, 224, 20, "raw"), // 224 - 3 - 200 - 1
            (255, 320, 0, "raw"),  // 320 - 3 - 1 = 316, capped at 255, 255 - 255 = 0
            (256, 320, 58, "raw"), // SDS_TYPE_16 (header 5): 320 - 5 - 1 = 314, 314 - 256 = 58
        ] {
            // Reset key
            dispatch_argv(&[b"DEL".to_vec(), b"k".to_vec()], &mut store, 0).ok();
            let val = vec![b'x'; val_len];
            dispatch_argv(&[b"SET".to_vec(), b"k".to_vec(), val], &mut store, 0).expect("seed");
            // Sanity-check the encoding (which drives the avail branch).
            let enc_reply = dispatch_argv(
                &[b"OBJECT".to_vec(), b"ENCODING".to_vec(), b"k".to_vec()],
                &mut store,
                0,
            )
            .expect("enc");
            let RespFrame::BulkString(Some(enc)) = enc_reply else {
                panic!("encoding shape for len={val_len}: {enc_reply:?}");
            };
            assert_eq!(
                std::str::from_utf8(&enc).unwrap(),
                encoding_should_be,
                "encoding mismatch for len={val_len}"
            );

            let reply = dispatch_argv(
                &[b"DEBUG".to_vec(), b"SDSLEN".to_vec(), b"k".to_vec()],
                &mut store,
                0,
            )
            .expect("debug sdslen");
            let RespFrame::SimpleString(info) = reply else {
                panic!("expected SimpleString for len={val_len}, got {reply:?}");
            };
            // Key is always "k" (1 byte) → SDS_TYPE_5, header 1, total 3, jemalloc 8.
            assert!(
                info.contains("key_sds_len:1, key_sds_avail:0, key_zmalloc: 8"),
                "key fields wrong for val_len={val_len}: {info}"
            );
            assert!(
                info.contains(&format!("val_sds_len:{val_len}")),
                "val_sds_len mismatch for len={val_len}: {info}"
            );
            assert!(
                info.contains(&format!("val_sds_avail:{expect_val_avail}")),
                "val_sds_avail mismatch for len={val_len}: expected {expect_val_avail}, got {info}"
            );
            assert!(
                info.contains(&format!("val_zmalloc: {expect_val_zmalloc}")),
                "val_zmalloc mismatch for len={val_len}: expected {expect_val_zmalloc}, got {info}"
            );
        }
    }

    #[test]
    fn debug_replicate_and_replybuffer_subcommands_match_upstream_wire_shapes() {
        // Upstream debug.c::debugCommand:
        //   REPLICATE <string> [<string> ...]                        at 867-870 → +OK
        //   REPLYBUFFER PEAK-RESET-TIME <NEVER|RESET|<time>>          at 1001-1010 → +OK
        //   REPLYBUFFER RESIZING <0|1>                                at 1011-1012 → +OK
        //   REPLYBUFFER <unknown>                                     → unknown-subcommand error
        // fr-command has no replica-feed hook nor reply-buffer mechanism,
        // so accept-and-OK on syntactically-valid inputs matches the wire
        // contract. (frankenredis-53n6u)
        let mut store = Store::new();

        let one = dispatch_argv(
            &[b"DEBUG".to_vec(), b"REPLICATE".to_vec(), b"PING".to_vec()],
            &mut store,
            0,
        )
        .expect("debug replicate ping");
        assert_eq!(one, RespFrame::SimpleString("OK".to_string()));

        let many = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"REPLICATE".to_vec(),
                b"SET".to_vec(),
                b"k".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("debug replicate variadic");
        assert_eq!(many, RespFrame::SimpleString("OK".to_string()));

        let bad = dispatch_argv(&[b"DEBUG".to_vec(), b"REPLICATE".to_vec()], &mut store, 0)
            .expect_err("replicate needs string");
        assert_eq!(
            bad,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'REPLICATE'. Try DEBUG HELP."
                    .to_string()
            )
        );

        for value in [b"NEVER".as_slice(), b"RESET", b"1500", b"-1", b"never"] {
            let out = dispatch_argv(
                &[
                    b"DEBUG".to_vec(),
                    b"REPLYBUFFER".to_vec(),
                    b"PEAK-RESET-TIME".to_vec(),
                    value.to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_or_else(|_| {
                panic!(
                    "REPLYBUFFER PEAK-RESET-TIME {} should be ok",
                    std::str::from_utf8(value).unwrap()
                )
            });
            assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        }

        let resizing = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"REPLYBUFFER".to_vec(),
                b"RESIZING".to_vec(),
                b"1".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("debug replybuffer resizing");
        assert_eq!(resizing, RespFrame::SimpleString("OK".to_string()));

        let unknown_sub2 = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"REPLYBUFFER".to_vec(),
                b"FOO".to_vec(),
                b"BAR".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("unknown sub2");
        assert_eq!(
            unknown_sub2,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'REPLYBUFFER'. Try DEBUG HELP."
                    .to_string()
            )
        );

        let bad_peak_value = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"REPLYBUFFER".to_vec(),
                b"PEAK-RESET-TIME".to_vec(),
                b"notanumber".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("peak-reset-time bad value");
        assert_eq!(
            bad_peak_value,
            CommandError::Custom("ERR value is not an integer or out of range".to_string())
        );
    }

    #[test]
    fn debug_pause_cron_set_disable_deny_scripts_aof_flush_sleep_skip_checksum_accept_and_ok() {
        // Upstream debug.c::debugCommand:
        //   PAUSE-CRON <0|1>                     at 997-1000  → +OK
        //   SET-DISABLE-DENY-SCRIPTS <0|1>        at 958-961   → +OK
        //   AOF-FLUSH-SLEEP <microsec>            at 862-866   → +OK
        //   SET-SKIP-CHECKSUM-VALIDATION <0|1>    at 857-861   → +OK
        // All four parse with atoi() and store on a server flag. fr-command
        // has no equivalent server-loop hooks, so accept-and-OK matches the
        // wire contract. (frankenredis-r2l7c)
        let mut store = Store::new();

        for (sub, arg) in [
            (b"PAUSE-CRON".as_slice(), b"1".as_slice()),
            (b"SET-DISABLE-DENY-SCRIPTS", b"1"),
            (b"AOF-FLUSH-SLEEP", b"1000"),
            (b"SET-SKIP-CHECKSUM-VALIDATION", b"0"),
        ] {
            let out = dispatch_argv(
                &[b"DEBUG".to_vec(), sub.to_vec(), arg.to_vec()],
                &mut store,
                0,
            )
            .unwrap_or_else(|_| panic!("debug {} ok", std::str::from_utf8(sub).unwrap()));
            assert_eq!(
                out,
                RespFrame::SimpleString("OK".to_string()),
                "DEBUG {} expected +OK",
                std::str::from_utf8(sub).unwrap()
            );

            // Wrong arity surfaces upstream's "unknown subcommand or wrong
            // number" text.
            let bad = dispatch_argv(&[b"DEBUG".to_vec(), sub.to_vec()], &mut store, 0)
                .expect_err("missing arg");
            assert_eq!(
                bad,
                CommandError::Custom(format!(
                    "ERR unknown subcommand or wrong number of arguments \
                     for '{}'. Try DEBUG HELP.",
                    std::str::from_utf8(sub).unwrap()
                ))
            );
        }
    }

    #[test]
    fn debug_error_log_leak_subcommands_match_upstream_wire_shapes() {
        // Upstream debug.c::debugCommand wires:
        //   ERROR <string> at 871-877 → raw RESP error with newlines mapped
        //                               to spaces.
        //   LOG <message>  at 529-531 → +OK (writes to server log at WARNING).
        //   LEAK <string>  at 532-534 → +OK (sdsdup leak, no client signal).
        // (frankenredis-l2zqy)
        let mut store = Store::new();

        let err = dispatch_argv(
            &[b"DEBUG".to_vec(), b"ERROR".to_vec(), b"foo bar".to_vec()],
            &mut store,
            0,
        )
        .expect("debug error");
        assert_eq!(err, RespFrame::Error("foo bar".to_string()));

        let err_with_nl = dispatch_argv(
            &[
                b"DEBUG".to_vec(),
                b"ERROR".to_vec(),
                b"first\nsecond\rthird".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("debug error with newline");
        assert_eq!(
            err_with_nl,
            RespFrame::Error("first second third".to_string()),
            "newlines must map to spaces to keep RESP valid"
        );

        let log = dispatch_argv(
            &[b"DEBUG".to_vec(), b"LOG".to_vec(), b"hello".to_vec()],
            &mut store,
            0,
        )
        .expect("debug log");
        assert_eq!(log, RespFrame::SimpleString("OK".to_string()));

        let leak = dispatch_argv(
            &[b"DEBUG".to_vec(), b"LEAK".to_vec(), b"x".to_vec()],
            &mut store,
            0,
        )
        .expect("debug leak");
        assert_eq!(leak, RespFrame::SimpleString("OK".to_string()));

        // Wrong-arity surfaces upstream's "unknown subcommand or wrong number"
        // text, matching the existing OBJECT / SET-ACTIVE-EXPIRE handling.
        let bad = dispatch_argv(&[b"DEBUG".to_vec(), b"ERROR".to_vec()], &mut store, 0)
            .expect_err("debug error needs arg");
        assert_eq!(
            bad,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments \
                 for 'ERROR'. Try DEBUG HELP."
                    .to_string()
            )
        );
    }

