    #[test]
    fn format_coord_human_handles_special_cases() {
        // Upstream Redis 7.2 emits GEOPOS / GEOSEARCH WITHCOORD coords
        // via addReplyHumanLongDouble (LD_STR_HUMAN — `%.17Lf` followed
        // by trailing-zero trim, with -0 normalized to 0). We mirror
        // the trim/special-case behavior; the per-value 17-digit
        // expansion is exercised end-to-end by
        // geopos_emits_seventeen_significant_digit_human_coords.
        // (br-frankenredis-nz2v)
        assert_eq!(format_coord_human(1.0), "1");
        assert_eq!(format_coord_human(-1.0), "-1");
        assert_eq!(format_coord_human(0.0), "0");
        assert_eq!(format_coord_human(-0.0), "0");
        assert_eq!(format_coord_human(0.5), "0.5");
        assert!(format_coord_human(f64::NAN) == "nan");
        assert_eq!(format_coord_human(f64::INFINITY), "inf");
        assert_eq!(format_coord_human(f64::NEG_INFINITY), "-inf");
    }

    #[test]
    fn format_coord_human_i128_path_matches_std_exact_formatter() {
        // Locks the fast i128 fixed-point coordinate formatter byte-for-byte
        // against the reference `format!("{value:.17}")` + trailing-zero-trim it
        // replaced, across the geo domain (lon/lat/distance) plus adversarial
        // magnitudes. Guards against a rounding/placement regression that would
        // silently diverge GEOPOS / GEOSEARCH WITHCOORD from Redis 7.2.4.
        fn reference(value: f64) -> String {
            if value.is_nan() {
                return "nan".to_string();
            }
            if value.is_infinite() {
                return if value.is_sign_positive() { "inf" } else { "-inf" }.to_string();
            }
            let mut s = format!("{value:.17}");
            if s.contains('.') {
                let t = s.trim_end_matches('0').trim_end_matches('.');
                s.truncate(t.len());
            }
            if s == "-0" {
                s = "0".to_string();
            }
            s
        }
        // Deterministic xorshift sweep over coord/distance/general ranges.
        let mut seed: u64 = 0x9e3779b97f4a7c15;
        for _ in 0..2_000_000u64 {
            seed ^= seed << 13;
            seed ^= seed >> 7;
            seed ^= seed << 17;
            let r = (seed >> 11) as f64 / (1u64 << 53) as f64;
            let v = match seed & 3 {
                0 => -180.0 + r * 360.0,     // longitude
                1 => -85.05 + r * 170.1,     // latitude
                2 => r * 20_000_000.0,       // distance in meters
                _ => (r - 0.5) * 2_000.0,    // general
            };
            assert_eq!(format_coord_human(v), reference(v), "mismatch at v={v}");
        }
        for &v in &[
            13.361_389_338_970_184_33_f64,
            38.115_556_395_496_298_59,
            -122.419_401_705_265_045_17,
            12.999_999_225_139_617_92,
            0.0,
            -0.0,
            1.0,
            -1.0,
            0.5,
            90.0,
            -90.0,
            180.0,
            1e-10,
            6e-18,
        ] {
            assert_eq!(format_coord_human(v), reference(v), "mismatch at explicit v={v}");
        }
    }

    #[test]
    fn geo_coord_frame_uses_resp3_double_else_bulk() {
        // Upstream geo.c emits GEOPOS / GEOSEARCH WITHCOORD coordinates via
        // addReplyHumanLongDouble: a RESP3 Double (`,`) under RESP3 and a bulk
        // string under RESP2, with byte-identical textual payload. Verified
        // byte-exact against vendored Redis 7.2.4.
        let v = 13.361_389_338_970_184_f64;
        let payload = format_coord_human(v);
        assert_eq!(geo_coord_frame(v, true), RespFrame::Double(payload.clone()));
        assert_eq!(
            geo_coord_frame(v, false),
            RespFrame::BulkString(Some(payload.into_bytes()))
        );
    }

    #[test]
    fn geopos_emits_seventeen_significant_digit_human_coords() {
        // Pins the upstream-compatible wire format: GEOPOS coordinates
        // round-trip through the geohash quantization grid, so the
        // emitted decimals always show the 17-digit %.17Lf expansion of
        // the bit pattern rather than Ryu's 16-digit shortest form.
        // (br-frankenredis-nz2v)
        let mut store = Store::new();
        let added = dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"geo".to_vec(),
                b"1".to_vec(),
                b"2".to_vec(),
                b"point".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geoadd");
        assert_eq!(added, RespFrame::Integer(1));
        let pos = dispatch_argv(
            &[b"GEOPOS".to_vec(), b"geo".to_vec(), b"point".to_vec()],
            &mut store,
            0,
        )
        .expect("geopos");
        let RespFrame::Array(Some(items)) = pos else {
            panic!("geopos should return array"); // ubs:ignore — AI triage
        };
        let RespFrame::Array(Some(coords)) = &items[0] else {
            panic!("expected coord array"); // ubs:ignore — AI triage
        };
        let lon = match &coords[0] {
            RespFrame::BulkString(Some(b)) => std::str::from_utf8(b).unwrap().to_string(),
            other => panic!("unexpected longitude frame: {other:?}"),
        };
        let lat = match &coords[1] {
            RespFrame::BulkString(Some(b)) => std::str::from_utf8(b).unwrap().to_string(),
            other => panic!("unexpected latitude frame: {other:?}"),
        };
        // The coordinates the geohash quantizer round-trips for (1, 2)
        // are upstream's verified 17-digit human form, identical byte-
        // for-byte to what redis 7.2.4 reports.
        assert_eq!(lon, "0.99999994039535522");
        assert_eq!(lat, "2.0000001856465488");
    }

    #[test]
    fn geosearch_radius_rejects_overflow_to_infinity_but_accepts_explicit_inf() {
        // (frankenredis-geoovf) Pin upstream util.c::string2d ERANGE
        // rejection for the BYRADIUS / BYBOX argument paths via
        // parse_geo_f64_with_msg. fr previously only rejected NaN,
        // so probes like `GEOSEARCH g FROMMEMBER a BYRADIUS 1e500 m`
        // silently coerced the overflow to f64::INFINITY and matched
        // every member instead of returning the bespoke
        // "ERR need numeric radius" wording. Differential probe vs
        // vendored Redis 7.2.4 confirmed the upstream wording.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"g".to_vec(),
                b"13.5".to_vec(),
                b"37.5".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("GEOADD seed");

        // BYRADIUS with overflow-to-infinity → "need numeric radius".
        for bad in [b"1e500".as_slice(), b"-1e500", b"1e1000", b"+1e500"] {
            let reply = dispatch_argv(
                &[
                    b"GEOSEARCH".to_vec(),
                    b"g".to_vec(),
                    b"FROMMEMBER".to_vec(),
                    b"a".to_vec(),
                    b"BYRADIUS".to_vec(),
                    bad.to_vec(),
                    b"m".to_vec(),
                ],
                &mut store,
                1,
            )
            .expect("GEOSEARCH must surface as Ok(Error)");
            assert_eq!(
                reply,
                RespFrame::Error("ERR need numeric radius".to_string()),
                "bad radius {:?}",
                String::from_utf8_lossy(bad)
            );
        }

        // BYBOX width with overflow-to-infinity → "need numeric width".
        for bad in [b"1e500".as_slice(), b"-1e500"] {
            let reply = dispatch_argv(
                &[
                    b"GEOSEARCH".to_vec(),
                    b"g".to_vec(),
                    b"FROMMEMBER".to_vec(),
                    b"a".to_vec(),
                    b"BYBOX".to_vec(),
                    bad.to_vec(),
                    b"100".to_vec(),
                    b"m".to_vec(),
                ],
                &mut store,
                2,
            )
            .expect("GEOSEARCH must surface as Ok(Error)");
            assert_eq!(
                reply,
                RespFrame::Error("ERR need numeric width".to_string()),
                "bad width {:?}",
                String::from_utf8_lossy(bad)
            );
        }

        // Explicit infinity literals must still be accepted (the
        // BYRADIUS branch then short-circuits inf > 0 to a single
        // member match because every distance is finite).
        let reply = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"g".to_vec(),
                b"FROMMEMBER".to_vec(),
                b"a".to_vec(),
                b"BYRADIUS".to_vec(),
                b"inf".to_vec(),
                b"m".to_vec(),
            ],
            &mut store,
            3,
        )
        .expect("inf radius must be accepted");
        match reply {
            RespFrame::Array(Some(items)) => {
                assert_eq!(items.len(), 1, "expected the seed member to match");
            }
            other => panic!("expected Array reply, got {other:?}"),
        }
    }

    #[test]
    fn georadius_store_storedist_argv_validation_matches_upstream_syntaxerr() {
        // (frankenredis-geostorearg) Upstream geo.c::georadiusGeneric
        // gates the STORE/STOREDIST option branches on
        // `(i+1) < remaining` and `!(flags & RADIUS_NOSTORE)`. A
        // trailing STORE/STOREDIST with no following key, or any
        // STORE/STOREDIST in the _RO variant, falls through to the
        // loop's else and surfaces shared.syntaxerr ("ERR syntax
        // error"). The radius arg in GEORADIUS / GEORADIUSBYMEMBER
        // routes through extractDistanceOrReply with the literal
        // "need numeric radius" wording — not the generic
        // "value is not a valid float" fr inherited from parse_geo_f64.
        let mut store = Store::new();
        add_geo_points(&mut store);

        // STORE / STOREDIST without a destination key surfaces
        // SyntaxError (matching upstream's shared.syntaxerr) for
        // the legacy GEORADIUS and GEORADIUSBYMEMBER commands.
        let trailing_store_cases: &[&[&[u8]]] = &[
            &[
                b"GEORADIUS",
                b"mygeo",
                b"15",
                b"37",
                b"200",
                b"km",
                b"STORE",
            ],
            &[
                b"GEORADIUS",
                b"mygeo",
                b"15",
                b"37",
                b"200",
                b"km",
                b"STOREDIST",
            ],
            &[
                b"GEORADIUSBYMEMBER",
                b"mygeo",
                b"Catania",
                b"200",
                b"km",
                b"STORE",
            ],
            &[
                b"GEORADIUSBYMEMBER",
                b"mygeo",
                b"Catania",
                b"200",
                b"km",
                b"STOREDIST",
            ],
        ];
        for argv_slices in trailing_store_cases {
            let argv: Vec<Vec<u8>> = argv_slices.iter().map(|s| s.to_vec()).collect();
            assert_eq!(
                dispatch_argv(&argv, &mut store, 0).expect_err("trailing STORE"),
                CommandError::SyntaxError,
                "argv = {argv_slices:?}",
            );
        }

        // _RO variants reject STORE/STOREDIST even with a key: upstream
        // sets RADIUS_NOSTORE for GEORADIUS_RO / GEORADIUSBYMEMBER_RO.
        let ro_cases: &[&[&[u8]]] = &[
            &[
                b"GEORADIUS_RO",
                b"mygeo",
                b"15",
                b"37",
                b"200",
                b"km",
                b"STORE",
                b"dst",
            ],
            &[
                b"GEORADIUS_RO",
                b"mygeo",
                b"15",
                b"37",
                b"200",
                b"km",
                b"STOREDIST",
                b"dst",
            ],
            &[
                b"GEORADIUSBYMEMBER_RO",
                b"mygeo",
                b"Catania",
                b"200",
                b"km",
                b"STORE",
                b"dst",
            ],
            &[
                b"GEORADIUSBYMEMBER_RO",
                b"mygeo",
                b"Catania",
                b"200",
                b"km",
                b"STOREDIST",
                b"dst",
            ],
        ];
        for argv_slices in ro_cases {
            let argv: Vec<Vec<u8>> = argv_slices.iter().map(|s| s.to_vec()).collect();
            assert_eq!(
                dispatch_argv(&argv, &mut store, 0).expect_err("_RO with STORE"),
                CommandError::SyntaxError,
                "argv = {argv_slices:?}",
            );
        }

        // Non-numeric radius surfaces "ERR need numeric radius" for
        // legacy GEORADIUS / GEORADIUSBYMEMBER (matching the existing
        // GEOSEARCH wording). This validates the radius-arg-specific
        // wording, distinguishing it from longitude/latitude failures.
        let radius_cases: &[&[&[u8]]] = &[
            &[b"GEORADIUS", b"mygeo", b"15", b"37", b"abc", b"km"],
            &[b"GEORADIUSBYMEMBER", b"mygeo", b"Catania", b"abc", b"km"],
        ];
        for argv_slices in radius_cases {
            let argv: Vec<Vec<u8>> = argv_slices.iter().map(|s| s.to_vec()).collect();
            let out = dispatch_argv(&argv, &mut store, 0).expect("non-numeric radius");
            assert_eq!(
                out,
                RespFrame::Error("ERR need numeric radius".to_string()),
                "argv = {argv_slices:?}",
            );
        }

        // Regression: STORE/STOREDIST with valid dest key still
        // produces a count reply on the legacy commands.
        let stored = dispatch_argv(
            &[
                b"GEORADIUS".to_vec(),
                b"mygeo".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"STORE".to_vec(),
                b"dst".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("STORE-with-key");
        assert!(matches!(stored, RespFrame::Integer(_)));
    }

    /// (frankenredis-kdmf3) Upstream geo.c::georadiusGeneric rejects
    /// STORE/STOREDIST when paired with any WITHCOORD/WITHDIST/WITHHASH
    /// flag. The two reply shapes are mutually exclusive — STORE returns
    /// just the count, WITH* returns metadata arrays — so the combination
    /// is forbidden with a dedicated error wording.
    #[test]
    fn georadius_rejects_store_with_with_flag_combinations_kdmf3() {
        let mut store = Store::new();
        add_geo_points(&mut store);
        let expected = RespFrame::Error(
            "ERR STORE option in GEORADIUS is not compatible with WITHDIST, WITHHASH and WITHCOORD options".to_string(),
        );

        // 3 WITH flags × 2 STORE-flavors × 2 commands = 12 cases.
        let with_flags = [&b"WITHCOORD"[..], &b"WITHDIST"[..], &b"WITHHASH"[..]];
        let store_kinds = [&b"STORE"[..], &b"STOREDIST"[..]];

        for &with_flag in &with_flags {
            for &store_kind in &store_kinds {
                // GEORADIUS
                let argv_gr = vec![
                    b"GEORADIUS".to_vec(),
                    b"mygeo".to_vec(),
                    b"15".to_vec(),
                    b"37".to_vec(),
                    b"200".to_vec(),
                    b"km".to_vec(),
                    with_flag.to_vec(),
                    store_kind.to_vec(),
                    b"dst".to_vec(),
                ];
                let reply = dispatch_argv(&argv_gr, &mut store, 0).expect("GEORADIUS dispatch");
                assert_eq!(
                    reply,
                    expected,
                    "GEORADIUS with {} {}",
                    String::from_utf8_lossy(with_flag),
                    String::from_utf8_lossy(store_kind)
                );

                // GEORADIUSBYMEMBER
                let argv_grbm = vec![
                    b"GEORADIUSBYMEMBER".to_vec(),
                    b"mygeo".to_vec(),
                    b"Catania".to_vec(),
                    b"200".to_vec(),
                    b"km".to_vec(),
                    with_flag.to_vec(),
                    store_kind.to_vec(),
                    b"dst".to_vec(),
                ];
                let reply2 =
                    dispatch_argv(&argv_grbm, &mut store, 0).expect("GEORADIUSBYMEMBER dispatch");
                assert_eq!(
                    reply2,
                    expected,
                    "GEORADIUSBYMEMBER with {} {}",
                    String::from_utf8_lossy(with_flag),
                    String::from_utf8_lossy(store_kind)
                );
            }
        }

        // Regression: STORE alone (no WITH*) still returns a count.
        let stored = dispatch_argv(
            &[
                b"GEORADIUS".to_vec(),
                b"mygeo".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"STORE".to_vec(),
                b"dst".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("STORE-alone");
        assert!(matches!(stored, RespFrame::Integer(_)));

        // Regression: WITH* alone (no STORE) still returns the metadata array.
        let with_alone = dispatch_argv(
            &[
                b"GEORADIUS".to_vec(),
                b"mygeo".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"WITHCOORD".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("WITHCOORD-alone");
        assert!(matches!(with_alone, RespFrame::Array(_)));
    }

    #[test]
    fn georadius_geosearch_reject_out_of_range_lonlat_nugoc() {
        // (frankenredis-nugoc) Upstream src/geo.c::extractLongLatOrReply
        // rejects |lon| > 180 or |lat| > 85.05112878 with the dedicated
        // "ERR invalid longitude,latitude pair %.6f,%.6f" wording.
        // GEORADIUS / GEORADIUS_RO / GEOSEARCH FROMLONLAT /
        // GEOSEARCHSTORE FROMLONLAT all share the validator upstream.
        let mut store = Store::new();
        add_geo_points(&mut store);

        let bad_pairs = [
            (-200.0, 38.0),
            (200.0, 0.0),
            (181.0, 0.0),
            (-181.0, 0.0),
            (0.0, 86.0),
            (0.0, -86.0),
            (0.0, 100.0),
            (0.0, -100.0),
        ];
        for &(lon, lat) in &bad_pairs {
            let expected = RespFrame::Error(format!(
                "ERR invalid longitude,latitude pair {lon:.6},{lat:.6}"
            ));

            // GEORADIUS
            let out = dispatch_argv(
                &[
                    b"GEORADIUS".to_vec(),
                    b"mygeo".to_vec(),
                    lon.to_string().into_bytes(),
                    lat.to_string().into_bytes(),
                    b"100".to_vec(),
                    b"km".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap();
            assert_eq!(out, expected, "GEORADIUS {lon},{lat}");

            // GEORADIUS_RO
            let out = dispatch_argv(
                &[
                    b"GEORADIUS_RO".to_vec(),
                    b"mygeo".to_vec(),
                    lon.to_string().into_bytes(),
                    lat.to_string().into_bytes(),
                    b"100".to_vec(),
                    b"km".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap();
            assert_eq!(out, expected, "GEORADIUS_RO {lon},{lat}");

            // GEOSEARCH FROMLONLAT
            let out = dispatch_argv(
                &[
                    b"GEOSEARCH".to_vec(),
                    b"mygeo".to_vec(),
                    b"FROMLONLAT".to_vec(),
                    lon.to_string().into_bytes(),
                    lat.to_string().into_bytes(),
                    b"BYRADIUS".to_vec(),
                    b"100".to_vec(),
                    b"km".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap();
            assert_eq!(out, expected, "GEOSEARCH FROMLONLAT {lon},{lat}");

            // GEOSEARCHSTORE FROMLONLAT
            let out = dispatch_argv(
                &[
                    b"GEOSEARCHSTORE".to_vec(),
                    b"dest".to_vec(),
                    b"mygeo".to_vec(),
                    b"FROMLONLAT".to_vec(),
                    lon.to_string().into_bytes(),
                    lat.to_string().into_bytes(),
                    b"BYRADIUS".to_vec(),
                    b"100".to_vec(),
                    b"km".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap();
            assert_eq!(out, expected, "GEOSEARCHSTORE FROMLONLAT {lon},{lat}");
        }

        // In-range edge values still accepted (boundary inclusive).
        let good_pairs = [
            (180.0, 0.0),
            (-180.0, 0.0),
            (0.0, 85.05112878),
            (0.0, -85.05112878),
            (0.0, 0.0),
        ];
        for &(lon, lat) in &good_pairs {
            let out = dispatch_argv(
                &[
                    b"GEORADIUS".to_vec(),
                    b"mygeo".to_vec(),
                    lon.to_string().into_bytes(),
                    lat.to_string().into_bytes(),
                    b"100".to_vec(),
                    b"km".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap();
            // Either a successful (possibly empty) Array response is fine,
            // never the validation error.
            assert!(
                matches!(out, RespFrame::Array(_)),
                "GEORADIUS {lon},{lat} should be accepted, got {out:?}"
            );
        }
    }

    #[test]
    fn geosearch_duplicate_same_clause_silently_overrides_dnguy() {
        // (frankenredis-dnguy) Upstream geo.c::geoSearchGeneric guards
        // FROMMEMBER with !fromloc, FROMLONLAT with !frommember,
        // BYRADIUS with !bybox, BYBOX with !byradius. The SAME clause
        // can appear twice — the later value silently overrides.
        // fr previously used single has_center/has_shape booleans
        // which also rejected duplicates-of-same as 'ERR syntax error'.
        let mut store = Store::new();
        add_geo_points(&mut store);
        // Duplicate FROMLONLAT: must succeed (second one wins).
        let out = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"mygeo".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"5000".to_vec(),
                b"km".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"16".to_vec(),
                b"38".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("duplicate FROMLONLAT");
        assert!(matches!(out, RespFrame::Array(_)));
        // Duplicate BYRADIUS: must succeed (second one wins).
        let out = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"mygeo".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"5000".to_vec(),
                b"km".to_vec(),
                b"BYRADIUS".to_vec(),
                b"1000".to_vec(),
                b"mi".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("duplicate BYRADIUS");
        assert!(matches!(out, RespFrame::Array(_)));
        // Mixed FROMMEMBER + FROMLONLAT must still error with the
        // upstream-shared "syntax error" wording (the !fromloc / !frommember
        // guards still fire on the mixed-pair case).
        let err = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"mygeo".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"5000".to_vec(),
                b"km".to_vec(),
                b"FROMMEMBER".to_vec(),
                b"Palermo".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert!(
            matches!(err, CommandError::SyntaxError),
            "expected SyntaxError for FROMLONLAT+FROMMEMBER mix, got {:?}",
            err
        );
        // Mixed BYRADIUS + BYBOX must still error.
        let err = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"mygeo".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"5000".to_vec(),
                b"km".to_vec(),
                b"BYBOX".to_vec(),
                b"100".to_vec(),
                b"100".to_vec(),
                b"km".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert!(
            matches!(err, CommandError::SyntaxError),
            "expected SyntaxError for BYRADIUS+BYBOX mix, got {:?}",
            err
        );
    }

    #[test]
    fn geosearchstore_rejects_with_options_w2whf() {
        // (frankenredis-w2whf) Upstream src/geo.c::georadiusGeneric on
        // the GEOSEARCHSTORE path rejects WITHCOORD/WITHDIST/WITHHASH
        // with the dedicated error wording. Plain GEOSEARCHSTORE and
        // GEOSEARCHSTORE with STOREDIST alone must still succeed.
        let mut store = Store::new();
        add_geo_points(&mut store);
        let expected_err = RespFrame::Error(
            "ERR GEOSEARCHSTORE is not compatible with WITHDIST, WITHHASH and WITHCOORD options"
                .to_string(),
        );
        for flag in [b"WITHCOORD".as_slice(), b"WITHDIST", b"WITHHASH"] {
            let out = dispatch_argv(
                &[
                    b"GEOSEARCHSTORE".to_vec(),
                    b"dest".to_vec(),
                    b"mygeo".to_vec(),
                    b"FROMLONLAT".to_vec(),
                    b"15".to_vec(),
                    b"37".to_vec(),
                    b"BYRADIUS".to_vec(),
                    b"200".to_vec(),
                    b"km".to_vec(),
                    flag.to_vec(),
                ],
                &mut store,
                0,
            )
            .expect("geosearchstore with-flag should not arity-error");
            assert_eq!(
                out,
                expected_err,
                "flag={:?}",
                String::from_utf8_lossy(flag)
            );
        }
        // STOREDIST + WITHCOORD also rejected.
        let out = dispatch_argv(
            &[
                b"GEOSEARCHSTORE".to_vec(),
                b"dest".to_vec(),
                b"mygeo".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"STOREDIST".to_vec(),
                b"WITHCOORD".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, expected_err);

        // Plain GEOSEARCHSTORE still works.
        let out = dispatch_argv(
            &[
                b"GEOSEARCHSTORE".to_vec(),
                b"dest".to_vec(),
                b"mygeo".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(2));

        // STOREDIST alone still works.
        let out = dispatch_argv(
            &[
                b"GEOSEARCHSTORE".to_vec(),
                b"dest2".to_vec(),
                b"mygeo".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"STOREDIST".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(2));
    }

