    #[test]
    fn sort_alpha_en_us_collation_matches_non_store_probe() {
        let mut options = CollatorOptions::default();
        options.alternate_handling = Some(AlternateHandling::Shifted);
        let locale = "en-US".parse::<Locale>().expect("valid en-US locale");
        let collator = Collator::try_new(locale.into(), options).expect("en-US collator");
        let mut values = [
            b"-2".to_vec(),
            b"0".to_vec(),
            b"18".to_vec(),
            b"5".to_vec(),
            b"6".to_vec(),
            b"apple".to_vec(),
            b"Banana".to_vec(),
            b"9x".to_vec(),
            b"3.5".to_vec(),
            b"".to_vec(),
        ];
        values.sort_by(|left, right| sort_alpha_compare(Some(&collator), left, right));
        assert_eq!(
            values.as_slice(),
            [
                b"".to_vec(),
                b"0".to_vec(),
                b"18".to_vec(),
                b"-2".to_vec(),
                b"3.5".to_vec(),
                b"5".to_vec(),
                b"6".to_vec(),
                b"9x".to_vec(),
                b"apple".to_vec(),
                b"Banana".to_vec(),
            ]
        );

        values.sort();
        assert_eq!(
            values.as_slice(),
            [
                b"".to_vec(),
                b"-2".to_vec(),
                b"0".to_vec(),
                b"18".to_vec(),
                b"3.5".to_vec(),
                b"5".to_vec(),
                b"6".to_vec(),
                b"9x".to_vec(),
                b"Banana".to_vec(),
                b"apple".to_vec(),
            ]
        );
    }

