    #[test]
    fn lolwut_returns_version() {
        // Pins the upstream-aligned single-line "Redis ver. <version>\n"
        // body emitted by the unstable-version branch (lolwut.c::
        // lolwutUnstableCommand). (br-frankenredis-m5nf)
        let mut store = Store::new();
        let out = dispatch_argv(&[b"LOLWUT".to_vec()], &mut store, 0).unwrap();
        let expected = format!("Redis ver. {}\n", fr_store::REDIS_COMPAT_VERSION);
        assert_eq!(out, RespFrame::BulkString(Some(expected.into_bytes())));
    }

    #[test]
    fn lolwut_version_argument_returns_same_text() {
        // VERSION 5 / 6 don't yet port the Schotter/braille art —
        // they fall through to the same unstable-branch body so
        // clients don't error out. (br-frankenredis-m5nf)
        let mut store = Store::new();
        let out = dispatch_argv(
            &[b"LOLWUT".to_vec(), b"VERSION".to_vec(), b"5".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        let expected = format!("Redis ver. {}\n", fr_store::REDIS_COMPAT_VERSION);
        assert_eq!(out, RespFrame::BulkString(Some(expected.into_bytes())));
    }

    #[test]
    fn lolwut_accepts_permissive_args_per_upstream_unstable_path() {
        // (frankenredis-lolwutpermit) Upstream lolwut.c::lolwutCommand
        // only enters the VERSION branch when `argc >= 3 && argv[1] is
        // "version"`. Everything else routes through the unstable
        // render fn for vendored 7.2.x, which IGNORES every remaining
        // arg and just emits "Redis ver. <REDIS_VERSION>\n". fr was
        // eagerly validating trailing args as i64 and rejecting
        // `LOLWUT VERSION` (no value) with WrongArity, surfacing
        // errors that vendored 7.2.4 never raises.
        let mut store = Store::new();
        let expected = format!("Redis ver. {}\n", fr_store::REDIS_COMPAT_VERSION);
        let permissive_cases: &[&[&[u8]]] = &[
            // VERSION keyword without a numeric arg → unstable fall-through.
            &[b"LOLWUT", b"VERSION"],
            // Non-VERSION first arg → ignored entirely.
            &[b"LOLWUT", b"BOGUS"],
            // Positional non-version arg → ignored.
            &[b"LOLWUT", b"5"],
            // VERSION + integer + extra trailing token → trailing tokens
            // are upstream-render-fn args; fr's unstable port ignores them.
            &[b"LOLWUT", b"VERSION", b"5", b"BOGUS"],
        ];
        for argv_in in permissive_cases {
            let argv: Vec<Vec<u8>> = argv_in.iter().map(|s| s.to_vec()).collect();
            let out = dispatch_argv(&argv, &mut store, 0)
                .unwrap_or_else(|e| panic!("argv {argv_in:?}: {e:?}"));
            assert_eq!(
                out,
                RespFrame::BulkString(Some(expected.clone().into_bytes())),
                "argv: {argv_in:?}",
            );
        }

        // Regression: VERSION + non-integer still errors via upstream's
        // getLongFromObjectOrReply path.
        let err = dispatch_argv(
            &[b"LOLWUT".to_vec(), b"VERSION".to_vec(), b"abc".to_vec()],
            &mut store,
            0,
        )
        .expect_err("VERSION + non-integer must still error");
        assert!(matches!(err, CommandError::InvalidInteger), "got {err:?}");
    }

    // ── WAITAOF test ────────────────────────────────────────────────

    #[test]
    fn wait_valid_direct_dispatch_returns_zero_ack_count_20i0i() {
        // (frankenredis-20i0i) Vendored waitCommand reaches the
        // CLIENT_DENY_BLOCKING short-circuit (set inside EVAL/FCALL)
        // and returns the current ack count immediately. With no
        // runtime replication state to consult, fr's dispatch-path
        // fallback returns 0 (the trivially correct ack count for
        // zero attached replicas). Argument-validation errors still
        // fire ahead of the success path.
        let mut store = Store::new();

        let invalid_numreplicas = dispatch_argv(
            &[b"WAIT".to_vec(), b"abc".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(invalid_numreplicas, CommandError::InvalidInteger);

        let valid = dispatch_argv(
            &[b"WAIT".to_vec(), b"0".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .expect("WAIT 0 0 must succeed without runtime context");
        assert_eq!(valid, RespFrame::Integer(0));

        let invalid_timeout = dispatch_argv(
            &[b"WAIT".to_vec(), b"0".to_vec(), b"abc".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            invalid_timeout,
            CommandError::Custom("ERR timeout is not an integer or out of range".to_string())
        );
    }

    #[test]
    fn wait_rejects_extra_args_and_returns_zero_in_script_context_20i0i() {
        // (frankenredis-waitsc) Upstream commands.def declares WAIT
        // with arity=3 (exact) and flags=0 — notably NOT
        // CMD_NOSCRIPT (compare the adjacent WAITAOF entry which
        // does carry CMD_NOSCRIPT). So trailing args surface
        // wrong-arity, but a scripted call must succeed and return
        // the current ack count (0 here, since no replicas attached).
        // (frankenredis-20i0i) fr previously errored with 'requires
        // runtime replication context' which diverged from vendored —
        // vendored's CLIENT_DENY_BLOCKING short-circuit returns the
        // ack count immediately.
        let mut store = Store::new();

        // Trailing args → WrongArity (was silently accepted prior
        // to o7kay).
        let extra = dispatch_argv(
            &[
                b"WAIT".to_vec(),
                b"0".to_vec(),
                b"0".to_vec(),
                b"extra".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(extra, CommandError::WrongArity("WAIT"));

        // Scripted call returns Integer(0) per vendored.
        store.script_nesting_level = 1;
        let scripted = dispatch_argv(
            &[b"WAIT".to_vec(), b"0".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .expect("script-context WAIT must return Integer(0) without runtime state");
        assert_eq!(scripted, RespFrame::Integer(0));
    }

    #[test]
    fn waitaof_and_failover_noscript_guard_precedes_argument_parsing() {
        // (frankenredis-d021m) Upstream commands.def declares both
        // WAITAOF and FAILOVER with CMD_NOSCRIPT, so processCommand
        // emits the noscript reply before any argument parsing runs.
        // Inside a Lua script, scripted bad-arg calls must surface
        // the noscript error rather than the parse / syntax error.
        let mut store = Store::new();
        store.script_nesting_level = 1;

        // WAITAOF with a non-integer numlocal still surfaces the
        // noscript reply because the guard fires before parse_i64_arg.
        let waitaof_scripted = dispatch_argv(
            &[
                b"WAITAOF".to_vec(),
                b"abc".to_vec(),
                b"0".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            waitaof_scripted,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );

        // FAILOVER with an unknown option should also short-circuit
        // to the noscript reply (was returning SyntaxError because
        // the option-parser ran first).
        let failover_scripted =
            dispatch_argv(&[b"FAILOVER".to_vec(), b"NOSUCH".to_vec()], &mut store, 0).unwrap_err();
        assert_eq!(
            failover_scripted,
            CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string())
        );
    }

