    #[test]
    fn cluster_admin_subcommands_honor_cluster_enabled_flag() {
        // When cluster support is disabled, every admin subcommand returns
        // the upstream-matching "cluster support disabled" error. Arity
        // validation fires before the flag check so a too-short request
        // still surfaces the precise arity error.
        let mut store = Store::new();
        for argv in [
            vec![
                b"CLUSTER".to_vec(),
                b"MEET".to_vec(),
                b"127.0.0.1".to_vec(),
                b"6380".to_vec(),
            ],
            vec![b"CLUSTER".to_vec(), b"FORGET".to_vec(), b"node".to_vec()],
            vec![b"CLUSTER".to_vec(), b"REPLICATE".to_vec(), b"node".to_vec()],
            vec![b"CLUSTER".to_vec(), b"REPLICAS".to_vec(), b"node".to_vec()],
            vec![b"CLUSTER".to_vec(), b"FAILOVER".to_vec()],
            vec![b"CLUSTER".to_vec(), b"ADDSLOTS".to_vec(), b"0".to_vec()],
            vec![b"CLUSTER".to_vec(), b"DELSLOTS".to_vec(), b"0".to_vec()],
            vec![
                b"CLUSTER".to_vec(),
                b"ADDSLOTSRANGE".to_vec(),
                b"0".to_vec(),
                b"10".to_vec(),
            ],
            vec![
                b"CLUSTER".to_vec(),
                b"DELSLOTSRANGE".to_vec(),
                b"0".to_vec(),
                b"10".to_vec(),
            ],
            vec![b"CLUSTER".to_vec(), b"FLUSHSLOTS".to_vec()],
            vec![b"CLUSTER".to_vec(), b"SAVECONFIG".to_vec()],
            vec![b"CLUSTER".to_vec(), b"BUMPEPOCH".to_vec()],
            vec![b"CLUSTER".to_vec(), b"LINKS".to_vec()],
            vec![
                b"CLUSTER".to_vec(),
                b"SET-CONFIG-EPOCH".to_vec(),
                b"1".to_vec(),
            ],
            // (frankenredis-cslotstate) SLOTSTATE is not a recognized
            // CLUSTER subcommand in upstream 7.2.4, so it now falls
            // through to the unknown-subcommand error path
            // (cunk-pinned) regardless of cluster_enabled state.
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(err, cluster_disabled_error(), "argv={argv:?}");
        }
    }

    #[test]
    fn cluster_slotstate_is_not_a_recognized_subcommand() {
        // (frankenredis-cslotstate) Differential probe vs vendored
        // Redis 7.2.4 confirms that SLOTSTATE is NOT a recognized
        // CLUSTER subcommand — neither commands.def nor cluster.c
        // references it. fr previously short-circuited it to
        // cluster_disabled_error(), so callers got the misleading
        // 'cluster support disabled' wording even when cluster mode
        // was enabled. The arm is removed; SLOTSTATE now falls
        // through to the unknown-subcommand wording (frankenredis-cunk).
        for cluster_enabled in [false, true] {
            let mut store = Store::new();
            store.cluster_enabled = cluster_enabled;
            let err = dispatch_argv(&[b"CLUSTER".to_vec(), b"SLOTSTATE".to_vec()], &mut store, 0)
                .unwrap_err();
            assert_eq!(
                err,
                CommandError::Custom(
                    "ERR unknown subcommand 'SLOTSTATE'. Try CLUSTER HELP.".to_string()
                ),
                "cluster_enabled={cluster_enabled}",
            );
        }
    }

