    // (frankenredis-u5he7) Upstream cluster.c::clusterCommand emits
    // the HELP / SLOTS replies when cluster_enabled is true. Pin
    // both happy paths and the cluster-disabled rejection.
    #[test]
    fn cluster_help_returns_help_array_when_cluster_enabled() {
        let mut store = Store::new();
        store.cluster_enabled = true;
        let out = dispatch_argv(&[b"CLUSTER".to_vec(), b"HELP".to_vec()], &mut store, 0)
            .expect("cluster help");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array reply for CLUSTER HELP"); // ubs:ignore — AI triage
        };
        assert!(
            items
                .iter()
                .any(|f| matches!(f, RespFrame::SimpleString(s) if s == "HELP")),
            "HELP entry must appear in CLUSTER HELP output, got {items:?}"
        );
        assert!(
            items
                .iter()
                .any(|f| matches!(f, RespFrame::SimpleString(s) if s == "INFO")),
            "INFO entry must appear in CLUSTER HELP output, got {items:?}"
        );
        // First entry is the standard subcommand envelope.
        assert_eq!(
            items.first(),
            Some(&RespFrame::SimpleString(
                "CLUSTER <subcommand> [<arg> [value] [opt] ...]. Subcommands are:".to_string()
            ))
        );
    }

    // (frankenredis-qteu5) CLIENT NO-EVICT / NO-TOUCH must write the
    // per-session flag through DispatchClientContext so Lua / AOF
    // replay / MULTI EXEC paths propagate the state to fr-runtime via
    // the existing sync-back. Previously the dispatch_argv arms
    // returned OK without touching any state.
    #[test]
    fn client_no_evict_no_touch_via_dispatch_persist_through_dispatch_client_ctx() {
        let mut store = Store::new();
        // Default state — both flags off.
        assert!(!store.dispatch_client_ctx.client_no_evict);
        assert!(!store.dispatch_client_ctx.client_no_touch);

        // NO-EVICT ON flips just the evict flag.
        let ok = dispatch_argv(
            &[b"CLIENT".to_vec(), b"NO-EVICT".to_vec(), b"ON".to_vec()],
            &mut store,
            0,
        )
        .expect("client no-evict on");
        assert_eq!(ok, RespFrame::SimpleString("OK".to_string()));
        assert!(store.dispatch_client_ctx.client_no_evict);
        assert!(!store.dispatch_client_ctx.client_no_touch);

        // NO-TOUCH ON flips the touch flag without disturbing evict.
        dispatch_argv(
            &[b"CLIENT".to_vec(), b"NO-TOUCH".to_vec(), b"ON".to_vec()],
            &mut store,
            0,
        )
        .expect("client no-touch on");
        assert!(store.dispatch_client_ctx.client_no_evict);
        assert!(store.dispatch_client_ctx.client_no_touch);

        // OFF flips back.
        dispatch_argv(
            &[b"CLIENT".to_vec(), b"NO-EVICT".to_vec(), b"OFF".to_vec()],
            &mut store,
            0,
        )
        .expect("client no-evict off");
        assert!(!store.dispatch_client_ctx.client_no_evict);
        assert!(store.dispatch_client_ctx.client_no_touch);
    }

    /// (frankenredis-0pnd6) Upstream cluster.c::clusterCommand uses a
    /// loose `c->argc >= 4` guard at the top of the SETSLOT handler,
    /// then checks server.cluster_enabled, then enforces per-action
    /// exact action shape (STABLE=4, NODE/IMPORTING/MIGRATING=5). With
    /// argc==6 (e.g. CLUSTER SETSLOT 0 NODE someid extra), upstream
    /// surfaces 'cluster support disabled' when cluster mode is off,
    /// because cluster_enabled is checked BEFORE the per-action
    /// exact-arity check. Pre-fix fr returned 'wrong number of
    /// arguments' here (over-strict top-level arity check). Pin the
    /// upstream order: <4 → wrong-arity; >=4 with cluster_disabled →
    /// cluster-disabled; with cluster_enabled but odd shape → the
    /// SETSLOT-specific action/argument help error.
    #[test]
    fn cluster_setslot_overarity_in_non_cluster_mode_returns_cluster_disabled() {
        // cluster_enabled defaults to false on a fresh Store.
        let mut store = Store::new();
        // 6 args → upstream's `c->argc >= 4` passes, then cluster_
        // enabled check fires.
        let err = dispatch_argv(
            &[
                b"CLUSTER".to_vec(),
                b"SETSLOT".to_vec(),
                b"0".to_vec(),
                b"NODE".to_vec(),
                b"someid".to_vec(),
                b"extra".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom("ERR This instance has cluster support disabled".to_string()),
            "6 args + cluster_disabled must surface 'cluster support disabled', not 'wrong arity'"
        );

        // <4 args still surfaces wrong-arity even when cluster disabled,
        // matching upstream's table-level arity rejection that fires
        // before clusterCommand is called at all.
        let arity_err = dispatch_argv(
            &[b"CLUSTER".to_vec(), b"SETSLOT".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert!(
            matches!(&arity_err, CommandError::Custom(s) if s.contains("wrong number of arguments"))
                || matches!(&arity_err, CommandError::WrongSubcommandArity { .. }),
            "<4 args must surface wrong-arity, got {arity_err:?}"
        );

        // With cluster_enabled true, 6 args reach the SETSLOT handler:
        // Redis parses the slot, then emits the SETSLOT-specific
        // action/argument help error.
        store.cluster_enabled = true;
        let action_err = dispatch_argv(
            &[
                b"CLUSTER".to_vec(),
                b"SETSLOT".to_vec(),
                b"0".to_vec(),
                b"NODE".to_vec(),
                b"someid".to_vec(),
                b"extra".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            action_err,
            cluster_invalid_setslot_action_error(),
            "6 args + cluster_enabled must surface SETSLOT action help"
        );
    }

    // (frankenredis-t1s3f) Upstream cluster.c::clusterCommand:6073-6132
    // dispatches CLUSTER SETSLOT into MIGRATING/IMPORTING/STABLE/NODE
    // subforms with specific arg shapes. fr validates the slot range
    // and routes the four subforms to OK / Unknown-node errors.
    #[test]
    fn cluster_setslot_validates_slot_range_and_subform_when_cluster_enabled() {
        let mut store = Store::new();
        store.cluster_enabled = true;
        // Slot out of range → "ERR Invalid slot".
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"99999".to_vec(),
                    b"STABLE".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Invalid slot".to_string())
        );
        // STABLE accepts argc=4 → OK.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"100".to_vec(),
                    b"STABLE".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        // STABLE with extra arg → SETSLOT-specific action/arity help.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"100".to_vec(),
                    b"STABLE".to_vec(),
                    b"extra".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            cluster_invalid_setslot_action_error()
        );
        // NODE without node id reaches the same SETSLOT-specific help error.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"100".to_vec(),
                    b"NODE".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            cluster_invalid_setslot_action_error()
        );
        // NODE with unknown peer → "Unknown node ...".
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"100".to_vec(),
                    b"NODE".to_vec(),
                    b"deadbeef".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Unknown node deadbeef".to_string())
        );
        let self_node_id = store.server_run_id.as_bytes().to_vec();
        // MIGRATING first checks local ownership of the slot.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"100".to_vec(),
                    b"MIGRATING".to_vec(),
                    self_node_id.clone(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR I'm not the owner of hash slot 100".to_string())
        );
        store.cluster_assigned_slots.insert(100);
        // MIGRATING with unknown peer → "I don't know about node ...".
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"100".to_vec(),
                    b"MIGRATING".to_vec(),
                    b"someid".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR I don't know about node someid".to_string())
        );
        // IMPORTING first rejects a slot already owned by this node.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"100".to_vec(),
                    b"IMPORTING".to_vec(),
                    self_node_id.clone(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR I'm already the owner of hash slot 100".to_string())
        );
        // NODE pointing at self id assigns the slot to this node.
        assert!(!store.cluster_assigned_slots.contains(&101));
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"101".to_vec(),
                    b"NODE".to_vec(),
                    self_node_id,
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert!(store.cluster_assigned_slots.contains(&101));
        // Bogus action → SETSLOT-specific action/arity help.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SETSLOT".to_vec(),
                    b"100".to_vec(),
                    b"WHATEVER".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            cluster_invalid_setslot_action_error()
        );
    }

    // (frankenredis-bdokn) Upstream cluster.c::clusterGenNodeDescription
    // emits per-node lines '<id> <ip:port@cport> <flags> <master>
    // <pings> <pongs> <epoch> <link> [<slot ranges>]'. fr emits one
    // line for the self node with deterministic flags / counters /
    // slot ranges from cluster_assigned_slots.
    #[test]
    fn cluster_nodes_returns_self_line_when_cluster_enabled() {
        let mut store = Store::new();
        store.cluster_enabled = true;
        let RespFrame::BulkString(Some(text)) =
            dispatch_argv(&[b"CLUSTER".to_vec(), b"NODES".to_vec()], &mut store, 0)
                .expect("cluster nodes empty")
        else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let line = String::from_utf8(text).expect("nodes text utf8");
        assert!(line.contains(" myself,master "), "got line: {line:?}");
        assert!(
            line.contains(" 127.0.0.1:6379@16379 "),
            "got line: {line:?}"
        );
        assert!(line.contains(" 0 0 0 connected"), "got line: {line:?}");
        assert!(line.starts_with(&store.server_run_id), "got line: {line:?}");
        assert!(
            line.ends_with('\n'),
            "trailing newline expected, got {line:?}"
        );

        // Add a contiguous slot range and verify it gets emitted as start-end.
        for slot in 0..=2u16 {
            store.cluster_assigned_slots.insert(slot);
        }
        // Add an isolated slot to confirm singleton formatting.
        store.cluster_assigned_slots.insert(100);
        let RespFrame::BulkString(Some(text)) =
            dispatch_argv(&[b"CLUSTER".to_vec(), b"NODES".to_vec()], &mut store, 0)
                .expect("cluster nodes populated")
        else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let line = String::from_utf8(text).expect("nodes text utf8");
        assert!(line.contains(" 0-2 "), "expected `0-2` range, got {line:?}");
        assert!(
            line.contains(" 100\n") || line.contains(" 100"),
            "expected singleton slot 100, got {line:?}"
        );
    }

    // (frankenredis-39rkv) Upstream cluster.c::genClusterInfoString
    // emits the cluster_state line plus deterministic slot / node
    // counters. fr emits the same fields with values derived from
    // its single-node stub state.
    #[test]
    fn cluster_info_returns_synthesized_text_when_cluster_enabled() {
        let mut store = Store::new();
        store.cluster_enabled = true;
        // No slots assigned → state=fail, size=0.
        let RespFrame::BulkString(Some(text)) =
            dispatch_argv(&[b"CLUSTER".to_vec(), b"INFO".to_vec()], &mut store, 0)
                .expect("cluster info empty")
        else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let body = String::from_utf8(text).expect("info text utf8");
        assert!(
            body.contains("cluster_state:fail\r\n"),
            "no slots → state=fail, got {body:?}"
        );
        assert!(body.contains("cluster_slots_assigned:0\r\n"));
        assert!(body.contains("cluster_size:0\r\n"));
        assert!(body.contains("cluster_known_nodes:1\r\n"));
        assert!(body.contains("cluster_current_epoch:0\r\n"));
        assert!(body.contains("total_cluster_links_buffer_limit_exceeded:0\r\n"));

        // Assign all 16384 slots → state=ok, size=1.
        for slot in 0..16384u16 {
            store.cluster_assigned_slots.insert(slot);
        }
        let RespFrame::BulkString(Some(text)) =
            dispatch_argv(&[b"CLUSTER".to_vec(), b"INFO".to_vec()], &mut store, 0)
                .expect("cluster info full")
        else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let body = String::from_utf8(text).expect("info text utf8");
        assert!(body.contains("cluster_state:ok\r\n"));
        assert!(body.contains("cluster_slots_assigned:16384\r\n"));
        assert!(body.contains("cluster_slots_ok:16384\r\n"));
        assert!(body.contains("cluster_size:1\r\n"));
    }

    #[test]
    fn cluster_slots_returns_assigned_ranges_when_cluster_enabled() {
        let mut store = Store::new();
        store.cluster_enabled = true;
        // No slots assigned → empty array.
        let out = dispatch_argv(&[b"CLUSTER".to_vec(), b"SLOTS".to_vec()], &mut store, 0)
            .expect("cluster slots empty");
        assert_eq!(out, RespFrame::Array(Some(vec![])));
        // After ADDSLOTS 0 1 2 → one merged range entry.
        dispatch_argv(
            &[
                b"CLUSTER".to_vec(),
                b"ADDSLOTS".to_vec(),
                b"0".to_vec(),
                b"1".to_vec(),
                b"2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("addslots");
        let RespFrame::Array(Some(ranges)) =
            dispatch_argv(&[b"CLUSTER".to_vec(), b"SLOTS".to_vec()], &mut store, 0)
                .expect("cluster slots populated")
        else {
            panic!("expected array"); // ubs:ignore — AI triage
        };
        assert_eq!(
            ranges.len(),
            1,
            "0..2 merges into one range, got {ranges:?}"
        );
    }

    #[test]
    fn cluster_admin_happy_paths_when_cluster_enabled_return_ok_or_specific_errors() {
        let mut store = Store::new();
        store.cluster_enabled = true;

        // MEET accepts host + numeric port (+ optional bus port).
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"MEET".to_vec(),
                    b"127.0.0.1".to_vec(),
                    b"6380".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"MEET".to_vec(),
                    b"127.0.0.1".to_vec(),
                    b"6380".to_vec(),
                    b"16380".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );

        assert_eq!(
            dispatch_argv(&[b"CLUSTER".to_vec(), b"LINKS".to_vec()], &mut store, 0).unwrap(),
            RespFrame::Array(Some(vec![]))
        );

        // MEET invalid host/port/bus-port surfaces match the Redis 7.2.4 oracle.
        let err = dispatch_argv(
            &[
                b"CLUSTER".to_vec(),
                b"MEET".to_vec(),
                b"127.0.0.1".to_vec(),
                b"port".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom("ERR Invalid base port specified: port".to_string())
        );
        let err = dispatch_argv(
            &[
                b"CLUSTER".to_vec(),
                b"MEET".to_vec(),
                b"127.0.0.1".to_vec(),
                b"6380".to_vec(),
                b"bus".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom("ERR Invalid bus port specified: bus".to_string())
        );
        let err = dispatch_argv(
            &[
                b"CLUSTER".to_vec(),
                b"MEET".to_vec(),
                b"bad-host".to_vec(),
                b"6380".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom("ERR Invalid node address specified: bad-host:6380".to_string())
        );
        let err = dispatch_argv(
            &[
                b"CLUSTER".to_vec(),
                b"MEET".to_vec(),
                b"127.0.0.1".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom("ERR Invalid node address specified: 127.0.0.1:0".to_string())
        );

        // FORGET / REPLICATE / REPLICAS on unknown node → upstream wording.
        let own_id = store.server_run_id.as_bytes().to_vec();
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"FORGET".to_vec(), own_id.clone()],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR I tried hard but I can't forget myself...".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"FORGET".to_vec(),
                    b"unknownnode".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Unknown node unknownnode".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"REPLICATE".to_vec(), own_id.clone()],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Can't replicate myself".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"REPLICATE".to_vec(),
                    b"unknownnode".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Unknown node unknownnode".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"REPLICAS".to_vec(), own_id.clone()],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::Array(Some(vec![]))
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"REPLICAS".to_vec(),
                    b"unknownnode".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom(
                "ERR The specified node is not known or can't be a replica".to_string()
            )
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"COUNT-FAILURE-REPORTS".to_vec(),
                    own_id
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::Integer(0)
        );

        // FAILOVER on master → upstream error about directing to a replica.
        assert_eq!(
            dispatch_argv(&[b"CLUSTER".to_vec(), b"FAILOVER".to_vec()], &mut store, 0).unwrap_err(),
            CommandError::Custom("ERR You should send CLUSTER FAILOVER to a replica".to_string())
        );
        // FAILOVER with invalid flag → syntax error.
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"FAILOVER".to_vec(), b"NOPE".to_vec()],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::SyntaxError
        );
        // FAILOVER with two flags (e.g. FORCE TAKEOVER) → upstream falls
        // through to the unknown-subcommand error since
        // `argc == 2 || argc == 3` is the gate. (frankenredis-7mqn0)
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"FAILOVER".to_vec(),
                    b"FORCE".to_vec(),
                    b"TAKEOVER".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments for 'FAILOVER'. \
                 Try CLUSTER HELP."
                    .to_string()
            )
        );
        // FAILOVER with duplicate flags also falls through.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"FAILOVER".to_vec(),
                    b"FORCE".to_vec(),
                    b"FORCE".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments for 'FAILOVER'. \
                 Try CLUSTER HELP."
                    .to_string()
            )
        );

        // ADDSLOTS / DELSLOTS update the single-node slot assignment surface.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"ADDSLOTS".to_vec(),
                    b"0".to_vec(),
                    b"16383".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"ADDSLOTS".to_vec(), b"0".to_vec()],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Slot 0 is already busy".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"ADDSLOTS".to_vec(),
                    b"0".to_vec(),
                    b"0".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Slot 0 is already busy".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"ADDSLOTS".to_vec(),
                    b"1".to_vec(),
                    b"1".to_vec()
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Slot 1 specified multiple times".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"DELSLOTS".to_vec(), b"0".to_vec()],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"DELSLOTS".to_vec(), b"0".to_vec()],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Slot 0 is already unassigned".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"ADDSLOTS".to_vec(), b"16384".to_vec()],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Invalid or out of range slot".to_string())
        );

        // ADDSLOTSRANGE / DELSLOTSRANGE expand to contiguous slot sets.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"ADDSLOTSRANGE".to_vec(),
                    b"10".to_vec(),
                    b"12".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"ADDSLOTSRANGE".to_vec(),
                    b"10".to_vec(),
                    b"11".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Slot 10 is already busy".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"ADDSLOTSRANGE".to_vec(),
                    b"10".to_vec(),
                    b"10".to_vec(),
                    b"10".to_vec(),
                    b"10".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Slot 10 is already busy".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"DELSLOTSRANGE".to_vec(),
                    b"10".to_vec(),
                    b"12".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"DELSLOTSRANGE".to_vec(),
                    b"10".to_vec(),
                    b"12".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Slot 10 is already unassigned".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"ADDSLOTSRANGE".to_vec(),
                    b"100".to_vec(),
                    b"50".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom(
                "ERR start slot number 100 is greater than end slot number 50".to_string()
            )
        );

        // FLUSHSLOTS on empty db → OK.
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"FLUSHSLOTS".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        // Populate db0 and retry: upstream-matching DB-not-empty error.
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"FLUSHSLOTS".to_vec()],
                &mut store,
                0
            )
            .unwrap_err(),
            CommandError::Custom("ERR DB must be empty to perform CLUSTER FLUSHSLOTS.".to_string())
        );

        // SAVECONFIG + BUMPEPOCH stateful replies.
        assert_eq!(
            dispatch_argv(
                &[b"CLUSTER".to_vec(), b"SAVECONFIG".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(&[b"CLUSTER".to_vec(), b"BUMPEPOCH".to_vec()], &mut store, 0).unwrap(),
            RespFrame::SimpleString("BUMPED 1".to_string())
        );
        assert_eq!(
            dispatch_argv(&[b"CLUSTER".to_vec(), b"BUMPEPOCH".to_vec()], &mut store, 0).unwrap(),
            RespFrame::SimpleString("STILL 1".to_string())
        );
        assert_eq!(store.cluster_current_epoch, 1);
        assert_eq!(store.cluster_my_config_epoch, 1);

        let mut epoch_store = Store::new();
        epoch_store.cluster_enabled = true;

        // SET-CONFIG-EPOCH: a fresh single node accepts one non-negative
        // epoch, records it in CLUSTER INFO/NODES, then rejects later
        // attempts because configEpoch is non-zero.
        // (frankenredis-pfamt, frankenredis-dc4q7)
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SET-CONFIG-EPOCH".to_vec(),
                    b"5".to_vec()
                ],
                &mut epoch_store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(epoch_store.cluster_current_epoch, 5);
        assert_eq!(epoch_store.cluster_my_config_epoch, 5);
        let RespFrame::BulkString(Some(info)) = dispatch_argv(
            &[b"CLUSTER".to_vec(), b"INFO".to_vec()],
            &mut epoch_store,
            0,
        )
        .unwrap() else {
            panic!("expected cluster info bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(info).expect("cluster info utf8");
        assert!(info.contains("cluster_current_epoch:5\r\n"), "{info}");
        assert!(info.contains("cluster_my_epoch:5\r\n"), "{info}");
        let RespFrame::BulkString(Some(nodes)) = dispatch_argv(
            &[b"CLUSTER".to_vec(), b"NODES".to_vec()],
            &mut epoch_store,
            0,
        )
        .unwrap() else {
            panic!("expected cluster nodes bulk string"); // ubs:ignore — AI triage
        };
        let nodes = String::from_utf8(nodes).expect("cluster nodes utf8");
        assert!(nodes.contains(" 0 0 5 connected"), "{nodes}");
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SET-CONFIG-EPOCH".to_vec(),
                    b"6".to_vec()
                ],
                &mut epoch_store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Node config epoch is already non-zero".to_string())
        );
        // Negative epoch is rejected with the upstream message.
        assert_eq!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SET-CONFIG-EPOCH".to_vec(),
                    b"-1".to_vec(),
                ],
                &mut epoch_store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom("ERR Invalid config epoch specified: -1".to_string())
        );
        // Non-integer arg surfaces the standard InvalidInteger error.
        assert!(matches!(
            dispatch_argv(
                &[
                    b"CLUSTER".to_vec(),
                    b"SET-CONFIG-EPOCH".to_vec(),
                    b"notanint".to_vec(),
                ],
                &mut epoch_store,
                0,
            )
            .unwrap_err(),
            CommandError::InvalidInteger
        ));
        // SLOTSTATE remains a follow-up stub.
    }

    // ── CLIENT KILL/PAUSE/UNPAUSE tests ─────────────────────────────

    #[test]
    fn client_kill_preserves_legacy_addr_and_filter_modes() {
        let mut store = Store::new();
        store.dispatch_client_ctx.peer_addr = "10.0.0.9:7777".to_string();

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"10.0.0.9:9999".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(err, CommandError::Custom("ERR No such client".to_string()));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"10.0.0.9:7777".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"ID".to_vec(),
                b"99999".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(0));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"TYPE".to_vec(),
                b"slave".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(0));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"SKIPME".to_vec(),
                b"no".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(1));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"USER".to_vec(),
                b"default".to_vec(),
                b"SKIPME".to_vec(),
                b"no".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(1));

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"USER".to_vec(),
                b"ghost".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom("ERR No such user 'ghost'".to_string())
        );

        store.dispatch_client_ctx.authenticated_user = b"alice".to_vec();
        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"USER".to_vec(),
                b"alice".to_vec(),
                b"SKIPME".to_vec(),
                b"no".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(1));

        let current_laddr = format!("127.0.0.1:{}", store.server_port).into_bytes();
        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"LADDR".to_vec(),
                current_laddr.clone(),
                b"SKIPME".to_vec(),
                b"no".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(1));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"LADDR".to_vec(),
                current_laddr,
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(0));

        let out = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"KILL".to_vec(),
                b"LADDR".to_vec(),
                b"127.0.0.1:1".to_vec(),
                b"SKIPME".to_vec(),
                b"no".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::Integer(0));
    }

