    #[test]
    fn client_pause_rejects_invalid_shape() {
        let mut store = Store::new();
        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"PAUSE".to_vec(),
                b"1000".to_vec(),
                b"WRITE".to_vec(),
                b"EXTRA".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        // (frankenredis-clipausearity) Too-many-args path keeps the
        // SubcommandSyntaxError envelope — pauseCommand reaches the
        // handler body before its addReplySubcommandSyntaxError fires.
        assert_eq!(
            err,
            CommandError::Custom(
                "ERR unknown subcommand or wrong number of arguments for 'PAUSE'. Try CLIENT HELP."
                    .to_string()
            )
        );

        // (frankenredis-clipausearity) Too-few-args path uses the
        // table-level wording. Upstream commands.def declares CLIENT
        // PAUSE with arity = -3, so the missing-timeout case never
        // reaches the handler — the table-level arity check emits
        // 'wrong number of arguments for client|pause command'.
        let err =
            dispatch_argv(&[b"CLIENT".to_vec(), b"PAUSE".to_vec()], &mut store, 0).unwrap_err();
        assert_eq!(err, client_wrong_subcommand_arity("PAUSE"));

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"PAUSE".to_vec(),
                b"notanumber".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom(CLIENT_PAUSE_TIMEOUT_INVALID.to_string())
        );

        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"PAUSE".to_vec(),
                b"1000".to_vec(),
                b"WAT".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::Custom(CLIENT_PAUSE_MODE_INVALID.to_string())
        );
    }

