    #[test]
    fn client_reply_rejected_from_scripts_after_validation() {
        let mut store = Store::new();
        store.script_nesting_level = 1;

        // (frankenredis-clirep) Upstream commands.def declares
        // client|reply with CMD_NOSCRIPT (line 1551). For an
        // arity-3 call, processCommand fires noscript BEFORE the
        // mode validator runs — even when the mode is bogus. fr
        // previously surfaced SyntaxError here because the dispatch-
        // level guard ran AFTER the parse step's `?` propagation.
        let err = dispatch_argv(
            &[b"CLIENT".to_vec(), b"REPLY".to_vec(), b"MAYBE".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(err, CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()));

        // 4-arg case is still wrong-arity at fr-command; lua_eval
        // wraps it into the script-context wording at the call site.
        let err = dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"REPLY".to_vec(),
                b"ON".to_vec(),
                b"NOW".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(err, client_wrong_subcommand_arity("REPLY"));

        for mode in [b"ON".as_slice(), b"OFF".as_slice(), b"SKIP".as_slice()] {
            let err = dispatch_argv(
                &[b"CLIENT".to_vec(), b"REPLY".to_vec(), mode.to_vec()],
                &mut store,
                0,
            )
            .unwrap_err();
            assert_eq!(err, CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()));
            assert!(!store.dispatch_client_ctx.client_reply.off);
            assert!(!store.dispatch_client_ctx.client_reply.skip_next);
            assert!(
                !store
                    .dispatch_client_ctx
                    .client_reply
                    .suppress_current_response
            );
        }
    }

    #[test]
    fn client_reply_state_tracks_off_skip_and_on() {
        let mut store = Store::new();

        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"REPLY".to_vec(), b"OFF".to_vec()],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert!(store.dispatch_client_ctx.client_reply.off);
        assert!(!store.dispatch_client_ctx.client_reply.skip_next);
        assert!(
            store
                .dispatch_client_ctx
                .client_reply
                .suppress_current_response
        );

        assert_eq!(
            dispatch_argv(&[b"PING".to_vec()], &mut store, 1).unwrap(),
            RespFrame::SimpleString("PONG".to_string())
        );
        assert!(store.dispatch_client_ctx.client_reply.off);
        assert!(!store.dispatch_client_ctx.client_reply.skip_next);
        assert!(
            store
                .dispatch_client_ctx
                .client_reply
                .suppress_current_response
        );

        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"REPLY".to_vec(), b"ON".to_vec()],
                &mut store,
                2,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert!(!store.dispatch_client_ctx.client_reply.off);
        assert!(!store.dispatch_client_ctx.client_reply.skip_next);
        assert!(
            !store
                .dispatch_client_ctx
                .client_reply
                .suppress_current_response
        );

        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"REPLY".to_vec(), b"SKIP".to_vec()],
                &mut store,
                3,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert!(!store.dispatch_client_ctx.client_reply.off);
        assert!(store.dispatch_client_ctx.client_reply.skip_next);
        assert!(
            store
                .dispatch_client_ctx
                .client_reply
                .suppress_current_response
        );

        assert_eq!(
            dispatch_argv(&[b"PING".to_vec()], &mut store, 4).unwrap(),
            RespFrame::SimpleString("PONG".to_string())
        );
        assert!(!store.dispatch_client_ctx.client_reply.off);
        assert!(!store.dispatch_client_ctx.client_reply.skip_next);
        assert!(
            store
                .dispatch_client_ctx
                .client_reply
                .suppress_current_response
        );

        assert_eq!(
            dispatch_argv(&[b"PING".to_vec()], &mut store, 5).unwrap(),
            RespFrame::SimpleString("PONG".to_string())
        );
        assert!(!store.dispatch_client_ctx.client_reply.off);
        assert!(!store.dispatch_client_ctx.client_reply.skip_next);
        assert!(
            !store
                .dispatch_client_ctx
                .client_reply
                .suppress_current_response
        );
    }

    #[test]
    fn client_reply_error_still_updates_suppression_state() {
        // Regression test for fuzz_client_reply crash (fuzz artifact
        // crash-e4c14920bd645b56349c2b4e4b9ebbb84ece0e88). When CLIENT
        // REPLY fails validation (wrong arity or invalid mode), the
        // suppress_current_response must still be set based on prior
        // off/skip_next state, and skip_next must be cleared.
        use crate::apply_client_reply_state;
        use fr_store::ClientReplyState;

        let mut state = ClientReplyState::default();

        // Set skip_next=true
        apply_client_reply_state(
            &[b"CLIENT".to_vec(), b"REPLY".to_vec(), b"SKIP".to_vec()],
            &mut state,
        )
        .unwrap();
        assert!(state.skip_next);
        assert!(state.suppress_current_response);

        // Invalid mode should still consume skip_next and set suppress
        let err = apply_client_reply_state(
            &[b"CLIENT".to_vec(), b"REPLY".to_vec(), b"GARBAGE".to_vec()],
            &mut state,
        )
        .unwrap_err();
        assert_eq!(err, CommandError::SyntaxError);
        assert!(!state.skip_next, "skip_next must be cleared on error");
        assert!(
            state.suppress_current_response,
            "suppress must be set based on prior skip_next"
        );

        // Same for wrong arity while off=true
        state = ClientReplyState::default();
        state.off = true;

        let err = apply_client_reply_state(
            &[
                b"CLIENT".to_vec(),
                b"REPLY".to_vec(),
                b"ON".to_vec(),
                b"EXTRA".to_vec(),
            ],
            &mut state,
        )
        .unwrap_err();
        assert_eq!(err, client_wrong_subcommand_arity("REPLY"));
        assert!(
            state.suppress_current_response,
            "suppress must be set based on prior off state"
        );
    }

