    /// (frankenredis-fqwyf) Upstream server.c::genRedisInfoString
    /// emits the maxmemory triple (maxmemory / maxmemory_human /
    /// maxmemory_policy) right after used_memory_scripts_human, just
    /// before allocator_frag_ratio — not in the middle of the
    /// dataset/allocator block. Pin the relative position so a future
    /// reorder trips a targeted test.
    #[test]
    fn info_memory_emits_maxmemory_triple_after_scripts_human_per_upstream() {
        let mut store = Store::new();
        let out = dispatch_argv(&[b"INFO".to_vec(), b"memory".to_vec()], &mut store, 0)
            .expect("info memory");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk INFO memory reply"); // ubs:ignore — AI triage
        };
        let body = String::from_utf8(bytes).expect("utf8 memory");
        let dataset_perc = body
            .find("used_memory_dataset_perc:")
            .expect("missing used_memory_dataset_perc");
        let alloc_allocated = body
            .find("allocator_allocated:")
            .expect("missing allocator_allocated");
        let scripts_human = body
            .find("used_memory_scripts_human:")
            .expect("missing used_memory_scripts_human");
        let maxmemory = body.find("maxmemory:").expect("missing maxmemory");
        let alloc_frag_ratio = body
            .find("allocator_frag_ratio:")
            .expect("missing allocator_frag_ratio");
        assert!(
            dataset_perc < alloc_allocated,
            "used_memory_dataset_perc must precede allocator_allocated; body=\n{body}"
        );
        assert!(
            alloc_allocated < scripts_human
                && scripts_human < maxmemory
                && maxmemory < alloc_frag_ratio,
            "expected order allocator_allocated < used_memory_scripts_human < maxmemory < allocator_frag_ratio, got {alloc_allocated}/{scripts_human}/{maxmemory}/{alloc_frag_ratio}; body=\n{body}"
        );
    }

    #[test]
    fn info_memory_reports_real_script_function_library_counts() {
        // (frankenredis-8tk8h) INFO memory used to hardcode
        // number_of_cached_scripts/functions/libraries to 0 even though
        // SCRIPT LOAD and FUNCTION LOAD populate real counters in
        // Store. Pin the live values.
        let mut store = Store::new();

        // Baseline: empty stores → all three zero.
        let out = dispatch_argv(&[b"INFO".to_vec(), b"memory".to_vec()], &mut store, 0)
            .expect("info memory baseline");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(info.contains("number_of_cached_scripts:0\r\n"));
        assert!(info.contains("number_of_functions:0\r\n"));
        assert!(info.contains("number_of_libraries:0\r\n"));

        // Load a script and a function library — counters should reflect them.
        dispatch_argv(
            &[b"SCRIPT".to_vec(), b"LOAD".to_vec(), b"return 1".to_vec()],
            &mut store,
            1,
        )
        .expect("script load");
        dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"#!lua name=lib1\nredis.register_function('f1', function() return 1 end)\nredis.register_function('f2', function() return 2 end)".to_vec(),
            ],
            &mut store,
            2,
        )
        .expect("function load");

        let out = dispatch_argv(&[b"INFO".to_vec(), b"memory".to_vec()], &mut store, 3)
            .expect("info memory loaded");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(
            info.contains("number_of_cached_scripts:1\r\n"),
            "expected 1 cached script in: {info}"
        );
        assert!(
            info.contains("number_of_functions:2\r\n"),
            "expected 2 functions in: {info}"
        );
        assert!(
            info.contains("number_of_libraries:1\r\n"),
            "expected 1 library in: {info}"
        );
    }

    #[test]
    fn info_memory_reports_real_used_memory_scripts_and_lua_bytes() {
        // (frankenredis-ymyrt) used_memory_scripts / used_memory_lua /
        // used_memory_scripts_eval / used_memory_lua_human were stubbed
        // to 0/0B even though Store::script_cache contains the body
        // bytes. The new helper Store::scripts_memory_bytes() approximates
        // upstream evalScriptsMemory: per-entry sha (40 hex chars) +
        // body bytes.
        let mut store = Store::new();

        // Empty: all four counters report 0.
        let out = dispatch_argv(&[b"INFO".to_vec(), b"memory".to_vec()], &mut store, 0)
            .expect("info memory baseline");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(info.contains("used_memory_scripts:0\r\n"));
        assert!(info.contains("used_memory_scripts_human:0B\r\n"));
        assert!(info.contains("used_memory_lua:0\r\n"));
        assert!(info.contains("used_memory_lua_human:0B\r\n"));
        assert!(info.contains("used_memory_scripts_eval:0\r\n"));

        // SCRIPT LOAD a body of known size — counter reflects 40-byte
        // sha overhead + body bytes.
        let body = b"return 1";
        dispatch_argv(
            &[b"SCRIPT".to_vec(), b"LOAD".to_vec(), body.to_vec()],
            &mut store,
            1,
        )
        .expect("script load");
        let expected = 40 + body.len();
        let out = dispatch_argv(&[b"INFO".to_vec(), b"memory".to_vec()], &mut store, 2)
            .expect("info memory loaded");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(
            info.contains(&format!("used_memory_scripts:{expected}\r\n")),
            "expected used_memory_scripts:{expected} in: {info}"
        );
        assert!(
            info.contains(&format!("used_memory_lua:{expected}\r\n")),
            "expected used_memory_lua:{expected} in: {info}"
        );
        assert!(
            info.contains(&format!("used_memory_scripts_eval:{expected}\r\n")),
            "expected used_memory_scripts_eval:{expected} in: {info}"
        );
        // Human formatter emits 'NB' for sub-KB byte counts.
        assert!(
            info.contains(&format!("used_memory_scripts_human:{expected}B\r\n")),
            "expected used_memory_scripts_human:{expected}B in: {info}"
        );
        assert!(
            info.contains(&format!("used_memory_lua_human:{expected}B\r\n")),
            "expected used_memory_lua_human:{expected}B in: {info}"
        );
    }

    #[test]
    fn info_memory_reports_real_used_memory_functions_bytes() {
        // (frankenredis-2usb3) used_memory_functions /
        // used_memory_vm_functions were stubbed to 0 even though
        // FunctionLibrary.code holds the raw library code. Pin
        // baseline + post-load shapes.
        let mut store = Store::new();

        let out = dispatch_argv(&[b"INFO".to_vec(), b"memory".to_vec()], &mut store, 0)
            .expect("info memory baseline");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(info.contains("used_memory_functions:0\r\n"));
        assert!(info.contains("used_memory_vm_functions:0\r\n"));

        // Load a library — counter must reflect the code byte count
        // plus per-library/per-function metadata bytes.
        let body = b"#!lua name=mylib\nredis.register_function('f', function() return 1 end)";
        dispatch_argv(
            &[b"FUNCTION".to_vec(), b"LOAD".to_vec(), body.to_vec()],
            &mut store,
            1,
        )
        .expect("function load");

        let bytes_after = store.functions_memory_bytes();
        // Sanity: counter must include at least the raw code length.
        assert!(
            bytes_after >= body.len(),
            "functions_memory_bytes ({bytes_after}) must include the raw \
             code length ({}) at minimum",
            body.len()
        );

        let out = dispatch_argv(&[b"INFO".to_vec(), b"memory".to_vec()], &mut store, 2)
            .expect("info memory loaded");
        let RespFrame::BulkString(Some(bytes)) = out else {
            panic!("expected bulk string"); // ubs:ignore — AI triage
        };
        let info = String::from_utf8(bytes).expect("utf8");
        assert!(
            info.contains(&format!("used_memory_functions:{bytes_after}\r\n")),
            "expected used_memory_functions:{bytes_after} in: {info}"
        );
        assert!(
            info.contains(&format!("used_memory_vm_functions:{bytes_after}\r\n")),
            "expected used_memory_vm_functions:{bytes_after} in: {info}"
        );
    }

    #[test]
    fn memory_stats_reports_live_lua_caches_and_functions_caches() {
        // (frankenredis-t344m) MEMORY STATS lua.caches and
        // functions.caches were hardcoded to 0 even after ymyrt and
        // 2usb3 wired Store::scripts_memory_bytes() and
        // Store::functions_memory_bytes() into INFO memory. Pin the
        // baseline (0) and post-load live state via the MEMORY STATS
        // command itself.
        let mut store = Store::new();

        // Baseline: empty store.
        let out = dispatch_argv(&[b"MEMORY".to_vec(), b"STATS".to_vec()], &mut store, 0)
            .expect("memory stats baseline");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected MEMORY STATS Array under RESP2"); // ubs:ignore — AI triage
        };
        // Find lua.caches and functions.caches by scanning the
        // alternating-Array body.
        let mut lua_caches: Option<i64> = None;
        let mut functions_caches: Option<i64> = None;
        for chunk in items.chunks(2) {
            let RespFrame::BulkString(Some(key)) = &chunk[0] else {
                continue;
            };
            let RespFrame::Integer(value) = chunk[1] else {
                continue;
            };
            match key.as_slice() {
                b"lua.caches" => lua_caches = Some(value),
                b"functions.caches" => functions_caches = Some(value),
                _ => {}
            }
        }
        assert_eq!(lua_caches, Some(0), "baseline lua.caches");
        assert_eq!(functions_caches, Some(0), "baseline functions.caches");

        // Load script + library — counters must reflect live bytes.
        dispatch_argv(
            &[b"SCRIPT".to_vec(), b"LOAD".to_vec(), b"return 1".to_vec()],
            &mut store,
            1,
        )
        .expect("script load");
        dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"#!lua name=lib1\nredis.register_function('f', function() return 1 end)".to_vec(),
            ],
            &mut store,
            2,
        )
        .expect("function load");

        let expected_lua = store.scripts_memory_bytes() as i64;
        let expected_funcs = store.functions_memory_bytes() as i64;
        assert!(expected_lua > 0);
        assert!(expected_funcs > 0);

        let out = dispatch_argv(&[b"MEMORY".to_vec(), b"STATS".to_vec()], &mut store, 3)
            .expect("memory stats loaded");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected MEMORY STATS Array under RESP2"); // ubs:ignore — AI triage
        };
        let mut lua_caches: Option<i64> = None;
        let mut functions_caches: Option<i64> = None;
        for chunk in items.chunks(2) {
            let RespFrame::BulkString(Some(key)) = &chunk[0] else {
                continue;
            };
            let RespFrame::Integer(value) = chunk[1] else {
                continue;
            };
            match key.as_slice() {
                b"lua.caches" => lua_caches = Some(value),
                b"functions.caches" => functions_caches = Some(value),
                _ => {}
            }
        }
        assert_eq!(lua_caches, Some(expected_lua));
        assert_eq!(functions_caches, Some(expected_funcs));
    }

    #[test]
    fn memory_stats_iterates_all_non_empty_dbs_and_skips_empty_ones() {
        // (frankenredis-0lsoy) Upstream MEMORY STATS emits one db.<n>
        // entry per non-empty db. fr was hardcoding a single db.0 with
        // zero counters regardless of which db actually held data. Pin
        // the new behavior: empty store has no db.<n> entries; a key
        // in db 5 surfaces a db.5 entry (and nothing else); two dbs
        // populated → two db.<n> entries.

        // 1. Empty store: zero db.<n> entries.
        let mut store = Store::new();
        let out = dispatch_argv(&[b"MEMORY".to_vec(), b"STATS".to_vec()], &mut store, 0)
            .expect("memory stats empty");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected Array under RESP2"); // ubs:ignore — AI triage
        };
        let count_db_entries = |items: &[RespFrame]| -> usize {
            items
                .iter()
                .filter(|f| {
                    matches!(
                        f,
                        RespFrame::BulkString(Some(b)) if b.starts_with(b"db.")
                    )
                })
                .count()
        };
        assert_eq!(
            count_db_entries(&items),
            0,
            "empty store should not emit any db.<n> entry"
        );

        // 2. Single key in db 5 → only db.5 emitted. fr-command's SET
        // handler stores at the raw key (no per-db namespacing), so
        // seed the per-db state directly via the store API using
        // encode_db_key.
        let mut store = Store::new();
        store.set(fr_store::encode_db_key(5, b"k"), b"v".to_vec(), None, 0);
        let out = dispatch_argv(&[b"MEMORY".to_vec(), b"STATS".to_vec()], &mut store, 2)
            .expect("memory stats db5");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected Array under RESP2"); // ubs:ignore — AI triage
        };
        let db_keys: Vec<&[u8]> = items
            .iter()
            .filter_map(|f| match f {
                RespFrame::BulkString(Some(b)) if b.starts_with(b"db.") => Some(b.as_slice()),
                _ => None,
            })
            .collect();
        assert_eq!(db_keys, vec![b"db.5".as_slice()]);

        // 3. Two dbs populated → both emitted in order.
        let mut store = Store::new();
        store.set(fr_store::encode_db_key(0, b"k0"), b"v".to_vec(), None, 0);
        store.set(fr_store::encode_db_key(3, b"k3"), b"v".to_vec(), None, 0);
        let out = dispatch_argv(&[b"MEMORY".to_vec(), b"STATS".to_vec()], &mut store, 3)
            .expect("memory stats two dbs");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected Array under RESP2"); // ubs:ignore — AI triage
        };
        let db_keys: Vec<&[u8]> = items
            .iter()
            .filter_map(|f| match f {
                RespFrame::BulkString(Some(b)) if b.starts_with(b"db.") => Some(b.as_slice()),
                _ => None,
            })
            .collect();
        assert_eq!(db_keys, vec![b"db.0".as_slice(), b"db.3".as_slice()]);

        // 4. overhead.hashtable.main reflects per-db key count × 64.
        let db3_idx = items
            .iter()
            .position(|f| matches!(f, RespFrame::BulkString(Some(b)) if b.as_slice() == b"db.3"))
            .expect("db.3 idx");
        let RespFrame::Array(Some(db3_inner)) = &items[db3_idx + 1] else {
            panic!("db.3 inner must be Array under RESP2"); // ubs:ignore — AI triage
        };
        // Inner [main_key, main_val, expires_key, expires_val, slot_key, slot_val]
        assert_eq!(db3_inner[1], RespFrame::Integer(64)); // 1 key × 64
    }

