    #[test]
    fn command_docs_emits_upstream_summary_since_complexity_for_get() {
        // (frankenredis-f39s3) Pin the per-command upstream metadata
        // pulled from legacy_redis_code/redis/src/commands/get.json:
        //   summary    = "Returns the string value of a key."
        //   since      = "1.0.0"
        //   complexity = "O(1)"
        // A future build.rs refactor that drops the JSON-driven
        // harvester would silently regress every COMMAND DOCS reply.
        let mut store = Store::new();
        let out = dispatch_argv(
            &[b"COMMAND".to_vec(), b"DOCS".to_vec(), b"GET".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        let RespFrame::Array(Some(entries)) = out else {
            panic!("expected docs array"); // ubs:ignore — AI triage
        };
        let RespFrame::Array(Some(doc_fields)) = &entries[1] else {
            panic!("expected doc fields array"); // ubs:ignore — AI triage
        };
        // Walk the [k1, v1, k2, v2, ...] field list and assert each
        // expected pair is present.
        let pairs: Vec<(Vec<u8>, Vec<u8>)> = doc_fields
            .chunks(2)
            .filter_map(|chunk| match chunk {
                [
                    RespFrame::BulkString(Some(k)),
                    RespFrame::BulkString(Some(v)),
                ] => Some((k.clone(), v.clone())),
                _ => None,
            })
            .collect();
        let kv = |key: &[u8]| -> Option<&[u8]> {
            pairs
                .iter()
                .find(|(k, _)| k.as_slice() == key)
                .map(|(_, v)| v.as_slice())
        };
        assert_eq!(
            kv(b"summary"),
            Some(&b"Returns the string value of a key."[..])
        );
        assert_eq!(kv(b"since"), Some(&b"1.0.0"[..]));
        assert_eq!(kv(b"complexity"), Some(&b"O(1)"[..]));
        assert_eq!(kv(b"group"), Some(&b"string"[..]));
    }

    fn command_docs_field(command: &[u8], field: &[u8]) -> RespFrame {
        let mut store = Store::new();
        let out = dispatch_argv(
            &[b"COMMAND".to_vec(), b"DOCS".to_vec(), command.to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        let RespFrame::Array(Some(entries)) = out else {
            panic!("expected docs array");
        };
        let RespFrame::Array(Some(doc_fields)) = &entries[1] else {
            panic!("expected doc fields array");
        };
        for chunk in doc_fields.chunks(2) {
            if let [RespFrame::BulkString(Some(k)), value] = chunk
                && k.as_slice() == field
            {
                return value.clone();
            }
        }
        panic!(
            "missing COMMAND DOCS field {:?} for {:?}",
            String::from_utf8_lossy(field),
            String::from_utf8_lossy(command)
        );
    }

    fn docs_arg(fields: Vec<(&str, RespFrame)>) -> RespFrame {
        let mut flat = Vec::with_capacity(fields.len() * 2);
        for (key, value) in fields {
            flat.push(hello_bulk(key));
            flat.push(value);
        }
        RespFrame::Array(Some(flat))
    }

    fn docs_flags(flags: &[&str]) -> RespFrame {
        // (frankenredis-vqyem) Mirror upstream addReplyCommandArgList — flag
        // tokens are status replies (SimpleString), not bulk strings.
        RespFrame::Array(Some(flags.iter().map(|flag| hello_simple(flag)).collect()))
    }

    #[test]
    fn command_docs_arguments_for_get_set_lpush_zadd_match_upstream_schema() {
        // (frankenredis-18wru) Upstream addReplyCommandArgList emits
        // argument metadata as a map-like flat field list in RESP2:
        // name, type, display_text for scalar args, key_spec_index for
        // keys, flags arrays for optional/multiple markers, and nested
        // arguments for oneof/block nodes. The old arity-derived docs
        // only emitted name/type plus a non-upstream optional integer.
        let get_args = command_docs_field(b"GET", b"arguments");
        assert_eq!(
            get_args,
            RespFrame::Array(Some(vec![docs_arg(vec![
                ("name", hello_bulk("key")),
                ("type", hello_bulk("key")),
                ("display_text", hello_bulk("key")),
                ("key_spec_index", RespFrame::Integer(0)),
            ])]))
        );

        let lpush_args = command_docs_field(b"LPUSH", b"arguments");
        assert_eq!(
            lpush_args,
            RespFrame::Array(Some(vec![
                docs_arg(vec![
                    ("name", hello_bulk("key")),
                    ("type", hello_bulk("key")),
                    ("display_text", hello_bulk("key")),
                    ("key_spec_index", RespFrame::Integer(0)),
                ]),
                docs_arg(vec![
                    ("name", hello_bulk("element")),
                    ("type", hello_bulk("string")),
                    ("display_text", hello_bulk("element")),
                    ("flags", docs_flags(&["multiple"])),
                ]),
            ]))
        );

        let set_args = command_docs_field(b"SET", b"arguments");
        let RespFrame::Array(Some(set_items)) = set_args else {
            panic!("SET arguments must be an array");
        };
        assert_eq!(set_items.len(), 5);
        assert_eq!(
            set_items[2],
            docs_arg(vec![
                ("name", hello_bulk("condition")),
                ("type", hello_bulk("oneof")),
                ("since", hello_bulk("2.6.12")),
                ("flags", docs_flags(&["optional"])),
                (
                    "arguments",
                    RespFrame::Array(Some(vec![
                        docs_arg(vec![
                            ("name", hello_bulk("nx")),
                            ("type", hello_bulk("pure-token")),
                            ("display_text", hello_bulk("nx")),
                            ("token", hello_bulk("NX")),
                        ]),
                        docs_arg(vec![
                            ("name", hello_bulk("xx")),
                            ("type", hello_bulk("pure-token")),
                            ("display_text", hello_bulk("xx")),
                            ("token", hello_bulk("XX")),
                        ]),
                    ])),
                ),
            ])
        );
        assert_eq!(
            set_items[3],
            docs_arg(vec![
                ("name", hello_bulk("get")),
                ("type", hello_bulk("pure-token")),
                ("display_text", hello_bulk("get")),
                ("token", hello_bulk("GET")),
                ("since", hello_bulk("6.2.0")),
                ("flags", docs_flags(&["optional"])),
            ])
        );

        let zadd_group = command_docs_field(b"ZADD", b"group");
        assert_eq!(zadd_group, hello_bulk("sorted-set"));
        let zadd_args = command_docs_field(b"ZADD", b"arguments");
        let RespFrame::Array(Some(zadd_items)) = zadd_args else {
            panic!("ZADD arguments must be an array");
        };
        assert_eq!(zadd_items.len(), 6);
        assert_eq!(
            zadd_items[5],
            docs_arg(vec![
                ("name", hello_bulk("data")),
                ("type", hello_bulk("block")),
                ("flags", docs_flags(&["multiple"])),
                (
                    "arguments",
                    RespFrame::Array(Some(vec![
                        docs_arg(vec![
                            ("name", hello_bulk("score")),
                            ("type", hello_bulk("double")),
                            ("display_text", hello_bulk("score")),
                        ]),
                        docs_arg(vec![
                            ("name", hello_bulk("member")),
                            ("type", hello_bulk("string")),
                            ("display_text", hello_bulk("member")),
                        ]),
                    ])),
                ),
            ])
        );
    }

    #[test]
    fn zpopmin_count_parse_failure_matches_upstream_must_be_positive_wording() {
        // Pins frankenredis-zpopminword. Upstream t_zset.c::genericZpopCommand
        // uses getRangeLongFromObjectOrReply with the unified message
        // "value is out of range, must be positive" — so non-numeric
        // count, negative count, and out-of-range count all surface the
        // same wording. fr's ZPOPMIN was using parse_i64_arg directly
        // and emitting the generic 'value is not an integer or out of
        // range' for non-numeric input, while ZPOPMAX (which already
        // routed through parse_zpop_count) had the right wording.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        let expected = "value is out of range, must be positive";

        // Non-numeric count.
        let err = dispatch_argv(
            &[b"ZPOPMIN".to_vec(), b"z".to_vec(), b"abc".to_vec()],
            &mut store,
            0,
        )
        .expect_err("non-numeric count should error");
        let resp = err.to_resp();
        let RespFrame::Error(s) = &resp else {
            panic!("expected error frame, got {resp:?}")
        };
        assert!(s.contains(expected), "got {s}");

        // Negative count.
        let err = dispatch_argv(
            &[b"ZPOPMIN".to_vec(), b"z".to_vec(), b"-1".to_vec()],
            &mut store,
            0,
        )
        .expect_err("negative count should error");
        let resp = err.to_resp();
        let RespFrame::Error(s) = &resp else {
            panic!("expected error frame, got {resp:?}")
        };
        assert!(s.contains(expected), "got {s}");

        // Float / mixed input.
        let err = dispatch_argv(
            &[b"ZPOPMIN".to_vec(), b"z".to_vec(), b"1.5".to_vec()],
            &mut store,
            0,
        )
        .expect_err("float count should error");
        let resp = err.to_resp();
        let RespFrame::Error(s) = &resp else {
            panic!("expected error frame, got {resp:?}")
        };
        assert!(s.contains(expected), "got {s}");

        // ZPOPMAX still surfaces the same wording (no regression).
        let err = dispatch_argv(
            &[b"ZPOPMAX".to_vec(), b"z".to_vec(), b"abc".to_vec()],
            &mut store,
            0,
        )
        .expect_err("non-numeric count should error");
        let resp = err.to_resp();
        let RespFrame::Error(s) = &resp else {
            panic!("expected error frame, got {resp:?}")
        };
        assert!(s.contains(expected), "got {s}");

        // Valid count (regression: positive count still works).
        let frame = dispatch_argv(
            &[b"ZPOPMIN".to_vec(), b"z".to_vec(), b"1".to_vec()],
            &mut store,
            0,
        )
        .expect("positive count should succeed");
        let RespFrame::Array(Some(items)) = frame else {
            panic!("expected array");
        };
        assert_eq!(items.len(), 2, "popped (member, score) pair");

        // Count 0 still returns empty array (special case in ZPOPMIN).
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"2".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let frame = dispatch_argv(
            &[b"ZPOPMIN".to_vec(), b"z".to_vec(), b"0".to_vec()],
            &mut store,
            0,
        )
        .expect("count 0 should succeed");
        assert_eq!(frame, RespFrame::Array(Some(Vec::new())));
    }

    #[test]
    fn zpopmin_zpopmax_too_many_args_return_syntax_error_bexnm() {
        // (frankenredis-bexnm) Upstream t_zset.c:4029 — when
        // `c->argc > 3` the shared `zpopMinMaxCommand` handler emits
        // `shared.syntaxerr` ("ERR syntax error"), NOT the generic
        // arity error. fr previously rejected too-many args via the
        // dispatcher's `argv.len() > 3` check, which surfaced the
        // generic 'wrong number of arguments' wording.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
                b"2".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        // Both ZPOPMIN and ZPOPMAX with 4 args -> "ERR syntax error".
        for cmd in [b"ZPOPMIN".to_vec(), b"ZPOPMAX".to_vec()] {
            let err = dispatch_argv(
                &[cmd.clone(), b"z".to_vec(), b"1".to_vec(), b"extra".to_vec()],
                &mut store,
                0,
            )
            .expect_err("4-arg call should error");
            let resp = err.to_resp();
            let RespFrame::Error(s) = &resp else {
                panic!("expected error frame, got {resp:?}");
            };
            assert_eq!(
                s,
                "ERR syntax error",
                "{} 4 args expected syntax error",
                std::str::from_utf8(&cmd).unwrap(),
            );

            // 5 args (4-arg case extended) -> still "ERR syntax error".
            let err = dispatch_argv(
                &[
                    cmd.clone(),
                    b"z".to_vec(),
                    b"1".to_vec(),
                    b"e1".to_vec(),
                    b"e2".to_vec(),
                ],
                &mut store,
                0,
            )
            .expect_err("5-arg call should error");
            let resp = err.to_resp();
            let RespFrame::Error(s) = &resp else {
                panic!("expected error frame, got {resp:?}");
            };
            assert_eq!(
                s,
                "ERR syntax error",
                "{} 5 args expected syntax error",
                std::str::from_utf8(&cmd).unwrap(),
            );

            // 1 arg (too few) is still WrongArity — different code path.
            let err = dispatch_argv(std::slice::from_ref(&cmd), &mut store, 0)
                .expect_err("1-arg call should error (arity)");
            let resp = err.to_resp();
            let RespFrame::Error(s) = &resp else {
                panic!("expected error frame, got {resp:?}");
            };
            assert!(
                s.contains("wrong number of arguments"),
                "{} with no args expected arity error, got {s}",
                std::str::from_utf8(&cmd).unwrap(),
            );
        }
    }

    #[test]
    fn command_getkeys_for_migrate_handles_single_and_multi_key_forms() {
        // Pins frankenredis-migratekeyspec. Upstream's commands/migrate.json
        // declares two key specs for MIGRATE: a positional spec at
        // argv[3] (single-key form) and a keyword-anchored 'KEYS' spec
        // for the multi-key form. fr's COMMAND_TABLE entry uses
        // first/last/step = 0/0/0 (no positional keys), so without an
        // explicit handler in command_key_indexes both forms returned
        // 'ERR The command has no key arguments' from COMMAND GETKEYS.
        let mut store = Store::new();

        // Single-key form: argv[3] = "mykey" (non-empty).
        let out = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYS".to_vec(),
                b"MIGRATE".to_vec(),
                b"host".to_vec(),
                b"port".to_vec(),
                b"mykey".to_vec(),
                b"0".to_vec(),
                b"5000".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("COMMAND GETKEYS MIGRATE single-key");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"mykey".to_vec()))]))
        );

        // Multi-key form: argv[3] = "" sentinel + KEYS tail.
        let out = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYS".to_vec(),
                b"MIGRATE".to_vec(),
                b"host".to_vec(),
                b"port".to_vec(),
                b"".to_vec(),
                b"0".to_vec(),
                b"5000".to_vec(),
                b"KEYS".to_vec(),
                b"k1".to_vec(),
                b"k2".to_vec(),
                b"k3".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("COMMAND GETKEYS MIGRATE multi-key");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"k1".to_vec())),
                RespFrame::BulkString(Some(b"k2".to_vec())),
                RespFrame::BulkString(Some(b"k3".to_vec())),
            ]))
        );

        // (frankenredis-6fnjb) With BOTH a non-empty positional key
        // AND a KEYS tail, vendored's keyspec validation rejects with
        // 'Invalid arguments specified for command'. The previous
        // expectation here mistakenly accepted both keys; live
        // differential probe vs 7.2.4 confirmed the error wording.
        let out = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYS".to_vec(),
                b"MIGRATE".to_vec(),
                b"host".to_vec(),
                b"port".to_vec(),
                b"first".to_vec(),
                b"0".to_vec(),
                b"5000".to_vec(),
                b"KEYS".to_vec(),
                b"second".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("MIGRATE single + KEYS form returns error frame");
        assert_eq!(
            out,
            RespFrame::Error("ERR Invalid arguments specified for command".to_string())
        );

        // With AUTH / COPY / REPLACE options between key and KEYS, the
        // KEYS sentinel still gets located.
        let out = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYS".to_vec(),
                b"MIGRATE".to_vec(),
                b"host".to_vec(),
                b"port".to_vec(),
                b"".to_vec(),
                b"0".to_vec(),
                b"5000".to_vec(),
                b"COPY".to_vec(),
                b"REPLACE".to_vec(),
                b"AUTH".to_vec(),
                b"password".to_vec(),
                b"KEYS".to_vec(),
                b"only".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("MIGRATE COPY REPLACE AUTH ... KEYS");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![RespFrame::BulkString(Some(b"only".to_vec()))]))
        );

        // Too few args (under arity-6 minimum) → empty key list (caller
        // surfaces 'no key arguments' / arity error envelope).
        let out = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYS".to_vec(),
                b"MIGRATE".to_vec(),
                b"h".to_vec(),
                b"p".to_vec(),
            ],
            &mut store,
            0,
        );
        // Upstream emits InvalidNumberOfArguments wording here; the
        // downstream command-handling layer transforms our empty-vec
        // return into either that or NoKeyArguments depending on the
        // arity check. Just assert it doesn't crash and surfaces an
        // error.
        assert!(matches!(out, Ok(RespFrame::Error(_)) | Err(_)));
    }

    /// (frankenredis-hila4) Mirror upstream commands.def XREAD_Keyspecs
    /// (line 9780): begin_search KEYWORD "STREAMS", find_keys RANGE
    /// lastkey=-1 keystep=1 limit=2. The limit=2 means num_keys =
    /// remaining_args / 2 (integer division), so XREAD COUNT 5 STREAMS
    /// s 0 EXTRA returns ["s"] even with the odd trailing tail.
    /// Pre-fix, fr enforced an even-tail check and rejected with
    /// "Invalid arguments specified for command".
    #[test]
    fn command_getkeys_xread_uses_keyspec_integer_division_for_odd_tails_per_upstream() {
        let mut store = Store::new();

        type GetKeysCase = (Vec<&'static [u8]>, Vec<&'static [u8]>);
        let cases: Vec<GetKeysCase> = vec![
            // (input argv after COMMAND GETKEYS, expected key list)
            (vec![b"XREAD", b"STREAMS", b"s", b"0"], vec![b"s"]),
            (vec![b"XREAD", b"STREAMS", b"s", b"0", b"EXTRA"], vec![b"s"]),
            (
                vec![b"XREAD", b"STREAMS", b"s", b"a", b"0", b"1"],
                vec![b"s", b"a"],
            ),
            (
                vec![b"XREAD", b"STREAMS", b"s", b"a", b"0", b"EXTRA"],
                vec![b"s", b"a"],
            ),
            (
                vec![b"XREAD", b"COUNT", b"5", b"STREAMS", b"s", b"0", b"EXTRA"],
                vec![b"s"],
            ),
            (
                vec![
                    b"XREADGROUP",
                    b"GROUP",
                    b"g",
                    b"c",
                    b"STREAMS",
                    b"s",
                    b"0",
                    b"EXTRA",
                ],
                vec![b"s"],
            ),
        ];
        for (input, expected) in &cases {
            let mut argv: Vec<Vec<u8>> = vec![b"COMMAND".to_vec(), b"GETKEYS".to_vec()];
            for arg in input.iter() {
                argv.push(arg.to_vec());
            }
            let out = dispatch_argv(&argv, &mut store, 0).unwrap_or_else(|e| {
                panic!("expected COMMAND GETKEYS reply for {input:?}, got err: {e:?}")
            });
            let RespFrame::Array(Some(keys)) = out else {
                panic!("expected Array reply for {input:?}, got {out:?}");
            };
            let key_bytes: Vec<&[u8]> = keys
                .iter()
                .filter_map(|f| match f {
                    RespFrame::BulkString(Some(b)) => Some(b.as_slice()),
                    _ => None,
                })
                .collect();
            assert_eq!(
                key_bytes,
                expected.as_slice(),
                "COMMAND GETKEYS {input:?} key list mismatch"
            );
        }
    }

    #[test]
    fn command_getkeys_no_key_commands_report_no_keys_before_arity() {
        // Pins frankenredis-getkeysorder. Upstream getKeysFromCommandWithSpecs
        // (commands.def) inspects the command's key spec count first, so
        // commands with zero key specs (PUBLISH, SUBSCRIBE, WAIT, ...) report
        // "no key arguments" regardless of whether the trailing argv would
        // satisfy the wrapped command's own arity. fr previously evaluated
        // arity first, so under-arity calls of no-key commands surfaced
        // "Invalid number of arguments specified for command" instead.
        let mut store = Store::new();
        let probes: &[&[&[u8]]] = &[
            &[b"COMMAND", b"GETKEYS", b"PUBLISH"],
            &[b"COMMAND", b"GETKEYS", b"SUBSCRIBE"],
            &[b"COMMAND", b"GETKEYS", b"UNSUBSCRIBE"],
            &[b"COMMAND", b"GETKEYS", b"WAIT"],
            &[b"COMMAND", b"GETKEYS", b"PING"],
            &[b"COMMAND", b"GETKEYSANDFLAGS", b"PUBLISH"],
            &[b"COMMAND", b"GETKEYSANDFLAGS", b"WAIT"],
        ];
        for argv in probes {
            let owned: Vec<Vec<u8>> = argv.iter().map(|a| a.to_vec()).collect();
            let frame = dispatch_argv(&owned, &mut store, 0).expect("dispatch");
            match frame {
                RespFrame::Error(msg) => assert_eq!(
                    msg, "ERR The command has no key arguments",
                    "unexpected error wording for {:?}",
                    argv,
                ),
                other => panic!("expected error frame for {:?}, got {:?}", argv, other),
            }
        }

        // Sanity: a no-key command with extra (irrelevant) argv still reports
        // "no key arguments" — the order swap must not regress the case where
        // arity *does* pass.
        let frame = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYS".to_vec(),
                b"PUBLISH".to_vec(),
                b"channel".to_vec(),
                b"msg".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("PUBLISH full-arity");
        assert_eq!(
            frame,
            RespFrame::Error("ERR The command has no key arguments".to_string()),
        );

        // Sanity: a *keyed* command with under-arity still surfaces the arity
        // wording (vendored: "Invalid number of arguments specified for
        // command"). The swap only affects no-key commands.
        let frame = dispatch_argv(
            &[b"COMMAND".to_vec(), b"GETKEYS".to_vec(), b"SET".to_vec()],
            &mut store,
            0,
        )
        .expect("SET under-arity");
        assert_eq!(
            frame,
            RespFrame::Error("ERR Invalid number of arguments specified for command".to_string()),
        );
    }

    #[test]
    fn command_getkeysandflags_georadius_store_uses_per_keyspec_flags() {
        // (frankenredis-georadius-getkeysflags) Upstream geo.c declares two
        // key specs for GEORADIUS/GEORADIUSBYMEMBER: the source key is
        // RO/access and the optional STORE/STOREDIST destination is OW/update.
        // fr previously fell through to the generic write-command flag set,
        // tagging BOTH keys RW/access/update. Verified byte-exact vs
        // vendored 7.2.4.
        let mut store = Store::new();
        let ro_access = RespFrame::Array(Some(vec![
            RespFrame::SimpleString("RO".into()),
            RespFrame::SimpleString("access".into()),
        ]));
        let ow_update = RespFrame::Array(Some(vec![
            RespFrame::SimpleString("OW".into()),
            RespFrame::SimpleString("update".into()),
        ]));
        for verb in [b"GEORADIUS".as_slice(), b"GEORADIUSBYMEMBER"] {
            // STORE form: src RO/access, dst OW/update.
            let argv: Vec<Vec<u8>> = [
                b"COMMAND".as_slice(),
                b"GETKEYSANDFLAGS",
                verb,
                b"src",
                b"0",
                b"0",
                b"1",
                b"m",
                b"STORE",
                b"dst",
            ]
            .iter()
            .map(|a| a.to_vec())
            .collect();
            let frame = dispatch_argv(&argv, &mut store, 0).expect("getkeysandflags store");
            let RespFrame::Array(Some(refs)) = frame else {
                panic!("expected array, got {frame:?}"); // ubs:ignore — AI triage
            };
            assert_eq!(refs.len(), 2, "{verb:?} STORE should report 2 keys");
            let RespFrame::Array(Some(src)) = &refs[0] else {
                panic!("src ref shape"); // ubs:ignore — AI triage
            };
            assert_eq!(src[1], ro_access, "{verb:?} source must be RO/access");
            let RespFrame::Array(Some(dst)) = &refs[1] else {
                panic!("dst ref shape"); // ubs:ignore — AI triage
            };
            assert_eq!(dst[1], ow_update, "{verb:?} STORE dst must be OW/update");
        }
    }

    #[test]
    fn command_getkeysandflags_setrange_xsetid_restore_use_exact_flags() {
        // (frankenredis-vc88p) The generic write-command fallback tagged
        // every key RW/access/update. Upstream commands/*.json key_specs
        // declare SETRANGE/XSETID as RW/update (no access) and RESTORE as
        // OW/update (overwrite). Verified byte-exact vs vendored 7.2.4.
        let mut store = Store::new();
        let cases: &[(&[u8], &[&str])] = &[
            (b"SETRANGE", &["RW", "update"]),
            (b"XSETID", &["RW", "update"]),
            (b"RESTORE", &["OW", "update"]),
        ];
        for (verb, want) in cases {
            let argv: Vec<Vec<u8>> = [
                b"COMMAND".as_slice(),
                b"GETKEYSANDFLAGS",
                verb,
                b"k",
                b"0",
                b"x",
            ]
            .iter()
            .map(|a| a.to_vec())
            .collect();
            let frame = dispatch_argv(&argv, &mut store, 0).expect("getkeysandflags");
            let RespFrame::Array(Some(refs)) = frame else {
                panic!("expected array for {verb:?}"); // ubs:ignore — AI triage
            };
            let RespFrame::Array(Some(entry)) = &refs[0] else {
                panic!("entry shape for {verb:?}"); // ubs:ignore — AI triage
            };
            let want_frame = RespFrame::Array(Some(
                want.iter()
                    .map(|f| RespFrame::SimpleString((*f).to_string()))
                    .collect(),
            ));
            assert_eq!(entry[1], want_frame, "{verb:?} flags mismatch");
        }
    }

