        let keyspace = commands_in_acl_category("keyspace");
        assert!(keyspace.contains(&"object|encoding"));
        assert!(keyspace.contains(&"restore-asking"));

        let admin = commands_in_acl_category("admin");
        assert!(admin.contains(&"config|set"));
