    // (frankenredis-btf8o) COMMAND GETKEYSANDFLAGS EVAL previously fell
    // through to the generic derived_flags path, whose flags string for
    // `eval` ("noscript stale skip_monitor no_mandatory_keys movablekeys")
    // contains neither `readonly` nor `write` — so each key wrongly
    // surfaced just &["access"]. Pin upstream's keyspec taxonomy:
    // EVAL/EVALSHA/FCALL → RW|access|update; EVAL_RO/EVALSHA_RO/FCALL_RO
    // → RO|access. Pin both 1-key and 2-key shapes plus the _RO variant.
    #[test]
    fn command_getkeysandflags_eval_emits_rw_access_update_per_key_btf8o() {
        let mut store = Store::new();

        let two_keys = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"EVAL".to_vec(),
                b"return 1".to_vec(),
                b"2".to_vec(),
                b"k1".to_vec(),
                b"k2".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        let key_block = |name: &[u8]| {
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(name.to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::SimpleString("RW".to_string()),
                    RespFrame::SimpleString("access".to_string()),
                    RespFrame::SimpleString("update".to_string()),
                ])),
            ]))
        };
        assert_eq!(
            two_keys,
            RespFrame::Array(Some(vec![key_block(b"k1"), key_block(b"k2")]))
        );

        let evalsha_one_key = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"EVALSHA".to_vec(),
                b"deadbeef".to_vec(),
                b"1".to_vec(),
                b"only".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            evalsha_one_key,
            RespFrame::Array(Some(vec![key_block(b"only")]))
        );

        let eval_ro_one_key = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"EVAL_RO".to_vec(),
                b"return 1".to_vec(),
                b"1".to_vec(),
                b"ro_key".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            eval_ro_one_key,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"ro_key".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::SimpleString("RO".to_string()),
                    RespFrame::SimpleString("access".to_string()),
                ])),
            ]))]))
        );

        let fcall_two_keys = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"FCALL".to_vec(),
                b"myfn".to_vec(),
                b"2".to_vec(),
                b"k1".to_vec(),
                b"k2".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            fcall_two_keys,
            RespFrame::Array(Some(vec![key_block(b"k1"), key_block(b"k2")]))
        );
    }

    // (frankenredis-bkk3h) GETKEYSANDFLAGS for store-style and in-place
    // mutate commands previously fell through to the generic derived_flags
    // path which always emitted [RW, access, update]. Pin the upstream
    // keyspec flag taxonomy per commands/<cmd>.json.
    #[test]
    fn command_getkeysandflags_store_and_mutate_match_upstream_keyspecs_bkk3h() {
        let mut store = Store::new();
        let key_block = |name: &[u8], flags: &[&str]| {
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(name.to_vec())),
                RespFrame::Array(Some(
                    flags
                        .iter()
                        .map(|flag| RespFrame::SimpleString((*flag).to_string()))
                        .collect(),
                )),
            ]))
        };

        // ZINTERSTORE dst 2 a b: dst=OW|update, a/b=RO|access
        let zis = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"ZINTERSTORE".to_vec(),
                b"dst".to_vec(),
                b"2".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            zis,
            RespFrame::Array(Some(vec![
                key_block(b"dst", &["OW", "update"]),
                key_block(b"a", &["RO", "access"]),
                key_block(b"b", &["RO", "access"]),
            ]))
        );

        // SINTERSTORE dst a b: dst=RW|update (NOT OW), srcs=RO|access
        let sis = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"SINTERSTORE".to_vec(),
                b"dst".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            sis,
            RespFrame::Array(Some(vec![
                key_block(b"dst", &["RW", "update"]),
                key_block(b"a", &["RO", "access"]),
                key_block(b"b", &["RO", "access"]),
            ]))
        );

        // SUNIONSTORE dst a b: dst=OW|update, srcs=RO|access
        let sus = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"SUNIONSTORE".to_vec(),
                b"dst".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            sus,
            RespFrame::Array(Some(vec![
                key_block(b"dst", &["OW", "update"]),
                key_block(b"a", &["RO", "access"]),
                key_block(b"b", &["RO", "access"]),
            ]))
        );

        // GEOSEARCHSTORE dst src ...: dst=OW|update, src=RO|access
        let gss = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"GEOSEARCHSTORE".to_vec(),
                b"dst".to_vec(),
                b"src".to_vec(),
                b"FROMMEMBER".to_vec(),
                b"m".to_vec(),
                b"BYRADIUS".to_vec(),
                b"5".to_vec(),
                b"km".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            gss,
            RespFrame::Array(Some(vec![
                key_block(b"dst", &["OW", "update"]),
                key_block(b"src", &["RO", "access"]),
            ]))
        );

        // ZRANGESTORE dst src 0 -1: dst=OW|update, src=RO|access
        let zrs = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"ZRANGESTORE".to_vec(),
                b"dst".to_vec(),
                b"src".to_vec(),
                b"0".to_vec(),
                b"-1".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            zrs,
            RespFrame::Array(Some(vec![
                key_block(b"dst", &["OW", "update"]),
                key_block(b"src", &["RO", "access"]),
            ]))
        );

        // SMOVE src dst m: src=RW|access|delete, dst=RW|insert
        let smv = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"SMOVE".to_vec(),
                b"src".to_vec(),
                b"dst".to_vec(),
                b"m".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            smv,
            RespFrame::Array(Some(vec![
                key_block(b"src", &["RW", "access", "delete"]),
                key_block(b"dst", &["RW", "insert"]),
            ]))
        );

        // LSET key i v: RW|update
        let lset = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"LSET".to_vec(),
                b"l".to_vec(),
                b"0".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            lset,
            RespFrame::Array(Some(vec![key_block(b"l", &["RW", "update"])]))
        );

        // LTRIM key 0 10: RW|delete
        let ltrim = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"LTRIM".to_vec(),
                b"l".to_vec(),
                b"0".to_vec(),
                b"10".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            ltrim,
            RespFrame::Array(Some(vec![key_block(b"l", &["RW", "delete"])]))
        );

        // LINSERT key BEFORE a v: RW|insert
        let lins = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"LINSERT".to_vec(),
                b"l".to_vec(),
                b"BEFORE".to_vec(),
                b"a".to_vec(),
                b"v".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            lins,
            RespFrame::Array(Some(vec![key_block(b"l", &["RW", "insert"])]))
        );

        // PFMERGE dst a b: dst=RW|access|insert, srcs=RO|access
        let pfm = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"PFMERGE".to_vec(),
                b"dst".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            pfm,
            RespFrame::Array(Some(vec![
                key_block(b"dst", &["RW", "access", "insert"]),
                key_block(b"a", &["RO", "access"]),
                key_block(b"b", &["RO", "access"]),
            ]))
        );
    }

    // (frankenredis-flfef) SSUBSCRIBE/SUNSUBSCRIBE/SPUBLISH declare a
    // NOT_KEY key_spec upstream; commandHasKeys() returns false because
    // the positional arg is a shard channel, not a keyspace key. fr's
    // COMMAND_TABLE keeps first_key=1 (so COMMAND INFO still reports the
    // keyspec) and command_has_keys() now special-cases these three.
    // Pin both GETKEYS and GETKEYSANDFLAGS, plus SPUBLISH's normal
    // arity-3 form.
    #[test]
    fn command_getkeys_for_shard_pubsub_reports_no_key_arguments_flfef() {
        let mut store = Store::new();
        let no_keys_err = RespFrame::Error("ERR The command has no key arguments".to_string());

        for argv in [
            vec![
                b"COMMAND".to_vec(),
                b"GETKEYS".to_vec(),
                b"SPUBLISH".to_vec(),
                b"ch".to_vec(),
                b"msg".to_vec(),
            ],
            vec![
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"SPUBLISH".to_vec(),
                b"ch".to_vec(),
                b"msg".to_vec(),
            ],
            vec![
                b"COMMAND".to_vec(),
                b"GETKEYS".to_vec(),
                b"SSUBSCRIBE".to_vec(),
                b"ch".to_vec(),
            ],
            vec![
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"SSUBSCRIBE".to_vec(),
                b"ch".to_vec(),
            ],
            vec![
                b"COMMAND".to_vec(),
                b"GETKEYS".to_vec(),
                b"SUNSUBSCRIBE".to_vec(),
                b"ch".to_vec(),
            ],
            vec![
                b"COMMAND".to_vec(),
                b"GETKEYSANDFLAGS".to_vec(),
                b"SUNSUBSCRIBE".to_vec(),
                b"ch".to_vec(),
            ],
        ] {
            let out = dispatch_argv(&argv, &mut store, 0).unwrap();
            assert_eq!(out, no_keys_err, "argv={:?}", argv);
        }
    }

