    #[test]
    fn set_pxat_absolute_expiry() {
        let mut store = Store::new();
        let now = 1000;
        // SET key value PXAT 5000 — absolute expiry at 5000ms
        let out = dispatch_argv(
            &[
                b"SET".to_vec(),
                b"k".to_vec(),
                b"v".to_vec(),
                b"PXAT".to_vec(),
                b"5000".to_vec(),
            ],
            &mut store,
            now,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        // Key should exist at now=4999
        assert_eq!(store.get(b"k", 4999).unwrap(), Some(b"v".to_vec()));
        // Still alive at EXACTLY the deadline: upstream expires on `now > when`,
        // not `now >= when` (db.c keyIsExpired), so 5000 == deadline is alive.
        // (frankenredis-bwbrb, see project_expiry_boundary_semantics / dc37c1d17)
        assert_eq!(store.get(b"k", 5000).unwrap(), Some(b"v".to_vec()));
        // Expired one millisecond past the deadline.
        assert_eq!(store.get(b"k", 5001).unwrap(), None);
    }

    #[test]
    fn set_exat_absolute_expiry() {
        let mut store = Store::new();
        let now = 1000;
        // SET key value EXAT 10 — absolute expiry at 10s = 10000ms
        let out = dispatch_argv(
            &[
                b"SET".to_vec(),
                b"k".to_vec(),
                b"v".to_vec(),
                b"EXAT".to_vec(),
                b"10".to_vec(),
            ],
            &mut store,
            now,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        // Key should exist at now=9999
        assert_eq!(store.get(b"k", 9999).unwrap(), Some(b"v".to_vec()));
        // Alive at EXACTLY the deadline (upstream expires on `now > when`).
        // (frankenredis-bwbrb, see project_expiry_boundary_semantics / dc37c1d17)
        assert_eq!(store.get(b"k", 10000).unwrap(), Some(b"v".to_vec()));
        // Expired one millisecond past the deadline.
        assert_eq!(store.get(b"k", 10001).unwrap(), None);
    }

    #[test]
    fn set_keepttl_preserves_existing_expiry() {
        let mut store = Store::new();
        let now = 1000;
        // SET key value PX 4000 — expires at now+4000 = 5000
        dispatch_argv(
            &[
                b"SET".to_vec(),
                b"k".to_vec(),
                b"v1".to_vec(),
                b"PX".to_vec(),
                b"4000".to_vec(),
            ],
            &mut store,
            now,
        )
        .unwrap();
        // SET key newvalue KEEPTTL — should keep expiry at 5000
        let out = dispatch_argv(
            &[
                b"SET".to_vec(),
                b"k".to_vec(),
                b"v2".to_vec(),
                b"KEEPTTL".to_vec(),
            ],
            &mut store,
            now,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));
        // Value should be updated
        assert_eq!(store.get(b"k", now).unwrap(), Some(b"v2".to_vec()));
        // Original TTL should be preserved — still alive at 4999
        assert_eq!(store.get(b"k", 4999).unwrap(), Some(b"v2".to_vec()));
        // Alive at EXACTLY the preserved deadline (upstream expires on `now > when`).
        // (frankenredis-bwbrb, see project_expiry_boundary_semantics / dc37c1d17)
        assert_eq!(store.get(b"k", 5000).unwrap(), Some(b"v2".to_vec()));
        // Expired one millisecond past the deadline.
        assert_eq!(store.get(b"k", 5001).unwrap(), None);
    }

    #[test]
    fn set_keepttl_no_prior_ttl() {
        let mut store = Store::new();
        // SET key value (no TTL)
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v1".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        // SET key newvalue KEEPTTL — no prior TTL, so no expiry
        dispatch_argv(
            &[
                b"SET".to_vec(),
                b"k".to_vec(),
                b"v2".to_vec(),
                b"KEEPTTL".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        // Should still exist far in the future
        assert_eq!(store.get(b"k", 999_999_999).unwrap(), Some(b"v2".to_vec()));
    }

