    #[test]
    fn client_tracking_rejected_from_scripts_after_arity_check() {
        // (frankenredis-ym2iw) Upstream commands.def line 1554 marks
        // CLIENT TRACKING with CMD_NOSCRIPT. Arity wins over noscript;
        // noscript wins over mode/option-matrix validation.
        let mut store = Store::new();
        store.script_nesting_level = 1;
        let before = store.dispatch_client_ctx.client_tracking.clone();

        let arity = dispatch_argv(&[b"CLIENT".to_vec(), b"TRACKING".to_vec()], &mut store, 0)
            .expect_err("client tracking arity");
        assert_eq!(arity, client_wrong_subcommand_arity("TRACKING"));

        // Every arity-correct scripted call — valid mode, invalid
        // mode, and option-matrix violations — surfaces the noscript
        // reply.
        for argv in [
            vec![b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"ON".to_vec()],
            vec![b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"OFF".to_vec()],
            vec![b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"MAYBE".to_vec()],
            vec![
                b"CLIENT".to_vec(),
                b"TRACKING".to_vec(),
                b"ON".to_vec(),
                b"PREFIX".to_vec(),
                b"foo".to_vec(),
            ],
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("client tracking noscript");
            assert_eq!(
                err,
                CommandError::Custom(SCRIPT_NOSCRIPT_ERROR.to_string()),
                "argv: {argv:?}"
            );
            assert_eq!(store.dispatch_client_ctx.client_tracking, before);
        }
    }

    #[test]
    fn client_tracking_validates_option_matrix() {
        let mut store = Store::new();
        for (argv, expected) in [
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"PREFIX".to_vec(),
                    b"foo".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_PREFIX_REQUIRES_BCAST.to_string()),
            ),
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"OPTIN".to_vec(),
                    b"OPTOUT".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_OPTIN_OPTOUT_CONFLICT.to_string()),
            ),
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"BCAST".to_vec(),
                    b"OPTIN".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_BCAST_OPT_CONFLICT.to_string()),
            ),
            // (frankenredis-60k1) BCAST + OPTIN + OPTOUT all set:
            // upstream networking.c::clientCommand checks the BCAST
            // conflict before the OPTIN/OPTOUT mutual-exclusion, so
            // user-visible error must be BCAST_OPT_CONFLICT.
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"BCAST".to_vec(),
                    b"OPTIN".to_vec(),
                    b"OPTOUT".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_BCAST_OPT_CONFLICT.to_string()),
            ),
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"BCAST".to_vec(),
                    b"OPTOUT".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_BCAST_OPT_CONFLICT.to_string()),
            ),
            (
                vec![
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"REDIRECT".to_vec(),
                    b"0".to_vec(),
                ],
                CommandError::Custom(CLIENT_TRACKING_REDIRECT_MISSING.to_string()),
            ),
        ] {
            let err = dispatch_argv(&argv, &mut store, 0).unwrap_err();
            assert_eq!(err, expected);
        }
    }

    #[test]
    fn client_caching_invalid_opt_with_tracking_disabled_uses_tracking_mode_error() {
        // (frankenredis-cacheorder) Upstream networking.c:3415-3441
        // checks the tracking-enabled gate BEFORE parsing YES|NO, so
        // `CLIENT CACHING BOGUS` against a non-tracking client surfaces
        // the dedicated 'tracking mode with OPTIN or OPTOUT' wording —
        // not 'syntax error'. Probe vs vendored 7.2.4 confirmed for
        // BOGUS / YES / NO / lowercase / mixed-case opts.
        let mut store = Store::new();
        for opt in [
            b"BOGUS".as_slice(),
            b"YES".as_slice(),
            b"NO".as_slice(),
            b"yes".as_slice(),
        ] {
            let err = dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), opt.to_vec()],
                &mut store,
                0,
            )
            .expect_err("client caching tracking-disabled");
            assert_eq!(
                err,
                CommandError::Custom(
                    "ERR CLIENT CACHING can be called only when the client is in tracking mode with OPTIN or OPTOUT mode enabled".to_string()
                ),
                "opt={:?}",
                std::str::from_utf8(opt).unwrap_or("<bin>")
            );
        }
        // Once tracking is enabled, an invalid opt surfaces SyntaxError.
        dispatch_argv(
            &[b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"ON".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        let err = dispatch_argv(
            &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"BOGUS".to_vec()],
            &mut store,
            0,
        )
        .expect_err("client caching invalid opt with tracking enabled");
        assert_eq!(err, CommandError::SyntaxError);
    }

    #[test]
    fn client_caching_requires_optin_or_optout_modes() {
        // Upstream's tracking-disabled branch emits the dedicated
        // 'tracking mode with OPTIN or OPTOUT' wording, then the
        // per-mode reply once tracking is enabled in the wrong mode.
        // (br-frankenredis-cachemode)
        let mut store = Store::new();
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap_err(),
            CommandError::Custom(
                "ERR CLIENT CACHING can be called only when the client is in tracking mode with OPTIN or OPTOUT mode enabled".to_string()
            )
        );
        dispatch_argv(
            &[b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"ON".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_CACHING_YES_REQUIRES_OPTIN.to_string())
        );

        dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"TRACKING".to_vec(),
                b"ON".to_vec(),
                b"OPTIN".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"NO".to_vec()],
                &mut store,
                0
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_CACHING_NO_REQUIRES_OPTOUT.to_string())
        );

        assert_eq!(
            dispatch_argv(
                &[
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"OPTOUT".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_TRACKING_OPT_SWITCH_REQUIRES_DISABLE.to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        dispatch_argv(
            &[b"CLIENT".to_vec(), b"TRACKING".to_vec(), b"OFF".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[
                b"CLIENT".to_vec(),
                b"TRACKING".to_vec(),
                b"ON".to_vec(),
                b"OPTOUT".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"NO".to_vec()],
                &mut store,
                0
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(
                &[b"CLIENT".to_vec(), b"CACHING".to_vec(), b"YES".to_vec()],
                &mut store,
                0
            )
            .unwrap_err(),
            CommandError::Custom(CLIENT_CACHING_YES_REQUIRES_OPTIN.to_string())
        );
    }

    #[test]
    fn client_tracking_redirect_validates_direct_dispatch_target() {
        let mut store = Store::new();
        store.dispatch_client_ctx.client_id = 42;

        assert_eq!(
            dispatch_argv(
                &[
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"ON".to_vec(),
                    b"REDIRECT".to_vec(),
                    b"42".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(&[b"CLIENT".to_vec(), b"GETREDIR".to_vec()], &mut store, 0).unwrap(),
            RespFrame::Integer(42)
        );

        for mode in [b"ON".as_slice(), b"OFF".as_slice()] {
            let err = dispatch_argv(
                &[
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    mode.to_vec(),
                    b"REDIRECT".to_vec(),
                    b"999".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_err();
            assert_eq!(
                err,
                CommandError::Custom(CLIENT_TRACKING_REDIRECT_MISSING.to_string())
            );
        }

        assert_eq!(
            dispatch_argv(
                &[
                    b"CLIENT".to_vec(),
                    b"TRACKING".to_vec(),
                    b"OFF".to_vec(),
                    b"REDIRECT".to_vec(),
                    b"42".to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap(),
            RespFrame::SimpleString("OK".to_string())
        );
        assert_eq!(
            dispatch_argv(&[b"CLIENT".to_vec(), b"GETREDIR".to_vec()], &mut store, 0).unwrap(),
            RespFrame::Integer(-1)
        );
    }

