    #[test]
    fn script_flush_function_dump_function_list_extra_arg_wordings_match_upstream() {
        // Pin three small extra-arg wordings caught by differential
        // probe vs vendored 7.2.4 (frankenredis-hpag):
        //   - SCRIPT FLUSH ASYNC SYNC (argc>3) → "SCRIPT FLUSH only
        //     support SYNC|ASYNC option" (eval.c::scriptCommand)
        //   - FUNCTION DUMP <extra> → table-level WrongSubcommandArity
        //     ("wrong number of arguments for 'function|dump' command")
        //   - FUNCTION LIST <unknown_token> → "Unknown argument <token>"
        //     (functions.c::functionListCommand)
        let mut store = Store::new();

        let script_flush_extra = dispatch_argv(
            &[
                b"SCRIPT".to_vec(),
                b"FLUSH".to_vec(),
                b"ASYNC".to_vec(),
                b"SYNC".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("script flush extra");
        assert_eq!(
            script_flush_extra,
            CommandError::Custom("ERR SCRIPT FLUSH only support SYNC|ASYNC option".to_string())
        );

        let function_dump_extra = dispatch_argv(
            &[b"FUNCTION".to_vec(), b"DUMP".to_vec(), b"extra".to_vec()],
            &mut store,
            0,
        )
        .expect_err("function dump extra");
        assert_eq!(
            function_dump_extra.to_resp(),
            RespFrame::Error(
                "ERR wrong number of arguments for 'function|dump' command".to_string()
            )
        );

        let function_list_bad = dispatch_argv(
            &[b"FUNCTION".to_vec(), b"LIST".to_vec(), b"NOPE".to_vec()],
            &mut store,
            0,
        )
        .expect_err("function list bad");
        assert_eq!(
            function_list_bad,
            CommandError::Custom("ERR Unknown argument NOPE".to_string())
        );
    }

    #[test]
    fn function_load_rejects_unknown_shebang_meta_tokens_like_upstream() {
        // Pin upstream functions.c rejection of unknown meta tokens in
        // the shebang line beyond the engine and `name=...` (frankenredis
        // -fnmeta): 'ERR Invalid metadata value given: <token>'. fr
        // previously silently ignored the extras and loaded the library.
        // Differential probe vs vendored 7.2.4 byte-matched the wording.
        let mut store = Store::new();
        let cases: &[(&[u8], &str)] = &[
            (
                b"#!lua name=lib1 extra_token\nredis.register_function('f',function() return 1 end)",
                "ERR Invalid metadata value given: extra_token",
            ),
            (
                b"#!lua badkey=value name=lib1\nredis.register_function('f',function() return 1 end)",
                "ERR Invalid metadata value given: badkey=value",
            ),
            (
                b"#!lua name=lib1 description=foo\nredis.register_function('f',function() return 1 end)",
                "ERR Invalid metadata value given: description=foo",
            ),
        ];
        for (code, expected) in cases {
            let err = dispatch_argv(
                &[b"FUNCTION".to_vec(), b"LOAD".to_vec(), code.to_vec()],
                &mut store,
                0,
            )
            .expect_err("function load bad meta");
            assert_eq!(
                err.to_resp(),
                RespFrame::Error(expected.to_string()),
                "code={:?}",
                String::from_utf8_lossy(code)
            );
        }

        // Sanity: the canonical engine + name=... combination still loads.
        let ok = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"#!lua name=goodmeta\nredis.register_function('f',function() return 1 end)"
                    .to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("function load valid meta");
        assert_eq!(ok, RespFrame::BulkString(Some(b"goodmeta".to_vec())));
    }

    #[test]
    fn function_load_engine_not_found_preserves_user_casing() {
        // Pin upstream functions.c reporting of the engine token
        // verbatim (frankenredis-fneng): the comparison is
        // case-insensitive (LUA / Lua / lua all accepted) but the
        // 'Engine X not found' wording must echo the user-typed
        // casing. fr previously uppercased the token before formatting.
        // Differential probe vs vendored 7.2.4 captured all four
        // representative cases.
        let mut store = Store::new();
        let cases: &[(&[u8], &str)] = &[
            (
                b"#!python name=lib1\nredis.register_function('f',function() return 1 end)",
                "ERR Engine 'python' not found",
            ),
            (
                b"#!PYTHON name=lib1\nredis.register_function('f',function() return 1 end)",
                "ERR Engine 'PYTHON' not found",
            ),
            (
                b"#!Python name=lib1\nredis.register_function('f',function() return 1 end)",
                "ERR Engine 'Python' not found",
            ),
            (
                b"#!js name=lib1\nredis.register_function('f',function() return 1 end)",
                "ERR Engine 'js' not found",
            ),
        ];
        for (code, expected) in cases {
            let err = dispatch_argv(
                &[b"FUNCTION".to_vec(), b"LOAD".to_vec(), code.to_vec()],
                &mut store,
                0,
            )
            .expect_err("function load bad engine");
            assert_eq!(
                err.to_resp(),
                RespFrame::Error(expected.to_string()),
                "code={:?}",
                String::from_utf8_lossy(code)
            );
        }

        // Sanity: case-insensitive LUA matching still works.
        for shebang in [
            "#!lua name=goodlua",
            "#!LUA name=GOODLUAUPPER",
            "#!Lua name=GoodLuaMixed",
        ] {
            let code = format!("{shebang}\nredis.register_function('f',function() return 1 end)");
            let mut s = Store::new();
            let ok = dispatch_argv(
                &[b"FUNCTION".to_vec(), b"LOAD".to_vec(), code.into_bytes()],
                &mut s,
                0,
            )
            .expect("function load lua");
            assert!(matches!(ok, RespFrame::BulkString(Some(_))));
        }
    }

    #[test]
    fn function_load_unknown_option_and_empty_body_match_upstream() {
        // Pin upstream functions.c rejection paths (frankenredis-fnopt):
        //
        // (1) FUNCTION LOAD <BANANA> <code> — upstream rejects the
        //     unknown option-slot token with 'ERR Unknown option given:
        //     BANANA' before parsing the body. fr previously treated
        //     the first token as code and surfaced 'Missing library
        //     metadata' from the body parser.
        //
        // (2) FUNCTION LOAD '#!lua name=lib\n' (well-formed shebang,
        //     no register_function calls) — upstream rejects with
        //     'ERR No functions registered'. fr previously accepted
        //     the empty-body library and returned the lib name.
        //
        // Differential probe vs vendored 7.2.4 byte-matched both wordings.
        let mut store = Store::new();

        let unknown_option = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"BANANA".to_vec(),
                b"#!lua name=ignored\nredis.register_function('f',function() return 1 end)"
                    .to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("function load bad option");
        assert_eq!(
            unknown_option,
            CommandError::Custom("ERR Unknown option given: BANANA".to_string())
        );

        let empty_body = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"#!lua name=emptylib\n".to_vec(),
            ],
            &mut store,
            0,
        );
        let msg = match empty_body {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected Error, got {other:?}"),
            },
            other => panic!("expected error reply, got {other:?}"),
        };
        assert_eq!(msg, "ERR No functions registered".to_string());

        // Sanity: a properly-formed library still loads.
        let ok = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"#!lua name=goodlib\nredis.register_function('f',function() return 1 end)"
                    .to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("function load good");
        assert_eq!(ok, RespFrame::BulkString(Some(b"goodlib".to_vec())));
    }

    #[test]
    fn function_flush_extra_args_and_restore_bad_payload_match_upstream() {
        // Pins two upstream wordings caught by differential probe vs
        // vendored 7.2.4 (frankenredis-ngn0):
        //   - FUNCTION FLUSH SYNC EXTRA -> "unknown subcommand or
        //     wrong number of arguments for 'FLUSH'. Try FUNCTION HELP."
        //     (functions.c::functionsCommand falls through to the
        //     subcommand-form addReplySubcommandSyntaxError envelope,
        //     not the generic wrong-arity reply.)
        //   - FUNCTION RESTORE <garbage> -> "DUMP payload version or
        //     checksum are wrong" (cluster.c::verifyDumpPayload guard
        //     reuses the DUMP payload validator wording.)
        let mut store = Store::new();

        let err = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"FLUSH".to_vec(),
                b"SYNC".to_vec(),
                b"EXTRA".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err.to_resp(),
            RespFrame::Error(
                "ERR unknown subcommand or wrong number of arguments for 'FLUSH'. Try FUNCTION HELP."
                    .to_string(),
            )
        );

        let restore_bad = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"RESTORE".to_vec(),
                b"not-a-real-dump".to_vec(),
            ],
            &mut store,
            0,
        );
        let err_msg = match restore_bad {
            Ok(RespFrame::Error(s)) => s,
            Err(e) => match e.to_resp() {
                RespFrame::Error(s) => s,
                other => panic!("expected error frame, got {other:?}"),
            },
            other => panic!("expected error, got {other:?}"),
        };
        assert_eq!(
            err_msg,
            "ERR DUMP payload version or checksum are wrong".to_string(),
        );
    }

    #[test]
    fn function_dump_restore_roundtrip_via_command_path() {
        let mut store = Store::new();
        let library = b"#!lua name=roundtriplib\nredis.register_function('roundtrip_echo', function(keys, args) return args[1] end)";

        let out = dispatch_argv(
            &[b"FUNCTION".to_vec(), b"LOAD".to_vec(), library.to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::BulkString(Some(b"roundtriplib".to_vec())));

        let dumped =
            dispatch_argv(&[b"FUNCTION".to_vec(), b"DUMP".to_vec()], &mut store, 0).unwrap();
        let RespFrame::BulkString(Some(dumped_bytes)) = dumped else {
            panic!("FUNCTION DUMP must return a bulk string");
        };
        assert!(
            !dumped_bytes.is_empty(),
            "FUNCTION DUMP payload must be non-empty"
        );

        let out = dispatch_argv(
            &[b"FUNCTION".to_vec(), b"FLUSH".to_vec(), b"SYNC".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));

        let out = dispatch_argv(
            &[b"FUNCTION".to_vec(), b"RESTORE".to_vec(), dumped_bytes],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::SimpleString("OK".to_string()));

        let out = dispatch_argv(&[b"FUNCTION".to_vec(), b"LIST".to_vec()], &mut store, 0).unwrap();
        let RespFrame::Array(Some(libraries)) = out else {
            panic!("FUNCTION LIST must return an array");
        };
        assert_eq!(
            libraries.len(),
            1,
            "restored dump must recreate the library"
        );

        let out = dispatch_argv(
            &[
                b"FCALL".to_vec(),
                b"roundtrip_echo".to_vec(),
                b"0".to_vec(),
                b"echoed".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::BulkString(Some(b"echoed".to_vec())));
    }

    #[test]
    fn fcall_ro_succeeds_for_table_form_function_with_no_writes_flag() {
        // The positional form has no way to declare flags, so
        // FCALL_RO always rejects it. The table form's
        // flags={'no-writes'} declaration must dispatch through
        // FCALL_RO successfully — exercising the
        // fr-store::function_load flag-capture path
        // (frankenredis-fnflagstore) and the FCALL_RO no-writes
        // gate at fr-command/src/lib.rs:9476.
        let mut store = Store::new();
        let out = dispatch_argv(
            &[
                b"FUNCTION".to_vec(),
                b"LOAD".to_vec(),
                b"#!lua name=rolib_nw\nredis.register_function{function_name='nw_echo', callback=function(keys, args) return args[1] end, flags={'no-writes'}}"
                    .to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::BulkString(Some(b"rolib_nw".to_vec())));

        let out = dispatch_argv(
            &[
                b"FCALL_RO".to_vec(),
                b"nw_echo".to_vec(),
                b"0".to_vec(),
                b"hello".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();
        assert_eq!(out, RespFrame::BulkString(Some(b"hello".to_vec())));
    }

