    #[test]
    fn zpop_with_count_under_resp3_returns_array_of_pair_subarrays() {
        // (frankenredis-1g3ao) Upstream zpopMinMaxCommand sets
        // use_nested_array = (c->resp > 2 && count != -1). With COUNT
        // and RESP3, each (member, score) is wrapped in a 2-Array.
        // Without COUNT (-1), the wire stays flat regardless.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"zs".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
                b"2".to_vec(),
                b"b".to_vec(),
                b"3".to_vec(),
                b"c".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zadd");
        store.dispatch_client_ctx.resp_protocol_version = 3;

        let out = dispatch_argv(
            &[b"ZPOPMIN".to_vec(), b"zs".to_vec(), b"2".to_vec()],
            &mut store,
            0,
        )
        .expect("zpopmin count resp3");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"a".to_vec())),
                    RespFrame::Double("1".to_string()),
                ])),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"b".to_vec())),
                    RespFrame::Double("2".to_string()),
                ])),
            ]))
        );

        // ZPOPMAX with count under RESP3 — same shape.
        let out = dispatch_argv(
            &[b"ZPOPMAX".to_vec(), b"zs".to_vec(), b"1".to_vec()],
            &mut store,
            0,
        )
        .expect("zpopmax count resp3");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"c".to_vec())),
                RespFrame::Double("3".to_string()),
            ]))]))
        );

        // No-COUNT form must stay flat 2-Array under RESP3 (upstream's
        // count == -1 disables nested wrapping).
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"zs".to_vec(),
                b"5".to_vec(),
                b"d".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zadd d");
        let out = dispatch_argv(&[b"ZPOPMIN".to_vec(), b"zs".to_vec()], &mut store, 0)
            .expect("zpopmin no count resp3");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"d".to_vec())),
                RespFrame::Double("5".to_string()),
            ]))
        );
    }

    #[test]
    fn zrank_withscore_score_is_resp3_double_under_hello3() {
        // Upstream t_zset.c zrankGenericCommand emits the score via
        // addReplyDouble, so under RESP3 it is a Double (`,<score>`) and under
        // RESP2 a bulk string. The rank stays an Integer in both. (Regression:
        // fr previously always emitted the score as a bulk string, diverging
        // from redis only in RESP3.)
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"3.5".to_vec(),
                b"a".to_vec(),
                b"1".to_vec(),
                b"b".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zadd");

        // RESP2: score is a bulk string.
        let out = dispatch_argv(
            &[
                b"ZRANK".to_vec(),
                b"z".to_vec(),
                b"a".to_vec(),
                b"WITHSCORE".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zrank withscore resp2");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![
                RespFrame::Integer(1),
                RespFrame::BulkString(Some(b"3.5".to_vec())),
            ]))
        );

        // RESP3: score is a Double; ZREVRANK matches.
        store.dispatch_client_ctx.resp_protocol_version = 3;
        let out = dispatch_argv(
            &[
                b"ZRANK".to_vec(),
                b"z".to_vec(),
                b"a".to_vec(),
                b"WITHSCORE".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zrank withscore resp3");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![
                RespFrame::Integer(1),
                RespFrame::Double("3.5".to_string()),
            ]))
        );
        let out = dispatch_argv(
            &[
                b"ZREVRANK".to_vec(),
                b"z".to_vec(),
                b"b".to_vec(),
                b"WITHSCORE".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zrevrank withscore resp3");
        assert_eq!(
            out,
            RespFrame::Array(Some(vec![
                RespFrame::Integer(1),
                RespFrame::Double("1".to_string()),
            ]))
        );

        // Missing member: null array (RESP3 `_`), no score frame at all.
        let out = dispatch_argv(
            &[
                b"ZRANK".to_vec(),
                b"z".to_vec(),
                b"nope".to_vec(),
                b"WITHSCORE".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("zrank withscore missing resp3");
        assert_eq!(out, RespFrame::Array(None));
    }

