    #[test]
    fn geosearch_any_without_count_is_rejected_like_upstream() {
        // Pin upstream geo.c::geoSearchGeneric rejection of ANY without
        // an accompanying COUNT argument: 'ERR the ANY argument requires
        // COUNT argument'. fr previously parsed ANY=true silently and
        // ignored the missing COUNT, executing as if ANY were absent.
        // Differential probe vs vendored 7.2.4 confirmed for
        // GEORADIUS / GEORADIUSBYMEMBER / GEOSEARCH (and their _RO /
        // STORE / STOREDIST variants which share parse_geo_search_flags).
        // (frankenredis-geoanyc)
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"g".to_vec(),
                b"13.5".to_vec(),
                b"38.0".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        let expected =
            CommandError::Custom("ERR the ANY argument requires COUNT argument".to_string());
        let cases: &[&[&[u8]]] = &[
            &[b"GEORADIUS", b"g", b"13.5", b"38.0", b"100", b"km", b"ANY"],
            &[b"GEORADIUSBYMEMBER", b"g", b"a", b"100", b"km", b"ANY"],
            &[
                b"GEOSEARCH",
                b"g",
                b"FROMMEMBER",
                b"a",
                b"BYRADIUS",
                b"100",
                b"km",
                b"ANY",
            ],
            &[
                b"GEOSEARCH",
                b"g",
                b"FROMLONLAT",
                b"13.5",
                b"38.0",
                b"BYBOX",
                b"100",
                b"100",
                b"km",
                b"ANY",
            ],
        ];
        for argv_in in cases {
            let argv: Vec<Vec<u8>> = argv_in.iter().map(|s| s.to_vec()).collect();
            let err = dispatch_argv(&argv, &mut store, 0).expect_err("ANY w/o COUNT");
            assert_eq!(err, expected, "argv={argv_in:?}");
        }

        // Sanity: ANY *with* COUNT must still parse cleanly.
        let ok = dispatch_argv(
            &[
                b"GEORADIUS".to_vec(),
                b"g".to_vec(),
                b"13.5".to_vec(),
                b"38.0".to_vec(),
                b"100".to_vec(),
                b"km".to_vec(),
                b"COUNT".to_vec(),
                b"5".to_vec(),
                b"ANY".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("ANY with COUNT");
        assert!(matches!(ok, RespFrame::Array(Some(_))));
    }

    #[test]
    fn geosearch_rejects_store_and_storedist_outside_geosearchstore_per_upstream() {
        // Pin upstream geo.c:596-616 STORE/STOREDIST gating:
        //   - GEORADIUS/GEORADIUSBYMEMBER: STORE key + STOREDIST key OK.
        //   - GEOSEARCH: both rejected with shared.syntaxerr (the
        //     command falls through to addReplyErrorObject because
        //     STORE is gated on `!(flags & GEOSEARCH)` and
        //     standalone STOREDIST is gated on
        //     `(flags & GEOSEARCH) && (flags & GEOSEARCHSTORE)`).
        //   - GEOSEARCHSTORE: bare STOREDIST (no key arg) is OK.
        //
        // Differential probe vs vendored 7.2.4 16380:
        //   GEOSEARCH geo FROMLONLAT 15 37 BYRADIUS 200 km STOREDIST
        //     vendored: ERR syntax error
        //     fr (pre-fix): silently dropped STOREDIST, returned
        //       the search result.
        // (frankenredis-ffr2k)
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"g".to_vec(),
                b"13.5".to_vec(),
                b"38.0".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        // GEOSEARCH + STOREDIST should error.
        let err = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"g".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"STOREDIST".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("GEOSEARCH STOREDIST must error");
        assert_eq!(err, CommandError::SyntaxError);

        // GEOSEARCH + STORE key should also error (not gated by NOSTORE
        // here — the gating in upstream is purely on the GEOSEARCH flag).
        let err_store = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"g".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"STORE".to_vec(),
                b"dst".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("GEOSEARCH STORE must error");
        assert_eq!(err_store, CommandError::SyntaxError);

        // GEOSEARCHSTORE + bare STOREDIST is the legitimate form — no error.
        let ok = dispatch_argv(
            &[
                b"GEOSEARCHSTORE".to_vec(),
                b"dst".to_vec(),
                b"g".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"STOREDIST".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("GEOSEARCHSTORE STOREDIST must succeed");
        assert!(matches!(ok, RespFrame::Integer(_)));

        // GEORADIUS + STORE/STOREDIST + key still works (regression guard).
        for opt in [&b"STORE"[..], &b"STOREDIST"[..]] {
            let _ = dispatch_argv(
                &[
                    b"GEORADIUS".to_vec(),
                    b"g".to_vec(),
                    b"13.5".to_vec(),
                    b"38.0".to_vec(),
                    b"100".to_vec(),
                    b"km".to_vec(),
                    opt.to_vec(),
                    b"dst".to_vec(),
                ],
                &mut store,
                0,
            )
            .expect("GEORADIUS STORE/STOREDIST key form must succeed");
        }
    }

    #[test]
    fn georadius_geosearch_no_sort_returns_zset_iteration_order_per_upstream() {
        // (frankenredis-1axne) Pin upstream geo.c:569,718 SORT_NONE
        // semantics: when neither ASC nor DESC is supplied, results
        // are returned in zset iteration order (geohash-score order),
        // NOT distance order. fr previously defaulted asc=true and
        // always sorted by distance, which broke parity for the
        // common no-flag case.
        //
        // The promotion rule (geo.c:714-718) — COUNT without ANY
        // promotes SORT_NONE to SORT_ASC — is also pinned.
        //
        // Layout: Palermo (13.36,38.12, geohash 3479099956230698)
        //         Catania (15.09,37.50, geohash 3479447370796909)
        // Search center (15,37): Catania ~56km, Palermo ~142km.
        // zset score order: Palermo first (smaller geohash), then Catania.
        // Distance order: Catania first, Palermo second.
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"g".to_vec(),
                b"13.361389".to_vec(),
                b"38.115556".to_vec(),
                b"Palermo".to_vec(),
                b"15.087269".to_vec(),
                b"37.502669".to_vec(),
                b"Catania".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        // No-sort: GEORADIUS without ASC/DESC.
        let out = dispatch_argv(
            &[
                b"GEORADIUS".to_vec(),
                b"g".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("georadius");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array, got {out:?}");
        };
        let names: Vec<_> = items
            .iter()
            .map(|f| match f {
                RespFrame::BulkString(Some(b)) => b.clone(),
                _ => Vec::new(),
            })
            .collect();
        assert_eq!(
            names,
            vec![b"Palermo".to_vec(), b"Catania".to_vec()],
            "no-sort GEORADIUS should return Palermo (lower geohash score) first"
        );

        // No-sort: GEOSEARCH BYRADIUS without ASC/DESC.
        let out = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"g".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geosearch byradius");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array");
        };
        let names: Vec<_> = items
            .iter()
            .map(|f| match f {
                RespFrame::BulkString(Some(b)) => b.clone(),
                _ => Vec::new(),
            })
            .collect();
        assert_eq!(
            names,
            vec![b"Palermo".to_vec(), b"Catania".to_vec()],
            "no-sort GEOSEARCH BYRADIUS should return zset iteration order"
        );

        // No-sort + COUNT N (no ANY): upstream promotes to ASC, so
        // closest-first wins → Catania first.
        let out = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"g".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"COUNT".to_vec(),
                b"2".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("count-promotes-asc");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array");
        };
        let names: Vec<_> = items
            .iter()
            .map(|f| match f {
                RespFrame::BulkString(Some(b)) => b.clone(),
                _ => Vec::new(),
            })
            .collect();
        assert_eq!(
            names,
            vec![b"Catania".to_vec(), b"Palermo".to_vec()],
            "COUNT without ANY/ASC/DESC must promote to ASC (closest-first)"
        );

        // No-sort + COUNT N + ANY: stays SORT_NONE → zset iteration
        // order, then truncated.
        let out = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"g".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"COUNT".to_vec(),
                b"1".to_vec(),
                b"ANY".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("count-any-no-sort");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array");
        };
        // ANY + COUNT 1 takes whichever of the two is first in zset
        // iteration order — Palermo (lower geohash score).
        assert_eq!(items.len(), 1);
        assert!(matches!(&items[0], RespFrame::BulkString(Some(b)) if b == b"Palermo"));

        // Explicit ASC still works.
        let out = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"g".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"ASC".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geosearch asc");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array");
        };
        let names: Vec<_> = items
            .iter()
            .map(|f| match f {
                RespFrame::BulkString(Some(b)) => b.clone(),
                _ => Vec::new(),
            })
            .collect();
        assert_eq!(
            names,
            vec![b"Catania".to_vec(), b"Palermo".to_vec()],
            "ASC = closest-first"
        );

        // Explicit DESC reverses.
        let out = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"g".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYRADIUS".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
                b"DESC".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("geosearch desc");
        let RespFrame::Array(Some(items)) = out else {
            panic!("expected array");
        };
        let names: Vec<_> = items
            .iter()
            .map(|f| match f {
                RespFrame::BulkString(Some(b)) => b.clone(),
                _ => Vec::new(),
            })
            .collect();
        assert_eq!(
            names,
            vec![b"Palermo".to_vec(), b"Catania".to_vec()],
            "DESC = farthest-first"
        );
    }

    /// (frankenredis-w6v9p) Upstream geo.c::geoSearchGeneric routes
    /// any unrecognised shape keyword (e.g. `BYSHAPE`, mistyped
    /// `BY_RADIUS`) through addReplyErrorObject(c, shared.syntaxerr)
    /// in the trailing-flags loop. fr's parse loop used to break on
    /// the unknown token and run the has_center/has_shape arity check
    /// first, so probe `GEOSEARCH key FROMLONLAT lon lat BYSHAPE 200 km`
    /// surfaced "wrong number of arguments" instead of "syntax error".
    #[test]
    fn geosearch_unknown_shape_keyword_surfaces_syntax_error_per_upstream() {
        let mut store = Store::new();
        dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"g".to_vec(),
                b"13.5".to_vec(),
                b"38.0".to_vec(),
                b"x".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("GEOADD seed");

        let err = dispatch_argv(
            &[
                b"GEOSEARCH".to_vec(),
                b"g".to_vec(),
                b"FROMLONLAT".to_vec(),
                b"15".to_vec(),
                b"37".to_vec(),
                b"BYSHAPE".to_vec(),
                b"200".to_vec(),
                b"km".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("GEOSEARCH BYSHAPE must surface syntax error");
        assert_eq!(err, CommandError::SyntaxError);
    }

    #[test]
    fn geosearch_byradius_bybox_numeric_wording_matches_upstream() {
        // Pin upstream geo.c::extractDistanceOrReply ("need numeric
        // radius") and extractBoxOrReply ("need numeric width" /
        // "need numeric height"), plus the negative-value branches
        // "radius cannot be negative" / "height or width cannot be
        // negative" (upstream's ordering puts height first).
        // (frankenredis-vfdt)
        let mut store = Store::new();

        // Seed a geo set so GEOSEARCH reaches the radius/box parsers.
        dispatch_argv(
            &[
                b"GEOADD".to_vec(),
                b"g".to_vec(),
                b"13.361389".to_vec(),
                b"38.115556".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        let cases: &[(&[&[u8]], &str)] = &[
            (
                &[
                    b"GEOSEARCH",
                    b"g",
                    b"FROMMEMBER",
                    b"a",
                    b"BYRADIUS",
                    b"abc",
                    b"m",
                ],
                "ERR need numeric radius",
            ),
            (
                &[
                    b"GEOSEARCH",
                    b"g",
                    b"FROMMEMBER",
                    b"a",
                    b"BYRADIUS",
                    b"-1",
                    b"m",
                ],
                "ERR radius cannot be negative",
            ),
            (
                &[
                    b"GEOSEARCH",
                    b"g",
                    b"FROMMEMBER",
                    b"a",
                    b"BYBOX",
                    b"abc",
                    b"1",
                    b"m",
                ],
                "ERR need numeric width",
            ),
            (
                &[
                    b"GEOSEARCH",
                    b"g",
                    b"FROMMEMBER",
                    b"a",
                    b"BYBOX",
                    b"1",
                    b"abc",
                    b"m",
                ],
                "ERR need numeric height",
            ),
            (
                &[
                    b"GEOSEARCH",
                    b"g",
                    b"FROMMEMBER",
                    b"a",
                    b"BYBOX",
                    b"-1",
                    b"-1",
                    b"m",
                ],
                "ERR height or width cannot be negative",
            ),
        ];

        for (argv_in, expected) in cases {
            let argv: Vec<Vec<u8>> = argv_in.iter().map(|s| s.to_vec()).collect();
            let out = dispatch_argv(&argv, &mut store, 0);
            let got = match out {
                Ok(RespFrame::Error(s)) => s,
                Err(e) => match e.to_resp() {
                    RespFrame::Error(s) => s,
                    other => panic!("expected error, got {other:?}"),
                },
                other => panic!("expected error frame for {argv_in:?}, got {other:?}"),
            };
            assert_eq!(&got, *expected, "argv: {argv_in:?}");
        }
    }

    #[test]
    fn srandmember_zrandmember_extra_args_match_upstream_syntax_error() {
        // Upstream commands.def declares both SRANDMEMBER and
        // ZRANDMEMBER with arity = -2; extra trailing args after the
        // [count [WITHSCORES/WITHVALUES]] tail land in the handler's
        // syntaxerr branch, not the table-level wrong-arity reply.
        // (frankenredis-8abz)
        let mut store = Store::new();
        dispatch_argv(
            &[b"SADD".to_vec(), b"s".to_vec(), b"a".to_vec()],
            &mut store,
            0,
        )
        .unwrap();
        dispatch_argv(
            &[
                b"ZADD".to_vec(),
                b"z".to_vec(),
                b"1".to_vec(),
                b"a".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap();

        let extra_srand = dispatch_argv(
            &[
                b"SRANDMEMBER".to_vec(),
                b"s".to_vec(),
                b"1".to_vec(),
                b"extra".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("srandmember extra");
        assert_eq!(extra_srand, CommandError::SyntaxError);

        let extra_zrand = dispatch_argv(
            &[
                b"ZRANDMEMBER".to_vec(),
                b"z".to_vec(),
                b"5".to_vec(),
                b"WITHSCORES".to_vec(),
                b"extra".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("zrandmember extra");
        assert_eq!(extra_zrand, CommandError::SyntaxError);

        // ZRANDMEMBER with 4-arg variant where the 4th token is not
        // WITHSCORES is also a syntax error.
        let bad_kw = dispatch_argv(
            &[
                b"ZRANDMEMBER".to_vec(),
                b"z".to_vec(),
                b"5".to_vec(),
                b"NOPE".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect_err("zrandmember bad kw");
        assert_eq!(bad_kw, CommandError::SyntaxError);
    }

    #[test]
    fn lpop_rpop_lpos_bad_count_wording_matches_upstream() {
        // Pin upstream t_list.c::popGenericCommand + lposCommand
        // wordings caught by ad-hoc differential probe vs vendored
        // 7.2.4 (frankenredis-stzv):
        //   - LPOP/RPOP <key> BAD     -> "value is out of range, must be positive"
        //   - LPOP/RPOP <key> -1      -> same wording
        //   - LPOS <key> a MAXLEN BAD -> "MAXLEN can't be negative"
        //   - LPOS <key> a MAXLEN -1  -> same wording
        let mut store = Store::new();

        for cmd in [b"LPOP".as_slice(), b"RPOP".as_slice()] {
            let err = dispatch_argv(
                &[cmd.to_vec(), b"l".to_vec(), b"BAD".to_vec()],
                &mut store,
                0,
            )
            .expect_err("error");
            assert_eq!(
                err,
                CommandError::Custom("ERR value is out of range, must be positive".to_string()),
                "{cmd:?}"
            );
            let err = dispatch_argv(
                &[cmd.to_vec(), b"l".to_vec(), b"-1".to_vec()],
                &mut store,
                0,
            )
            .expect_err("error");
            assert_eq!(
                err,
                CommandError::Custom("ERR value is out of range, must be positive".to_string()),
                "{cmd:?}"
            );
        }

        for bad in [b"BAD".as_slice(), b"-1".as_slice()] {
            let err = dispatch_argv(
                &[
                    b"LPOS".to_vec(),
                    b"l".to_vec(),
                    b"a".to_vec(),
                    b"MAXLEN".to_vec(),
                    bad.to_vec(),
                ],
                &mut store,
                0,
            )
            .expect_err("error");
            assert_eq!(
                err,
                CommandError::Custom("ERR MAXLEN can't be negative".to_string()),
                "{bad:?}"
            );
        }

        // (frankenredis-29ct) LPOS COUNT mirrors MAXLEN — both
        // unparseable and negative inputs share upstream's
        // "COUNT can't be negative" wording (lposCommand uses
        // getPositiveLongFromObjectOrReply with that error string).
        for bad in [b"BAD".as_slice(), b"-1".as_slice()] {
            let err = dispatch_argv(
                &[
                    b"LPOS".to_vec(),
                    b"l".to_vec(),
                    b"a".to_vec(),
                    b"COUNT".to_vec(),
                    bad.to_vec(),
                ],
                &mut store,
                0,
            )
            .expect_err("error");
            assert_eq!(
                err,
                CommandError::Custom("ERR COUNT can't be negative".to_string()),
                "{bad:?}"
            );
        }
    }

