    #[test]
    fn migrate_existing_key_invalid_port_reports_ioerr_like_redis() {
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"present".to_vec(), b"value".to_vec()],
            &mut store,
            0,
        )
        .expect("seed present key");
        let err = dispatch_argv(
            &[
                b"MIGRATE".to_vec(),
                b"127.0.0.1".to_vec(),
                b"notaport".to_vec(),
                b"present".to_vec(),
                b"0".to_vec(),
                b"1000".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert!(
            matches!(err, CommandError::Custom(ref message) if message.starts_with("IOERR")),
            "existing-key MIGRATE with a nonnumeric port should reach the IOERR socket path like Redis, got {err:?}"
        );

        let err = dispatch_argv(
            &[
                b"MIGRATE".to_vec(),
                b"127.0.0.1".to_vec(),
                b"65536".to_vec(),
                b"present".to_vec(),
                b"0".to_vec(),
                b"1000".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert!(
            matches!(err, CommandError::Custom(ref message) if message.starts_with("IOERR")),
            "out-of-range MIGRATE port should report IOERR instead of integer syntax, got {err:?}"
        );
    }

    #[test]
    fn eval_closure_captures_upvalues() {
        let mut store = Store::new();
        // Test: closure accesses local variable from enclosing scope
        let result = dispatch_argv(
            &[
                b"EVAL".to_vec(),
                b"local x = 42; local f = function() return x end; return f()".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("eval closure");
        assert_eq!(result, RespFrame::Integer(42));

        // Test: nested closure
        let result2 = dispatch_argv(
            &[
                b"EVAL".to_vec(),
                b"local a = 10; local f = function() local g = function() return a end; return g() end; return f()".to_vec(),
                b"0".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("eval nested closure");
        assert_eq!(result2, RespFrame::Integer(10));
    }

