    #[test]
    fn scan_cursor_parses_like_redis_cursor_arg() {
        let mut store = Store::new();
        dispatch_argv(
            &[b"SET".to_vec(), b"k".to_vec(), b"v".to_vec()],
            &mut store,
            0,
        )
        .expect("seed key");

        let err = dispatch_argv(&[b"SCAN".to_vec(), b"abc".to_vec()], &mut store, 0).unwrap_err();
        assert_eq!(err, CommandError::Custom("ERR invalid cursor".to_string()));

        let empty_scan = RespFrame::Array(Some(vec![
            RespFrame::BulkString(Some(b"0".to_vec())),
            RespFrame::Array(Some(Vec::new())),
        ]));
        assert_eq!(
            dispatch_argv(&[b"SCAN".to_vec(), b"-1".to_vec()], &mut store, 0)
                .expect("negative cursor should parse"),
            empty_scan
        );
        assert_eq!(
            dispatch_argv(&[b"SCAN".to_vec(), b"+1".to_vec()], &mut store, 0)
                .expect("plus cursor should parse"),
            empty_scan
        );
        assert_eq!(
            dispatch_argv(&[b"SCAN".to_vec(), b"01".to_vec()], &mut store, 0)
                .expect("leading-zero cursor should parse"),
            empty_scan
        );

        store
            .hset(b"h", b"field".to_vec(), b"value".to_vec(), 0)
            .expect("hset");
        assert_eq!(
            dispatch_argv(
                &[b"HSCAN".to_vec(), b"h".to_vec(), b"-1".to_vec()],
                &mut store,
                0
            )
            .expect("collection negative cursor should parse"),
            RespFrame::Array(Some(vec![
                RespFrame::BulkString(Some(b"0".to_vec())),
                RespFrame::Array(Some(vec![
                    RespFrame::BulkString(Some(b"field".to_vec())),
                    RespFrame::BulkString(Some(b"value".to_vec())),
                ])),
            ]))
        );
    }

    #[test]
    fn config_set_odd_arity_returns_upstream_syntax_error() {
        // (frankenredis-cfgsetodd) Upstream config.c::configSetCommand
        // line 819-821 routes odd-arity (`c->argc & 1`) through
        // addReplyErrorObject(shared.syntaxerr) — 'ERR syntax error'.
        // fr previously surfaced the table-level wrong-arity reply.
        // Differential probe vs vendored 7.2.4 confirmed.
        let mut store = Store::new();
        let err = dispatch_argv(
            &[
                b"CONFIG".to_vec(),
                b"SET".to_vec(),
                b"maxmemory".to_vec(),
                b"0".to_vec(),
                b"extra".to_vec(),
            ],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(err, CommandError::SyntaxError);

        // Sanity: argv.len() < 4 still surfaces wrong-arity.
        let err = dispatch_argv(
            &[b"CONFIG".to_vec(), b"SET".to_vec(), b"maxmemory".to_vec()],
            &mut store,
            0,
        )
        .unwrap_err();
        assert_eq!(
            err,
            CommandError::WrongSubcommandArity {
                command: "CONFIG",
                subcommand: "SET".to_string(),
            }
        );
    }

