    /// (frankenredis-arityfixes2) COMMAND_TABLE arity entries that
    /// must match upstream commands.def for the variadic forms:
    ///   ZRANK/ZREVRANK    -> -3 (optional WITHSCORE)
    ///   ZREVRANGE         -> -4 (optional WITHSCORES)
    ///   XAUTOCLAIM        -> -6 (key group consumer min-idle-time start)
    /// Handlers were already correct; only the COMMAND INFO metadata
    /// diverged.
    #[test]
    fn command_info_arity_for_zrank_zrevrange_xautoclaim_matches_upstream() {
        let mut store = Store::new();
        for (cmd, want) in [
            ("ZRANK", -3i64),
            ("ZREVRANK", -3),
            ("ZREVRANGE", -4),
            ("XAUTOCLAIM", -6),
        ] {
            let r = dispatch_argv(
                &[
                    b"COMMAND".to_vec(),
                    b"INFO".to_vec(),
                    cmd.as_bytes().to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_or_else(|_| panic!("COMMAND INFO {cmd}"));
            let RespFrame::Array(Some(rows)) = r else {
                panic!("expected Array reply for COMMAND INFO {cmd}");
            };
            let RespFrame::Array(Some(fields)) = rows.into_iter().next().expect("one row") else {
                panic!("expected sub-Array entry for {cmd}");
            };
            assert_eq!(
                fields[1],
                RespFrame::Integer(want),
                "{cmd} arity must be {want}, got {:?}",
                fields[1]
            );
        }
    }

    /// (frankenredis-msoqu) Upstream src/commands/*.json populates a
    /// `command_tips` array per command (lowercased on the wire by
    /// addReplyCommandTips). fr previously left the tips slot empty for
    /// every command except COMMAND/COMMAND|INFO/etc., so cluster-aware
    /// callers couldn't infer request_policy/response_policy or
    /// nondeterminism flags. Pin a representative subset across each
    /// distinct tip-set so regressions in command_info_tips trip a
    /// targeted test instead of waiting for the live oracle.
    #[test]
    fn command_info_tips_match_upstream_tip_table() {
        let mut store = Store::new();
        for (cmd, want) in [
            (
                "ACL|SETUSER",
                vec!["request_policy:all_nodes", "response_policy:all_succeeded"],
            ),
            (
                "DBSIZE",
                vec!["request_policy:all_shards", "response_policy:agg_sum"],
            ),
            (
                "KEYS",
                vec!["request_policy:all_shards", "nondeterministic_output_order"],
            ),
            ("MGET", vec!["request_policy:multi_shard"]),
            (
                "MSET",
                vec![
                    "request_policy:multi_shard",
                    "response_policy:all_succeeded",
                ],
            ),
            (
                "PING",
                vec!["request_policy:all_shards", "response_policy:all_succeeded"],
            ),
            (
                "RANDOMKEY",
                vec![
                    "request_policy:all_shards",
                    "response_policy:special",
                    "nondeterministic_output",
                ],
            ),
            (
                "SCAN",
                vec![
                    "nondeterministic_output",
                    "request_policy:special",
                    "response_policy:special",
                ],
            ),
            (
                "SLOWLOG|LEN",
                vec![
                    "request_policy:all_nodes",
                    "response_policy:agg_sum",
                    "nondeterministic_output",
                ],
            ),
            ("TIME", vec!["nondeterministic_output"]),
            (
                "WAIT",
                vec!["request_policy:all_shards", "response_policy:agg_min"],
            ),
            ("HGETALL", vec!["nondeterministic_output_order"]),
        ] {
            let r = dispatch_argv(
                &[
                    b"COMMAND".to_vec(),
                    b"INFO".to_vec(),
                    cmd.as_bytes().to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_or_else(|_| panic!("COMMAND INFO {cmd}"));
            let RespFrame::Array(Some(rows)) = r else {
                panic!("expected Array reply for COMMAND INFO {cmd}");
            };
            let RespFrame::Array(Some(fields)) = rows.into_iter().next().expect("one row") else {
                panic!("expected sub-Array entry for {cmd}");
            };
            let RespFrame::Array(Some(tips)) = fields[7].clone() else {
                panic!("tips slot must be an Array for {cmd}, got {:?}", fields[7]);
            };
            let got: Vec<String> = tips
                .iter()
                .map(|f| match f {
                    RespFrame::BulkString(Some(b)) => String::from_utf8_lossy(b).into_owned(),
                    other => panic!("expected BulkString tip for {cmd}, got {other:?}"),
                })
                .collect();
            let want_strs: Vec<String> = want.iter().map(|s| (*s).to_string()).collect();
            assert_eq!(got, want_strs, "{cmd} tips must match upstream order");
        }
    }

    /// (frankenredis-expirearity) Upstream commands.def declares
    /// EXPIRE/PEXPIRE/EXPIREAT/PEXPIREAT with arity=-3 (variadic for the
    /// optional NX/XX/GT/LT modifiers introduced in Redis 7.0). fr's
    /// COMMAND_TABLE previously had arity=3, so `COMMAND INFO EXPIRE`
    /// reported Integer(3) instead of Integer(-3).
