    /// (frankenredis-containerkeyspecs) Top-level OBJECT/XGROUP/XINFO
    /// container commands emit first/last/step = 0/0/0 and an empty
    /// key_specs sub-array in vendored 7.2.4 because the actual key
    /// position lives in subcommand-level KEYSPECS arrays. fr's
    /// command_key_indexes has dedicated name branches for these
    /// commands so dropping the COMMAND_TABLE triple to (0,0,0)
    /// only changes COMMAND INFO emission — runtime key extraction
    /// (and ACL key permission checks) continue to find argv[2]
    /// via the name-based path.
    #[test]
    fn command_info_keyspecs_for_object_xgroup_xinfo_emit_empty_per_upstream() {
        let mut store = Store::new();
        for cmd in ["OBJECT", "XGROUP", "XINFO"] {
            let r = dispatch_argv(
                &[
                    b"COMMAND".to_vec(),
                    b"INFO".to_vec(),
                    cmd.as_bytes().to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_or_else(|_| panic!("COMMAND INFO {cmd}"));
            let RespFrame::Array(Some(rows)) = r else {
                panic!("expected Array reply for COMMAND INFO {cmd}");
            };
            let RespFrame::Array(Some(fields)) = rows.into_iter().next().expect("one row") else {
                panic!("expected sub-Array entry for {cmd}");
            };
            assert_eq!(
                fields[3],
                RespFrame::Integer(0),
                "{cmd} first_key must be 0"
            );
            assert_eq!(fields[4], RespFrame::Integer(0), "{cmd} last_key must be 0");
            assert_eq!(fields[5], RespFrame::Integer(0), "{cmd} step must be 0");
            // key_specs sub-array is empty when first/last/step are 0.
            let RespFrame::Array(Some(key_specs)) = &fields[8] else {
                panic!("expected key_specs Array for {cmd}, got {:?}", fields[8]);
            };
            assert!(
                key_specs.is_empty(),
                "{cmd} key_specs must be empty, got {key_specs:?}"
            );
        }

        // Runtime extraction must still find the key argument for
        // OBJECT/XGROUP/XINFO subcommands via the name-based path.
        // (Confirms the (0,0,0) triple change didn't regress
        // ACL/cluster key resolution.)
        for argv in [
            vec![b"OBJECT".to_vec(), b"ENCODING".to_vec(), b"mykey".to_vec()],
            vec![b"XINFO".to_vec(), b"STREAM".to_vec(), b"mystream".to_vec()],
            vec![
                b"XGROUP".to_vec(),
                b"CREATE".to_vec(),
                b"mystream".to_vec(),
                b"g1".to_vec(),
                b"$".to_vec(),
            ],
        ] {
            let keys = super::command_key_indexes(&argv);
            assert_eq!(
                keys,
                vec![2],
                "{:?} key extraction must yield [2], got {keys:?}",
                String::from_utf8_lossy(&argv[0])
            );
        }
    }

    /// (frankenredis-restoreasking) RESTORE-ASKING is the cluster
    /// slot-migration alias of RESTORE. Upstream commands.def
    /// declares both names backed by restoreCommand with arity=-4
    /// and key spec firstkey=1/lastkey=1/keystep=1; RESTORE-ASKING
    /// adds the CMD_ASKING flag. fr aliases RESTORE-ASKING to
    /// CommandId::Restore in classify_command and registers the
    /// dedicated COMMAND_TABLE entry so `COMMAND INFO restore-asking`
    /// returns the right metadata. The handler / is_write_command /
    /// command_key_indexes paths reuse the RESTORE branches via
    /// the alias.
    #[test]
    fn command_info_restore_asking_matches_upstream_metadata() {
        let mut store = Store::new();
        let r = dispatch_argv(
            &[
                b"COMMAND".to_vec(),
                b"INFO".to_vec(),
                b"RESTORE-ASKING".to_vec(),
            ],
            &mut store,
            0,
        )
        .expect("COMMAND INFO RESTORE-ASKING");
        let RespFrame::Array(Some(rows)) = r else {
            panic!("expected Array");
        };
        let RespFrame::Array(Some(fields)) = rows.into_iter().next().expect("one row") else {
            panic!("expected sub-Array");
        };
        // name
        assert_eq!(
            fields[0],
            RespFrame::BulkString(Some(b"restore-asking".to_vec()))
        );
        // arity
        assert_eq!(fields[1], RespFrame::Integer(-4));
        // flags
        let RespFrame::Array(Some(emitted_flags)) = &fields[2] else {
            panic!("expected flags Array");
        };
        let got_flags: Vec<String> = emitted_flags
            .iter()
            .map(|f| match f {
                RespFrame::SimpleString(s) => s.clone(),
                other => panic!("expected SimpleString flag, got {other:?}"),
            })
            .collect();
        assert_eq!(
            got_flags,
            vec![
                "write".to_string(),
                "denyoom".to_string(),
                "asking".to_string()
            ],
            "flags must match upstream `write denyoom asking`"
        );
        // first/last/step
        assert_eq!(fields[3], RespFrame::Integer(1));
        assert_eq!(fields[4], RespFrame::Integer(1));
        assert_eq!(fields[5], RespFrame::Integer(1));

        // RESTORE-ASKING is a write command (AOF replay gate).
        assert!(
            is_write_command(b"RESTORE-ASKING"),
            "RESTORE-ASKING must be marked as a write command for AOF replay"
        );

        // RESTORE-ASKING shares RESTORE's classification (alias).
        assert_eq!(
            classify_command(b"RESTORE-ASKING"),
            classify_command(b"RESTORE")
        );

        // ACL category derivation includes @write, @keyspace, @dangerous.
        let cats = command_acl_categories("restore-asking");
        assert!(
            cats.contains(&"keyspace"),
            "restore-asking must be in @keyspace, got {cats:?}"
        );
        assert!(
            cats.contains(&"write"),
            "restore-asking must be in @write, got {cats:?}"
        );
        assert!(
            cats.contains(&"dangerous"),
            "restore-asking must be in @dangerous, got {cats:?}"
        );
    }

    /// (frankenredis-keyspecfixes) Differential probe vs vendored 7.2.4
    /// found five COMMAND_TABLE rows whose first_key/last_key/step
    /// triple disagreed with the upstream COMMAND INFO emission AND
    /// where the divergence either misled fr's own key-extraction
    /// algorithm (PFDEBUG read argv[1] = the subcommand string instead
    /// of argv[2] = the actual key) or simply failed to advertise the
    /// channel/key positions to clients (MIGRATE reported 0/0/0
    /// despite the explicit key at argv[3]; SPUBLISH/SSUBSCRIBE/
    /// SUNSUBSCRIBE reported 0/0/0 despite the channel at argv[1]).
    /// MIGRATE's special-case key extractor sits above the
    /// COMMAND_TABLE fallback so the multi-key 'KEYS' form continues
    /// to work; the triple change only affects emission.
    #[test]
    fn command_info_key_specs_first_last_step_for_keyspec_fixes_matches_upstream() {
        let mut store = Store::new();
        let cases: &[(&str, i64, i64, i64)] = &[
            ("MIGRATE", 3, 3, 1),
            ("PFDEBUG", 2, 2, 1),
            ("SPUBLISH", 1, 1, 1),
            ("SSUBSCRIBE", 1, -1, 1),
            ("SUNSUBSCRIBE", 1, -1, 1),
        ];
        for (cmd, first, last, step) in cases {
            let r = dispatch_argv(
                &[
                    b"COMMAND".to_vec(),
                    b"INFO".to_vec(),
                    cmd.as_bytes().to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_or_else(|_| panic!("COMMAND INFO {cmd}"));
            let RespFrame::Array(Some(rows)) = r else {
                panic!("expected Array reply for COMMAND INFO {cmd}");
            };
            let RespFrame::Array(Some(fields)) = rows.into_iter().next().expect("one row") else {
                panic!("expected sub-Array entry for {cmd}");
            };
            assert_eq!(
                fields[3],
                RespFrame::Integer(*first),
                "{cmd} first_key must be {first}, got {:?}",
                fields[3]
            );
            assert_eq!(
                fields[4],
                RespFrame::Integer(*last),
                "{cmd} last_key must be {last}, got {:?}",
                fields[4]
            );
            assert_eq!(
                fields[5],
                RespFrame::Integer(*step),
                "{cmd} step must be {step}, got {:?}",
                fields[5]
            );
        }
    }

    /// (frankenredis-89b8r) Per upstream commands.def, nine commands carry
    /// a non-default keySpec with a 'notes' description string and a
    /// custom flag bitmask. Pin all nine via COMMAND INFO key_specs[0].
    /// Pre-fix: SET/XADD emitted [RW, insert] (wrong); GETEX/BITFIELD/PFCOUNT
    /// fell through to the [RW, access] / [RO, access] defaults (missing
    /// update/variable_flags/RW); EVAL family emitted empty key_specs
    /// because their tabular first/last/step are 0/0/0 and the fn early-
    /// returned before adding the keynum find_keys spec.
    #[test]
    fn command_info_key_specs_notes_and_flags_for_set_xadd_getex_bitfield_pfcount_eval_fcall_match_upstream()
     {
        let mut store = Store::new();
        let cases: &[(&str, &str, &[&str])] = &[
            (
                "SET",
                "RW and ACCESS due to the optional `GET` argument",
                &["RW", "access", "update", "variable_flags"],
            ),
            (
                "XADD",
                "UPDATE instead of INSERT because of the optional trimming feature",
                &["RW", "update"],
            ),
            (
                "GETEX",
                "RW and UPDATE because it changes the TTL",
                &["RW", "access", "update"],
            ),
            (
                "BITFIELD",
                "This command allows both access and modification of the key",
                &["RW", "access", "update", "variable_flags"],
            ),
            (
                "PFCOUNT",
                "RW because it may change the internal representation of the key, and propagate to replicas",
                &["RW", "access"],
            ),
            (
                "EVAL",
                "We cannot tell how the keys will be used so we assume the worst, RW and UPDATE",
                &["RW", "access", "update"],
            ),
            (
                "EVAL_RO",
                "We cannot tell how the keys will be used so we assume the worst, RO and ACCESS",
                &["RO", "access"],
            ),
            (
                "FCALL",
                "We cannot tell how the keys will be used so we assume the worst, RW and UPDATE",
                &["RW", "access", "update"],
            ),
            (
                "FCALL_RO",
                "We cannot tell how the keys will be used so we assume the worst, RO and ACCESS",
                &["RO", "access"],
            ),
        ];
        for (cmd, expected_notes, expected_flags) in cases {
            let r = dispatch_argv(
                &[
                    b"COMMAND".to_vec(),
                    b"INFO".to_vec(),
                    cmd.as_bytes().to_vec(),
                ],
                &mut store,
                0,
            )
            .unwrap_or_else(|_| panic!("COMMAND INFO {cmd}"));
            let RespFrame::Array(Some(rows)) = r else {
                panic!("expected Array reply for COMMAND INFO {cmd}");
            };
            let RespFrame::Array(Some(fields)) = rows.into_iter().next().expect("one row") else {
                panic!("expected sub-Array entry for {cmd}");
            };
            let RespFrame::Array(Some(specs)) = &fields[8] else {
                panic!("expected key_specs Array for {cmd}, got {:?}", fields[8]);
            };
            assert_eq!(specs.len(), 1, "{cmd} must emit exactly one key_spec");
            let RespFrame::Array(Some(spec)) = &specs[0] else {
                panic!("expected key_spec Array for {cmd}");
            };
            // First field-name must be 'notes'.
            assert_eq!(
                spec[0],
                RespFrame::BulkString(Some(b"notes".to_vec())),
                "{cmd} key_spec[0] must be 'notes' field name"
            );
            assert_eq!(
                spec[1],
                RespFrame::BulkString(Some(expected_notes.as_bytes().to_vec())),
                "{cmd} notes must match upstream"
            );
            // Second field is 'flags'.
            assert_eq!(
                spec[2],
                RespFrame::BulkString(Some(b"flags".to_vec())),
                "{cmd} key_spec[2] must be 'flags' field name"
            );
            let RespFrame::Array(Some(flags)) = &spec[3] else {
                panic!("expected flags Array for {cmd}");
            };
            let actual_flags: Vec<String> = flags
                .iter()
                .filter_map(|f| match f {
                    RespFrame::SimpleString(s) => Some(s.clone()),
                    _ => None,
                })
                .collect();
            let expected: Vec<String> = expected_flags.iter().map(|s| (*s).to_string()).collect();
            assert_eq!(actual_flags, expected, "{cmd} flag set must match upstream");
        }
    }

